window.DOC_DATA = {"catalog":{"items":[{"children":[{"children":[],"order":0,"path":"introduction","title":"專案介紹與功能特色"},{"children":[],"order":1,"path":"tech-stack","title":"技術棧與相依套件"},{"children":[],"order":2,"path":"output-structure","title":"輸出結構說明"}],"order":0,"path":"overview","title":"概述"},{"children":[{"children":[],"order":0,"path":"installation","title":"安裝與建置"},{"children":[],"order":1,"path":"init","title":"初始化設定"},{"children":[],"order":2,"path":"first-run","title":"產生第一份文件"}],"order":1,"path":"getting-started","title":"快速開始"},{"children":[{"children":[],"order":0,"path":"cmd-init","title":"selfmd init"},{"children":[],"order":1,"path":"cmd-generate","title":"selfmd generate"},{"children":[],"order":2,"path":"cmd-update","title":"selfmd update"},{"children":[],"order":3,"path":"cmd-translate","title":"selfmd translate"}],"order":2,"path":"cli","title":"CLI 指令參考"},{"children":[{"children":[],"order":0,"path":"config-overview","title":"selfmd.yaml 結構總覽"},{"children":[],"order":1,"path":"project-targets","title":"專案與掃描目標設定"},{"children":[],"order":2,"path":"output-language","title":"輸出與多語言設定"},{"children":[],"order":3,"path":"claude-config","title":"Claude CLI 整合設定"},{"children":[],"order":4,"path":"git-config","title":"Git 整合設定"}],"order":3,"path":"configuration","title":"設定說明"},{"children":[{"children":[],"order":0,"path":"pipeline","title":"整體流程與四階段管線"},{"children":[],"order":1,"path":"module-dependencies","title":"模組依賴關係"}],"order":4,"path":"architecture","title":"系統架構"},{"children":[{"children":[],"order":0,"path":"scanner","title":"專案掃描器"},{"children":[],"order":1,"path":"catalog","title":"文件目錄管理"},{"children":[],"order":2,"path":"prompt-engine","title":"Prompt 模板引擎"},{"children":[],"order":3,"path":"claude-runner","title":"Claude CLI 執行器"},{"children":[{"children":[],"order":0,"path":"catalog-phase","title":"目錄產生階段"},{"children":[],"order":1,"path":"content-phase","title":"內容頁面產生階段"},{"children":[],"order":2,"path":"index-phase","title":"索引與導航產生階段"},{"children":[],"order":3,"path":"translate-phase","title":"翻譯階段"}],"order":4,"path":"generator","title":"文件產生管線"},{"children":[],"order":5,"path":"incremental-update","title":"增量更新"},{"children":[],"order":6,"path":"output-writer","title":"輸出寫入與連結修復"},{"children":[],"order":7,"path":"static-viewer","title":"靜態文件瀏覽器"}],"order":5,"path":"core-modules","title":"核心模組"},{"children":[{"children":[],"order":0,"path":"supported-languages","title":"支援的語言與模板"},{"children":[],"order":1,"path":"translation-workflow","title":"翻譯工作流程"}],"order":6,"path":"i18n","title":"多語言支援"},{"children":[{"children":[],"order":0,"path":"change-detection","title":"Git Diff 變更偵測"},{"children":[],"order":1,"path":"affected-pages","title":"受影響頁面判斷邏輯"}],"order":7,"path":"git-integration","title":"Git 整合與增量更新"}]},"meta":{"default_language":"en-US","available_languages":[{"code":"en-US","native_name":"English","is_default":true},{"code":"zh-TW","native_name":"繁體中文","is_default":false}]},"pages":{"architecture/index.md":"# 系統架構\n\nThis section contains the following:\n\n- [整體流程與四階段管線](pipeline/index.md)\n- [模組依賴關係](module-dependencies/index.md)\n","architecture/module-dependencies/index.md":"# 模組依賴關係\n\nselfmd 採用清晰的分層架構，各模組間的依賴關係呈現單向流動，從基礎層向上至協調層與 CLI 層，避免循環依賴。\n\n## 概述\n\nselfmd 的模組依賴關係可分為四個明確的層次：\n\n1. **基礎層**（Foundation）：不依賴任何專案內部套件，僅使用標準函式庫或第三方套件\n2. **中間層**（Middleware）：僅依賴基礎層模組\n3. **協調層**（Orchestration）：`generator` 套件，依賴所有中間層與基礎層模組，負責整合各階段\n4. **CLI 層**（Entry Points）：`cmd` 套件，依賴協調層與部分基礎層模組，提供使用者介面\n\n此設計確保模組間**無循環依賴**，低層模組對高層模組一無所知，測試與替換各模組的成本極低。\n\n### 關鍵術語\n\n| 術語 | 說明 |\n|------|------|\n| 基礎層 | 零內部依賴的純函式套件 |\n| 協調層 | 整合多個模組、執行完整工作流程的套件 |\n| 依賴注入 | `Generator` struct 在建構時接收 `Runner`、`Engine`、`Writer` 實體 |\n\n---\n\n## 架構\n\n### 整體依賴層次圖\n\n```mermaid\nflowchart TD\n    subgraph CLI[\"CLI 層（cmd/）\"]\n        cmd_root[\"root.go\"]\n        cmd_init[\"init.go\"]\n        cmd_gen[\"generate.go\"]\n        cmd_update[\"update.go\"]\n        cmd_translate[\"translate.go\"]\n    end\n\n    subgraph Orchestration[\"協調層（internal/generator/）\"]\n        pipeline[\"pipeline.go\u003cbr/\u003eGenerator\"]\n        catalog_phase[\"catalog_phase.go\u003cbr/\u003eGenerateCatalog\"]\n        content_phase[\"content_phase.go\u003cbr/\u003eGenerateContent\"]\n        index_phase[\"index_phase.go\u003cbr/\u003eGenerateIndex\"]\n        translate_phase[\"translate_phase.go\u003cbr/\u003eTranslate\"]\n        updater[\"updater.go\u003cbr/\u003eUpdate\"]\n    end\n\n    subgraph Middleware[\"中間層（internal/）\"]\n        claude[\"claude/\u003cbr/\u003eRunner · Parser · Types\"]\n        output_pkg[\"output/\u003cbr/\u003eWriter · LinkFixer · Navigation\"]\n        scanner_pkg[\"scanner/\u003cbr/\u003eScanner · FileTree\"]\n    end\n\n    subgraph Foundation[\"基礎層（internal/）\"]\n        config_pkg[\"config/\u003cbr/\u003eConfig\"]\n        catalog_pkg[\"catalog/\u003cbr/\u003eCatalog\"]\n        prompt_pkg[\"prompt/\u003cbr/\u003eEngine\"]\n        git_pkg[\"git/\u003cbr/\u003eGit\"]\n    end\n\n    cmd_gen --\u003e pipeline\n    cmd_update --\u003e pipeline\n    cmd_update --\u003e git_pkg\n    cmd_update --\u003e scanner_pkg\n    cmd_translate --\u003e pipeline\n    cmd_init --\u003e config_pkg\n    cmd_gen --\u003e claude\n    cmd_update --\u003e claude\n    cmd_translate --\u003e claude\n\n    pipeline --\u003e catalog_phase\n    pipeline --\u003e content_phase\n    pipeline --\u003e index_phase\n    pipeline --\u003e translate_phase\n    pipeline --\u003e updater\n\n    catalog_phase --\u003e claude\n    catalog_phase --\u003e prompt_pkg\n    catalog_phase --\u003e scanner_pkg\n    catalog_phase --\u003e catalog_pkg\n\n    content_phase --\u003e claude\n    content_phase --\u003e prompt_pkg\n    content_phase --\u003e scanner_pkg\n    content_phase --\u003e catalog_pkg\n    content_phase --\u003e output_pkg\n\n    index_phase --\u003e catalog_pkg\n    index_phase --\u003e output_pkg\n\n    translate_phase --\u003e claude\n    translate_phase --\u003e prompt_pkg\n    translate_phase --\u003e catalog_pkg\n    translate_phase --\u003e output_pkg\n\n    updater --\u003e claude\n    updater --\u003e prompt_pkg\n    updater --\u003e scanner_pkg\n    updater --\u003e catalog_pkg\n    updater --\u003e output_pkg\n    updater --\u003e git_pkg\n\n    claude --\u003e config_pkg\n    scanner_pkg --\u003e config_pkg\n    output_pkg --\u003e catalog_pkg\n```\n\n\u003e 來源：`cmd/generate.go#L1-L14`、`cmd/update.go#L1-L18`、`internal/generator/pipeline.go#L1-L16`\n\n---\n\n## 各層詳細說明\n\n### 基礎層（Foundation Layer）\n\n基礎層模組彼此獨立，不相互依賴，可單獨測試與使用。\n\n#### `internal/config`\n\n**職責**：讀取、驗證、序列化 `selfmd.yaml` 設定檔，並提供 `DefaultConfig()`。\n\n- **內部依賴**：無\n- **外部依賴**：`gopkg.in/yaml.v3`\n- **被依賴於**：`claude`、`scanner`、`generator`（所有階段）、`cmd`\n\n```go\ntype Config struct {\n    Project ProjectConfig `yaml:\"project\"`\n    Targets TargetsConfig `yaml:\"targets\"`\n    Output  OutputConfig  `yaml:\"output\"`\n    Claude  ClaudeConfig  `yaml:\"claude\"`\n    Git     GitConfig     `yaml:\"git\"`\n}\n```\n\n\u003e 來源：`internal/config/config.go#L11-L17`\n\n#### `internal/catalog`\n\n**職責**：定義文件目錄的資料模型（`Catalog`、`CatalogItem`、`FlatItem`），並提供 JSON 序列化與扁平化方法。\n\n- **內部依賴**：無\n- **外部依賴**：標準函式庫（`encoding/json`）\n- **被依賴於**：`output`、`generator`（所有階段）\n\n```go\ntype Catalog struct {\n    Items []CatalogItem `json:\"items\"`\n}\n\ntype FlatItem struct {\n    Title       string\n    Path        string // dot-notation, e.g., \"core-modules.authentication\"\n    DirPath     string // filesystem path, e.g., \"core-modules/authentication\"\n    Depth       int\n    ParentPath  string\n    HasChildren bool\n}\n```\n\n\u003e 來源：`internal/catalog/catalog.go#L10-L31`\n\n#### `internal/prompt`\n\n**職責**：管理 Prompt 模板（`templates/zh-TW/*.tmpl`、`templates/en-US/*.tmpl`），提供各階段所需的渲染方法。\n\n- **內部依賴**：無\n- **外部依賴**：標準函式庫（`text/template`、`embed`）\n- **被依賴於**：`generator`（所有使用 Claude 的階段）\n\n```go\ntype Engine struct {\n    templates       *template.Template // 語言專屬模板\n    sharedTemplates *template.Template // 共用模板（translate.tmpl）\n}\n```\n\n\u003e 來源：`internal/prompt/engine.go#L13-L17`\n\n#### `internal/git`\n\n**職責**：封裝 Git CLI 操作（取得 commit、diff、過濾變更檔案），不解析業務邏輯。\n\n- **內部依賴**：無\n- **外部依賴**：`github.com/bmatcuk/doublestar/v4`、標準函式庫（`os/exec`）\n- **被依賴於**：`generator/updater`、`generator/pipeline`、`cmd/update`\n\n```go\ntype ChangedFile struct {\n    Status string // \"M\", \"A\", \"D\", \"R\"\n    Path   string\n}\n```\n\n\u003e 來源：`internal/git/git.go#L47-L51`\n\n---\n\n### 中間層（Middleware Layer）\n\n中間層模組依賴基礎層，但彼此之間**不互相依賴**。\n\n#### `internal/claude`\n\n**職責**：封裝 Claude CLI 子行程的呼叫（`Runner`），解析 JSON 輸出（`Parser`），並定義資料型別（`Types`）。\n\n- **內部依賴**：`internal/config`（讀取 `ClaudeConfig`）\n- **外部依賴**：標準函式庫（`os/exec`、`encoding/json`、`regexp`）\n\n```go\ntype Runner struct {\n    config *config.ClaudeConfig\n    logger *slog.Logger\n}\n```\n\n\u003e 來源：`internal/claude/runner.go#L16-L19`\n\n`claude` 套件包含三個檔案，各有明確分工：\n\n| 檔案 | 職責 |\n|------|------|\n| `runner.go` | 執行 `claude` CLI 子行程，支援重試 |\n| `parser.go` | 解析 JSON 回應、擷取 `\u003cdocument\u003e` 標籤、擷取 JSON 區塊 |\n| `types.go` | 定義 `RunOptions`、`RunResult`、`CLIResponse` |\n\n#### `internal/scanner`\n\n**職責**：掃描專案目錄，依據 `Config.Targets` 過濾檔案，建構 `FileNode` 樹狀結構，讀取 README 與入口檔案。\n\n- **內部依賴**：`internal/config`（存取 `Targets.Include` / `Targets.Exclude`）\n- **外部依賴**：`github.com/bmatcuk/doublestar/v4`\n\n```go\ntype ScanResult struct {\n    RootDir            string\n    Tree               *FileNode\n    FileList           []string\n    TotalFiles         int\n    TotalDirs          int\n    ReadmeContent      string\n    EntryPointContents map[string]string\n}\n```\n\n\u003e 來源：`internal/scanner/filetree.go#L18-L27`\n\n#### `internal/output`\n\n**職責**：將文件寫入磁碟（`Writer`），修復相對路徑連結（`LinkFixer`），產生導航頁面（`navigation.go`），以及靜態瀏覽器（`viewer.go`）。\n\n- **內部依賴**：`internal/catalog`（存取 `FlatItem`、`Catalog`）\n- **外部依賴**：標準函式庫（`os`、`path/filepath`、`regexp`）\n\n```go\ntype Writer struct {\n    BaseDir string // absolute path to .doc-build/\n}\n\ntype LinkFixer struct {\n    allItems  []catalog.FlatItem\n    dirPaths  map[string]bool\n    pathIndex map[string]string\n}\n```\n\n\u003e 來源：`internal/output/writer.go#L26-L28`、`internal/output/linkfixer.go#L12-L16`\n\n---\n\n### 協調層（Orchestration Layer）\n\n`internal/generator` 是整個系統的核心協調層，負責將所有中間層與基礎層模組整合為完整的工作流程。\n\n#### `Generator` struct 與依賴注入\n\n```go\ntype Generator struct {\n    Config  *config.Config\n    Runner  *claude.Runner\n    Engine  *prompt.Engine\n    Writer  *output.Writer\n    Logger  *slog.Logger\n    RootDir string\n\n    TotalCost   float64\n    TotalPages  int\n    FailedPages int\n}\n```\n\n\u003e 來源：`internal/generator/pipeline.go#L19-L31`\n\n`NewGenerator` 建構時統一初始化所有依賴：\n\n```go\nfunc NewGenerator(cfg *config.Config, rootDir string, logger *slog.Logger) (*Generator, error) {\n    templateLang := cfg.Output.GetEffectiveTemplateLang()\n    engine, err := prompt.NewEngine(templateLang)\n    // ...\n    runner := claude.NewRunner(\u0026cfg.Claude, logger)\n    writer := output.NewWriter(absOutDir)\n    return \u0026Generator{\n        Config:  cfg,\n        Runner:  runner,\n        Engine:  engine,\n        Writer:  writer,\n        Logger:  logger,\n        RootDir: rootDir,\n    }, nil\n}\n```\n\n\u003e 來源：`internal/generator/pipeline.go#L34-L58`\n\n#### generator 各子檔案的依賴範圍\n\n```mermaid\nflowchart LR\n    subgraph generator[\"internal/generator/\"]\n        pipeline[\"pipeline.go\"]\n        catalog_p[\"catalog_phase.go\"]\n        content_p[\"content_phase.go\"]\n        index_p[\"index_phase.go\"]\n        translate_p[\"translate_phase.go\"]\n        updater[\"updater.go\"]\n    end\n\n    catalog_p --\u003e |\"catalog, claude\u003cbr/\u003econfig, prompt, scanner\"| deps1[\"基礎層＋中間層\"]\n    content_p --\u003e |\"catalog, claude\u003cbr/\u003econfig, output, prompt, scanner\"| deps1\n    index_p --\u003e |\"catalog, output\"| deps2[\"輕量依賴\"]\n    translate_p --\u003e |\"catalog, claude\u003cbr/\u003econfig, output, prompt\"| deps1\n    updater --\u003e |\"catalog, claude\u003cbr/\u003egit, output, prompt, scanner\"| deps1\n    pipeline --\u003e |\"整合所有子模組\"| deps1\n```\n\n---\n\n### CLI 層（Entry Points Layer）\n\n`cmd` 套件的各指令直接依賴協調層，並視需求直接呼叫部分中間層（如 `claude.CheckAvailable()`）。\n\n```mermaid\nflowchart LR\n    cmd_init[\"cmd/init.go\"] --\u003e config[\"internal/config\"]\n    cmd_gen[\"cmd/generate.go\"] --\u003e generator[\"internal/generator\"]\n    cmd_gen --\u003e claude[\"internal/claude\"]\n    cmd_gen --\u003e config\n    cmd_update[\"cmd/update.go\"] --\u003e generator\n    cmd_update --\u003e claude\n    cmd_update --\u003e config\n    cmd_update --\u003e git[\"internal/git\"]\n    cmd_update --\u003e scanner[\"internal/scanner\"]\n    cmd_translate[\"cmd/translate.go\"] --\u003e generator\n    cmd_translate --\u003e claude\n    cmd_translate --\u003e config\n```\n\n\u003e 來源：`cmd/generate.go#L1-L14`、`cmd/update.go#L1-L18`、`cmd/translate.go#L1-L17`\n\n---\n\n## 依賴矩陣\n\n下表列出各模組所依賴的其他**內部**模組（✓ 表示直接依賴）：\n\n| 模組 | config | catalog | prompt | git | scanner | claude | output | generator |\n|------|:------:|:-------:|:------:|:---:|:-------:|:------:|:------:|:---------:|\n| `config` | — | | | | | | | |\n| `catalog` | | — | | | | | | |\n| `prompt` | | | — | | | | | |\n| `git` | | | | — | | | | |\n| `scanner` | ✓ | | | | — | | | |\n| `claude` | ✓ | | | | | — | | |\n| `output` | | ✓ | | | | | — | |\n| `generator` | ✓ | ✓ | ✓ | ✓ | ✓ | ✓ | ✓ | — |\n| `cmd` | ✓ | | | ✓ | ✓ | ✓ | | ✓ |\n\n---\n\n## 核心流程：依賴初始化順序\n\n```mermaid\nsequenceDiagram\n    participant Main as main.go\n    participant CMD as cmd/generate.go\n    participant CFG as config.Load()\n    participant Gen as generator.NewGenerator()\n    participant Engine as prompt.NewEngine()\n    participant Runner as claude.NewRunner()\n    participant Writer as output.NewWriter()\n\n    Main-\u003e\u003eCMD: Execute()\n    CMD-\u003e\u003eCFG: config.Load(cfgFile)\n    CFG--\u003e\u003eCMD: *Config\n    CMD-\u003e\u003eGen: NewGenerator(cfg, rootDir, logger)\n    Gen-\u003e\u003eEngine: prompt.NewEngine(templateLang)\n    Engine--\u003e\u003eGen: *Engine\n    Gen-\u003e\u003eRunner: claude.NewRunner(\u0026cfg.Claude, logger)\n    Runner--\u003e\u003eGen: *Runner\n    Gen-\u003e\u003eWriter: output.NewWriter(outDir)\n    Writer--\u003e\u003eGen: *Writer\n    Gen--\u003e\u003eCMD: *Generator\n    CMD-\u003e\u003eGen: gen.Generate(ctx, opts)\n```\n\n---\n\n## 外部依賴彙整\n\nselfmd 使用以下第三方套件：\n\n| 套件 | 版本 | 使用模組 | 用途 |\n|------|------|---------|------|\n| `github.com/spf13/cobra` | — | `cmd/` | CLI 指令框架 |\n| `gopkg.in/yaml.v3` | — | `internal/config` | YAML 設定檔解析 |\n| `github.com/bmatcuk/doublestar/v4` | — | `internal/scanner`, `internal/git` | Glob 模式匹配（`**` 雙星號） |\n| `golang.org/x/sync/errgroup` | — | `internal/generator` | 並行任務錯誤群組管理 |\n\n---\n\n## 相關連結\n\n- [整體流程與四階段管線](../pipeline/index.md) — 各模組如何在四階段中協作\n- [文件產生管線](../../core-modules/generator/index.md) — Generator 協調層的詳細說明\n- [專案掃描器](../../core-modules/scanner/index.md) — `internal/scanner` 模組說明\n- [Claude CLI 執行器](../../core-modules/claude-runner/index.md) — `internal/claude` 模組說明\n- [Prompt 模板引擎](../../core-modules/prompt-engine/index.md) — `internal/prompt` 模組說明\n- [輸出寫入與連結修復](../../core-modules/output-writer/index.md) — `internal/output` 模組說明\n- [設定說明](../../configuration/index.md) — `selfmd.yaml` 設定結構總覽\n\n---\n\n## 參考檔案\n\n| 檔案路徑 | 說明 |\n|----------|------|\n| `cmd/root.go` | CLI 根指令，全域 flag 定義 |\n| `cmd/generate.go` | `selfmd generate` 指令實作，依賴 `generator`、`claude`、`config` |\n| `cmd/init.go` | `selfmd init` 指令實作，依賴 `config` |\n| `cmd/update.go` | `selfmd update` 指令實作，依賴 `generator`、`git`、`scanner`、`claude`、`config` |\n| `cmd/translate.go` | `selfmd translate` 指令實作，依賴 `generator`、`claude`、`config` |\n| `internal/config/config.go` | `Config` 結構定義、預設值、載入與驗證邏輯 |\n| `internal/catalog/catalog.go` | `Catalog`、`CatalogItem`、`FlatItem` 資料模型與操作方法 |\n| `internal/prompt/engine.go` | `Engine` 模板引擎，`CatalogPromptData`、`ContentPromptData` 等資料型別 |\n| `internal/git/git.go` | Git CLI 封裝：取得 commit、diff、過濾檔案 |\n| `internal/scanner/scanner.go` | 目錄遍歷與 glob 過濾邏輯 |\n| `internal/scanner/filetree.go` | `ScanResult`、`FileNode` 定義與樹狀渲染 |\n| `internal/claude/runner.go` | `Runner` struct，執行 Claude CLI 子行程與重試邏輯 |\n| `internal/claude/parser.go` | JSON 解析、`\u003cdocument\u003e` 標籤擷取、樣板清理 |\n| `internal/claude/types.go` | `RunOptions`、`RunResult`、`CLIResponse` 型別定義 |\n| `internal/output/writer.go` | `Writer` 寫入文件頁面、目錄 JSON、commit 記錄 |\n| `internal/output/linkfixer.go` | `LinkFixer` 修復 Markdown 相對路徑連結 |\n| `internal/output/navigation.go` | 產生 `index.md`、`_sidebar.md`、分類索引頁 |\n| `internal/generator/pipeline.go` | `Generator` struct 定義、`NewGenerator`、`Generate` 主流程 |\n| `internal/generator/catalog_phase.go` | 第二階段：呼叫 Claude 產生目錄 |\n| `internal/generator/content_phase.go` | 第三階段：並行產生內容頁面 |\n| `internal/generator/index_phase.go` | 第四階段：產生索引與導航 |\n| `internal/generator/translate_phase.go` | 翻譯流程：並行翻譯所有頁面至目標語言 |\n| `internal/generator/updater.go` | 增量更新流程：比對 git diff 並選擇性重新產生 |","architecture/pipeline/index.md":"# 整體流程與四階段管線\n\n`selfmd generate` 指令透過 `Generator` 協調器執行四個有序階段，將原始碼轉換為完整的 Markdown 文件站台。每個階段職責分明，互相串接，最終輸出可瀏覽的靜態文件。\n\n## 概述\n\n`Generator`（位於 `internal/generator/pipeline.go`）是整個系統的核心協調器。它持有所有子系統的參照——掃描器、Claude 執行器、Prompt 引擎、輸出寫入器——並按順序驅動以下四個階段：\n\n| 階段 | 編號 | 職責 |\n|------|------|------|\n| 掃描（Scan） | 1/4 | 遍歷專案目錄，建立檔案樹 |\n| 目錄產生（Catalog） | 2/4 | 呼叫 Claude 規劃文件架構 |\n| 內容產生（Content） | 3/4 | 並行產生每一頁文件 |\n| 索引與導航（Index） | 4/4 | 產生首頁、側欄、分類索引 |\n\n執行完四個階段後，系統還會額外進行靜態瀏覽器產生與 Git commit 記錄存檔，作為後處理步驟。\n\n## 架構\n\n```mermaid\nflowchart TD\n    CLI[\"cmd/generate.go\\nCLI 入口\"] --\u003e Gen\n\n    subgraph Gen[\"Generator（pipeline.go）\"]\n        direction TB\n        GS[\"GenerateOptions\\n{Clean, DryRun, Concurrency}\"]\n    end\n\n    Gen --\u003e|\"Phase 1\"| Scanner[\"scanner.Scan()\\n專案掃描\"]\n    Scanner --\u003e|\"ScanResult\"| CatalogPhase\n\n    Gen --\u003e|\"Phase 2\"| CatalogPhase[\"GenerateCatalog()\\n目錄產生\"]\n    CatalogPhase --\u003e|\"Prompt\"| Runner[\"claude.Runner\\nRunWithRetry()\"]\n    Runner --\u003e|\"JSON\"| CatalogParse[\"catalog.Parse()\\n目錄解析\"]\n    CatalogParse --\u003e|\"Catalog\"| ContentPhase\n\n    Gen --\u003e|\"Phase 3\"| ContentPhase[\"GenerateContent()\\n內容頁面（並行）\"]\n    ContentPhase --\u003e|\"Prompt × N\"| Runner\n    Runner --\u003e|\"Markdown\"| LinkFixer[\"output.LinkFixer\\n連結修復\"]\n    LinkFixer --\u003e|\"WritePage()\"| Writer[\"output.Writer\\n輸出寫入\"]\n\n    Gen --\u003e|\"Phase 4\"| IndexPhase[\"GenerateIndex()\\n索引與導航\"]\n    IndexPhase --\u003e|\"index.md\\n_sidebar.md\"| Writer\n\n    Writer --\u003e|\"Post\"| ViewerGen[\"Writer.WriteViewer()\\n靜態瀏覽器\"]\n    Writer --\u003e|\"Post\"| GitSave[\"Writer.SaveLastCommit()\\nGit 記錄\"]\n```\n\n## Generator 結構\n\n`Generator` 結構體集中管理所有子系統的生命週期，並累計執行統計資料：\n\n```go\ntype Generator struct {\n    Config  *config.Config\n    Runner  *claude.Runner\n    Engine  *prompt.Engine\n    Writer  *output.Writer\n    Logger  *slog.Logger\n    RootDir string // 目標專案根目錄\n\n    // 統計\n    TotalCost   float64\n    TotalPages  int\n    FailedPages int\n}\n```\n\n\u003e 來源：internal/generator/pipeline.go#L19-L31\n\n`NewGenerator` 初始化時會根據設定決定 Prompt 模板語言、建立 Claude Runner 與 Writer：\n\n```go\nfunc NewGenerator(cfg *config.Config, rootDir string, logger *slog.Logger) (*Generator, error) {\n    templateLang := cfg.Output.GetEffectiveTemplateLang()\n    engine, err := prompt.NewEngine(templateLang)\n    if err != nil {\n        return nil, err\n    }\n\n    runner := claude.NewRunner(\u0026cfg.Claude, logger)\n\n    absOutDir := cfg.Output.Dir\n    if absOutDir == \"\" {\n        absOutDir = \".doc-build\"\n    }\n\n    writer := output.NewWriter(absOutDir)\n    // ...\n}\n```\n\n\u003e 來源：internal/generator/pipeline.go#L34-L58\n\n## 四個執行階段詳解\n\n### 準備步驟（Phase 0）\n\n在四個主要階段之前，系統先處理輸出目錄：若 `--clean` 旗標為真，則清除並重建輸出目錄；否則僅確保目錄存在。\n\n```go\n// Phase 0: Setup\nclean := opts.Clean || g.Config.Output.CleanBeforeGenerate\nif clean {\n    fmt.Println(\"[0/4] 清除輸出目錄...\")\n    if !opts.DryRun {\n        if err := g.Writer.Clean(); err != nil {\n            return err\n        }\n    }\n} else {\n    if err := g.Writer.EnsureDir(); err != nil {\n        return err\n    }\n}\n```\n\n\u003e 來源：internal/generator/pipeline.go#L71-L84\n\n---\n\n### 階段一：掃描（Scan）\n\n呼叫 `scanner.Scan()` 遍歷整個專案目錄。掃描器依照設定檔中的 include/exclude glob 規則過濾檔案，並讀取 README 與入口點檔案內容：\n\n```go\n// Phase 1: Scan\nfmt.Println(\"[1/4] 掃描專案結構...\")\nscan, err := scanner.Scan(g.Config, g.RootDir)\nif err != nil {\n    return fmt.Errorf(\"掃描專案失敗: %w\", err)\n}\nfmt.Printf(\"      找到 %d 個檔案，分布於 %d 個目錄\\n\", scan.TotalFiles, scan.TotalDirs)\n```\n\n\u003e 來源：internal/generator/pipeline.go#L86-L93\n\n掃描結果 `ScanResult` 包含：\n- `Tree`：檔案樹結構（用於 Prompt 中的 `FileTree`）\n- `FileList`：所有符合規則的檔案清單\n- `ReadmeContent`：專案 README 內容\n- `EntryPointContents`：設定的入口點檔案內容\n\n若開啟 `--dry-run` 模式，系統在此階段後印出檔案樹並結束，不實際呼叫 Claude。\n\n---\n\n### 階段二：目錄產生（Catalog）\n\n`GenerateCatalog()` 建構 Prompt，將檔案樹、README、入口點等資訊傳給 Claude，由 Claude 設計整份文件的架構：\n\n```go\nfunc (g *Generator) GenerateCatalog(ctx context.Context, scan *scanner.ScanResult) (*catalog.Catalog, error) {\n    langName := config.GetLangNativeName(g.Config.Output.Language)\n    data := prompt.CatalogPromptData{\n        RepositoryName:       g.Config.Project.Name,\n        ProjectType:          g.Config.Project.Type,\n        Language:             g.Config.Output.Language,\n        LanguageName:         langName,\n        KeyFiles:             scan.KeyFiles(),\n        EntryPoints:          scan.EntryPointsFormatted(),\n        FileTree:             scanner.RenderTree(scan.Tree, 4),\n        ReadmeContent:        scan.ReadmeContent,\n    }\n\n    rendered, err := g.Engine.RenderCatalog(data)\n    // ...\n    result, err := g.Runner.RunWithRetry(ctx, claude.RunOptions{\n        Prompt:  rendered,\n        WorkDir: g.RootDir,\n    })\n    // ...\n    jsonStr, err := claude.ExtractJSONBlock(result.Content)\n    return catalog.Parse(jsonStr)\n}\n```\n\n\u003e 來源：internal/generator/catalog_phase.go#L15-L61\n\n**目錄快取機制**：若非全新產生（`--no-clean` 模式），系統會嘗試讀取 `.doc-build/_catalog.json`。若成功解析，則複用已存在的目錄，跳過 Claude 呼叫以節省費用：\n\n```go\nif !clean {\n    catJSON, readErr := g.Writer.ReadCatalogJSON()\n    if readErr == nil {\n        cat, err = catalog.Parse(catJSON)\n    }\n    if cat != nil {\n        // 載入已存目錄，跳過 Claude 呼叫\n    }\n}\n```\n\n\u003e 來源：internal/generator/pipeline.go#L102-L113\n\n---\n\n### 階段三：內容頁面產生（Content）\n\n`GenerateContent()` 對目錄中所有葉節點頁面發起並行的 Claude 呼叫。並行度由設定檔 `claude.max_concurrent` 或 `--concurrency` 旗標控制，透過 semaphore channel 限流：\n\n```go\nfunc (g *Generator) GenerateContent(ctx context.Context, scan *scanner.ScanResult, cat *catalog.Catalog, concurrency int, skipExisting bool) error {\n    items := cat.Flatten()\n    total := len(items)\n\n    // 建立連結表與連結修復器，供所有頁面共用\n    catalogTable := cat.BuildLinkTable()\n    linkFixer := output.NewLinkFixer(cat)\n\n    var done atomic.Int32\n    var failed atomic.Int32\n    var skipped atomic.Int32\n\n    eg, ctx := errgroup.WithContext(ctx)\n    sem := make(chan struct{}, concurrency)\n\n    for _, item := range items {\n        item := item\n        eg.Go(func() error {\n            if skipExisting \u0026\u0026 g.Writer.PageExists(item) {\n                skipped.Add(1)\n                // 跳過已存在的頁面\n                return nil\n            }\n            sem \u003c- struct{}{}\n            defer func() { \u003c-sem }()\n            // 呼叫 generateSinglePage()\n            err := g.generateSinglePage(ctx, scan, item, catalogTable, linkFixer, \"\")\n            // ...\n        })\n    }\n    return eg.Wait()\n}\n```\n\n\u003e 來源：internal/generator/content_phase.go#L21-L87\n\n每頁的產生流程（`generateSinglePage`）包含：\n1. 建構 `ContentPromptData`（含目錄路徑、頁面標題、連結表）\n2. 呼叫 `Runner.RunWithRetry()` 取得 Claude 回應\n3. 從 `\u003cdocument\u003e` 標籤擷取 Markdown 內容\n4. 驗證內容有效性（必須以 `#` 開頭）\n5. 呼叫 `linkFixer.FixLinks()` 修復相對連結\n6. 呼叫 `Writer.WritePage()` 寫入檔案\n\n若產生失敗，系統寫入佔位頁面（placeholder），但不中止其他頁面的產生。\n\n---\n\n### 階段四：索引與導航產生（Index）\n\n`GenerateIndex()` 不呼叫 Claude，而是根據目錄結構直接產生三種導航檔案：\n\n```go\nfunc (g *Generator) GenerateIndex(_ context.Context, cat *catalog.Catalog) error {\n    lang := g.Config.Output.Language\n\n    // 產生主首頁\n    indexContent := output.GenerateIndex(g.Config.Project.Name, g.Config.Project.Description, cat, lang)\n    if err := g.Writer.WriteFile(\"index.md\", indexContent); err != nil {\n        return err\n    }\n\n    // 產生側欄\n    sidebarContent := output.GenerateSidebar(g.Config.Project.Name, cat, lang)\n    if err := g.Writer.WriteFile(\"_sidebar.md\", sidebarContent); err != nil {\n        return err\n    }\n\n    // 為有子項目的節點產生分類索引\n    items := cat.Flatten()\n    for _, item := range items {\n        if !item.HasChildren {\n            continue\n        }\n        // ...產生分類首頁\n    }\n    return nil\n}\n```\n\n\u003e 來源：internal/generator/index_phase.go#L11-L55\n\n產生的檔案：\n- `index.md`：文件站台首頁\n- `_sidebar.md`：側邊欄導航\n- `{分類}/index.md`：每個有子頁面的分類首頁\n\n---\n\n### 後處理步驟\n\n完成四個階段後，`Generate()` 額外執行兩項後處理：\n\n```go\n// 產生靜態瀏覽器（HTML/JS/CSS + _data.js bundle）\ndocMeta := g.buildDocMeta()\nif err := g.Writer.WriteViewer(g.Config.Project.Name, docMeta); err != nil {\n    // 失敗不中止流程\n}\n\n// 若為 Git 儲存庫，儲存當前 commit hash 供增量更新使用\nif git.IsGitRepo(g.RootDir) {\n    if commit, err := git.GetCurrentCommit(g.RootDir); err == nil {\n        g.Writer.SaveLastCommit(commit)\n    }\n}\n```\n\n\u003e 來源：internal/generator/pipeline.go#L146-L164\n\n## 核心流程\n\n### 完整產生流程（Generate）\n\n```mermaid\nsequenceDiagram\n    participant CLI as cmd/generate.go\n    participant Gen as Generator\n    participant Scan as scanner\n    participant Claude as claude.Runner\n    participant Writer as output.Writer\n\n    CLI-\u003e\u003eGen: Generate(ctx, opts)\n    Gen-\u003e\u003eWriter: Clean() 或 EnsureDir()\n\n    Gen-\u003e\u003eScan: Scan(config, rootDir)\n    Scan--\u003e\u003eGen: ScanResult\n\n    alt 已有目錄快取\n        Gen-\u003e\u003eWriter: ReadCatalogJSON()\n        Writer--\u003e\u003eGen: Catalog（快取）\n    else 需要產生目錄\n        Gen-\u003e\u003eClaude: RunWithRetry(catalogPrompt)\n        Claude--\u003e\u003eGen: JSON 目錄\n        Gen-\u003e\u003eWriter: WriteCatalogJSON()\n    end\n\n    par 並行產生內容頁面\n        Gen-\u003e\u003eClaude: RunWithRetry(contentPrompt[1])\n        Gen-\u003e\u003eClaude: RunWithRetry(contentPrompt[2])\n        Gen-\u003e\u003eClaude: RunWithRetry(contentPrompt[N])\n    end\n    Claude--\u003e\u003eGen: Markdown × N\n    Gen-\u003e\u003eWriter: WritePage() × N\n\n    Gen-\u003e\u003eWriter: WriteFile(index.md)\n    Gen-\u003e\u003eWriter: WriteFile(_sidebar.md)\n    Gen-\u003e\u003eWriter: WriteViewer()\n    Gen-\u003e\u003eWriter: SaveLastCommit()\n```\n\n### 增量更新流程（Update）\n\n`Update()`（位於 `updater.go`）採用不同策略，適用於 `selfmd update` 指令：\n\n```mermaid\nflowchart TD\n    Start[\"Update(ctx, scan, prevCommit, curCommit, changedFiles)\"] --\u003e Parse[\"git.ParseChangedFiles()\\n解析變更清單\"]\n    Parse --\u003e Match[\"matchChangedFilesToDocs()\\n比對文件內容\"]\n\n    Match --\u003e|\"已匹配（Matched）\"| Determine[\"Claude 判斷\\n哪些頁面需更新\"]\n    Match --\u003e|\"未匹配（Unmatched）\"| NewPage[\"Claude 判斷\\n是否新增頁面\"]\n\n    Determine --\u003e|\"需更新的頁面清單\"| Regen\n    NewPage --\u003e|\"新頁面清單\"| AddCatalog[\"addItemToCatalog()\\n更新目錄\"]\n    AddCatalog --\u003e Regen[\"generateSinglePage() × N\\n重新產生頁面\"]\n\n    Regen --\u003e IndexUpdate[\"GenerateIndex()\\n更新索引（若有新頁面）\"]\n    IndexUpdate --\u003e SaveCommit[\"Writer.SaveLastCommit()\\n記錄 commit\"]\n```\n\n## 使用範例\n\n`GenerateOptions` 可控制管線執行模式：\n\n```go\nopts := generator.GenerateOptions{\n    Clean:       clean,       // 是否清除輸出目錄\n    DryRun:      dryRun,      // 只掃描，不呼叫 Claude\n    Concurrency: concurrencyNum, // 並行度（0 = 使用設定值）\n}\n\nreturn gen.Generate(ctx, opts)\n```\n\n\u003e 來源：cmd/generate.go#L89-L95\n\n並行度的優先順序為：CLI `--concurrency` 旗標 \u003e `selfmd.yaml` 中 `claude.max_concurrent` 設定。\n\n```go\n// Phase 3: Generate Content\nconcurrency := g.Config.Claude.MaxConcurrent\nif opts.Concurrency \u003e 0 {\n    concurrency = opts.Concurrency\n}\nfmt.Printf(\"[3/4] 產生內容頁面（並行度：%d）...\\n\", concurrency)\n```\n\n\u003e 來源：internal/generator/pipeline.go#L130-L134\n\n## 費用追蹤\n\n每次 Claude 呼叫的費用會累計到 `Generator.TotalCost`，並在執行完成後於終端輸出摘要：\n\n```\n========================================\n文件產生完成！\n  輸出目錄：.doc-build\n  頁面數量：42 成功\n  總耗時：3m20s\n  總費用：$0.1234 USD\n========================================\n```\n\n\u003e 來源：internal/generator/pipeline.go#L166-L179\n\n## 相關連結\n\n- [系統架構](../index.md)\n- [模組依賴關係](../module-dependencies/index.md)\n- [文件產生管線（核心模組）](../../core-modules/generator/index.md)\n- [目錄產生階段](../../core-modules/generator/catalog-phase/index.md)\n- [內容頁面產生階段](../../core-modules/generator/content-phase/index.md)\n- [索引與導航產生階段](../../core-modules/generator/index-phase/index.md)\n- [翻譯階段](../../core-modules/generator/translate-phase/index.md)\n- [增量更新](../../core-modules/incremental-update/index.md)\n- [selfmd generate 指令](../../cli/cmd-generate/index.md)\n\n## 參考檔案\n\n| 檔案路徑 | 說明 |\n|----------|------|\n| `internal/generator/pipeline.go` | `Generator` 結構定義、`Generate()` 主流程協調器 |\n| `internal/generator/catalog_phase.go` | 階段二：目錄產生邏輯、Claude Prompt 建構 |\n| `internal/generator/content_phase.go` | 階段三：並行內容頁面產生、`generateSinglePage()` |\n| `internal/generator/index_phase.go` | 階段四：索引與側欄導航產生 |\n| `internal/generator/translate_phase.go` | 翻譯管線（`Translate()`）與多語言支援 |\n| `internal/generator/updater.go` | 增量更新流程（`Update()`）、Git 變更比對邏輯 |\n| `internal/scanner/scanner.go` | 專案掃描器、`Scan()` 函式 |\n| `internal/catalog/catalog.go` | `Catalog`、`FlatItem` 結構定義與操作 |\n| `internal/claude/runner.go` | Claude CLI 執行器、`RunWithRetry()` |\n| `internal/output/writer.go` | 輸出寫入器、檔案管理、catalog JSON 持久化 |\n| `internal/git/git.go` | Git 整合工具、變更檔案解析 |\n| `cmd/generate.go` | `selfmd generate` CLI 入口點 |","cli/cmd-generate/index.md":"# selfmd generate\n\n執行完整的四階段文件產生流程，掃描專案原始碼並透過 Claude CLI 自動產生結構化的 Wiki 風格技術文件。\n\n## 概述\n\n`selfmd generate` 是 selfmd 的核心指令，負責從零開始（或增量地）產生完整的專案技術文件。執行時，指令會依序完成以下工作：\n\n1. 驗證 Claude CLI 環境是否就緒\n2. 載入 `selfmd.yaml` 設定檔\n3. 掃描專案目錄結構與原始碼\n4. 呼叫 Claude AI 產生文件目錄（Catalog）\n5. 以並行方式為每個目錄項目產生內容頁面\n6. 產生導航索引與靜態文件瀏覽器\n\n**增量產生**：若輸出目錄中已存在有效頁面，且未使用 `--clean` 旗標，系統會自動跳過這些頁面，僅產生缺失或失敗的部分，大幅節省 API 費用與執行時間。\n\n## 用法\n\n```sh\nselfmd generate [flags]\n```\n\n\u003e 來源：`cmd/generate.go#L23-L32`\n\n## 旗標（Flags）\n\n| 旗標 | 型別 | 預設值 | 說明 |\n|------|------|--------|------|\n| `--clean` | bool | `false` | 強制清除輸出目錄後重新產生所有頁面 |\n| `--no-clean` | bool | `false` | 覆蓋設定檔的 `clean_before_generate`，保留現有頁面 |\n| `--dry-run` | bool | `false` | 僅掃描並顯示檔案樹，不呼叫 Claude 也不寫入任何檔案 |\n| `--concurrency` | int | `0` | 覆蓋設定檔的 `claude.max_concurrent` 並行度設定 |\n| `-c, --config` | string | `selfmd.yaml` | 設定檔路徑（全域旗標，繼承自 rootCmd） |\n| `-v, --verbose` | bool | `false` | 顯示 Debug 層級的詳細日誌（全域旗標） |\n| `-q, --quiet` | bool | `false` | 僅顯示錯誤訊息（全域旗標） |\n\n### `--clean` 與 `--no-clean` 的優先順序\n\n最終的 clean 行為由以下規則決定（優先順序由高至低）：\n\n```\n--no-clean flag → clean = false（強制保留）\n--clean flag    → clean = true（強制清除）\nconfig 設定     → output.clean_before_generate 的值\n```\n\n\u003e 來源：`cmd/generate.go#L80-L87`\n\n## 架構\n\n```mermaid\nflowchart TD\n    A[\"generateCmd\\n(cobra.Command)\"] --\u003e B[\"runGenerate()\"]\n    B --\u003e C[\"claude.CheckAvailable()\"]\n    B --\u003e D[\"config.Load()\"]\n    B --\u003e E[\"generator.NewGenerator()\"]\n    E --\u003e F[\"prompt.NewEngine()\"]\n    E --\u003e G[\"claude.NewRunner()\"]\n    E --\u003e H[\"output.NewWriter()\"]\n    B --\u003e I[\"gen.Generate(ctx, opts)\"]\n\n    I --\u003e P0[\"Phase 0\\nSetup / Clean\"]\n    I --\u003e P1[\"Phase 1\\nscanner.Scan()\"]\n    I --\u003e P2[\"Phase 2\\nGenerateCatalog()\"]\n    I --\u003e P3[\"Phase 3\\nGenerateContent()\"]\n    I --\u003e P4[\"Phase 4\\nGenerateIndex()\"]\n    I --\u003e P5[\"WriteViewer()\"]\n    I --\u003e P6[\"SaveLastCommit()\"]\n\n    P3 --\u003e W[\"errgroup\\n並行 worker\"]\n    W --\u003e S[\"semaphore\\n(max_concurrent)\"]\n    S --\u003e Claude[\"claude.Runner\\n.RunWithRetry()\"]\n```\n\n## 四階段產生流程\n\n### 階段 0：初始化設定\n\n根據 `clean` 選項決定輸出目錄的處理方式：\n\n```go\nif clean {\n    fmt.Println(\"[0/4] 清除輸出目錄...\")\n    if !opts.DryRun {\n        if err := g.Writer.Clean(); err != nil {\n            return err\n        }\n    }\n} else {\n    if err := g.Writer.EnsureDir(); err != nil {\n        return err\n    }\n}\n```\n\n\u003e 來源：`internal/generator/pipeline.go#L72-L84`\n\n`Writer.Clean()` 會呼叫 `os.RemoveAll()` 刪除整個輸出目錄後重建，`EnsureDir()` 則以 `os.MkdirAll()` 確保目錄存在。\n\n---\n\n### 階段 1：掃描專案結構\n\n```go\nscan, err := scanner.Scan(g.Config, g.RootDir)\n```\n\n\u003e 來源：`internal/generator/pipeline.go#L88-L92`\n\n掃描器遞迴走訪專案目錄，依據設定檔中的 `targets.include` 與 `targets.exclude` glob 模式篩選檔案，同時讀取 `README.md` 與設定的進入點（entry points）內容。\n\n**Dry Run 行為**：若指定 `--dry-run`，掃描完成後僅顯示檔案樹（深度 3 層）並結束，不執行後續任何 Claude 呼叫：\n\n```go\nif opts.DryRun {\n    fmt.Println(\"\\n[Dry Run] 檔案樹：\")\n    fmt.Println(scanner.RenderTree(scan.Tree, 3))\n    fmt.Println(\"[Dry Run] 將不會執行 Claude 呼叫。\")\n    return nil\n}\n```\n\n\u003e 來源：`internal/generator/pipeline.go#L94-L99`\n\n---\n\n### 階段 2：產生文件目錄（Catalog）\n\n目錄是文件結構的骨架，定義了所有頁面的標題、路徑與層級關係。\n\n```go\n// 優先嘗試重用既有目錄（非 clean 模式）\nif !clean {\n    catJSON, readErr := g.Writer.ReadCatalogJSON()\n    if readErr == nil {\n        cat, err = catalog.Parse(catJSON)\n    }\n    // ...\n}\n// 若無既有目錄，呼叫 Claude 產生\nif cat == nil {\n    cat, err = g.GenerateCatalog(ctx, scan)\n    // 儲存為 _catalog.json 供下次使用\n    g.Writer.WriteCatalogJSON(cat)\n}\n```\n\n\u003e 來源：`internal/generator/pipeline.go#L102-L127`\n\n`GenerateCatalog()` 將掃描結果組裝為 prompt 後呼叫 Claude CLI，從回應中擷取 JSON 格式的目錄結構：\n\n```go\nresult, err := g.Runner.RunWithRetry(ctx, claude.RunOptions{\n    Prompt:  rendered,\n    WorkDir: g.RootDir,\n})\n// ...\njsonStr, err := claude.ExtractJSONBlock(result.Content)\ncat, err := catalog.Parse(jsonStr)\n```\n\n\u003e 來源：`internal/generator/catalog_phase.go#L37-L58`\n\n---\n\n### 階段 3：並行產生內容頁面\n\n這是最耗時的階段，系統以並行方式為每個目錄項目呼叫 Claude 產生完整的 Markdown 文件：\n\n```go\neg, ctx := errgroup.WithContext(ctx)\nsem := make(chan struct{}, concurrency)\n\nfor _, item := range items {\n    item := item\n    eg.Go(func() error {\n        // 跳過已存在的頁面（非 clean 模式）\n        if skipExisting \u0026\u0026 g.Writer.PageExists(item) {\n            skipped.Add(1)\n            return nil\n        }\n        sem \u003c- struct{}{}\n        defer func() { \u003c-sem }()\n        // ...呼叫 Claude 產生頁面...\n    })\n}\n```\n\n\u003e 來源：`internal/generator/content_phase.go#L36-L73`\n\n**並行度控制**：使用 channel 作為 semaphore，限制同時執行的 Claude 呼叫數量。預設值來自設定檔的 `claude.max_concurrent`（預設 `3`），可用 `--concurrency` 旗標覆蓋。\n\n**失敗容錯**：單一頁面產生失敗不會中止整體流程。失敗時會寫入佔位頁面（placeholder），提示使用者重新執行：\n\n```go\nfunc (g *Generator) writePlaceholder(item catalog.FlatItem, genErr error) {\n    content := fmt.Sprintf(\"# %s\\n\\n\u003e 此頁面產生失敗，請重新執行 `selfmd generate`。\\n\u003e\\n\u003e 錯誤：%v\\n\", item.Title, genErr)\n    g.Writer.WritePage(item, content)\n}\n```\n\n\u003e 來源：`internal/generator/content_phase.go#L159-L164`\n\n**格式驗證與重試**：每個頁面最多嘗試 2 次，若 Claude 回應缺少 `\u003cdocument\u003e` 標籤或不是以 `#` 開頭的有效 Markdown，會自動重試：\n\n```go\ncontent, extractErr := claude.ExtractDocumentTag(result.Content)\n// ...\nif content == \"\" || !strings.HasPrefix(content, \"#\") {\n    // 重試\n}\n```\n\n\u003e 來源：`internal/generator/content_phase.go#L126-L146`\n\n---\n\n### 階段 4：產生導航與索引\n\n```go\nfunc (g *Generator) GenerateIndex(_ context.Context, cat *catalog.Catalog) error {\n    // 產生 index.md（文件首頁）\n    output.GenerateIndex(...)\n    g.Writer.WriteFile(\"index.md\", indexContent)\n\n    // 產生 _sidebar.md（側邊欄導航）\n    output.GenerateSidebar(...)\n    g.Writer.WriteFile(\"_sidebar.md\", sidebarContent)\n\n    // 為有子項目的分類產生索引頁\n    for _, item := range items {\n        if item.HasChildren { ... }\n    }\n}\n```\n\n\u003e 來源：`internal/generator/index_phase.go#L11-L55`\n\n---\n\n### 後置處理\n\n階段 4 完成後，`Generate()` 還會執行：\n\n1. **產生靜態瀏覽器**：呼叫 `Writer.WriteViewer()` 產生 `index.html` 與相關資源，支援直接在瀏覽器開啟瀏覽文件。\n2. **記錄 Git commit**：若當前目錄為 Git 倉庫，儲存目前的 commit hash 至 `_last_commit`，供 `selfmd update` 的增量更新使用。\n\n```go\nif git.IsGitRepo(g.RootDir) {\n    if commit, err := git.GetCurrentCommit(g.RootDir); err == nil {\n        g.Writer.SaveLastCommit(commit)\n    }\n}\n```\n\n\u003e 來源：`internal/generator/pipeline.go#L158-L164`\n\n## 核心流程\n\n```mermaid\nsequenceDiagram\n    participant CLI as \"selfmd generate\"\n    participant Gen as \"Generator\"\n    participant Scanner as \"scanner.Scan()\"\n    participant Claude as \"claude.Runner\"\n    participant Writer as \"output.Writer\"\n\n    CLI-\u003e\u003eClaude: CheckAvailable()\n    CLI-\u003e\u003eGen: NewGenerator(cfg, rootDir)\n    CLI-\u003e\u003eGen: Generate(ctx, opts)\n\n    Gen-\u003e\u003eWriter: Clean() / EnsureDir()\n    Gen-\u003e\u003eScanner: Scan(cfg, rootDir)\n    Scanner--\u003e\u003eGen: ScanResult\n\n    alt 無既有目錄\n        Gen-\u003e\u003eClaude: RunWithRetry（Catalog Prompt）\n        Claude--\u003e\u003eGen: catalog JSON\n    else 有既有目錄\n        Gen-\u003e\u003eWriter: ReadCatalogJSON()\n        Writer--\u003e\u003eGen: catalog JSON\n    end\n\n    loop 並行（max_concurrent goroutines）\n        Gen-\u003e\u003eClaude: RunWithRetry（Content Prompt）\n        Claude--\u003e\u003eGen: Markdown content\n        Gen-\u003e\u003eWriter: WritePage(item, content)\n    end\n\n    Gen-\u003e\u003eWriter: WriteFile(\"index.md\")\n    Gen-\u003e\u003eWriter: WriteFile(\"_sidebar.md\")\n    Gen-\u003e\u003eWriter: WriteViewer()\n    Gen-\u003e\u003eWriter: SaveLastCommit()\n```\n\n## 輸出結構\n\n成功執行後，`--output.dir`（預設 `.doc-build/`）目錄下會產生以下檔案：\n\n```\n.doc-build/\n├── index.html          # 靜態文件瀏覽器入口\n├── index.md            # 文件首頁（Markdown）\n├── _sidebar.md         # 側邊欄導航\n├── _catalog.json       # 目錄結構快取（供增量更新使用）\n├── _last_commit        # Git commit hash 記錄\n├── \u003csection\u003e/\n│   └── \u003csubsection\u003e/\n│       └── index.md   # 各章節文件頁面\n└── \u003clang\u003e/             # 翻譯語言目錄（若有次要語言）\n    ├── index.md\n    └── ...\n```\n\n## 使用範例\n\n### 基本用法\n\n```sh\n# 標準產生流程（增量，跳過已存在頁面）\nselfmd generate\n\n# 強制重新產生所有頁面\nselfmd generate --clean\n\n# 預覽模式：只顯示掃描結果，不呼叫 Claude\nselfmd generate --dry-run\n```\n\n### 調整並行度\n\n```sh\n# 提高並行度加快產生速度（注意 Claude API 限速）\nselfmd generate --concurrency 5\n\n# 降低並行度減少 API 請求速率\nselfmd generate --concurrency 1\n```\n\n### 使用自訂設定檔\n\n```sh\nselfmd generate --config ./configs/my-project.yaml\n```\n\n### 搭配日誌旗標\n\n```sh\n# 顯示詳細 Debug 日誌（含每次 Claude 呼叫的詳細資訊）\nselfmd generate --verbose\n\n# 靜默模式（僅顯示錯誤）\nselfmd generate --quiet\n```\n\n## 執行輸出範例\n\n成功執行時，終端機會顯示以下進度輸出：\n\n```\n[0/4] 清除輸出目錄...\n[1/4] 掃描專案結構...\n      找到 42 個檔案，分布於 12 個目錄\n[2/4] 產生文件目錄...\n      呼叫 Claude 產生目錄... 完成（8.3s，$0.0025）\n      目錄：6 個章節，18 個項目\n[3/4] 產生內容頁面（並行度：3）...\n      [1/18] 概述（overview）... 完成（12.5s，$0.0041）\n      [2/18] 快速開始（getting-started）... 完成（10.2s，$0.0038）\n      ...\n[4/4] 產生導航與索引...\n產生文件瀏覽器...\n      完成，開啟 .doc-build/index.html 即可瀏覽\n\n========================================\n文件產生完成！\n  輸出目錄：.doc-build\n  頁面數量：18 成功\n  總耗時：3m 24s\n  總費用：$0.0842 USD\n========================================\n```\n\n## 前置條件\n\n執行 `selfmd generate` 前，必須滿足以下條件：\n\n1. **Claude CLI 已安裝**：系統 PATH 中存在 `claude` 指令（由 `claude.CheckAvailable()` 驗證）\n2. **設定檔存在**：工作目錄中存在 `selfmd.yaml`（或以 `--config` 指定其他路徑）\n3. **已執行 `selfmd init`**：初始化產生設定檔\n\n## 相關連結\n\n- [CLI 指令參考](../index.md)\n- [selfmd init](../cmd-init/index.md) — 初始化設定檔\n- [selfmd update](../cmd-update/index.md) — 增量更新（僅更新變更頁面）\n- [selfmd translate](../cmd-translate/index.md) — 翻譯文件至其他語言\n- [整體流程與四階段管線](../../architecture/pipeline/index.md) — 深入了解管線架構\n- [文件產生管線](../../core-modules/generator/index.md) — Generator 模組詳解\n- [Claude CLI 執行器](../../core-modules/claude-runner/index.md) — Runner 模組詳解\n- [專案掃描器](../../core-modules/scanner/index.md) — Scanner 模組詳解\n- [設定說明](../../configuration/index.md) — selfmd.yaml 完整設定參考\n\n## 參考檔案\n\n| 檔案路徑 | 說明 |\n|----------|------|\n| `cmd/generate.go` | generate 指令定義、旗標宣告、`runGenerate()` 進入點 |\n| `cmd/root.go` | rootCmd 定義，全域旗標（`--config`、`--verbose`、`--quiet`） |\n| `internal/generator/pipeline.go` | `Generator` 結構定義、`NewGenerator()`、`Generate()` 主流程 |\n| `internal/generator/catalog_phase.go` | `GenerateCatalog()` 實作：組裝 prompt 並呼叫 Claude 產生目錄 |\n| `internal/generator/content_phase.go` | `GenerateContent()` 實作：並行產生頁面、重試邏輯、佔位頁面 |\n| `internal/generator/index_phase.go` | `GenerateIndex()` 實作：產生 `index.md`、`_sidebar.md` 及分類索引 |\n| `internal/generator/translate_phase.go` | `Translate()` 實作（翻譯管線，由 `selfmd translate` 呼叫） |\n| `internal/config/config.go` | `Config` 結構定義、`Load()`、`DefaultConfig()`、驗證邏輯 |\n| `internal/scanner/scanner.go` | `Scan()` 實作：目錄走訪、include/exclude 過濾、README 讀取 |\n| `internal/claude/runner.go` | `Runner.Run()`、`RunWithRetry()`、`CheckAvailable()` |\n| `internal/output/writer.go` | `Writer` 結構：`WritePage()`、`Clean()`、`WriteCatalogJSON()` 等 |","cli/cmd-init/index.md":"# selfmd init\n\n初始化指令，掃描當前目錄並自動偵測專案類型，產生 `selfmd.yaml` 設定檔。\n\n## 概述\n\n`selfmd init` 是使用 selfmd 的第一步。執行後，它會：\n\n1. 檢查當前目錄是否已有設定檔（預設為 `selfmd.yaml`）\n2. 呼叫 `detectProject()` 自動辨識專案類型（如 Go、Rust、Node.js、Python 等）\n3. 根據偵測結果與預設值，透過 `config.DefaultConfig()` 建立完整設定\n4. 將設定序列化為 YAML 並寫入磁碟\n\n產生的 `selfmd.yaml` 是後續所有 selfmd 指令的執行基礎，使用者可在初始化後依需求手動調整。\n\n---\n\n## 架構\n\n```mermaid\nflowchart TD\n    User[\"使用者執行 selfmd init\"]\n    initCmd[\"initCmd\\ncmd/init.go\"]\n    checkExists{\"selfmd.yaml\\n已存在？\"}\n    forceFlag{\"--force\\n旗標？\"}\n    errorExit[\"錯誤退出\"]\n    DefaultConfig[\"config.DefaultConfig()\\ninternal/config/config.go\"]\n    detectProject[\"detectProject()\\ncmd/init.go\"]\n    fillConfig[\"填入 ProjectName\\nProjectType\\nEntryPoints\"]\n    Save[\"cfg.Save(cfgFile)\\ninternal/config/config.go\"]\n    printSummary[\"印出設定摘要\"]\n\n    User --\u003e initCmd\n    initCmd --\u003e checkExists\n    checkExists -- 是 --\u003e forceFlag\n    forceFlag -- 否 --\u003e errorExit\n    forceFlag -- 是 --\u003e DefaultConfig\n    checkExists -- 否 --\u003e DefaultConfig\n    DefaultConfig --\u003e detectProject\n    detectProject --\u003e fillConfig\n    fillConfig --\u003e Save\n    Save --\u003e printSummary\n```\n\n---\n\n## 旗標與參數\n\n| 旗標 | 類型 | 預設值 | 說明 |\n|------|------|--------|------|\n| `--force` | bool | `false` | 強制覆蓋已存在的設定檔 |\n| `--config` / `-c` | string | `selfmd.yaml` | 指定設定檔路徑（繼承自根指令） |\n\n`--config` 旗標由根指令 `rootCmd` 定義，所有子指令皆可使用：\n\n```go\nrootCmd.PersistentFlags().StringVarP(\u0026cfgFile, \"config\", \"c\", \"selfmd.yaml\", \"設定檔路徑\")\n```\n\n\u003e 來源：cmd/root.go#L31\n\n---\n\n## 專案類型自動偵測\n\n`detectProject()` 函式依序掃描當前目錄中的特定檔案，藉此推斷專案類型與入口點：\n\n```go\nfunc detectProject() (projectType string, entryPoints []string) {\n\tchecks := []struct {\n\t\tfile       string\n\t\tpType      string\n\t\tentries    []string\n\t}{\n\t\t{\"go.mod\", \"backend\", []string{\"main.go\", \"cmd/root.go\"}},\n\t\t{\"Cargo.toml\", \"backend\", []string{\"src/main.rs\", \"src/lib.rs\"}},\n\t\t{\"package.json\", \"frontend\", []string{\"src/index.ts\", \"src/index.js\", \"src/main.ts\", \"src/App.tsx\"}},\n\t\t{\"pom.xml\", \"backend\", []string{\"src/main/java\"}},\n\t\t{\"build.gradle\", \"backend\", []string{\"src/main/java\"}},\n\t\t{\"requirements.txt\", \"backend\", []string{\"main.py\", \"app.py\", \"src/main.py\"}},\n\t\t{\"pyproject.toml\", \"backend\", []string{\"src/main.py\", \"main.py\"}},\n\t\t{\"composer.json\", \"backend\", []string{\"public/index.php\", \"src/Kernel.php\"}},\n\t\t{\"Gemfile\", \"backend\", []string{\"config/application.rb\", \"app/\"}},\n\t}\n\t// ...\n}\n```\n\n\u003e 來源：cmd/init.go#L60-L76\n\n### 偵測邏輯\n\n1. **依序檢查**：依上表順序逐一偵測，命中第一個符合的即停止\n2. **入口點過濾**：候選入口點清單中只保留實際存在的檔案\n3. **Fullstack 判斷**：若偵測到 `package.json`（frontend），再額外確認 `go.mod` 或 `server/` 目錄是否存在，若有則改標記為 `fullstack`\n4. **預設類型**：若所有規則均不符合，回傳 `\"library\"` 與空入口點\n\n```mermaid\nflowchart TD\n    start[\"開始偵測\"]\n    gomod{\"go.mod\\n存在？\"}\n    cargo{\"Cargo.toml\\n存在？\"}\n    pkg{\"package.json\\n存在？\"}\n    others{\"其他指標\\n檔案存在？\"}\n    fallback[\"type: library\\nentries: []\"]\n    backendGo[\"type: backend\"]\n    backendCargo[\"type: backend\"]\n    frontendCheck{\"同時有\\ngo.mod 或 server/？\"}\n    fullstack[\"type: fullstack\"]\n    frontend[\"type: frontend\"]\n    backendOther[\"type: backend\"]\n\n    start --\u003e gomod\n    gomod -- 是 --\u003e backendGo\n    gomod -- 否 --\u003e cargo\n    cargo -- 是 --\u003e backendCargo\n    cargo -- 否 --\u003e pkg\n    pkg -- 是 --\u003e frontendCheck\n    frontendCheck -- 是 --\u003e fullstack\n    frontendCheck -- 否 --\u003e frontend\n    pkg -- 否 --\u003e others\n    others -- 是 --\u003e backendOther\n    others -- 否 --\u003e fallback\n```\n\n---\n\n## 預設設定值\n\n`config.DefaultConfig()` 回傳的預設值如下：\n\n```go\nfunc DefaultConfig() *Config {\n\treturn \u0026Config{\n\t\tProject: ProjectConfig{\n\t\t\tName: filepath.Base(mustGetwd()),\n\t\t\tType: \"backend\",\n\t\t},\n\t\tTargets: TargetsConfig{\n\t\t\tInclude: []string{\"src/**\", \"pkg/**\", \"cmd/**\", \"internal/**\", \"lib/**\", \"app/**\"},\n\t\t\tExclude: []string{\n\t\t\t\t\"vendor/**\", \"node_modules/**\", \".git/**\", \".doc-build/**\",\n\t\t\t\t\"**/*.pb.go\", \"**/generated/**\", \"dist/**\", \"build/**\",\n\t\t\t},\n\t\t\tEntryPoints: []string{},\n\t\t},\n\t\tOutput: OutputConfig{\n\t\t\tDir:                 \".doc-build\",\n\t\t\tLanguage:            \"zh-TW\",\n\t\t\tSecondaryLanguages:  []string{},\n\t\t\tCleanBeforeGenerate: false,\n\t\t},\n\t\tClaude: ClaudeConfig{\n\t\t\tModel:          \"sonnet\",\n\t\t\tMaxConcurrent:  3,\n\t\t\tTimeoutSeconds: 300,\n\t\t\tMaxRetries:     2,\n\t\t\tAllowedTools:   []string{\"Read\", \"Glob\", \"Grep\"},\n\t\t\tExtraArgs:      []string{},\n\t\t},\n\t\tGit: GitConfig{\n\t\t\tEnabled:    true,\n\t\t\tBaseBranch: \"main\",\n\t\t},\n\t}\n}\n```\n\n\u003e 來源：internal/config/config.go#L96-L129\n\n`init` 指令在預設值基礎上，以偵測結果覆寫以下三個欄位：\n\n| 欄位 | 覆寫來源 |\n|------|----------|\n| `project.name` | `filepath.Base(mustCwd())` — 當前目錄名稱 |\n| `project.type` | `detectProject()` 偵測結果 |\n| `targets.entry_points` | `detectProject()` 偵測到的實際入口點 |\n\n---\n\n## 核心流程\n\n```mermaid\nsequenceDiagram\n    participant CLI as 使用者終端\n    participant initCmd as initCmd（cmd/init.go）\n    participant config as config（internal/config）\n    participant OS as 作業系統檔案系統\n\n    CLI-\u003e\u003einitCmd: selfmd init [--force]\n    initCmd-\u003e\u003eOS: os.Stat(cfgFile)\n    alt 設定檔已存在且未帶 --force\n        initCmd--\u003e\u003eCLI: 錯誤：設定檔已存在\n    end\n    initCmd-\u003e\u003econfig: config.DefaultConfig()\n    config--\u003e\u003einitCmd: *Config（預設值）\n    initCmd-\u003e\u003eOS: 逐一 os.Stat 偵測指標檔案\n    OS--\u003e\u003einitCmd: 存在/不存在\n    initCmd-\u003e\u003einitCmd: 決定 projectType 與 entryPoints\n    initCmd-\u003e\u003einitCmd: 填入 cfg.Project / cfg.Targets\n    initCmd-\u003e\u003econfig: cfg.Save(cfgFile)\n    config-\u003e\u003eOS: yaml.Marshal → os.WriteFile\n    OS--\u003e\u003econfig: 寫入成功\n    config--\u003e\u003einitCmd: nil\n    initCmd--\u003e\u003eCLI: 印出設定摘要\n```\n\n---\n\n## 輸出摘要說明\n\n指令執行成功後，終端會印出以下資訊：\n\n```\n已建立設定檔：selfmd.yaml\n  專案名稱：my-project\n  專案類型：backend\n  輸出目錄：.doc-build\n  文件語言：zh-TW\n  入口檔案：main.go, cmd/root.go\n\n請根據專案需求編輯設定檔後，執行 selfmd generate 產生文件。\n```\n\n\u003e 來源：cmd/init.go#L43-L56\n\n---\n\n## 使用範例\n\n### 基本初始化\n\n```bash\nselfmd init\n```\n\n在當前目錄產生 `selfmd.yaml`。若偵測到 `go.mod` 與 `cmd/root.go`，設定檔將包含：\n\n```yaml\nproject:\n  name: my-project\n  type: backend\ntargets:\n  entry_points:\n    - cmd/root.go\n```\n\n### 強制覆蓋既有設定檔\n\n```bash\nselfmd init --force\n```\n\n\u003e 來源：cmd/init.go#L28-L30\n\n### 指定自訂設定檔路徑\n\n```bash\nselfmd init --config config/selfmd.yaml\n```\n\n---\n\n## 注意事項\n\n- `selfmd init` 不會覆寫 `targets.include` 與 `targets.exclude`，這兩個欄位維持預設值，需使用者視需求手動調整\n- 若專案同時符合多個偵測條件（如同時有 `go.mod` 與 `package.json`），僅最先命中的規則生效\n- 產生的 `selfmd.yaml` 使用 YAML v3 格式序列化\n\n---\n\n## 相關連結\n\n- [初始化設定](../../getting-started/init/index.md)\n- [selfmd.yaml 結構總覽](../../configuration/config-overview/index.md)\n- [專案與掃描目標設定](../../configuration/project-targets/index.md)\n- [selfmd generate](../cmd-generate/index.md)\n- [CLI 指令參考](../index.md)\n\n---\n\n## 參考檔案\n\n| 檔案路徑 | 說明 |\n|----------|------|\n| `cmd/init.go` | `init` 指令實作、`detectProject()` 偵測邏輯 |\n| `cmd/root.go` | 根指令定義，含 `--config`、`--verbose`、`--quiet` 全域旗標 |\n| `internal/config/config.go` | `Config` 結構定義、`DefaultConfig()`、`Save()`、`Load()` 實作 |","cli/cmd-translate/index.md":"# selfmd translate\n\n將主要語言的已產生文件，透過 Claude CLI 翻譯成設定檔中定義的次要語言，並儲存至對應的語言子目錄。\n\n## 概述\n\n`selfmd translate` 指令讀取已由 `selfmd generate` 產生的主要語言文件，逐頁呼叫 Claude CLI 進行翻譯，並將翻譯結果寫入 `.doc-build/{語言代碼}/` 子目錄。\n\n此指令的核心前提是：**主要語言文件必須已存在**。翻譯流程不會重新掃描原始碼，而是直接以現有的 Markdown 頁面作為翻譯來源。\n\n關鍵特性：\n\n- **增量翻譯**：預設自動跳過已存在的翻譯頁面，只翻譯尚未翻譯的內容\n- **多目標語言**：單次執行可同時翻譯至多個次要語言\n- **並行翻譯**：使用 semaphore 並行模式加速翻譯，並行度可透過設定或參數控制\n- **目錄同步**：翻譯完成後自動建立各語言版本的目錄（`_catalog.json`）、首頁（`index.md`）及側欄（`_sidebar.md`）\n- **費用追蹤**：翻譯完成後顯示每頁耗時與總 API 費用\n\n翻譯所使用的 Prompt 模板（`translate.tmpl`）為**語言無關的共用模板**，與主要語言的內容生成模板分開維護。\n\n## 架構\n\n```mermaid\nflowchart TD\n    translateCmd[\"translateCmd\\ncmd/translate.go\"]\n    checkAvailable[\"claude.CheckAvailable()\"]\n    loadConfig[\"config.Load()\"]\n    validateLangs[\"驗證目標語言\"]\n    newGenerator[\"generator.NewGenerator()\"]\n    genTranslate[\"Generator.Translate()\"]\n\n    readCatalog[\"Writer.ReadCatalogJSON()\\n讀取主目錄\"]\n    parseCatalog[\"catalog.Parse()\"]\n    flattenItems[\"cat.Flatten()\\n取得所有頁面\"]\n\n    forEachLang[\"for each targetLang\"]\n    translatePages[\"translatePages()\\n並行翻譯葉節點頁面\"]\n    buildTranslatedCatalog[\"buildTranslatedCatalog()\\n更新翻譯標題\"]\n    writeArtifacts[\"寫入 _catalog.json\\nindex.md\\n_sidebar.md\\n分類索引頁\"]\n    writeViewer[\"Writer.WriteViewer()\\n重新產生靜態瀏覽器\"]\n\n    subgraph perPage[\"每頁翻譯（並行）\"]\n        checkExists[\"PageExists?\\n已存在則跳過\"]\n        readSource[\"Writer.ReadPage()\\n讀取原始頁面\"]\n        renderPrompt[\"Engine.RenderTranslate()\\n渲染翻譯 Prompt\"]\n        callClaude[\"Runner.RunWithRetry()\\n呼叫 Claude CLI\"]\n        extractDoc[\"claude.ExtractDocumentTag()\\n擷取 document 標籤\"]\n        extractTitle[\"extractTitle()\\n擷取翻譯標題\"]\n        writePage[\"langWriter.WritePage()\\n寫入翻譯頁面\"]\n    end\n\n    translateCmd --\u003e checkAvailable\n    translateCmd --\u003e loadConfig\n    loadConfig --\u003e validateLangs\n    validateLangs --\u003e newGenerator\n    newGenerator --\u003e genTranslate\n    genTranslate --\u003e readCatalog\n    readCatalog --\u003e parseCatalog\n    parseCatalog --\u003e flattenItems\n    flattenItems --\u003e forEachLang\n    forEachLang --\u003e translatePages\n    translatePages --\u003e perPage\n    checkExists --\u003e|\"--force 或不存在\"| readSource\n    checkExists --\u003e|\"已存在\"| skip[\"跳過\"]\n    readSource --\u003e renderPrompt\n    renderPrompt --\u003e callClaude\n    callClaude --\u003e extractDoc\n    extractDoc --\u003e extractTitle\n    extractTitle --\u003e writePage\n    translatePages --\u003e buildTranslatedCatalog\n    buildTranslatedCatalog --\u003e writeArtifacts\n    writeArtifacts --\u003e forEachLang\n    forEachLang --\u003e writeViewer\n```\n\n## 指令語法\n\n```\nselfmd translate [flags]\n```\n\n### 旗標（Flags）\n\n| 旗標 | 類型 | 預設值 | 說明 |\n|------|------|--------|------|\n| `--lang` | `[]string` | `nil`（所有次要語言） | 限定只翻譯指定的語言代碼，可重複或逗號分隔 |\n| `--force` | `bool` | `false` | 強制重新翻譯已存在的翻譯檔案 |\n| `--concurrency` | `int` | `0`（使用設定值） | 並行翻譯工作數，覆蓋 `claude.max_concurrent` |\n| `-c, --config` | `string` | `selfmd.yaml` | 設定檔路徑（繼承自 root） |\n| `-v, --verbose` | `bool` | `false` | 顯示詳細 debug 輸出 |\n| `-q, --quiet` | `bool` | `false` | 僅顯示錯誤訊息 |\n\n\u003e 來源：`cmd/translate.go#L33-L37`\n\n### 使用範例\n\n```bash\n# 翻譯所有設定的次要語言\nselfmd translate\n\n# 只翻譯英文版本\nselfmd translate --lang en-US\n\n# 翻譯多個語言\nselfmd translate --lang en-US,ja-JP\n\n# 強制重新翻譯（即使已存在）\nselfmd translate --force\n\n# 提高並行度加速翻譯\nselfmd translate --concurrency 5\n```\n\n## 前置條件\n\n執行 `selfmd translate` 前，必須滿足以下條件：\n\n1. **已安裝 Claude CLI**：系統 `PATH` 中必須可找到 `claude` 執行檔\n2. **已產生主要語言文件**：`.doc-build/_catalog.json` 及各頁面 `index.md` 必須存在\n3. **設定檔含 `secondary_languages`**：`selfmd.yaml` 中的 `output.secondary_languages` 不可為空\n\n若未滿足條件三，指令將直接回報錯誤並終止：\n\n```go\nif len(cfg.Output.SecondaryLanguages) == 0 {\n    return fmt.Errorf(\"設定檔中未定義 secondary_languages，無法翻譯\")\n}\n```\n\n\u003e 來源：`cmd/translate.go#L50-L52`\n\n## 核心流程\n\n### 翻譯管線序列圖\n\n```mermaid\nsequenceDiagram\n    participant User\n    participant translateCmd\n    participant Generator\n    participant Writer\n    participant Engine\n    participant Runner as \"Runner（Claude CLI）\"\n\n    User-\u003e\u003etranslateCmd: selfmd translate\n    translateCmd-\u003e\u003etranslateCmd: CheckAvailable()\n    translateCmd-\u003e\u003etranslateCmd: config.Load()\n    translateCmd-\u003e\u003eGenerator: NewGenerator()\n    translateCmd-\u003e\u003eGenerator: Translate(opts)\n\n    Generator-\u003e\u003eWriter: ReadCatalogJSON()\n    Writer--\u003e\u003eGenerator: catJSON\n    Generator-\u003e\u003eGenerator: catalog.Parse() + Flatten()\n\n    loop 每個 targetLang\n        Generator-\u003e\u003eWriter: ForLanguage(lang).EnsureDir()\n\n        par 並行翻譯葉節點頁面\n            loop 每個 leafItem\n                Generator-\u003e\u003eWriter: PageExists(item)\n                alt 已存在且非 --force\n                    Writer--\u003e\u003eGenerator: 跳過\n                else 需要翻譯\n                    Generator-\u003e\u003eWriter: ReadPage(item)\n                    Writer--\u003e\u003eGenerator: sourceContent\n                    Generator-\u003e\u003eEngine: RenderTranslate(data)\n                    Engine--\u003e\u003eGenerator: rendered prompt\n                    Generator-\u003e\u003eRunner: RunWithRetry(ctx, opts)\n                    Runner--\u003e\u003eGenerator: result\n                    Generator-\u003e\u003eGenerator: ExtractDocumentTag()\n                    Generator-\u003e\u003eWriter: langWriter.WritePage(item, content)\n                end\n            end\n        end\n\n        Generator-\u003e\u003eGenerator: buildTranslatedCatalog()\n        Generator-\u003e\u003eWriter: WriteCatalogJSON (lang)\n        Generator-\u003e\u003eWriter: WriteFile(\"index.md\")\n        Generator-\u003e\u003eWriter: WriteFile(\"_sidebar.md\")\n    end\n\n    Generator-\u003e\u003eWriter: WriteViewer()\n    Generator--\u003e\u003eUser: 顯示翻譯摘要\n```\n\n### 增量翻譯邏輯\n\n`translatePages()` 函式在翻譯每頁前，先透過 `Writer.PageExists()` 檢查翻譯檔是否存在且有效內容。判定「需要翻譯」的條件：\n\n- 檔案不存在\n- 檔案內容為空\n- 檔案內容包含 `\"此頁面產生失敗\"` 字串\n- 使用者指定了 `--force` 旗標\n\n```go\nif !opts.Force \u0026\u0026 langWriter.PageExists(item) {\n    skipped.Add(1)\n    // 嘗試從已有翻譯擷取標題\n    if content, err := langWriter.ReadPage(item); err == nil {\n        if title := extractTitle(content); title != \"\" {\n            titlesMu.Lock()\n            translatedTitles[item.Path] = title\n            titlesMu.Unlock()\n        }\n    }\n    fmt.Printf(\"      [跳過] %s（已存在）\\n\", item.Title)\n    return nil\n}\n```\n\n\u003e 來源：`internal/generator/translate_phase.go#L156-L169`\n\n### 翻譯目錄同步\n\n翻譯完成後，系統會以翻譯後的標題重建目錄結構，讓各語言版本的導航都能正確顯示本地語言標題：\n\n```go\nfunc buildTranslatedCatalog(original *catalog.Catalog, translatedTitles map[string]string) *catalog.Catalog {\n    translated := \u0026catalog.Catalog{\n        Items: translateCatalogItems(original.Items, translatedTitles, \"\"),\n    }\n    return translated\n}\n```\n\n\u003e 來源：`internal/generator/translate_phase.go#L277-L282`\n\n## 翻譯 Prompt 模板\n\n翻譯使用的是位於 `internal/prompt/templates/translate.tmpl` 的**共用模板**（非語言特定），由 `Engine.RenderTranslate()` 渲染。翻譯規則由模板硬編碼：\n\n| 規則 | 說明 |\n|------|------|\n| 保留 Markdown 格式 | 標題、連結、程式碼區塊、表格、Mermaid 圖表 |\n| 不翻譯程式碼識別符 | 變數名稱、檔案路徑、程式碼區塊維持原文 |\n| 翻譯章節標題 | 使用自然的目標語言翻譯 |\n| 保留相對連結路徑 | 只翻譯連結顯示文字，路徑不變 |\n| 保留來源標註 | `\u003e Source: path/to/file#L10-L25` 格式不變 |\n\n`TranslatePromptData` 結構提供以下資料給模板：\n\n```go\ntype TranslatePromptData struct {\n    SourceLanguage     string // 例如 \"zh-TW\"\n    SourceLanguageName string // 例如 \"繁體中文\"\n    TargetLanguage     string // 例如 \"en-US\"\n    TargetLanguageName string // 例如 \"English\"\n    SourceContent      string // 要翻譯的完整 Markdown 內容\n}\n```\n\n\u003e 來源：`internal/prompt/engine.go#L97-L104`\n\n## 語言設定\n\n次要語言在 `selfmd.yaml` 的 `output.secondary_languages` 欄位設定：\n\n```yaml\noutput:\n  language: zh-TW              # 主要語言（翻譯來源）\n  secondary_languages:         # 翻譯目標語言列表\n    - en-US\n    - ja-JP\n```\n\n系統目前內建以下語言的原生名稱顯示：\n\n| 語言代碼 | 原生名稱 |\n|---------|---------|\n| `zh-TW` | 繁體中文 |\n| `zh-CN` | 简体中文 |\n| `en-US` | English |\n| `ja-JP` | 日本語 |\n| `ko-KR` | 한국어 |\n| `fr-FR` | Français |\n| `de-DE` | Deutsch |\n| `es-ES` | Español |\n| `pt-BR` | Português |\n| `th-TH` | ไทย |\n| `vi-VN` | Tiếng Việt |\n\n\u003e 來源：`internal/config/config.go#L39-L51`\n\n## 輸出結構\n\n翻譯完成後，各語言版本的文件放置於 `.doc-build/{語言代碼}/` 子目錄，結構與主要語言版本相同：\n\n```\n.doc-build/\n├── （主要語言，例如 zh-TW）\n│   ├── _catalog.json\n│   ├── index.md\n│   ├── _sidebar.md\n│   └── section/page/index.md\n├── en-US/\n│   ├── _catalog.json\n│   ├── index.md\n│   ├── _sidebar.md\n│   └── section/page/index.md\n└── ja-JP/\n    ├── _catalog.json\n    ├── index.md\n    └── ...\n```\n\n翻譯完成後，靜態瀏覽器（`index.html`）也會重新產生，以納入所有語言的切換資訊。\n\n## 執行輸出範例\n\n```\n翻譯源語言：繁體中文（zh-TW）\n目標語言：en-US, ja-JP\n頁面數量：42\n\n========== 翻譯至 English（en-US）==========\n      [1/42] 概述...  完成（12.3s，$0.0042）\n      [2/42] 快速開始... 完成（9.8s，$0.0038）\n      [跳過] 安裝與建置（已存在）\n      ...\n      翻譯結果：40 成功，0 失敗，2 跳過\n\n========== 翻譯至 日本語（ja-JP）==========\n      ...\n\n重新產生文件瀏覽器...\n      完成\n\n========================================\n翻譯完成！\n  總耗時：8m32s\n  總費用：$0.3241 USD\n========================================\n```\n\n## 相關連結\n\n- [CLI 指令參考](../index.md)\n- [selfmd generate](../cmd-generate/index.md)\n- [selfmd update](../cmd-update/index.md)\n- [輸出與多語言設定](../../configuration/output-language/index.md)\n- [翻譯階段](../../core-modules/generator/translate-phase/index.md)\n- [翻譯工作流程](../../i18n/translation-workflow/index.md)\n- [支援的語言與模板](../../i18n/supported-languages/index.md)\n- [Claude CLI 整合設定](../../configuration/claude-config/index.md)\n\n## 參考檔案\n\n| 檔案路徑 | 說明 |\n|----------|------|\n| `cmd/translate.go` | `translate` 指令定義、旗標解析與執行入口 |\n| `cmd/root.go` | 根指令與全域旗標定義 |\n| `internal/generator/translate_phase.go` | `Translate()`、`translatePages()`、`buildTranslatedCatalog()` 核心翻譯邏輯 |\n| `internal/generator/pipeline.go` | `Generator` 結構定義與 `NewGenerator()` |\n| `internal/prompt/engine.go` | `TranslatePromptData` 結構與 `RenderTranslate()` 方法 |\n| `internal/prompt/templates/translate.tmpl` | 翻譯 Prompt 共用模板 |\n| `internal/config/config.go` | `OutputConfig`（`SecondaryLanguages`）、`KnownLanguages`、`GetLangNativeName()` |\n| `internal/output/writer.go` | `Writer`、`ForLanguage()`、`PageExists()`、`ReadPage()` |\n| `internal/claude/runner.go` | `Runner.RunWithRetry()` 與 `CheckAvailable()` |","cli/cmd-update/index.md":"# selfmd update\n\n`selfmd update` 指令分析 git 變更歷史，以增量方式更新受影響的文件頁面，無需重新產生所有文件。\n\n## 概述\n\n`selfmd update` 是 selfmd 的增量更新模式。與每次全量重新產生的 `selfmd generate` 不同，`update` 指令透過比對 git commit 之間的差異，只重新產生受變更影響的文件頁面，大幅節省時間與 API 費用。\n\n**使用前提：**\n- 必須已執行過 `selfmd generate`，`.doc-build/` 目錄中存在初始文件\n- 專案必須是 git 儲存庫\n- Claude CLI 必須可用\n\n**核心概念：**\n- **比較範圍（Comparison Range）**：兩個 commit 之間的差異，即 `previousCommit..currentCommit`\n- **匹配（Matching）**：已變更的原始碼檔案路徑是否出現在現有文件頁面內容中\n- **葉節點升級（Leaf Promotion）**：當新增頁面需要成為現有頁面的子頁面時，舊的葉節點會自動升級為父節點\n\n## 架構\n\n```mermaid\nflowchart TD\n    CLI[\"cmd/update.go\\nCLI 入口點\"]\n    GitCheck[\"git.IsGitRepo\\n驗證 git 環境\"]\n    CommitResolution[\"Commit 解析\\n--since / _last_commit / merge-base\"]\n    GitDiff[\"git.GetChangedFiles\\n取得變更檔案清單\"]\n    Filter[\"git.FilterChangedFiles\\n套用 include/exclude 過濾\"]\n    Scanner[\"scanner.Scan\\n掃描專案結構\"]\n    Update[\"generator.Update\\n增量更新主流程\"]\n\n    ReadCatalog[\"Writer.ReadCatalogJSON\\n讀取 _catalog.json\"]\n    Match[\"matchChangedFilesToDocs\\n比對變更檔案與文件頁面\"]\n    ClaudeMatched[\"determineMatchedUpdates\\nClaude 決定哪些頁面需要更新\"]\n    ClaudeUnmatched[\"determineUnmatchedPages\\nClaude 決定是否新增頁面\"]\n    Regenerate[\"generateSinglePage\\n重新產生頁面內容\"]\n    GenerateIndex[\"GenerateIndex\\n重新產生導覽與索引\"]\n    SaveCommit[\"Writer.SaveLastCommit\\n儲存 _last_commit\"]\n\n    CLI --\u003e GitCheck\n    CLI --\u003e CommitResolution\n    CommitResolution --\u003e GitDiff\n    GitDiff --\u003e Filter\n    Filter --\u003e Scanner\n    Scanner --\u003e Update\n\n    Update --\u003e ReadCatalog\n    ReadCatalog --\u003e Match\n    Match --\u003e ClaudeMatched\n    Match --\u003e ClaudeUnmatched\n    ClaudeMatched --\u003e Regenerate\n    ClaudeUnmatched --\u003e Regenerate\n    Regenerate --\u003e GenerateIndex\n    GenerateIndex --\u003e SaveCommit\n```\n\n## 指令語法\n\n```bash\nselfmd update [flags]\n```\n\n**可用旗標：**\n\n| 旗標 | 類型 | 說明 |\n|------|------|------|\n| `--since \u003ccommit\u003e` | string | 指定比較基準 commit（預設自動偵測） |\n| `--config \u003cpath\u003e` | string | 指定設定檔路徑（全域旗標，繼承自 root） |\n| `--verbose` | bool | 顯示詳細的除錯日誌（全域旗標，繼承自 root） |\n\n\u003e 來源：`cmd/update.go#L19-L31`\n\n## Commit 解析邏輯\n\n`selfmd update` 在執行前需要確定「從哪個 commit 開始比較」。系統依照以下優先順序解析基準 commit：\n\n```mermaid\nflowchart TD\n    A{有無 --since 旗標?} -- 有 --\u003e B[\"使用 --since 指定的 commit\"]\n    A -- 無 --\u003e C{讀取 _last_commit 是否成功?}\n    C -- 成功 --\u003e D[\"使用 _last_commit 中儲存的 commit\"]\n    C -- 失敗 --\u003e E{git merge-base 是否成功?}\n    E -- 成功 --\u003e F[\"使用 merge-base\\n（當前分支與 baseBranch 的分叉點）\"]\n    E -- 失敗 --\u003e G[\"回傳錯誤\\n提示先執行 selfmd generate\\n或使用 --since 指定 commit\"]\n```\n\n`_last_commit` 檔案由每次 `generate` 或 `update` 完成後自動寫入，存放於 `.doc-build/_last_commit`。\n\n```go\n// Determine comparison commit\npreviousCommit := sinceCommit\nif previousCommit == \"\" {\n    // Try reading saved commit from last generate/update\n    saved, readErr := gen.Writer.ReadLastCommit()\n    if readErr == nil \u0026\u0026 saved != \"\" {\n        previousCommit = saved\n    } else {\n        // Fallback to merge-base\n        base, err := git.GetMergeBase(rootDir, cfg.Git.BaseBranch)\n        if err != nil {\n            return fmt.Errorf(\"無法取得基準 commit: %w\\n提示：先執行 selfmd generate 或使用 --since 指定 commit\", err)\n        }\n        previousCommit = base\n    }\n}\n```\n\n\u003e 來源：`cmd/update.go#L68-L82`\n\n## 四階段更新流程\n\n`generator.Update()` 方法依序執行以下四個階段：\n\n### [1/4] 搜尋受影響的文件頁面\n\n`matchChangedFilesToDocs` 對每個已變更的原始碼檔案，掃描所有現有文件頁面的內容，尋找包含該檔案路徑的頁面。\n\n```go\n// For each changed file, find which pages reference it\nfor _, f := range files {\n    var matchedPages []catalog.FlatItem\n    for _, item := range items {\n        content, ok := pageContents[item.Path]\n        if !ok {\n            continue\n        }\n        if strings.Contains(content, f.Path) {\n            matchedPages = append(matchedPages, item)\n        }\n    }\n    // ...\n}\n```\n\n\u003e 來源：`internal/generator/updater.go#L191-L211`\n\n此步驟將變更檔案分為兩類：\n- **matched**（已匹配）：在現有文件中找到引用的檔案\n- **unmatched**（未匹配）：沒有任何現有文件引用的新檔案\n\n### [2/4] Claude 判斷需更新的現有頁面\n\n針對已匹配的檔案，呼叫 Claude CLI 評估每個相關文件頁面是否確實受到影響，並返回需要重新產生的頁面清單。\n\nClaude 的判斷結果以 JSON 格式返回，包含 `catalogPath`、`title`、`reason` 三個欄位：\n\n```go\ntype UpdateMatchedResult struct {\n    CatalogPath string `json:\"catalogPath\"`\n    Title       string `json:\"title\"`\n    Reason      string `json:\"reason\"`\n}\n```\n\n\u003e 來源：`internal/generator/updater.go#L18-L22`\n\n### [3/4] Claude 判斷是否新增頁面\n\n針對未匹配的檔案（即現有文件中沒有引用的新檔案），呼叫 Claude CLI 評估是否應為這些檔案新增文件頁面。\n\n```go\ntype UpdateUnmatchedResult struct {\n    CatalogPath string `json:\"catalogPath\"`\n    Title       string `json:\"title\"`\n    Reason      string `json:\"reason\"`\n}\n```\n\n\u003e 來源：`internal/generator/updater.go#L24-L29`\n\n若 Claude 決定需要新增頁面，系統會呼叫 `addItemToCatalog` 將新頁面插入現有目錄樹，並觸發葉節點升級機制（見下方說明）。\n\n### [4/4] 重新產生頁面內容\n\n對所有需要更新的頁面（已匹配需更新的 + 新增的），呼叫與 `selfmd generate` 相同的 `generateSinglePage` 流程重新產生內容。產生時會將現有頁面內容作為上下文傳入，讓 Claude 在更新時保留原有結構。\n\n```go\n// Read existing content to pass as context for regeneration\nexisting, _ := g.Writer.ReadPage(item)\nerr := g.generateSinglePage(ctx, scan, item, catalogTable, linkFixer, existing)\n```\n\n\u003e 來源：`internal/generator/updater.go#L141-L142`\n\n## 葉節點升級機制\n\n當 Claude 決定在現有頁面的路徑下新增子頁面時（例如在 `core-modules.scanner` 下新增 `core-modules.scanner.advanced`），原本的葉節點（`core-modules.scanner`）需要升級為父節點。\n\n系統會自動：\n1. 將原葉節點的現有內容搬移到新建的 `overview` 子頁面（如 `core-modules.scanner.overview`）\n2. 將原葉節點標記為父節點\n3. 在父節點下建立新請求的子頁面\n\n```go\n// A leaf node was promoted to a parent.\n// Move the original content to the new \"overview\" child.\norigItem := catalog.FlatItem{\n    Path:    promoted.OriginalPath,\n    DirPath: catalogPathToDir(promoted.OriginalPath),\n}\noverviewItem := catalog.FlatItem{\n    Title:   promoted.OriginalTitle,\n    Path:    promoted.OverviewPath,\n    DirPath: catalogPathToDir(promoted.OverviewPath),\n}\nif content, err := g.Writer.ReadPage(origItem); err == nil \u0026\u0026 content != \"\" {\n    if err := g.Writer.WritePage(overviewItem, content); err != nil {\n        // ...\n    }\n}\n```\n\n\u003e 來源：`internal/generator/updater.go#L99-L116`\n\n## 變更檔案過濾\n\n系統使用與 `selfmd generate` 相同的 include/exclude 規則過濾 git 差異輸出，確保只有符合設定目標的檔案變更才會觸發文件更新。\n\n```go\nchangedFiles = git.FilterChangedFiles(changedFiles, cfg.Targets.Include, cfg.Targets.Exclude)\n```\n\n\u003e 來源：`cmd/update.go#L94`\n\n`FilterChangedFiles` 支援 doublestar glob 語法（`**/*.go`），並正確處理 git rename 格式（`R100\\told\\tnew`），使用目標路徑進行匹配。\n\n```go\n// git diff --name-status format: \"M\\tpath/to/file\" or \"R100\\told\\tnew\"\nparts := strings.SplitN(line, \"\\t\", 3)\n// For renames, check the destination path (last element)\nfilePath := parts[len(parts)-1]\n```\n\n\u003e 來源：`internal/git/git.go#L83-L91`\n\n## 輸出檔案\n\n每次 `update` 完成後，系統會更新以下持久化檔案：\n\n| 檔案 | 說明 |\n|------|------|\n| `.doc-build/_last_commit` | 記錄本次更新的 HEAD commit hash，供下次 update 使用 |\n| `.doc-build/_catalog.json` | 若有新增頁面，更新文件目錄結構 |\n| `.doc-build/\u003cpath\u003e/index.md` | 被更新或新建的文件頁面 |\n\n## 使用範例\n\n```bash\n# 基本用法：與上次 generate/update 相比，更新有變更的文件\nselfmd update\n\n# 指定與特定 commit 比較\nselfmd update --since a1b2c3d\n\n# 開啟詳細日誌模式\nselfmd update --verbose\n\n# 指定設定檔\nselfmd update --config ./selfmd.yaml\n```\n\n典型的執行輸出：\n\n```\n比較範圍：a1b2c3d..e4f5g6h\n變更檔案：\nM       internal/scanner/scanner.go\nA       internal/scanner/filetree.go\n\n[1/4] 搜尋受影響的文件頁面...\n      2 個變更檔案已匹配到現有文件，0 個未匹配\n[2/4] 呼叫 Claude 判斷需要更新的頁面...\n      → 專案掃描器：scanner.go 的公開 API 有變更，需要更新\n       完成（1 個頁面需要更新）\n[3/4] 所有變更檔案均已有對應文件，跳過\n[4/4] 重新產生 1 個頁面...\n      [1/1] 專案掃描器（core-modules.scanner）... 完成\n\n更新完成！總費用：$0.0023 USD\n```\n\n## 前置需求錯誤處理\n\n| 條件 | 錯誤訊息 |\n|------|---------|\n| Claude CLI 不可用 | 由 `claude.CheckAvailable()` 回傳錯誤 |\n| 非 git 倉庫 | `當前目錄不是 git 倉庫，無法執行增量更新` |\n| 無法解析基準 commit | `無法取得基準 commit: ...` 並提示先執行 `selfmd generate` |\n| 未執行過 generate | `讀取現有目錄失敗（請先執行 selfmd generate）` |\n\n## 相關連結\n\n- [CLI 指令參考](../index.md)\n- [selfmd generate](../cmd-generate/index.md)\n- [Git 整合與增量更新](../../git-integration/index.md)\n- [Git Diff 變更偵測](../../git-integration/change-detection/index.md)\n- [受影響頁面判斷邏輯](../../git-integration/affected-pages/index.md)\n- [增量更新（核心模組）](../../core-modules/incremental-update/index.md)\n- [文件目錄管理](../../core-modules/catalog/index.md)\n- [Git 整合設定](../../configuration/git-config/index.md)\n\n## 參考檔案\n\n| 檔案路徑 | 說明 |\n|----------|------|\n| `cmd/update.go` | `selfmd update` CLI 指令定義、旗標宣告、前置驗證、commit 解析邏輯 |\n| `internal/generator/updater.go` | 增量更新主流程 `Update()`、匹配邏輯、Claude 判斷呼叫、葉節點升級機制 |\n| `internal/git/git.go` | git 操作封裝：`IsGitRepo`、`GetChangedFiles`、`ParseChangedFiles`、`FilterChangedFiles` |\n| `internal/output/writer.go` | `SaveLastCommit`、`ReadLastCommit`、`ReadCatalogJSON`、`WriteCatalogJSON` |\n| `internal/generator/pipeline.go` | `Generator` 結構定義、`NewGenerator` 建構函式 |\n| `internal/catalog/catalog.go` | `Catalog`、`FlatItem`、`BuildLinkTable`、`Flatten` 等目錄操作 |\n| `internal/prompt/engine.go` | `UpdateMatchedPromptData`、`UpdateUnmatchedPromptData`、`RenderUpdateMatched`、`RenderUpdateUnmatched` |","cli/index.md":"# CLI 指令參考\n\nThis section contains the following:\n\n- [selfmd init](cmd-init/index.md)\n- [selfmd generate](cmd-generate/index.md)\n- [selfmd update](cmd-update/index.md)\n- [selfmd translate](cmd-translate/index.md)\n","configuration/claude-config/index.md":"# Claude CLI 整合設定\n\n控制 selfmd 如何呼叫 Claude CLI 子程序，包含模型選擇、並行度、逾時、重試與工具存取權限。\n\n## 概述\n\n`claude` 設定區塊定義了 selfmd 與 Claude CLI（`claude` 指令）互動的所有行為參數。selfmd 在文件產生管線的每個階段——目錄產生、內容頁面產生、翻譯——都會以子程序（subprocess）方式呼叫 Claude CLI，這些呼叫的行為均由此設定控制。\n\n**核心職責：**\n- 指定要使用的 Claude 模型版本\n- 限制單次執行的並行 Claude 子程序數量，避免超出 API 速率限制\n- 設定每次呼叫的最長等待時間（逾時）\n- 控制失敗後的自動重試次數與退避間隔\n- 限縮 Claude 可存取的工具，確保文件分析的安全邊界\n- 注入自訂的額外 CLI 參數\n\n## 設定結構\n\n`selfmd.yaml` 中的 `claude` 區塊對應至 `ClaudeConfig` 結構：\n\n```go\ntype ClaudeConfig struct {\n    Model          string   `yaml:\"model\"`\n    MaxConcurrent  int      `yaml:\"max_concurrent\"`\n    TimeoutSeconds int      `yaml:\"timeout_seconds\"`\n    MaxRetries     int      `yaml:\"max_retries\"`\n    AllowedTools   []string `yaml:\"allowed_tools\"`\n    ExtraArgs      []string `yaml:\"extra_args\"`\n}\n```\n\n\u003e 來源：internal/config/config.go#L82-L89\n\n### 完整預設值\n\n```go\nClaude: ClaudeConfig{\n    Model:          \"sonnet\",\n    MaxConcurrent:  3,\n    TimeoutSeconds: 300,\n    MaxRetries:     2,\n    AllowedTools:   []string{\"Read\", \"Glob\", \"Grep\"},\n    ExtraArgs:      []string{},\n},\n```\n\n\u003e 來源：internal/config/config.go#L116-L123\n\n## 欄位說明\n\n### `model`\n\n**型別：** `string`　**預設值：** `\"sonnet\"`\n\n指定要使用的 Claude 模型。此值直接傳遞給 `claude --model` 旗標。若留空，則不傳遞 `--model` 旗標，由 Claude CLI 使用其自身預設值。\n\n```yaml\nclaude:\n  model: sonnet       # 使用 Claude Sonnet（較快、較省費用）\n  # model: opus       # 使用 Claude Opus（較強、較貴）\n```\n\n### `max_concurrent`\n\n**型別：** `int`　**預設值：** `3`　**最小值：** `1`\n\n設定同時執行的 Claude CLI 子程序上限。此值控制「內容頁面產生」與「翻譯」兩個階段的並行工作數量。\n\n- 設定過高可能觸發 Anthropic API 速率限制（Rate Limit）\n- `selfmd generate --concurrency` 旗標可在執行期暫時覆寫此值\n- 驗證邏輯保證此值不低於 `1`\n\n### `timeout_seconds`\n\n**型別：** `int`　**預設值：** `300`　**最小值：** `30`\n\n每次 Claude CLI 呼叫的逾時秒數。超過此時間後，Runner 會取消子程序並回報逾時錯誤。\n\n- 若文件量龐大或 Prompt 複雜，建議適度調高\n- 驗證邏輯保證此值不低於 `30` 秒\n\n### `max_retries`\n\n**型別：** `int`　**預設值：** `2`　**最小值：** `0`\n\n當 Claude CLI 呼叫失敗時，自動重試的最大次數。重試間隔採退避策略：第 N 次重試前等待 `N × 5` 秒。\n\n- 設為 `0` 表示不重試\n- 驗證邏輯保證此值不低於 `0`\n\n### `allowed_tools`\n\n**型別：** `[]string`　**預設值：** `[\"Read\", \"Glob\", \"Grep\"]`\n\n指定 Claude 在分析原始碼時可使用的工具清單。對應 `claude --allowedTools` 旗標，每個工具傳遞一次。\n\n**注意：** 無論此設定為何，`Write` 與 `Edit` 工具一律被封鎖（傳遞 `--disallowedTools Write --disallowedTools Edit`），防止 Claude 直接修改原始碼。\n\n```yaml\nclaude:\n  allowed_tools:\n    - Read    # 讀取檔案內容\n    - Glob    # 依模式搜尋檔案\n    - Grep    # 在檔案中搜尋文字\n```\n\n### `extra_args`\n\n**型別：** `[]string`　**預設值：** `[]`\n\n注入到每次 `claude` 指令的額外 CLI 參數，附加在自動產生的參數之後。可用於傳遞 selfmd 未直接支援的 Claude CLI 旗標。\n\n```yaml\nclaude:\n  extra_args:\n    - \"--verbose\"\n```\n\n## 架構\n\n```mermaid\nflowchart TD\n    YAML[\"selfmd.yaml\\n(claude 區塊)\"]\n    CFG[\"ClaudeConfig\\ninternal/config/config.go\"]\n    RUNNER[\"Runner\\ninternal/claude/runner.go\"]\n    CLI[\"claude CLI\\n子程序\"]\n    PIPELINE[\"Generator\\ninternal/generator/pipeline.go\"]\n    TRANSLATE[\"Translate\\ncmd/translate.go\"]\n\n    YAML --\u003e|\"yaml.Unmarshal\"| CFG\n    CFG --\u003e|\"\u0026cfg.Claude\"| RUNNER\n    PIPELINE --\u003e|\"MaxConcurrent\\n並行度控制\"| RUNNER\n    TRANSLATE --\u003e|\"MaxConcurrent\\n並行度控制\"| RUNNER\n    RUNNER --\u003e|\"exec.CommandContext\"| CLI\n\n    subgraph Runner內部\n        ARGS[\"組裝 CLI 參數\\n-p --output-format json\\n--model --allowedTools\\n--disallowedTools Write/Edit\"]\n        TIMEOUT[\"context.WithTimeout\\n(TimeoutSeconds)\"]\n        RETRY[\"RunWithRetry\\n退避重試 (MaxRetries)\"]\n    end\n\n    RUNNER --\u003e ARGS\n    RUNNER --\u003e TIMEOUT\n    RUNNER --\u003e RETRY\n```\n\n## 核心流程\n\n### Runner 呼叫流程\n\n```mermaid\nsequenceDiagram\n    participant G as Generator\n    participant R as Runner\n    participant CLI as claude CLI\n\n    G-\u003e\u003eR: RunWithRetry(ctx, opts)\n    loop 最多 MaxRetries+1 次\n        R-\u003e\u003eR: 組裝 CLI 參數\n        note over R: -p --output-format json\u003cbr/\u003e--model {Model}\u003cbr/\u003e--allowedTools {每個工具}\u003cbr/\u003e--disallowedTools Write Edit\u003cbr/\u003e{ExtraArgs}\n        R-\u003e\u003eCLI: exec.CommandContext(ctx, \"claude\", args...)\n        note over R,CLI: Prompt 經 stdin 傳入\n        alt 成功\n            CLI--\u003e\u003eR: JSON 回應 (stdout)\n            R-\u003e\u003eR: ParseResponse(stdout)\n            R--\u003e\u003eG: RunResult\n        else 失敗或 IsError\n            R-\u003e\u003eR: 等待 attempt × 5 秒\n        end\n    end\n    R--\u003e\u003eG: 錯誤（所有重試均失敗）\n```\n\n### 逾時處理\n\n```go\ntimeout := opts.Timeout\nif timeout == 0 {\n    timeout = time.Duration(r.config.TimeoutSeconds) * time.Second\n}\n\nctx, cancel := context.WithTimeout(ctx, timeout)\ndefer cancel()\n```\n\n\u003e 來源：internal/claude/runner.go#L61-L67\n\n### 重試退避邏輯\n\n```go\nfor attempt := 0; attempt \u003c= maxRetries; attempt++ {\n    if attempt \u003e 0 {\n        backoff := time.Duration(attempt) * 5 * time.Second\n        r.logger.Info(\"重試中\", \"attempt\", attempt+1, \"backoff\", backoff)\n        select {\n        case \u003c-ctx.Done():\n            return nil, ctx.Err()\n        case \u003c-time.After(backoff):\n        }\n    }\n    // ...\n}\n```\n\n\u003e 來源：internal/claude/runner.go#L117-L127\n\n## 使用範例\n\n### `selfmd.yaml` 完整 `claude` 區塊\n\n```yaml\nclaude:\n  model: sonnet\n  max_concurrent: 3\n  timeout_seconds: 300\n  max_retries: 2\n  allowed_tools:\n    - Read\n    - Glob\n    - Grep\n  extra_args: []\n```\n\n### 高吞吐量設定（大型專案）\n\n```yaml\nclaude:\n  model: sonnet\n  max_concurrent: 5      # 提高並行度\n  timeout_seconds: 600   # 延長逾時至 10 分鐘\n  max_retries: 3\n  allowed_tools:\n    - Read\n    - Glob\n    - Grep\n```\n\n### 驗證邏輯\n\n```go\nfunc (c *Config) validate() error {\n    if c.Claude.MaxConcurrent \u003c 1 {\n        c.Claude.MaxConcurrent = 1\n    }\n    if c.Claude.TimeoutSeconds \u003c 30 {\n        c.Claude.TimeoutSeconds = 30\n    }\n    if c.Claude.MaxRetries \u003c 0 {\n        c.Claude.MaxRetries = 0\n    }\n    return nil\n}\n```\n\n\u003e 來源：internal/config/config.go#L157-L174\n\n## 工具限制設計\n\nselfmd 在工具存取上採用「白名單 + 強制黑名單」的雙重策略：\n\n| 機制 | 設定來源 | 說明 |\n|------|----------|------|\n| `--allowedTools` | `allowed_tools` 欄位 | 允許 Claude 使用的工具（唯讀分析工具） |\n| `--disallowedTools Write` | 硬編碼於 Runner | 無論設定為何，一律封鎖寫入 |\n| `--disallowedTools Edit` | 硬編碼於 Runner | 無論設定為何，一律封鎖編輯 |\n\n此設計確保 Claude 只能「讀取」原始碼用於文件分析，無法修改任何檔案。相關實作：\n\n```go\n// Explicitly block Write/Edit to prevent content from being lost in denied tool calls\nargs = append(args, \"--disallowedTools\", \"Write\", \"--disallowedTools\", \"Edit\")\n```\n\n\u003e 來源：internal/claude/runner.go#L55-L56\n\n## 相關連結\n\n- [設定說明](../index.md)\n- [selfmd.yaml 結構總覽](../config-overview/index.md)\n- [輸出與多語言設定](../output-language/index.md)\n- [Git 整合設定](../git-config/index.md)\n- [Claude CLI 執行器](../../core-modules/claude-runner/index.md)\n- [文件產生管線](../../core-modules/generator/index.md)\n- [翻譯階段](../../core-modules/generator/translate-phase/index.md)\n\n## 參考檔案\n\n| 檔案路徑 | 說明 |\n|----------|------|\n| `internal/config/config.go` | `ClaudeConfig` 結構定義、預設值與驗證邏輯 |\n| `internal/claude/runner.go` | `Runner` 實作，負責組裝 CLI 參數與執行子程序 |\n| `internal/claude/types.go` | `RunOptions`、`RunResult`、`CLIResponse` 型別定義 |\n| `internal/claude/parser.go` | Claude CLI JSON 回應解析邏輯 |\n| `internal/generator/pipeline.go` | `MaxConcurrent` 用於控制內容產生並行度 |\n| `cmd/translate.go` | `MaxConcurrent` 用於控制翻譯並行度 |","configuration/config-overview/index.md":"# selfmd.yaml 結構總覽\n\n`selfmd.yaml` 是 selfmd 的核心設定檔，包含五個頂層區段，控制從專案掃描到 Claude CLI 呼叫的所有行為。\n\n## 概述\n\n`selfmd.yaml` 採用 YAML 格式，由 `internal/config/config.go` 定義的 `Config` 結構解析。執行任何 selfmd 指令前，系統會先載入並驗證此設定檔。\n\n設定檔的五個頂層區段各自負責不同的功能面向：\n\n| 區段 | Go 型別 | 功能說明 |\n|------|---------|---------|\n| `project` | `ProjectConfig` | 專案基本資訊（名稱、類型、描述） |\n| `targets` | `TargetsConfig` | 掃描目標路徑（包含、排除、入口點） |\n| `output` | `OutputConfig` | 輸出目錄與多語言設定 |\n| `claude` | `ClaudeConfig` | Claude CLI 執行參數 |\n| `git` | `GitConfig` | Git 整合與增量更新設定 |\n\n執行 `selfmd init` 時，系統會自動偵測專案類型並套用預設值，產生完整的 `selfmd.yaml` 範本。設定檔路徑預設為 `selfmd.yaml`，可透過 `--config` 旗標覆蓋。\n\n## 架構\n\n```mermaid\ngraph TD\n    YAML[\"selfmd.yaml\"]\n\n    YAML --\u003e P[\"project\\n（ProjectConfig）\"]\n    YAML --\u003e T[\"targets\\n（TargetsConfig）\"]\n    YAML --\u003e O[\"output\\n（OutputConfig）\"]\n    YAML --\u003e C[\"claude\\n（ClaudeConfig）\"]\n    YAML --\u003e G[\"git\\n（GitConfig）\"]\n\n    P --\u003e P1[\"name\"]\n    P --\u003e P2[\"type\"]\n    P --\u003e P3[\"description\"]\n\n    T --\u003e T1[\"include\"]\n    T --\u003e T2[\"exclude\"]\n    T --\u003e T3[\"entry_points\"]\n\n    O --\u003e O1[\"dir\"]\n    O --\u003e O2[\"language\"]\n    O --\u003e O3[\"secondary_languages\"]\n    O --\u003e O4[\"clean_before_generate\"]\n\n    C --\u003e C1[\"model\"]\n    C --\u003e C2[\"max_concurrent\"]\n    C --\u003e C3[\"timeout_seconds\"]\n    C --\u003e C4[\"max_retries\"]\n    C --\u003e C5[\"allowed_tools\"]\n    C --\u003e C6[\"extra_args\"]\n\n    G --\u003e G1[\"enabled\"]\n    G --\u003e G2[\"base_branch\"]\n```\n\n## 完整結構說明\n\n### `project` — 專案基本資訊\n\n```yaml\nproject:\n  name: myproject         # 專案名稱，用於文件標題與瀏覽器頁籤\n  type: backend           # 專案類型：backend / frontend / fullstack / library\n  description: \"\"         # 專案描述（可選）\n```\n\n\u003e 來源：`internal/config/config.go#L19-L23`\n\n`type` 欄位影響 Claude 產生文件時的上下文描述，`selfmd init` 會自動偵測（根據 `go.mod`、`package.json` 等標誌性檔案）。\n\n---\n\n### `targets` — 掃描目標設定\n\n```yaml\ntargets:\n  include:\n    - src/**\n    - pkg/**\n    - cmd/**\n    - internal/**\n    - lib/**\n    - app/**\n  exclude:\n    - vendor/**\n    - node_modules/**\n    - .git/**\n    - .doc-build/**\n    - \"**/*.pb.go\"\n    - \"**/generated/**\"\n    - dist/**\n    - build/**\n  entry_points:\n    - main.go\n    - cmd/root.go\n```\n\n\u003e 來源：`internal/config/config.go#L25-L29`，預設值：`internal/config/config.go#L102-L109`\n\n- `include`：以 glob 模式指定要掃描的目錄，支援 `**` 萬用字元\n- `exclude`：排除自動產生的程式碼、依賴套件、建置產物等雜訊路徑\n- `entry_points`：標記核心入口檔案，引導 Claude 優先理解專案架構\n\n---\n\n### `output` — 輸出與語言設定\n\n```yaml\noutput:\n  dir: .doc-build               # 文件輸出目錄\n  language: zh-TW               # 主要文件語言（master lang）\n  secondary_languages:          # 次要語言列表（翻譯用）\n    - en-US\n  clean_before_generate: false  # 每次產生前是否清除輸出目錄\n```\n\n\u003e 來源：`internal/config/config.go#L31-L36`\n\n**語言代碼**：`language` 與 `secondary_languages` 使用 BCP 47 格式。系統內建支援下列語言代碼：\n\n| 代碼 | 語言名稱 |\n|------|---------|\n| `zh-TW` | 繁體中文 |\n| `zh-CN` | 简体中文 |\n| `en-US` | English |\n| `ja-JP` | 日本語 |\n| `ko-KR` | 한국어 |\n| `fr-FR` | Français |\n| `de-DE` | Deutsch |\n| `es-ES` | Español |\n| `pt-BR` | Português |\n| `th-TH` | ไทย |\n| `vi-VN` | Tiếng Việt |\n\n\u003e 來源：`internal/config/config.go#L39-L51`\n\n`clean_before_generate` 可被 CLI 旗標 `--clean` 或 `--no-clean` 覆蓋。\n\n---\n\n### `claude` — Claude CLI 整合設定\n\n```yaml\nclaude:\n  model: sonnet           # Claude 模型識別符\n  max_concurrent: 3       # 最大並行請求數\n  timeout_seconds: 300    # 單次請求逾時（秒），最小值 30\n  max_retries: 2          # 失敗重試次數，最小值 0\n  allowed_tools:          # 允許 Claude 使用的工具清單\n    - Read\n    - Glob\n    - Grep\n  extra_args: []          # 傳遞給 claude CLI 的額外旗標\n```\n\n\u003e 來源：`internal/config/config.go#L82-L89`，預設值：`internal/config/config.go#L116-L123`\n\n`max_concurrent` 控制同時呼叫 Claude CLI 的數量，可透過 `selfmd generate --concurrency \u003cN\u003e` 在執行時覆蓋。\n\n---\n\n### `git` — Git 整合設定\n\n```yaml\ngit:\n  enabled: true           # 是否啟用 Git 整合（增量更新）\n  base_branch: main       # 比對差異用的基準分支\n```\n\n\u003e 來源：`internal/config/config.go#L91-L94`\n\n啟用 Git 整合後，`selfmd update` 指令會比對 `base_branch` 與目前工作樹的差異，僅重新產生受影響的文件頁面。\n\n## 載入與驗證流程\n\n```mermaid\nsequenceDiagram\n    participant CLI as CLI 指令\n    participant Load as config.Load()\n    participant Default as DefaultConfig()\n    participant Validate as validate()\n\n    CLI-\u003e\u003eLoad: Load(\"selfmd.yaml\")\n    Load-\u003e\u003eDefault: 建立預設值\n    Default--\u003e\u003eLoad: *Config（含所有預設值）\n    Load-\u003e\u003eLoad: yaml.Unmarshal（覆蓋使用者設定）\n    Load-\u003e\u003eValidate: cfg.validate()\n    Validate-\u003e\u003eValidate: 檢查 output.dir 非空\n    Validate-\u003e\u003eValidate: 檢查 output.language 非空\n    Validate-\u003e\u003eValidate: 修正 max_concurrent \u003c 1\n    Validate-\u003e\u003eValidate: 修正 timeout_seconds \u003c 30\n    Validate-\u003e\u003eValidate: 修正 max_retries \u003c 0\n    Validate--\u003e\u003eLoad: 驗證通過\n    Load--\u003e\u003eCLI: *Config\n```\n\n`Load()` 採用「預設值優先，使用者覆蓋」的策略：先建立完整的預設 `Config`，再以 YAML 內容覆蓋指定欄位。未填寫的欄位自動沿用預設值。\n\n```go\nfunc Load(path string) (*Config, error) {\n    data, err := os.ReadFile(path)\n    if err != nil {\n        return nil, fmt.Errorf(\"無法讀取設定檔 %s: %w\", path, err)\n    }\n\n    cfg := DefaultConfig()\n    if err := yaml.Unmarshal(data, cfg); err != nil {\n        return nil, fmt.Errorf(\"設定檔格式錯誤: %w\", err)\n    }\n\n    if err := cfg.validate(); err != nil {\n        return nil, err\n    }\n\n    return cfg, nil\n}\n```\n\n\u003e 來源：`internal/config/config.go#L131-L147`\n\n## Prompt 模板語言選擇邏輯\n\n`output.language` 不只控制文件輸出語言，也影響 Prompt 模板的選擇。目前內建模板僅支援 `zh-TW` 與 `en-US`；其他語言代碼會回退到 `en-US` 模板，並在 Prompt 中插入明確的語言輸出指示。\n\n```go\n// GetEffectiveTemplateLang returns which template folder to load.\nfunc (o *OutputConfig) GetEffectiveTemplateLang() string {\n    for _, lang := range SupportedTemplateLangs {\n        if o.Language == lang {\n            return o.Language\n        }\n    }\n    return \"en-US\"\n}\n\n// NeedsLanguageOverride returns true when the template language differs from Language.\nfunc (o *OutputConfig) NeedsLanguageOverride() bool {\n    return o.GetEffectiveTemplateLang() != o.Language\n}\n```\n\n\u003e 來源：`internal/config/config.go#L58-L71`\n\n## 相關連結\n\n- [設定說明](../index.md) — 設定章節總覽\n- [專案與掃描目標設定](../project-targets/index.md) — `project` 與 `targets` 區段詳解\n- [輸出與多語言設定](../output-language/index.md) — `output` 區段與語言機制\n- [Claude CLI 整合設定](../claude-config/index.md) — `claude` 區段詳解\n- [Git 整合設定](../git-config/index.md) — `git` 區段詳解\n- [selfmd init](../../cli/cmd-init/index.md) — 自動產生設定檔的指令\n- [多語言支援](../../i18n/index.md) — 語言代碼與翻譯工作流程\n\n## 參考檔案\n\n| 檔案路徑 | 說明 |\n|----------|------|\n| `internal/config/config.go` | `Config` 結構定義、預設值、載入與驗證邏輯 |\n| `cmd/init.go` | `selfmd init` 實作，包含專案類型自動偵測與設定檔產生 |\n| `cmd/root.go` | 根指令定義，包含 `--config` 旗標宣告 |\n| `cmd/generate.go` | `selfmd generate` 實作，展示設定檔如何傳遞至 Generator |\n| `internal/generator/pipeline.go` | Generator 如何使用 Config 各欄位驅動文件產生流程 |","configuration/git-config/index.md":"# Git 整合設定\n\n設定 selfmd 如何利用 Git 歷史追蹤原始碼變更，以實現增量文件更新功能。\n\n## 概述\n\nselfmd 的 Git 整合設定位於 `selfmd.yaml` 的 `git` 區塊。此設定決定了 `selfmd update` 指令在執行增量更新時，如何比較 Git commit 以偵測受影響的原始碼檔案。\n\nGit 整合的核心概念：\n\n- **基準分支（Base Branch）**：作為比較起點的分支。當系統找不到上次執行記錄時，會以此分支與 `HEAD` 的 merge-base 作為比較起點。\n- **啟用狀態（Enabled）**：控制是否啟用 Git diff 功能，目前此欄位由系統讀取，`selfmd update` 指令本身已強制要求當前目錄為 Git 倉庫。\n- **Commit 記錄持久化**：每次執行 `generate` 或 `update` 後，系統會將當前的 commit hash 儲存至輸出目錄的 `_last_commit` 檔案，供下次增量更新使用。\n\n## 架構\n\n```mermaid\nflowchart TD\n    YAML[\"selfmd.yaml\\ngit.enabled\\ngit.base_branch\"]\n    GitConfig[\"GitConfig 結構\\ninternal/config/config.go\"]\n    UpdateCmd[\"selfmd update\\ncmd/update.go\"]\n    GitPkg[\"git 套件\\ninternal/git/git.go\"]\n    LastCommit[\"_last_commit 檔案\\n輸出目錄\"]\n    MergeBase[\"git merge-base\\n基準分支 vs HEAD\"]\n\n    YAML --\u003e GitConfig\n    GitConfig --\u003e UpdateCmd\n    UpdateCmd --\u003e|\"讀取上次 commit\"| LastCommit\n    LastCommit --\u003e|\"找不到時\"| MergeBase\n    MergeBase --\u003e|\"使用 base_branch\"| GitConfig\n    UpdateCmd --\u003e GitPkg\n    GitPkg --\u003e|\"git diff --name-status\"| UpdateCmd\n```\n\n## 設定欄位說明\n\n`GitConfig` 結構定義於 `internal/config/config.go`：\n\n```go\ntype GitConfig struct {\n\tEnabled    bool   `yaml:\"enabled\"`\n\tBaseBranch string `yaml:\"base_branch\"`\n}\n```\n\n\u003e 來源：internal/config/config.go#L91-L94\n\n### `git.enabled`\n\n| 屬性 | 值 |\n|------|-----|\n| 類型 | `bool` |\n| 預設值 | `true` |\n| 必填 | 否 |\n\n控制 Git 整合是否啟用。\n\n### `git.base_branch`\n\n| 屬性 | 值 |\n|------|-----|\n| 類型 | `string` |\n| 預設值 | `\"main\"` |\n| 必填 | 否 |\n\n基準分支名稱。當系統找不到上次執行的 commit 記錄（`_last_commit` 檔案不存在）時，會以此分支為基準，使用 `git merge-base \u003cbase_branch\u003e HEAD` 計算出比較起點。\n\n## 預設值\n\n`DefaultConfig()` 中 Git 設定的預設值：\n\n```go\nGit: GitConfig{\n    Enabled:    true,\n    BaseBranch: \"main\",\n},\n```\n\n\u003e 來源：internal/config/config.go#L124-L127\n\n## selfmd.yaml 設定範例\n\n```yaml\ngit:\n  enabled: true\n  base_branch: main\n```\n\n若你的主分支名稱為 `master`，請將 `base_branch` 改為：\n\n```yaml\ngit:\n  enabled: true\n  base_branch: master\n```\n\n## 核心流程\n\n以下為 `selfmd update` 指令如何使用 Git 設定決定比較範圍：\n\n```mermaid\nflowchart TD\n    Start[\"執行 selfmd update\"]\n    CheckGit{\"IsGitRepo？\"}\n    ErrorNotGit[\"錯誤：非 Git 倉庫\"]\n    SinceFlag{\"--since 旗標\\n有指定？\"}\n    ReadSaved{\"讀取 _last_commit\\n檔案\"}\n    UseSince[\"使用指定 commit\"]\n    UseSaved[\"使用儲存的 commit\"]\n    GetMergeBase[\"git merge-base\\nbase_branch HEAD\"]\n    GetCurrent[\"git rev-parse HEAD\\n取得當前 commit\"]\n    GetDiff[\"git diff --relative\\n--name-status FROM..TO\"]\n    Filter[\"依 targets.include/exclude\\n過濾變更檔案\"]\n    Update[\"執行增量更新流程\"]\n    SaveCommit[\"儲存當前 commit\\n至 _last_commit\"]\n\n    Start --\u003e CheckGit\n    CheckGit --\u003e|\"否\"| ErrorNotGit\n    CheckGit --\u003e|\"是\"| SinceFlag\n    SinceFlag --\u003e|\"是\"| UseSince\n    SinceFlag --\u003e|\"否\"| ReadSaved\n    ReadSaved --\u003e|\"讀取成功\"| UseSaved\n    ReadSaved --\u003e|\"讀取失敗\"| GetMergeBase\n    GetMergeBase --\u003e UseSaved\n    UseSince --\u003e GetCurrent\n    UseSaved --\u003e GetCurrent\n    GetCurrent --\u003e GetDiff\n    GetDiff --\u003e Filter\n    Filter --\u003e Update\n    Update --\u003e SaveCommit\n```\n\n## 使用範例\n\n### 基本增量更新\n\n執行 `selfmd update` 時，系統會：\n\n1. 從 `selfmd.yaml` 讀取 `git.base_branch`\n2. 嘗試讀取上次儲存的 commit（`_last_commit` 檔案）\n3. 若無記錄，則呼叫 `git merge-base` 以 `base_branch` 計算起點\n\n```go\n// cmd/update.go 中的比較起點決定邏輯\npreviousCommit := sinceCommit\nif previousCommit == \"\" {\n    saved, readErr := gen.Writer.ReadLastCommit()\n    if readErr == nil \u0026\u0026 saved != \"\" {\n        previousCommit = saved\n    } else {\n        base, err := git.GetMergeBase(rootDir, cfg.Git.BaseBranch)\n        // ...\n        previousCommit = base\n    }\n}\n```\n\n\u003e 來源：cmd/update.go#L69-L86\n\n### 使用 `--since` 旗標指定比較起點\n\n你也可以直接指定比較起點的 commit hash，跳過自動偵測邏輯：\n\n```bash\nselfmd update --since abc1234\n```\n\n### `git diff` 輸出解析\n\n`internal/git/git.go` 中的 `ParseChangedFiles` 函式負責解析 `git diff --name-status` 的輸出：\n\n```go\n// ChangedFile represents a single file from git diff --name-status output.\ntype ChangedFile struct {\n\tStatus string // \"M\", \"A\", \"D\", \"R\"\n\tPath   string\n}\n\n// ParseChangedFiles parses git diff --name-status output into structured ChangedFile list.\nfunc ParseChangedFiles(changedFiles string) []ChangedFile {\n\tvar result []ChangedFile\n\tfor _, line := range strings.Split(changedFiles, \"\\n\") {\n\t\tline = strings.TrimSpace(line)\n\t\tif line == \"\" {\n\t\t\tcontinue\n\t\t}\n\t\tparts := strings.SplitN(line, \"\\t\", 3)\n\t\tif len(parts) \u003c 2 {\n\t\t\tcontinue\n\t\t}\n\t\tstatus := string(parts[0][0]) // \"M\", \"A\", \"D\", or \"R\" (R100 → R)\n\t\tpath := parts[len(parts)-1]   // for renames, use destination path\n\t\tresult = append(result, ChangedFile{Status: status, Path: path})\n\t}\n\treturn result\n}\n```\n\n\u003e 來源：internal/git/git.go#L47-L70\n\n### 變更檔案過濾\n\n取得 Git diff 結果後，系統還會依據 `targets.include` 與 `targets.exclude` 設定進行過濾，排除不相關的檔案（如 `vendor/**`、`.git/**`）：\n\n```go\nchangedFiles = git.FilterChangedFiles(changedFiles, cfg.Targets.Include, cfg.Targets.Exclude)\n```\n\n\u003e 來源：cmd/update.go#L98\n\n## 注意事項\n\n- `selfmd update` 執行前需先確認當前目錄為 Git 倉庫，否則指令會直接回報錯誤\n- 首次使用增量更新前，必須先執行 `selfmd generate` 建立初始文件，否則找不到 `_last_commit` 記錄時，會嘗試以 `base_branch` 計算 merge-base\n- `git.enabled` 欄位目前在設定中存在，但 `selfmd update` 指令本身已強制要求 Git 環境，無論此值為何\n\n## 相關連結\n\n- [設定說明](../index.md)\n- [selfmd.yaml 結構總覽](../config-overview/index.md)\n- [Claude CLI 整合設定](../claude-config/index.md)\n- [selfmd update](../../cli/cmd-update/index.md)\n- [Git Diff 變更偵測](../../git-integration/change-detection/index.md)\n- [受影響頁面判斷邏輯](../../git-integration/affected-pages/index.md)\n- [增量更新](../../core-modules/incremental-update/index.md)\n\n## 參考檔案\n\n| 檔案路徑 | 說明 |\n|----------|------|\n| `internal/config/config.go` | `GitConfig` 結構定義、預設值與 `Config` 整體結構 |\n| `internal/git/git.go` | Git 操作函式實作，包含 diff 解析、過濾與 commit 查詢 |\n| `cmd/update.go` | `selfmd update` 指令實作，使用 Git 設定決定比較範圍 |\n| `internal/generator/updater.go` | 增量更新邏輯，呼叫 Git 套件進行變更比對與文件重新產生 |\n| `internal/output/writer.go` | `_last_commit` 檔案的讀寫實作 |","configuration/index.md":"# 設定說明\n\nThis section contains the following:\n\n- [selfmd.yaml 結構總覽](config-overview/index.md)\n- [專案與掃描目標設定](project-targets/index.md)\n- [輸出與多語言設定](output-language/index.md)\n- [Claude CLI 整合設定](claude-config/index.md)\n- [Git 整合設定](git-config/index.md)\n","configuration/output-language/index.md":"# 輸出與多語言設定\n\n本頁說明 `selfmd.yaml` 中 `output` 區塊的所有欄位，以及 selfmd 如何支援主要語言文件產生與次要語言自動翻譯。\n\n## 概述\n\n`output` 區塊控制兩大類行為：\n\n1. **輸出目錄設定**：指定文件產生到哪個路徑、是否在產生前清除舊檔案。\n2. **多語言設定**：定義主要語言（master language）與次要語言（secondary languages）清單。主要語言決定文件的撰寫語言與 Prompt 模板的選取邏輯；次要語言則用於 `selfmd translate` 指令，將主要語言文件批次翻譯為指定語言。\n\nselfmd 的多語言系統採用「先產生、再翻譯」的兩階段策略：先以主要語言完整產生所有技術文件，再透過 Claude 將每一頁翻譯為次要語言，翻譯結果儲存於 `.doc-build/{語言代碼}/` 子目錄中。\n\n---\n\n## 架構\n\n```mermaid\nflowchart TD\n    Config[\"selfmd.yaml\\noutput 區塊\"]\n\n    Config --\u003e Dir[\"output.dir\\n輸出根目錄\"]\n    Config --\u003e Lang[\"output.language\\n主要語言\"]\n    Config --\u003e SecLangs[\"output.secondary_languages\\n次要語言列表\"]\n    Config --\u003e Clean[\"output.clean_before_generate\\n產生前清除\"]\n\n    Lang --\u003e TemplateLang[\"GetEffectiveTemplateLang()\\n取得模板語言\"]\n    Lang --\u003e LangOverride[\"NeedsLanguageOverride()\\n是否需語言覆蓋指令\"]\n\n    TemplateLang --\u003e |\"zh-TW 或 en-US\"| BuiltinTmpl[\"使用對應內建模板\\ntemplates/zh-TW/\\ntemplates/en-US/\"]\n    TemplateLang --\u003e |\"其他語言\"| FallbackTmpl[\"回退至 en-US 模板\\n+ 語言覆蓋指令\"]\n\n    SecLangs --\u003e TranslateCmd[\"selfmd translate\"]\n    TranslateCmd --\u003e TranslatePhase[\"TranslatePhase\\n翻譯管線\"]\n    TranslatePhase --\u003e LangDir[\".doc-build/{lang}/\\n各語言子目錄\"]\n\n    Dir --\u003e MasterOut[\".doc-build/\\n主要語言輸出\"]\n    Dir --\u003e LangDir\n```\n\n---\n\n## 設定欄位參考\n\n`output` 區塊的完整結構定義如下：\n\n```go\ntype OutputConfig struct {\n    Dir                 string   `yaml:\"dir\"`\n    Language            string   `yaml:\"language\"`\n    SecondaryLanguages  []string `yaml:\"secondary_languages\"`\n    CleanBeforeGenerate bool     `yaml:\"clean_before_generate\"`\n}\n```\n\n\u003e 來源：internal/config/config.go#L31-L36\n\n### `output.dir`\n\n| 項目 | 說明 |\n|------|------|\n| 類型 | `string` |\n| 預設值 | `.doc-build` |\n| 說明 | 所有文件的輸出根目錄。主要語言文件直接放置於此目錄，次要語言文件放置於 `{dir}/{lang}/` 子目錄。 |\n\n### `output.language`\n\n| 項目 | 說明 |\n|------|------|\n| 類型 | `string` |\n| 預設值 | `zh-TW` |\n| 驗證 | 不可為空字串 |\n| 說明 | 主要語言代碼（BCP 47 格式）。決定 Claude Prompt 模板的選取語言，以及產生文件的輸出語言。 |\n\n### `output.secondary_languages`\n\n| 項目 | 說明 |\n|------|------|\n| 類型 | `[]string` |\n| 預設值 | `[]`（空列表） |\n| 說明 | 次要語言代碼列表。執行 `selfmd translate` 時，會逐一將主要語言文件翻譯為這些語言。若此欄位為空，`translate` 指令會回傳錯誤。 |\n\n### `output.clean_before_generate`\n\n| 項目 | 說明 |\n|------|------|\n| 類型 | `bool` |\n| 預設值 | `false` |\n| 說明 | 設為 `true` 時，每次執行 `selfmd generate` 前會先刪除並重建輸出目錄。等同於每次執行 `generate --clean`。 |\n\n---\n\n## 完整設定範例\n\n以下為一個啟用多語言的典型設定：\n\n```yaml\noutput:\n  dir: .doc-build\n  language: zh-TW\n  secondary_languages:\n    - en-US\n    - ja-JP\n  clean_before_generate: false\n```\n\n\u003e 來源：internal/config/config.go#L110-L115（DefaultConfig 函式）\n\n---\n\n## 支援的語言代碼\n\nselfmd 內建以下語言代碼與其對應的原生名稱。使用這些代碼時，語言名稱會自動顯示在文件導覽與翻譯流程的輸出中：\n\n```go\nvar KnownLanguages = map[string]string{\n    \"zh-TW\": \"繁體中文\",\n    \"zh-CN\": \"简体中文\",\n    \"en-US\": \"English\",\n    \"ja-JP\": \"日本語\",\n    \"ko-KR\": \"한국어\",\n    \"fr-FR\": \"Français\",\n    \"de-DE\": \"Deutsch\",\n    \"es-ES\": \"Español\",\n    \"pt-BR\": \"Português\",\n    \"th-TH\": \"ไทย\",\n    \"vi-VN\": \"Tiếng Việt\",\n}\n```\n\n\u003e 來源：internal/config/config.go#L39-L51\n\n使用 `KnownLanguages` 以外的語言代碼（如 `it-IT`）仍可運作，但語言名稱將直接顯示為代碼本身（例如 `it-IT`）。\n\n---\n\n## Prompt 模板語言與語言覆蓋機制\n\nselfmd 僅為以下兩種語言提供內建 Prompt 模板：\n\n```go\nvar SupportedTemplateLangs = []string{\"zh-TW\", \"en-US\"}\n```\n\n\u003e 來源：internal/config/config.go#L54\n\n當 `output.language` 設為 `SupportedTemplateLangs` 以外的語言時，系統自動回退至 `en-US` 模板，並在 Prompt 中加入明確的語言覆蓋指令（language override），要求 Claude 以指定語言輸出文件。\n\n此邏輯由以下兩個方法實作：\n\n```go\n// GetEffectiveTemplateLang returns which template folder to load.\n// If Language has a built-in template set, returns it; otherwise falls back to \"en-US\".\nfunc (o *OutputConfig) GetEffectiveTemplateLang() string {\n    for _, lang := range SupportedTemplateLangs {\n        if o.Language == lang {\n            return o.Language\n        }\n    }\n    return \"en-US\"\n}\n\n// NeedsLanguageOverride returns true when the template language differs from Language,\n// meaning the prompt needs an explicit instruction to output in the configured language.\nfunc (o *OutputConfig) NeedsLanguageOverride() bool {\n    return o.GetEffectiveTemplateLang() != o.Language\n}\n```\n\n\u003e 來源：internal/config/config.go#L58-L71\n\n### 模板語言選取邏輯\n\n```mermaid\nflowchart TD\n    Start[\"output.language 設定值\"]\n    Check{\"是否在\\nSupportedTemplateLangs\\n中？\"}\n    UseNative[\"使用對應語言模板\\n（zh-TW 或 en-US）\"]\n    Fallback[\"回退至 en-US 模板\"]\n    Override[\"NeedsLanguageOverride = true\\n在 Prompt 中加入語言指令\"]\n    NoOverride[\"NeedsLanguageOverride = false\\n模板語言即輸出語言\"]\n\n    Start --\u003e Check\n    Check --\u003e|是| UseNative --\u003e NoOverride\n    Check --\u003e|否| Fallback --\u003e Override\n```\n\n`Generator` 初始化時會呼叫 `GetEffectiveTemplateLang()` 來選取正確的模板資料夾：\n\n```go\nfunc NewGenerator(cfg *config.Config, rootDir string, logger *slog.Logger) (*Generator, error) {\n    templateLang := cfg.Output.GetEffectiveTemplateLang()\n    engine, err := prompt.NewEngine(templateLang)\n    if err != nil {\n        return nil, err\n    }\n    // ...\n}\n```\n\n\u003e 來源：internal/generator/pipeline.go#L34-L38\n\n---\n\n## 多語言輸出目錄結構\n\n啟用次要語言後，輸出目錄結構如下：\n\n```\n.doc-build/                    ← 主要語言（output.language）\n├── index.html                 ← 靜態瀏覽器\n├── _catalog.json              ← 主要語言目錄資料\n├── index.md\n├── _sidebar.md\n└── {章節}/\n    └── {頁面}/\n        └── index.md\n\n.doc-build/en-US/              ← 次要語言（secondary_languages[0]）\n├── _catalog.json\n├── index.md\n├── _sidebar.md\n└── {章節}/\n    └── {頁面}/\n        └── index.md\n\n.doc-build/ja-JP/              ← 次要語言（secondary_languages[1]）\n└── ...\n```\n\n`Writer.ForLanguage()` 方法會建立一個指向語言子目錄的新 `Writer` 實體：\n\n```go\n// ForLanguage returns a new Writer that writes to a language-specific subdirectory.\nfunc (w *Writer) ForLanguage(lang string) *Writer {\n    return \u0026Writer{\n        BaseDir: filepath.Join(w.BaseDir, lang),\n    }\n}\n```\n\n\u003e 來源：internal/output/writer.go#L139-L143\n\n---\n\n## 文件瀏覽器的語言中繼資料\n\n執行 `selfmd generate` 或 `selfmd translate` 後，系統會產生 `DocMeta` 物件，記錄所有可用語言資訊供靜態文件瀏覽器使用：\n\n```go\nfunc (g *Generator) buildDocMeta() *output.DocMeta {\n    meta := \u0026output.DocMeta{\n        DefaultLanguage: g.Config.Output.Language,\n        AvailableLanguages: []output.LangInfo{\n            {\n                Code:       g.Config.Output.Language,\n                NativeName: config.GetLangNativeName(g.Config.Output.Language),\n                IsDefault:  true,\n            },\n        },\n    }\n    for _, lang := range g.Config.Output.SecondaryLanguages {\n        meta.AvailableLanguages = append(meta.AvailableLanguages, output.LangInfo{\n            Code:       lang,\n            NativeName: config.GetLangNativeName(lang),\n            IsDefault:  false,\n        })\n    }\n    return meta\n}\n```\n\n\u003e 來源：internal/generator/pipeline.go#L184-L203\n\n---\n\n## 翻譯指令整合\n\n`secondary_languages` 設定決定 `selfmd translate` 的翻譯目標。以下為 CLI 層的驗證邏輯：\n\n```go\nif len(cfg.Output.SecondaryLanguages) == 0 {\n    return fmt.Errorf(\"設定檔中未定義 secondary_languages，無法翻譯\")\n}\n\n// Determine target languages\ntargetLangs := cfg.Output.SecondaryLanguages\nif len(translateLangs) \u003e 0 {\n    // Validate specified languages are in the config\n    validLangs := make(map[string]bool)\n    for _, l := range cfg.Output.SecondaryLanguages {\n        validLangs[l] = true\n    }\n    for _, l := range translateLangs {\n        if !validLangs[l] {\n            return fmt.Errorf(\"語言 %s 不在 secondary_languages 列表中（可用：%s）\", l, strings.Join(cfg.Output.SecondaryLanguages, \", \"))\n        }\n    }\n    targetLangs = translateLangs\n}\n```\n\n\u003e 來源：cmd/translate.go#L49-L67\n\n透過 `--lang` 旗標可指定只翻譯部分語言，但指定的語言必須已在 `secondary_languages` 中定義，否則會回傳驗證錯誤。\n\n---\n\n## 導覽頁面的語言本地化\n\n`output.md`、`index.md` 與 `_sidebar.md` 等導覽頁面的 UI 字串也支援多語言。目前內建 `zh-TW` 與 `en-US` 兩種 UI 字串集，其他語言自動回退至 `en-US`：\n\n```go\nvar UIStrings = map[string]map[string]string{\n    \"zh-TW\": {\n        \"techDocs\":        \"技術文件\",\n        \"catalog\":         \"目錄\",\n        \"home\":            \"首頁\",\n        \"sectionContains\": \"本章節包含以下內容：\",\n        \"autoGenerated\":   \"本文件由 [selfmd](https://github.com/monkenwu/selfmd) 自動產生\",\n    },\n    \"en-US\": {\n        \"techDocs\":        \"Technical Documentation\",\n        \"catalog\":         \"Table of Contents\",\n        \"home\":            \"Home\",\n        \"sectionContains\": \"This section contains the following:\",\n        \"autoGenerated\":   \"This documentation was automatically generated by [selfmd](https://github.com/monkenwu/selfmd)\",\n    },\n}\n```\n\n\u003e 來源：internal/output/navigation.go#L12-L27\n\n---\n\n## 相關連結\n\n- [selfmd.yaml 結構總覽](../config-overview/index.md)\n- [專案與掃描目標設定](../project-targets/index.md)\n- [Claude CLI 整合設定](../claude-config/index.md)\n- [selfmd translate 指令](../../cli/cmd-translate/index.md)\n- [支援的語言與模板](../../i18n/supported-languages/index.md)\n- [翻譯工作流程](../../i18n/translation-workflow/index.md)\n- [翻譯階段](../../core-modules/generator/translate-phase/index.md)\n- [Prompt 模板引擎](../../core-modules/prompt-engine/index.md)\n\n---\n\n## 參考檔案\n\n| 檔案路徑 | 說明 |\n|----------|------|\n| `internal/config/config.go` | `OutputConfig` 結構定義、`KnownLanguages`、`SupportedTemplateLangs`、`GetEffectiveTemplateLang()`、`NeedsLanguageOverride()`、`GetLangNativeName()` |\n| `internal/generator/pipeline.go` | `Generator` 初始化（模板語言選取）、`buildDocMeta()`（多語言中繼資料） |\n| `internal/generator/translate_phase.go` | 翻譯管線主邏輯、`translatePages()`、`buildTranslatedCatalog()` |\n| `internal/output/writer.go` | `DocMeta`、`LangInfo` 定義、`ForLanguage()` 方法 |\n| `internal/output/navigation.go` | `UIStrings` 多語言 UI 字串、`GenerateIndex()`、`GenerateSidebar()` |\n| `internal/prompt/engine.go` | `TranslatePromptData` 定義、`RenderTranslate()` 方法 |\n| `internal/prompt/templates/translate.tmpl` | 翻譯 Prompt 模板（共用，語言無關） |\n| `cmd/translate.go` | `translate` 指令實作、`secondary_languages` 驗證邏輯 |\n| `cmd/init.go` | `init` 指令實作（展示預設輸出設定） |","configuration/project-targets/index.md":"# 專案與掃描目標設定\n\n`selfmd.yaml` 中的 `project` 與 `targets` 兩個頂層區段，定義了文件化對象的基本資訊與掃描範圍。這兩個設定區段是 selfmd 理解「要為哪個專案的哪些檔案」產生文件的核心依據。\n\n## 概述\n\nselfmd 在執行 `generate` 或 `update` 指令時，首先會讀取設定檔，再交由掃描器（Scanner）根據 `targets` 的 `include`、`exclude` 規則遍歷目錄，過濾出需要分析的原始碼檔案。`project` 區段則提供專案的名稱、類型等中繼資料，作為 Claude 產生文件時的重要上下文。\n\n關鍵概念說明：\n- **Glob 模式**（glob pattern）：使用 `**` 萬用字元匹配多層目錄的路徑匹配語法，底層由 `doublestar` 函式庫實作。\n- **入口點**（entry points）：額外讀取並完整傳遞給 Claude 的特定檔案，通常為 `main.go`、`cmd/root.go` 等程式進入點。\n- **排除優先**：exclude 規則的優先順序高於 include 規則，若一個路徑同時符合兩者，以排除為準。\n\n`selfmd init` 指令會自動偵測專案類型並產生包含合理預設值的設定檔，使用者通常只需微調 `include`／`exclude` 即可。\n\n## 架構\n\n```mermaid\nflowchart TD\n    YAML[\"selfmd.yaml\"]\n    Load[\"config.Load()\"]\n    ProjectConfig[\"ProjectConfig\\n(name, type, description)\"]\n    TargetsConfig[\"TargetsConfig\\n(include, exclude, entry_points)\"]\n    Scanner[\"scanner.Scan()\"]\n    WalkDir[\"filepath.WalkDir()\"]\n    ExcludeCheck[\"排除規則檢查\\ndoublestar.Match(exclude)\"]\n    IncludeCheck[\"包含規則檢查\\ndoublestar.Match(include)\"]\n    ScanResult[\"ScanResult\\n(FileList, Tree, EntryPointContents)\"]\n    CatalogPhase[\"GenerateCatalog()\\n目錄產生階段\"]\n\n    YAML --\u003e Load\n    Load --\u003e ProjectConfig\n    Load --\u003e TargetsConfig\n    TargetsConfig --\u003e Scanner\n    Scanner --\u003e WalkDir\n    WalkDir --\u003e ExcludeCheck\n    ExcludeCheck --\u003e|\"未命中 → 繼續\"| IncludeCheck\n    ExcludeCheck --\u003e|\"命中 → 跳過\"| WalkDir\n    IncludeCheck --\u003e|\"命中 → 收錄\"| ScanResult\n    IncludeCheck --\u003e|\"未命中 → 忽略\"| WalkDir\n    ProjectConfig --\u003e CatalogPhase\n    ScanResult --\u003e CatalogPhase\n```\n\n## `project` 區段\n\n`project` 區段提供當前專案的基本描述資訊，這些資訊會直接注入 Claude 的 Prompt 中，幫助 AI 理解專案背景。\n\n```yaml\nproject:\n  name: selfmd\n  type: backend\n  description: \"\"\n```\n\n### 欄位說明\n\n| 欄位 | 型別 | 必填 | 預設值 | 說明 |\n|------|------|------|--------|------|\n| `name` | string | 否 | 當前目錄名稱 | 專案名稱，顯示於文件標題與靜態瀏覽器 |\n| `type` | string | 否 | `backend` | 專案類型，提示 Claude 文件架構風格 |\n| `description` | string | 否 | 空字串 | 專案的附加說明（選填） |\n\n### 可用的 `type` 值\n\n`selfmd init` 的自動偵測邏輯會根據特定指標檔案決定專案類型：\n\n```go\nchecks := []struct {\n    file       string\n    pType      string\n    entries    []string\n}{\n    {\"go.mod\", \"backend\", []string{\"main.go\", \"cmd/root.go\"}},\n    {\"Cargo.toml\", \"backend\", []string{\"src/main.rs\", \"src/lib.rs\"}},\n    {\"package.json\", \"frontend\", []string{\"src/index.ts\", \"src/index.js\", \"src/main.ts\", \"src/App.tsx\"}},\n    {\"pom.xml\", \"backend\", []string{\"src/main/java\"}},\n    {\"build.gradle\", \"backend\", []string{\"src/main/java\"}},\n    {\"requirements.txt\", \"backend\", []string{\"main.py\", \"app.py\", \"src/main.py\"}},\n    {\"pyproject.toml\", \"backend\", []string{\"src/main.py\", \"main.py\"}},\n    {\"composer.json\", \"backend\", []string{\"public/index.php\", \"src/Kernel.php\"}},\n    {\"Gemfile\", \"backend\", []string{\"config/application.rb\", \"app/\"}},\n}\n```\n\n\u003e 來源：`cmd/init.go#L61-L75`\n\n| `type` 值 | 意義 |\n|-----------|------|\n| `backend` | 後端服務、API、CLI 工具 |\n| `frontend` | 前端應用程式（SPA、Web App） |\n| `fullstack` | 同時包含前後端的全端專案 |\n| `library` | 函式庫或無法偵測到指標檔案的專案 |\n\n若同時存在 `package.json` 與 `go.mod`（或 `server/` 目錄），則自動判定為 `fullstack`。\n\n## `targets` 區段\n\n`targets` 區段控制掃描器要分析哪些檔案，是影響文件覆蓋範圍最關鍵的設定。\n\n```yaml\ntargets:\n  include:\n    - src/**\n    - pkg/**\n    - cmd/**\n    - internal/**\n    - lib/**\n    - app/**\n  exclude:\n    - vendor/**\n    - node_modules/**\n    - .git/**\n    - .doc-build/**\n    - \"**/*.pb.go\"\n    - \"**/generated/**\"\n    - dist/**\n    - build/**\n  entry_points:\n    - main.go\n    - cmd/root.go\n```\n\n### 欄位說明\n\n| 欄位 | 型別 | 必填 | 預設值 | 說明 |\n|------|------|------|--------|------|\n| `include` | []string | 否 | 見下方 | 需要掃描的路徑模式（glob），空陣列代表包含所有檔案 |\n| `exclude` | []string | 否 | 見下方 | 需要排除的路徑模式（glob），優先於 include |\n| `entry_points` | []string | 否 | `[]` | 額外讀取並完整注入 Prompt 的重要檔案路徑 |\n\n### 預設的 `include` 模式\n\n```go\nInclude: []string{\"src/**\", \"pkg/**\", \"cmd/**\", \"internal/**\", \"lib/**\", \"app/**\"},\n```\n\n\u003e 來源：`internal/config/config.go#L103`\n\n### 預設的 `exclude` 模式\n\n```go\nExclude: []string{\n    \"vendor/**\", \"node_modules/**\", \".git/**\", \".doc-build/**\",\n    \"**/*.pb.go\", \"**/generated/**\", \"dist/**\", \"build/**\",\n},\n```\n\n\u003e 來源：`internal/config/config.go#L104-L108`\n\n## 掃描規則的執行順序\n\n掃描器在遍歷目錄時，排除規則（exclude）的優先級高於包含規則（include）。當掃描到一個目錄且命中 exclude 規則時，會直接跳過整個子目錄樹（`filepath.SkipDir`），大幅提升效能。\n\n```go\n// check excludes\nfor _, pattern := range cfg.Targets.Exclude {\n    matched, _ := doublestar.Match(pattern, rel)\n    if matched {\n        if d.IsDir() {\n            return filepath.SkipDir\n        }\n        return nil\n    }\n}\n\n// ...（目錄本身不做 include 過濾）\n\n// check includes\nif len(cfg.Targets.Include) \u003e 0 {\n    included := false\n    for _, pattern := range cfg.Targets.Include {\n        matched, _ := doublestar.Match(pattern, rel)\n        if matched {\n            included = true\n            break\n        }\n    }\n    if !included {\n        return nil\n    }\n}\n```\n\n\u003e 來源：`internal/scanner/scanner.go#L33-L61`\n\n### 過濾流程\n\n```mermaid\nflowchart TD\n    Start([\"遍歷到路徑 path\"])\n    IsExcluded{\"命中 exclude\\n模式？\"}\n    IsDir{\"是目錄？\"}\n    SkipDir[\"SkipDir\\n跳過整個子目錄\"]\n    SkipFile[\"跳過此檔案\"]\n    CountDir[\"計入 totalDirs\"]\n    IsIncluded{\"命中 include\\n模式？\\n（include 非空時）\"}\n    AddFile[\"加入 files 清單\"]\n    Done([\"結束此路徑\"])\n\n    Start --\u003e IsExcluded\n    IsExcluded --\u003e|是| IsDir\n    IsDir --\u003e|是目錄| SkipDir --\u003e Done\n    IsDir --\u003e|是檔案| SkipFile --\u003e Done\n    IsExcluded --\u003e|否| IsDir2{\"是目錄？\"}\n    IsDir2 --\u003e|是| CountDir --\u003e Done\n    IsDir2 --\u003e|否| IsIncluded\n    IsIncluded --\u003e|是| AddFile --\u003e Done\n    IsIncluded --\u003e|否| Done\n```\n\n## 入口點（Entry Points）的作用\n\n`entry_points` 中指定的檔案，會在掃描完成後被讀取，其完整內容會格式化後注入 Claude 的目錄產生 Prompt（`CatalogPromptData.EntryPoints`）。這讓 Claude 在理解專案結構時能直接閱讀最核心的程式碼邏輯。\n\n```go\n// read entry points\nentryPointContents := make(map[string]string)\nfor _, ep := range cfg.Targets.EntryPoints {\n    content := readFileIfExists(rootDir, ep)\n    if content != \"\" {\n        entryPointContents[ep] = content\n    }\n}\n```\n\n\u003e 來源：`internal/scanner/scanner.go#L83-L91`\n\n入口點檔案會被截斷至 10,000 字元以避免超出 context 限制，並以 Markdown 程式碼區塊格式傳遞：\n\n```go\nfunc (s *ScanResult) EntryPointsFormatted() string {\n    if len(s.EntryPointContents) == 0 {\n        return \"(no entry points specified)\"\n    }\n\n    var sb strings.Builder\n    for path, content := range s.EntryPointContents {\n        sb.WriteString(\"### \" + path + \"\\n```\\n\")\n        // truncate large files\n        if len(content) \u003e 10000 {\n            content = content[:10000] + \"\\n... (truncated)\"\n        }\n        sb.WriteString(content)\n        sb.WriteString(\"\\n```\\n\\n\")\n    }\n    return sb.String()\n}\n```\n\n\u003e 來源：`internal/scanner/scanner.go#L143-L160`\n\n## 常見設定範例\n\n### Go 後端專案（預設）\n\n```yaml\nproject:\n  name: my-service\n  type: backend\n\ntargets:\n  include:\n    - cmd/**\n    - internal/**\n    - pkg/**\n  exclude:\n    - vendor/**\n    - .doc-build/**\n    - \"**/*.pb.go\"\n  entry_points:\n    - main.go\n    - cmd/root.go\n```\n\n### Node.js 前端專案\n\n```yaml\nproject:\n  name: my-frontend\n  type: frontend\n\ntargets:\n  include:\n    - src/**\n    - components/**\n    - pages/**\n  exclude:\n    - node_modules/**\n    - dist/**\n    - \"**/*.test.ts\"\n  entry_points:\n    - src/main.ts\n    - src/App.tsx\n```\n\n### 排除特定目錄與檔案類型\n\n```yaml\ntargets:\n  include:\n    - src/**\n  exclude:\n    - src/vendor/**\n    - \"**/*.generated.go\"\n    - \"**/testdata/**\"\n    - \"**/*_test.go\"\n```\n\n## 相關連結\n\n- [selfmd.yaml 結構總覽](../config-overview/index.md)\n- [輸出與多語言設定](../output-language/index.md)\n- [Claude CLI 整合設定](../claude-config/index.md)\n- [Git 整合設定](../git-config/index.md)\n- [專案掃描器](../../core-modules/scanner/index.md)\n- [selfmd init 指令](../../cli/cmd-init/index.md)\n\n## 參考檔案\n\n| 檔案路徑 | 說明 |\n|----------|------|\n| `internal/config/config.go` | `Config`、`ProjectConfig`、`TargetsConfig` 結構定義、預設值、載入與驗證邏輯 |\n| `internal/scanner/scanner.go` | `Scan()` 實作：目錄遍歷、include/exclude 過濾、entry points 讀取 |\n| `internal/scanner/filetree.go` | `ScanResult`、`FileNode` 結構定義；`BuildTree()`、`RenderTree()` 實作 |\n| `cmd/init.go` | `init` 指令實作；`detectProject()` 自動偵測專案類型與入口點 |\n| `internal/prompt/engine.go` | `CatalogPromptData` 結構，顯示 `ProjectType`、`EntryPoints`、`FileTree` 如何注入 Prompt |\n| `internal/generator/catalog_phase.go` | 目錄產生階段，展示 `ProjectConfig` 與 `ScanResult` 如何組合成 Prompt |\n| `internal/generator/pipeline.go` | 完整管線流程，顯示 `scanner.Scan()` 被呼叫的時機與上下文 |","core-modules/catalog/index.md":"# 文件目錄管理\n\n`catalog` 模組是 selfmd 的核心資料結構層，負責定義、解析、展平與序列化整份文件的樹狀目錄，並為下游的內容產生、導航輸出與增量更新提供統一的資料存取介面。\n\n## 概述\n\n文件目錄（Catalog）是 selfmd 整個產生流程的骨幹。它由 Claude 根據專案原始碼結構一次性產生，以 JSON 格式持久化儲存於輸出目錄中，並在後續所有階段（內容產生、導航輸出、增量更新）中被重複讀取與使用。\n\n核心概念說明：\n\n- **Catalog**：目錄的根節點，持有一組 `CatalogItem` 作為頂層章節\n- **CatalogItem**：樹狀節點，可遞迴包含子節點，代表一個文件章節\n- **FlatItem**：展平後的線性節點，包含深度優先遍歷所計算出的完整路徑資訊，供下游模組使用\n- **dot-notation 路徑**：如 `core-modules.authentication`，作為目錄項目的唯一識別符\n- **filesystem 路徑**：如 `core-modules/authentication`，對應實際的輸出目錄結構\n\n目錄管理模組解決了「樹狀結構 → 線性可迭代清單 → 檔案系統目錄」的全程轉換問題，同時相容 Claude 回傳的兩種路徑格式（相對路徑 Format A 與含父層的完整路徑 Format B）。\n\n## 架構\n\n```mermaid\nflowchart TD\n    subgraph catalog[\"internal/catalog/catalog.go\"]\n        Catalog[\"Catalog\\n{ Items: []CatalogItem }\"]\n        CatalogItem[\"CatalogItem\\n{ Title, Path, Order, Children }\"]\n        FlatItem[\"FlatItem\\n{ Title, Path, DirPath, Depth,\\nParentPath, HasChildren }\"]\n        Parse[\"Parse(data string)\"]\n        Flatten[\"Flatten()\"]\n        ToJSON[\"ToJSON()\"]\n        BuildLinkTable[\"BuildLinkTable()\"]\n    end\n\n    subgraph generator[\"internal/generator/\"]\n        CatalogPhase[\"catalog_phase.go\\nGenerateCatalog()\"]\n        Pipeline[\"pipeline.go\\nGenerate()\"]\n        ContentPhase[\"content_phase.go\\nGenerateContent()\"]\n        IndexPhase[\"index_phase.go\\nGenerateIndex()\"]\n        Updater[\"updater.go\\nUpdate()\"]\n    end\n\n    subgraph outputPkg[\"internal/output/\"]\n        Navigation[\"navigation.go\\nGenerateIndex/Sidebar\"]\n        Writer[\"writer.go\\nWriteCatalogJSON / ReadCatalogJSON\"]\n        LinkFixer[\"linkfixer.go\\nNewLinkFixer()\"]\n    end\n\n    Claude[\"Claude CLI Runner\"] --\u003e|JSON 回應| CatalogPhase\n    CatalogPhase --\u003e|Parse| Catalog\n    Catalog --\u003e CatalogItem\n    CatalogItem --\u003e|Flatten| FlatItem\n    Catalog --\u003e Flatten\n    Flatten --\u003e FlatItem\n\n    Pipeline --\u003e CatalogPhase\n    Pipeline --\u003e ContentPhase\n    Pipeline --\u003e IndexPhase\n\n    ContentPhase --\u003e|BuildLinkTable| BuildLinkTable\n    ContentPhase --\u003e|Flatten| FlatItem\n    IndexPhase --\u003e|Flatten| FlatItem\n    Updater --\u003e|Parse, Flatten,\\nBuildLinkTable| Catalog\n\n    Navigation --\u003e|Items| Catalog\n    Writer --\u003e|WriteCatalogJSON| ToJSON\n    Writer --\u003e|ReadCatalogJSON → Parse| Parse\n    LinkFixer --\u003e|Flatten| FlatItem\n```\n\n## 資料結構\n\n### Catalog 與 CatalogItem\n\n```go\n// Catalog represents the documentation catalog structure.\ntype Catalog struct {\n\tItems []CatalogItem `json:\"items\"`\n}\n\n// CatalogItem represents a single item in the catalog tree.\ntype CatalogItem struct {\n\tTitle    string        `json:\"title\"`\n\tPath     string        `json:\"path\"`\n\tOrder    int           `json:\"order\"`\n\tChildren []CatalogItem `json:\"children\"`\n}\n```\n\n\u003e 來源：`internal/catalog/catalog.go#L9-L20`\n\n`CatalogItem.Path` 存放的是**相對於父節點的路徑片段**（如 `authentication`）或**完整的 filesystem 路徑**（如 `core-modules/authentication`），視 Claude 回傳的格式而定。`flattenItem` 函式會統一正規化為 dot-notation。\n\n### FlatItem\n\n```go\n// FlatItem represents a flattened catalog item with computed paths.\ntype FlatItem struct {\n\tTitle      string\n\tPath       string // dot-notation path, e.g., \"core-modules.authentication\"\n\tDirPath    string // filesystem path, e.g., \"core-modules/authentication\"\n\tDepth      int\n\tParentPath string\n\tHasChildren bool\n}\n```\n\n\u003e 來源：`internal/catalog/catalog.go#L22-L30`\n\n`FlatItem` 是下游模組的主要消費介面。`DirPath` 直接對應 `.doc-build/` 目錄下的子目錄結構。\n\n## 核心方法\n\n### Parse — 解析 JSON 目錄\n\n```go\n// Parse parses a JSON string into a Catalog.\nfunc Parse(data string) (*Catalog, error) {\n\tvar cat Catalog\n\tif err := json.Unmarshal([]byte(data), \u0026cat); err != nil {\n\t\treturn nil, fmt.Errorf(\"目錄 JSON 解析失敗: %w\", err)\n\t}\n\n\tif len(cat.Items) == 0 {\n\t\treturn nil, fmt.Errorf(\"目錄不可為空\")\n\t}\n\n\treturn \u0026cat, nil\n}\n```\n\n\u003e 來源：`internal/catalog/catalog.go#L32-L44`\n\n`Parse` 是目錄的入口，在兩個場景下被呼叫：\n1. `GenerateCatalog()` 取得 Claude 回傳 JSON 後立即呼叫\n2. `pipeline.go` 的 `Generate()` 嘗試載入既有的 `_catalog.json` 時呼叫\n\n### Flatten — 深度優先展平\n\n```go\n// Flatten returns all catalog items in depth-first order.\nfunc (c *Catalog) Flatten() []FlatItem {\n\tvar items []FlatItem\n\tfor _, item := range c.Items {\n\t\tflattenItem(\u0026items, item, \"\", 0)\n\t}\n\treturn items\n}\n```\n\n\u003e 來源：`internal/catalog/catalog.go#L46-L53`\n\n`Flatten` 以深度優先順序（DFS）走訪整棵樹，輸出線性的 `[]FlatItem`。其核心邏輯由 `flattenItem` 遞迴實作，並相容兩種路徑格式：\n\n```go\nfunc flattenItem(items *[]FlatItem, item CatalogItem, parentPath string, depth int) {\n\t// Handle both formats:\n\t// Format A: child.Path = \"introduction\" (relative, needs parent prefix)\n\t// Format B: child.Path = \"overview/introduction\" (already includes parent)\n\tpath := item.Path\n\tdirPath := strings.ReplaceAll(path, \".\", \"/\")\n\n\tif parentPath != \"\" {\n\t\tparentDir := strings.ReplaceAll(parentPath, \".\", \"/\")\n\t\tif !strings.HasPrefix(dirPath, parentDir+\"/\") {\n\t\t\tpath = parentPath + \".\" + item.Path\n\t\t\tdirPath = strings.ReplaceAll(path, \".\", \"/\")\n\t\t} else {\n\t\t\tpath = strings.ReplaceAll(dirPath, \"/\", \".\")\n\t\t}\n\t}\n\t// ...\n}\n```\n\n\u003e 來源：`internal/catalog/catalog.go#L55-L87`\n\n### BuildLinkTable — 建立 Prompt 用連結表格\n\n```go\n// BuildLinkTable returns a formatted string showing all catalog items\n// and their corresponding directory paths, for use in prompts.\nfunc (c *Catalog) BuildLinkTable() string {\n\titems := c.Flatten()\n\tvar sb strings.Builder\n\tfor _, item := range items {\n\t\tindent := strings.Repeat(\"  \", item.Depth)\n\t\tsb.WriteString(fmt.Sprintf(\"%s- 「%s」 → %s/index.md\\n\", indent, item.Title, item.DirPath))\n\t}\n\treturn sb.String()\n}\n```\n\n\u003e 來源：`internal/catalog/catalog.go#L103-L113`\n\n此方法產生的字串會被嵌入至 content.tmpl prompt 中，讓 Claude 在撰寫各頁面的「相關連結」章節時，能正確引用其他頁面的路徑。\n\n### ToJSON — 序列化為 JSON\n\n```go\n// ToJSON serializes the catalog to indented JSON.\nfunc (c *Catalog) ToJSON() (string, error) {\n\tdata, err := json.MarshalIndent(c, \"\", \"  \")\n\tif err != nil {\n\t\treturn \"\", err\n\t}\n\treturn string(data), nil\n}\n```\n\n\u003e 來源：`internal/catalog/catalog.go#L89-L96`\n\n`ToJSON` 配合 `output.Writer.WriteCatalogJSON()` 將目錄持久化至 `.doc-build/_catalog.json`，供後續的增量更新（`selfmd update`）重新讀取。\n\n## 核心流程\n\n### 目錄生命週期\n\n```mermaid\nsequenceDiagram\n    participant Pipeline as pipeline.go\n    participant CatalogPhase as catalog_phase.go\n    participant CatalogPkg as catalog.go\n    participant Writer as output/writer.go\n    participant Claude as Claude CLI\n\n    Pipeline-\u003e\u003eWriter: ReadCatalogJSON()\n    alt _catalog.json 存在且可讀\n        Writer--\u003e\u003ePipeline: JSON 字串\n        Pipeline-\u003e\u003eCatalogPkg: Parse(jsonStr)\n        CatalogPkg--\u003e\u003ePipeline: *Catalog（重用既有目錄）\n    else 不存在或需要全新產生\n        Pipeline-\u003e\u003eCatalogPhase: GenerateCatalog(scan)\n        CatalogPhase-\u003e\u003eClaude: RunWithRetry（catalog prompt）\n        Claude--\u003e\u003eCatalogPhase: JSON 回應\n        CatalogPhase-\u003e\u003eCatalogPkg: ExtractJSONBlock → Parse()\n        CatalogPkg--\u003e\u003eCatalogPhase: *Catalog\n        CatalogPhase-\u003e\u003eWriter: WriteCatalogJSON(cat)\n        CatalogPhase--\u003e\u003ePipeline: *Catalog\n    end\n\n    Pipeline-\u003e\u003eCatalogPkg: Flatten()\n    CatalogPkg--\u003e\u003ePipeline: []FlatItem（所有頁面）\n\n    Pipeline-\u003e\u003eCatalogPkg: BuildLinkTable()\n    CatalogPkg--\u003e\u003ePipeline: 連結表格字串（注入 prompt）\n```\n\n### 增量更新中的目錄擴展\n\n當 `selfmd update` 偵測到未被現有文件覆蓋的變更檔案時，會動態向目錄新增項目：\n\n```mermaid\nflowchart TD\n    A[\"unmatched 變更檔案\"] --\u003e B[\"determineUnmatchedPages()\"]\n    B --\u003e C[\"Claude 判斷是否需要新頁面\"]\n    C --\u003e D{\"需要新增？\"}\n    D --\u003e|是| E[\"addItemToCatalog(cat, catalogPath, title)\"]\n    D --\u003e|否| F[\"跳過\"]\n    E --\u003e G{\"目標父節點存在且\\n目前為葉節點？\"}\n    G --\u003e|是，需升級| H[\"insertOverviewChild\\n原葉節點 → .overview 子節點\"]\n    G --\u003e|否| I[\"直接插入新葉節點\"]\n    H --\u003e J[\"WriteCatalogJSON（更新持久化）\"]\n    I --\u003e J\n    J --\u003e K[\"重建 BuildLinkTable 與 LinkFixer\"]\n```\n\n\u003e 來源：`internal/generator/updater.go#L369-L430`\n\n## 使用範例\n\n### 在產生器中取得所有頁面\n\n```go\n// 在 content_phase.go 中，取得目錄的線性清單並並行產生每一頁\nitems := cat.Flatten()\ncatalogTable := cat.BuildLinkTable()\nlinkFixer := output.NewLinkFixer(cat)\n\nfor _, item := range items {\n    // 每個 item 是 FlatItem，可直接用 item.DirPath 寫入檔案\n    err := g.generateSinglePage(ctx, scan, item, catalogTable, linkFixer, \"\")\n}\n```\n\n\u003e 來源：`internal/generator/content_phase.go#L22-L55`\n\n### WriteCatalogJSON 持久化目錄\n\n```go\n// 在 pipeline.go 中，目錄產生後立即持久化\nif err := g.Writer.WriteCatalogJSON(cat); err != nil {\n    g.Logger.Warn(\"保存目錄 JSON 失敗\", \"error\", err)\n}\n```\n\n\u003e 來源：`internal/generator/pipeline.go#L124-L126`\n\n### 讀取既有目錄（增量更新）\n\n```go\n// 在 updater.go 中，讀取上次產生的目錄\nexistingCatalogJSON, err := g.Writer.ReadCatalogJSON()\nif err != nil {\n    return fmt.Errorf(\"讀取現有目錄失敗（請先執行 selfmd generate）: %w\", err)\n}\ncat, err := catalog.Parse(existingCatalogJSON)\n```\n\n\u003e 來源：`internal/generator/updater.go#L33-L40`\n\n### BuildLinkTable 輸出範例\n\n`BuildLinkTable()` 產生的字串格式如下（以本專案的目錄為例）：\n\n```\n- 「概述」 → overview/index.md\n  - 「專案介紹與功能特色」 → overview/introduction/index.md\n  - 「技術棧與相依套件」 → overview/tech-stack/index.md\n- 「核心模組」 → core-modules/index.md\n  - 「文件目錄管理」 → core-modules/catalog/index.md\n```\n\n\u003e 來源：`internal/catalog/catalog.go#L103-L113`\n\n## 相關連結\n\n- [文件產生管線](../generator/index.md) — 目錄在四階段管線中的完整使用流程\n- [目錄產生階段](../generator/catalog-phase/index.md) — 呼叫 Claude 產生初始目錄的詳細實作\n- [Prompt 模板引擎](../prompt-engine/index.md) — `CatalogPromptData` 與 `catalog.tmpl` 的渲染機制\n- [Claude CLI 執行器](../claude-runner/index.md) — `RunWithRetry` 與 `ExtractJSONBlock` 的實作細節\n- [增量更新](../incremental-update/index.md) — `addItemToCatalog` 的動態目錄擴展流程\n- [輸出寫入與連結修復](../output-writer/index.md) — `WriteCatalogJSON`、`ReadCatalogJSON` 與 `LinkFixer` 的使用方式\n- [整體流程與四階段管線](../../architecture/pipeline/index.md) — 目錄在整體架構中的角色\n\n## 參考檔案\n\n| 檔案路徑 | 說明 |\n|----------|------|\n| `internal/catalog/catalog.go` | `Catalog`、`CatalogItem`、`FlatItem` 結構定義，以及 `Parse`、`Flatten`、`ToJSON`、`BuildLinkTable` 等核心方法實作 |\n| `internal/generator/catalog_phase.go` | `GenerateCatalog()`：呼叫 Claude 並使用 `catalog.Parse` 解析回應 |\n| `internal/generator/pipeline.go` | 四階段管線主流程，包含目錄的快取讀取與持久化邏輯 |\n| `internal/generator/content_phase.go` | `GenerateContent()`：使用 `cat.Flatten()` 與 `cat.BuildLinkTable()` 並行產生頁面 |\n| `internal/generator/index_phase.go` | `GenerateIndex()`：使用 `cat.Flatten()` 產生分類索引頁 |\n| `internal/generator/updater.go` | `Update()`、`addItemToCatalog()`：增量更新流程與動態目錄擴展 |\n| `internal/output/writer.go` | `WriteCatalogJSON()`、`ReadCatalogJSON()`：目錄的 JSON 持久化讀寫 |\n| `internal/output/navigation.go` | `GenerateIndex()`、`GenerateSidebar()`：使用 `cat.Items` 產生導航檔案 |\n| `internal/prompt/engine.go` | `CatalogPromptData` 定義與 `RenderCatalog()` 渲染方法 |","core-modules/claude-runner/index.md":"# Claude CLI 執行器\n\n`claude` 套件封裝了對 Claude CLI 子行程的所有呼叫，提供統一的執行介面、重試邏輯、超時控制以及回應解析功能。\n\n## 概述\n\nClaude CLI 執行器（`internal/claude`）是 selfmd 與 AI 模型互動的唯一入口。它負責：\n\n- **子行程管理**：透過 `os/exec` 啟動 `claude -p --output-format json` 子行程，並以 stdin 傳入 Prompt\n- **參數組裝**：根據 `ClaudeConfig` 與每次呼叫的 `RunOptions` 動態組裝 CLI 引數\n- **安全限制**：強制禁止 Claude 使用 `Write`、`Edit` 工具，防止子行程修改本地檔案\n- **重試機制**：在呼叫失敗或 Claude 本身回報錯誤時，以線性退避（linear backoff）自動重試\n- **回應解析**：將 JSON 格式的 CLI 輸出轉換為 Go 結構體，並提供多種輔助函式從 Claude 回應中擷取特定格式內容\n\n整個產生管線（`internal/generator`）的所有階段皆共用同一個 `Runner` 實例，由 `Generator` 結構體持有並傳遞。\n\n## 架構\n\n### 模組結構\n\n```mermaid\nflowchart TD\n    subgraph claude_pkg[\"package claude\"]\n        Runner[\"Runner\\n執行器\"]\n        RunOptions[\"RunOptions\\n執行選項\"]\n        RunResult[\"RunResult\\n執行結果\"]\n        CLIResponse[\"CLIResponse\\nCLI JSON 回應\"]\n        ParseResponse[\"ParseResponse()\"]\n        ExtractJSONBlock[\"ExtractJSONBlock()\"]\n        ExtractMarkdown[\"ExtractMarkdown()\"]\n        ExtractDocumentTag[\"ExtractDocumentTag()\"]\n        cleanBoilerplate[\"cleanBoilerplate()（私有）\"]\n    end\n\n    ClaudeConfig[\"config.ClaudeConfig\\n設定結構\"]\n    ClaudeCLI[\"claude CLI\\n子行程\"]\n    GeneratorPkg[\"generator 套件\\n各產生階段\"]\n\n    ClaudeConfig --\u003e|\"注入\"| Runner\n    GeneratorPkg --\u003e|\"呼叫 RunWithRetry()\"| Runner\n    Runner --\u003e|\"組裝引數\"| RunOptions\n    Runner --\u003e|\"exec.CommandContext\"| ClaudeCLI\n    ClaudeCLI --\u003e|\"stdout JSON\"| ParseResponse\n    ParseResponse --\u003e|\"填入\"| RunResult\n    RunResult --\u003e|\"回傳給\"| GeneratorPkg\n    GeneratorPkg --\u003e|\"ExtractJSONBlock()\"| ExtractJSONBlock\n    GeneratorPkg --\u003e|\"ExtractDocumentTag()\"| ExtractDocumentTag\n    ExtractMarkdown --\u003e|\"呼叫\"| cleanBoilerplate\n    CLIResponse --\u003e|\"json.Unmarshal\"| ParseResponse\n```\n\n### 依賴關係\n\n```mermaid\nflowchart LR\n    catalog_phase[\"catalog_phase\\n目錄產生階段\"]\n    content_phase[\"content_phase\\n內容產生階段\"]\n    translate_phase[\"translate_phase\\n翻譯階段\"]\n    updater[\"updater\\n增量更新\"]\n\n    Runner[\"claude.Runner\"]\n\n    catalog_phase --\u003e|\"RunWithRetry + ExtractJSONBlock\"| Runner\n    content_phase --\u003e|\"RunWithRetry + ExtractDocumentTag\"| Runner\n    translate_phase --\u003e|\"RunWithRetry + ExtractDocumentTag\"| Runner\n    updater --\u003e|\"RunWithRetry + ExtractJSONBlock\"| Runner\n```\n\n## 核心型別\n\n### RunOptions — 執行選項\n\n每次呼叫 Claude CLI 時傳入的參數集合：\n\n```go\n// RunOptions configures a single Claude CLI invocation.\ntype RunOptions struct {\n\tPrompt       string\n\tWorkDir      string        // CWD for the claude process\n\tAllowedTools []string      // tool restrictions\n\tModel        string        // model override\n\tTimeout      time.Duration // per-invocation timeout\n\tExtraArgs    []string      // additional CLI arguments\n}\n```\n\n\u003e 來源：internal/claude/types.go#L6-L13\n\n| 欄位 | 說明 |\n|------|------|\n| `Prompt` | 傳入 Claude stdin 的完整提示文字 |\n| `WorkDir` | 子行程的工作目錄，用於 Claude 存取專案檔案 |\n| `AllowedTools` | 覆蓋設定中的 `allowed_tools`，若為空則使用設定值 |\n| `Model` | 覆蓋設定中的 `model`，若為空則使用設定值 |\n| `Timeout` | 覆蓋設定中的 `timeout_seconds`，若為零則使用設定值 |\n| `ExtraArgs` | 附加在設定 `extra_args` 之後的額外 CLI 引數 |\n\n### RunResult — 執行結果\n\n```go\n// RunResult holds the parsed result from a Claude CLI invocation.\ntype RunResult struct {\n\tContent    string  // the text result from Claude\n\tIsError    bool    // whether Claude reported an error\n\tDurationMs int64   // execution time in milliseconds\n\tCostUSD    float64 // cost of this invocation\n\tSessionID  string  // Claude session ID\n}\n```\n\n\u003e 來源：internal/claude/types.go#L16-L23\n\n### CLIResponse — CLI JSON 原始回應\n\n對應 `claude -p --output-format json` 輸出的 JSON 結構：\n\n```go\n// CLIResponse represents the JSON response from `claude -p --output-format json`.\ntype CLIResponse struct {\n\tType       string  `json:\"type\"`\n\tSubtype    string  `json:\"subtype\"`\n\tIsError    bool    `json:\"is_error\"`\n\tResult     string  `json:\"result\"`\n\tDurationMs int64   `json:\"duration_ms\"`\n\tTotalCost  float64 `json:\"total_cost_usd\"`\n\tSessionID  string  `json:\"session_id\"`\n}\n```\n\n\u003e 來源：internal/claude/types.go#L25-L33\n\n## 執行方法\n\n### Run() — 單次呼叫\n\n`Run()` 執行一次 Claude CLI 呼叫，組裝引數、建立子行程、傳遞 Prompt、等待結果並解析回應：\n\n```go\n// Run executes a single Claude CLI invocation.\nfunc (r *Runner) Run(ctx context.Context, opts RunOptions) (*RunResult, error) {\n\t// build command args\n\targs := []string{\n\t\t\"-p\",\n\t\t\"--output-format\", \"json\",\n\t}\n\n\tmodel := opts.Model\n\tif model == \"\" {\n\t\tmodel = r.config.Model\n\t}\n\tif model != \"\" {\n\t\targs = append(args, \"--model\", model)\n\t}\n\n\t// ...（工具清單組裝省略）\n\n\t// Explicitly block Write/Edit to prevent content from being lost in denied tool calls\n\targs = append(args, \"--disallowedTools\", \"Write\", \"--disallowedTools\", \"Edit\")\n\n\t// ...（超時、子行程建立省略）\n\n\t// pipe prompt via stdin\n\tcmd.Stdin = strings.NewReader(opts.Prompt)\n```\n\n\u003e 來源：internal/claude/runner.go#L30-L75\n\n**引數組裝優先順序：**\n\n1. 固定引數：`-p`、`--output-format json`\n2. Model：`opts.Model` \u003e `config.Model`（均為空則不指定）\n3. AllowedTools：`opts.AllowedTools` \u003e `config.AllowedTools`\n4. 強制禁用：`--disallowedTools Write --disallowedTools Edit`\n5. 附加引數：`config.ExtraArgs` + `opts.ExtraArgs`\n\n### RunWithRetry() — 帶重試呼叫\n\n`RunWithRetry()` 在 `Run()` 基礎上加入線性退避重試。重試次數由 `config.MaxRetries` 控制，每次重試等待 `attempt * 5` 秒：\n\n```go\n// RunWithRetry executes a Claude CLI invocation with retry logic.\nfunc (r *Runner) RunWithRetry(ctx context.Context, opts RunOptions) (*RunResult, error) {\n\tmaxRetries := r.config.MaxRetries\n\tvar lastErr error\n\n\tfor attempt := 0; attempt \u003c= maxRetries; attempt++ {\n\t\tif attempt \u003e 0 {\n\t\t\tbackoff := time.Duration(attempt) * 5 * time.Second\n\t\t\tr.logger.Info(\"重試中\", \"attempt\", attempt+1, \"backoff\", backoff)\n\t\t\tselect {\n\t\t\tcase \u003c-ctx.Done():\n\t\t\t\treturn nil, ctx.Err()\n\t\t\tcase \u003c-time.After(backoff):\n\t\t\t}\n\t\t}\n\n\t\tresult, err := r.Run(ctx, opts)\n\t\tif err == nil \u0026\u0026 !result.IsError {\n\t\t\treturn result, nil\n\t\t}\n\t\t// ...\n\t}\n\treturn nil, fmt.Errorf(\"所有 %d 次嘗試均失敗: %w\", maxRetries+1, lastErr)\n}\n```\n\n\u003e 來源：internal/claude/runner.go#L113-L143\n\n**失敗條件（任一滿足即觸發重試）：**\n- `Run()` 回傳 `err != nil`（子行程錯誤、超時等）\n- `result.IsError == true`（Claude 自身回報錯誤）\n\n### CheckAvailable() — 環境檢查\n\n```go\n// CheckAvailable verifies that the claude CLI is installed and accessible.\nfunc CheckAvailable() error {\n\t_, err := exec.LookPath(\"claude\")\n\tif err != nil {\n\t\treturn fmt.Errorf(\"找不到 claude CLI。請先安裝 Claude Code：https://docs.anthropic.com/en/docs/claude-code\")\n\t}\n\treturn nil\n}\n```\n\n\u003e 來源：internal/claude/runner.go#L146-L152\n\n## 回應解析函式\n\n`parser.go` 提供四個公開函式，供產生管線各階段從 Claude 回應中擷取所需格式的內容。\n\n### ParseResponse() — 解析 CLI JSON\n\n將 `claude -p --output-format json` 的原始 JSON 輸出轉換為 `RunResult`：\n\n```go\nfunc ParseResponse(data []byte) (*RunResult, error) {\n\tvar resp CLIResponse\n\tif err := json.Unmarshal(data, \u0026resp); err != nil {\n\t\treturn nil, fmt.Errorf(\"JSON 解析失敗: %w\", err)\n\t}\n\n\treturn \u0026RunResult{\n\t\tContent:    resp.Result,\n\t\tIsError:    resp.IsError,\n\t\tDurationMs: resp.DurationMs,\n\t\tCostUSD:    resp.TotalCost,\n\t\tSessionID:  resp.SessionID,\n\t}, nil\n}\n```\n\n\u003e 來源：internal/claude/parser.go#L11-L24\n\n### ExtractJSONBlock() — 擷取 JSON 區塊\n\n從 Claude 的 Markdown 回應中擷取第一個 JSON 物件，依序嘗試三種策略：\n\n```go\nfunc ExtractJSONBlock(text string) (string, error) {\n\t// try fenced code block first\n\tre := regexp.MustCompile(\"(?s)```json\\\\s*\\n(.*?)```\")\n\t// ...\n\t// try without language tag\n\tre = regexp.MustCompile(\"(?s)```\\\\s*\\n(\\\\{.*?\\\\})\\\\s*```\")\n\t// ...\n\t// try to find raw JSON object\n\tstart := strings.Index(text, \"{\")\n\t// ...\n}\n```\n\n\u003e 來源：internal/claude/parser.go#L28-L61\n\n**三階段擷取策略：**\n1. ` ```json ... ``` ` 圍欄程式碼區塊\n2. ` ``` ... ``` ` 不含語言標籤的圍欄區塊（內容為 JSON 物件）\n3. 直接從原始文字中尋找 `{...}` 配對的 JSON 物件\n\n**使用場景**：`catalog_phase`（目錄產生）與 `updater`（增量更新判斷）呼叫此函式解析 Claude 回傳的 JSON 結果。\n\n### ExtractDocumentTag() — 擷取 `\u003cdocument\u003e` 標籤\n\n從 Claude 回應中擷取 `\u003cdocument\u003e...","core-modules/generator/catalog-phase/index.md":"# 目錄產生階段\n\n目錄產生階段（Catalog Phase）是整個文件產生管線的第二階段，負責透過 Claude CLI 分析專案結構，並自動生成結構化的文件目錄樹。\n\n## 概述\n\n在 selfmd 的四階段管線中，目錄產生階段（Pipeline 第 2 階段）扮演核心樞紐角色：它接收掃描器的專案結構資料，透過 Prompt 模板引擎組裝提示語，呼叫 Claude CLI 進行 AI 分析，最終輸出一份結構化的 `Catalog`（文件目錄）物件，供後續的內容頁面產生階段使用。\n\n本階段的關鍵設計決策包括：\n\n- **AI 驅動**：讓 Claude 理解程式碼語意，而非單純分析檔案結構，以產生更符合業務邏輯的文件目錄\n- **快取復用**：若輸出目錄中已存在 `_catalog.json`，則直接載入跳過本階段，節省 API 費用\n- **重試機制**：透過 `RunWithRetry` 應對 Claude CLI 的暫時性失敗\n- **結構化輸出**：強制要求 Claude 輸出 JSON 格式，再解析為強型別的 `Catalog` 結構\n\n## 架構\n\n```mermaid\nflowchart TD\n    Pipeline[\"pipeline.go\\nGenerator.Generate()\"]\n    CatalogPhase[\"catalog_phase.go\\nGenerator.GenerateCatalog()\"]\n    PromptEngine[\"prompt.Engine\\nRenderCatalog()\"]\n    CatalogTmpl[\"catalog.tmpl\\n（語言模板）\"]\n    ClaudeRunner[\"claude.Runner\\nRunWithRetry()\"]\n    ExtractJSON[\"claude.ExtractJSONBlock()\"]\n    CatalogParse[\"catalog.Parse()\"]\n    CatalogStruct[\"catalog.Catalog\\n結構化目錄\"]\n    Writer[\"output.Writer\\nWriteCatalogJSON()\"]\n\n    Pipeline --\u003e|\"clean 或無快取\"| CatalogPhase\n    Pipeline --\u003e|\"有快取 _catalog.json\"| Writer2[\"output.Writer\\nReadCatalogJSON()\"]\n    Writer2 --\u003e|JSON 字串| CatalogParse\n    CatalogPhase --\u003e PromptEngine\n    PromptEngine --\u003e CatalogTmpl\n    CatalogTmpl --\u003e|rendered prompt| ClaudeRunner\n    ClaudeRunner --\u003e|RunResult.Content| ExtractJSON\n    ExtractJSON --\u003e|JSON 字串| CatalogParse\n    CatalogParse --\u003e CatalogStruct\n    CatalogPhase --\u003e|\"儲存快取\"| Writer\n```\n\n## 入口方法\n\n`GenerateCatalog` 定義在 `internal/generator/catalog_phase.go`，是本階段唯一的公開方法：\n\n```go\nfunc (g *Generator) GenerateCatalog(ctx context.Context, scan *scanner.ScanResult) (*catalog.Catalog, error) {\n\tlangName := config.GetLangNativeName(g.Config.Output.Language)\n\tdata := prompt.CatalogPromptData{\n\t\tRepositoryName:       g.Config.Project.Name,\n\t\tProjectType:          g.Config.Project.Type,\n\t\tLanguage:             g.Config.Output.Language,\n\t\tLanguageName:         langName,\n\t\tLanguageOverride:     g.Config.Output.NeedsLanguageOverride(),\n\t\tLanguageOverrideName: langName,\n\t\tKeyFiles:             scan.KeyFiles(),\n\t\tEntryPoints:          scan.EntryPointsFormatted(),\n\t\tFileTree:             scanner.RenderTree(scan.Tree, 4),\n\t\tReadmeContent:        scan.ReadmeContent,\n\t}\n\n\trendered, err := g.Engine.RenderCatalog(data)\n\tif err != nil {\n\t\treturn nil, err\n\t}\n\t// ...\n}\n```\n\n\u003e 來源：internal/generator/catalog_phase.go#L16-L34\n\n### CatalogPromptData 欄位說明\n\n`prompt.CatalogPromptData` 結構集合了所有用於驅動 Claude 分析的上下文資料：\n\n| 欄位 | 來源 | 說明 |\n|------|------|------|\n| `RepositoryName` | `config.Project.Name` | 專案名稱 |\n| `ProjectType` | `config.Project.Type` | 專案類型（如 `go-cli`） |\n| `Language` | `config.Output.Language` | 目標輸出語言代碼（如 `zh-TW`） |\n| `LanguageName` | `GetLangNativeName()` | 語言的本地名稱（如「繁體中文」） |\n| `LanguageOverride` | `Output.NeedsLanguageOverride()` | 模板語言與輸出語言是否不一致 |\n| `KeyFiles` | `scan.KeyFiles()` | 重要檔案清單（main.go、go.mod 等） |\n| `EntryPoints` | `scan.EntryPointsFormatted()` | 入口檔案的格式化內容 |\n| `FileTree` | `scanner.RenderTree(scan.Tree, 4)` | 深度限制 4 層的檔案樹文字 |\n| `ReadmeContent` | `scan.ReadmeContent` | README 內容（最多 50,000 字元） |\n\n\u003e 來源：internal/prompt/engine.go#L39-L51\n\n## 快取復用機制\n\n在 `pipeline.go` 的 `Generate()` 方法中，目錄產生具備智慧快取邏輯：\n\n```go\nvar cat *catalog.Catalog\nif !clean {\n\t// Try to reuse existing catalog\n\tcatJSON, readErr := g.Writer.ReadCatalogJSON()\n\tif readErr == nil {\n\t\tcat, err = catalog.Parse(catJSON)\n\t}\n\tif cat != nil {\n\t\titems := cat.Flatten()\n\t\tfmt.Printf(ui.T(\"[2/4] 載入已存目錄（%d 個章節，%d 個項目）\\n\", ...), len(cat.Items), len(items))\n\t}\n}\nif cat == nil {\n\tfmt.Println(ui.T(\"[2/4] 產生文件目錄...\", ...))\n\tcat, err = g.GenerateCatalog(ctx, scan)\n\t// ...\n\tif err := g.Writer.WriteCatalogJSON(cat); err != nil {\n\t\tg.Logger.Warn(...)\n\t}\n}\n```\n\n\u003e 來源：internal/generator/pipeline.go#L103-L128\n\n快取以 `_catalog.json` 檔案儲存在輸出目錄（`.doc-build/`）下。以下情況會重新呼叫 Claude 產生目錄：\n\n- 使用者指定 `--clean` 旗標\n- 設定中 `output.clean_before_generate: true`\n- `_catalog.json` 檔案不存在或無法讀取\n- `_catalog.json` 解析失敗\n\n## 核心流程\n\n```mermaid\nsequenceDiagram\n    participant Pipeline as pipeline.go\n    participant CatalogPhase as catalog_phase.go\n    participant Engine as prompt.Engine\n    participant Runner as claude.Runner\n    participant Parser as claude.parser.go\n    participant CatalogPkg as catalog.Parse()\n    participant Writer as output.Writer\n\n    Pipeline-\u003e\u003eWriter: ReadCatalogJSON()\n    alt 快取存在且有效\n        Writer--\u003e\u003ePipeline: JSON 字串\n        Pipeline-\u003e\u003eCatalogPkg: Parse(jsonStr)\n        CatalogPkg--\u003e\u003ePipeline: *Catalog（復用）\n    else 需要重新產生\n        Pipeline-\u003e\u003eCatalogPhase: GenerateCatalog(ctx, scan)\n        CatalogPhase-\u003e\u003eEngine: RenderCatalog(CatalogPromptData)\n        Engine--\u003e\u003eCatalogPhase: rendered prompt 字串\n        CatalogPhase-\u003e\u003eRunner: RunWithRetry(ctx, RunOptions{Prompt, WorkDir})\n        loop 最多 maxRetries+1 次\n            Runner-\u003e\u003eRunner: Run()（呼叫 claude CLI）\n            Runner--\u003e\u003eRunner: ParseResponse()\n        end\n        Runner--\u003e\u003eCatalogPhase: *RunResult{Content, CostUSD, DurationMs}\n        CatalogPhase-\u003e\u003eParser: ExtractJSONBlock(result.Content)\n        Parser--\u003e\u003eCatalogPhase: JSON 字串\n        CatalogPhase-\u003e\u003eCatalogPkg: Parse(jsonStr)\n        CatalogPkg--\u003e\u003eCatalogPhase: *Catalog\n        CatalogPhase--\u003e\u003ePipeline: *Catalog\n        Pipeline-\u003e\u003eWriter: WriteCatalogJSON(cat)\n    end\n```\n\n## Catalog 資料結構\n\nClaude 必須以 JSON 格式輸出目錄，再由 `catalog.Parse()` 解析為強型別結構：\n\n```go\n// Catalog represents the documentation catalog structure.\ntype Catalog struct {\n\tItems []CatalogItem `json:\"items\"`\n}\n\n// CatalogItem represents a single item in the catalog tree.\ntype CatalogItem struct {\n\tTitle    string        `json:\"title\"`\n\tPath     string        `json:\"path\"`\n\tOrder    int           `json:\"order\"`\n\tChildren []CatalogItem `json:\"children\"`\n}\n```\n\n\u003e 來源：internal/catalog/catalog.go#L9-L20\n\nClaude 輸出的原始 JSON 範例格式：\n\n```json\n{\n  \"items\": [\n    {\n      \"title\": \"概述\",\n      \"path\": \"overview\",\n      \"order\": 0,\n      \"children\": [\n        {\n          \"title\": \"專案介紹與功能特色\",\n          \"path\": \"introduction\",\n          \"order\": 0,\n          \"children\": []\n        }\n      ]\n    }\n  ]\n}\n```\n\n## JSON 擷取邏輯\n\nClaude 的回應可能包含 Markdown 格式的說明文字，`ExtractJSONBlock` 採三階段降級策略從中擷取 JSON：\n\n```go\nfunc ExtractJSONBlock(text string) (string, error) {\n\t// 策略 1：尋找 ```json ... ``` 圍欄程式碼區塊\n\tre := regexp.MustCompile(\"(?s)```json\\\\s*\\n(.*?)```\")\n\tmatches := re.FindStringSubmatch(text)\n\tif len(matches) \u003e 1 {\n\t\treturn strings.TrimSpace(matches[1]), nil\n\t}\n\n\t// 策略 2：尋找無語言標籤的 ``` ... ``` 圍欄區塊\n\tre = regexp.MustCompile(\"(?s)```\\\\s*\\n(\\\\{.*?\\\\})\\\\s*```\")\n\t// ...\n\n\t// 策略 3：在純文字中尋找原始 JSON 物件（括號平衡掃描）\n\tstart := strings.Index(text, \"{\")\n\t// ...\n}\n```\n\n\u003e 來源：internal/claude/parser.go#L26-L61\n\n## 統計追蹤\n\n每次成功呼叫 Claude 後，費用會累計到 `Generator.TotalCost`：\n\n```go\ng.TotalCost += result.CostUSD\nfmt.Printf(ui.T(\" 完成（%.1fs，$%.4f）\\n\", \" Done (%.1fs, $%.4f)\\n\"),\n    float64(result.DurationMs)/1000, result.CostUSD)\n```\n\n\u003e 來源：internal/generator/catalog_phase.go#L47-L48\n\n## Prompt 模板\n\n目錄產生使用的 Prompt 模板位於 `internal/prompt/templates/\u003clang\u003e/catalog.tmpl`，模板要求 Claude：\n\n1. 使用工具（Glob、Read、Grep）實際探索專案原始碼\n2. 依業務功能而非檔案結構設計目錄\n3. 僅輸出一個 `\\`\\`\\`json` 程式碼區塊，不附加任何說明文字\n\n\u003e 來源：internal/prompt/templates/zh-TW/catalog.tmpl#L1-L121\n\n## 相關連結\n\n- [文件產生管線](../index.md) — 了解本階段在四階段管線中的完整位置\n- [內容頁面產生階段](../content-phase/index.md) — 接收本階段輸出 Catalog 的下一個階段\n- [文件目錄管理](../../catalog/index.md) — `Catalog`、`CatalogItem`、`FlatItem` 資料結構詳解\n- [Prompt 模板引擎](../../prompt-engine/index.md) — `Engine.RenderCatalog()` 與模板系統\n- [Claude CLI 執行器](../../claude-runner/index.md) — `Runner.RunWithRetry()` 的重試機制詳解\n- [專案掃描器](../../scanner/index.md) — 提供本階段輸入資料的 `ScanResult`\n- [整體流程與四階段管線](../../../architecture/pipeline/index.md) — 系統架構總覽\n\n## 參考檔案\n\n| 檔案路徑 | 說明 |\n|----------|------|\n| `internal/generator/catalog_phase.go` | `GenerateCatalog()` 主要實作 |\n| `internal/generator/pipeline.go` | 管線編排、快取復用邏輯與費用統計 |\n| `internal/catalog/catalog.go` | `Catalog`、`CatalogItem`、`FlatItem` 資料結構與解析邏輯 |\n| `internal/prompt/engine.go` | `CatalogPromptData` 定義與 `RenderCatalog()` |\n| `internal/prompt/templates/zh-TW/catalog.tmpl` | 繁體中文目錄產生 Prompt 模板 |\n| `internal/claude/runner.go` | `Runner.Run()` 與 `RunWithRetry()` 實作 |\n| `internal/claude/types.go` | `RunOptions`、`RunResult`、`CLIResponse` 結構定義 |\n| `internal/claude/parser.go` | `ExtractJSONBlock()` JSON 擷取邏輯 |\n| `internal/scanner/scanner.go` | `ScanResult.KeyFiles()` 與 `EntryPointsFormatted()` |\n| `internal/output/writer.go` | `WriteCatalogJSON()` 與 `ReadCatalogJSON()` 快取操作 |","core-modules/generator/content-phase/index.md":"# 內容頁面產生階段\n\n內容頁面產生階段（Phase 3）是 selfmd 四階段管線的核心，負責將目錄中的每個條目平行地轉換為完整的 Markdown 文件頁面。\n\n## 概述\n\n當目錄（Catalog）建立完畢後，內容產生階段接手，對目錄中每一個 `FlatItem`（扁平化目錄項目）呼叫 Claude CLI，要求其根據專案原始碼產生對應的說明文件。\n\n此階段的主要職責包括：\n\n- **並行控制**：透過 `errgroup` 與 semaphore 實現可設定的並行度，同時保護系統資源\n- **跳過既有頁面**：非 clean 模式下，已存在且有效的頁面將被略過，節省 API 費用\n- **重試與格式驗證**：確保 Claude 輸出符合格式要求（必須有 `\u003cdocument\u003e` 標籤且包含 Markdown 標題）\n- **連結修復後處理**：產生後自動修復頁面內的相對路徑連結\n- **失敗降級**：頁面產生失敗時寫入佔位頁面，不中斷整體流程\n\n核心實作位於 `internal/generator/content_phase.go`，主要入口為 `Generator.GenerateContent()`。\n\n## 架構\n\n```mermaid\nflowchart TD\n    GC[\"GenerateContent()\"] --\u003e FL[\"cat.Flatten()\"]\n    GC --\u003e BLT[\"cat.BuildLinkTable()\"]\n    GC --\u003e NLF[\"output.NewLinkFixer()\"]\n    GC --\u003e EG[\"errgroup + semaphore channel\"]\n\n    EG --\u003e CHK[\"Writer.PageExists()\"]\n    CHK -- \"skipExisting \u0026\u0026 已存在\" --\u003e SKIP[\"atomic skipped++\"]\n    CHK -- \"需要產生\" --\u003e GSP[\"generateSinglePage()\"]\n\n    GSP --\u003e CPD[\"ContentPromptData 組裝\"]\n    CPD --\u003e RND[\"Engine.RenderContent()\"]\n    RND --\u003e RWR[\"Runner.RunWithRetry()\"]\n    RWR --\u003e EDT[\"ExtractDocumentTag()\"]\n    EDT --\u003e VAL{\"格式驗證\"}\n    VAL -- \"通過\" --\u003e LFX[\"LinkFixer.FixLinks()\"]\n    LFX --\u003e WP[\"Writer.WritePage()\"]\n    VAL -- \"失敗，可重試\" --\u003e RWR\n    VAL -- \"超過最大嘗試次數\" --\u003e ERR[\"atomic failed++\"]\n    ERR --\u003e WPH[\"writePlaceholder()\"]\n```\n\n## 主要元件與資料結構\n\n### Generator 結構體\n\n`Generator` 是整個管線的協調者，在 `pipeline.go` 中定義：\n\n```go\ntype Generator struct {\n    Config  *config.Config\n    Runner  *claude.Runner\n    Engine  *prompt.Engine\n    Writer  *output.Writer\n    Logger  *slog.Logger\n    RootDir string\n\n    TotalCost   float64\n    TotalPages  int\n    FailedPages int\n}\n```\n\n\u003e 來源：internal/generator/pipeline.go#L19-L31\n\n### ContentPromptData 資料模型\n\n`generateSinglePage()` 為每個頁面組裝以下 prompt 資料結構：\n\n```go\ndata := prompt.ContentPromptData{\n    RepositoryName:       g.Config.Project.Name,\n    Language:             g.Config.Output.Language,\n    LanguageName:         langName,\n    LanguageOverride:     g.Config.Output.NeedsLanguageOverride(),\n    LanguageOverrideName: langName,\n    CatalogPath:          item.Path,\n    CatalogTitle:         item.Title,\n    CatalogDirPath:       item.DirPath,\n    ProjectDir:           g.RootDir,\n    FileTree:             scanner.RenderTree(scan.Tree, 3),\n    CatalogTable:         catalogTable,\n    ExistingContent:      existingContent,\n}\n```\n\n\u003e 來源：internal/generator/content_phase.go#L91-L104\n\n`ExistingContent` 在全新產生時為空字串；在增量更新場景（`updater.go`）中會填入既有頁面內容，供 Claude 進行修改而非全量重寫。\n\n## 核心流程\n\n### 並行產生流程\n\n```mermaid\nsequenceDiagram\n    participant GC as GenerateContent\n    participant EG as errgroup\n    participant SEM as semaphore\n    participant GSP as generateSinglePage\n    participant CR as Runner.RunWithRetry\n    participant EDT as ExtractDocumentTag\n    participant LF as LinkFixer\n    participant W as Writer\n\n    GC-\u003e\u003eEG: 為每個 FlatItem 啟動 goroutine\n    loop 每個目錄項目\n        EG-\u003e\u003eW: PageExists(item)\n        alt skipExisting \u0026\u0026 頁面存在\n            EG-\u003e\u003eEG: skipped.Add(1)\n        else 需要產生\n            EG-\u003e\u003eSEM: sem \u003c- struct{}{} (取得 token)\n            EG-\u003e\u003eGSP: generateSinglePage(ctx, item)\n            GSP-\u003e\u003eCR: RunWithRetry(ctx, RunOptions)\n            CR--\u003e\u003eGSP: RunResult{Content, CostUSD}\n            GSP-\u003e\u003eEDT: ExtractDocumentTag(result.Content)\n            EDT--\u003e\u003eGSP: markdown 字串\n            GSP-\u003e\u003eLF: FixLinks(content, item.DirPath)\n            LF--\u003e\u003eGSP: 修復後的 content\n            GSP-\u003e\u003eW: WritePage(item, content)\n            EG-\u003e\u003eSEM: \u003c-sem (釋放 token)\n        end\n    end\n    GC-\u003e\u003eGC: eg.Wait()\n    GC-\u003e\u003eGC: 更新 TotalPages / FailedPages\n```\n\n### 並行度控制\n\n並行度以 semaphore channel 實作，大小由設定檔的 `claude.max_concurrent` 決定（可透過 CLI `--concurrency` 旗標覆蓋）：\n\n```go\nsem := make(chan struct{}, concurrency)\n\nfor _, item := range items {\n    item := item\n    eg.Go(func() error {\n        // ...skipExisting 檢查...\n\n        sem \u003c- struct{}{}\n        defer func() { \u003c-sem }()\n\n        // 執行 generateSinglePage\n    })\n}\n```\n\n\u003e 來源：internal/generator/content_phase.go#L37-L73\n\n### 格式驗證與重試機制\n\n`generateSinglePage()` 內建最多 2 次嘗試（`maxAttempts = 2`），分別針對兩種格式錯誤情況重試：\n\n```go\nmaxAttempts := 2\nfor attempt := 1; attempt \u003c= maxAttempts; attempt++ {\n    result, err := g.Runner.RunWithRetry(ctx, claude.RunOptions{...})\n\n    // 嘗試從 \u003cdocument\u003e 標籤擷取內容\n    content, extractErr := claude.ExtractDocumentTag(result.Content)\n    if extractErr != nil {\n        if attempt \u003c maxAttempts {\n            fmt.Printf(\" 格式錯誤，重試中...\\n      \")\n            continue\n        }\n        return lastErr\n    }\n\n    // 驗證是否有有效的 Markdown 標題\n    content = strings.TrimSpace(content)\n    if content == \"\" || !strings.HasPrefix(content, \"#\") {\n        if attempt \u003c maxAttempts {\n            fmt.Printf(\" 內容無效，重試中...\\n      \")\n            continue\n        }\n        return lastErr\n    }\n\n    // 後處理並寫入\n    content = linkFixer.FixLinks(content, item.DirPath)\n    return g.Writer.WritePage(item, content)\n}\n```\n\n\u003e 來源：internal/generator/content_phase.go#L111-L156\n\n**驗證條件：**\n1. `claude.ExtractDocumentTag()` 必須能從回應中找到 `\u003cdocument\u003e...","core-modules/generator/index-phase/index.md":"# 索引與導航產生階段\n\n索引與導航產生階段（Index Phase）是整個文件產生管線的第四階段，負責根據已建立的目錄結構（`Catalog`），自動產生主索引頁、側邊欄導航檔及各分類的子頁索引，讓整份文件具備可瀏覽的導航骨架。\n\n## 概述\n\n在前三個階段（掃描、目錄產生、內容產生）完成後，所有文件內容已經寫入輸出目錄，但尚缺乏統一的入口與導航結構。索引與導航產生階段的核心職責是：\n\n- **產生 `index.md`**：文件的主入口頁面，以樹狀目錄列出所有章節\n- **產生 `_sidebar.md`**：供 Docsify 等靜態文件瀏覽器使用的側邊欄導航檔\n- **產生各分類索引頁**：對所有「含子項目的父節點」產生獨立的分類索引頁（`\u003csection\u003e/index.md`），列出其直屬子項目的連結\n\n此階段完全基於已建立的 `catalog.Catalog` 結構運作，不需呼叫 Claude CLI，屬於純粹的本地內容產生工作。多語言支援透過 `UIStrings` 字串映射表實現，目前支援 `zh-TW` 與 `en-US` 兩種介面語言。\n\n## 架構\n\n```mermaid\nflowchart TD\n    GenerateIndex[\"GenerateIndex\\n(index_phase.go)\"]\n    Catalog[\"catalog.Catalog\"]\n    Flatten[\"Catalog.Flatten()\"]\n    navGenIndex[\"output.GenerateIndex()\"]\n    navGenSidebar[\"output.GenerateSidebar()\"]\n    navGenCategory[\"output.GenerateCategoryIndex()\"]\n    Writer[\"output.Writer\"]\n    UIStrings[\"output.UIStrings\\n(語言字串對照表)\"]\n\n    WriteFile[\"Writer.WriteFile()\"]\n    WritePage[\"Writer.WritePage()\"]\n\n    outIndex[\"index.md\\n（主入口頁）\"]\n    outSidebar[\"_sidebar.md\\n（側邊欄導航）\"]\n    outCatPages[\"分類索引頁\\n（各 section/index.md）\"]\n\n    GenerateIndex --\u003e Catalog\n    Catalog --\u003e Flatten\n    GenerateIndex --\u003e navGenIndex\n    GenerateIndex --\u003e navGenSidebar\n    GenerateIndex --\u003e navGenCategory\n\n    navGenIndex --\u003e UIStrings\n    navGenSidebar --\u003e UIStrings\n    navGenCategory --\u003e UIStrings\n\n    navGenIndex --\u003e WriteFile --\u003e outIndex\n    navGenSidebar --\u003e WriteFile --\u003e outSidebar\n    navGenCategory --\u003e WritePage --\u003e outCatPages\n\n    Flatten --\u003e|\"HasChildren 判斷\\n及子項目篩選\"| GenerateIndex\n```\n\n## 產出檔案說明\n\n### 主索引頁 `index.md`\n\n由 `output.GenerateIndex()` 產生，包含：\n\n1. 一級標題：`{專案名稱} {techDocs 語言字串}`\n2. 專案描述（若設定中有填寫）\n3. 水平分隔線\n4. 二級標題「目錄」（依語言）\n5. 以縮排巢狀列表展示所有目錄項目，每項均為相對路徑連結\n\n```go\nfunc GenerateIndex(projectName, projectDesc string, cat *catalog.Catalog, lang string) string {\n\tui := getUIStrings(lang)\n\tvar sb strings.Builder\n\n\tsb.WriteString(fmt.Sprintf(\"# %s %s\\n\\n\", projectName, ui[\"techDocs\"]))\n\n\tif projectDesc != \"\" {\n\t\tsb.WriteString(projectDesc + \"\\n\\n\")\n\t}\n\n\tsb.WriteString(\"---\\n\\n\")\n\tsb.WriteString(fmt.Sprintf(\"## %s\\n\\n\", ui[\"catalog\"]))\n\n\tfor _, item := range cat.Items {\n\t\twriteIndexItem(\u0026sb, item, \"\", 0)\n\t}\n\n\tsb.WriteString(\"\\n---\\n\\n\")\n\tsb.WriteString(fmt.Sprintf(\"*%s*\\n\", ui[\"autoGenerated\"]))\n\n\treturn sb.String()\n}\n```\n\n\u003e 來源：internal/output/navigation.go#L38-L59\n\n每個目錄項目的連結由 `writeIndexItem` 遞迴建立，使用 `resolveDirPath` 函式處理 Format A（相對路徑）與 Format B（已含父路徑）兩種格式：\n\n```go\nfunc writeIndexItem(sb *strings.Builder, item catalog.CatalogItem, parentDir string, depth int) {\n\tindent := strings.Repeat(\"  \", depth)\n\tdirPath := resolveDirPath(item.Path, parentDir)\n\n\tlink := fmt.Sprintf(\"./%s/index.md\", dirPath)\n\tsb.WriteString(fmt.Sprintf(\"%s- [%s](%s)\\n\", indent, item.Title, link))\n\n\tfor _, child := range item.Children {\n\t\twriteIndexItem(sb, child, dirPath, depth+1)\n\t}\n}\n```\n\n\u003e 來源：internal/output/navigation.go#L61-L71\n\n---\n\n### 側邊欄導航 `_sidebar.md`\n\n由 `output.GenerateSidebar()` 產生，格式與主索引頁類似，但：\n\n- 標題為純文字的專案名稱（無附加語言字串）\n- 頂部固定插入一個「首頁」連結（指向 `./index.md`）\n\n```go\nfunc GenerateSidebar(projectName string, cat *catalog.Catalog, lang string) string {\n\tui := getUIStrings(lang)\n\tvar sb strings.Builder\n\n\tsb.WriteString(fmt.Sprintf(\"# %s\\n\\n\", projectName))\n\tsb.WriteString(fmt.Sprintf(\"- [%s](./index.md)\\n\", ui[\"home\"]))\n\n\tfor _, item := range cat.Items {\n\t\twriteSidebarItem(\u0026sb, item, \"\", 0)\n\t}\n\n\treturn sb.String()\n}\n```\n\n\u003e 來源：internal/output/navigation.go#L74-L86\n\n---\n\n### 分類索引頁\n\n對所有 `HasChildren == true` 的目錄項目，`GenerateIndex` 會額外產生對應的 `\u003cDirPath\u003e/index.md`，內容為列出其**直屬子項目**的連結列表。\n\n子項目篩選邏輯在 `index_phase.go` 中實作：\n\n```go\nitems := cat.Flatten()\nfor _, item := range items {\n    if !item.HasChildren {\n        continue\n    }\n\n    // find direct children\n    var children []catalog.FlatItem\n    for _, child := range items {\n        if child.ParentPath == item.Path \u0026\u0026 child.Path != item.Path {\n            children = append(children, child)\n        }\n    }\n\n    if len(children) \u003e 0 {\n        categoryContent := output.GenerateCategoryIndex(item, children, lang)\n        if err := g.Writer.WritePage(item, categoryContent); err != nil {\n            g.Logger.Warn(\"寫入分類索引失敗\", \"path\", item.Path, \"error\", err)\n        }\n    }\n}\n```\n\n\u003e 來源：internal/generator/index_phase.go#L32-L52\n\n`output.GenerateCategoryIndex` 使用 `computeRelativePath`（基於 `filepath.Rel`）計算子項目的正確相對路徑：\n\n```go\nfunc GenerateCategoryIndex(item catalog.FlatItem, children []catalog.FlatItem, lang string) string {\n\tui := getUIStrings(lang)\n\tvar sb strings.Builder\n\n\tsb.WriteString(fmt.Sprintf(\"# %s\\n\\n\", item.Title))\n\tsb.WriteString(ui[\"sectionContains\"] + \"\\n\\n\")\n\n\tfor _, child := range children {\n\t\trelPath := computeRelativePath(item.DirPath, child.DirPath)\n\t\tsb.WriteString(fmt.Sprintf(\"- [%s](%s/index.md)\\n\", child.Title, relPath))\n\t}\n\n\treturn sb.String()\n}\n```\n\n\u003e 來源：internal/output/navigation.go#L101-L114\n\n## 多語言字串對照\n\n`navigation.go` 中定義了 `UIStrings` 映射表，以語言代碼為鍵：\n\n```go\nvar UIStrings = map[string]map[string]string{\n\t\"zh-TW\": {\n\t\t\"techDocs\":        \"技術文件\",\n\t\t\"catalog\":         \"目錄\",\n\t\t\"home\":            \"首頁\",\n\t\t\"sectionContains\": \"本章節包含以下內容：\",\n\t\t\"autoGenerated\":   \"本文件由 [selfmd](https://github.com/monkenwu/selfmd) 自動產生\",\n\t},\n\t\"en-US\": {\n\t\t\"techDocs\":        \"Technical Documentation\",\n\t\t\"catalog\":         \"Table of Contents\",\n\t\t\"home\":            \"Home\",\n\t\t\"sectionContains\": \"This section contains the following:\",\n\t\t\"autoGenerated\":   \"This documentation was automatically generated by [selfmd](https://github.com/monkenwu/selfmd)\",\n\t},\n}\n```\n\n\u003e 來源：internal/output/navigation.go#L12-L27\n\n`getUIStrings` 函式在找不到對應語言時，自動退回（fallback）至 `en-US`：\n\n```go\nfunc getUIStrings(lang string) map[string]string {\n\tif s, ok := UIStrings[lang]; ok {\n\t\treturn s\n\t}\n\treturn UIStrings[\"en-US\"]\n}\n```\n\n\u003e 來源：internal/output/navigation.go#L30-L35\n\n語言代碼取自 `g.Config.Output.Language`，在 `GenerateIndex` 入口處讀取：\n\n```go\nfunc (g *Generator) GenerateIndex(_ context.Context, cat *catalog.Catalog) error {\n\tlang := g.Config.Output.Language\n\t// ...\n}\n```\n\n\u003e 來源：internal/generator/index_phase.go#L11-L12\n\n## 核心流程\n\n```mermaid\nsequenceDiagram\n    participant Pipeline as \"pipeline.go\\nGenerate()\"\n    participant IndexPhase as \"index_phase.go\\nGenerateIndex()\"\n    participant Nav as \"output/navigation.go\"\n    participant Writer as \"output.Writer\"\n\n    Pipeline-\u003e\u003eIndexPhase: GenerateIndex(ctx, cat)\n    IndexPhase-\u003e\u003eNav: output.GenerateIndex(name, desc, cat, lang)\n    Nav--\u003e\u003eIndexPhase: indexContent (string)\n    IndexPhase-\u003e\u003eWriter: WriteFile(\"index.md\", indexContent)\n\n    IndexPhase-\u003e\u003eNav: output.GenerateSidebar(name, cat, lang)\n    Nav--\u003e\u003eIndexPhase: sidebarContent (string)\n    IndexPhase-\u003e\u003eWriter: WriteFile(\"_sidebar.md\", sidebarContent)\n\n    IndexPhase-\u003e\u003eIndexPhase: cat.Flatten() → 取得所有 FlatItem\n\n    loop 每個 HasChildren == true 的 item\n        IndexPhase-\u003e\u003eIndexPhase: 篩選 child.ParentPath == item.Path 的直屬子項\n        IndexPhase-\u003e\u003eNav: output.GenerateCategoryIndex(item, children, lang)\n        Nav--\u003e\u003eIndexPhase: categoryContent (string)\n        IndexPhase-\u003e\u003eWriter: WritePage(item, categoryContent)\n    end\n\n    IndexPhase--\u003e\u003ePipeline: nil (success)\n\n    Pipeline-\u003e\u003eWriter: WriteViewer(projectName, docMeta)\n    Note over Writer: 產生 index.html、app.js、\u003cbr/\u003estyle.css、_data.js（靜態瀏覽器）\n```\n\n## 路徑解析邏輯\n\n### `resolveDirPath`\n\n`navigation.go` 中的 `resolveDirPath` 處理目錄項目路徑的兩種格式：\n\n- **Format A**：`item.Path` 為相對路徑（如 `\"init\"`），需要拼接父路徑 → 輸出 `\"cli/init\"`\n- **Format B**：`item.Path` 已包含父路徑前綴（如 `\"cli/init\"`），直接使用\n\n```go\nfunc resolveDirPath(itemPath, parentDir string) string {\n\tif parentDir == \"\" {\n\t\treturn itemPath\n\t}\n\tif strings.HasPrefix(itemPath, parentDir+\"/\") {\n\t\treturn itemPath\n\t}\n\treturn parentDir + \"/\" + itemPath\n}\n```\n\n\u003e 來源：internal/output/navigation.go#L118-L126\n\n### `computeRelativePath`\n\n分類索引頁中子項目的連結使用 `computeRelativePath` 計算相對路徑，底層依賴標準庫的 `filepath.Rel`：\n\n```go\nfunc computeRelativePath(fromDir, toDir string) string {\n\trel, err := filepath.Rel(fromDir, toDir)\n\tif err != nil {\n\t\treturn \"./\" + toDir\n\t}\n\treturn filepath.ToSlash(rel)\n}\n```\n\n\u003e 來源：internal/output/navigation.go#L129-L135\n\n## 在管線中的位置\n\n`GenerateIndex` 由 `pipeline.go` 的 `Generate()` 方法在 **Phase 4** 呼叫，緊接在內容頁面產生（Phase 3）之後：\n\n```go\n// Phase 4: Generate Index \u0026 Navigation\nfmt.Println(\"[4/4] 產生導航與索引...\")\nif err := g.GenerateIndex(ctx, cat); err != nil {\n    return fmt.Errorf(\"產生索引失敗: %w\", err)\n}\n```\n\n\u003e 來源：internal/generator/pipeline.go#L139-L143\n\n`GenerateIndex` 完成後，管線繼續呼叫 `g.Writer.WriteViewer()` 產生靜態 HTML 瀏覽器（`index.html`、`app.js`、`style.css`、`_data.js`），此部分屬於 `output.Writer` 的職責，不在 `index_phase.go` 範圍內。\n\n## 相關連結\n\n- [文件產生管線](../index.md)\n- [目錄產生階段](../catalog-phase/index.md)\n- [內容頁面產生階段](../content-phase/index.md)\n- [翻譯階段](../translate-phase/index.md)\n- [文件目錄管理](../../catalog/index.md)\n- [輸出寫入與連結修復](../../output-writer/index.md)\n- [靜態文件瀏覽器](../../static-viewer/index.md)\n- [多語言支援](../../../i18n/index.md)\n- [整體流程與四階段管線](../../../architecture/pipeline/index.md)\n\n## 參考檔案\n\n| 檔案路徑 | 說明 |\n|----------|------|\n| `internal/generator/index_phase.go` | `GenerateIndex` 主函式，分類索引頁篩選邏輯 |\n| `internal/generator/pipeline.go` | `Generator` 結構定義、管線流程、Phase 4 呼叫點 |\n| `internal/output/navigation.go` | `GenerateIndex`、`GenerateSidebar`、`GenerateCategoryIndex` 及路徑解析輔助函式 |\n| `internal/output/writer.go` | `Writer.WriteFile`、`Writer.WritePage`、`DocMeta`、`LangInfo` 結構 |\n| `internal/output/viewer.go` | `WriteViewer`、`bundleData`，靜態瀏覽器資產產生 |\n| `internal/catalog/catalog.go` | `Catalog`、`CatalogItem`、`FlatItem` 結構定義，`Flatten()` 方法 |","core-modules/generator/index.md":"# 文件產生管線\n\nThis section contains the following:\n\n- [目錄產生階段](catalog-phase/index.md)\n- [內容頁面產生階段](content-phase/index.md)\n- [索引與導航產生階段](index-phase/index.md)\n- [翻譯階段](translate-phase/index.md)\n","core-modules/generator/translate-phase/index.md":"# 翻譯階段\n\n翻譯階段負責將主要語言產生的文件，透過 Claude CLI 批次翻譯為 `selfmd.yaml` 設定中所定義的次要語言，並在對應的語言子目錄中產生完整的導航結構。\n\n## 概述\n\n翻譯階段是獨立於四階段文件產生管線之外的附加流程，由 `selfmd translate` 指令觸發。其核心設計原則是：\n\n- **增量翻譯**：預設跳過已存在的翻譯頁面，只翻譯新增或缺少的頁面\n- **並行處理**：使用 `errgroup` 與 semaphore（信號量）控制並行度，加速大型文件庫的翻譯\n- **目錄重建**：翻譯完成後自動重建翻譯語言的文件目錄，保持標題與目錄結構的一致性\n- **僅翻譯葉節點**：分類首頁（`HasChildren = true`）由系統自動產生，不需要 Claude 翻譯\n\n翻譯階段的輸出放置於 `.doc-build/{語言代碼}/` 子目錄，與主要語言的輸出並行存放。\n\n### 關鍵術語\n\n| 術語 | 說明 |\n|------|------|\n| 主要語言（source language）| `output.language` 設定的語言，即原始文件的語言 |\n| 次要語言（secondary languages）| `output.secondary_languages` 設定的目標翻譯語言列表 |\n| 葉節點（leaf item）| 目錄中沒有子項目的終端頁面，即實際文件內容頁面 |\n| `langWriter` | 指向語言子目錄的 `output.Writer`，透過 `ForLanguage()` 建立 |\n\n## 架構\n\n```mermaid\nflowchart TD\n    CLI[\"cmd/translate.go\\nrunTranslate()\"]\n    Gen[\"Generator\\nTranslate()\"]\n    CatReader[\"output.Writer\\nReadCatalogJSON()\"]\n    CatParser[\"catalog.Parse()\"]\n    Flatten[\"catalog.Flatten()\"]\n    LangWriter[\"output.Writer\\nForLanguage(lang)\"]\n    TranslatePages[\"Generator\\ntranslatePages()\"]\n    PromptEngine[\"prompt.Engine\\nRenderTranslate()\"]\n    ClaudeRunner[\"claude.Runner\\nRunWithRetry()\"]\n    ExtractDoc[\"claude.ExtractDocumentTag()\"]\n    ExtractTitle[\"extractTitle()\"]\n    BuildCat[\"buildTranslatedCatalog()\"]\n    NavGen[\"output.GenerateIndex()\\noutput.GenerateSidebar()\\noutput.GenerateCategoryIndex()\"]\n    ViewerGen[\"output.Writer\\nWriteViewer()\"]\n\n    CLI --\u003e|\"TranslateOptions\"| Gen\n    Gen --\u003e CatReader\n    CatReader --\u003e|\"JSON string\"| CatParser\n    CatParser --\u003e|\"*Catalog\"| Flatten\n    Flatten --\u003e|\"[]FlatItem\"| TranslatePages\n    Gen --\u003e LangWriter\n    LangWriter --\u003e TranslatePages\n    TranslatePages --\u003e|\"TranslatePromptData\"| PromptEngine\n    PromptEngine --\u003e|\"rendered prompt\"| ClaudeRunner\n    ClaudeRunner --\u003e|\"RunResult\"| ExtractDoc\n    ExtractDoc --\u003e|\"translated content\"| ExtractTitle\n    ExtractTitle --\u003e|\"translatedTitles map\"| BuildCat\n    BuildCat --\u003e|\"*Catalog（翻譯版）\"| NavGen\n    NavGen --\u003e LangWriter\n    Gen --\u003e ViewerGen\n```\n\n## 核心資料結構\n\n### TranslateOptions\n\n翻譯執行時的設定選項，由 CLI 指令傳入：\n\n```go\ntype TranslateOptions struct {\n    TargetLanguages []string\n    Force           bool\n    Concurrency     int\n}\n```\n\n\u003e 來源：internal/generator/translate_phase.go#L21-L25\n\n### TranslatePromptData\n\n傳遞給翻譯 Prompt 模板的資料：\n\n```go\ntype TranslatePromptData struct {\n    SourceLanguage     string // e.g., \"zh-TW\"\n    SourceLanguageName string // e.g., \"繁體中文\"\n    TargetLanguage     string // e.g., \"en-US\"\n    TargetLanguageName string // e.g., \"English\"\n    SourceContent      string // the full markdown content to translate\n}\n```\n\n\u003e 來源：internal/prompt/engine.go#L98-L104\n\n## 核心流程\n\n### Translate() — 主流程\n\n```mermaid\nsequenceDiagram\n    participant CLI as selfmd translate\n    participant G as Generator\n    participant W as Writer\n    participant Cat as catalog\n    participant Nav as output\n\n    CLI-\u003e\u003eG: Translate(ctx, opts)\n    G-\u003e\u003eW: ReadCatalogJSON()\n    W--\u003e\u003eG: JSON string\n    G-\u003e\u003eCat: Parse(json)\n    Cat--\u003e\u003eG: *Catalog\n    G-\u003e\u003eCat: Flatten()\n    Cat--\u003e\u003eG: []FlatItem\n\n    loop 每個目標語言\n        G-\u003e\u003eW: ForLanguage(targetLang)\n        W--\u003e\u003eG: langWriter\n        G-\u003e\u003eG: translatePages(ctx, items, langWriter, ...)\n        Note over G: 並行翻譯所有葉節點頁面\n        G-\u003e\u003eG: buildTranslatedCatalog(cat, translatedTitles)\n        G-\u003e\u003eNav: GenerateIndex(projectName, desc, translatedCat, lang)\n        G-\u003e\u003eNav: GenerateSidebar(projectName, translatedCat, lang)\n        G-\u003e\u003eNav: GenerateCategoryIndex(item, children, lang)\n    end\n\n    G-\u003e\u003eW: WriteViewer(projectName, docMeta)\n```\n\n### translatePages() — 並行翻譯\n\n`translatePages()` 只處理葉節點頁面（`HasChildren == false`），使用 `errgroup` 與 semaphore 進行並行控制：\n\n```go\neg, ctx := errgroup.WithContext(ctx)\nsem := make(chan struct{}, opts.Concurrency)\n\nfor _, item := range leafItems {\n    item := item\n    eg.Go(func() error {\n        // Skip if already translated and not forcing\n        if !opts.Force \u0026\u0026 langWriter.PageExists(item) {\n            skipped.Add(1)\n            // ...\n            return nil\n        }\n\n        sem \u003c- struct{}{}\n        defer func() { \u003c-sem }()\n\n        // Read source content\n        sourceContent, err := g.Writer.ReadPage(item)\n        // ...\n\n        // Render translate prompt\n        data := prompt.TranslatePromptData{ /* ... */ }\n        rendered, err := g.Engine.RenderTranslate(data)\n\n        // Call Claude\n        result, err := g.Runner.RunWithRetry(ctx, claude.RunOptions{\n            Prompt:  rendered,\n            WorkDir: g.RootDir,\n        })\n\n        // Extract translated content\n        content, err := claude.ExtractDocumentTag(result.Content)\n        // ...\n\n        // Write translated page\n        langWriter.WritePage(item, content)\n        return nil\n    })\n}\neg.Wait()\n```\n\n\u003e 來源：internal/generator/translate_phase.go#L150-L249\n\n### 翻譯跳過邏輯\n\n當 `--force` 未指定時，若目標語言目錄中已存在對應的翻譯檔案，該頁面將被跳過。跳過時仍會嘗試從既有翻譯中提取標題，確保翻譯目錄的完整性：\n\n```go\nif !opts.Force \u0026\u0026 langWriter.PageExists(item) {\n    skipped.Add(1)\n    // Try to extract title from existing translation\n    if content, err := langWriter.ReadPage(item); err == nil {\n        if title := extractTitle(content); title != \"\" {\n            titlesMu.Lock()\n            translatedTitles[item.Path] = title\n            titlesMu.Unlock()\n        }\n    }\n    fmt.Printf(\"      [跳過] %s（已存在）\\n\", item.Title)\n    return nil\n}\n```\n\n\u003e 來源：internal/generator/translate_phase.go#L157-L169\n\n## 翻譯目錄重建\n\n翻譯完成後，系統會用收集到的翻譯標題（`translatedTitles` map）重建翻譯語言的 `Catalog`，再用此目錄產生導航結構：\n\n```go\n// buildTranslatedCatalog creates a copy of the catalog with translated titles.\nfunc buildTranslatedCatalog(original *catalog.Catalog, translatedTitles map[string]string) *catalog.Catalog {\n    translated := \u0026catalog.Catalog{\n        Items: translateCatalogItems(original.Items, translatedTitles, \"\"),\n    }\n    return translated\n}\n```\n\n\u003e 來源：internal/generator/translate_phase.go#L276-L282\n\n`translateCatalogItems()` 以遞迴方式走訪所有目錄項目，若某個 `dotPath`（如 `core-modules.scanner`）在 `translatedTitles` 中有對應的翻譯標題，則使用翻譯後的標題：\n\n```go\n// Use translated title if available\nif translatedTitle, ok := titles[dotPath]; ok {\n    result[i].Title = translatedTitle\n}\n```\n\n\u003e 來源：internal/generator/translate_phase.go#L298-L300\n\n## 翻譯 Prompt 模板\n\n翻譯使用共用模板（`templates/translate.tmpl`），不依賴語言特定的子資料夾，確保翻譯指令的語言無關性：\n\n```\nYou are a professional technical documentation translator. Your task is to translate\nthe following documentation page from {{.SourceLanguageName}} ({{.SourceLanguage}})\nto {{.TargetLanguageName}} ({{.TargetLanguage}}).\n\n## Translation Rules\n1. Preserve all Markdown formatting\n2. Do not translate code — code identifiers, file paths remain as-is\n3. Translate section headings\n4. Preserve relative links — only translate display text\n5. Preserve Mermaid diagrams — translate labels but keep syntax correct\n6. Preserve source annotations\n7. Natural translation — produce fluent {{.TargetLanguageName}}\n8. Preserve reference file tables — translate headers but keep paths\n```\n\n\u003e 來源：internal/prompt/templates/translate.tmpl#L1-L35\n\n`Engine.RenderTranslate()` 使用 `renderShared()` 而非 `render()`，因此模板從共用的 `sharedTemplates` 而非語言特定的 `templates` 執行：\n\n```go\nfunc (e *Engine) RenderTranslate(data TranslatePromptData) (string, error) {\n    return e.renderShared(\"translate.tmpl\", data)\n}\n```\n\n\u003e 來源：internal/prompt/engine.go#L132-L134\n\n## 輸出結構\n\n翻譯完成後，每個次要語言的輸出放置於 `.doc-build/{lang}/`：\n\n```\n.doc-build/\n├── index.md            # 主要語言首頁\n├── _sidebar.md         # 主要語言側欄\n├── _catalog.json       # 主要語言目錄 JSON\n├── en-US/              # 次要語言目錄（例）\n│   ├── index.md        # 翻譯後首頁\n│   ├── _sidebar.md     # 翻譯後側欄\n│   ├── _catalog.json   # 翻譯後目錄 JSON（含翻譯標題）\n│   └── {section}/\n│       └── {page}/\n│           └── index.md   # 翻譯後的頁面\n└── index.html          # 瀏覽器入口（含所有語言資料）\n```\n\n`ForLanguage()` 方法建立指向語言子目錄的 Writer：\n\n```go\nfunc (w *Writer) ForLanguage(lang string) *Writer {\n    return \u0026Writer{\n        BaseDir: filepath.Join(w.BaseDir, lang),\n    }\n}\n```\n\n\u003e 來源：internal/output/writer.go#L139-L143\n\n## 導航元件的本地化\n\n翻譯後產生的 `index.md`、`_sidebar.md` 與分類索引頁使用 `output.UIStrings` 提供的語言特定 UI 字串：\n\n```go\nvar UIStrings = map[string]map[string]string{\n    \"zh-TW\": {\n        \"techDocs\":        \"技術文件\",\n        \"sectionContains\": \"本章節包含以下內容：\",\n        // ...\n    },\n    \"en-US\": {\n        \"techDocs\":        \"Technical Documentation\",\n        \"sectionContains\": \"This section contains the following:\",\n        // ...\n    },\n}\n```\n\n\u003e 來源：internal/output/navigation.go#L12-L27\n\n## 標題提取輔助函式\n\n`extractTitle()` 以正則表達式擷取 Markdown 文件的第一個 `#` 標題，用於收集翻譯後的頁面標題並重建翻譯目錄：\n\n```go\nfunc extractTitle(content string) string {\n    re := regexp.MustCompile(`(?m)^#\\s+(.+)$`)\n    match := re.FindStringSubmatch(content)\n    if len(match) \u003e= 2 {\n        return strings.TrimSpace(match[1])\n    }\n    return \"\"\n}\n```\n\n\u003e 來源：internal/generator/translate_phase.go#L267-L274\n\n## CLI 使用範例\n\n透過 `selfmd translate` 指令觸發翻譯階段：\n\n```go\nvar translateCmd = \u0026cobra.Command{\n    Use:   \"translate\",\n    Short: \"將主要語言文件翻譯為次要語言\",\n    Long: `以已產生的主要語言文件為基準，翻譯為設定檔中定義的次要語言。\n翻譯結果放置於 .doc-build/{語言代碼}/ 子目錄。`,\n    RunE: runTranslate,\n}\n```\n\n\u003e 來源：cmd/translate.go#L24-L30\n\n可用的旗標：\n\n| 旗標 | 說明 |\n|------|------|\n| `--lang \u003ccode,...\u003e` | 只翻譯指定語言（預設：所有次要語言） |\n| `--force` | 強制重新翻譯已存在的檔案 |\n| `--concurrency \u003cn\u003e` | 並行度（覆蓋設定檔中的 `max_concurrent`） |\n\n**前置條件**：必須先執行 `selfmd generate` 產生主要語言文件，翻譯階段依賴 `.doc-build/_catalog.json` 與原始頁面內容。\n\n## 相關連結\n\n- [selfmd translate](../../../cli/cmd-translate/index.md)\n- [文件產生管線](../index.md)\n- [索引與導航產生階段](../index-phase/index.md)\n- [多語言支援](../../../i18n/index.md)\n- [翻譯工作流程](../../../i18n/translation-workflow/index.md)\n- [支援的語言與模板](../../../i18n/supported-languages/index.md)\n- [Prompt 模板引擎](../../prompt-engine/index.md)\n- [Claude CLI 執行器](../../claude-runner/index.md)\n- [輸出寫入與連結修復](../../output-writer/index.md)\n\n## 參考檔案\n\n| 檔案路徑 | 說明 |\n|----------|------|\n| `internal/generator/translate_phase.go` | 翻譯階段核心實作：`Translate()`、`translatePages()`、`buildTranslatedCatalog()`、`extractTitle()` |\n| `internal/generator/pipeline.go` | `Generator` 結構定義與 `NewGenerator()`、`buildDocMeta()` |\n| `internal/prompt/engine.go` | `TranslatePromptData` 結構、`RenderTranslate()` 方法 |\n| `internal/prompt/templates/translate.tmpl` | 翻譯 Prompt 共用模板 |\n| `internal/output/writer.go` | `Writer`、`ForLanguage()`、`PageExists()`、`ReadPage()`、`WritePage()` |\n| `internal/output/navigation.go` | `UIStrings`、`GenerateIndex()`、`GenerateSidebar()`、`GenerateCategoryIndex()` |\n| `internal/catalog/catalog.go` | `Catalog`、`FlatItem`、`Flatten()`、`CatalogItem` |\n| `internal/config/config.go` | `OutputConfig`、`GetLangNativeName()`、`KnownLanguages` |\n| `cmd/translate.go` | `translate` CLI 指令實作 |","core-modules/incremental-update/index.md":"# 增量更新\n\n增量更新（Incremental Update）模組讓 selfmd 能在 git 變更後，僅針對受影響的文件頁面進行重新產生，避免每次都執行耗時的完整 `generate` 流程，大幅節省時間與 API 費用。\n\n## 概述\n\n增量更新的核心思想是：**只更新需要更新的頁面**。當程式碼發生變更時，系統會：\n\n1. 從 git diff 取得變更的原始碼檔案清單\n2. 比對哪些現有文件頁面引用了這些變更檔案（稱為「匹配」）\n3. 對於尚未有對應文件的新檔案，判斷是否需要新增頁面\n4. 僅重新產生確實需要更新的頁面\n\n系統透過在輸出目錄中持久化一個 `_last_commit` 檔案來追蹤上次更新的 commit，使得每次執行 `selfmd update` 都能精確計算需要重新產生的範圍。\n\n**關鍵術語：**\n\n| 術語 | 說明 |\n|------|------|\n| 匹配頁面（matched） | 內容中含有變更檔案路徑的既有文件頁面 |\n| 未匹配檔案（unmatched） | 沒有任何文件頁面引用的變更檔案 |\n| 葉節點升格（leaf promotion） | 當現有文件目錄的葉節點需要成為父節點時，自動將其原始內容移至 `overview` 子頁面 |\n| 基準 commit（previousCommit） | 與當前 HEAD 進行 diff 比較的起點 commit |\n\n## 架構\n\n```mermaid\nflowchart TD\n    CLI[\"cmd/update.go\\nrunUpdate()\"]\n    GitPkg[\"git package\\nGetChangedFiles()\\nFilterChangedFiles()\\nParseChangedFiles()\"]\n    Scanner[\"scanner.Scan()\"]\n    Updater[\"Generator.Update()\"]\n    Match[\"matchChangedFilesToDocs()\\n比對變更檔案 vs 現有頁面\"]\n    DetermineMatched[\"determineMatchedUpdates()\\n詢問 Claude：哪些頁面需更新\"]\n    DetermineUnmatched[\"determineUnmatchedPages()\\n詢問 Claude：是否需新增頁面\"]\n    AddCatalog[\"addItemToCatalog()\\n更新目錄樹\"]\n    Generate[\"generateSinglePage()\\n重新產生頁面內容\"]\n    GenerateIndex[\"GenerateIndex()\\n更新導航與索引\"]\n    Writer[\"output.Writer\\n讀寫頁面、目錄、commit 記錄\"]\n    CatalogPkg[\"catalog.Catalog\\n目錄資料結構\"]\n    ClaudeRunner[\"claude.Runner\\n呼叫 Claude CLI\"]\n    PromptEngine[\"prompt.Engine\\nRenderUpdateMatched()\\nRenderUpdateUnmatched()\"]\n\n    CLI --\u003e GitPkg\n    CLI --\u003e Scanner\n    CLI --\u003e Updater\n    Updater --\u003e Match\n    Updater --\u003e DetermineMatched\n    Updater --\u003e DetermineUnmatched\n    Updater --\u003e AddCatalog\n    Updater --\u003e Generate\n    Updater --\u003e GenerateIndex\n    Updater --\u003e Writer\n    DetermineMatched --\u003e ClaudeRunner\n    DetermineMatched --\u003e PromptEngine\n    DetermineUnmatched --\u003e ClaudeRunner\n    DetermineUnmatched --\u003e PromptEngine\n    Generate --\u003e ClaudeRunner\n    Match --\u003e Writer\n    Match --\u003e CatalogPkg\n    AddCatalog --\u003e CatalogPkg\n    Writer --\u003e CatalogPkg\n```\n\n## 資料結構\n\n### 核心型別\n\n```go\n// UpdateMatchedResult represents a page that Claude determined needs regeneration.\ntype UpdateMatchedResult struct {\n\tCatalogPath string `json:\"catalogPath\"`\n\tTitle       string `json:\"title\"`\n\tReason      string `json:\"reason\"`\n}\n\n// UpdateUnmatchedResult represents a new page that Claude determined should be created.\ntype UpdateUnmatchedResult struct {\n\tCatalogPath string `json:\"catalogPath\"`\n\tTitle       string `json:\"title\"`\n\tReason      string `json:\"reason\"`\n}\n```\n\n\u003e 來源：internal/generator/updater.go#L17-L29\n\n```go\n// matchResult holds the mapping between changed files and the doc pages that reference them.\ntype matchResult struct {\n\t// changedFile is the source file path that changed\n\tchangedFile string\n\t// pages are the doc pages that reference this file\n\tpages []catalog.FlatItem\n}\n```\n\n\u003e 來源：internal/generator/updater.go#L168-L174\n\n```go\n// promotedLeaf records when a leaf node was promoted to a parent by adding an \"overview\" child.\ntype promotedLeaf struct {\n\t// OriginalPath is the dot-notation path of the original leaf (e.g. \"core-modules.mcp-integration\")\n\tOriginalPath string\n\t// OverviewPath is the dot-notation path of the new overview child (e.g. \"core-modules.mcp-integration.overview\")\n\tOverviewPath string\n\t// OriginalTitle is the title of the original leaf\n\tOriginalTitle string\n}\n```\n\n\u003e 來源：internal/generator/updater.go#L359-L367\n\n### Prompt 資料結構\n\n增量更新使用兩種 prompt 資料結構，分別對應「匹配頁面判斷」與「未匹配頁面判斷」兩個 Claude 呼叫：\n\n```go\n// UpdateMatchedPromptData holds data for deciding which existing pages need regeneration.\ntype UpdateMatchedPromptData struct {\n\tRepositoryName string\n\tLanguage       string\n\tChangedFiles   string // list of changed source files\n\tAffectedPages  string // pages that reference these files (path + title + summary)\n}\n\n// UpdateUnmatchedPromptData holds data for deciding whether new pages are needed.\ntype UpdateUnmatchedPromptData struct {\n\tRepositoryName  string\n\tLanguage        string\n\tUnmatchedFiles  string // changed files not referenced in any existing doc\n\tExistingCatalog string // existing catalog JSON\n\tCatalogTable    string // formatted link table of all pages\n}\n```\n\n\u003e 來源：internal/prompt/engine.go#L80-L95\n\n## 核心流程\n\n### Update() 的四個步驟\n\n```mermaid\nflowchart TD\n    A[\"開始：Update()\"] --\u003e B[\"讀取 _catalog.json\\n解析現有目錄\"]\n    B --\u003e C[\"ParseChangedFiles()\\n解析 git diff 輸出\"]\n    C --\u003e D{有變更檔案？}\n    D --\u003e|否| E[\"列印「無變更」\\n結束\"]\n    D --\u003e|是| F[\"[1/4] matchChangedFilesToDocs()\\n比對變更檔案與文件頁面\"]\n    F --\u003e G[\"[2/4] determineMatchedUpdates()\\n（有匹配時）\\nClaude 判斷需更新的頁面\"]\n    G --\u003e H[\"[3/4] determineUnmatchedPages()\\n（有未匹配時）\\nClaude 判斷是否需新增頁面\"]\n    H --\u003e I{有新頁面？}\n    I --\u003e|是| J[\"addItemToCatalog()\\n更新目錄樹\"]\n    J --\u003e K[\"WriteCatalogJSON()\\n保存更新後的目錄\"]\n    K --\u003e L[\"[4/4] generateSinglePage()\\n逐頁重新產生\"]\n    I --\u003e|否| L\n    L --\u003e M{有新增頁面？}\n    M --\u003e|是| N[\"GenerateIndex()\\n重新產生導航與索引\"]\n    M --\u003e|否| O[\"SaveLastCommit()\\n保存當前 commit\"]\n    N --\u003e O\n    O --\u003e P[\"列印總費用\\n結束\"]\n```\n\n### 匹配邏輯\n\n`matchChangedFilesToDocs()` 採用**字串搜尋**策略：先一次性讀入所有文件頁面的內容，再逐一檢查每個變更檔案的路徑是否出現在任何頁面的文字中。\n\n```go\n// For each changed file, find which pages reference it\nfor _, f := range files {\n    var matchedPages []catalog.FlatItem\n    for _, item := range items {\n        content, ok := pageContents[item.Path]\n        if !ok {\n            continue\n        }\n        if strings.Contains(content, f.Path) {\n            matchedPages = append(matchedPages, item)\n        }\n    }\n    // ...\n}\n```\n\n\u003e 來源：internal/generator/updater.go#L191-L213\n\n### 葉節點升格（Leaf Promotion）\n\n當 Claude 決定在現有葉節點下新增子頁面時（例如在 `core-modules.scanner` 下新增 `core-modules.scanner.advanced`），系統會自動將原葉節點升格為父節點，並將其原始內容搬移至 `overview` 子頁面：\n\n```go\nif len(item.Children) == 0 {\n    // This is a leaf node that needs to become a parent.\n    // Add an \"overview\" child to preserve the original content.\n    (*children)[i].Children = append((*children)[i].Children, catalog.CatalogItem{\n        Title: item.Title,\n        Path:  \"overview\",\n        Order: 0,\n    })\n    *promoted = \u0026promotedLeaf{\n        OriginalPath:  currentDotPath,\n        OverviewPath:  currentDotPath + \".overview\",\n        OriginalTitle: item.Title,\n    }\n}\n```\n\n\u003e 來源：internal/generator/updater.go#L402-L414\n\n## Commit 追蹤機制\n\n增量更新依賴一個「基準 commit」（previousCommit）來計算 git diff 範圍。系統的優先順序如下：\n\n```mermaid\nflowchart TD\n    A[\"runUpdate() 啟動\"] --\u003e B{使用者有\\n指定 --since？}\n    B --\u003e|是| C[\"使用 --since 指定的 commit\\n作為基準\"]\n    B --\u003e|否| D[\"ReadLastCommit()\\n讀取 _last_commit 檔案\"]\n    D --\u003e E{讀取成功？}\n    E --\u003e|是| F[\"使用上次 generate/update\\n儲存的 commit\"]\n    E --\u003e|否| G[\"GetMergeBase()\\n計算與 baseBranch 的分叉點\"]\n    G --\u003e H{成功？}\n    H --\u003e|是| I[\"使用 merge-base commit\"]\n    H --\u003e|否| J[\"回傳錯誤：\\n提示先執行 selfmd generate\"]\n```\n\n\u003e 來源：cmd/update.go#L67-L81\n\n每次成功的 `update` 執行後，系統會將當前 HEAD commit 儲存至 `_last_commit` 檔案，供下次增量更新使用：\n\n```go\n// Save current commit for next incremental update\nif err := g.Writer.SaveLastCommit(currentCommit); err != nil {\n    g.Logger.Warn(\"保存 commit 記錄失敗\", \"error\", err)\n}\n```\n\n\u003e 來源：internal/generator/updater.go#L159-L162\n\n`_last_commit` 同樣在 `generate` 完成後也會寫入，確保初次執行後即可立即使用 `update`：\n\n```go\n// Save current commit for incremental updates\nif git.IsGitRepo(g.RootDir) {\n    if commit, err := git.GetCurrentCommit(g.RootDir); err == nil {\n        if err := g.Writer.SaveLastCommit(commit); err != nil {\n            g.Logger.Warn(\"保存 commit 記錄失敗\", \"error\", err)\n        }\n    }\n}\n```\n\n\u003e 來源：internal/generator/pipeline.go#L157-L164\n\n## 使用範例\n\n### 基本增量更新\n\n```bash\n# 自動偵測上次 generate/update 後的所有變更\nselfmd update\n```\n\n### 指定基準 Commit\n\n```bash\n# 與指定的 commit 比較\nselfmd update --since abc1234\n\n# 與某個 tag 或分支比較\nselfmd update --since v1.0.0\nselfmd update --since main\n```\n\n\u003e 來源：cmd/update.go#L19-L31\n\n### CLI 命令定義\n\n```go\nvar updateCmd = \u0026cobra.Command{\n    Use:   \"update\",\n    Short: \"基於 git 變更增量更新文件\",\n    Long: `分析 git 變更並增量更新受影響的文件頁面。\n需要先執行過 selfmd generate 產生初始文件。`,\n    RunE: runUpdate,\n}\n\nfunc init() {\n    updateCmd.Flags().StringVar(\u0026sinceCommit, \"since\", \"\", \"與指定 commit 比較（預設為上次 generate/update 的 commit）\")\n    rootCmd.AddCommand(updateCmd)\n}\n```\n\n\u003e 來源：cmd/update.go#L21-L32\n\n### 執行輸出範例\n\n系統在執行時會顯示四個步驟的進度：\n\n```\n比較範圍：abc12345..def67890\n變更檔案：\nM   internal/scanner/scanner.go\nA   internal/scanner/filetree.go\n\n[1/4] 搜尋受影響的文件頁面...\n      2 個變更檔案已匹配到現有文件，0 個未匹配\n[2/4] 呼叫 Claude 判斷需要更新的頁面...\n      → 專案掃描器：scanner.go 的核心邏輯已變更\n      完成（1 個頁面需要更新）\n[3/4] 所有變更檔案均已有對應文件，跳過\n[4/4] 重新產生 1 個頁面...\n      [1/1] 專案掃描器（core-modules.scanner）... 完成（12.3s，$0.0024）\n\n更新完成！總費用：$0.0024 USD\n```\n\n## 前置條件\n\n執行 `selfmd update` 需要滿足以下條件：\n\n1. **必須為 git 倉庫**：系統會在啟動時檢查 `git.IsGitRepo(rootDir)`，若非 git 倉庫則立即回傳錯誤\n2. **必須已執行過 `selfmd generate`**：系統需要讀取 `_catalog.json` 以了解現有文件結構；若目錄不存在，會提示先執行 `generate`\n3. **Claude CLI 必須可用**：與 `generate` 相同，需要 Claude CLI 正常運作\n\n```go\nif !git.IsGitRepo(rootDir) {\n    return fmt.Errorf(\"當前目錄不是 git 倉庫，無法執行增量更新\")\n}\n```\n\n\u003e 來源：cmd/update.go#L49-L51\n\n## 相關連結\n\n- [Git Diff 變更偵測](../../git-integration/change-detection/index.md)\n- [受影響頁面判斷邏輯](../../git-integration/affected-pages/index.md)\n- [文件目錄管理](../catalog/index.md)\n- [文件產生管線](../generator/index.md)\n- [內容頁面產生階段](../generator/content-phase/index.md)\n- [Prompt 模板引擎](../prompt-engine/index.md)\n- [selfmd update 指令](../../cli/cmd-update/index.md)\n\n## 參考檔案\n\n| 檔案路徑 | 說明 |\n|----------|------|\n| `internal/generator/updater.go` | 增量更新核心邏輯：`Update()`、`matchChangedFilesToDocs()`、`determineMatchedUpdates()`、`determineUnmatchedPages()`、`addItemToCatalog()` |\n| `internal/generator/pipeline.go` | `Generator` 結構定義、`Generate()` 完整管線（包含 commit 保存） |\n| `internal/generator/content_phase.go` | `generateSinglePage()` 實作，被 updater 重用以重新產生頁面 |\n| `internal/git/git.go` | Git 操作封裝：`GetChangedFiles()`、`FilterChangedFiles()`、`ParseChangedFiles()`、`GetCurrentCommit()` |\n| `internal/catalog/catalog.go` | `Catalog`、`CatalogItem`、`FlatItem` 資料結構與 `Flatten()` 方法 |\n| `internal/output/writer.go` | `ReadPage()`、`WritePage()`、`SaveLastCommit()`、`ReadLastCommit()`、`WriteCatalogJSON()` |\n| `internal/prompt/engine.go` | `UpdateMatchedPromptData`、`UpdateUnmatchedPromptData` 資料結構與 `RenderUpdateMatched()`、`RenderUpdateUnmatched()` |\n| `cmd/update.go` | `selfmd update` 指令定義與 `runUpdate()` 執行邏輯 |","core-modules/index.md":"# 核心模組\n\nThis section contains the following:\n\n- [專案掃描器](scanner/index.md)\n- [文件目錄管理](catalog/index.md)\n- [Prompt 模板引擎](prompt-engine/index.md)\n- [Claude CLI 執行器](claude-runner/index.md)\n- [文件產生管線](generator/index.md)\n- [增量更新](incremental-update/index.md)\n- [輸出寫入與連結修復](output-writer/index.md)\n- [靜態文件瀏覽器](static-viewer/index.md)\n","core-modules/output-writer/index.md":"# 輸出寫入與連結修復\n\n`internal/output` 套件負責將已產生的 Markdown 文件寫入磁碟、修復文件內的相對連結、產生導航結構，以及打包靜態瀏覽器資源。\n\n## 概述\n\n完成 Claude CLI 的內容產生後，系統需要將結果持久化到 `.doc-build/` 輸出目錄，並確保頁面之間的內部連結是有效且可跳轉的。`output` 套件由四個相互配合的元件組成：\n\n| 元件 | 檔案 | 職責 |\n|------|------|------|\n| `Writer` | `writer.go` | 低階檔案 I/O，統一管理所有寫入操作 |\n| `LinkFixer` | `linkfixer.go` | 偵測並修復破損的相對連結 |\n| Navigation 函式 | `navigation.go` | 產生 `index.md`、`_sidebar.md` 及分類索引頁 |\n| `WriteViewer` | `viewer.go` | 打包靜態 HTML/JS/CSS 及 `_data.js` 資料包 |\n\n在管線中，`output` 套件在第三階段（內容頁面產生）與第四階段（導航與靜態瀏覽器產生）均被呼叫。\n\n## 架構\n\n```mermaid\nflowchart TD\n    Generator[\"Generator（pipeline.go）\"]\n\n    subgraph output_pkg[\"internal/output 套件\"]\n        Writer[\"Writer\\n（writer.go）\"]\n        LinkFixer[\"LinkFixer\\n（linkfixer.go）\"]\n        NavFuncs[\"Navigation 函式\\n（navigation.go）\"]\n        ViewerFunc[\"WriteViewer\\n（viewer.go）\"]\n    end\n\n    subgraph output_dir[\".doc-build/ 輸出目錄\"]\n        Pages[\"*.md 文件頁面\"]\n        Catalog[\"_catalog.json\"]\n        LastCommit[\"_last_commit\"]\n        Index[\"index.md / _sidebar.md\"]\n        HTML[\"index.html / app.js / style.css\"]\n        DataJS[\"_data.js（資料包）\"]\n        DocMeta[\"_doc_meta.json\"]\n    end\n\n    Generator --\u003e|\"WritePage / WriteFile\"| Writer\n    Generator --\u003e|\"NewLinkFixer → FixLinks\"| LinkFixer\n    Generator --\u003e|\"GenerateIndex / GenerateSidebar\"| NavFuncs\n    Generator --\u003e|\"WriteViewer\"| ViewerFunc\n\n    Writer --\u003e Pages\n    Writer --\u003e Catalog\n    Writer --\u003e LastCommit\n    NavFuncs --\u003e Index\n    ViewerFunc --\u003e HTML\n    ViewerFunc --\u003e DataJS\n    ViewerFunc --\u003e DocMeta\n\n    LinkFixer -.-\u003e|\"修復後傳回 content\"| Writer\n```\n\n## Writer — 檔案寫入器\n\n`Writer` 是所有磁碟操作的統一入口，持有輸出目錄的絕對路徑 `BaseDir`（預設為 `.doc-build/`）。\n\n### 結構定義\n\n```go\n// Writer handles writing documentation files to the output directory.\ntype Writer struct {\n\tBaseDir string // absolute path to .doc-build/\n}\n\n// NewWriter creates a new output writer.\nfunc NewWriter(baseDir string) *Writer {\n\treturn \u0026Writer{BaseDir: baseDir}\n}\n```\n\n\u003e 來源：internal/output/writer.go#L26-L33\n\n### 核心方法\n\n#### 目錄與生命週期\n\n```go\n// Clean removes the output directory and recreates it.\nfunc (w *Writer) Clean() error {\n\tif err := os.RemoveAll(w.BaseDir); err != nil {\n\t\treturn fmt.Errorf(\"清除輸出目錄失敗: %w\", err)\n\t}\n\treturn os.MkdirAll(w.BaseDir, 0755)\n}\n\n// EnsureDir ensures the output directory exists.\nfunc (w *Writer) EnsureDir() error {\n\treturn os.MkdirAll(w.BaseDir, 0755)\n}\n```\n\n\u003e 來源：internal/output/writer.go#L36-L46\n\n#### 頁面寫入與讀取\n\n```go\n// WritePage writes a documentation page for a catalog item.\nfunc (w *Writer) WritePage(item catalog.FlatItem, content string) error {\n\tdir := filepath.Join(w.BaseDir, item.DirPath)\n\tif err := os.MkdirAll(dir, 0755); err != nil {\n\t\treturn fmt.Errorf(\"建立目錄 %s 失敗: %w\", dir, err)\n\t}\n\n\tpath := filepath.Join(dir, \"index.md\")\n\tif err := os.WriteFile(path, []byte(content), 0644); err != nil {\n\t\treturn fmt.Errorf(\"寫入 %s 失敗: %w\", path, err)\n\t}\n\treturn nil\n}\n```\n\n\u003e 來源：internal/output/writer.go#L48-L60\n\n`WritePage` 接受 `catalog.FlatItem`（目錄項目的扁平化結構），自動在對應的 `DirPath` 下建立 `index.md`。\n\n#### 頁面存在性驗證\n\n```go\n// PageExists checks if a documentation page exists and has valid content.\nfunc (w *Writer) PageExists(item catalog.FlatItem) bool {\n\tpath := filepath.Join(w.BaseDir, item.DirPath, \"index.md\")\n\tdata, err := os.ReadFile(path)\n\tif err != nil {\n\t\treturn false\n\t}\n\tcontent := strings.TrimSpace(string(data))\n\tif content == \"\" {\n\t\treturn false\n\t}\n\tif strings.Contains(content, \"此頁面產生失敗\") {\n\t\treturn false\n\t}\n\treturn true\n}\n```\n\n\u003e 來源：internal/output/writer.go#L95-L111\n\n`PageExists` 不只檢查檔案是否存在，還會排除空白頁面與失敗佔位頁（含有「此頁面產生失敗」標記），確保增量更新時能正確判斷哪些頁面需要重新產生。\n\n#### 多語言支援\n\n```go\n// ForLanguage returns a new Writer that writes to a language-specific subdirectory.\nfunc (w *Writer) ForLanguage(lang string) *Writer {\n\treturn \u0026Writer{\n\t\tBaseDir: filepath.Join(w.BaseDir, lang),\n\t}\n}\n```\n\n\u003e 來源：internal/output/writer.go#L138-L143\n\n多語系的翻譯內容會寫入 `.doc-build/{lang}/` 子目錄，`ForLanguage` 建立指向該子目錄的 `Writer` 實例。\n\n#### 持久化輔助檔案\n\n| 方法 | 檔案 | 用途 |\n|------|------|------|\n| `WriteCatalogJSON` | `_catalog.json` | 保存目錄結構，供增量更新重複使用 |\n| `ReadCatalogJSON` | `_catalog.json` | 讀回目錄結構 |\n| `SaveLastCommit` | `_last_commit` | 保存 Git commit hash |\n| `ReadLastCommit` | `_last_commit` | 讀取上次 commit，用於 diff 計算 |\n\n## LinkFixer — 連結修復器\n\n`LinkFixer` 在內容寫入磁碟前對 Markdown 中的所有內部連結進行驗證與修復，處理 Claude 產生的連結格式不正確（如 dot-notation、缺少路徑段等）的問題。\n\n### 初始化\n\n```go\n// LinkFixer validates and fixes relative links in generated markdown content.\ntype LinkFixer struct {\n\tallItems  []catalog.FlatItem\n\tdirPaths  map[string]bool   // set of all valid dirPaths\n\tpathIndex map[string]string // various lookup keys → dirPath\n}\n\n// NewLinkFixer creates a link fixer from a catalog.\nfunc NewLinkFixer(cat *catalog.Catalog) *LinkFixer {\n\titems := cat.Flatten()\n\tdirPaths := make(map[string]bool)\n\tpathIndex := make(map[string]string)\n\n\tfor _, item := range items {\n\t\tdirPaths[item.DirPath] = true\n\n\t\t// index by multiple keys for fuzzy matching\n\t\tpathIndex[item.DirPath] = item.DirPath\n\t\tpathIndex[item.Path] = item.DirPath                          // dot-notation\n\t\tpathIndex[strings.ReplaceAll(item.Path, \".\", \"/\")] = item.DirPath // explicit slash conversion\n\n\t\t// index by last segment (e.g., \"scanner\" → \"core-modules/scanner\")\n\t\tparts := strings.Split(item.DirPath, \"/\")\n\t\tlastSeg := parts[len(parts)-1]\n\t\tif _, exists := pathIndex[lastSeg]; !exists {\n\t\t\tpathIndex[lastSeg] = item.DirPath\n\t\t}\n\t}\n\n\treturn \u0026LinkFixer{\n\t\tallItems:  items,\n\t\tdirPaths:  dirPaths,\n\t\tpathIndex: pathIndex,\n\t}\n}\n```\n\n\u003e 來源：internal/output/linkfixer.go#L11-L48\n\n`pathIndex` 建立多種鍵值索引，讓後續的模糊查找更有彈性：\n- `dirPath`（如 `core-modules/scanner`）\n- `dot-notation path`（如 `core-modules.scanner`）\n- 最後一個路徑段（如 `scanner`）\n- 小寫版本\n\n### 連結修復流程\n\n```go\n// FixLinks scans markdown content for relative links and fixes broken ones.\nfunc (lf *LinkFixer) FixLinks(content string, currentDirPath string) string {\n\t// match markdown links: [text](target)\n\tlinkRe := regexp.MustCompile(`\\[([^\\]]+)\\]\\(([^)]+)\\)`)\n\n\treturn linkRe.ReplaceAllStringFunc(content, func(match string) string {\n\t\t// ...skip external links, anchors, images...\n\t\tfixed := lf.fixSingleLink(target, currentDirPath)\n\t\tif fixed != \"\" \u0026\u0026 fixed != target {\n\t\t\treturn \"[\" + text + \"](\" + fixed + \")\"\n\t\t}\n\t\treturn match\n\t})\n}\n```\n\n\u003e 來源：internal/output/linkfixer.go#L50-L82\n\n修復策略依序為：\n\n```mermaid\nflowchart TD\n    A[\"取得連結 target\"] --\u003e B{\"是否為外部連結\\n/ anchor / 圖片？\"}\n    B --\u003e|是| Z[\"原樣保留\"]\n    B --\u003e|否| C[\"resolveRelative：\\n嘗試直接解析相對路徑\"]\n    C --\u003e D{\"是否指向有效頁面？\"}\n    D --\u003e|是| Z\n    D --\u003e|否| E[\"extractPathSlug：\\n清理 target（去除 ../ .md /index.md）\"]\n    E --\u003e F[\"在 pathIndex 中查找（精確）\"]\n    F --\u003e G{\"找到？\"}\n    G --\u003e|是| H[\"computeRelativePath：\\n計算正確相對路徑\"]\n    G --\u003e|否| I[\"小寫查找\"]\n    I --\u003e J{\"找到？\"}\n    J --\u003e|是| H\n    J --\u003e|否| K[\"最後一段 / 連字符組合查找\"]\n    K --\u003e L{\"找到？\"}\n    L --\u003e|是| H\n    L --\u003e|否| M[\"suffix 子字串比對\"]\n    M --\u003e N{\"找到？\"}\n    N --\u003e|是| H\n    N --\u003e|否| Z\n    H --\u003e O[\"輸出修正後的連結\"]\n```\n\n### 相對路徑計算\n\n```go\n// computeRelativePath computes the relative path from one catalog item to another.\nfunc (lf *LinkFixer) computeRelativePath(fromDirPath, toDirPath string) string {\n\trel, err := filepath.Rel(fromDirPath, toDirPath)\n\tif err != nil {\n\t\treturn \"\"\n\t}\n\trel = filepath.ToSlash(rel)\n\treturn rel + \"/index.md\"\n}\n```\n\n\u003e 來源：internal/output/linkfixer.go#L174-L182\n\n所有修復後的連結均統一為 `{相對路徑}/index.md` 格式。\n\n## Navigation — 導航產生\n\n`navigation.go` 提供三個純函式，產生文件的導航結構，不依賴任何外部狀態。\n\n### 多語言 UI 字串\n\n```go\nvar UIStrings = map[string]map[string]string{\n\t\"zh-TW\": {\n\t\t\"techDocs\":        \"技術文件\",\n\t\t\"catalog\":         \"目錄\",\n\t\t\"home\":            \"首頁\",\n\t\t\"sectionContains\": \"本章節包含以下內容：\",\n\t\t\"autoGenerated\":   \"本文件由 [selfmd](https://github.com/monkenwu/selfmd) 自動產生\",\n\t},\n\t\"en-US\": {\n\t\t\"techDocs\":        \"Technical Documentation\",\n\t\t// ...\n\t},\n}\n```\n\n\u003e 來源：internal/output/navigation.go#L12-L27\n\n### 三個導航產生函式\n\n| 函式 | 產生目標 | 說明 |\n|------|---------|------|\n| `GenerateIndex` | `index.md` | 主頁，列出完整目錄並附上連結 |\n| `GenerateSidebar` | `_sidebar.md` | 側邊欄導航，供靜態瀏覽器使用 |\n| `GenerateCategoryIndex` | 各父節點的 `index.md` | 列出子章節的分類索引頁 |\n\n```go\n// GenerateIndex generates the main index.md landing page.\nfunc GenerateIndex(projectName, projectDesc string, cat *catalog.Catalog, lang string) string {\n\tui := getUIStrings(lang)\n\tvar sb strings.Builder\n\tsb.WriteString(fmt.Sprintf(\"# %s %s\\n\\n\", projectName, ui[\"techDocs\"]))\n\t// ...\n\tfor _, item := range cat.Items {\n\t\twriteIndexItem(\u0026sb, item, \"\", 0)\n\t}\n\t// ...\n}\n```\n\n\u003e 來源：internal/output/navigation.go#L37-L59\n\n## WriteViewer — 靜態瀏覽器打包\n\n`viewer.go` 利用 Go 的 `//go:embed` 指令將靜態瀏覽器資源直接嵌入二進位檔案，並在產生時寫出，無需外部網路資源。\n\n### 嵌入式資源\n\n```go\n//go:embed viewer/index.html\nvar viewerHTML string\n\n//go:embed viewer/app.js\nvar viewerJS string\n\n//go:embed viewer/style.css\nvar viewerCSS string\n```\n\n\u003e 來源：internal/output/viewer.go#L12-L19\n\n### 資料打包（`_data.js`）\n\n```go\n// bundleData walks the output directory, collects all .md files and _catalog.json,\n// and writes them as a single _data.js file for client-side rendering.\nfunc (w *Writer) bundleData(projectName string, docMeta *DocMeta) error {\n\t// ...\n\t// Build data object\n\tdata := map[string]interface{}{\n\t\t\"catalog\": catalogObj,\n\t\t\"pages\":   pages,\n\t}\n\t// ...\n\tcontent := \"window.DOC_DATA = \" + string(jsonBytes) + \";\\n\"\n\treturn w.WriteFile(\"_data.js\", content)\n}\n```\n\n\u003e 來源：internal/output/viewer.go#L61-L193\n\n`_data.js` 將所有 Markdown 頁面內容和目錄結構序列化為 JSON，以 `window.DOC_DATA` 全域變數注入，讓瀏覽器端的 `app.js` 可在不啟動伺服器的情況下渲染文件。\n\n多語言模式下，次要語言（Secondary Language）的頁面也會被收集並放入 `data[\"languages\"][langCode]`：\n\n```go\nlanguages := make(map[string]interface{})\nfor _, lang := range docMeta.AvailableLanguages {\n    if lang.IsDefault {\n        continue\n    }\n    // Read lang-specific catalog and pages from .doc-build/{lang}/\n    langEntry[\"catalog\"] = catObj\n    langEntry[\"pages\"] = langPages\n    languages[lang.Code] = langEntry\n}\n```\n\n\u003e 來源：internal/output/viewer.go#L135-L185\n\n### DocMeta — 語言元資料\n\n```go\n// DocMeta holds metadata about the documentation build, including language info.\ntype DocMeta struct {\n\tDefaultLanguage    string     `json:\"default_language\"`\n\tAvailableLanguages []LangInfo `json:\"available_languages\"`\n}\n\n// LangInfo describes a single available language.\ntype LangInfo struct {\n\tCode       string `json:\"code\"`\n\tNativeName string `json:\"native_name\"`\n\tIsDefault  bool   `json:\"is_default\"`\n}\n```\n\n\u003e 來源：internal/output/writer.go#L12-L23\n\n## 核心流程\n\n### 內容頁面寫入序列\n\n```mermaid\nsequenceDiagram\n    participant G as Generator\n    participant LF as LinkFixer\n    participant W as Writer\n    participant FS as 檔案系統\n\n    G-\u003e\u003eLF: NewLinkFixer(cat)\n    Note over LF: 建立 pathIndex 多鍵索引\n\n    loop 每個 catalog.FlatItem\n        G-\u003e\u003eG: generateSinglePage（呼叫 Claude）\n        G-\u003e\u003eG: claude.ExtractDocumentTag（擷取 document 標籤）\n        G-\u003e\u003eLF: FixLinks(content, item.DirPath)\n        LF-\u003e\u003eLF: regexp 掃描所有 [text](target)\n        LF-\u003e\u003eLF: fixSingleLink（模糊查找 + 計算相對路徑）\n        LF--\u003e\u003eG: 修復後的 content\n        G-\u003e\u003eW: WritePage(item, content)\n        W-\u003e\u003eFS: MkdirAll + WriteFile（index.md）\n    end\n```\n\n### 完整管線中的角色\n\n```mermaid\nsequenceDiagram\n    participant P as pipeline.go\n    participant W as Writer\n    participant Nav as navigation.go\n    participant V as viewer.go\n\n    P-\u003e\u003eW: Clean() 或 EnsureDir()\n    P-\u003e\u003eW: WriteCatalogJSON(cat)\n    P-\u003e\u003eNav: GenerateIndex / GenerateSidebar / GenerateCategoryIndex\n    Nav--\u003e\u003eP: Markdown 字串\n    P-\u003e\u003eW: WriteFile(\"index.md\")\n    P-\u003e\u003eW: WriteFile(\"_sidebar.md\")\n    P-\u003e\u003eW: WritePage(item, categoryContent)\n    P-\u003e\u003eV: WriteViewer(projectName, docMeta)\n    V-\u003e\u003eW: WriteFile(\"index.html\" / \"app.js\" / \"style.css\")\n    V-\u003e\u003eV: bundleData（掃描所有 .md）\n    V-\u003e\u003eW: WriteFile(\"_data.js\")\n    V-\u003e\u003eW: WriteFile(\"_doc_meta.json\")\n    P-\u003e\u003eW: SaveLastCommit(commit)\n```\n\n## 使用範例\n\n### Writer 初始化（來自 Generator）\n\n```go\nabsOutDir := cfg.Output.Dir\nif absOutDir == \"\" {\n    absOutDir = \".doc-build\"\n}\n\nwriter := output.NewWriter(absOutDir)\n```\n\n\u003e 來源：internal/generator/pipeline.go#L43-L48\n\n### 在內容產生階段使用 LinkFixer\n\n```go\n// Build the link fixer once for all pages\nlinkFixer := output.NewLinkFixer(cat)\n\n// ...（並行產生每個頁面後）\n\n// Post-process: fix broken links\ncontent = linkFixer.FixLinks(content, item.DirPath)\n\nreturn g.Writer.WritePage(item, content)\n```\n\n\u003e 來源：internal/generator/content_phase.go#L29-L153\n\n### 多語言 Writer\n\n```go\n// ForLanguage returns a new Writer that writes to a language-specific subdirectory.\nfunc (w *Writer) ForLanguage(lang string) *Writer {\n    return \u0026Writer{\n        BaseDir: filepath.Join(w.BaseDir, lang),\n    }\n}\n```\n\n\u003e 來源：internal/output/writer.go#L138-L143\n\n翻譯階段呼叫 `w.ForLanguage(\"en-US\")` 即可取得指向 `.doc-build/en-US/` 的 Writer，翻譯後的頁面寫入後也會被 `bundleData` 收集進 `_data.js`。\n\n## 相關連結\n\n- [文件產生管線](../generator/index.md) — 管線如何呼叫 `Writer` 與 `LinkFixer`\n- [內容頁面產生階段](../generator/content-phase/index.md) — `LinkFixer.FixLinks` 的使用時機\n- [索引與導航產生階段](../generator/index-phase/index.md) — Navigation 函式的呼叫方\n- [靜態文件瀏覽器](../static-viewer/index.md) — `_data.js` 的消費端\n- [文件目錄管理](../catalog/index.md) — `catalog.FlatItem` 與 `catalog.Catalog` 的定義\n- [增量更新](../incremental-update/index.md) — `PageExists`、`ReadLastCommit` 的使用情境\n- [翻譯階段](../generator/translate-phase/index.md) — `ForLanguage` 的使用情境\n\n## 參考檔案\n\n| 檔案路徑 | 說明 |\n|----------|------|\n| `internal/output/writer.go` | `Writer` 結構定義、頁面寫入、持久化輔助方法、`DocMeta` 定義 |\n| `internal/output/linkfixer.go` | `LinkFixer` 結構、多鍵索引建立、連結掃描與修復邏輯 |\n| `internal/output/navigation.go` | `GenerateIndex`、`GenerateSidebar`、`GenerateCategoryIndex` 及多語言 UI 字串 |\n| `internal/output/viewer.go` | `WriteViewer`、`bundleData`、嵌入式靜態資源寫出 |\n| `internal/catalog/catalog.go` | `Catalog`、`CatalogItem`、`FlatItem` 定義與 `Flatten` 方法 |\n| `internal/generator/pipeline.go` | `Generator` 結構、四階段管線主流程、`buildDocMeta` |\n| `internal/generator/content_phase.go` | `GenerateContent`、`generateSinglePage`、`LinkFixer` 使用方式 |\n| `internal/generator/index_phase.go` | `GenerateIndex` 呼叫 Navigation 函式的實作 |","core-modules/prompt-engine/index.md":"# Prompt 模板引擎\n\n`prompt.Engine` 是 selfmd 的 Prompt 模板引擎，負責將結構化資料與預定義模板結合，產生傳遞給 Claude CLI 的完整提示詞（Prompt）。\n\n## 概述\n\nPrompt 模板引擎位於 `internal/prompt/` 套件，核心職責有三：\n\n1. **模板載入**：使用 Go 的 `embed.FS` 機制，在編譯時將 `templates/` 目錄下的所有 `.tmpl` 檔案嵌入二進位檔，確保部署時無需額外的模板檔案。\n2. **語言路由**：根據 `OutputConfig.GetEffectiveTemplateLang()` 決定載入哪一個語言子資料夾（`zh-TW` 或 `en-US`）的模板集。共用模板（`translate.tmpl`）則獨立管理，不隸屬於任何語言子資料夾。\n3. **資料渲染**：提供六個高階渲染方法，每個方法對應文件產生管線的一個特定階段，接受強型別的資料結構（Data Struct）並回傳渲染後的字串。\n\n在整體架構中，`Engine` 是 `Generator` 的核心依賴之一，與 `claude.Runner` 協作：`Engine` 負責「把資料轉成 Prompt 文字」，`Runner` 負責「把 Prompt 文字送給 Claude 並取得回應」。\n\n### 關鍵術語\n\n- **模板語言（Template Language）**：決定使用哪個語言資料夾下的 `.tmpl` 檔案，目前支援 `zh-TW` 與 `en-US`。\n- **語言覆寫（Language Override）**：當使用者設定的輸出語言沒有對應模板時（例如 `ja-JP`），引擎會退回使用英文模板（`en-US`），並在 Prompt 中加入明確指令，要求 Claude 以目標語言輸出。\n- **共用模板（Shared Template）**：`translate.tmpl` 不依賴特定語言，可翻譯任意語言組合，因此獨立於語言子資料夾外載入。\n\n## 架構\n\n### 元件依賴關係\n\n```mermaid\nflowchart TD\n    Config[\"config.OutputConfig\"]\n    Pipeline[\"generator.NewGenerator\"]\n    Engine[\"prompt.Engine\"]\n    LangTmpl[\"語言模板集\\ntemplates/zh-TW/*.tmpl\\ntemplates/en-US/*.tmpl\"]\n    SharedTmpl[\"共用模板\\ntemplates/translate.tmpl\"]\n    EmbedFS[\"embed.FS\\ntemplatFS\"]\n\n    CatalogPhase[\"generator.GenerateCatalog\"]\n    ContentPhase[\"generator.GenerateContent\"]\n    TranslatePhase[\"generator.Translate\"]\n    UpdaterPhase[\"generator.Updater\"]\n\n    Config --\u003e|\"GetEffectiveTemplateLang()\"| Pipeline\n    Pipeline --\u003e|\"prompt.NewEngine(templateLang)\"| Engine\n    EmbedFS --\u003e LangTmpl\n    EmbedFS --\u003e SharedTmpl\n    LangTmpl --\u003e Engine\n    SharedTmpl --\u003e Engine\n\n    Engine --\u003e|\"RenderCatalog()\"| CatalogPhase\n    Engine --\u003e|\"RenderContent()\"| ContentPhase\n    Engine --\u003e|\"RenderTranslate()\"| TranslatePhase\n    Engine --\u003e|\"RenderUpdateMatched()\\nRenderUpdateUnmatched()\"| UpdaterPhase\n```\n\n### 模板檔案組織\n\n```mermaid\nflowchart TD\n    subgraph FS[\"embed.FS：templateFS\"]\n        subgraph ZhTW[\"templates/zh-TW/\"]\n            z1[\"catalog.tmpl\"]\n            z2[\"content.tmpl\"]\n            z3[\"updater.tmpl\"]\n            z4[\"update_matched.tmpl\"]\n            z5[\"update_unmatched.tmpl\"]\n        end\n        subgraph EnUS[\"templates/en-US/\"]\n            e1[\"catalog.tmpl\"]\n            e2[\"content.tmpl\"]\n            e3[\"updater.tmpl\"]\n            e4[\"update_matched.tmpl\"]\n            e5[\"update_unmatched.tmpl\"]\n        end\n        subgraph Shared[\"templates/（根目錄）\"]\n            s1[\"translate.tmpl\"]\n        end\n    end\n\n    Engine_Lang[\"Engine.templates\\n（語言模板集）\"]\n    Engine_Shared[\"Engine.sharedTemplates\\n（共用模板）\"]\n\n    ZhTW --\u003e Engine_Lang\n    EnUS --\u003e Engine_Lang\n    Shared --\u003e Engine_Shared\n```\n\n## 核心資料結構\n\n`Engine` 中定義了六個對應不同渲染場景的資料結構（Data Struct）：\n\n### CatalogPromptData\n\n用於**目錄產生階段**，提供專案的完整掃描結果讓 Claude 分析並設計文件目錄。\n\n```go\ntype CatalogPromptData struct {\n\tRepositoryName       string\n\tProjectType          string\n\tLanguage             string\n\tLanguageName         string // native display name (e.g., \"繁體中文\")\n\tLanguageOverride     bool   // true when template lang != output lang\n\tLanguageOverrideName string // native name of the desired output language\n\tKeyFiles             string\n\tEntryPoints          string\n\tFileTree             string\n\tReadmeContent        string\n}\n```\n\n\u003e 來源：internal/prompt/engine.go#L40-L51\n\n### ContentPromptData\n\n用於**內容頁面產生階段**，指定要撰寫的頁面在目錄中的位置、可連結的頁面清單，以及更新情境下的現有內容。\n\n```go\ntype ContentPromptData struct {\n\tRepositoryName       string\n\tLanguage             string\n\tLanguageName         string\n\tLanguageOverride     bool\n\tLanguageOverrideName string\n\tCatalogPath          string\n\tCatalogTitle         string\n\tCatalogDirPath       string // filesystem dir path of THIS item, e.g., \"configuration/claude-config\"\n\tProjectDir           string\n\tFileTree             string\n\tCatalogTable         string // formatted table of all catalog items with their dir paths\n\tExistingContent      string // existing page content for update context (empty for new pages)\n}\n```\n\n\u003e 來源：internal/prompt/engine.go#L54-L67\n\n### UpdateMatchedPromptData 與 UpdateUnmatchedPromptData\n\n用於**增量更新階段**，分別處理「判斷哪些現有頁面需要重新產生」與「判斷是否需要新增頁面」兩個子任務。\n\n```go\ntype UpdateMatchedPromptData struct {\n\tRepositoryName string\n\tLanguage       string\n\tChangedFiles   string // list of changed source files\n\tAffectedPages  string // pages that reference these files (path + title + summary)\n}\n\ntype UpdateUnmatchedPromptData struct {\n\tRepositoryName  string\n\tLanguage        string\n\tUnmatchedFiles  string // changed files not referenced in any existing doc\n\tExistingCatalog string // existing catalog JSON\n\tCatalogTable    string // formatted link table of all pages\n}\n```\n\n\u003e 來源：internal/prompt/engine.go#L81-L95\n\n### TranslatePromptData\n\n用於**翻譯階段**，指定來源語言、目標語言，以及要翻譯的完整 Markdown 內容。\n\n```go\ntype TranslatePromptData struct {\n\tSourceLanguage     string // e.g., \"zh-TW\"\n\tSourceLanguageName string // e.g., \"繁體中文\"\n\tTargetLanguage     string // e.g., \"en-US\"\n\tTargetLanguageName string // e.g., \"English\"\n\tSourceContent      string // the full markdown content to translate\n}\n```\n\n\u003e 來源：internal/prompt/engine.go#L98-L104\n\n## 模板語言選擇邏輯\n\n引擎的語言選擇由 `config.OutputConfig` 中的兩個方法控制：\n\n```go\n// SupportedTemplateLangs lists language codes that have built-in prompt template folders.\nvar SupportedTemplateLangs = []string{\"zh-TW\", \"en-US\"}\n\n// GetEffectiveTemplateLang returns which template folder to load.\n// If Language has a built-in template set, returns it; otherwise falls back to \"en-US\".\nfunc (o *OutputConfig) GetEffectiveTemplateLang() string {\n\tfor _, lang := range SupportedTemplateLangs {\n\t\tif o.Language == lang {\n\t\t\treturn o.Language\n\t\t}\n\t}\n\treturn \"en-US\"\n}\n\n// NeedsLanguageOverride returns true when the template language differs from Language,\n// meaning the prompt needs an explicit instruction to output in the configured language.\nfunc (o *OutputConfig) NeedsLanguageOverride() bool {\n\treturn o.GetEffectiveTemplateLang() != o.Language\n}\n```\n\n\u003e 來源：internal/config/config.go#L53-L71\n\n當 `LanguageOverride` 為 `true` 時，模板會在 Prompt 中加入明確的語言指令，要求 Claude 以指定語言輸出，即使模板本身是英文撰寫的。\n\n## 核心流程\n\n### Engine 初始化與渲染流程\n\n```mermaid\nsequenceDiagram\n    participant Gen as generator.NewGenerator\n    participant Cfg as config.OutputConfig\n    participant Eng as prompt.NewEngine\n    participant FS as embed.FS\n\n    Gen-\u003e\u003eCfg: GetEffectiveTemplateLang()\n    Cfg--\u003e\u003eGen: templateLang（如 \"zh-TW\"）\n    Gen-\u003e\u003eEng: NewEngine(templateLang)\n    Eng-\u003e\u003eFS: ParseFS(\"templates/zh-TW/*.tmpl\")\n    FS--\u003e\u003eEng: language-specific templates\n    Eng-\u003e\u003eFS: ParseFS(\"templates/*.tmpl\")\n    FS--\u003e\u003eEng: shared templates（translate.tmpl）\n    Eng--\u003e\u003eGen: *Engine\n\n    Note over Gen: 文件產生階段開始\n\n    Gen-\u003e\u003eEng: RenderCatalog(data)\n    Eng-\u003e\u003eEng: render(\"catalog.tmpl\", data)\n    Eng--\u003e\u003eGen: rendered prompt string\n\n    Gen-\u003e\u003eEng: RenderContent(data)\n    Eng-\u003e\u003eEng: render(\"content.tmpl\", data)\n    Eng--\u003e\u003eGen: rendered prompt string\n\n    Gen-\u003e\u003eEng: RenderTranslate(data)\n    Eng-\u003e\u003eEng: renderShared(\"translate.tmpl\", data)\n    Eng--\u003e\u003eGen: rendered prompt string\n```\n\n### 語言覆寫決策流程\n\n```mermaid\nflowchart TD\n    A[\"使用者設定 output.language\\n（例：ja-JP）\"]\n    B{\"是否為支援的\\n模板語言？\\nSupportedTemplateLangs\"}\n    C[\"使用對應語言模板\\n（zh-TW 或 en-US）\\nLanguageOverride = false\"]\n    D[\"退回使用 en-US 模板\\nLanguageOverride = true\\nLanguageOverrideName = ja-JP\"]\n    E[\"模板中加入語言覆寫指令\\n要求 Claude 以目標語言輸出\"]\n\n    A --\u003e B\n    B --\u003e|\"是（zh-TW / en-US）\"| C\n    B --\u003e|\"否\"| D\n    D --\u003e E\n```\n\n## 使用範例\n\n### 初始化 Engine\n\n```go\n// NewGenerator creates a new Generator.\nfunc NewGenerator(cfg *config.Config, rootDir string, logger *slog.Logger) (*Generator, error) {\n\ttemplateLang := cfg.Output.GetEffectiveTemplateLang()\n\tengine, err := prompt.NewEngine(templateLang)\n\tif err != nil {\n\t\treturn nil, err\n\t}\n\t// ...\n\treturn \u0026Generator{\n\t\t// ...\n\t\tEngine: engine,\n\t}, nil\n}\n```\n\n\u003e 來源：internal/generator/pipeline.go#L35-L59\n\n### 渲染目錄 Prompt\n\n```go\nfunc (g *Generator) GenerateCatalog(ctx context.Context, scan *scanner.ScanResult) (*catalog.Catalog, error) {\n\tlangName := config.GetLangNativeName(g.Config.Output.Language)\n\tdata := prompt.CatalogPromptData{\n\t\tRepositoryName:       g.Config.Project.Name,\n\t\tProjectType:          g.Config.Project.Type,\n\t\tLanguage:             g.Config.Output.Language,\n\t\tLanguageName:         langName,\n\t\tLanguageOverride:     g.Config.Output.NeedsLanguageOverride(),\n\t\tLanguageOverrideName: langName,\n\t\tKeyFiles:             scan.KeyFiles(),\n\t\tEntryPoints:          scan.EntryPointsFormatted(),\n\t\tFileTree:             scanner.RenderTree(scan.Tree, 4),\n\t\tReadmeContent:        scan.ReadmeContent,\n\t}\n\n\trendered, err := g.Engine.RenderCatalog(data)\n\tif err != nil {\n\t\treturn nil, err\n\t}\n\t// rendered 為完整的 Prompt 字串，傳遞給 claude.Runner\n}\n```\n\n\u003e 來源：internal/generator/catalog_phase.go#L16-L62\n\n### 渲染翻譯 Prompt\n\n```go\nrendered, err := g.Engine.RenderTranslate(data)\n```\n\n\u003e 來源：internal/generator/translate_phase.go#L195\n\n## 相關連結\n\n- [文件產生管線](../generator/index.md) — `Engine` 在四階段管線中的使用方式\n- [目錄產生階段](../generator/catalog-phase/index.md) — 使用 `RenderCatalog` 的詳細流程\n- [內容頁面產生階段](../generator/content-phase/index.md) — 使用 `RenderContent` 的詳細流程\n- [翻譯階段](../generator/translate-phase/index.md) — 使用 `RenderTranslate` 的詳細流程\n- [增量更新](../incremental-update/index.md) — 使用 `RenderUpdateMatched`、`RenderUpdateUnmatched` 的情境\n- [Claude CLI 執行器](../claude-runner/index.md) — 接收 `Engine` 渲染結果的下游元件\n- [多語言支援](../../i18n/index.md) — 語言覆寫機制的使用者端設定\n\n## 參考檔案\n\n| 檔案路徑 | 說明 |\n|----------|------|\n| `internal/prompt/engine.go` | `Engine` 結構、資料型別定義與渲染方法 |\n| `internal/prompt/templates/zh-TW/catalog.tmpl` | 繁體中文目錄產生 Prompt 模板 |\n| `internal/prompt/templates/zh-TW/content.tmpl` | 繁體中文內容頁面產生 Prompt 模板 |\n| `internal/prompt/templates/zh-TW/updater.tmpl` | 繁體中文增量更新（legacy）Prompt 模板 |\n| `internal/prompt/templates/zh-TW/update_matched.tmpl` | 繁體中文：判斷現有頁面是否需重新產生的 Prompt 模板 |\n| `internal/prompt/templates/zh-TW/update_unmatched.tmpl` | 繁體中文：判斷是否需新增頁面的 Prompt 模板 |\n| `internal/prompt/templates/translate.tmpl` | 共用翻譯 Prompt 模板（語言無關） |\n| `internal/prompt/templates/en-US/catalog.tmpl` | 英文目錄產生 Prompt 模板 |\n| `internal/config/config.go` | `OutputConfig.GetEffectiveTemplateLang()`、`NeedsLanguageOverride()` 與 `SupportedTemplateLangs` 定義 |\n| `internal/generator/pipeline.go` | `Generator` 結構定義與 `NewGenerator` 初始化邏輯 |\n| `internal/generator/catalog_phase.go` | `GenerateCatalog`：使用 `RenderCatalog` 的範例 |","core-modules/scanner/index.md":"# 專案掃描器\n\n專案掃描器（`scanner` 套件）負責遍歷目標專案的目錄結構，收集檔案清單、建構樹狀結構、讀取 README 與進入點（entry points）檔案，並將結果封裝為 `ScanResult`，供後續的文件產生管線使用。\n\n## 概述\n\n在 selfmd 的四階段管線中，掃描器是第一個執行的核心模組（Phase 1）。它的職責是：\n\n- **收集符合條件的檔案**：依照 `selfmd.yaml` 中 `targets.include` 與 `targets.exclude` 的 glob 規則，過濾出需要文件化的原始碼檔案\n- **建構檔案樹（File Tree）**：將扁平的檔案路徑清單轉換為層次化的 `FileNode` 樹狀結構，供後續渲染為可讀的目錄格式\n- **讀取關鍵上下文**：自動讀取 `README.md` 及設定檔中指定的進入點檔案，作為 Claude 產生目錄時的背景資料\n\n掃描結果（`ScanResult`）是整個管線的起點：Catalog Phase 和 Content Phase 都依賴它提供的檔案樹、KEY files 清單與進入點內容。\n\n### 核心概念\n\n| 術語 | 說明 |\n|------|------|\n| `ScanResult` | 掃描完成後的完整結果物件，包含樹狀結構、檔案清單、README 等資訊 |\n| `FileNode` | 代表檔案樹中的單一節點，可以是目錄或檔案 |\n| `BuildTree` | 將扁平路徑清單轉換為 `FileNode` 樹的函式 |\n| `RenderTree` | 將 `FileNode` 樹渲染為類 UNIX `tree` 指令格式的文字，用於注入 Prompt |\n| Entry Points | 設定中指定的重要檔案（如 `main.go`），其內容會被完整讀入供 Claude 參考 |\n\n## 架構\n\n```mermaid\nflowchart TD\n    Config[\"config.Config\\n(targets.include / exclude\\ntargets.entry_points)\"]\n    RootDir[\"rootDir\\n目標專案根目錄\"]\n\n    Scan[\"scanner.Scan()\"]\n\n    WalkDir[\"filepath.WalkDir()\"]\n    GlobMatch[\"doublestar.Match()\\ninclude / exclude 篩選\"]\n    ReadReadme[\"readFileIfExists()\\nREADME.md\"]\n    ReadEntryPoints[\"readFileIfExists()\\nentry_points\"]\n    BuildTree[\"BuildTree()\\n扁平路徑 → FileNode 樹\"]\n    SortTree[\"sortTree()\\n目錄優先，字母排序\"]\n\n    ScanResult[\"ScanResult\\n- RootDir\\n- Tree (*FileNode)\\n- FileList\\n- TotalFiles / TotalDirs\\n- ReadmeContent\\n- EntryPointContents\"]\n\n    CatalogPhase[\"GenerateCatalog()\\nCatalog Phase\"]\n    ContentPhase[\"GenerateContent()\\nContent Phase\"]\n    RenderTree[\"RenderTree()\\n文字樹渲染\"]\n\n    Config --\u003e Scan\n    RootDir --\u003e Scan\n    Scan --\u003e WalkDir\n    WalkDir --\u003e GlobMatch\n    GlobMatch --\u003e BuildTree\n    BuildTree --\u003e SortTree\n    Scan --\u003e ReadReadme\n    Scan --\u003e ReadEntryPoints\n    SortTree --\u003e ScanResult\n    ReadReadme --\u003e ScanResult\n    ReadEntryPoints --\u003e ScanResult\n\n    ScanResult --\u003e CatalogPhase\n    ScanResult --\u003e ContentPhase\n    ScanResult --\u003e RenderTree\n```\n\n## 資料結構\n\n### FileNode\n\n`FileNode` 是檔案樹的基本單元，代表一個目錄或檔案：\n\n```go\ntype FileNode struct {\n    Name     string\n    Path     string // relative path from project root\n    IsDir    bool\n    Children []*FileNode\n}\n```\n\n\u003e 來源：`internal/scanner/filetree.go#L11-L16`\n\n### ScanResult\n\n`ScanResult` 封裝了一次完整掃描的所有輸出：\n\n```go\ntype ScanResult struct {\n    RootDir            string\n    Tree               *FileNode\n    FileList           []string\n    TotalFiles         int\n    TotalDirs          int\n    ReadmeContent      string\n    EntryPointContents map[string]string\n}\n```\n\n\u003e 來源：`internal/scanner/filetree.go#L19-L27`\n\n## 核心流程\n\n### Scan 掃描主流程\n\n```mermaid\nsequenceDiagram\n    participant Pipeline as generator.Generate()\n    participant S as scanner.Scan()\n    participant FS as 檔案系統\n    participant BT as BuildTree()\n\n    Pipeline-\u003e\u003eS: Scan(cfg, rootDir)\n    S-\u003e\u003eFS: filepath.WalkDir(rootDir, ...)\n    loop 每個路徑\n        FS--\u003e\u003eS: path, DirEntry\n        S-\u003e\u003eS: 計算相對路徑 (rel)\n        alt 符合 exclude 規則\n            S-\u003e\u003eS: 跳過（目錄則 SkipDir）\n        else 符合 include 規則（或無 include）\n            S-\u003e\u003eS: 加入 files []string\n        end\n    end\n    S-\u003e\u003eBT: BuildTree(projectName, files)\n    BT--\u003e\u003eS: *FileNode（已排序）\n    S-\u003e\u003eFS: 讀取 README.md\n    S-\u003e\u003eFS: 讀取 entry_points 各檔案\n    S--\u003e\u003ePipeline: *ScanResult\n```\n\n### 檔案過濾邏輯\n\n掃描時採用「先排除、後包含」的雙層過濾策略：\n\n1. **排除（Exclude）優先**：若路徑符合任一 `exclude` glob pattern，目錄直接呼叫 `filepath.SkipDir` 跳過整個子樹，檔案則略過\n2. **包含（Include）過濾**：若設定了 `include` 清單，只有符合至少一個 pattern 的檔案才會被收入結果\n\n```go\n// check excludes\nfor _, pattern := range cfg.Targets.Exclude {\n    matched, _ := doublestar.Match(pattern, rel)\n    if matched {\n        if d.IsDir() {\n            return filepath.SkipDir\n        }\n        return nil\n    }\n}\n\n// check includes\nif len(cfg.Targets.Include) \u003e 0 {\n    included := false\n    for _, pattern := range cfg.Targets.Include {\n        matched, _ := doublestar.Match(pattern, rel)\n        if matched {\n            included = true\n            break\n        }\n    }\n    if !included {\n        return nil\n    }\n}\n```\n\n\u003e 來源：`internal/scanner/scanner.go#L33-L61`\n\nGlob 匹配使用 `doublestar` 套件，支援 `**` 通配符（如 `vendor/**`、`internal/**`）。\n\n### BuildTree 樹狀結構建構\n\n`BuildTree` 接受扁平的相對路徑清單，逐步建構 `FileNode` 樹：\n\n```go\nfunc BuildTree(rootName string, paths []string) *FileNode {\n    root := \u0026FileNode{\n        Name:  rootName,\n        Path:  \"\",\n        IsDir: true,\n    }\n\n    for _, p := range paths {\n        parts := strings.Split(filepath.ToSlash(p), \"/\")\n        current := root\n        for i, part := range parts {\n            isLast := i == len(parts)-1\n            child := findChild(current, part)\n            if child == nil {\n                child = \u0026FileNode{\n                    Name:  part,\n                    Path:  strings.Join(parts[:i+1], \"/\"),\n                    IsDir: !isLast,\n                }\n                current.Children = append(current.Children, child)\n            }\n            if !isLast {\n                child.IsDir = true\n            }\n            current = child\n        }\n    }\n\n    sortTree(root)\n    return root\n}\n```\n\n\u003e 來源：`internal/scanner/filetree.go#L30-L60`\n\n建構完成後，`sortTree` 對每層節點進行排序：**目錄節點優先，相同類型則按字母順序**。\n\n### RenderTree 樹狀文字渲染\n\n`RenderTree` 將 `FileNode` 樹轉換為類似 UNIX `tree` 指令輸出的文字格式，注入至 Claude Prompt 中：\n\n```go\nfunc RenderTree(node *FileNode, maxDepth int) string {\n    var sb strings.Builder\n    sb.WriteString(node.Name + \"/\\n\")\n    renderChildren(\u0026sb, node, \"\", maxDepth, 0)\n    return sb.String()\n}\n```\n\n\u003e 來源：`internal/scanner/filetree.go#L87-L92`\n\n渲染時具備兩項保護機制：\n- `maxDepth`：限制最大展開深度（Catalog Phase 用 4 層，Content Phase 用 3 層）\n- 每層最多渲染 30 個子節點，超過時顯示 `... (N more items)`\n\n## 輔助方法\n\n### KeyFiles()\n\n掃描結果提供 `KeyFiles()` 方法，從 `FileList` 中篩選出知名的重要檔案（如 `main.go`、`Dockerfile`、`go.mod` 等），以逗號分隔回傳，作為 Catalog Prompt 的補充資訊：\n\n```go\nfunc (s *ScanResult) KeyFiles() string {\n    notable := []string{}\n    patterns := []string{\n        \"main.go\", \"main.py\", \"main.rs\", \"main.ts\", \"main.js\",\n        \"index.ts\", \"index.js\", \"app.go\", \"app.py\", \"app.ts\",\n        \"Makefile\", \"Dockerfile\", \"docker-compose.yml\", \"compose.yaml\",\n        \"package.json\", \"go.mod\", \"Cargo.toml\", \"pom.xml\",\n        \"README.md\", \"CHANGELOG.md\",\n    }\n    // ...\n    if len(notable) \u003e 20 {\n        notable = notable[:20]\n    }\n    return strings.Join(notable, \", \")\n}\n```\n\n\u003e 來源：`internal/scanner/scanner.go#L117-L141`\n\n### EntryPointsFormatted()\n\n將設定中指定的進入點檔案內容格式化為 Markdown 程式碼區塊，每個進入點限制最多 10,000 字元，超過則截斷：\n\n```go\nfunc (s *ScanResult) EntryPointsFormatted() string {\n    if len(s.EntryPointContents) == 0 {\n        return \"(no entry points specified)\"\n    }\n\n    var sb strings.Builder\n    for path, content := range s.EntryPointContents {\n        sb.WriteString(\"### \" + path + \"\\n```\\n\")\n        if len(content) \u003e 10000 {\n            content = content[:10000] + \"\\n... (truncated)\"\n        }\n        sb.WriteString(content)\n        sb.WriteString(\"\\n```\\n\\n\")\n    }\n    return sb.String()\n}\n```\n\n\u003e 來源：`internal/scanner/scanner.go#L144-L160`\n\n### readFileIfExists()\n\n私有輔助函式，讀取檔案內容並在超過 50,000 字元時自動截斷：\n\n```go\nfunc readFileIfExists(rootDir, relPath string) string {\n    data, err := os.ReadFile(filepath.Join(rootDir, relPath))\n    if err != nil {\n        return \"\"\n    }\n    content := string(data)\n    if len(content) \u003e 50000 {\n        content = content[:50000] + \"\\n... (truncated)\"\n    }\n    return content\n}\n```\n\n\u003e 來源：`internal/scanner/scanner.go#L103-L114`\n\n## 使用範例\n\n### 在管線中呼叫掃描器\n\n以下是 `generator.Generate()` 中呼叫掃描器的實際程式碼：\n\n```go\n// Phase 1: Scan\nfmt.Println(ui.T(\"[1/4] 掃描專案結構...\", \"[1/4] Scanning project structure...\"))\nscan, err := scanner.Scan(g.Config, g.RootDir)\nif err != nil {\n    return fmt.Errorf(ui.T(\"掃描專案失敗: %w\", \"failed to scan project: %w\"), err)\n}\nfmt.Printf(ui.T(\"      找到 %d 個檔案，分布於 %d 個目錄\\n\", \"      Found %d files in %d directories\\n\"), scan.TotalFiles, scan.TotalDirs)\n```\n\n\u003e 來源：`internal/generator/pipeline.go#L88-L94`\n\n### 掃描結果用於 Catalog Phase\n\n```go\ndata := prompt.CatalogPromptData{\n    // ...\n    KeyFiles:      scan.KeyFiles(),\n    EntryPoints:   scan.EntryPointsFormatted(),\n    FileTree:      scanner.RenderTree(scan.Tree, 4),\n    ReadmeContent: scan.ReadmeContent,\n}\n```\n\n\u003e 來源：`internal/generator/catalog_phase.go#L18-L29`\n\n### 掃描結果用於 Content Phase\n\n```go\ndata := prompt.ContentPromptData{\n    // ...\n    FileTree: scanner.RenderTree(scan.Tree, 3),\n}\n```\n\n\u003e 來源：`internal/generator/content_phase.go#L102-L103`\n\n## 相關連結\n\n- [文件產生管線](../generator/index.md) — 掃描器在四階段管線中的位置與呼叫時機\n- [目錄產生階段](../generator/catalog-phase/index.md) — 直接消費 `ScanResult` 的第一個下游階段\n- [內容頁面產生階段](../generator/content-phase/index.md) — 使用 `RenderTree` 注入檔案樹至 Prompt\n- [專案與掃描目標設定](../../configuration/project-targets/index.md) — `include`、`exclude`、`entry_points` 的設定方式\n- [核心模組](../index.md) — 回到核心模組總覽\n\n## 參考檔案\n\n| 檔案路徑 | 說明 |\n|----------|------|\n| `internal/scanner/scanner.go` | `Scan()` 主函式、`KeyFiles()`、`EntryPointsFormatted()`、`readFileIfExists()` |\n| `internal/scanner/filetree.go` | `FileNode`、`ScanResult` 資料結構定義；`BuildTree()`、`RenderTree()`、`sortTree()` |\n| `internal/generator/pipeline.go` | 管線主流程，展示掃描器的呼叫時機與結果使用 |\n| `internal/generator/catalog_phase.go` | Catalog Phase 中對 `ScanResult` 各方法的消費方式 |\n| `internal/generator/content_phase.go` | Content Phase 中 `RenderTree` 的使用方式 |\n| `internal/config/config.go` | `TargetsConfig` 結構定義（`Include`、`Exclude`、`EntryPoints`） |","core-modules/static-viewer/index.md":"# 靜態文件瀏覽器\n\n靜態文件瀏覽器是 selfmd 的最終輸出介面，以零依賴的單頁應用程式（SPA）形式呈現，僅需開啟 `index.html` 即可瀏覽所有文件，無須任何伺服器或網路服務。\n\n## 概述\n\nselfmd 在每次文件產生完成後，會自動在 `.doc-build/` 目錄下建立一組靜態網頁檔案。使用者只需在瀏覽器中開啟 `.doc-build/index.html`，便可透過側邊欄導覽、即時 Markdown 渲染與 Mermaid 圖表檢視所有產生的文件。\n\n靜態瀏覽器的核心設計原則如下：\n\n- **無伺服器（Serverless）**：所有 Markdown 內容與目錄結構預先打包成 `_data.js`，以 JavaScript 全域變數形式注入，不依賴任何後端 API\n- **二進位嵌入（Binary Embed）**：HTML、JavaScript、CSS 三個靜態資產以 Go `//go:embed` 指令編譯進 selfmd 執行檔，發佈時無需附帶額外檔案\n- **單一入口點**：`index.html` 為唯一入口，使用 URL hash（`#path/to/page.md`）實現客戶端路由\n- **多語言支援**：若文件有翻譯版本，側邊欄頂部會顯示語言切換器，切換時動態替換頁面內容與目錄\n\n瀏覽器涉及的輸出檔案：\n\n| 檔案 | 說明 |\n|------|------|\n| `index.html` | HTML 外殼，含專案名稱與語言代碼注入 |\n| `app.js` | 前端 SPA 邏輯（路由、渲染、互動） |\n| `style.css` | 版面配置與視覺樣式 |\n| `_data.js` | 打包所有 Markdown 內容與目錄的資料包 |\n| `_doc_meta.json` | 語言元資料（可選） |\n\n## 架構\n\n```mermaid\nflowchart TD\n    subgraph Go_Build[\"Go 二進位（embed）\"]\n        EmbedHTML[\"viewer/index.html\"]\n        EmbedJS[\"viewer/app.js\"]\n        EmbedCSS[\"viewer/style.css\"]\n    end\n\n    subgraph WriteViewer[\"Writer.WriteViewer()\"]\n        Inject[\"注入 PROJECT_NAME / LANG\"]\n        BundleData[\"bundleData()\\n收集 .md + _catalog.json\"]\n        DocMeta[\"序列化 _doc_meta.json\"]\n    end\n\n    subgraph Output[\".doc-build/ 輸出目錄\"]\n        OutHTML[\"index.html\"]\n        OutJS[\"app.js\"]\n        OutCSS[\"style.css\"]\n        OutData[\"_data.js\\nwindow.DOC_DATA = {...}\"]\n        OutMeta[\"_doc_meta.json\"]\n    end\n\n    subgraph Browser[\"瀏覽器 SPA（app.js）\"]\n        Init[\"init()\"]\n        Sidebar[\"buildSidebar()\"]\n        Router[\"handleRoute() — Hash 路由\"]\n        Render[\"renderContent() — Markdown 渲染\"]\n        LangSwitch[\"switchLanguage()\"]\n    end\n\n    EmbedHTML --\u003e Inject\n    EmbedJS --\u003e WriteViewer\n    EmbedCSS --\u003e WriteViewer\n    Inject --\u003e OutHTML\n    BundleData --\u003e OutData\n    DocMeta --\u003e OutMeta\n    WriteViewer --\u003e OutJS\n    WriteViewer --\u003e OutCSS\n\n    OutHTML --\u003e Browser\n    OutData --\u003e Init\n    Init --\u003e Sidebar\n    Init --\u003e Router\n    Router --\u003e Render\n    LangSwitch --\u003e Sidebar\n```\n\n\u003e 來源：`internal/output/viewer.go`、`internal/output/viewer/app.js`\n\n## 靜態資產嵌入機制\n\n三個靜態資產檔案透過 Go `embed` 套件在編譯時期直接嵌入執行檔，不需要在執行環境中存在對應的檔案路徑。\n\n```go\n//go:embed viewer/index.html\nvar viewerHTML string\n\n//go:embed viewer/app.js\nvar viewerJS string\n\n//go:embed viewer/style.css\nvar viewerCSS string\n```\n\n\u003e 來源：`internal/output/viewer.go#L12-L19`\n\n`WriteViewer` 在寫出 `index.html` 前，會對模板進行字串替換，將專案名稱（`{{PROJECT_NAME}}`）與語言代碼（`{{LANG}}`）注入 HTML：\n\n```go\nfunc (w *Writer) WriteViewer(projectName string, docMeta *DocMeta) error {\n    html := strings.ReplaceAll(viewerHTML, \"{{PROJECT_NAME}}\", projectName)\n    lang := \"zh-TW\"\n    if docMeta != nil {\n        lang = docMeta.DefaultLanguage\n    }\n    html = strings.ReplaceAll(html, \"{{LANG}}\", lang)\n\n    if err := w.WriteFile(\"index.html\", html); err != nil {\n        return fmt.Errorf(\"寫入 index.html 失敗: %w\", err)\n    }\n    // ...\n}\n```\n\n\u003e 來源：`internal/output/viewer.go#L23-L43`\n\n## 資料打包機制（bundleData）\n\n`bundleData` 函式負責掃描 `.doc-build/` 目錄，將所有 Markdown 頁面與目錄結構打包成單一 `_data.js` 檔案。\n\n### 打包流程\n\n1. 讀取 `_catalog.json` 作為目錄結構\n2. 使用 `filepath.Walk` 遍歷輸出目錄，收集所有 `.md` 檔案（排除 `_` 開頭的特殊檔案）\n3. 若有多語言設定，跳過語言子目錄（`en-US/`、`ja-JP/` 等）中的主語言頁面\n4. 若有翻譯語言，另行收集各語言子目錄的目錄與頁面\n5. 將所有資料序列化為 JSON，寫入 `_data.js`\n\n```go\nfunc (w *Writer) bundleData(projectName string, docMeta *DocMeta) error {\n    // Read catalog\n    catalogPath := filepath.Join(w.BaseDir, \"_catalog.json\")\n    catalogBytes, err := os.ReadFile(catalogPath)\n    // ...\n\n    // Collect all master-language .md files (skip language subdirectories)\n    pages := make(map[string]string)\n    // ...\n    err = filepath.Walk(w.BaseDir, func(path string, info os.FileInfo, err error) error {\n        // Skip files starting with _\n        if strings.HasPrefix(filepath.Base(relPath), \"_\") {\n            return nil\n        }\n        // Skip files inside language subdirectories\n        topDir := strings.SplitN(relPath, \"/\", 2)[0]\n        if langDirs[topDir] {\n            return nil\n        }\n        // ...\n    })\n    // ...\n    content := \"window.DOC_DATA = \" + string(jsonBytes) + \";\\n\"\n    return w.WriteFile(\"_data.js\", content)\n}\n```\n\n\u003e 來源：`internal/output/viewer.go#L61-L193`\n\n### `_data.js` 資料結構\n\n最終產生的 `window.DOC_DATA` 全域物件結構如下：\n\n```javascript\nwindow.DOC_DATA = {\n  \"catalog\": { /* _catalog.json 的內容 */ },\n  \"pages\": {\n    \"overview/index.md\": \"# 概述\\n...\",\n    \"core-modules/scanner/index.md\": \"# 掃描器\\n...\"\n    // 所有主語言 .md 檔案\n  },\n  \"meta\": {\n    \"default_language\": \"zh-TW\",\n    \"available_languages\": [\n      { \"code\": \"zh-TW\", \"native_name\": \"繁體中文\", \"is_default\": true },\n      { \"code\": \"en-US\", \"native_name\": \"English\", \"is_default\": false }\n    ]\n  },\n  \"languages\": {\n    \"en-US\": {\n      \"catalog\": { /* 英文目錄 */ },\n      \"pages\": { \"overview/index.md\": \"# Overview\\n...\" }\n    }\n  }\n};\n```\n\n\u003e 來源：`internal/output/viewer.go#L126-L192`\n\n## 前端應用程式（app.js）\n\n`app.js` 是一個以原生 JavaScript（ES5 相容）撰寫的 SPA，使用立即呼叫函式（IIFE）封裝，不依賴任何前端框架。\n\n### 模組功能一覽\n\n| 函式群組 | 主要函式 | 說明 |\n|---------|---------|------|\n| 初始化 | `init()` | 載入資料、設定 Marked、初始化路由 |\n| 目錄建立 | `buildSidebar()` / `renderSidebarSection()` | 從 catalog 遞迴建立可折疊側邊欄 |\n| 路由 | `handleRoute()` / `loadPage()` | 基於 URL hash 的客戶端路由 |\n| 內容渲染 | `renderContent()` / `fixLinks()` | Markdown 渲染與相對路徑轉換 |\n| Mermaid | `renderMermaid()` | 偵測 mermaid 程式碼區塊並呼叫 `mermaid.run()` |\n| 語言切換 | `buildLangSwitcher()` / `switchLanguage()` | 多語言 `\u003cselect\u003e` 元件與資料切換 |\n| 工具列 | `buildPageToolbar()` | 每頁頂部的「複製路徑」與「下載 Markdown」按鈕 |\n| 全螢幕 | `enterMindmapFullscreen()` / `exitMindmapFullscreen()` | Mermaid 圖表的全螢幕縮放平移功能 |\n| 行動端 | `setupMobileMenu()` | 漢堡選單與側邊欄覆蓋層 |\n\n### 路由機制\n\n路由以 URL hash 實作：`location.hash` 的值即為頁面的相對路徑（如 `#core-modules/scanner/index.md`）。頁面切換時呼叫 `loadPage(path)`，從 `window.DOC_DATA.pages` 取出 Markdown 字串並渲染。\n\n```javascript\nfunction handleRoute() {\n    var path = location.hash.slice(1) || \"index.md\";\n    loadPage(path);\n}\n\nfunction loadPage(path) {\n    var md = pages[path];\n    if (!md) {\n        document.getElementById(\"article\").innerHTML =\n            \"\u003ch1\u003e頁面未找到\u003c/h1\u003e\u003cp\u003e找不到 \u003ccode\u003e\" + escapeHtml(path) + \"\u003c/code\u003e\u003c/p\u003e\";\n        return;\n    }\n    renderContent(md, path);\n    updateActiveLink(path);\n    updateTitle(path);\n    document.getElementById(\"content\").scrollTop = 0;\n    document.getElementById(\"sidebar\").classList.remove(\"open\");\n}\n```\n\n\u003e 來源：`internal/output/viewer/app.js#L172-L196`\n\n### 相對路徑修正\n\nMarkdown 中的相對連結（如 `../other-section/index.md`）在 SPA 中需轉換為 hash 連結（`#other-section/index.md`）。`fixLinks()` 在渲染後遍歷所有 `\u003ca\u003e` 元素執行此轉換：\n\n```javascript\nfunction fixLinks(container, currentPath) {\n    var baseDir = currentPath.replace(/[^/]*$/, \"\");\n    var links = container.querySelectorAll(\"a[href]\");\n    for (var i = 0; i \u003c links.length; i++) {\n        var href = links[i].getAttribute(\"href\");\n        if (href.indexOf(\"://\") !== -1 || href.charAt(0) === \"#\" || href.indexOf(\"mailto:\") === 0) continue;\n        var resolved = resolvePath(baseDir, href);\n        links[i].setAttribute(\"href\", \"#\" + resolved);\n    }\n}\n```\n\n\u003e 來源：`internal/output/viewer/app.js#L280-L293`\n\n### Mermaid 圖表全螢幕功能\n\n每個 Mermaid 圖表旁都有全螢幕按鈕（`⛶`），點擊後進入全螢幕模式，支援滾輪縮放（0.8× 至 2.0×）與滑鼠拖曳平移：\n\n```javascript\nfunction onMmWheel(e) {\n    e.preventDefault();\n    var delta = e.deltaY \u003e 0 ? 0.95 : 1.05;\n    var newScale = mmState.scale * delta;\n    if (newScale \u003c 0.8) newScale = 0.8;\n    if (newScale \u003e 2.0) newScale = 2.0;\n    mmState.scale = newScale;\n    applyMmTransform();\n}\n```\n\n\u003e 來源：`internal/output/viewer/app.js#L526-L534`\n\n## 視覺樣式（style.css）\n\n`style.css` 使用 CSS 自訂屬性（CSS Variables）定義設計系統，以深色主題側邊欄搭配淺色主內容區呈現：\n\n```css\n:root {\n    --sidebar-width: 280px;\n    --sidebar-bg: #1a1b26;\n    --sidebar-text: #a9b1d6;\n    --sidebar-active-bg: rgba(122, 162, 247, 0.12);\n    --sidebar-active-text: #7aa2f7;\n    --content-bg: #ffffff;\n    --text-color: #2e3440;\n    /* ... */\n}\n```\n\n\u003e 來源：`internal/output/viewer/style.css#L1-L19`\n\n響應式設計以 `@media (max-width: 860px)` 斷點為基準，在窄螢幕上隱藏側邊欄並顯示漢堡選單：\n\n```css\n@media (max-width: 860px) {\n    #menu-toggle { display: block; }\n    #sidebar {\n        position: fixed;\n        transform: translateX(-100%);\n        transition: transform 0.25s ease;\n    }\n    #sidebar.open { transform: translateX(0); }\n}\n```\n\n\u003e 來源：`internal/output/viewer/style.css#L521-L551`\n\n## 核心流程\n\n```mermaid\nsequenceDiagram\n    participant Pipeline as generator/pipeline.go\n    participant ViewerWriter as Writer.WriteViewer()\n    participant BundleData as bundleData()\n    participant FS as .doc-build/ 檔案系統\n    participant Browser as 使用者瀏覽器\n\n    Pipeline-\u003e\u003eViewerWriter: WriteViewer(projectName, docMeta)\n    ViewerWriter-\u003e\u003eViewerWriter: 注入 PROJECT_NAME / LANG 至 HTML\n    ViewerWriter-\u003e\u003eFS: 寫出 index.html\n    ViewerWriter-\u003e\u003eFS: 寫出 app.js\n    ViewerWriter-\u003e\u003eFS: 寫出 style.css\n    ViewerWriter-\u003e\u003eFS: 寫出 _doc_meta.json\n    ViewerWriter-\u003e\u003eBundleData: bundleData()\n    BundleData-\u003e\u003eFS: 讀取 _catalog.json\n    BundleData-\u003e\u003eFS: Walk 收集所有 .md 檔案\n    BundleData-\u003e\u003eFS: 收集翻譯語言頁面（若有）\n    BundleData-\u003e\u003eFS: 寫出 _data.js（window.DOC_DATA）\n    BundleData--\u003e\u003eViewerWriter: 完成\n    ViewerWriter--\u003e\u003ePipeline: nil（成功）\n\n    Note over Browser: 使用者開啟 index.html\n    Browser-\u003e\u003eFS: 載入 _data.js\n    Browser-\u003e\u003eBrowser: init()\n    Browser-\u003e\u003eBrowser: buildSidebar()\n    Browser-\u003e\u003eBrowser: handleRoute()（讀取 URL hash）\n    Browser-\u003e\u003eBrowser: renderContent()（Markdown → HTML）\n    Browser-\u003e\u003eBrowser: renderMermaid()（Mermaid 圖表）\n```\n\n## 外部函式庫依賴\n\n瀏覽器端透過 CDN 載入三個第三方函式庫，均從 `index.html` 中的 `\u003cscript\u003e` 標籤引入：\n\n```html\n\u003cscript src=\"https://cdn.jsdelivr.net/npm/marked/marked.min.js\"\u003e\u003c/script\u003e\n\u003cscript src=\"https://cdn.jsdelivr.net/npm/highlight.js@11/highlight.min.js\"\u003e\u003c/script\u003e\n\u003cscript src=\"https://cdn.jsdelivr.net/npm/mermaid/dist/mermaid.min.js\"\u003e\u003c/script\u003e\n```\n\n\u003e 來源：`internal/output/viewer/index.html#L26-L28`\n\n| 函式庫 | 用途 |\n|--------|------|\n| [marked](https://marked.js.org/) | Markdown 轉 HTML 渲染（GFM 支援） |\n| [highlight.js](https://highlightjs.org/) | 程式碼語法高亮 |\n| [mermaid](https://mermaid.js.org/) | Mermaid 圖表渲染（流程圖、序列圖等） |\n\n\u003e **注意**：由於依賴 CDN，在離線環境下瀏覽器仍可顯示文字內容，但程式碼高亮與 Mermaid 圖表需要網路連線才能正確渲染。\n\n## 觸發時機\n\n`WriteViewer` 在以下兩個時機被呼叫：\n\n1. **`selfmd generate` 完成**：管線第四階段（索引與導航）完成後，立即呼叫 `WriteViewer`\n2. **`selfmd translate` 完成**：翻譯完成後，重新打包含多語言資料的 `_data.js`\n\n```go\n// 在 pipeline.go 中（generate 完成後）\nif err := g.Writer.WriteViewer(g.Config.Project.Name, docMeta); err != nil {\n    g.Logger.Warn(\"產生瀏覽器失敗\", \"error\", err)\n} else {\n    fmt.Println(\"      完成，開啟 .doc-build/index.html 即可瀏覽\")\n}\n```\n\n\u003e 來源：`internal/generator/pipeline.go#L149-L155`\n\n## 相關連結\n\n- [輸出寫入與連結修復](../output-writer/index.md) — `Writer` 結構與 `WriteFile` 等基礎寫入函式\n- [文件產生管線](../generator/index.md) — 觸發 `WriteViewer` 的四階段管線說明\n- [索引與導航產生階段](../generator/index-phase/index.md) — 管線第四階段，WriteViewer 在此之後呼叫\n- [翻譯階段](../generator/translate-phase/index.md) — translate 完成後重新呼叫 WriteViewer\n- [多語言支援](../../i18n/index.md) — 語言切換器與多語言資料打包機制\n- [輸出結構說明](../../overview/output-structure/index.md) — `.doc-build/` 目錄下所有輸出檔案說明\n\n## 參考檔案\n\n| 檔案路徑 | 說明 |\n|----------|------|\n| `internal/output/viewer.go` | `WriteViewer()`、`bundleData()`、Go embed 嵌入宣告 |\n| `internal/output/viewer/index.html` | HTML 外殼模板，含 `{{PROJECT_NAME}}` 與 `{{LANG}}` 佔位符 |\n| `internal/output/viewer/app.js` | 前端 SPA 完整邏輯（路由、渲染、語言切換、Mermaid 全螢幕） |\n| `internal/output/viewer/style.css` | CSS 樣式，含 CSS 變數、響應式設計、列印模式 |\n| `internal/output/writer.go` | `Writer` 結構定義與 `WriteFile` 等基礎寫入函式 |\n| `internal/output/navigation.go` | `GenerateIndex`、`GenerateSidebar` 等導航頁面產生函式 |\n| `internal/generator/pipeline.go` | 呼叫 `WriteViewer` 的管線主流程 |\n| `internal/generator/translate_phase.go` | 翻譯完成後重新呼叫 `WriteViewer` |","en-US/architecture/index.md":"# System Architecture\n\nThis section contains the following:\n\n- [Overall Flow and Four-Phase Pipeline](pipeline/index.md)\n- [Module Dependency Graph](module-dependencies/index.md)\n","en-US/architecture/module-dependencies/index.md":"# Module Dependency Graph\n\nselfmd follows a clear layered architecture where dependencies flow in a single direction — from the foundation layer upward to the orchestration and CLI layers — eliminating circular dependencies.\n\n## Overview\n\nselfmd's module dependencies are organized into four distinct layers:\n\n1. **Foundation Layer**: No internal project dependencies; uses only the standard library or third-party packages\n2. **Middleware Layer**: Depends only on Foundation layer modules\n3. **Orchestration Layer**: The `generator` package, which depends on all Middleware and Foundation modules and is responsible for integrating all phases\n4. **CLI Layer** (Entry Points): The `cmd` package, which depends on the Orchestration layer and select Foundation modules to provide the user interface\n\nThis design guarantees **no circular dependencies** — lower-layer modules have no knowledge of higher-layer modules, making each module cheap to test and replace.\n\n### Key Terms\n\n| Term | Description |\n|------|-------------|\n| Foundation Layer | Pure-function packages with zero internal dependencies |\n| Orchestration Layer | Packages that integrate multiple modules and execute a complete workflow |\n| Dependency Injection | The `Generator` struct receives `Runner`, `Engine`, and `Writer` instances at construction time |\n\n---\n\n## Architecture\n\n### Overall Dependency Layer Diagram\n\n```mermaid\nflowchart TD\n    subgraph CLI[\"CLI Layer (cmd/)\"]\n        cmd_root[\"root.go\"]\n        cmd_init[\"init.go\"]\n        cmd_gen[\"generate.go\"]\n        cmd_update[\"update.go\"]\n        cmd_translate[\"translate.go\"]\n    end\n\n    subgraph Orchestration[\"Orchestration Layer (internal/generator/)\"]\n        pipeline[\"pipeline.go\u003cbr/\u003eGenerator\"]\n        catalog_phase[\"catalog_phase.go\u003cbr/\u003eGenerateCatalog\"]\n        content_phase[\"content_phase.go\u003cbr/\u003eGenerateContent\"]\n        index_phase[\"index_phase.go\u003cbr/\u003eGenerateIndex\"]\n        translate_phase[\"translate_phase.go\u003cbr/\u003eTranslate\"]\n        updater[\"updater.go\u003cbr/\u003eUpdate\"]\n    end\n\n    subgraph Middleware[\"Middleware Layer (internal/)\"]\n        claude[\"claude/\u003cbr/\u003eRunner · Parser · Types\"]\n        output_pkg[\"output/\u003cbr/\u003eWriter · LinkFixer · Navigation\"]\n        scanner_pkg[\"scanner/\u003cbr/\u003eScanner · FileTree\"]\n    end\n\n    subgraph Foundation[\"Foundation Layer (internal/)\"]\n        config_pkg[\"config/\u003cbr/\u003eConfig\"]\n        catalog_pkg[\"catalog/\u003cbr/\u003eCatalog\"]\n        prompt_pkg[\"prompt/\u003cbr/\u003eEngine\"]\n        git_pkg[\"git/\u003cbr/\u003eGit\"]\n    end\n\n    cmd_gen --\u003e pipeline\n    cmd_update --\u003e pipeline\n    cmd_update --\u003e git_pkg\n    cmd_update --\u003e scanner_pkg\n    cmd_translate --\u003e pipeline\n    cmd_init --\u003e config_pkg\n    cmd_gen --\u003e claude\n    cmd_update --\u003e claude\n    cmd_translate --\u003e claude\n\n    pipeline --\u003e catalog_phase\n    pipeline --\u003e content_phase\n    pipeline --\u003e index_phase\n    pipeline --\u003e translate_phase\n    pipeline --\u003e updater\n\n    catalog_phase --\u003e claude\n    catalog_phase --\u003e prompt_pkg\n    catalog_phase --\u003e scanner_pkg\n    catalog_phase --\u003e catalog_pkg\n\n    content_phase --\u003e claude\n    content_phase --\u003e prompt_pkg\n    content_phase --\u003e scanner_pkg\n    content_phase --\u003e catalog_pkg\n    content_phase --\u003e output_pkg\n\n    index_phase --\u003e catalog_pkg\n    index_phase --\u003e output_pkg\n\n    translate_phase --\u003e claude\n    translate_phase --\u003e prompt_pkg\n    translate_phase --\u003e catalog_pkg\n    translate_phase --\u003e output_pkg\n\n    updater --\u003e claude\n    updater --\u003e prompt_pkg\n    updater --\u003e scanner_pkg\n    updater --\u003e catalog_pkg\n    updater --\u003e output_pkg\n    updater --\u003e git_pkg\n\n    claude --\u003e config_pkg\n    scanner_pkg --\u003e config_pkg\n    output_pkg --\u003e catalog_pkg\n```\n\n\u003e Source: `cmd/generate.go#L1-L14`, `cmd/update.go#L1-L18`, `internal/generator/pipeline.go#L1-L16`\n\n---\n\n## Layer Details\n\n### Foundation Layer\n\nFoundation layer modules are independent of one another and can be tested and used in isolation.\n\n#### `internal/config`\n\n**Responsibility**: Reads, validates, and serializes the `selfmd.yaml` configuration file, and provides `DefaultConfig()`.\n\n- **Internal dependencies**: None\n- **External dependencies**: `gopkg.in/yaml.v3`\n- **Depended on by**: `claude`, `scanner`, `generator` (all phases), `cmd`\n\n```go\ntype Config struct {\n    Project ProjectConfig `yaml:\"project\"`\n    Targets TargetsConfig `yaml:\"targets\"`\n    Output  OutputConfig  `yaml:\"output\"`\n    Claude  ClaudeConfig  `yaml:\"claude\"`\n    Git     GitConfig     `yaml:\"git\"`\n}\n```\n\n\u003e Source: `internal/config/config.go#L11-L17`\n\n#### `internal/catalog`\n\n**Responsibility**: Defines the data model for the documentation catalog (`Catalog`, `CatalogItem`, `FlatItem`) and provides JSON serialization and flattening methods.\n\n- **Internal dependencies**: None\n- **External dependencies**: Standard library (`encoding/json`)\n- **Depended on by**: `output`, `generator` (all phases)\n\n```go\ntype Catalog struct {\n    Items []CatalogItem `json:\"items\"`\n}\n\ntype FlatItem struct {\n    Title       string\n    Path        string // dot-notation, e.g., \"core-modules.authentication\"\n    DirPath     string // filesystem path, e.g., \"core-modules/authentication\"\n    Depth       int\n    ParentPath  string\n    HasChildren bool\n}\n```\n\n\u003e Source: `internal/catalog/catalog.go#L10-L31`\n\n#### `internal/prompt`\n\n**Responsibility**: Manages prompt templates (`templates/zh-TW/*.tmpl`, `templates/en-US/*.tmpl`) and provides rendering methods for each pipeline phase.\n\n- **Internal dependencies**: None\n- **External dependencies**: Standard library (`text/template`, `embed`)\n- **Depended on by**: `generator` (all phases that use Claude)\n\n```go\ntype Engine struct {\n    templates       *template.Template // language-specific templates\n    sharedTemplates *template.Template // shared templates (translate.tmpl)\n}\n```\n\n\u003e Source: `internal/prompt/engine.go#L13-L17`\n\n#### `internal/git`\n\n**Responsibility**: Wraps Git CLI operations (retrieving commits, diffs, filtering changed files) without parsing business logic.\n\n- **Internal dependencies**: None\n- **External dependencies**: `github.com/bmatcuk/doublestar/v4`, standard library (`os/exec`)\n- **Depended on by**: `generator/updater`, `generator/pipeline`, `cmd/update`\n\n```go\ntype ChangedFile struct {\n    Status string // \"M\", \"A\", \"D\", \"R\"\n    Path   string\n}\n```\n\n\u003e Source: `internal/git/git.go#L47-L51`\n\n---\n\n### Middleware Layer\n\nMiddleware layer modules depend on the Foundation layer but **do not depend on each other**.\n\n#### `internal/claude`\n\n**Responsibility**: Wraps Claude CLI subprocess invocation (`Runner`), parses JSON output (`Parser`), and defines data types (`Types`).\n\n- **Internal dependencies**: `internal/config` (reads `ClaudeConfig`)\n- **External dependencies**: Standard library (`os/exec`, `encoding/json`, `regexp`)\n\n```go\ntype Runner struct {\n    config *config.ClaudeConfig\n    logger *slog.Logger\n}\n```\n\n\u003e Source: `internal/claude/runner.go#L16-L19`\n\nThe `claude` package contains three files, each with a clear responsibility:\n\n| File | Responsibility |\n|------|----------------|\n| `runner.go` | Executes the `claude` CLI subprocess with retry support |\n| `parser.go` | Parses JSON responses, extracts `\u003cdocument\u003e` tags, extracts JSON blocks |\n| `types.go` | Defines `RunOptions`, `RunResult`, `CLIResponse` |\n\n#### `internal/scanner`\n\n**Responsibility**: Scans the project directory, filters files according to `Config.Targets`, builds the `FileNode` tree structure, and reads README and entry point files.\n\n- **Internal dependencies**: `internal/config` (accesses `Targets.Include` / `Targets.Exclude`)\n- **External dependencies**: `github.com/bmatcuk/doublestar/v4`\n\n```go\ntype ScanResult struct {\n    RootDir            string\n    Tree               *FileNode\n    FileList           []string\n    TotalFiles         int\n    TotalDirs          int\n    ReadmeContent      string\n    EntryPointContents map[string]string\n}\n```\n\n\u003e Source: `internal/scanner/filetree.go#L18-L27`\n\n#### `internal/output`\n\n**Responsibility**: Writes documentation to disk (`Writer`), fixes relative path links (`LinkFixer`), generates navigation pages (`navigation.go`), and provides a static browser (`viewer.go`).\n\n- **Internal dependencies**: `internal/catalog` (accesses `FlatItem`, `Catalog`)\n- **External dependencies**: Standard library (`os`, `path/filepath`, `regexp`)\n\n```go\ntype Writer struct {\n    BaseDir string // absolute path to .doc-build/\n}\n\ntype LinkFixer struct {\n    allItems  []catalog.FlatItem\n    dirPaths  map[string]bool\n    pathIndex map[string]string\n}\n```\n\n\u003e Source: `internal/output/writer.go#L26-L28`, `internal/output/linkfixer.go#L12-L16`\n\n---\n\n### Orchestration Layer\n\n`internal/generator` is the central orchestration layer of the entire system, responsible for integrating all Middleware and Foundation modules into a complete workflow.\n\n#### `Generator` Struct and Dependency Injection\n\n```go\ntype Generator struct {\n    Config  *config.Config\n    Runner  *claude.Runner\n    Engine  *prompt.Engine\n    Writer  *output.Writer\n    Logger  *slog.Logger\n    RootDir string\n\n    TotalCost   float64\n    TotalPages  int\n    FailedPages int\n}\n```\n\n\u003e Source: `internal/generator/pipeline.go#L19-L31`\n\n`NewGenerator` initializes all dependencies at construction time:\n\n```go\nfunc NewGenerator(cfg *config.Config, rootDir string, logger *slog.Logger) (*Generator, error) {\n    templateLang := cfg.Output.GetEffectiveTemplateLang()\n    engine, err := prompt.NewEngine(templateLang)\n    // ...\n    runner := claude.NewRunner(\u0026cfg.Claude, logger)\n    writer := output.NewWriter(absOutDir)\n    return \u0026Generator{\n        Config:  cfg,\n        Runner:  runner,\n        Engine:  engine,\n        Writer:  writer,\n        Logger:  logger,\n        RootDir: rootDir,\n    }, nil\n}\n```\n\n\u003e Source: `internal/generator/pipeline.go#L34-L58`\n\n#### Dependency Scope of Each Generator Sub-file\n\n```mermaid\nflowchart LR\n    subgraph generator[\"internal/generator/\"]\n        pipeline[\"pipeline.go\"]\n        catalog_p[\"catalog_phase.go\"]\n        content_p[\"content_phase.go\"]\n        index_p[\"index_phase.go\"]\n        translate_p[\"translate_phase.go\"]\n        updater[\"updater.go\"]\n    end\n\n    catalog_p --\u003e |\"catalog, claude\u003cbr/\u003econfig, prompt, scanner\"| deps1[\"Foundation + Middleware\"]\n    content_p --\u003e |\"catalog, claude\u003cbr/\u003econfig, output, prompt, scanner\"| deps1\n    index_p --\u003e |\"catalog, output\"| deps2[\"Lightweight deps\"]\n    translate_p --\u003e |\"catalog, claude\u003cbr/\u003econfig, output, prompt\"| deps1\n    updater --\u003e |\"catalog, claude\u003cbr/\u003egit, output, prompt, scanner\"| deps1\n    pipeline --\u003e |\"integrates all sub-modules\"| deps1\n```\n\n---\n\n### CLI Layer (Entry Points Layer)\n\nEach command in the `cmd` package depends directly on the Orchestration layer and, where needed, calls select Middleware modules directly (e.g., `claude.CheckAvailable()`).\n\n```mermaid\nflowchart LR\n    cmd_init[\"cmd/init.go\"] --\u003e config[\"internal/config\"]\n    cmd_gen[\"cmd/generate.go\"] --\u003e generator[\"internal/generator\"]\n    cmd_gen --\u003e claude[\"internal/claude\"]\n    cmd_gen --\u003e config\n    cmd_update[\"cmd/update.go\"] --\u003e generator\n    cmd_update --\u003e claude\n    cmd_update --\u003e config\n    cmd_update --\u003e git[\"internal/git\"]\n    cmd_update --\u003e scanner[\"internal/scanner\"]\n    cmd_translate[\"cmd/translate.go\"] --\u003e generator\n    cmd_translate --\u003e claude\n    cmd_translate --\u003e config\n```\n\n\u003e Source: `cmd/generate.go#L1-L14`, `cmd/update.go#L1-L18`, `cmd/translate.go#L1-L17`\n\n---\n\n## Dependency Matrix\n\nThe table below lists the **internal** modules each module directly depends on (✓ indicates a direct dependency):\n\n| Module | config | catalog | prompt | git | scanner | claude | output | generator |\n|--------|:------:|:-------:|:------:|:---:|:-------:|:------:|:------:|:---------:|\n| `config` | — | | | | | | | |\n| `catalog` | | — | | | | | | |\n| `prompt` | | | — | | | | | |\n| `git` | | | | — | | | | |\n| `scanner` | ✓ | | | | — | | | |\n| `claude` | ✓ | | | | | — | | |\n| `output` | | ✓ | | | | | — | |\n| `generator` | ✓ | ✓ | ✓ | ✓ | ✓ | ✓ | ✓ | — |\n| `cmd` | ✓ | | | ✓ | ✓ | ✓ | | ✓ |\n\n---\n\n## Core Flow: Dependency Initialization Order\n\n```mermaid\nsequenceDiagram\n    participant Main as main.go\n    participant CMD as cmd/generate.go\n    participant CFG as config.Load()\n    participant Gen as generator.NewGenerator()\n    participant Engine as prompt.NewEngine()\n    participant Runner as claude.NewRunner()\n    participant Writer as output.NewWriter()\n\n    Main-\u003e\u003eCMD: Execute()\n    CMD-\u003e\u003eCFG: config.Load(cfgFile)\n    CFG--\u003e\u003eCMD: *Config\n    CMD-\u003e\u003eGen: NewGenerator(cfg, rootDir, logger)\n    Gen-\u003e\u003eEngine: prompt.NewEngine(templateLang)\n    Engine--\u003e\u003eGen: *Engine\n    Gen-\u003e\u003eRunner: claude.NewRunner(\u0026cfg.Claude, logger)\n    Runner--\u003e\u003eGen: *Runner\n    Gen-\u003e\u003eWriter: output.NewWriter(outDir)\n    Writer--\u003e\u003eGen: *Writer\n    Gen--\u003e\u003eCMD: *Generator\n    CMD-\u003e\u003eGen: gen.Generate(ctx, opts)\n```\n\n---\n\n## External Dependencies Summary\n\nselfmd uses the following third-party packages:\n\n| Package | Version | Used By | Purpose |\n|---------|---------|---------|---------|\n| `github.com/spf13/cobra` | — | `cmd/` | CLI command framework |\n| `gopkg.in/yaml.v3` | — | `internal/config` | YAML configuration file parsing |\n| `github.com/bmatcuk/doublestar/v4` | — | `internal/scanner`, `internal/git` | Glob pattern matching (`**` double-star) |\n| `golang.org/x/sync/errgroup` | — | `internal/generator` | Parallel task error group management |\n\n---\n\n## Related Links\n\n- [Overall Flow and Four-Phase Pipeline](../pipeline/index.md) — How modules collaborate across the four phases\n- [Documentation Generation Pipeline](../../core-modules/generator/index.md) — Detailed description of the Generator orchestration layer\n- [Project Scanner](../../core-modules/scanner/index.md) — `internal/scanner` module documentation\n- [Claude CLI Runner](../../core-modules/claude-runner/index.md) — `internal/claude` module documentation\n- [Prompt Template Engine](../../core-modules/prompt-engine/index.md) — `internal/prompt` module documentation\n- [Output Writer and Link Fixer](../../core-modules/output-writer/index.md) — `internal/output` module documentation\n- [Configuration Reference](../../configuration/index.md) — Overview of the `selfmd.yaml` configuration structure\n\n---\n\n## Reference Files\n\n| File Path | Description |\n|-----------|-------------|\n| `cmd/root.go` | CLI root command; global flag definitions |\n| `cmd/generate.go` | `selfmd generate` command implementation; depends on `generator`, `claude`, `config` |\n| `cmd/init.go` | `selfmd init` command implementation; depends on `config` |\n| `cmd/update.go` | `selfmd update` command implementation; depends on `generator`, `git`, `scanner`, `claude`, `config` |\n| `cmd/translate.go` | `selfmd translate` command implementation; depends on `generator`, `claude`, `config` |\n| `internal/config/config.go` | `Config` struct definition, defaults, loading and validation logic |\n| `internal/catalog/catalog.go` | `Catalog`, `CatalogItem`, `FlatItem` data models and operation methods |\n| `internal/prompt/engine.go` | `Engine` template engine; `CatalogPromptData`, `ContentPromptData`, and other data types |\n| `internal/git/git.go` | Git CLI wrapper: retrieving commits, diffs, and filtering files |\n| `internal/scanner/scanner.go` | Directory traversal and glob filtering logic |\n| `internal/scanner/filetree.go` | `ScanResult`, `FileNode` definitions and tree rendering |\n| `internal/claude/runner.go` | `Runner` struct; executes Claude CLI subprocess with retry logic |\n| `internal/claude/parser.go` | JSON parsing, `\u003cdocument\u003e` tag extraction, template cleanup |\n| `internal/claude/types.go` | `RunOptions`, `RunResult`, `CLIResponse` type definitions |\n| `internal/output/writer.go` | `Writer` writes documentation pages, catalog JSON, and commit records |\n| `internal/output/linkfixer.go` | `LinkFixer` repairs Markdown relative path links |\n| `internal/output/navigation.go` | Generates `index.md`, `_sidebar.md`, and category index pages |\n| `internal/generator/pipeline.go` | `Generator` struct definition, `NewGenerator`, `Generate` main flow |\n| `internal/generator/catalog_phase.go` | Phase 2: calls Claude to generate the catalog |\n| `internal/generator/content_phase.go` | Phase 3: generates content pages in parallel |\n| `internal/generator/index_phase.go` | Phase 4: generates indexes and navigation |\n| `internal/generator/translate_phase.go` | Translation flow: translates all pages to the target language in parallel |\n| `internal/generator/updater.go` | Incremental update flow: compares git diff and selectively regenerates pages |","en-US/architecture/pipeline/index.md":"# Overall Flow and Four-Phase Pipeline\n\nThe `selfmd generate` command runs four ordered phases through the `Generator` orchestrator, transforming source code into a complete Markdown documentation site. Each phase has a clear responsibility and feeds into the next, ultimately producing a browsable static documentation output.\n\n## Overview\n\n`Generator` (located in `internal/generator/pipeline.go`) is the central orchestrator of the entire system. It holds references to all subsystems — scanner, Claude runner, prompt engine, output writer — and drives the following four phases in sequence:\n\n| Phase | Number | Responsibility |\n|-------|--------|---------------|\n| Scan | 1/4 | Traverse the project directory and build the file tree |\n| Catalog | 2/4 | Call Claude to plan the documentation structure |\n| Content | 3/4 | Generate each documentation page in parallel |\n| Index \u0026 Navigation | 4/4 | Generate the home page, sidebar, and category indexes |\n\nAfter the four phases complete, the system performs additional post-processing steps: static viewer generation and Git commit history archiving.\n\n## Architecture\n\n```mermaid\nflowchart TD\n    CLI[\"cmd/generate.go\\nCLI Entry Point\"] --\u003e Gen\n\n    subgraph Gen[\"Generator（pipeline.go）\"]\n        direction TB\n        GS[\"GenerateOptions\\n{Clean, DryRun, Concurrency}\"]\n    end\n\n    Gen --\u003e|\"Phase 1\"| Scanner[\"scanner.Scan()\\nProject Scan\"]\n    Scanner --\u003e|\"ScanResult\"| CatalogPhase\n\n    Gen --\u003e|\"Phase 2\"| CatalogPhase[\"GenerateCatalog()\\nCatalog Generation\"]\n    CatalogPhase --\u003e|\"Prompt\"| Runner[\"claude.Runner\\nRunWithRetry()\"]\n    Runner --\u003e|\"JSON\"| CatalogParse[\"catalog.Parse()\\nCatalog Parsing\"]\n    CatalogParse --\u003e|\"Catalog\"| ContentPhase\n\n    Gen --\u003e|\"Phase 3\"| ContentPhase[\"GenerateContent()\\nContent Pages (Parallel)\"]\n    ContentPhase --\u003e|\"Prompt × N\"| Runner\n    Runner --\u003e|\"Markdown\"| LinkFixer[\"output.LinkFixer\\nLink Fixing\"]\n    LinkFixer --\u003e|\"WritePage()\"| Writer[\"output.Writer\\nOutput Writing\"]\n\n    Gen --\u003e|\"Phase 4\"| IndexPhase[\"GenerateIndex()\\nIndex \u0026 Navigation\"]\n    IndexPhase --\u003e|\"index.md\\n_sidebar.md\"| Writer\n\n    Writer --\u003e|\"Post\"| ViewerGen[\"Writer.WriteViewer()\\nStatic Viewer\"]\n    Writer --\u003e|\"Post\"| GitSave[\"Writer.SaveLastCommit()\\nGit Record\"]\n```\n\n## Generator Structure\n\nThe `Generator` struct centrally manages the lifecycle of all subsystems and accumulates runtime statistics:\n\n```go\ntype Generator struct {\n    Config  *config.Config\n    Runner  *claude.Runner\n    Engine  *prompt.Engine\n    Writer  *output.Writer\n    Logger  *slog.Logger\n    RootDir string // Target project root directory\n\n    // Statistics\n    TotalCost   float64\n    TotalPages  int\n    FailedPages int\n}\n```\n\n\u003e Source: internal/generator/pipeline.go#L19-L31\n\n`NewGenerator` determines the prompt template language based on configuration, and initializes the Claude Runner and Writer:\n\n```go\nfunc NewGenerator(cfg *config.Config, rootDir string, logger *slog.Logger) (*Generator, error) {\n    templateLang := cfg.Output.GetEffectiveTemplateLang()\n    engine, err := prompt.NewEngine(templateLang)\n    if err != nil {\n        return nil, err\n    }\n\n    runner := claude.NewRunner(\u0026cfg.Claude, logger)\n\n    absOutDir := cfg.Output.Dir\n    if absOutDir == \"\" {\n        absOutDir = \".doc-build\"\n    }\n\n    writer := output.NewWriter(absOutDir)\n    // ...\n}\n```\n\n\u003e Source: internal/generator/pipeline.go#L34-L58\n\n## Four Phases in Detail\n\n### Setup Step (Phase 0)\n\nBefore the four main phases, the system prepares the output directory: if the `--clean` flag is set, the output directory is cleared and recreated; otherwise, the system simply ensures the directory exists.\n\n```go\n// Phase 0: Setup\nclean := opts.Clean || g.Config.Output.CleanBeforeGenerate\nif clean {\n    fmt.Println(\"[0/4] Cleaning output directory...\")\n    if !opts.DryRun {\n        if err := g.Writer.Clean(); err != nil {\n            return err\n        }\n    }\n} else {\n    if err := g.Writer.EnsureDir(); err != nil {\n        return err\n    }\n}\n```\n\n\u003e Source: internal/generator/pipeline.go#L71-L84\n\n---\n\n### Phase 1: Scan\n\nCalls `scanner.Scan()` to traverse the entire project directory. The scanner filters files according to include/exclude glob rules from the configuration file, and reads the content of README and entry point files:\n\n```go\n// Phase 1: Scan\nfmt.Println(\"[1/4] Scanning project structure...\")\nscan, err := scanner.Scan(g.Config, g.RootDir)\nif err != nil {\n    return fmt.Errorf(\"failed to scan project: %w\", err)\n}\nfmt.Printf(\"      Found %d files across %d directories\\n\", scan.TotalFiles, scan.TotalDirs)\n```\n\n\u003e Source: internal/generator/pipeline.go#L86-L93\n\nThe `ScanResult` contains:\n- `Tree`: File tree structure (used as `FileTree` in prompts)\n- `FileList`: List of all files matching the rules\n- `ReadmeContent`: Project README content\n- `EntryPointContents`: Content of configured entry point files\n\nIf `--dry-run` mode is enabled, the system prints the file tree and exits after this phase without calling Claude.\n\n---\n\n### Phase 2: Catalog Generation\n\n`GenerateCatalog()` constructs a prompt with the file tree, README, entry points, and other information, then sends it to Claude to design the overall documentation structure:\n\n```go\nfunc (g *Generator) GenerateCatalog(ctx context.Context, scan *scanner.ScanResult) (*catalog.Catalog, error) {\n    langName := config.GetLangNativeName(g.Config.Output.Language)\n    data := prompt.CatalogPromptData{\n        RepositoryName:       g.Config.Project.Name,\n        ProjectType:          g.Config.Project.Type,\n        Language:             g.Config.Output.Language,\n        LanguageName:         langName,\n        KeyFiles:             scan.KeyFiles(),\n        EntryPoints:          scan.EntryPointsFormatted(),\n        FileTree:             scanner.RenderTree(scan.Tree, 4),\n        ReadmeContent:        scan.ReadmeContent,\n    }\n\n    rendered, err := g.Engine.RenderCatalog(data)\n    // ...\n    result, err := g.Runner.RunWithRetry(ctx, claude.RunOptions{\n        Prompt:  rendered,\n        WorkDir: g.RootDir,\n    })\n    // ...\n    jsonStr, err := claude.ExtractJSONBlock(result.Content)\n    return catalog.Parse(jsonStr)\n}\n```\n\n\u003e Source: internal/generator/catalog_phase.go#L15-L61\n\n**Catalog caching**: When not doing a full regeneration (`--no-clean` mode), the system tries to read `.doc-build/_catalog.json`. If parsing succeeds, the existing catalog is reused and the Claude call is skipped to save cost:\n\n```go\nif !clean {\n    catJSON, readErr := g.Writer.ReadCatalogJSON()\n    if readErr == nil {\n        cat, err = catalog.Parse(catJSON)\n    }\n    if cat != nil {\n        // Loaded existing catalog, skipping Claude call\n    }\n}\n```\n\n\u003e Source: internal/generator/pipeline.go#L102-L113\n\n---\n\n### Phase 3: Content Page Generation\n\n`GenerateContent()` issues parallel Claude calls for all leaf-node pages in the catalog. Concurrency is controlled by the `claude.max_concurrent` configuration setting or the `--concurrency` flag, enforced via a semaphore channel:\n\n```go\nfunc (g *Generator) GenerateContent(ctx context.Context, scan *scanner.ScanResult, cat *catalog.Catalog, concurrency int, skipExisting bool) error {\n    items := cat.Flatten()\n    total := len(items)\n\n    // Build link table and link fixer, shared across all pages\n    catalogTable := cat.BuildLinkTable()\n    linkFixer := output.NewLinkFixer(cat)\n\n    var done atomic.Int32\n    var failed atomic.Int32\n    var skipped atomic.Int32\n\n    eg, ctx := errgroup.WithContext(ctx)\n    sem := make(chan struct{}, concurrency)\n\n    for _, item := range items {\n        item := item\n        eg.Go(func() error {\n            if skipExisting \u0026\u0026 g.Writer.PageExists(item) {\n                skipped.Add(1)\n                // Skip existing pages\n                return nil\n            }\n            sem \u003c- struct{}{}\n            defer func() { \u003c-sem }()\n            // Call generateSinglePage()\n            err := g.generateSinglePage(ctx, scan, item, catalogTable, linkFixer, \"\")\n            // ...\n        })\n    }\n    return eg.Wait()\n}\n```\n\n\u003e Source: internal/generator/content_phase.go#L21-L87\n\nThe per-page generation flow (`generateSinglePage`) includes:\n1. Build `ContentPromptData` (with catalog path, page title, link table)\n2. Call `Runner.RunWithRetry()` to get the Claude response\n3. Extract Markdown content from `\u003cdocument\u003e` tags\n4. Validate content (must begin with `#`)\n5. Call `linkFixer.FixLinks()` to fix relative links\n6. Call `Writer.WritePage()` to write the file\n\nIf generation fails, the system writes a placeholder page but does not abort generation of other pages.\n\n---\n\n### Phase 4: Index \u0026 Navigation Generation\n\n`GenerateIndex()` does not call Claude — it generates three navigation files directly from the catalog structure:\n\n```go\nfunc (g *Generator) GenerateIndex(_ context.Context, cat *catalog.Catalog) error {\n    lang := g.Config.Output.Language\n\n    // Generate main home page\n    indexContent := output.GenerateIndex(g.Config.Project.Name, g.Config.Project.Description, cat, lang)\n    if err := g.Writer.WriteFile(\"index.md\", indexContent); err != nil {\n        return err\n    }\n\n    // Generate sidebar\n    sidebarContent := output.GenerateSidebar(g.Config.Project.Name, cat, lang)\n    if err := g.Writer.WriteFile(\"_sidebar.md\", sidebarContent); err != nil {\n        return err\n    }\n\n    // Generate category indexes for nodes with children\n    items := cat.Flatten()\n    for _, item := range items {\n        if !item.HasChildren {\n            continue\n        }\n        // ...generate category home page\n    }\n    return nil\n}\n```\n\n\u003e Source: internal/generator/index_phase.go#L11-L55\n\nGenerated files:\n- `index.md`: Documentation site home page\n- `_sidebar.md`: Sidebar navigation\n- `{category}/index.md`: Category home page for each node with child pages\n\n---\n\n### Post-Processing Steps\n\nAfter the four phases complete, `Generate()` performs two additional post-processing operations:\n\n```go\n// Generate static viewer (HTML/JS/CSS + _data.js bundle)\ndocMeta := g.buildDocMeta()\nif err := g.Writer.WriteViewer(g.Config.Project.Name, docMeta); err != nil {\n    // Failure does not abort the flow\n}\n\n// If this is a Git repository, save the current commit hash for incremental updates\nif git.IsGitRepo(g.RootDir) {\n    if commit, err := git.GetCurrentCommit(g.RootDir); err == nil {\n        g.Writer.SaveLastCommit(commit)\n    }\n}\n```\n\n\u003e Source: internal/generator/pipeline.go#L146-L164\n\n## Core Flows\n\n### Full Generation Flow (Generate)\n\n```mermaid\nsequenceDiagram\n    participant CLI as cmd/generate.go\n    participant Gen as Generator\n    participant Scan as scanner\n    participant Claude as claude.Runner\n    participant Writer as output.Writer\n\n    CLI-\u003e\u003eGen: Generate(ctx, opts)\n    Gen-\u003e\u003eWriter: Clean() or EnsureDir()\n\n    Gen-\u003e\u003eScan: Scan(config, rootDir)\n    Scan--\u003e\u003eGen: ScanResult\n\n    alt Catalog cache exists\n        Gen-\u003e\u003eWriter: ReadCatalogJSON()\n        Writer--\u003e\u003eGen: Catalog (cached)\n    else Catalog must be generated\n        Gen-\u003e\u003eClaude: RunWithRetry(catalogPrompt)\n        Claude--\u003e\u003eGen: JSON catalog\n        Gen-\u003e\u003eWriter: WriteCatalogJSON()\n    end\n\n    par Generate content pages in parallel\n        Gen-\u003e\u003eClaude: RunWithRetry(contentPrompt[1])\n        Gen-\u003e\u003eClaude: RunWithRetry(contentPrompt[2])\n        Gen-\u003e\u003eClaude: RunWithRetry(contentPrompt[N])\n    end\n    Claude--\u003e\u003eGen: Markdown × N\n    Gen-\u003e\u003eWriter: WritePage() × N\n\n    Gen-\u003e\u003eWriter: WriteFile(index.md)\n    Gen-\u003e\u003eWriter: WriteFile(_sidebar.md)\n    Gen-\u003e\u003eWriter: WriteViewer()\n    Gen-\u003e\u003eWriter: SaveLastCommit()\n```\n\n### Incremental Update Flow (Update)\n\n`Update()` (located in `updater.go`) uses a different strategy, used by the `selfmd update` command:\n\n```mermaid\nflowchart TD\n    Start[\"Update(ctx, scan, prevCommit, curCommit, changedFiles)\"] --\u003e Parse[\"git.ParseChangedFiles()\\nParse Change List\"]\n    Parse --\u003e Match[\"matchChangedFilesToDocs()\\nMatch to Documentation\"]\n\n    Match --\u003e|\"Matched\"| Determine[\"Claude determines\\nwhich pages need updating\"]\n    Match --\u003e|\"Unmatched\"| NewPage[\"Claude determines\\nwhether to add new pages\"]\n\n    Determine --\u003e|\"List of pages to update\"| Regen\n    NewPage --\u003e|\"List of new pages\"| AddCatalog[\"addItemToCatalog()\\nUpdate Catalog\"]\n    AddCatalog --\u003e Regen[\"generateSinglePage() × N\\nRegenerate Pages\"]\n\n    Regen --\u003e IndexUpdate[\"GenerateIndex()\\nUpdate Index (if new pages added)\"]\n    IndexUpdate --\u003e SaveCommit[\"Writer.SaveLastCommit()\\nRecord Commit\"]\n```\n\n## Usage Example\n\n`GenerateOptions` controls the pipeline execution mode:\n\n```go\nopts := generator.GenerateOptions{\n    Clean:       clean,       // Whether to clean the output directory\n    DryRun:      dryRun,      // Scan only, do not call Claude\n    Concurrency: concurrencyNum, // Concurrency level (0 = use config value)\n}\n\nreturn gen.Generate(ctx, opts)\n```\n\n\u003e Source: cmd/generate.go#L89-L95\n\nConcurrency priority order: CLI `--concurrency` flag \u003e `claude.max_concurrent` setting in `selfmd.yaml`.\n\n```go\n// Phase 3: Generate Content\nconcurrency := g.Config.Claude.MaxConcurrent\nif opts.Concurrency \u003e 0 {\n    concurrency = opts.Concurrency\n}\nfmt.Printf(\"[3/4] Generating content pages (concurrency: %d)...\\n\", concurrency)\n```\n\n\u003e Source: internal/generator/pipeline.go#L130-L134\n\n## Cost Tracking\n\nThe cost of each Claude call is accumulated in `Generator.TotalCost` and printed as a summary in the terminal after execution:\n\n```\n========================================\nDocumentation generation complete!\n  Output directory: .doc-build\n  Pages: 42 succeeded\n  Total time: 3m20s\n  Total cost: $0.1234 USD\n========================================\n```\n\n\u003e Source: internal/generator/pipeline.go#L166-L179\n\n## Related Links\n\n- [System Architecture](../index.md)\n- [Module Dependencies](../module-dependencies/index.md)\n- [Documentation Generation Pipeline (Core Module)](../../core-modules/generator/index.md)\n- [Catalog Generation Phase](../../core-modules/generator/catalog-phase/index.md)\n- [Content Page Generation Phase](../../core-modules/generator/content-phase/index.md)\n- [Index \u0026 Navigation Generation Phase](../../core-modules/generator/index-phase/index.md)\n- [Translation Phase](../../core-modules/generator/translate-phase/index.md)\n- [Incremental Update](../../core-modules/incremental-update/index.md)\n- [selfmd generate Command](../../cli/cmd-generate/index.md)\n\n## Reference Files\n\n| File Path | Description |\n|-----------|-------------|\n| `internal/generator/pipeline.go` | `Generator` struct definition, `Generate()` main flow orchestrator |\n| `internal/generator/catalog_phase.go` | Phase 2: Catalog generation logic, Claude prompt construction |\n| `internal/generator/content_phase.go` | Phase 3: Parallel content page generation, `generateSinglePage()` |\n| `internal/generator/index_phase.go` | Phase 4: Index and sidebar navigation generation |\n| `internal/generator/translate_phase.go` | Translation pipeline (`Translate()`) and multi-language support |\n| `internal/generator/updater.go` | Incremental update flow (`Update()`), Git change diff logic |\n| `internal/scanner/scanner.go` | Project scanner, `Scan()` function |\n| `internal/catalog/catalog.go` | `Catalog`, `FlatItem` struct definitions and operations |\n| `internal/claude/runner.go` | Claude CLI runner, `RunWithRetry()` |\n| `internal/output/writer.go` | Output writer, file management, catalog JSON persistence |\n| `internal/git/git.go` | Git integration utilities, changed file parsing |\n| `cmd/generate.go` | `selfmd generate` CLI entry point |","en-US/cli/cmd-generate/index.md":"# selfmd generate\n\nExecutes the complete four-phase documentation generation pipeline, scanning project source code and automatically generating structured, Wiki-style technical documentation via the Claude CLI.\n\n## Overview\n\n`selfmd generate` is selfmd's core command, responsible for generating complete project documentation from scratch (or incrementally). When executed, the command performs the following steps in order:\n\n1. Validates that the Claude CLI environment is ready\n2. Loads the `selfmd.yaml` configuration file\n3. Scans the project directory structure and source code\n4. Calls Claude AI to generate the documentation catalog\n5. Generates content pages for each catalog item in parallel\n6. Generates the navigation index and static documentation browser\n\n**Incremental generation**: If valid pages already exist in the output directory and the `--clean` flag is not used, the system automatically skips those pages and only generates missing or failed ones, significantly reducing API costs and execution time.\n\n## Usage\n\n```sh\nselfmd generate [flags]\n```\n\n\u003e Source: `cmd/generate.go#L23-L32`\n\n## Flags\n\n| Flag | Type | Default | Description |\n|------|------|---------|-------------|\n| `--clean` | bool | `false` | Forces the output directory to be cleared before regenerating all pages |\n| `--no-clean` | bool | `false` | Overrides the config's `clean_before_generate` setting, preserving existing pages |\n| `--dry-run` | bool | `false` | Scans and displays the file tree only, without calling Claude or writing any files |\n| `--concurrency` | int | `0` | Overrides the config's `claude.max_concurrent` concurrency setting |\n| `-c, --config` | string | `selfmd.yaml` | Path to the configuration file (global flag, inherited from rootCmd) |\n| `-v, --verbose` | bool | `false` | Shows Debug-level detailed logs (global flag) |\n| `-q, --quiet` | bool | `false` | Shows error messages only (global flag) |\n\n### Priority Order for `--clean` and `--no-clean`\n\nThe final clean behavior is determined by the following rules (highest to lowest priority):\n\n```\n--no-clean flag → clean = false (force preserve)\n--clean flag    → clean = true (force clean)\nconfig setting  → value of output.clean_before_generate\n```\n\n\u003e Source: `cmd/generate.go#L80-L87`\n\n## Architecture\n\n```mermaid\nflowchart TD\n    A[\"generateCmd\\n(cobra.Command)\"] --\u003e B[\"runGenerate()\"]\n    B --\u003e C[\"claude.CheckAvailable()\"]\n    B --\u003e D[\"config.Load()\"]\n    B --\u003e E[\"generator.NewGenerator()\"]\n    E --\u003e F[\"prompt.NewEngine()\"]\n    E --\u003e G[\"claude.NewRunner()\"]\n    E --\u003e H[\"output.NewWriter()\"]\n    B --\u003e I[\"gen.Generate(ctx, opts)\"]\n\n    I --\u003e P0[\"Phase 0\\nSetup / Clean\"]\n    I --\u003e P1[\"Phase 1\\nscanner.Scan()\"]\n    I --\u003e P2[\"Phase 2\\nGenerateCatalog()\"]\n    I --\u003e P3[\"Phase 3\\nGenerateContent()\"]\n    I --\u003e P4[\"Phase 4\\nGenerateIndex()\"]\n    I --\u003e P5[\"WriteViewer()\"]\n    I --\u003e P6[\"SaveLastCommit()\"]\n\n    P3 --\u003e W[\"errgroup\\nParallel Workers\"]\n    W --\u003e S[\"semaphore\\n(max_concurrent)\"]\n    S --\u003e Claude[\"claude.Runner\\n.RunWithRetry()\"]\n```\n\n## Four-Phase Generation Pipeline\n\n### Phase 0: Initialization and Setup\n\nDetermines how to handle the output directory based on the `clean` option:\n\n```go\nif clean {\n    fmt.Println(\"[0/4] Cleaning output directory...\")\n    if !opts.DryRun {\n        if err := g.Writer.Clean(); err != nil {\n            return err\n        }\n    }\n} else {\n    if err := g.Writer.EnsureDir(); err != nil {\n        return err\n    }\n}\n```\n\n\u003e Source: `internal/generator/pipeline.go#L72-L84`\n\n`Writer.Clean()` calls `os.RemoveAll()` to delete the entire output directory and recreate it, while `EnsureDir()` uses `os.MkdirAll()` to ensure the directory exists.\n\n---\n\n### Phase 1: Scan Project Structure\n\n```go\nscan, err := scanner.Scan(g.Config, g.RootDir)\n```\n\n\u003e Source: `internal/generator/pipeline.go#L88-L92`\n\nThe scanner recursively traverses the project directory, filtering files based on the `targets.include` and `targets.exclude` glob patterns defined in the configuration file, while also reading `README.md` and the configured entry point contents.\n\n**Dry Run behavior**: If `--dry-run` is specified, after scanning the file tree is displayed (up to 3 levels deep) and execution stops — no subsequent Claude calls are made:\n\n```go\nif opts.DryRun {\n    fmt.Println(\"\\n[Dry Run] File tree:\")\n    fmt.Println(scanner.RenderTree(scan.Tree, 3))\n    fmt.Println(\"[Dry Run] No Claude calls will be made.\")\n    return nil\n}\n```\n\n\u003e Source: `internal/generator/pipeline.go#L94-L99`\n\n---\n\n### Phase 2: Generate Documentation Catalog\n\nThe catalog is the skeleton of the documentation structure, defining the titles, paths, and hierarchical relationships of all pages.\n\n```go\n// First attempt to reuse an existing catalog (non-clean mode)\nif !clean {\n    catJSON, readErr := g.Writer.ReadCatalogJSON()\n    if readErr == nil {\n        cat, err = catalog.Parse(catJSON)\n    }\n    // ...\n}\n// If no existing catalog, call Claude to generate one\nif cat == nil {\n    cat, err = g.GenerateCatalog(ctx, scan)\n    // Save as _catalog.json for future reuse\n    g.Writer.WriteCatalogJSON(cat)\n}\n```\n\n\u003e Source: `internal/generator/pipeline.go#L102-L127`\n\n`GenerateCatalog()` assembles the scan results into a prompt, calls the Claude CLI, and extracts the JSON-formatted catalog structure from the response:\n\n```go\nresult, err := g.Runner.RunWithRetry(ctx, claude.RunOptions{\n    Prompt:  rendered,\n    WorkDir: g.RootDir,\n})\n// ...\njsonStr, err := claude.ExtractJSONBlock(result.Content)\ncat, err := catalog.Parse(jsonStr)\n```\n\n\u003e Source: `internal/generator/catalog_phase.go#L37-L58`\n\n---\n\n### Phase 3: Generate Content Pages in Parallel\n\nThis is the most time-consuming phase. The system calls Claude in parallel for each catalog item to generate complete Markdown documentation:\n\n```go\neg, ctx := errgroup.WithContext(ctx)\nsem := make(chan struct{}, concurrency)\n\nfor _, item := range items {\n    item := item\n    eg.Go(func() error {\n        // Skip existing pages (non-clean mode)\n        if skipExisting \u0026\u0026 g.Writer.PageExists(item) {\n            skipped.Add(1)\n            return nil\n        }\n        sem \u003c- struct{}{}\n        defer func() { \u003c-sem }()\n        // ...call Claude to generate page...\n    })\n}\n```\n\n\u003e Source: `internal/generator/content_phase.go#L36-L73`\n\n**Concurrency control**: Uses a channel as a semaphore to limit the number of simultaneous Claude calls. The default value comes from the config's `claude.max_concurrent` (default `3`), and can be overridden with the `--concurrency` flag.\n\n**Fault tolerance**: A single page generation failure does not abort the entire process. On failure, a placeholder page is written prompting the user to re-run:\n\n```go\nfunc (g *Generator) writePlaceholder(item catalog.FlatItem, genErr error) {\n    content := fmt.Sprintf(\"# %s\\n\\n\u003e This page failed to generate. Please re-run `selfmd generate`.\\n\u003e\\n\u003e Error: %v\\n\", item.Title, genErr)\n    g.Writer.WritePage(item, content)\n}\n```\n\n\u003e Source: `internal/generator/content_phase.go#L159-L164`\n\n**Format validation and retry**: Each page is attempted up to 2 times. If the Claude response is missing a `\u003cdocument\u003e` tag or is not valid Markdown starting with `#`, it retries automatically:\n\n```go\ncontent, extractErr := claude.ExtractDocumentTag(result.Content)\n// ...\nif content == \"\" || !strings.HasPrefix(content, \"#\") {\n    // retry\n}\n```\n\n\u003e Source: `internal/generator/content_phase.go#L126-L146`\n\n---\n\n### Phase 4: Generate Navigation and Index\n\n```go\nfunc (g *Generator) GenerateIndex(_ context.Context, cat *catalog.Catalog) error {\n    // Generate index.md (documentation home page)\n    output.GenerateIndex(...)\n    g.Writer.WriteFile(\"index.md\", indexContent)\n\n    // Generate _sidebar.md (sidebar navigation)\n    output.GenerateSidebar(...)\n    g.Writer.WriteFile(\"_sidebar.md\", sidebarContent)\n\n    // Generate index pages for categories with children\n    for _, item := range items {\n        if item.HasChildren { ... }\n    }\n}\n```\n\n\u003e Source: `internal/generator/index_phase.go#L11-L55`\n\n---\n\n### Post-processing\n\nAfter Phase 4 completes, `Generate()` also performs:\n\n1. **Generate static browser**: Calls `Writer.WriteViewer()` to generate `index.html` and related assets, enabling documentation to be browsed directly in a web browser.\n2. **Record Git commit**: If the current directory is a Git repository, saves the current commit hash to `_last_commit` for use by `selfmd update`'s incremental update feature.\n\n```go\nif git.IsGitRepo(g.RootDir) {\n    if commit, err := git.GetCurrentCommit(g.RootDir); err == nil {\n        g.Writer.SaveLastCommit(commit)\n    }\n}\n```\n\n\u003e Source: `internal/generator/pipeline.go#L158-L164`\n\n## Core Flow\n\n```mermaid\nsequenceDiagram\n    participant CLI as \"selfmd generate\"\n    participant Gen as \"Generator\"\n    participant Scanner as \"scanner.Scan()\"\n    participant Claude as \"claude.Runner\"\n    participant Writer as \"output.Writer\"\n\n    CLI-\u003e\u003eClaude: CheckAvailable()\n    CLI-\u003e\u003eGen: NewGenerator(cfg, rootDir)\n    CLI-\u003e\u003eGen: Generate(ctx, opts)\n\n    Gen-\u003e\u003eWriter: Clean() / EnsureDir()\n    Gen-\u003e\u003eScanner: Scan(cfg, rootDir)\n    Scanner--\u003e\u003eGen: ScanResult\n\n    alt No existing catalog\n        Gen-\u003e\u003eClaude: RunWithRetry (Catalog Prompt)\n        Claude--\u003e\u003eGen: catalog JSON\n    else Existing catalog found\n        Gen-\u003e\u003eWriter: ReadCatalogJSON()\n        Writer--\u003e\u003eGen: catalog JSON\n    end\n\n    loop Parallel (max_concurrent goroutines)\n        Gen-\u003e\u003eClaude: RunWithRetry (Content Prompt)\n        Claude--\u003e\u003eGen: Markdown content\n        Gen-\u003e\u003eWriter: WritePage(item, content)\n    end\n\n    Gen-\u003e\u003eWriter: WriteFile(\"index.md\")\n    Gen-\u003e\u003eWriter: WriteFile(\"_sidebar.md\")\n    Gen-\u003e\u003eWriter: WriteViewer()\n    Gen-\u003e\u003eWriter: SaveLastCommit()\n```\n\n## Output Structure\n\nAfter successful execution, the following files are generated under the `--output.dir` directory (default `.doc-build/`):\n\n```\n.doc-build/\n├── index.html          # Static documentation browser entry point\n├── index.md            # Documentation home page (Markdown)\n├── _sidebar.md         # Sidebar navigation\n├── _catalog.json       # Catalog structure cache (used for incremental updates)\n├── _last_commit        # Git commit hash record\n├── \u003csection\u003e/\n│   └── \u003csubsection\u003e/\n│       └── index.md   # Documentation pages per section\n└── \u003clang\u003e/             # Translation language directory (if secondary languages are configured)\n    ├── index.md\n    └── ...\n```\n\n## Usage Examples\n\n### Basic Usage\n\n```sh\n# Standard generation (incremental, skips existing pages)\nselfmd generate\n\n# Force regenerate all pages\nselfmd generate --clean\n\n# Preview mode: show scan results only, no Claude calls\nselfmd generate --dry-run\n```\n\n### Adjusting Concurrency\n\n```sh\n# Increase concurrency for faster generation (watch out for Claude API rate limits)\nselfmd generate --concurrency 5\n\n# Decrease concurrency to reduce API request rate\nselfmd generate --concurrency 1\n```\n\n### Using a Custom Configuration File\n\n```sh\nselfmd generate --config ./configs/my-project.yaml\n```\n\n### Using Log Flags\n\n```sh\n# Show detailed Debug logs (including details for each Claude call)\nselfmd generate --verbose\n\n# Silent mode (errors only)\nselfmd generate --quiet\n```\n\n## Example Terminal Output\n\nOn successful execution, the terminal displays the following progress output:\n\n```\n[0/4] Cleaning output directory...\n[1/4] Scanning project structure...\n      Found 42 files across 12 directories\n[2/4] Generating documentation catalog...\n      Calling Claude to generate catalog... done (8.3s, $0.0025)\n      Catalog: 6 sections, 18 items\n[3/4] Generating content pages (concurrency: 3)...\n      [1/18] Overview... done (12.5s, $0.0041)\n      [2/18] Getting Started... done (10.2s, $0.0038)\n      ...\n[4/4] Generating navigation and index...\nGenerating documentation browser...\n      Done. Open .doc-build/index.html to browse.\n\n========================================\nDocumentation generation complete!\n  Output directory: .doc-build\n  Pages: 18 succeeded\n  Total time: 3m 24s\n  Total cost: $0.0842 USD\n========================================\n```\n\n## Prerequisites\n\nBefore running `selfmd generate`, the following conditions must be met:\n\n1. **Claude CLI installed**: The `claude` command must be available in the system PATH (verified by `claude.CheckAvailable()`)\n2. **Configuration file exists**: `selfmd.yaml` must exist in the working directory (or another path specified with `--config`)\n3. **`selfmd init` has been run**: Initialization must have generated the configuration file\n\n## Related Links\n\n- [CLI Command Reference](../index.md)\n- [selfmd init](../cmd-init/index.md) — Initialize the configuration file\n- [selfmd update](../cmd-update/index.md) — Incremental update (only updates changed pages)\n- [selfmd translate](../cmd-translate/index.md) — Translate documentation to other languages\n- [Overall Flow and Four-Phase Pipeline](../../architecture/pipeline/index.md) — Deep dive into pipeline architecture\n- [Documentation Generation Pipeline](../../core-modules/generator/index.md) — Generator module details\n- [Claude CLI Runner](../../core-modules/claude-runner/index.md) — Runner module details\n- [Project Scanner](../../core-modules/scanner/index.md) — Scanner module details\n- [Configuration Reference](../../configuration/index.md) — Complete selfmd.yaml configuration reference\n\n## Reference Files\n\n| File Path | Description |\n|-----------|-------------|\n| `cmd/generate.go` | generate command definition, flag declarations, `runGenerate()` entry point |\n| `cmd/root.go` | rootCmd definition, global flags (`--config`, `--verbose`, `--quiet`) |\n| `internal/generator/pipeline.go` | `Generator` struct definition, `NewGenerator()`, `Generate()` main flow |\n| `internal/generator/catalog_phase.go` | `GenerateCatalog()` implementation: assembles prompt and calls Claude to generate catalog |\n| `internal/generator/content_phase.go` | `GenerateContent()` implementation: parallel page generation, retry logic, placeholder pages |\n| `internal/generator/index_phase.go` | `GenerateIndex()` implementation: generates `index.md`, `_sidebar.md`, and category indexes |\n| `internal/generator/translate_phase.go` | `Translate()` implementation (translation pipeline, called by `selfmd translate`) |\n| `internal/config/config.go` | `Config` struct definition, `Load()`, `DefaultConfig()`, validation logic |\n| `internal/scanner/scanner.go` | `Scan()` implementation: directory traversal, include/exclude filtering, README reading |\n| `internal/claude/runner.go` | `Runner.Run()`, `RunWithRetry()`, `CheckAvailable()` |\n| `internal/output/writer.go` | `Writer` struct: `WritePage()`, `Clean()`, `WriteCatalogJSON()`, etc. |","en-US/cli/cmd-init/index.md":"# selfmd init\n\nThe initialization command that scans the current directory, auto-detects the project type, and generates a `selfmd.yaml` configuration file.\n\n## Overview\n\n`selfmd init` is the first step in using selfmd. When executed, it:\n\n1. Checks whether a configuration file already exists in the current directory (default: `selfmd.yaml`)\n2. Calls `detectProject()` to automatically identify the project type (e.g., Go, Rust, Node.js, Python, etc.)\n3. Builds a complete configuration via `config.DefaultConfig()` based on detection results and default values\n4. Serializes the configuration to YAML and writes it to disk\n\nThe generated `selfmd.yaml` serves as the foundation for all subsequent selfmd commands. Users can manually adjust it after initialization as needed.\n\n---\n\n## Architecture\n\n```mermaid\nflowchart TD\n    User[\"User runs selfmd init\"]\n    initCmd[\"initCmd\\ncmd/init.go\"]\n    checkExists{\"selfmd.yaml\\nalready exists?\"}\n    forceFlag{\"--force\\nflag?\"}\n    errorExit[\"Error exit\"]\n    DefaultConfig[\"config.DefaultConfig()\\ninternal/config/config.go\"]\n    detectProject[\"detectProject()\\ncmd/init.go\"]\n    fillConfig[\"Populate ProjectName\\nProjectType\\nEntryPoints\"]\n    Save[\"cfg.Save(cfgFile)\\ninternal/config/config.go\"]\n    printSummary[\"Print config summary\"]\n\n    User --\u003e initCmd\n    initCmd --\u003e checkExists\n    checkExists -- Yes --\u003e forceFlag\n    forceFlag -- No --\u003e errorExit\n    forceFlag -- Yes --\u003e DefaultConfig\n    checkExists -- No --\u003e DefaultConfig\n    DefaultConfig --\u003e detectProject\n    detectProject --\u003e fillConfig\n    fillConfig --\u003e Save\n    Save --\u003e printSummary\n```\n\n---\n\n## Flags and Parameters\n\n| Flag | Type | Default | Description |\n|------|------|---------|-------------|\n| `--force` | bool | `false` | Force overwrite an existing configuration file |\n| `--config` / `-c` | string | `selfmd.yaml` | Specify the configuration file path (inherited from root command) |\n\nThe `--config` flag is defined on the root command `rootCmd` and is available to all subcommands:\n\n```go\nrootCmd.PersistentFlags().StringVarP(\u0026cfgFile, \"config\", \"c\", \"selfmd.yaml\", \"設定檔路徑\")\n```\n\n\u003e Source: cmd/root.go#L31\n\n---\n\n## Automatic Project Type Detection\n\nThe `detectProject()` function scans the current directory for specific files in order to infer the project type and entry points:\n\n```go\nfunc detectProject() (projectType string, entryPoints []string) {\n\tchecks := []struct {\n\t\tfile       string\n\t\tpType      string\n\t\tentries    []string\n\t}{\n\t\t{\"go.mod\", \"backend\", []string{\"main.go\", \"cmd/root.go\"}},\n\t\t{\"Cargo.toml\", \"backend\", []string{\"src/main.rs\", \"src/lib.rs\"}},\n\t\t{\"package.json\", \"frontend\", []string{\"src/index.ts\", \"src/index.js\", \"src/main.ts\", \"src/App.tsx\"}},\n\t\t{\"pom.xml\", \"backend\", []string{\"src/main/java\"}},\n\t\t{\"build.gradle\", \"backend\", []string{\"src/main/java\"}},\n\t\t{\"requirements.txt\", \"backend\", []string{\"main.py\", \"app.py\", \"src/main.py\"}},\n\t\t{\"pyproject.toml\", \"backend\", []string{\"src/main.py\", \"main.py\"}},\n\t\t{\"composer.json\", \"backend\", []string{\"public/index.php\", \"src/Kernel.php\"}},\n\t\t{\"Gemfile\", \"backend\", []string{\"config/application.rb\", \"app/\"}},\n\t}\n\t// ...\n}\n```\n\n\u003e Source: cmd/init.go#L60-L76\n\n### Detection Logic\n\n1. **Sequential checks**: Indicators are checked in the order shown above; detection stops at the first match\n2. **Entry point filtering**: Only files that actually exist are kept from the candidate entry point list\n3. **Fullstack determination**: If `package.json` (frontend) is detected, the function additionally checks whether `go.mod` or a `server/` directory exists — if so, the type is changed to `fullstack`\n4. **Default type**: If no rules match, returns `\"library\"` with an empty entry point list\n\n```mermaid\nflowchart TD\n    start[\"Start detection\"]\n    gomod{\"go.mod\\nexists?\"}\n    cargo{\"Cargo.toml\\nexists?\"}\n    pkg{\"package.json\\nexists?\"}\n    others{\"Other indicator\\nfiles exist?\"}\n    fallback[\"type: library\\nentries: []\"]\n    backendGo[\"type: backend\"]\n    backendCargo[\"type: backend\"]\n    frontendCheck{\"Also has\\ngo.mod or server/?\"}\n    fullstack[\"type: fullstack\"]\n    frontend[\"type: frontend\"]\n    backendOther[\"type: backend\"]\n\n    start --\u003e gomod\n    gomod -- Yes --\u003e backendGo\n    gomod -- No --\u003e cargo\n    cargo -- Yes --\u003e backendCargo\n    cargo -- No --\u003e pkg\n    pkg -- Yes --\u003e frontendCheck\n    frontendCheck -- Yes --\u003e fullstack\n    frontendCheck -- No --\u003e frontend\n    pkg -- No --\u003e others\n    others -- Yes --\u003e backendOther\n    others -- No --\u003e fallback\n```\n\n---\n\n## Default Configuration Values\n\n`config.DefaultConfig()` returns the following defaults:\n\n```go\nfunc DefaultConfig() *Config {\n\treturn \u0026Config{\n\t\tProject: ProjectConfig{\n\t\t\tName: filepath.Base(mustGetwd()),\n\t\t\tType: \"backend\",\n\t\t},\n\t\tTargets: TargetsConfig{\n\t\t\tInclude: []string{\"src/**\", \"pkg/**\", \"cmd/**\", \"internal/**\", \"lib/**\", \"app/**\"},\n\t\t\tExclude: []string{\n\t\t\t\t\"vendor/**\", \"node_modules/**\", \".git/**\", \".doc-build/**\",\n\t\t\t\t\"**/*.pb.go\", \"**/generated/**\", \"dist/**\", \"build/**\",\n\t\t\t},\n\t\t\tEntryPoints: []string{},\n\t\t},\n\t\tOutput: OutputConfig{\n\t\t\tDir:                 \".doc-build\",\n\t\t\tLanguage:            \"zh-TW\",\n\t\t\tSecondaryLanguages:  []string{},\n\t\t\tCleanBeforeGenerate: false,\n\t\t},\n\t\tClaude: ClaudeConfig{\n\t\t\tModel:          \"sonnet\",\n\t\t\tMaxConcurrent:  3,\n\t\t\tTimeoutSeconds: 300,\n\t\t\tMaxRetries:     2,\n\t\t\tAllowedTools:   []string{\"Read\", \"Glob\", \"Grep\"},\n\t\t\tExtraArgs:      []string{},\n\t\t},\n\t\tGit: GitConfig{\n\t\t\tEnabled:    true,\n\t\t\tBaseBranch: \"main\",\n\t\t},\n\t}\n}\n```\n\n\u003e Source: internal/config/config.go#L96-L129\n\nThe `init` command overrides the following three fields on top of the defaults using detection results:\n\n| Field | Override Source |\n|-------|----------------|\n| `project.name` | `filepath.Base(mustCwd())` — current directory name |\n| `project.type` | Result from `detectProject()` |\n| `targets.entry_points` | Actual entry points detected by `detectProject()` |\n\n---\n\n## Core Flow\n\n```mermaid\nsequenceDiagram\n    participant CLI as User Terminal\n    participant initCmd as initCmd (cmd/init.go)\n    participant config as config (internal/config)\n    participant OS as OS Filesystem\n\n    CLI-\u003e\u003einitCmd: selfmd init [--force]\n    initCmd-\u003e\u003eOS: os.Stat(cfgFile)\n    alt Config file exists and --force not provided\n        initCmd--\u003e\u003eCLI: Error: config file already exists\n    end\n    initCmd-\u003e\u003econfig: config.DefaultConfig()\n    config--\u003e\u003einitCmd: *Config (default values)\n    initCmd-\u003e\u003eOS: os.Stat each indicator file in sequence\n    OS--\u003e\u003einitCmd: exists / not exists\n    initCmd-\u003e\u003einitCmd: Determine projectType and entryPoints\n    initCmd-\u003e\u003einitCmd: Populate cfg.Project / cfg.Targets\n    initCmd-\u003e\u003econfig: cfg.Save(cfgFile)\n    config-\u003e\u003eOS: yaml.Marshal → os.WriteFile\n    OS--\u003e\u003econfig: Write successful\n    config--\u003e\u003einitCmd: nil\n    initCmd--\u003e\u003eCLI: Print config summary\n```\n\n---\n\n## Output Summary\n\nAfter successful execution, the terminal prints the following:\n\n```\nConfig file created: selfmd.yaml\n  Project name: my-project\n  Project type: backend\n  Output dir:   .doc-build\n  Doc language: zh-TW\n  Entry files:  main.go, cmd/root.go\n\nEdit the config file to suit your project needs, then run selfmd generate to produce documentation.\n```\n\n\u003e Source: cmd/init.go#L43-L56\n\n---\n\n## Usage Examples\n\n### Basic Initialization\n\n```bash\nselfmd init\n```\n\nGenerates `selfmd.yaml` in the current directory. If `go.mod` and `cmd/root.go` are detected, the configuration file will contain:\n\n```yaml\nproject:\n  name: my-project\n  type: backend\ntargets:\n  entry_points:\n    - cmd/root.go\n```\n\n### Force Overwrite an Existing Config File\n\n```bash\nselfmd init --force\n```\n\n\u003e Source: cmd/init.go#L28-L30\n\n### Specify a Custom Config File Path\n\n```bash\nselfmd init --config config/selfmd.yaml\n```\n\n---\n\n## Notes\n\n- `selfmd init` does not overwrite `targets.include` or `targets.exclude` — these fields retain their default values and must be adjusted manually as needed\n- If a project matches multiple detection conditions (e.g., both `go.mod` and `package.json` are present), only the first matching rule takes effect\n- The generated `selfmd.yaml` is serialized in YAML v3 format\n\n---\n\n## Related Links\n\n- [Initialization Setup](../../getting-started/init/index.md)\n- [selfmd.yaml Structure Overview](../../configuration/config-overview/index.md)\n- [Project and Scan Target Configuration](../../configuration/project-targets/index.md)\n- [selfmd generate](../cmd-generate/index.md)\n- [CLI Command Reference](../index.md)\n\n---\n\n## Reference Files\n\n| File Path | Description |\n|-----------|-------------|\n| `cmd/init.go` | `init` command implementation and `detectProject()` detection logic |\n| `cmd/root.go` | Root command definition, including `--config`, `--verbose`, and `--quiet` global flags |\n| `internal/config/config.go` | `Config` struct definition, `DefaultConfig()`, `Save()`, and `Load()` implementations |","en-US/cli/cmd-translate/index.md":"# selfmd translate\n\nTranslates documentation generated in the primary language into secondary languages defined in the configuration file via Claude CLI, and saves the results to the corresponding language subdirectories.\n\n## Overview\n\nThe `selfmd translate` command reads primary-language documentation already produced by `selfmd generate`, calls Claude CLI page by page for translation, and writes the translated output to `.doc-build/{language-code}/` subdirectories.\n\nThe core premise of this command is: **primary-language documentation must already exist**. The translation process does not re-scan the source code — it uses existing Markdown pages directly as the translation source.\n\nKey features:\n\n- **Incremental translation**: Automatically skips already-translated pages by default, only translating content that hasn't been translated yet\n- **Multiple target languages**: A single run can translate to multiple secondary languages simultaneously\n- **Concurrent translation**: Uses semaphore-based concurrency to speed up translation; concurrency level is controllable via configuration or flags\n- **Catalog sync**: After translation, automatically creates a catalog (`_catalog.json`), homepage (`index.md`), and sidebar (`_sidebar.md`) for each language version\n- **Cost tracking**: Displays per-page duration and total API cost after translation completes\n\nThe prompt template used for translation (`translate.tmpl`) is a **language-agnostic shared template**, maintained separately from the primary-language content generation templates.\n\n## Architecture\n\n```mermaid\nflowchart TD\n    translateCmd[\"translateCmd\\ncmd/translate.go\"]\n    checkAvailable[\"claude.CheckAvailable()\"]\n    loadConfig[\"config.Load()\"]\n    validateLangs[\"Validate target languages\"]\n    newGenerator[\"generator.NewGenerator()\"]\n    genTranslate[\"Generator.Translate()\"]\n\n    readCatalog[\"Writer.ReadCatalogJSON()\\nRead primary catalog\"]\n    parseCatalog[\"catalog.Parse()\"]\n    flattenItems[\"cat.Flatten()\\nGet all pages\"]\n\n    forEachLang[\"for each targetLang\"]\n    translatePages[\"translatePages()\\nConcurrently translate leaf pages\"]\n    buildTranslatedCatalog[\"buildTranslatedCatalog()\\nUpdate translated titles\"]\n    writeArtifacts[\"Write _catalog.json\\nindex.md\\n_sidebar.md\\nCategory index pages\"]\n    writeViewer[\"Writer.WriteViewer()\\nRegenerate static viewer\"]\n\n    subgraph perPage[\"Per-page translation (concurrent)\"]\n        checkExists[\"PageExists?\\nSkip if already exists\"]\n        readSource[\"Writer.ReadPage()\\nRead source page\"]\n        renderPrompt[\"Engine.RenderTranslate()\\nRender translation prompt\"]\n        callClaude[\"Runner.RunWithRetry()\\nCall Claude CLI\"]\n        extractDoc[\"claude.ExtractDocumentTag()\\nExtract document tag\"]\n        extractTitle[\"extractTitle()\\nExtract translated title\"]\n        writePage[\"langWriter.WritePage()\\nWrite translated page\"]\n    end\n\n    translateCmd --\u003e checkAvailable\n    translateCmd --\u003e loadConfig\n    loadConfig --\u003e validateLangs\n    validateLangs --\u003e newGenerator\n    newGenerator --\u003e genTranslate\n    genTranslate --\u003e readCatalog\n    readCatalog --\u003e parseCatalog\n    parseCatalog --\u003e flattenItems\n    flattenItems --\u003e forEachLang\n    forEachLang --\u003e translatePages\n    translatePages --\u003e perPage\n    checkExists --\u003e|\"--force or not exists\"| readSource\n    checkExists --\u003e|\"already exists\"| skip[\"Skip\"]\n    readSource --\u003e renderPrompt\n    renderPrompt --\u003e callClaude\n    callClaude --\u003e extractDoc\n    extractDoc --\u003e extractTitle\n    extractTitle --\u003e writePage\n    translatePages --\u003e buildTranslatedCatalog\n    buildTranslatedCatalog --\u003e writeArtifacts\n    writeArtifacts --\u003e forEachLang\n    forEachLang --\u003e writeViewer\n```\n\n## Command Syntax\n\n```\nselfmd translate [flags]\n```\n\n### Flags\n\n| Flag | Type | Default | Description |\n|------|------|---------|-------------|\n| `--lang` | `[]string` | `nil` (all secondary languages) | Restrict translation to specified language codes; can be repeated or comma-separated |\n| `--force` | `bool` | `false` | Force re-translation of already-translated files |\n| `--concurrency` | `int` | `0` (use config value) | Number of concurrent translation workers, overrides `claude.max_concurrent` |\n| `-c, --config` | `string` | `selfmd.yaml` | Config file path (inherited from root) |\n| `-v, --verbose` | `bool` | `false` | Show verbose debug output |\n| `-q, --quiet` | `bool` | `false` | Show errors only |\n\n\u003e Source: `cmd/translate.go#L33-L37`\n\n### Usage Examples\n\n```bash\n# Translate all configured secondary languages\nselfmd translate\n\n# Translate to English only\nselfmd translate --lang en-US\n\n# Translate to multiple languages\nselfmd translate --lang en-US,ja-JP\n\n# Force re-translation (even if already exists)\nselfmd translate --force\n\n# Increase concurrency to speed up translation\nselfmd translate --concurrency 5\n```\n\n## Prerequisites\n\nBefore running `selfmd translate`, the following conditions must be met:\n\n1. **Claude CLI is installed**: The `claude` executable must be found in the system `PATH`\n2. **Primary-language documentation has been generated**: `.doc-build/_catalog.json` and each page's `index.md` must exist\n3. **Config file contains `secondary_languages`**: `output.secondary_languages` in `selfmd.yaml` must not be empty\n\nIf condition 3 is not met, the command will report an error and exit immediately:\n\n```go\nif len(cfg.Output.SecondaryLanguages) == 0 {\n    return fmt.Errorf(\"設定檔中未定義 secondary_languages，無法翻譯\")\n}\n```\n\n\u003e Source: `cmd/translate.go#L50-L52`\n\n## Core Process\n\n### Translation Pipeline Sequence Diagram\n\n```mermaid\nsequenceDiagram\n    participant User\n    participant translateCmd\n    participant Generator\n    participant Writer\n    participant Engine\n    participant Runner as \"Runner (Claude CLI)\"\n\n    User-\u003e\u003etranslateCmd: selfmd translate\n    translateCmd-\u003e\u003etranslateCmd: CheckAvailable()\n    translateCmd-\u003e\u003etranslateCmd: config.Load()\n    translateCmd-\u003e\u003eGenerator: NewGenerator()\n    translateCmd-\u003e\u003eGenerator: Translate(opts)\n\n    Generator-\u003e\u003eWriter: ReadCatalogJSON()\n    Writer--\u003e\u003eGenerator: catJSON\n    Generator-\u003e\u003eGenerator: catalog.Parse() + Flatten()\n\n    loop For each targetLang\n        Generator-\u003e\u003eWriter: ForLanguage(lang).EnsureDir()\n\n        par Concurrently translate leaf pages\n            loop For each leafItem\n                Generator-\u003e\u003eWriter: PageExists(item)\n                alt Already exists and not --force\n                    Writer--\u003e\u003eGenerator: Skip\n                else Needs translation\n                    Generator-\u003e\u003eWriter: ReadPage(item)\n                    Writer--\u003e\u003eGenerator: sourceContent\n                    Generator-\u003e\u003eEngine: RenderTranslate(data)\n                    Engine--\u003e\u003eGenerator: rendered prompt\n                    Generator-\u003e\u003eRunner: RunWithRetry(ctx, opts)\n                    Runner--\u003e\u003eGenerator: result\n                    Generator-\u003e\u003eGenerator: ExtractDocumentTag()\n                    Generator-\u003e\u003eWriter: langWriter.WritePage(item, content)\n                end\n            end\n        end\n\n        Generator-\u003e\u003eGenerator: buildTranslatedCatalog()\n        Generator-\u003e\u003eWriter: WriteCatalogJSON (lang)\n        Generator-\u003e\u003eWriter: WriteFile(\"index.md\")\n        Generator-\u003e\u003eWriter: WriteFile(\"_sidebar.md\")\n    end\n\n    Generator-\u003e\u003eWriter: WriteViewer()\n    Generator--\u003e\u003eUser: Display translation summary\n```\n\n### Incremental Translation Logic\n\nThe `translatePages()` function checks whether the translated file exists and has valid content via `Writer.PageExists()` before translating each page. Conditions that determine a page \"needs translation\":\n\n- File does not exist\n- File content is empty\n- File content contains the string `\"此頁面產生失敗\"`\n- The user specified the `--force` flag\n\n```go\nif !opts.Force \u0026\u0026 langWriter.PageExists(item) {\n    skipped.Add(1)\n    // Attempt to extract title from existing translation\n    if content, err := langWriter.ReadPage(item); err == nil {\n        if title := extractTitle(content); title != \"\" {\n            titlesMu.Lock()\n            translatedTitles[item.Path] = title\n            titlesMu.Unlock()\n        }\n    }\n    fmt.Printf(\"      [跳過] %s（已存在）\\n\", item.Title)\n    return nil\n}\n```\n\n\u003e Source: `internal/generator/translate_phase.go#L156-L169`\n\n### Translation Catalog Sync\n\nAfter translation completes, the system rebuilds the catalog structure using translated titles so that navigation in each language version correctly displays titles in the local language:\n\n```go\nfunc buildTranslatedCatalog(original *catalog.Catalog, translatedTitles map[string]string) *catalog.Catalog {\n    translated := \u0026catalog.Catalog{\n        Items: translateCatalogItems(original.Items, translatedTitles, \"\"),\n    }\n    return translated\n}\n```\n\n\u003e Source: `internal/generator/translate_phase.go#L277-L282`\n\n## Translation Prompt Template\n\nTranslation uses the **shared template** at `internal/prompt/templates/translate.tmpl` (not language-specific), rendered by `Engine.RenderTranslate()`. The translation rules are hardcoded in the template:\n\n| Rule | Description |\n|------|-------------|\n| Preserve Markdown formatting | Headings, links, code blocks, tables, Mermaid diagrams |\n| Do not translate code identifiers | Variable names, file paths, and code blocks remain as-is |\n| Translate section headings | Use natural translations in the target language |\n| Preserve relative link paths | Only translate link display text; paths remain unchanged |\n| Preserve source annotations | `\u003e Source: path/to/file#L10-L25` format stays unchanged |\n\nThe `TranslatePromptData` struct provides the following data to the template:\n\n```go\ntype TranslatePromptData struct {\n    SourceLanguage     string // e.g. \"zh-TW\"\n    SourceLanguageName string // e.g. \"繁體中文\"\n    TargetLanguage     string // e.g. \"en-US\"\n    TargetLanguageName string // e.g. \"English\"\n    SourceContent      string // Full Markdown content to translate\n}\n```\n\n\u003e Source: `internal/prompt/engine.go#L97-L104`\n\n## Language Configuration\n\nSecondary languages are configured in the `output.secondary_languages` field of `selfmd.yaml`:\n\n```yaml\noutput:\n  language: zh-TW              # Primary language (translation source)\n  secondary_languages:         # List of target languages for translation\n    - en-US\n    - ja-JP\n```\n\nThe system currently has built-in native name display for the following languages:\n\n| Language Code | Native Name |\n|--------------|-------------|\n| `zh-TW` | 繁體中文 |\n| `zh-CN` | 简体中文 |\n| `en-US` | English |\n| `ja-JP` | 日本語 |\n| `ko-KR` | 한국어 |\n| `fr-FR` | Français |\n| `de-DE` | Deutsch |\n| `es-ES` | Español |\n| `pt-BR` | Português |\n| `th-TH` | ไทย |\n| `vi-VN` | Tiếng Việt |\n\n\u003e Source: `internal/config/config.go#L39-L51`\n\n## Output Structure\n\nAfter translation, each language version's documentation is placed in the `.doc-build/{language-code}/` subdirectory, with the same structure as the primary language version:\n\n```\n.doc-build/\n├── (primary language, e.g. zh-TW)\n│   ├── _catalog.json\n│   ├── index.md\n│   ├── _sidebar.md\n│   └── section/page/index.md\n├── en-US/\n│   ├── _catalog.json\n│   ├── index.md\n│   ├── _sidebar.md\n│   └── section/page/index.md\n└── ja-JP/\n    ├── _catalog.json\n    ├── index.md\n    └── ...\n```\n\nAfter translation completes, the static viewer (`index.html`) is also regenerated to include language-switching information for all languages.\n\n## Sample Output\n\n```\nTranslation source language: 繁體中文 (zh-TW)\nTarget languages: en-US, ja-JP\nPage count: 42\n\n========== Translating to English (en-US) ==========\n      [1/42] Overview...  Done (12.3s, $0.0042)\n      [2/42] Quick Start... Done (9.8s, $0.0038)\n      [Skipped] Installation \u0026 Build (already exists)\n      ...\n      Translation result: 40 succeeded, 0 failed, 2 skipped\n\n========== Translating to 日本語 (ja-JP) ==========\n      ...\n\nRegenerating documentation viewer...\n      Done\n\n========================================\nTranslation complete!\n  Total duration: 8m32s\n  Total cost: $0.3241 USD\n========================================\n```\n\n## Related Links\n\n- [CLI Command Reference](../index.md)\n- [selfmd generate](../cmd-generate/index.md)\n- [selfmd update](../cmd-update/index.md)\n- [Output \u0026 Multilingual Configuration](../../configuration/output-language/index.md)\n- [Translation Phase](../../core-modules/generator/translate-phase/index.md)\n- [Translation Workflow](../../i18n/translation-workflow/index.md)\n- [Supported Languages \u0026 Templates](../../i18n/supported-languages/index.md)\n- [Claude CLI Integration Configuration](../../configuration/claude-config/index.md)\n\n## Reference Files\n\n| File Path | Description |\n|-----------|-------------|\n| `cmd/translate.go` | `translate` command definition, flag parsing, and execution entry point |\n| `cmd/root.go` | Root command and global flag definitions |\n| `internal/generator/translate_phase.go` | Core translation logic: `Translate()`, `translatePages()`, `buildTranslatedCatalog()` |\n| `internal/generator/pipeline.go` | `Generator` struct definition and `NewGenerator()` |\n| `internal/prompt/engine.go` | `TranslatePromptData` struct and `RenderTranslate()` method |\n| `internal/prompt/templates/translate.tmpl` | Shared translation prompt template |\n| `internal/config/config.go` | `OutputConfig` (`SecondaryLanguages`), `KnownLanguages`, `GetLangNativeName()` |\n| `internal/output/writer.go` | `Writer`, `ForLanguage()`, `PageExists()`, `ReadPage()` |\n| `internal/claude/runner.go` | `Runner.RunWithRetry()` and `CheckAvailable()` |","en-US/cli/cmd-update/index.md":"# selfmd update\n\nThe `selfmd update` command analyzes git change history to incrementally update affected documentation pages, without regenerating all documentation from scratch.\n\n## Overview\n\n`selfmd update` is selfmd's incremental update mode. Unlike `selfmd generate`, which performs a full regeneration each time, the `update` command compares the differences between git commits and only regenerates documentation pages affected by changes — significantly saving time and API costs.\n\n**Prerequisites:**\n- `selfmd generate` must have been run previously, with initial documentation present in the `.doc-build/` directory\n- The project must be a git repository\n- Claude CLI must be available\n\n**Core Concepts:**\n- **Comparison Range**: The diff between two commits, i.e. `previousCommit..currentCommit`\n- **Matching**: Whether a changed source file path appears in the content of an existing documentation page\n- **Leaf Promotion**: When a new page needs to become a child of an existing page, the old leaf node is automatically promoted to a parent node\n\n## Architecture\n\n```mermaid\nflowchart TD\n    CLI[\"cmd/update.go\\nCLI Entry Point\"]\n    GitCheck[\"git.IsGitRepo\\nValidate Git Environment\"]\n    CommitResolution[\"Commit Resolution\\n--since / _last_commit / merge-base\"]\n    GitDiff[\"git.GetChangedFiles\\nGet Changed File List\"]\n    Filter[\"git.FilterChangedFiles\\nApply include/exclude Filters\"]\n    Scanner[\"scanner.Scan\\nScan Project Structure\"]\n    Update[\"generator.Update\\nIncremental Update Main Flow\"]\n\n    ReadCatalog[\"Writer.ReadCatalogJSON\\nRead _catalog.json\"]\n    Match[\"matchChangedFilesToDocs\\nMatch Changed Files to Doc Pages\"]\n    ClaudeMatched[\"determineMatchedUpdates\\nClaude Determines Which Pages Need Update\"]\n    ClaudeUnmatched[\"determineUnmatchedPages\\nClaude Determines Whether to Add New Pages\"]\n    Regenerate[\"generateSinglePage\\nRegenerate Page Content\"]\n    GenerateIndex[\"GenerateIndex\\nRegenerate Navigation and Index\"]\n    SaveCommit[\"Writer.SaveLastCommit\\nSave _last_commit\"]\n\n    CLI --\u003e GitCheck\n    CLI --\u003e CommitResolution\n    CommitResolution --\u003e GitDiff\n    GitDiff --\u003e Filter\n    Filter --\u003e Scanner\n    Scanner --\u003e Update\n\n    Update --\u003e ReadCatalog\n    ReadCatalog --\u003e Match\n    Match --\u003e ClaudeMatched\n    Match --\u003e ClaudeUnmatched\n    ClaudeMatched --\u003e Regenerate\n    ClaudeUnmatched --\u003e Regenerate\n    Regenerate --\u003e GenerateIndex\n    GenerateIndex --\u003e SaveCommit\n```\n\n## Command Syntax\n\n```bash\nselfmd update [flags]\n```\n\n**Available Flags:**\n\n| Flag | Type | Description |\n|------|------|-------------|\n| `--since \u003ccommit\u003e` | string | Specify the base commit for comparison (auto-detected by default) |\n| `--config \u003cpath\u003e` | string | Specify config file path (global flag, inherited from root) |\n| `--verbose` | bool | Show detailed debug logs (global flag, inherited from root) |\n\n\u003e Source: `cmd/update.go#L19-L31`\n\n## Commit Resolution Logic\n\nBefore running, `selfmd update` needs to determine \"which commit to start comparing from.\" The system resolves the base commit using the following priority order:\n\n```mermaid\nflowchart TD\n    A{Is --since flag provided?} -- Yes --\u003e B[\"Use commit specified by --since\"]\n    A -- No --\u003e C{Can _last_commit be read successfully?}\n    C -- Yes --\u003e D[\"Use the commit saved in _last_commit\"]\n    C -- No --\u003e E{Does git merge-base succeed?}\n    E -- Yes --\u003e F[\"Use merge-base\\n(divergence point of current branch and baseBranch)\"]\n    E -- No --\u003e G[\"Return error\\nSuggesting to run selfmd generate first\\nor specify a commit with --since\"]\n```\n\nThe `_last_commit` file is automatically written after each `generate` or `update` completes, stored at `.doc-build/_last_commit`.\n\n```go\n// Determine comparison commit\npreviousCommit := sinceCommit\nif previousCommit == \"\" {\n    // Try reading saved commit from last generate/update\n    saved, readErr := gen.Writer.ReadLastCommit()\n    if readErr == nil \u0026\u0026 saved != \"\" {\n        previousCommit = saved\n    } else {\n        // Fallback to merge-base\n        base, err := git.GetMergeBase(rootDir, cfg.Git.BaseBranch)\n        if err != nil {\n            return fmt.Errorf(\"無法取得基準 commit: %w\\n提示：先執行 selfmd generate 或使用 --since 指定 commit\", err)\n        }\n        previousCommit = base\n    }\n}\n```\n\n\u003e Source: `cmd/update.go#L68-L82`\n\n## Four-Phase Update Flow\n\nThe `generator.Update()` method executes the following four phases in order:\n\n### [1/4] Find Affected Documentation Pages\n\n`matchChangedFilesToDocs` scans the content of all existing documentation pages for each changed source file, looking for pages that contain a reference to that file's path.\n\n```go\n// For each changed file, find which pages reference it\nfor _, f := range files {\n    var matchedPages []catalog.FlatItem\n    for _, item := range items {\n        content, ok := pageContents[item.Path]\n        if !ok {\n            continue\n        }\n        if strings.Contains(content, f.Path) {\n            matchedPages = append(matchedPages, item)\n        }\n    }\n    // ...\n}\n```\n\n\u003e Source: `internal/generator/updater.go#L191-L211`\n\nThis step categorizes changed files into two groups:\n- **matched**: Files that are referenced in existing documentation\n- **unmatched**: New files that are not referenced in any existing documentation\n\n### [2/4] Claude Determines Which Existing Pages Need Updating\n\nFor matched files, Claude CLI is called to evaluate whether each related documentation page is genuinely affected, and returns a list of pages that need to be regenerated.\n\nClaude's decision is returned in JSON format, containing three fields: `catalogPath`, `title`, and `reason`:\n\n```go\ntype UpdateMatchedResult struct {\n    CatalogPath string `json:\"catalogPath\"`\n    Title       string `json:\"title\"`\n    Reason      string `json:\"reason\"`\n}\n```\n\n\u003e Source: `internal/generator/updater.go#L18-L22`\n\n### [3/4] Claude Determines Whether to Add New Pages\n\nFor unmatched files (new files not referenced in any existing documentation), Claude CLI is called to evaluate whether documentation pages should be added for these files.\n\n```go\ntype UpdateUnmatchedResult struct {\n    CatalogPath string `json:\"catalogPath\"`\n    Title       string `json:\"title\"`\n    Reason      string `json:\"reason\"`\n}\n```\n\n\u003e Source: `internal/generator/updater.go#L24-L29`\n\nIf Claude decides new pages need to be added, the system calls `addItemToCatalog` to insert the new pages into the existing catalog tree, and triggers the leaf promotion mechanism (described below).\n\n### [4/4] Regenerate Page Content\n\nFor all pages that need updating (matched pages requiring updates + newly added pages), the same `generateSinglePage` flow used by `selfmd generate` is called to regenerate content. The existing page content is passed as context during generation, allowing Claude to preserve the original structure when updating.\n\n```go\n// Read existing content to pass as context for regeneration\nexisting, _ := g.Writer.ReadPage(item)\nerr := g.generateSinglePage(ctx, scan, item, catalogTable, linkFixer, existing)\n```\n\n\u003e Source: `internal/generator/updater.go#L141-L142`\n\n## Leaf Promotion Mechanism\n\nWhen Claude decides to add a child page under an existing page's path (for example, adding `core-modules.scanner.advanced` under `core-modules.scanner`), the original leaf node (`core-modules.scanner`) needs to be promoted to a parent node.\n\nThe system automatically:\n1. Moves the original leaf node's existing content to a newly created `overview` child page (e.g. `core-modules.scanner.overview`)\n2. Marks the original leaf node as a parent node\n3. Creates the newly requested child page under the parent node\n\n```go\n// A leaf node was promoted to a parent.\n// Move the original content to the new \"overview\" child.\norigItem := catalog.FlatItem{\n    Path:    promoted.OriginalPath,\n    DirPath: catalogPathToDir(promoted.OriginalPath),\n}\noverviewItem := catalog.FlatItem{\n    Title:   promoted.OriginalTitle,\n    Path:    promoted.OverviewPath,\n    DirPath: catalogPathToDir(promoted.OverviewPath),\n}\nif content, err := g.Writer.ReadPage(origItem); err == nil \u0026\u0026 content != \"\" {\n    if err := g.Writer.WritePage(overviewItem, content); err != nil {\n        // ...\n    }\n}\n```\n\n\u003e Source: `internal/generator/updater.go#L99-L116`\n\n## Changed File Filtering\n\nThe system uses the same include/exclude rules as `selfmd generate` to filter git diff output, ensuring that only file changes matching the configured targets trigger documentation updates.\n\n```go\nchangedFiles = git.FilterChangedFiles(changedFiles, cfg.Targets.Include, cfg.Targets.Exclude)\n```\n\n\u003e Source: `cmd/update.go#L94`\n\n`FilterChangedFiles` supports doublestar glob syntax (`**/*.go`) and correctly handles git rename format (`R100\\told\\tnew`), using the destination path for matching.\n\n```go\n// git diff --name-status format: \"M\\tpath/to/file\" or \"R100\\told\\tnew\"\nparts := strings.SplitN(line, \"\\t\", 3)\n// For renames, check the destination path (last element)\nfilePath := parts[len(parts)-1]\n```\n\n\u003e Source: `internal/git/git.go#L83-L91`\n\n## Output Files\n\nAfter each `update` completes, the system updates the following persistent files:\n\n| File | Description |\n|------|-------------|\n| `.doc-build/_last_commit` | Records the HEAD commit hash of this update run, used by the next update |\n| `.doc-build/_catalog.json` | Updated documentation catalog structure if new pages were added |\n| `.doc-build/\u003cpath\u003e/index.md` | Documentation pages that were updated or newly created |\n\n## Usage Examples\n\n```bash\n# Basic usage: update documentation changed since the last generate/update\nselfmd update\n\n# Compare against a specific commit\nselfmd update --since a1b2c3d\n\n# Enable verbose logging\nselfmd update --verbose\n\n# Specify a config file\nselfmd update --config ./selfmd.yaml\n```\n\nTypical output:\n\n```\nComparison range: a1b2c3d..e4f5g6h\nChanged files:\nM       internal/scanner/scanner.go\nA       internal/scanner/filetree.go\n\n[1/4] Finding affected documentation pages...\n      2 changed files matched to existing docs, 0 unmatched\n[2/4] Calling Claude to determine pages that need updating...\n      → Project Scanner: public API in scanner.go has changed, update required\n      Done (1 page needs updating)\n[3/4] All changed files already have corresponding documentation, skipping\n[4/4] Regenerating 1 page...\n      [1/1] Project Scanner (core-modules.scanner)... Done\n\nUpdate complete! Total cost: $0.0023 USD\n```\n\n## Prerequisite Error Handling\n\n| Condition | Error Message |\n|-----------|---------------|\n| Claude CLI not available | Error returned by `claude.CheckAvailable()` |\n| Not a git repository | `Current directory is not a git repository, cannot perform incremental update` |\n| Cannot resolve base commit | `Failed to get base commit: ...` with suggestion to run `selfmd generate` first |\n| `generate` has never been run | `Failed to read existing catalog (please run selfmd generate first)` |\n\n## Related Links\n\n- [CLI Command Reference](../index.md)\n- [selfmd generate](../cmd-generate/index.md)\n- [Git Integration and Incremental Updates](../../git-integration/index.md)\n- [Git Diff Change Detection](../../git-integration/change-detection/index.md)\n- [Affected Page Determination Logic](../../git-integration/affected-pages/index.md)\n- [Incremental Update (Core Module)](../../core-modules/incremental-update/index.md)\n- [Documentation Catalog Management](../../core-modules/catalog/index.md)\n- [Git Integration Configuration](../../configuration/git-config/index.md)\n\n## Reference Files\n\n| File Path | Description |\n|-----------|-------------|\n| `cmd/update.go` | `selfmd update` CLI command definition, flag declarations, prerequisite validation, commit resolution logic |\n| `internal/generator/updater.go` | Incremental update main flow `Update()`, matching logic, Claude decision calls, leaf promotion mechanism |\n| `internal/git/git.go` | Git operation wrappers: `IsGitRepo`, `GetChangedFiles`, `ParseChangedFiles`, `FilterChangedFiles` |\n| `internal/output/writer.go` | `SaveLastCommit`, `ReadLastCommit`, `ReadCatalogJSON`, `WriteCatalogJSON` |\n| `internal/generator/pipeline.go` | `Generator` struct definition, `NewGenerator` constructor |\n| `internal/catalog/catalog.go` | `Catalog`, `FlatItem`, `BuildLinkTable`, `Flatten`, and other catalog operations |\n| `internal/prompt/engine.go` | `UpdateMatchedPromptData`, `UpdateUnmatchedPromptData`, `RenderUpdateMatched`, `RenderUpdateUnmatched` |","en-US/cli/index.md":"# CLI Command Reference\n\nThis section contains the following:\n\n- [selfmd init](cmd-init/index.md)\n- [selfmd generate](cmd-generate/index.md)\n- [selfmd update](cmd-update/index.md)\n- [selfmd translate](cmd-translate/index.md)\n","en-US/configuration/claude-config/index.md":"# Claude CLI Integration Settings\n\nControls how selfmd invokes Claude CLI subprocesses, including model selection, concurrency, timeout, retries, and tool access permissions.\n\n## Overview\n\nThe `claude` configuration block defines all behavioral parameters for how selfmd interacts with the Claude CLI (`claude` command). selfmd calls the Claude CLI as a subprocess at each stage of the documentation generation pipeline — directory generation, content page generation, and translation — and all of these calls are governed by this configuration.\n\n**Core responsibilities:**\n- Specify the Claude model version to use\n- Limit the number of concurrent Claude subprocesses per run to avoid exceeding API rate limits\n- Set the maximum wait time (timeout) for each call\n- Control the number of automatic retries and backoff intervals after failures\n- Restrict which tools Claude can access to ensure safe boundaries for documentation analysis\n- Inject custom additional CLI arguments\n\n## Configuration Structure\n\nThe `claude` block in `selfmd.yaml` maps to the `ClaudeConfig` struct:\n\n```go\ntype ClaudeConfig struct {\n    Model          string   `yaml:\"model\"`\n    MaxConcurrent  int      `yaml:\"max_concurrent\"`\n    TimeoutSeconds int      `yaml:\"timeout_seconds\"`\n    MaxRetries     int      `yaml:\"max_retries\"`\n    AllowedTools   []string `yaml:\"allowed_tools\"`\n    ExtraArgs      []string `yaml:\"extra_args\"`\n}\n```\n\n\u003e Source: internal/config/config.go#L82-L89\n\n### Full Default Values\n\n```go\nClaude: ClaudeConfig{\n    Model:          \"sonnet\",\n    MaxConcurrent:  3,\n    TimeoutSeconds: 300,\n    MaxRetries:     2,\n    AllowedTools:   []string{\"Read\", \"Glob\", \"Grep\"},\n    ExtraArgs:      []string{},\n},\n```\n\n\u003e Source: internal/config/config.go#L116-L123\n\n## Field Reference\n\n### `model`\n\n**Type:** `string`　**Default:** `\"sonnet\"`\n\nSpecifies the Claude model to use. This value is passed directly to the `claude --model` flag. If left empty, the `--model` flag is not passed and the Claude CLI uses its own default.\n\n```yaml\nclaude:\n  model: sonnet       # Use Claude Sonnet (faster, more cost-efficient)\n  # model: opus       # Use Claude Opus (more capable, more expensive)\n```\n\n### `max_concurrent`\n\n**Type:** `int`　**Default:** `3`　**Minimum:** `1`\n\nSets the maximum number of concurrent Claude CLI subprocesses. This value controls the parallelism for both the content page generation and translation stages.\n\n- Setting this too high may trigger Anthropic API rate limits\n- The `selfmd generate --concurrency` flag can temporarily override this value at runtime\n- Validation logic ensures this value is never less than `1`\n\n### `timeout_seconds`\n\n**Type:** `int`　**Default:** `300`　**Minimum:** `30`\n\nThe timeout in seconds for each Claude CLI call. After this duration, the Runner cancels the subprocess and reports a timeout error.\n\n- If documents are large or prompts are complex, consider increasing this value\n- Validation logic ensures this value is never less than `30` seconds\n\n### `max_retries`\n\n**Type:** `int`　**Default:** `2`　**Minimum:** `0`\n\nThe maximum number of automatic retries when a Claude CLI call fails. Retries use a backoff strategy: before the Nth retry, the runner waits `N × 5` seconds.\n\n- Set to `0` to disable retries\n- Validation logic ensures this value is never less than `0`\n\n### `allowed_tools`\n\n**Type:** `[]string`　**Default:** `[\"Read\", \"Glob\", \"Grep\"]`\n\nSpecifies the list of tools Claude is allowed to use when analyzing source code. Corresponds to the `claude --allowedTools` flag, passed once per tool.\n\n**Note:** Regardless of this setting, the `Write` and `Edit` tools are always blocked (via `--disallowedTools Write --disallowedTools Edit`) to prevent Claude from directly modifying source code.\n\n```yaml\nclaude:\n  allowed_tools:\n    - Read    # Read file contents\n    - Glob    # Search files by pattern\n    - Grep    # Search text within files\n```\n\n### `extra_args`\n\n**Type:** `[]string`　**Default:** `[]`\n\nAdditional CLI arguments injected into every `claude` command, appended after the automatically generated arguments. Useful for passing Claude CLI flags not directly supported by selfmd.\n\n```yaml\nclaude:\n  extra_args:\n    - \"--verbose\"\n```\n\n## Architecture\n\n```mermaid\nflowchart TD\n    YAML[\"selfmd.yaml\\n(claude block)\"]\n    CFG[\"ClaudeConfig\\ninternal/config/config.go\"]\n    RUNNER[\"Runner\\ninternal/claude/runner.go\"]\n    CLI[\"claude CLI\\nsubprocess\"]\n    PIPELINE[\"Generator\\ninternal/generator/pipeline.go\"]\n    TRANSLATE[\"Translate\\ncmd/translate.go\"]\n\n    YAML --\u003e|\"yaml.Unmarshal\"| CFG\n    CFG --\u003e|\"\u0026cfg.Claude\"| RUNNER\n    PIPELINE --\u003e|\"MaxConcurrent\\nconcurrency control\"| RUNNER\n    TRANSLATE --\u003e|\"MaxConcurrent\\nconcurrency control\"| RUNNER\n    RUNNER --\u003e|\"exec.CommandContext\"| CLI\n\n    subgraph Runner Internals\n        ARGS[\"Assemble CLI args\\n-p --output-format json\\n--model --allowedTools\\n--disallowedTools Write/Edit\"]\n        TIMEOUT[\"context.WithTimeout\\n(TimeoutSeconds)\"]\n        RETRY[\"RunWithRetry\\nbackoff retry (MaxRetries)\"]\n    end\n\n    RUNNER --\u003e ARGS\n    RUNNER --\u003e TIMEOUT\n    RUNNER --\u003e RETRY\n```\n\n## Core Flow\n\n### Runner Invocation Flow\n\n```mermaid\nsequenceDiagram\n    participant G as Generator\n    participant R as Runner\n    participant CLI as claude CLI\n\n    G-\u003e\u003eR: RunWithRetry(ctx, opts)\n    loop Up to MaxRetries+1 times\n        R-\u003e\u003eR: Assemble CLI args\n        note over R: -p --output-format json\u003cbr/\u003e--model {Model}\u003cbr/\u003e--allowedTools {each tool}\u003cbr/\u003e--disallowedTools Write Edit\u003cbr/\u003e{ExtraArgs}\n        R-\u003e\u003eCLI: exec.CommandContext(ctx, \"claude\", args...)\n        note over R,CLI: Prompt passed via stdin\n        alt Success\n            CLI--\u003e\u003eR: JSON response (stdout)\n            R-\u003e\u003eR: ParseResponse(stdout)\n            R--\u003e\u003eG: RunResult\n        else Failure or IsError\n            R-\u003e\u003eR: Wait attempt × 5 seconds\n        end\n    end\n    R--\u003e\u003eG: Error (all retries exhausted)\n```\n\n### Timeout Handling\n\n```go\ntimeout := opts.Timeout\nif timeout == 0 {\n    timeout = time.Duration(r.config.TimeoutSeconds) * time.Second\n}\n\nctx, cancel := context.WithTimeout(ctx, timeout)\ndefer cancel()\n```\n\n\u003e Source: internal/claude/runner.go#L61-L67\n\n### Retry Backoff Logic\n\n```go\nfor attempt := 0; attempt \u003c= maxRetries; attempt++ {\n    if attempt \u003e 0 {\n        backoff := time.Duration(attempt) * 5 * time.Second\n        r.logger.Info(\"Retrying\", \"attempt\", attempt+1, \"backoff\", backoff)\n        select {\n        case \u003c-ctx.Done():\n            return nil, ctx.Err()\n        case \u003c-time.After(backoff):\n        }\n    }\n    // ...\n}\n```\n\n\u003e Source: internal/claude/runner.go#L117-L127\n\n## Usage Examples\n\n### Full `claude` Block in `selfmd.yaml`\n\n```yaml\nclaude:\n  model: sonnet\n  max_concurrent: 3\n  timeout_seconds: 300\n  max_retries: 2\n  allowed_tools:\n    - Read\n    - Glob\n    - Grep\n  extra_args: []\n```\n\n### High-Throughput Configuration (Large Projects)\n\n```yaml\nclaude:\n  model: sonnet\n  max_concurrent: 5      # Increase concurrency\n  timeout_seconds: 600   # Extend timeout to 10 minutes\n  max_retries: 3\n  allowed_tools:\n    - Read\n    - Glob\n    - Grep\n```\n\n### Validation Logic\n\n```go\nfunc (c *Config) validate() error {\n    if c.Claude.MaxConcurrent \u003c 1 {\n        c.Claude.MaxConcurrent = 1\n    }\n    if c.Claude.TimeoutSeconds \u003c 30 {\n        c.Claude.TimeoutSeconds = 30\n    }\n    if c.Claude.MaxRetries \u003c 0 {\n        c.Claude.MaxRetries = 0\n    }\n    return nil\n}\n```\n\n\u003e Source: internal/config/config.go#L157-L174\n\n## Tool Restriction Design\n\nselfmd uses a dual strategy of \"allowlist + enforced blocklist\" for tool access:\n\n| Mechanism | Configuration Source | Description |\n|-----------|----------------------|-------------|\n| `--allowedTools` | `allowed_tools` field | Tools Claude is permitted to use (read-only analysis tools) |\n| `--disallowedTools Write` | Hardcoded in Runner | Write is always blocked regardless of configuration |\n| `--disallowedTools Edit` | Hardcoded in Runner | Edit is always blocked regardless of configuration |\n\nThis design ensures Claude can only \"read\" source code for documentation analysis and cannot modify any files. Related implementation:\n\n```go\n// Explicitly block Write/Edit to prevent content from being lost in denied tool calls\nargs = append(args, \"--disallowedTools\", \"Write\", \"--disallowedTools\", \"Edit\")\n```\n\n\u003e Source: internal/claude/runner.go#L55-L56\n\n## Related Links\n\n- [Configuration Reference](../index.md)\n- [selfmd.yaml Structure Overview](../config-overview/index.md)\n- [Output and Multilingual Settings](../output-language/index.md)\n- [Git Integration Settings](../git-config/index.md)\n- [Claude CLI Runner](../../core-modules/claude-runner/index.md)\n- [Documentation Generation Pipeline](../../core-modules/generator/index.md)\n- [Translation Phase](../../core-modules/generator/translate-phase/index.md)\n\n## Reference Files\n\n| File Path | Description |\n|-----------|-------------|\n| `internal/config/config.go` | `ClaudeConfig` struct definition, default values, and validation logic |\n| `internal/claude/runner.go` | `Runner` implementation responsible for assembling CLI arguments and executing subprocesses |\n| `internal/claude/types.go` | Type definitions for `RunOptions`, `RunResult`, and `CLIResponse` |\n| `internal/claude/parser.go` | Claude CLI JSON response parsing logic |\n| `internal/generator/pipeline.go` | `MaxConcurrent` used to control content generation concurrency |\n| `cmd/translate.go` | `MaxConcurrent` used to control translation concurrency |","en-US/configuration/config-overview/index.md":"# selfmd.yaml Structure Overview\n\n`selfmd.yaml` is the core configuration file for selfmd, containing five top-level sections that control everything from project scanning to Claude CLI invocation.\n\n## Overview\n\n`selfmd.yaml` uses YAML format and is parsed into the `Config` struct defined in `internal/config/config.go`. Before any selfmd command runs, the system loads and validates this configuration file.\n\nEach of the five top-level sections is responsible for a different functional area:\n\n| Section | Go Type | Description |\n|---------|---------|-------------|\n| `project` | `ProjectConfig` | Basic project information (name, type, description) |\n| `targets` | `TargetsConfig` | Scan target paths (include, exclude, entry points) |\n| `output` | `OutputConfig` | Output directory and multi-language settings |\n| `claude` | `ClaudeConfig` | Claude CLI execution parameters |\n| `git` | `GitConfig` | Git integration and incremental update settings |\n\nWhen you run `selfmd init`, the system automatically detects the project type, applies defaults, and generates a complete `selfmd.yaml` template. The configuration file path defaults to `selfmd.yaml` and can be overridden with the `--config` flag.\n\n## Architecture\n\n```mermaid\ngraph TD\n    YAML[\"selfmd.yaml\"]\n\n    YAML --\u003e P[\"project\\n（ProjectConfig）\"]\n    YAML --\u003e T[\"targets\\n（TargetsConfig）\"]\n    YAML --\u003e O[\"output\\n（OutputConfig）\"]\n    YAML --\u003e C[\"claude\\n（ClaudeConfig）\"]\n    YAML --\u003e G[\"git\\n（GitConfig）\"]\n\n    P --\u003e P1[\"name\"]\n    P --\u003e P2[\"type\"]\n    P --\u003e P3[\"description\"]\n\n    T --\u003e T1[\"include\"]\n    T --\u003e T2[\"exclude\"]\n    T --\u003e T3[\"entry_points\"]\n\n    O --\u003e O1[\"dir\"]\n    O --\u003e O2[\"language\"]\n    O --\u003e O3[\"secondary_languages\"]\n    O --\u003e O4[\"clean_before_generate\"]\n\n    C --\u003e C1[\"model\"]\n    C --\u003e C2[\"max_concurrent\"]\n    C --\u003e C3[\"timeout_seconds\"]\n    C --\u003e C4[\"max_retries\"]\n    C --\u003e C5[\"allowed_tools\"]\n    C --\u003e C6[\"extra_args\"]\n\n    G --\u003e G1[\"enabled\"]\n    G --\u003e G2[\"base_branch\"]\n```\n\n## Full Structure Reference\n\n### `project` — Basic Project Information\n\n```yaml\nproject:\n  name: myproject         # Project name, used in doc titles and browser tabs\n  type: backend           # Project type: backend / frontend / fullstack / library\n  description: \"\"         # Project description (optional)\n```\n\n\u003e Source: `internal/config/config.go#L19-L23`\n\nThe `type` field influences the context description Claude uses when generating documentation. `selfmd init` detects this automatically based on indicator files such as `go.mod` and `package.json`.\n\n---\n\n### `targets` — Scan Target Configuration\n\n```yaml\ntargets:\n  include:\n    - src/**\n    - pkg/**\n    - cmd/**\n    - internal/**\n    - lib/**\n    - app/**\n  exclude:\n    - vendor/**\n    - node_modules/**\n    - .git/**\n    - .doc-build/**\n    - \"**/*.pb.go\"\n    - \"**/generated/**\"\n    - dist/**\n    - build/**\n  entry_points:\n    - main.go\n    - cmd/root.go\n```\n\n\u003e Source: `internal/config/config.go#L25-L29`, defaults: `internal/config/config.go#L102-L109`\n\n- `include`: Specifies directories to scan using glob patterns; supports `**` wildcards\n- `exclude`: Excludes noisy paths such as auto-generated code, dependencies, and build artifacts\n- `entry_points`: Marks core entry files to guide Claude in understanding the project architecture first\n\n---\n\n### `output` — Output and Language Settings\n\n```yaml\noutput:\n  dir: .doc-build               # Documentation output directory\n  language: zh-TW               # Primary documentation language (master lang)\n  secondary_languages:          # List of secondary languages (for translation)\n    - en-US\n  clean_before_generate: false  # Whether to clear the output directory before each generation\n```\n\n\u003e Source: `internal/config/config.go#L31-L36`\n\n**Language codes**: `language` and `secondary_languages` use BCP 47 format. The system has built-in support for the following language codes:\n\n| Code | Language Name |\n|------|--------------|\n| `zh-TW` | 繁體中文 |\n| `zh-CN` | 简体中文 |\n| `en-US` | English |\n| `ja-JP` | 日本語 |\n| `ko-KR` | 한국어 |\n| `fr-FR` | Français |\n| `de-DE` | Deutsch |\n| `es-ES` | Español |\n| `pt-BR` | Português |\n| `th-TH` | ไทย |\n| `vi-VN` | Tiếng Việt |\n\n\u003e Source: `internal/config/config.go#L39-L51`\n\n`clean_before_generate` can be overridden by the CLI flags `--clean` or `--no-clean`.\n\n---\n\n### `claude` — Claude CLI Integration Settings\n\n```yaml\nclaude:\n  model: sonnet           # Claude model identifier\n  max_concurrent: 3       # Maximum number of concurrent requests\n  timeout_seconds: 300    # Per-request timeout (seconds), minimum 30\n  max_retries: 2          # Number of retry attempts on failure, minimum 0\n  allowed_tools:          # List of tools Claude is allowed to use\n    - Read\n    - Glob\n    - Grep\n  extra_args: []          # Additional flags to pass to the claude CLI\n```\n\n\u003e Source: `internal/config/config.go#L82-L89`, defaults: `internal/config/config.go#L116-L123`\n\n`max_concurrent` controls how many Claude CLI calls run simultaneously and can be overridden at runtime with `selfmd generate --concurrency \u003cN\u003e`.\n\n---\n\n### `git` — Git Integration Settings\n\n```yaml\ngit:\n  enabled: true           # Whether to enable Git integration (incremental updates)\n  base_branch: main       # Base branch used for diffing\n```\n\n\u003e Source: `internal/config/config.go#L91-L94`\n\nWhen Git integration is enabled, the `selfmd update` command diffs `base_branch` against the current working tree and regenerates only the documentation pages affected by the changes.\n\n## Load and Validation Flow\n\n```mermaid\nsequenceDiagram\n    participant CLI as CLI Command\n    participant Load as config.Load()\n    participant Default as DefaultConfig()\n    participant Validate as validate()\n\n    CLI-\u003e\u003eLoad: Load(\"selfmd.yaml\")\n    Load-\u003e\u003eDefault: Create defaults\n    Default--\u003e\u003eLoad: *Config (with all default values)\n    Load-\u003e\u003eLoad: yaml.Unmarshal (override with user settings)\n    Load-\u003e\u003eValidate: cfg.validate()\n    Validate-\u003e\u003eValidate: Check output.dir is non-empty\n    Validate-\u003e\u003eValidate: Check output.language is non-empty\n    Validate-\u003e\u003eValidate: Fix max_concurrent \u003c 1\n    Validate-\u003e\u003eValidate: Fix timeout_seconds \u003c 30\n    Validate-\u003e\u003eValidate: Fix max_retries \u003c 0\n    Validate--\u003e\u003eLoad: Validation passed\n    Load--\u003e\u003eCLI: *Config\n```\n\n`Load()` follows a \"defaults first, user overrides\" strategy: it starts by building a complete default `Config`, then overlays the YAML content on top. Any fields left unset automatically retain their default values.\n\n```go\nfunc Load(path string) (*Config, error) {\n    data, err := os.ReadFile(path)\n    if err != nil {\n        return nil, fmt.Errorf(\"無法讀取設定檔 %s: %w\", path, err)\n    }\n\n    cfg := DefaultConfig()\n    if err := yaml.Unmarshal(data, cfg); err != nil {\n        return nil, fmt.Errorf(\"設定檔格式錯誤: %w\", err)\n    }\n\n    if err := cfg.validate(); err != nil {\n        return nil, err\n    }\n\n    return cfg, nil\n}\n```\n\n\u003e Source: `internal/config/config.go#L131-L147`\n\n## Prompt Template Language Selection Logic\n\n`output.language` controls not only the documentation output language but also which prompt template is selected. Currently, built-in templates only support `zh-TW` and `en-US`; other language codes fall back to the `en-US` template, with an explicit language output instruction injected into the prompt.\n\n```go\n// GetEffectiveTemplateLang returns which template folder to load.\nfunc (o *OutputConfig) GetEffectiveTemplateLang() string {\n    for _, lang := range SupportedTemplateLangs {\n        if o.Language == lang {\n            return o.Language\n        }\n    }\n    return \"en-US\"\n}\n\n// NeedsLanguageOverride returns true when the template language differs from Language.\nfunc (o *OutputConfig) NeedsLanguageOverride() bool {\n    return o.GetEffectiveTemplateLang() != o.Language\n}\n```\n\n\u003e Source: `internal/config/config.go#L58-L71`\n\n## Related Links\n\n- [Configuration Overview](../index.md) — Configuration section overview\n- [Project and Scan Target Settings](../project-targets/index.md) — Detailed reference for the `project` and `targets` sections\n- [Output and Multi-Language Settings](../output-language/index.md) — The `output` section and language mechanism\n- [Claude CLI Integration Settings](../claude-config/index.md) — Detailed reference for the `claude` section\n- [Git Integration Settings](../git-config/index.md) — Detailed reference for the `git` section\n- [selfmd init](../../cli/cmd-init/index.md) — Command for auto-generating the configuration file\n- [Multi-Language Support](../../i18n/index.md) — Language codes and translation workflow\n\n## Reference Files\n\n| File Path | Description |\n|-----------|-------------|\n| `internal/config/config.go` | `Config` struct definition, defaults, load and validation logic |\n| `cmd/init.go` | `selfmd init` implementation, including project type auto-detection and config file generation |\n| `cmd/root.go` | Root command definition, including the `--config` flag declaration |\n| `cmd/generate.go` | `selfmd generate` implementation, showing how the config is passed to the Generator |\n| `internal/generator/pipeline.go` | How the Generator uses Config fields to drive the documentation generation pipeline |","en-US/configuration/git-config/index.md":"# Git Integration Configuration\n\nConfigure how selfmd uses Git history to track source code changes for incremental documentation updates.\n\n## Overview\n\nselfmd's Git integration configuration is located in the `git` block of `selfmd.yaml`. This configuration determines how the `selfmd update` command compares Git commits to detect affected source files during incremental updates.\n\nCore concepts of Git integration:\n\n- **Base Branch**: The branch used as the starting point for comparison. When no previous run record is found, the system uses the merge-base of this branch and `HEAD` as the comparison starting point.\n- **Enabled**: Controls whether the Git diff feature is active. This field is read by the system, though `selfmd update` itself already requires the current directory to be a Git repository.\n- **Commit Record Persistence**: After each `generate` or `update` run, the system saves the current commit hash to a `_last_commit` file in the output directory for use in the next incremental update.\n\n## Architecture\n\n```mermaid\nflowchart TD\n    YAML[\"selfmd.yaml\\ngit.enabled\\ngit.base_branch\"]\n    GitConfig[\"GitConfig struct\\ninternal/config/config.go\"]\n    UpdateCmd[\"selfmd update\\ncmd/update.go\"]\n    GitPkg[\"git package\\ninternal/git/git.go\"]\n    LastCommit[\"_last_commit file\\noutput directory\"]\n    MergeBase[\"git merge-base\\nbase branch vs HEAD\"]\n\n    YAML --\u003e GitConfig\n    GitConfig --\u003e UpdateCmd\n    UpdateCmd --\u003e|\"read last commit\"| LastCommit\n    LastCommit --\u003e|\"not found\"| MergeBase\n    MergeBase --\u003e|\"use base_branch\"| GitConfig\n    UpdateCmd --\u003e GitPkg\n    GitPkg --\u003e|\"git diff --name-status\"| UpdateCmd\n```\n\n## Configuration Fields\n\nThe `GitConfig` struct is defined in `internal/config/config.go`:\n\n```go\ntype GitConfig struct {\n\tEnabled    bool   `yaml:\"enabled\"`\n\tBaseBranch string `yaml:\"base_branch\"`\n}\n```\n\n\u003e Source: internal/config/config.go#L91-L94\n\n### `git.enabled`\n\n| Property | Value |\n|----------|-------|\n| Type | `bool` |\n| Default | `true` |\n| Required | No |\n\nControls whether Git integration is enabled.\n\n### `git.base_branch`\n\n| Property | Value |\n|----------|-------|\n| Type | `string` |\n| Default | `\"main\"` |\n| Required | No |\n\nThe base branch name. When no previous commit record is found (the `_last_commit` file does not exist), the system uses this branch as the reference and runs `git merge-base \u003cbase_branch\u003e HEAD` to calculate the comparison starting point.\n\n## Default Values\n\nGit configuration defaults in `DefaultConfig()`:\n\n```go\nGit: GitConfig{\n    Enabled:    true,\n    BaseBranch: \"main\",\n},\n```\n\n\u003e Source: internal/config/config.go#L124-L127\n\n## selfmd.yaml Configuration Example\n\n```yaml\ngit:\n  enabled: true\n  base_branch: main\n```\n\nIf your main branch is named `master`, change `base_branch` to:\n\n```yaml\ngit:\n  enabled: true\n  base_branch: master\n```\n\n## Core Flow\n\nThe following shows how the `selfmd update` command uses Git configuration to determine the comparison range:\n\n```mermaid\nflowchart TD\n    Start[\"Run selfmd update\"]\n    CheckGit{\"IsGitRepo?\"}\n    ErrorNotGit[\"Error: not a Git repository\"]\n    SinceFlag{\"--since flag\\nspecified?\"}\n    ReadSaved{\"Read _last_commit\\nfile\"}\n    UseSince[\"Use specified commit\"]\n    UseSaved[\"Use saved commit\"]\n    GetMergeBase[\"git merge-base\\nbase_branch HEAD\"]\n    GetCurrent[\"git rev-parse HEAD\\nget current commit\"]\n    GetDiff[\"git diff --relative\\n--name-status FROM..TO\"]\n    Filter[\"Filter changed files by\\ntargets.include/exclude\"]\n    Update[\"Run incremental update flow\"]\n    SaveCommit[\"Save current commit\\nto _last_commit\"]\n\n    Start --\u003e CheckGit\n    CheckGit --\u003e|\"No\"| ErrorNotGit\n    CheckGit --\u003e|\"Yes\"| SinceFlag\n    SinceFlag --\u003e|\"Yes\"| UseSince\n    SinceFlag --\u003e|\"No\"| ReadSaved\n    ReadSaved --\u003e|\"Success\"| UseSaved\n    ReadSaved --\u003e|\"Failed\"| GetMergeBase\n    GetMergeBase --\u003e UseSaved\n    UseSince --\u003e GetCurrent\n    UseSaved --\u003e GetCurrent\n    GetCurrent --\u003e GetDiff\n    GetDiff --\u003e Filter\n    Filter --\u003e Update\n    Update --\u003e SaveCommit\n```\n\n## Usage Examples\n\n### Basic Incremental Update\n\nWhen running `selfmd update`, the system will:\n\n1. Read `git.base_branch` from `selfmd.yaml`\n2. Attempt to read the previously saved commit (the `_last_commit` file)\n3. If no record exists, call `git merge-base` with `base_branch` to calculate the starting point\n\n```go\n// Comparison starting point determination logic in cmd/update.go\npreviousCommit := sinceCommit\nif previousCommit == \"\" {\n    saved, readErr := gen.Writer.ReadLastCommit()\n    if readErr == nil \u0026\u0026 saved != \"\" {\n        previousCommit = saved\n    } else {\n        base, err := git.GetMergeBase(rootDir, cfg.Git.BaseBranch)\n        // ...\n        previousCommit = base\n    }\n}\n```\n\n\u003e Source: cmd/update.go#L69-L86\n\n### Specifying a Comparison Starting Point with `--since`\n\nYou can also directly specify a commit hash as the comparison starting point, bypassing the automatic detection logic:\n\n```bash\nselfmd update --since abc1234\n```\n\n### Parsing `git diff` Output\n\nThe `ParseChangedFiles` function in `internal/git/git.go` parses the output of `git diff --name-status`:\n\n```go\n// ChangedFile represents a single file from git diff --name-status output.\ntype ChangedFile struct {\n\tStatus string // \"M\", \"A\", \"D\", \"R\"\n\tPath   string\n}\n\n// ParseChangedFiles parses git diff --name-status output into structured ChangedFile list.\nfunc ParseChangedFiles(changedFiles string) []ChangedFile {\n\tvar result []ChangedFile\n\tfor _, line := range strings.Split(changedFiles, \"\\n\") {\n\t\tline = strings.TrimSpace(line)\n\t\tif line == \"\" {\n\t\t\tcontinue\n\t\t}\n\t\tparts := strings.SplitN(line, \"\\t\", 3)\n\t\tif len(parts) \u003c 2 {\n\t\t\tcontinue\n\t\t}\n\t\tstatus := string(parts[0][0]) // \"M\", \"A\", \"D\", or \"R\" (R100 → R)\n\t\tpath := parts[len(parts)-1]   // for renames, use destination path\n\t\tresult = append(result, ChangedFile{Status: status, Path: path})\n\t}\n\treturn result\n}\n```\n\n\u003e Source: internal/git/git.go#L47-L70\n\n### Filtering Changed Files\n\nAfter obtaining the Git diff results, the system also filters them according to `targets.include` and `targets.exclude` configuration to exclude irrelevant files (such as `vendor/**`, `.git/**`):\n\n```go\nchangedFiles = git.FilterChangedFiles(changedFiles, cfg.Targets.Include, cfg.Targets.Exclude)\n```\n\n\u003e Source: cmd/update.go#L98\n\n## Notes\n\n- Before running `selfmd update`, confirm that the current directory is a Git repository; otherwise the command will immediately report an error\n- Before using incremental updates for the first time, you must run `selfmd generate` to build the initial documentation. If no `_last_commit` record is found, the system will attempt to calculate the merge-base using `base_branch`\n- The `git.enabled` field currently exists in the configuration, but `selfmd update` itself already requires a Git environment regardless of this value\n\n## Related Links\n\n- [Configuration Overview](../index.md)\n- [selfmd.yaml Structure Overview](../config-overview/index.md)\n- [Claude CLI Integration Configuration](../claude-config/index.md)\n- [selfmd update](../../cli/cmd-update/index.md)\n- [Git Diff Change Detection](../../git-integration/change-detection/index.md)\n- [Affected Pages Determination Logic](../../git-integration/affected-pages/index.md)\n- [Incremental Update](../../core-modules/incremental-update/index.md)\n\n## Reference Files\n\n| File Path | Description |\n|-----------|-------------|\n| `internal/config/config.go` | `GitConfig` struct definition, default values, and overall `Config` structure |\n| `internal/git/git.go` | Git operation function implementations, including diff parsing, filtering, and commit queries |\n| `cmd/update.go` | `selfmd update` command implementation, using Git configuration to determine comparison range |\n| `internal/generator/updater.go` | Incremental update logic, calls the Git package for change comparison and documentation regeneration |\n| `internal/output/writer.go` | Read/write implementation for the `_last_commit` file |","en-US/configuration/index.md":"# Configuration Guide\n\nThis section contains the following:\n\n- [selfmd.yaml Structure Overview](config-overview/index.md)\n- [Project and Scan Target Configuration](project-targets/index.md)\n- [Output \u0026 Multilingual Configuration](output-language/index.md)\n- [Claude CLI Integration Settings](claude-config/index.md)\n- [Git Integration Configuration](git-config/index.md)\n","en-US/configuration/output-language/index.md":"# Output \u0026 Multilingual Configuration\n\nThis page describes all fields in the `output` block of `selfmd.yaml`, and how selfmd supports primary-language document generation and automatic secondary-language translation.\n\n## Overview\n\nThe `output` block controls two categories of behavior:\n\n1. **Output directory settings**: Specifies where documents are generated and whether to clear existing files before generation.\n2. **Multilingual settings**: Defines the master language and a list of secondary languages. The master language determines the writing language of the documents and the template selection logic; secondary languages are used by the `selfmd translate` command to batch-translate primary-language documents into the specified languages.\n\nselfmd's multilingual system follows a \"generate first, translate second\" two-phase strategy: first, all technical documents are fully generated in the master language; then, Claude translates each page into the secondary languages. Translation results are stored in `.doc-build/{lang-code}/` subdirectories.\n\n---\n\n## Architecture\n\n```mermaid\nflowchart TD\n    Config[\"selfmd.yaml\\noutput block\"]\n\n    Config --\u003e Dir[\"output.dir\\nOutput root directory\"]\n    Config --\u003e Lang[\"output.language\\nMaster language\"]\n    Config --\u003e SecLangs[\"output.secondary_languages\\nSecondary language list\"]\n    Config --\u003e Clean[\"output.clean_before_generate\\nClean before generate\"]\n\n    Lang --\u003e TemplateLang[\"GetEffectiveTemplateLang()\\nGet template language\"]\n    Lang --\u003e LangOverride[\"NeedsLanguageOverride()\\nWhether language override is needed\"]\n\n    TemplateLang --\u003e |\"zh-TW or en-US\"| BuiltinTmpl[\"Use corresponding built-in template\\ntemplates/zh-TW/\\ntemplates/en-US/\"]\n    TemplateLang --\u003e |\"Other languages\"| FallbackTmpl[\"Fall back to en-US template\\n+ language override instruction\"]\n\n    SecLangs --\u003e TranslateCmd[\"selfmd translate\"]\n    TranslateCmd --\u003e TranslatePhase[\"TranslatePhase\\nTranslation pipeline\"]\n    TranslatePhase --\u003e LangDir[\".doc-build/{lang}/\\nPer-language subdirectory\"]\n\n    Dir --\u003e MasterOut[\".doc-build/\\nMaster language output\"]\n    Dir --\u003e LangDir\n```\n\n---\n\n## Configuration Field Reference\n\nThe complete structure definition of the `output` block is as follows:\n\n```go\ntype OutputConfig struct {\n    Dir                 string   `yaml:\"dir\"`\n    Language            string   `yaml:\"language\"`\n    SecondaryLanguages  []string `yaml:\"secondary_languages\"`\n    CleanBeforeGenerate bool     `yaml:\"clean_before_generate\"`\n}\n```\n\n\u003e Source: internal/config/config.go#L31-L36\n\n### `output.dir`\n\n| Field | Description |\n|-------|-------------|\n| Type | `string` |\n| Default | `.doc-build` |\n| Description | The output root directory for all documents. Primary-language documents are placed directly in this directory; secondary-language documents are placed in `{dir}/{lang}/` subdirectories. |\n\n### `output.language`\n\n| Field | Description |\n|-------|-------------|\n| Type | `string` |\n| Default | `zh-TW` |\n| Validation | Must not be an empty string |\n| Description | The primary language code (BCP 47 format). Determines which Claude prompt template is selected and the output language of the generated documents. |\n\n### `output.secondary_languages`\n\n| Field | Description |\n|-------|-------------|\n| Type | `[]string` |\n| Default | `[]` (empty list) |\n| Description | List of secondary language codes. When `selfmd translate` is run, it translates the primary-language documents into each of these languages in turn. If this field is empty, the `translate` command returns an error. |\n\n### `output.clean_before_generate`\n\n| Field | Description |\n|-------|-------------|\n| Type | `bool` |\n| Default | `false` |\n| Description | When set to `true`, the output directory is deleted and recreated before each `selfmd generate` run. Equivalent to running `generate --clean` every time. |\n\n---\n\n## Full Configuration Example\n\nThe following is a typical configuration with multilingual support enabled:\n\n```yaml\noutput:\n  dir: .doc-build\n  language: zh-TW\n  secondary_languages:\n    - en-US\n    - ja-JP\n  clean_before_generate: false\n```\n\n\u003e Source: internal/config/config.go#L110-L115 (DefaultConfig function)\n\n---\n\n## Supported Language Codes\n\nselfmd has the following language codes and their corresponding native names built in. When these codes are used, the language names are automatically displayed in the document navigation and translation pipeline output:\n\n```go\nvar KnownLanguages = map[string]string{\n    \"zh-TW\": \"繁體中文\",\n    \"zh-CN\": \"简体中文\",\n    \"en-US\": \"English\",\n    \"ja-JP\": \"日本語\",\n    \"ko-KR\": \"한국어\",\n    \"fr-FR\": \"Français\",\n    \"de-DE\": \"Deutsch\",\n    \"es-ES\": \"Español\",\n    \"pt-BR\": \"Português\",\n    \"th-TH\": \"ไทย\",\n    \"vi-VN\": \"Tiếng Việt\",\n}\n```\n\n\u003e Source: internal/config/config.go#L39-L51\n\nUsing a language code not in `KnownLanguages` (e.g., `it-IT`) will still work, but the language name will be displayed as the code itself (e.g., `it-IT`).\n\n---\n\n## Prompt Template Language \u0026 Language Override Mechanism\n\nselfmd provides built-in prompt templates for only the following two languages:\n\n```go\nvar SupportedTemplateLangs = []string{\"zh-TW\", \"en-US\"}\n```\n\n\u003e Source: internal/config/config.go#L54\n\nWhen `output.language` is set to a language outside of `SupportedTemplateLangs`, the system automatically falls back to the `en-US` template and adds an explicit language override instruction to the prompt, directing Claude to output documents in the specified language.\n\nThis logic is implemented by the following two methods:\n\n```go\n// GetEffectiveTemplateLang returns which template folder to load.\n// If Language has a built-in template set, returns it; otherwise falls back to \"en-US\".\nfunc (o *OutputConfig) GetEffectiveTemplateLang() string {\n    for _, lang := range SupportedTemplateLangs {\n        if o.Language == lang {\n            return o.Language\n        }\n    }\n    return \"en-US\"\n}\n\n// NeedsLanguageOverride returns true when the template language differs from Language,\n// meaning the prompt needs an explicit instruction to output in the configured language.\nfunc (o *OutputConfig) NeedsLanguageOverride() bool {\n    return o.GetEffectiveTemplateLang() != o.Language\n}\n```\n\n\u003e Source: internal/config/config.go#L58-L71\n\n### Template Language Selection Logic\n\n```mermaid\nflowchart TD\n    Start[\"output.language value\"]\n    Check{\"Is it in\\nSupportedTemplateLangs?\"}\n    UseNative[\"Use the corresponding language template\\n(zh-TW or en-US)\"]\n    Fallback[\"Fall back to en-US template\"]\n    Override[\"NeedsLanguageOverride = true\\nAdd language instruction to prompt\"]\n    NoOverride[\"NeedsLanguageOverride = false\\nTemplate language is the output language\"]\n\n    Start --\u003e Check\n    Check --\u003e|Yes| UseNative --\u003e NoOverride\n    Check --\u003e|No| Fallback --\u003e Override\n```\n\nDuring `Generator` initialization, `GetEffectiveTemplateLang()` is called to select the correct template folder:\n\n```go\nfunc NewGenerator(cfg *config.Config, rootDir string, logger *slog.Logger) (*Generator, error) {\n    templateLang := cfg.Output.GetEffectiveTemplateLang()\n    engine, err := prompt.NewEngine(templateLang)\n    if err != nil {\n        return nil, err\n    }\n    // ...\n}\n```\n\n\u003e Source: internal/generator/pipeline.go#L34-L38\n\n---\n\n## Multilingual Output Directory Structure\n\nWhen secondary languages are enabled, the output directory structure is as follows:\n\n```\n.doc-build/                    ← Master language (output.language)\n├── index.html                 ← Static browser\n├── _catalog.json              ← Master language catalog data\n├── index.md\n├── _sidebar.md\n└── {section}/\n    └── {page}/\n        └── index.md\n\n.doc-build/en-US/              ← Secondary language (secondary_languages[0])\n├── _catalog.json\n├── index.md\n├── _sidebar.md\n└── {section}/\n    └── {page}/\n        └── index.md\n\n.doc-build/ja-JP/              ← Secondary language (secondary_languages[1])\n└── ...\n```\n\nThe `Writer.ForLanguage()` method creates a new `Writer` instance pointing to the language subdirectory:\n\n```go\n// ForLanguage returns a new Writer that writes to a language-specific subdirectory.\nfunc (w *Writer) ForLanguage(lang string) *Writer {\n    return \u0026Writer{\n        BaseDir: filepath.Join(w.BaseDir, lang),\n    }\n}\n```\n\n\u003e Source: internal/output/writer.go#L139-L143\n\n---\n\n## Language Metadata for the Document Browser\n\nAfter running `selfmd generate` or `selfmd translate`, the system generates a `DocMeta` object that records all available language information for use by the static document browser:\n\n```go\nfunc (g *Generator) buildDocMeta() *output.DocMeta {\n    meta := \u0026output.DocMeta{\n        DefaultLanguage: g.Config.Output.Language,\n        AvailableLanguages: []output.LangInfo{\n            {\n                Code:       g.Config.Output.Language,\n                NativeName: config.GetLangNativeName(g.Config.Output.Language),\n                IsDefault:  true,\n            },\n        },\n    }\n    for _, lang := range g.Config.Output.SecondaryLanguages {\n        meta.AvailableLanguages = append(meta.AvailableLanguages, output.LangInfo{\n            Code:       lang,\n            NativeName: config.GetLangNativeName(lang),\n            IsDefault:  false,\n        })\n    }\n    return meta\n}\n```\n\n\u003e Source: internal/generator/pipeline.go#L184-L203\n\n---\n\n## Translate Command Integration\n\nThe `secondary_languages` configuration determines the translation targets for `selfmd translate`. The following is the validation logic at the CLI layer:\n\n```go\nif len(cfg.Output.SecondaryLanguages) == 0 {\n    return fmt.Errorf(\"設定檔中未定義 secondary_languages，無法翻譯\")\n}\n\n// Determine target languages\ntargetLangs := cfg.Output.SecondaryLanguages\nif len(translateLangs) \u003e 0 {\n    // Validate specified languages are in the config\n    validLangs := make(map[string]bool)\n    for _, l := range cfg.Output.SecondaryLanguages {\n        validLangs[l] = true\n    }\n    for _, l := range translateLangs {\n        if !validLangs[l] {\n            return fmt.Errorf(\"語言 %s 不在 secondary_languages 列表中（可用：%s）\", l, strings.Join(cfg.Output.SecondaryLanguages, \", \"))\n        }\n    }\n    targetLangs = translateLangs\n}\n```\n\n\u003e Source: cmd/translate.go#L49-L67\n\nThe `--lang` flag can be used to translate only a subset of languages, but the specified languages must already be defined in `secondary_languages`; otherwise a validation error is returned.\n\n---\n\n## Language Localization for Navigation Pages\n\nUI strings in navigation pages such as `output.md`, `index.md`, and `_sidebar.md` also support multiple languages. Currently, `zh-TW` and `en-US` UI string sets are built in; other languages automatically fall back to `en-US`:\n\n```go\nvar UIStrings = map[string]map[string]string{\n    \"zh-TW\": {\n        \"techDocs\":        \"技術文件\",\n        \"catalog\":         \"目錄\",\n        \"home\":            \"首頁\",\n        \"sectionContains\": \"本章節包含以下內容：\",\n        \"autoGenerated\":   \"本文件由 [selfmd](https://github.com/monkenwu/selfmd) 自動產生\",\n    },\n    \"en-US\": {\n        \"techDocs\":        \"Technical Documentation\",\n        \"catalog\":         \"Table of Contents\",\n        \"home\":            \"Home\",\n        \"sectionContains\": \"This section contains the following:\",\n        \"autoGenerated\":   \"This documentation was automatically generated by [selfmd](https://github.com/monkenwu/selfmd)\",\n    },\n}\n```\n\n\u003e Source: internal/output/navigation.go#L12-L27\n\n---\n\n## Related Links\n\n- [selfmd.yaml Structure Overview](../config-overview/index.md)\n- [Project \u0026 Scan Target Configuration](../project-targets/index.md)\n- [Claude CLI Integration Configuration](../claude-config/index.md)\n- [selfmd translate Command](../../cli/cmd-translate/index.md)\n- [Supported Languages \u0026 Templates](../../i18n/supported-languages/index.md)\n- [Translation Workflow](../../i18n/translation-workflow/index.md)\n- [Translation Phase](../../core-modules/generator/translate-phase/index.md)\n- [Prompt Template Engine](../../core-modules/prompt-engine/index.md)\n\n---\n\n## Reference Files\n\n| File Path | Description |\n|-----------|-------------|\n| `internal/config/config.go` | `OutputConfig` struct definition, `KnownLanguages`, `SupportedTemplateLangs`, `GetEffectiveTemplateLang()`, `NeedsLanguageOverride()`, `GetLangNativeName()` |\n| `internal/generator/pipeline.go` | `Generator` initialization (template language selection), `buildDocMeta()` (multilingual metadata) |\n| `internal/generator/translate_phase.go` | Translation pipeline main logic, `translatePages()`, `buildTranslatedCatalog()` |\n| `internal/output/writer.go` | `DocMeta`, `LangInfo` definitions, `ForLanguage()` method |\n| `internal/output/navigation.go` | `UIStrings` multilingual UI strings, `GenerateIndex()`, `GenerateSidebar()` |\n| `internal/prompt/engine.go` | `TranslatePromptData` definition, `RenderTranslate()` method |\n| `internal/prompt/templates/translate.tmpl` | Translation prompt template (shared, language-agnostic) |\n| `cmd/translate.go` | `translate` command implementation, `secondary_languages` validation logic |\n| `cmd/init.go` | `init` command implementation (demonstrates default output settings) |","en-US/configuration/project-targets/index.md":"# Project and Scan Target Configuration\n\nThe `project` and `targets` top-level sections in `selfmd.yaml` define the basic information and scan scope for the documentation target. These two configuration sections are the core basis for selfmd to understand \"which files in which project\" to generate documentation for.\n\n## Overview\n\nWhen selfmd executes the `generate` or `update` command, it first reads the configuration file, then delegates to the Scanner to traverse directories according to the `include` and `exclude` rules in `targets`, filtering out the source code files that need to be analyzed. The `project` section provides metadata such as the project name and type, serving as important context for Claude when generating documentation.\n\nKey concepts:\n- **Glob pattern**: A path-matching syntax using `**` wildcards to match multiple directory levels, implemented under the hood by the `doublestar` library.\n- **Entry points**: Specific files that are read in full and passed entirely to Claude, typically program entry points such as `main.go` or `cmd/root.go`.\n- **Exclude takes priority**: Exclude rules take precedence over include rules. If a path matches both, the exclusion wins.\n\nThe `selfmd init` command automatically detects the project type and generates a configuration file with sensible defaults. Users typically only need to fine-tune `include`/`exclude`.\n\n## Architecture\n\n```mermaid\nflowchart TD\n    YAML[\"selfmd.yaml\"]\n    Load[\"config.Load()\"]\n    ProjectConfig[\"ProjectConfig\\n(name, type, description)\"]\n    TargetsConfig[\"TargetsConfig\\n(include, exclude, entry_points)\"]\n    Scanner[\"scanner.Scan()\"]\n    WalkDir[\"filepath.WalkDir()\"]\n    ExcludeCheck[\"Exclude rule check\\ndoublestar.Match(exclude)\"]\n    IncludeCheck[\"Include rule check\\ndoublestar.Match(include)\"]\n    ScanResult[\"ScanResult\\n(FileList, Tree, EntryPointContents)\"]\n    CatalogPhase[\"GenerateCatalog()\\nCatalog generation phase\"]\n\n    YAML --\u003e Load\n    Load --\u003e ProjectConfig\n    Load --\u003e TargetsConfig\n    TargetsConfig --\u003e Scanner\n    Scanner --\u003e WalkDir\n    WalkDir --\u003e ExcludeCheck\n    ExcludeCheck --\u003e|\"No match → continue\"| IncludeCheck\n    ExcludeCheck --\u003e|\"Match → skip\"| WalkDir\n    IncludeCheck --\u003e|\"Match → include\"| ScanResult\n    IncludeCheck --\u003e|\"No match → ignore\"| WalkDir\n    ProjectConfig --\u003e CatalogPhase\n    ScanResult --\u003e CatalogPhase\n```\n\n## The `project` Section\n\nThe `project` section provides basic descriptive information about the current project. This information is injected directly into Claude's prompt to help the AI understand the project context.\n\n```yaml\nproject:\n  name: selfmd\n  type: backend\n  description: \"\"\n```\n\n### Field Reference\n\n| Field | Type | Required | Default | Description |\n|-------|------|----------|---------|-------------|\n| `name` | string | No | Current directory name | Project name, displayed in document titles and the static browser |\n| `type` | string | No | `backend` | Project type, hints to Claude about the documentation structure style |\n| `description` | string | No | Empty string | Additional project description (optional) |\n\n### Available `type` Values\n\nThe auto-detection logic in `selfmd init` determines the project type based on specific indicator files:\n\n```go\nchecks := []struct {\n    file       string\n    pType      string\n    entries    []string\n}{\n    {\"go.mod\", \"backend\", []string{\"main.go\", \"cmd/root.go\"}},\n    {\"Cargo.toml\", \"backend\", []string{\"src/main.rs\", \"src/lib.rs\"}},\n    {\"package.json\", \"frontend\", []string{\"src/index.ts\", \"src/index.js\", \"src/main.ts\", \"src/App.tsx\"}},\n    {\"pom.xml\", \"backend\", []string{\"src/main/java\"}},\n    {\"build.gradle\", \"backend\", []string{\"src/main/java\"}},\n    {\"requirements.txt\", \"backend\", []string{\"main.py\", \"app.py\", \"src/main.py\"}},\n    {\"pyproject.toml\", \"backend\", []string{\"src/main.py\", \"main.py\"}},\n    {\"composer.json\", \"backend\", []string{\"public/index.php\", \"src/Kernel.php\"}},\n    {\"Gemfile\", \"backend\", []string{\"config/application.rb\", \"app/\"}},\n}\n```\n\n\u003e Source: `cmd/init.go#L61-L75`\n\n| `type` Value | Meaning |\n|--------------|---------|\n| `backend` | Backend services, APIs, CLI tools |\n| `frontend` | Frontend applications (SPA, Web App) |\n| `fullstack` | Full-stack projects containing both frontend and backend |\n| `library` | Libraries or projects where no indicator file is detected |\n\nIf both `package.json` and `go.mod` (or a `server/` directory) exist simultaneously, the project is automatically classified as `fullstack`.\n\n## The `targets` Section\n\nThe `targets` section controls which files the scanner should analyze, and is the most critical configuration affecting documentation coverage.\n\n```yaml\ntargets:\n  include:\n    - src/**\n    - pkg/**\n    - cmd/**\n    - internal/**\n    - lib/**\n    - app/**\n  exclude:\n    - vendor/**\n    - node_modules/**\n    - .git/**\n    - .doc-build/**\n    - \"**/*.pb.go\"\n    - \"**/generated/**\"\n    - dist/**\n    - build/**\n  entry_points:\n    - main.go\n    - cmd/root.go\n```\n\n### Field Reference\n\n| Field | Type | Required | Default | Description |\n|-------|------|----------|---------|-------------|\n| `include` | []string | No | See below | Path patterns (glob) to scan; an empty array means all files are included |\n| `exclude` | []string | No | See below | Path patterns (glob) to exclude; takes priority over include |\n| `entry_points` | []string | No | `[]` | Paths to important files that are read in full and injected into the prompt |\n\n### Default `include` Patterns\n\n```go\nInclude: []string{\"src/**\", \"pkg/**\", \"cmd/**\", \"internal/**\", \"lib/**\", \"app/**\"},\n```\n\n\u003e Source: `internal/config/config.go#L103`\n\n### Default `exclude` Patterns\n\n```go\nExclude: []string{\n    \"vendor/**\", \"node_modules/**\", \".git/**\", \".doc-build/**\",\n    \"**/*.pb.go\", \"**/generated/**\", \"dist/**\", \"build/**\",\n},\n```\n\n\u003e Source: `internal/config/config.go#L104-L108`\n\n## Scan Rule Execution Order\n\nWhen the scanner traverses directories, exclude rules take higher priority than include rules. When a directory is matched by an exclude rule during traversal, the entire subdirectory tree is skipped immediately (`filepath.SkipDir`), significantly improving performance.\n\n```go\n// check excludes\nfor _, pattern := range cfg.Targets.Exclude {\n    matched, _ := doublestar.Match(pattern, rel)\n    if matched {\n        if d.IsDir() {\n            return filepath.SkipDir\n        }\n        return nil\n    }\n}\n\n// ...（directories themselves are not filtered by include rules）\n\n// check includes\nif len(cfg.Targets.Include) \u003e 0 {\n    included := false\n    for _, pattern := range cfg.Targets.Include {\n        matched, _ := doublestar.Match(pattern, rel)\n        if matched {\n            included = true\n            break\n        }\n    }\n    if !included {\n        return nil\n    }\n}\n```\n\n\u003e Source: `internal/scanner/scanner.go#L33-L61`\n\n### Filtering Flow\n\n```mermaid\nflowchart TD\n    Start([\"Traverse path\"])\n    IsExcluded{\"Matches exclude\\npattern?\"}\n    IsDir{\"Is directory?\"}\n    SkipDir[\"SkipDir\\nSkip entire subtree\"]\n    SkipFile[\"Skip this file\"]\n    CountDir[\"Count in totalDirs\"]\n    IsIncluded{\"Matches include\\npattern?\\n(when include is non-empty)\"}\n    AddFile[\"Add to files list\"]\n    Done([\"Done with this path\"])\n\n    Start --\u003e IsExcluded\n    IsExcluded --\u003e|Yes| IsDir\n    IsDir --\u003e|Directory| SkipDir --\u003e Done\n    IsDir --\u003e|File| SkipFile --\u003e Done\n    IsExcluded --\u003e|No| IsDir2{\"Is directory?\"}\n    IsDir2 --\u003e|Yes| CountDir --\u003e Done\n    IsDir2 --\u003e|No| IsIncluded\n    IsIncluded --\u003e|Yes| AddFile --\u003e Done\n    IsIncluded --\u003e|No| Done\n```\n\n## The Role of Entry Points\n\nFiles specified in `entry_points` are read after scanning is complete. Their full contents are formatted and injected into Claude's catalog generation prompt (`CatalogPromptData.EntryPoints`). This allows Claude to read the most core program logic directly when understanding the project structure.\n\n```go\n// read entry points\nentryPointContents := make(map[string]string)\nfor _, ep := range cfg.Targets.EntryPoints {\n    content := readFileIfExists(rootDir, ep)\n    if content != \"\" {\n        entryPointContents[ep] = content\n    }\n}\n```\n\n\u003e Source: `internal/scanner/scanner.go#L83-L91`\n\nEntry point files are truncated to 10,000 characters to avoid exceeding context limits, and are passed as Markdown code blocks:\n\n```go\nfunc (s *ScanResult) EntryPointsFormatted() string {\n    if len(s.EntryPointContents) == 0 {\n        return \"(no entry points specified)\"\n    }\n\n    var sb strings.Builder\n    for path, content := range s.EntryPointContents {\n        sb.WriteString(\"### \" + path + \"\\n```\\n\")\n        // truncate large files\n        if len(content) \u003e 10000 {\n            content = content[:10000] + \"\\n... (truncated)\"\n        }\n        sb.WriteString(content)\n        sb.WriteString(\"\\n```\\n\\n\")\n    }\n    return sb.String()\n}\n```\n\n\u003e Source: `internal/scanner/scanner.go#L143-L160`\n\n## Common Configuration Examples\n\n### Go Backend Project (Default)\n\n```yaml\nproject:\n  name: my-service\n  type: backend\n\ntargets:\n  include:\n    - cmd/**\n    - internal/**\n    - pkg/**\n  exclude:\n    - vendor/**\n    - .doc-build/**\n    - \"**/*.pb.go\"\n  entry_points:\n    - main.go\n    - cmd/root.go\n```\n\n### Node.js Frontend Project\n\n```yaml\nproject:\n  name: my-frontend\n  type: frontend\n\ntargets:\n  include:\n    - src/**\n    - components/**\n    - pages/**\n  exclude:\n    - node_modules/**\n    - dist/**\n    - \"**/*.test.ts\"\n  entry_points:\n    - src/main.ts\n    - src/App.tsx\n```\n\n### Excluding Specific Directories and File Types\n\n```yaml\ntargets:\n  include:\n    - src/**\n  exclude:\n    - src/vendor/**\n    - \"**/*.generated.go\"\n    - \"**/testdata/**\"\n    - \"**/*_test.go\"\n```\n\n## Related Links\n\n- [selfmd.yaml Structure Overview](../config-overview/index.md)\n- [Output and Language Configuration](../output-language/index.md)\n- [Claude CLI Integration Configuration](../claude-config/index.md)\n- [Git Integration Configuration](../git-config/index.md)\n- [Project Scanner](../../core-modules/scanner/index.md)\n- [selfmd init Command](../../cli/cmd-init/index.md)\n\n## Reference Files\n\n| File Path | Description |\n|-----------|-------------|\n| `internal/config/config.go` | `Config`, `ProjectConfig`, `TargetsConfig` struct definitions, defaults, loading and validation logic |\n| `internal/scanner/scanner.go` | `Scan()` implementation: directory traversal, include/exclude filtering, entry point reading |\n| `internal/scanner/filetree.go` | `ScanResult`, `FileNode` struct definitions; `BuildTree()`, `RenderTree()` implementation |\n| `cmd/init.go` | `init` command implementation; `detectProject()` auto-detection of project type and entry points |\n| `internal/prompt/engine.go` | `CatalogPromptData` struct, showing how `ProjectType`, `EntryPoints`, and `FileTree` are injected into the prompt |\n| `internal/generator/catalog_phase.go` | Catalog generation phase, showing how `ProjectConfig` and `ScanResult` are combined into a prompt |\n| `internal/generator/pipeline.go` | Full pipeline flow, showing when and in what context `scanner.Scan()` is called |","en-US/core-modules/catalog/index.md":"# Documentation Catalog Management\n\nThe `catalog` module is the core data structure layer of selfmd, responsible for defining, parsing, flattening, and serializing the full documentation tree, and providing a unified data access interface for downstream content generation, navigation output, and incremental updates.\n\n## Overview\n\nThe documentation catalog (Catalog) is the backbone of selfmd's entire generation pipeline. It is generated once by Claude based on the project source code structure, persisted in JSON format in the output directory, and repeatedly read and used across all subsequent phases (content generation, navigation output, incremental updates).\n\nCore concepts:\n\n- **Catalog**: The root node of the catalog, holding a set of `CatalogItem` entries as top-level sections\n- **CatalogItem**: A tree node that can recursively contain child nodes, representing a documentation section\n- **FlatItem**: A flattened linear node containing full path information computed via depth-first traversal, used by downstream modules\n- **dot-notation path**: e.g., `core-modules.authentication`, used as the unique identifier for a catalog entry\n- **filesystem path**: e.g., `core-modules/authentication`, corresponding to the actual output directory structure\n\nThe catalog management module solves the full conversion chain from \"tree structure → linear iterable list → filesystem directories\", while being compatible with the two path formats returned by Claude (relative path Format A and full path with parent Format B).\n\n## Architecture\n\n```mermaid\nflowchart TD\n    subgraph catalog[\"internal/catalog/catalog.go\"]\n        Catalog[\"Catalog\\n{ Items: []CatalogItem }\"]\n        CatalogItem[\"CatalogItem\\n{ Title, Path, Order, Children }\"]\n        FlatItem[\"FlatItem\\n{ Title, Path, DirPath, Depth,\\nParentPath, HasChildren }\"]\n        Parse[\"Parse(data string)\"]\n        Flatten[\"Flatten()\"]\n        ToJSON[\"ToJSON()\"]\n        BuildLinkTable[\"BuildLinkTable()\"]\n    end\n\n    subgraph generator[\"internal/generator/\"]\n        CatalogPhase[\"catalog_phase.go\\nGenerateCatalog()\"]\n        Pipeline[\"pipeline.go\\nGenerate()\"]\n        ContentPhase[\"content_phase.go\\nGenerateContent()\"]\n        IndexPhase[\"index_phase.go\\nGenerateIndex()\"]\n        Updater[\"updater.go\\nUpdate()\"]\n    end\n\n    subgraph outputPkg[\"internal/output/\"]\n        Navigation[\"navigation.go\\nGenerateIndex/Sidebar\"]\n        Writer[\"writer.go\\nWriteCatalogJSON / ReadCatalogJSON\"]\n        LinkFixer[\"linkfixer.go\\nNewLinkFixer()\"]\n    end\n\n    Claude[\"Claude CLI Runner\"] --\u003e|JSON response| CatalogPhase\n    CatalogPhase --\u003e|Parse| Catalog\n    Catalog --\u003e CatalogItem\n    CatalogItem --\u003e|Flatten| FlatItem\n    Catalog --\u003e Flatten\n    Flatten --\u003e FlatItem\n\n    Pipeline --\u003e CatalogPhase\n    Pipeline --\u003e ContentPhase\n    Pipeline --\u003e IndexPhase\n\n    ContentPhase --\u003e|BuildLinkTable| BuildLinkTable\n    ContentPhase --\u003e|Flatten| FlatItem\n    IndexPhase --\u003e|Flatten| FlatItem\n    Updater --\u003e|Parse, Flatten,\\nBuildLinkTable| Catalog\n\n    Navigation --\u003e|Items| Catalog\n    Writer --\u003e|WriteCatalogJSON| ToJSON\n    Writer --\u003e|ReadCatalogJSON → Parse| Parse\n    LinkFixer --\u003e|Flatten| FlatItem\n```\n\n## Data Structures\n\n### Catalog and CatalogItem\n\n```go\n// Catalog represents the documentation catalog structure.\ntype Catalog struct {\n\tItems []CatalogItem `json:\"items\"`\n}\n\n// CatalogItem represents a single item in the catalog tree.\ntype CatalogItem struct {\n\tTitle    string        `json:\"title\"`\n\tPath     string        `json:\"path\"`\n\tOrder    int           `json:\"order\"`\n\tChildren []CatalogItem `json:\"children\"`\n}\n```\n\n\u003e Source: `internal/catalog/catalog.go#L9-L20`\n\n`CatalogItem.Path` stores either a **path segment relative to the parent node** (e.g., `authentication`) or a **full filesystem path** (e.g., `core-modules/authentication`), depending on the format returned by Claude. The `flattenItem` function normalizes both to dot-notation.\n\n### FlatItem\n\n```go\n// FlatItem represents a flattened catalog item with computed paths.\ntype FlatItem struct {\n\tTitle      string\n\tPath       string // dot-notation path, e.g., \"core-modules.authentication\"\n\tDirPath    string // filesystem path, e.g., \"core-modules/authentication\"\n\tDepth      int\n\tParentPath string\n\tHasChildren bool\n}\n```\n\n\u003e Source: `internal/catalog/catalog.go#L22-L30`\n\n`FlatItem` is the primary consumption interface for downstream modules. `DirPath` directly corresponds to the subdirectory structure under `.doc-build/`.\n\n## Core Methods\n\n### Parse — Parse JSON Catalog\n\n```go\n// Parse parses a JSON string into a Catalog.\nfunc Parse(data string) (*Catalog, error) {\n\tvar cat Catalog\n\tif err := json.Unmarshal([]byte(data), \u0026cat); err != nil {\n\t\treturn nil, fmt.Errorf(\"目錄 JSON 解析失敗: %w\", err)\n\t}\n\n\tif len(cat.Items) == 0 {\n\t\treturn nil, fmt.Errorf(\"目錄不可為空\")\n\t}\n\n\treturn \u0026cat, nil\n}\n```\n\n\u003e Source: `internal/catalog/catalog.go#L32-L44`\n\n`Parse` is the entry point for the catalog, called in two scenarios:\n1. Immediately after `GenerateCatalog()` receives the JSON response from Claude\n2. When `Generate()` in `pipeline.go` attempts to load an existing `_catalog.json`\n\n### Flatten — Depth-First Flattening\n\n```go\n// Flatten returns all catalog items in depth-first order.\nfunc (c *Catalog) Flatten() []FlatItem {\n\tvar items []FlatItem\n\tfor _, item := range c.Items {\n\t\tflattenItem(\u0026items, item, \"\", 0)\n\t}\n\treturn items\n}\n```\n\n\u003e Source: `internal/catalog/catalog.go#L46-L53`\n\n`Flatten` traverses the entire tree in depth-first order (DFS), outputting a linear `[]FlatItem`. Its core logic is implemented recursively by `flattenItem`, compatible with both path formats:\n\n```go\nfunc flattenItem(items *[]FlatItem, item CatalogItem, parentPath string, depth int) {\n\t// Handle both formats:\n\t// Format A: child.Path = \"introduction\" (relative, needs parent prefix)\n\t// Format B: child.Path = \"overview/introduction\" (already includes parent)\n\tpath := item.Path\n\tdirPath := strings.ReplaceAll(path, \".\", \"/\")\n\n\tif parentPath != \"\" {\n\t\tparentDir := strings.ReplaceAll(parentPath, \".\", \"/\")\n\t\tif !strings.HasPrefix(dirPath, parentDir+\"/\") {\n\t\t\tpath = parentPath + \".\" + item.Path\n\t\t\tdirPath = strings.ReplaceAll(path, \".\", \"/\")\n\t\t} else {\n\t\t\tpath = strings.ReplaceAll(dirPath, \"/\", \".\")\n\t\t}\n\t}\n\t// ...\n}\n```\n\n\u003e Source: `internal/catalog/catalog.go#L55-L87`\n\n### BuildLinkTable — Build Prompt Link Table\n\n```go\n// BuildLinkTable returns a formatted string showing all catalog items\n// and their corresponding directory paths, for use in prompts.\nfunc (c *Catalog) BuildLinkTable() string {\n\titems := c.Flatten()\n\tvar sb strings.Builder\n\tfor _, item := range items {\n\t\tindent := strings.Repeat(\"  \", item.Depth)\n\t\tsb.WriteString(fmt.Sprintf(\"%s- 「%s」 → %s/index.md\\n\", indent, item.Title, item.DirPath))\n\t}\n\treturn sb.String()\n}\n```\n\n\u003e Source: `internal/catalog/catalog.go#L103-L113`\n\nThe string produced by this method is embedded into the content.tmpl prompt, allowing Claude to correctly reference other pages' paths when writing the \"Related Links\" section of each page.\n\n### ToJSON — Serialize to JSON\n\n```go\n// ToJSON serializes the catalog to indented JSON.\nfunc (c *Catalog) ToJSON() (string, error) {\n\tdata, err := json.MarshalIndent(c, \"\", \"  \")\n\tif err != nil {\n\t\treturn \"\", err\n\t}\n\treturn string(data), nil\n}\n```\n\n\u003e Source: `internal/catalog/catalog.go#L89-L96`\n\n`ToJSON` works together with `output.Writer.WriteCatalogJSON()` to persist the catalog to `.doc-build/_catalog.json` for subsequent incremental updates (`selfmd update`) to re-read.\n\n## Core Flows\n\n### Catalog Lifecycle\n\n```mermaid\nsequenceDiagram\n    participant Pipeline as pipeline.go\n    participant CatalogPhase as catalog_phase.go\n    participant CatalogPkg as catalog.go\n    participant Writer as output/writer.go\n    participant Claude as Claude CLI\n\n    Pipeline-\u003e\u003eWriter: ReadCatalogJSON()\n    alt _catalog.json exists and is readable\n        Writer--\u003e\u003ePipeline: JSON string\n        Pipeline-\u003e\u003eCatalogPkg: Parse(jsonStr)\n        CatalogPkg--\u003e\u003ePipeline: *Catalog (reusing existing catalog)\n    else does not exist or needs fresh generation\n        Pipeline-\u003e\u003eCatalogPhase: GenerateCatalog(scan)\n        CatalogPhase-\u003e\u003eClaude: RunWithRetry (catalog prompt)\n        Claude--\u003e\u003eCatalogPhase: JSON response\n        CatalogPhase-\u003e\u003eCatalogPkg: ExtractJSONBlock → Parse()\n        CatalogPkg--\u003e\u003eCatalogPhase: *Catalog\n        CatalogPhase-\u003e\u003eWriter: WriteCatalogJSON(cat)\n        CatalogPhase--\u003e\u003ePipeline: *Catalog\n    end\n\n    Pipeline-\u003e\u003eCatalogPkg: Flatten()\n    CatalogPkg--\u003e\u003ePipeline: []FlatItem (all pages)\n\n    Pipeline-\u003e\u003eCatalogPkg: BuildLinkTable()\n    CatalogPkg--\u003e\u003ePipeline: link table string (injected into prompt)\n```\n\n### Catalog Expansion During Incremental Updates\n\nWhen `selfmd update` detects changed files not covered by existing documentation, it dynamically adds entries to the catalog:\n\n```mermaid\nflowchart TD\n    A[\"unmatched changed files\"] --\u003e B[\"determineUnmatchedPages()\"]\n    B --\u003e C[\"Claude determines if new pages are needed\"]\n    C --\u003e D{\"Need to add?\"}\n    D --\u003e|Yes| E[\"addItemToCatalog(cat, catalogPath, title)\"]\n    D --\u003e|No| F[\"Skip\"]\n    E --\u003e G{\"Target parent node exists\\nand is currently a leaf node?\"}\n    G --\u003e|Yes, upgrade needed| H[\"insertOverviewChild\\noriginal leaf node → .overview child node\"]\n    G --\u003e|No| I[\"Insert new leaf node directly\"]\n    H --\u003e J[\"WriteCatalogJSON (persist update)\"]\n    I --\u003e J\n    J --\u003e K[\"Rebuild BuildLinkTable and LinkFixer\"]\n```\n\n\u003e Source: `internal/generator/updater.go#L369-L430`\n\n## Usage Examples\n\n### Get All Pages in the Generator\n\n```go\n// In content_phase.go, get the linear list of the catalog and generate each page concurrently\nitems := cat.Flatten()\ncatalogTable := cat.BuildLinkTable()\nlinkFixer := output.NewLinkFixer(cat)\n\nfor _, item := range items {\n    // Each item is a FlatItem; use item.DirPath directly to write files\n    err := g.generateSinglePage(ctx, scan, item, catalogTable, linkFixer, \"\")\n}\n```\n\n\u003e Source: `internal/generator/content_phase.go#L22-L55`\n\n### Persist Catalog with WriteCatalogJSON\n\n```go\n// In pipeline.go, persist the catalog immediately after generation\nif err := g.Writer.WriteCatalogJSON(cat); err != nil {\n    g.Logger.Warn(\"保存目錄 JSON 失敗\", \"error\", err)\n}\n```\n\n\u003e Source: `internal/generator/pipeline.go#L124-L126`\n\n### Read Existing Catalog (Incremental Update)\n\n```go\n// In updater.go, read the catalog from the previous generation\nexistingCatalogJSON, err := g.Writer.ReadCatalogJSON()\nif err != nil {\n    return fmt.Errorf(\"讀取現有目錄失敗（請先執行 selfmd generate）: %w\", err)\n}\ncat, err := catalog.Parse(existingCatalogJSON)\n```\n\n\u003e Source: `internal/generator/updater.go#L33-L40`\n\n### BuildLinkTable Output Example\n\nThe string format produced by `BuildLinkTable()` looks like this (using this project's catalog as an example):\n\n```\n- 「概述」 → overview/index.md\n  - 「專案介紹與功能特色」 → overview/introduction/index.md\n  - 「技術棧與相依套件」 → overview/tech-stack/index.md\n- 「核心模組」 → core-modules/index.md\n  - 「文件目錄管理」 → core-modules/catalog/index.md\n```\n\n\u003e Source: `internal/catalog/catalog.go#L103-L113`\n\n## Related Links\n\n- [Documentation Generation Pipeline](../generator/index.md) — The complete usage flow of the catalog across the four-phase pipeline\n- [Catalog Generation Phase](../generator/catalog-phase/index.md) — Detailed implementation of calling Claude to generate the initial catalog\n- [Prompt Template Engine](../prompt-engine/index.md) — Rendering mechanism for `CatalogPromptData` and `catalog.tmpl`\n- [Claude CLI Runner](../claude-runner/index.md) — Implementation details for `RunWithRetry` and `ExtractJSONBlock`\n- [Incremental Updates](../incremental-update/index.md) — The dynamic catalog expansion flow of `addItemToCatalog`\n- [Output Writer and Link Fixer](../output-writer/index.md) — Usage of `WriteCatalogJSON`, `ReadCatalogJSON`, and `LinkFixer`\n- [Overall Flow and Four-Phase Pipeline](../../architecture/pipeline/index.md) — The role of the catalog in the overall architecture\n\n## Reference Files\n\n| File Path | Description |\n|-----------|-------------|\n| `internal/catalog/catalog.go` | Structure definitions for `Catalog`, `CatalogItem`, and `FlatItem`, plus core method implementations: `Parse`, `Flatten`, `ToJSON`, and `BuildLinkTable` |\n| `internal/generator/catalog_phase.go` | `GenerateCatalog()`: calls Claude and parses the response using `catalog.Parse` |\n| `internal/generator/pipeline.go` | Main four-phase pipeline flow, including catalog cache reading and persistence logic |\n| `internal/generator/content_phase.go` | `GenerateContent()`: uses `cat.Flatten()` and `cat.BuildLinkTable()` to generate pages concurrently |\n| `internal/generator/index_phase.go` | `GenerateIndex()`: uses `cat.Flatten()` to generate category index pages |\n| `internal/generator/updater.go` | `Update()`, `addItemToCatalog()`: incremental update flow and dynamic catalog expansion |\n| `internal/output/writer.go` | `WriteCatalogJSON()`, `ReadCatalogJSON()`: JSON persistence read/write for the catalog |\n| `internal/output/navigation.go` | `GenerateIndex()`, `GenerateSidebar()`: uses `cat.Items` to generate navigation files |\n| `internal/prompt/engine.go` | `CatalogPromptData` definition and `RenderCatalog()` rendering method |","en-US/core-modules/claude-runner/index.md":"# Claude CLI Runner\n\nThe `claude` package encapsulates all calls to the Claude CLI subprocess, providing a unified execution interface, retry logic, timeout control, and response parsing.\n\n## Overview\n\nThe Claude CLI Runner (`internal/claude`) is the sole entry point for selfmd's interaction with the AI model. It is responsible for:\n\n- **Subprocess management**: Launches `claude -p --output-format json` subprocesses via `os/exec`, passing the prompt through stdin\n- **Argument assembly**: Dynamically assembles CLI arguments based on `ClaudeConfig` and per-call `RunOptions`\n- **Safety restrictions**: Explicitly disables Claude's `Write` and `Edit` tools to prevent subprocesses from modifying local files\n- **Retry logic**: Automatically retries with linear backoff when a call fails or Claude itself reports an error\n- **Response parsing**: Converts JSON-formatted CLI output into Go structs, and provides helper functions for extracting specific formats from Claude responses\n\nAll stages of the generation pipeline (`internal/generator`) share a single `Runner` instance, which is held and passed by the `Generator` struct.\n\n## Architecture\n\n### Module Structure\n\n```mermaid\nflowchart TD\n    subgraph claude_pkg[\"package claude\"]\n        Runner[\"Runner\"]\n        RunOptions[\"RunOptions\"]\n        RunResult[\"RunResult\"]\n        CLIResponse[\"CLIResponse\\nCLI JSON Response\"]\n        ParseResponse[\"ParseResponse()\"]\n        ExtractJSONBlock[\"ExtractJSONBlock()\"]\n        ExtractMarkdown[\"ExtractMarkdown()\"]\n        ExtractDocumentTag[\"ExtractDocumentTag()\"]\n        cleanBoilerplate[\"cleanBoilerplate() (private)\"]\n    end\n\n    ClaudeConfig[\"config.ClaudeConfig\\nConfiguration Struct\"]\n    ClaudeCLI[\"claude CLI\\nSubprocess\"]\n    GeneratorPkg[\"generator package\\nGeneration Stages\"]\n\n    ClaudeConfig --\u003e|\"inject\"| Runner\n    GeneratorPkg --\u003e|\"call RunWithRetry()\"| Runner\n    Runner --\u003e|\"assemble args\"| RunOptions\n    Runner --\u003e|\"exec.CommandContext\"| ClaudeCLI\n    ClaudeCLI --\u003e|\"stdout JSON\"| ParseResponse\n    ParseResponse --\u003e|\"populate\"| RunResult\n    RunResult --\u003e|\"return to\"| GeneratorPkg\n    GeneratorPkg --\u003e|\"ExtractJSONBlock()\"| ExtractJSONBlock\n    GeneratorPkg --\u003e|\"ExtractDocumentTag()\"| ExtractDocumentTag\n    ExtractMarkdown --\u003e|\"calls\"| cleanBoilerplate\n    CLIResponse --\u003e|\"json.Unmarshal\"| ParseResponse\n```\n\n### Dependencies\n\n```mermaid\nflowchart LR\n    catalog_phase[\"catalog_phase\\nCatalog Generation Stage\"]\n    content_phase[\"content_phase\\nContent Generation Stage\"]\n    translate_phase[\"translate_phase\\nTranslation Stage\"]\n    updater[\"updater\\nIncremental Update\"]\n\n    Runner[\"claude.Runner\"]\n\n    catalog_phase --\u003e|\"RunWithRetry + ExtractJSONBlock\"| Runner\n    content_phase --\u003e|\"RunWithRetry + ExtractDocumentTag\"| Runner\n    translate_phase --\u003e|\"RunWithRetry + ExtractDocumentTag\"| Runner\n    updater --\u003e|\"RunWithRetry + ExtractJSONBlock\"| Runner\n```\n\n## Core Types\n\n### RunOptions — Execution Options\n\nThe set of parameters passed to each Claude CLI invocation:\n\n```go\n// RunOptions configures a single Claude CLI invocation.\ntype RunOptions struct {\n\tPrompt       string\n\tWorkDir      string        // CWD for the claude process\n\tAllowedTools []string      // tool restrictions\n\tModel        string        // model override\n\tTimeout      time.Duration // per-invocation timeout\n\tExtraArgs    []string      // additional CLI arguments\n}\n```\n\n\u003e Source: internal/claude/types.go#L6-L13\n\n| Field | Description |\n|-------|-------------|\n| `Prompt` | The full prompt text passed to Claude via stdin |\n| `WorkDir` | Working directory for the subprocess, used by Claude to access project files |\n| `AllowedTools` | Overrides `allowed_tools` from config; uses config value if empty |\n| `Model` | Overrides `model` from config; uses config value if empty |\n| `Timeout` | Overrides `timeout_seconds` from config; uses config value if zero |\n| `ExtraArgs` | Additional CLI arguments appended after config's `extra_args` |\n\n### RunResult — Execution Result\n\n```go\n// RunResult holds the parsed result from a Claude CLI invocation.\ntype RunResult struct {\n\tContent    string  // the text result from Claude\n\tIsError    bool    // whether Claude reported an error\n\tDurationMs int64   // execution time in milliseconds\n\tCostUSD    float64 // cost of this invocation\n\tSessionID  string  // Claude session ID\n}\n```\n\n\u003e Source: internal/claude/types.go#L16-L23\n\n### CLIResponse — Raw CLI JSON Response\n\nThe JSON structure corresponding to the output of `claude -p --output-format json`:\n\n```go\n// CLIResponse represents the JSON response from `claude -p --output-format json`.\ntype CLIResponse struct {\n\tType       string  `json:\"type\"`\n\tSubtype    string  `json:\"subtype\"`\n\tIsError    bool    `json:\"is_error\"`\n\tResult     string  `json:\"result\"`\n\tDurationMs int64   `json:\"duration_ms\"`\n\tTotalCost  float64 `json:\"total_cost_usd\"`\n\tSessionID  string  `json:\"session_id\"`\n}\n```\n\n\u003e Source: internal/claude/types.go#L25-L33\n\n## Execution Methods\n\n### Run() — Single Invocation\n\n`Run()` executes a single Claude CLI call: assembles arguments, creates the subprocess, pipes the prompt, waits for the result, and parses the response:\n\n```go\n// Run executes a single Claude CLI invocation.\nfunc (r *Runner) Run(ctx context.Context, opts RunOptions) (*RunResult, error) {\n\t// build command args\n\targs := []string{\n\t\t\"-p\",\n\t\t\"--output-format\", \"json\",\n\t}\n\n\tmodel := opts.Model\n\tif model == \"\" {\n\t\tmodel = r.config.Model\n\t}\n\tif model != \"\" {\n\t\targs = append(args, \"--model\", model)\n\t}\n\n\t// ...（tool list assembly omitted）\n\n\t// Explicitly block Write/Edit to prevent content from being lost in denied tool calls\n\targs = append(args, \"--disallowedTools\", \"Write\", \"--disallowedTools\", \"Edit\")\n\n\t// ...（timeout and subprocess creation omitted）\n\n\t// pipe prompt via stdin\n\tcmd.Stdin = strings.NewReader(opts.Prompt)\n```\n\n\u003e Source: internal/claude/runner.go#L30-L75\n\n**Argument assembly precedence:**\n\n1. Fixed arguments: `-p`, `--output-format json`\n2. Model: `opts.Model` \u003e `config.Model` (omitted if both are empty)\n3. AllowedTools: `opts.AllowedTools` \u003e `config.AllowedTools`\n4. Forced disallow: `--disallowedTools Write --disallowedTools Edit`\n5. Extra arguments: `config.ExtraArgs` + `opts.ExtraArgs`\n\n### RunWithRetry() — Invocation with Retry\n\n`RunWithRetry()` wraps `Run()` with linear backoff retry. The number of retries is controlled by `config.MaxRetries`, with each retry waiting `attempt * 5` seconds:\n\n```go\n// RunWithRetry executes a Claude CLI invocation with retry logic.\nfunc (r *Runner) RunWithRetry(ctx context.Context, opts RunOptions) (*RunResult, error) {\n\tmaxRetries := r.config.MaxRetries\n\tvar lastErr error\n\n\tfor attempt := 0; attempt \u003c= maxRetries; attempt++ {\n\t\tif attempt \u003e 0 {\n\t\t\tbackoff := time.Duration(attempt) * 5 * time.Second\n\t\t\tr.logger.Info(\"重試中\", \"attempt\", attempt+1, \"backoff\", backoff)\n\t\t\tselect {\n\t\t\tcase \u003c-ctx.Done():\n\t\t\t\treturn nil, ctx.Err()\n\t\t\tcase \u003c-time.After(backoff):\n\t\t\t}\n\t\t}\n\n\t\tresult, err := r.Run(ctx, opts)\n\t\tif err == nil \u0026\u0026 !result.IsError {\n\t\t\treturn result, nil\n\t\t}\n\t\t// ...\n\t}\n\treturn nil, fmt.Errorf(\"所有 %d 次嘗試均失敗: %w\", maxRetries+1, lastErr)\n}\n```\n\n\u003e Source: internal/claude/runner.go#L113-L143\n\n**Failure conditions (any one triggers a retry):**\n- `Run()` returns `err != nil` (subprocess error, timeout, etc.)\n- `result.IsError == true` (Claude itself reported an error)\n\n### CheckAvailable() — Environment Check\n\n```go\n// CheckAvailable verifies that the claude CLI is installed and accessible.\nfunc CheckAvailable() error {\n\t_, err := exec.LookPath(\"claude\")\n\tif err != nil {\n\t\treturn fmt.Errorf(\"找不到 claude CLI。請先安裝 Claude Code：https://docs.anthropic.com/en/docs/claude-code\")\n\t}\n\treturn nil\n}\n```\n\n\u003e Source: internal/claude/runner.go#L146-L152\n\n## Response Parsing Functions\n\n`parser.go` provides four public functions used by each stage of the generation pipeline to extract content in the required format from Claude responses.\n\n### ParseResponse() — Parse CLI JSON\n\nConverts the raw JSON output of `claude -p --output-format json` into a `RunResult`:\n\n```go\nfunc ParseResponse(data []byte) (*RunResult, error) {\n\tvar resp CLIResponse\n\tif err := json.Unmarshal(data, \u0026resp); err != nil {\n\t\treturn nil, fmt.Errorf(\"JSON 解析失敗: %w\", err)\n\t}\n\n\treturn \u0026RunResult{\n\t\tContent:    resp.Result,\n\t\tIsError:    resp.IsError,\n\t\tDurationMs: resp.DurationMs,\n\t\tCostUSD:    resp.TotalCost,\n\t\tSessionID:  resp.SessionID,\n\t}, nil\n}\n```\n\n\u003e Source: internal/claude/parser.go#L11-L24\n\n### ExtractJSONBlock() — Extract JSON Block\n\nExtracts the first JSON object from Claude's Markdown response, attempting three strategies in order:\n\n```go\nfunc ExtractJSONBlock(text string) (string, error) {\n\t// try fenced code block first\n\tre := regexp.MustCompile(\"(?s)```json\\\\s*\\n(.*?)```\")\n\t// ...\n\t// try without language tag\n\tre = regexp.MustCompile(\"(?s)```\\\\s*\\n(\\\\{.*?\\\\})\\\\s*```\")\n\t// ...\n\t// try to find raw JSON object\n\tstart := strings.Index(text, \"{\")\n\t// ...\n}\n```\n\n\u003e Source: internal/claude/parser.go#L28-L61\n\n**Three-stage extraction strategy:**\n1. ` ```json ... ``` ` fenced code block\n2. ` ``` ... ``` ` fenced block without language tag (containing a JSON object)\n3. Find a `{...}` matched JSON object directly in raw text\n\n**Usage**: `catalog_phase` (catalog generation) and `updater` (incremental update decision) call this function to parse JSON results returned by Claude.\n\n### ExtractDocumentTag() — Extract `\u003cdocument\u003e` Tag\n\nExtracts `\u003cdocument\u003e...` from Claude responses.","en-US/core-modules/generator/catalog-phase/index.md":"# Catalog Generation Phase\n\nThe Catalog Generation Phase is the second stage of the entire documentation generation pipeline. It is responsible for analyzing the project structure via the Claude CLI and automatically generating a structured documentation catalog tree.\n\n## Overview\n\nIn selfmd's four-stage pipeline, the Catalog Generation Phase (Pipeline Stage 2) plays a central hub role: it receives project structure data from the scanner, assembles prompts via the Prompt Template Engine, calls the Claude CLI for AI analysis, and ultimately outputs a structured `Catalog` object for use by the subsequent content page generation phase.\n\nKey design decisions for this phase include:\n\n- **AI-driven**: Lets Claude understand code semantics rather than simply analyzing file structure, producing a catalog that better reflects business logic\n- **Cache reuse**: If `_catalog.json` already exists in the output directory, it is loaded directly and this phase is skipped, saving API costs\n- **Retry mechanism**: Uses `RunWithRetry` to handle transient Claude CLI failures\n- **Structured output**: Forces Claude to output JSON format, then parses it into a strongly-typed `Catalog` structure\n\n## Architecture\n\n```mermaid\nflowchart TD\n    Pipeline[\"pipeline.go\\nGenerator.Generate()\"]\n    CatalogPhase[\"catalog_phase.go\\nGenerator.GenerateCatalog()\"]\n    PromptEngine[\"prompt.Engine\\nRenderCatalog()\"]\n    CatalogTmpl[\"catalog.tmpl\\n(language template)\"]\n    ClaudeRunner[\"claude.Runner\\nRunWithRetry()\"]\n    ExtractJSON[\"claude.ExtractJSONBlock()\"]\n    CatalogParse[\"catalog.Parse()\"]\n    CatalogStruct[\"catalog.Catalog\\nStructured Catalog\"]\n    Writer[\"output.Writer\\nWriteCatalogJSON()\"]\n\n    Pipeline --\u003e|\"clean or no cache\"| CatalogPhase\n    Pipeline --\u003e|\"cache _catalog.json exists\"| Writer2[\"output.Writer\\nReadCatalogJSON()\"]\n    Writer2 --\u003e|JSON string| CatalogParse\n    CatalogPhase --\u003e PromptEngine\n    PromptEngine --\u003e CatalogTmpl\n    CatalogTmpl --\u003e|rendered prompt| ClaudeRunner\n    ClaudeRunner --\u003e|RunResult.Content| ExtractJSON\n    ExtractJSON --\u003e|JSON string| CatalogParse\n    CatalogParse --\u003e CatalogStruct\n    CatalogPhase --\u003e|\"save cache\"| Writer\n```\n\n## Entry Method\n\n`GenerateCatalog` is defined in `internal/generator/catalog_phase.go` and is the only public method of this phase:\n\n```go\nfunc (g *Generator) GenerateCatalog(ctx context.Context, scan *scanner.ScanResult) (*catalog.Catalog, error) {\n\tlangName := config.GetLangNativeName(g.Config.Output.Language)\n\tdata := prompt.CatalogPromptData{\n\t\tRepositoryName:       g.Config.Project.Name,\n\t\tProjectType:          g.Config.Project.Type,\n\t\tLanguage:             g.Config.Output.Language,\n\t\tLanguageName:         langName,\n\t\tLanguageOverride:     g.Config.Output.NeedsLanguageOverride(),\n\t\tLanguageOverrideName: langName,\n\t\tKeyFiles:             scan.KeyFiles(),\n\t\tEntryPoints:          scan.EntryPointsFormatted(),\n\t\tFileTree:             scanner.RenderTree(scan.Tree, 4),\n\t\tReadmeContent:        scan.ReadmeContent,\n\t}\n\n\trendered, err := g.Engine.RenderCatalog(data)\n\tif err != nil {\n\t\treturn nil, err\n\t}\n\t// ...\n}\n```\n\n\u003e Source: internal/generator/catalog_phase.go#L16-L34\n\n### CatalogPromptData Field Descriptions\n\nThe `prompt.CatalogPromptData` struct aggregates all context data used to drive Claude's analysis:\n\n| Field | Source | Description |\n|------|------|------|\n| `RepositoryName` | `config.Project.Name` | Project name |\n| `ProjectType` | `config.Project.Type` | Project type (e.g., `go-cli`) |\n| `Language` | `config.Output.Language` | Target output language code (e.g., `zh-TW`) |\n| `LanguageName` | `GetLangNativeName()` | Native name of the language (e.g., \"Traditional Chinese\") |\n| `LanguageOverride` | `Output.NeedsLanguageOverride()` | Whether the template language differs from the output language |\n| `KeyFiles` | `scan.KeyFiles()` | List of important files (main.go, go.mod, etc.) |\n| `EntryPoints` | `scan.EntryPointsFormatted()` | Formatted content of entry point files |\n| `FileTree` | `scanner.RenderTree(scan.Tree, 4)` | File tree text limited to 4 levels deep |\n| `ReadmeContent` | `scan.ReadmeContent` | README content (up to 50,000 characters) |\n\n\u003e Source: internal/prompt/engine.go#L39-L51\n\n## Cache Reuse Mechanism\n\nIn the `Generate()` method of `pipeline.go`, catalog generation includes smart cache logic:\n\n```go\nvar cat *catalog.Catalog\nif !clean {\n\t// Try to reuse existing catalog\n\tcatJSON, readErr := g.Writer.ReadCatalogJSON()\n\tif readErr == nil {\n\t\tcat, err = catalog.Parse(catJSON)\n\t}\n\tif cat != nil {\n\t\titems := cat.Flatten()\n\t\tfmt.Printf(ui.T(\"[2/4] 載入已存目錄（%d 個章節，%d 個項目）\\n\", ...), len(cat.Items), len(items))\n\t}\n}\nif cat == nil {\n\tfmt.Println(ui.T(\"[2/4] 產生文件目錄...\", ...))\n\tcat, err = g.GenerateCatalog(ctx, scan)\n\t// ...\n\tif err := g.Writer.WriteCatalogJSON(cat); err != nil {\n\t\tg.Logger.Warn(...)\n\t}\n}\n```\n\n\u003e Source: internal/generator/pipeline.go#L103-L128\n\nThe cache is stored as a `_catalog.json` file in the output directory (`.doc-build/`). Claude will be called again to regenerate the catalog in the following situations:\n\n- The user specifies the `--clean` flag\n- The configuration has `output.clean_before_generate: true`\n- The `_catalog.json` file does not exist or cannot be read\n- The `_catalog.json` file fails to parse\n\n## Core Flow\n\n```mermaid\nsequenceDiagram\n    participant Pipeline as pipeline.go\n    participant CatalogPhase as catalog_phase.go\n    participant Engine as prompt.Engine\n    participant Runner as claude.Runner\n    participant Parser as claude.parser.go\n    participant CatalogPkg as catalog.Parse()\n    participant Writer as output.Writer\n\n    Pipeline-\u003e\u003eWriter: ReadCatalogJSON()\n    alt Cache exists and is valid\n        Writer--\u003e\u003ePipeline: JSON string\n        Pipeline-\u003e\u003eCatalogPkg: Parse(jsonStr)\n        CatalogPkg--\u003e\u003ePipeline: *Catalog (reused)\n    else Regeneration needed\n        Pipeline-\u003e\u003eCatalogPhase: GenerateCatalog(ctx, scan)\n        CatalogPhase-\u003e\u003eEngine: RenderCatalog(CatalogPromptData)\n        Engine--\u003e\u003eCatalogPhase: rendered prompt string\n        CatalogPhase-\u003e\u003eRunner: RunWithRetry(ctx, RunOptions{Prompt, WorkDir})\n        loop Up to maxRetries+1 times\n            Runner-\u003e\u003eRunner: Run() (calls claude CLI)\n            Runner--\u003e\u003eRunner: ParseResponse()\n        end\n        Runner--\u003e\u003eCatalogPhase: *RunResult{Content, CostUSD, DurationMs}\n        CatalogPhase-\u003e\u003eParser: ExtractJSONBlock(result.Content)\n        Parser--\u003e\u003eCatalogPhase: JSON string\n        CatalogPhase-\u003e\u003eCatalogPkg: Parse(jsonStr)\n        CatalogPkg--\u003e\u003eCatalogPhase: *Catalog\n        CatalogPhase--\u003e\u003ePipeline: *Catalog\n        Pipeline-\u003e\u003eWriter: WriteCatalogJSON(cat)\n    end\n```\n\n## Catalog Data Structure\n\nClaude must output the catalog in JSON format, which is then parsed by `catalog.Parse()` into a strongly-typed structure:\n\n```go\n// Catalog represents the documentation catalog structure.\ntype Catalog struct {\n\tItems []CatalogItem `json:\"items\"`\n}\n\n// CatalogItem represents a single item in the catalog tree.\ntype CatalogItem struct {\n\tTitle    string        `json:\"title\"`\n\tPath     string        `json:\"path\"`\n\tOrder    int           `json:\"order\"`\n\tChildren []CatalogItem `json:\"children\"`\n}\n```\n\n\u003e Source: internal/catalog/catalog.go#L9-L20\n\nExample of the raw JSON format output by Claude:\n\n```json\n{\n  \"items\": [\n    {\n      \"title\": \"Overview\",\n      \"path\": \"overview\",\n      \"order\": 0,\n      \"children\": [\n        {\n          \"title\": \"Project Introduction and Features\",\n          \"path\": \"introduction\",\n          \"order\": 0,\n          \"children\": []\n        }\n      ]\n    }\n  ]\n}\n```\n\n## JSON Extraction Logic\n\nClaude's response may contain explanatory text in Markdown format. `ExtractJSONBlock` uses a three-stage fallback strategy to extract JSON from it:\n\n```go\nfunc ExtractJSONBlock(text string) (string, error) {\n\t// Strategy 1: Find ```json ... ``` fenced code blocks\n\tre := regexp.MustCompile(\"(?s)```json\\\\s*\\n(.*?)```\")\n\tmatches := re.FindStringSubmatch(text)\n\tif len(matches) \u003e 1 {\n\t\treturn strings.TrimSpace(matches[1]), nil\n\t}\n\n\t// Strategy 2: Find ``` ... ``` fenced blocks without a language tag\n\tre = regexp.MustCompile(\"(?s)```\\\\s*\\n(\\\\{.*?\\\\})\\\\s*```\")\n\t// ...\n\n\t// Strategy 3: Find raw JSON objects in plain text (bracket-balance scan)\n\tstart := strings.Index(text, \"{\")\n\t// ...\n}\n```\n\n\u003e Source: internal/claude/parser.go#L26-L61\n\n## Statistics Tracking\n\nAfter each successful Claude call, the cost is accumulated into `Generator.TotalCost`:\n\n```go\ng.TotalCost += result.CostUSD\nfmt.Printf(ui.T(\" 完成（%.1fs，$%.4f）\\n\", \" Done (%.1fs, $%.4f)\\n\"),\n    float64(result.DurationMs)/1000, result.CostUSD)\n```\n\n\u003e Source: internal/generator/catalog_phase.go#L47-L48\n\n## Prompt Template\n\nThe prompt template used for catalog generation is located at `internal/prompt/templates/\u003clang\u003e/catalog.tmpl`. The template instructs Claude to:\n\n1. Use tools (Glob, Read, Grep) to actually explore the project source code\n2. Design the catalog based on business functionality rather than file structure\n3. Output only a single ` ```json ` code block with no additional explanatory text\n\n\u003e Source: internal/prompt/templates/zh-TW/catalog.tmpl#L1-L121\n\n## Related Links\n\n- [Documentation Generation Pipeline](../index.md) — Understand this phase's full position in the four-stage pipeline\n- [Content Page Generation Phase](../content-phase/index.md) — The next phase that receives the Catalog output from this phase\n- [Documentation Catalog Management](../../catalog/index.md) — Detailed explanation of `Catalog`, `CatalogItem`, and `FlatItem` data structures\n- [Prompt Template Engine](../../prompt-engine/index.md) — `Engine.RenderCatalog()` and the template system\n- [Claude CLI Runner](../../claude-runner/index.md) — Detailed explanation of `Runner.RunWithRetry()` retry mechanism\n- [Project Scanner](../../scanner/index.md) — The `ScanResult` that provides input data for this phase\n- [Overall Flow and Four-Stage Pipeline](../../../architecture/pipeline/index.md) — System architecture overview\n\n## Reference Files\n\n| File Path | Description |\n|----------|------|\n| `internal/generator/catalog_phase.go` | Main implementation of `GenerateCatalog()` |\n| `internal/generator/pipeline.go` | Pipeline orchestration, cache reuse logic, and cost tracking |\n| `internal/catalog/catalog.go` | `Catalog`, `CatalogItem`, `FlatItem` data structures and parsing logic |\n| `internal/prompt/engine.go` | `CatalogPromptData` definition and `RenderCatalog()` |\n| `internal/prompt/templates/zh-TW/catalog.tmpl` | Traditional Chinese catalog generation prompt template |\n| `internal/claude/runner.go` | `Runner.Run()` and `RunWithRetry()` implementation |\n| `internal/claude/types.go` | `RunOptions`, `RunResult`, `CLIResponse` struct definitions |\n| `internal/claude/parser.go` | `ExtractJSONBlock()` JSON extraction logic |\n| `internal/scanner/scanner.go` | `ScanResult.KeyFiles()` and `EntryPointsFormatted()` |\n| `internal/output/writer.go` | `WriteCatalogJSON()` and `ReadCatalogJSON()` cache operations |","en-US/core-modules/generator/content-phase/index.md":"# Content Page Generation Phase\n\nThe content page generation phase (Phase 3) is the core of the selfmd four-stage pipeline, responsible for converting each entry in the catalog into a complete Markdown document page in parallel.\n\n## Overview\n\nOnce the Catalog is built, the content generation phase takes over, calling the Claude CLI for each `FlatItem` (flattened catalog entry) in the catalog, requesting it to generate the corresponding documentation based on the project source code.\n\nThe primary responsibilities of this phase include:\n\n- **Concurrency control**: Configurable parallelism via `errgroup` and semaphore to protect system resources\n- **Skip existing pages**: In non-clean mode, pages that already exist and are valid will be skipped to save API costs\n- **Retry and format validation**: Ensures Claude output meets format requirements (must have `\u003cdocument\u003e` tags and contain a Markdown heading)\n- **Link fix post-processing**: Automatically repairs relative path links within pages after generation\n- **Failure degradation**: Writes a placeholder page when page generation fails, without interrupting the overall process\n\nThe core implementation is in `internal/generator/content_phase.go`, with the main entry point being `Generator.GenerateContent()`.\n\n## Architecture\n\n```mermaid\nflowchart TD\n    GC[\"GenerateContent()\"] --\u003e FL[\"cat.Flatten()\"]\n    GC --\u003e BLT[\"cat.BuildLinkTable()\"]\n    GC --\u003e NLF[\"output.NewLinkFixer()\"]\n    GC --\u003e EG[\"errgroup + semaphore channel\"]\n\n    EG --\u003e CHK[\"Writer.PageExists()\"]\n    CHK -- \"skipExisting \u0026\u0026 exists\" --\u003e SKIP[\"atomic skipped++\"]\n    CHK -- \"needs generation\" --\u003e GSP[\"generateSinglePage()\"]\n\n    GSP --\u003e CPD[\"ContentPromptData assembly\"]\n    CPD --\u003e RND[\"Engine.RenderContent()\"]\n    RND --\u003e RWR[\"Runner.RunWithRetry()\"]\n    RWR --\u003e EDT[\"ExtractDocumentTag()\"]\n    EDT --\u003e VAL{\"Format validation\"}\n    VAL -- \"passed\" --\u003e LFX[\"LinkFixer.FixLinks()\"]\n    LFX --\u003e WP[\"Writer.WritePage()\"]\n    VAL -- \"failed, retryable\" --\u003e RWR\n    VAL -- \"max attempts exceeded\" --\u003e ERR[\"atomic failed++\"]\n    ERR --\u003e WPH[\"writePlaceholder()\"]\n```\n\n## Key Components and Data Structures\n\n### Generator Struct\n\n`Generator` is the coordinator of the entire pipeline, defined in `pipeline.go`:\n\n```go\ntype Generator struct {\n    Config  *config.Config\n    Runner  *claude.Runner\n    Engine  *prompt.Engine\n    Writer  *output.Writer\n    Logger  *slog.Logger\n    RootDir string\n\n    TotalCost   float64\n    TotalPages  int\n    FailedPages int\n}\n```\n\n\u003e Source: internal/generator/pipeline.go#L19-L31\n\n### ContentPromptData Data Model\n\n`generateSinglePage()` assembles the following prompt data structure for each page:\n\n```go\ndata := prompt.ContentPromptData{\n    RepositoryName:       g.Config.Project.Name,\n    Language:             g.Config.Output.Language,\n    LanguageName:         langName,\n    LanguageOverride:     g.Config.Output.NeedsLanguageOverride(),\n    LanguageOverrideName: langName,\n    CatalogPath:          item.Path,\n    CatalogTitle:         item.Title,\n    CatalogDirPath:       item.DirPath,\n    ProjectDir:           g.RootDir,\n    FileTree:             scanner.RenderTree(scan.Tree, 3),\n    CatalogTable:         catalogTable,\n    ExistingContent:      existingContent,\n}\n```\n\n\u003e Source: internal/generator/content_phase.go#L91-L104\n\n`ExistingContent` is an empty string during fresh generation; in incremental update scenarios (`updater.go`), it is populated with the existing page content so Claude can modify rather than fully rewrite it.\n\n## Core Flow\n\n### Parallel Generation Flow\n\n```mermaid\nsequenceDiagram\n    participant GC as GenerateContent\n    participant EG as errgroup\n    participant SEM as semaphore\n    participant GSP as generateSinglePage\n    participant CR as Runner.RunWithRetry\n    participant EDT as ExtractDocumentTag\n    participant LF as LinkFixer\n    participant W as Writer\n\n    GC-\u003e\u003eEG: Launch goroutine for each FlatItem\n    loop Each catalog entry\n        EG-\u003e\u003eW: PageExists(item)\n        alt skipExisting \u0026\u0026 page exists\n            EG-\u003e\u003eEG: skipped.Add(1)\n        else needs generation\n            EG-\u003e\u003eSEM: sem \u003c- struct{}{} (acquire token)\n            EG-\u003e\u003eGSP: generateSinglePage(ctx, item)\n            GSP-\u003e\u003eCR: RunWithRetry(ctx, RunOptions)\n            CR--\u003e\u003eGSP: RunResult{Content, CostUSD}\n            GSP-\u003e\u003eEDT: ExtractDocumentTag(result.Content)\n            EDT--\u003e\u003eGSP: markdown string\n            GSP-\u003e\u003eLF: FixLinks(content, item.DirPath)\n            LF--\u003e\u003eGSP: fixed content\n            GSP-\u003e\u003eW: WritePage(item, content)\n            EG-\u003e\u003eSEM: \u003c-sem (release token)\n        end\n    end\n    GC-\u003e\u003eGC: eg.Wait()\n    GC-\u003e\u003eGC: Update TotalPages / FailedPages\n```\n\n### Concurrency Control\n\nConcurrency is implemented via a semaphore channel, with the size determined by `claude.max_concurrent` in the config file (overridable via the CLI `--concurrency` flag):\n\n```go\nsem := make(chan struct{}, concurrency)\n\nfor _, item := range items {\n    item := item\n    eg.Go(func() error {\n        // ...skipExisting check...\n\n        sem \u003c- struct{}{}\n        defer func() { \u003c-sem }()\n\n        // execute generateSinglePage\n    })\n}\n```\n\n\u003e Source: internal/generator/content_phase.go#L37-L73\n\n### Format Validation and Retry Mechanism\n\n`generateSinglePage()` has a built-in maximum of 2 attempts (`maxAttempts = 2`), retrying for two types of format errors:\n\n```go\nmaxAttempts := 2\nfor attempt := 1; attempt \u003c= maxAttempts; attempt++ {\n    result, err := g.Runner.RunWithRetry(ctx, claude.RunOptions{...})\n\n    // Attempt to extract content from \u003cdocument\u003e tags\n    content, extractErr := claude.ExtractDocumentTag(result.Content)\n    if extractErr != nil {\n        if attempt \u003c maxAttempts {\n            fmt.Printf(\" Format error, retrying...\\n      \")\n            continue\n        }\n        return lastErr\n    }\n\n    // Validate that a valid Markdown heading exists\n    content = strings.TrimSpace(content)\n    if content == \"\" || !strings.HasPrefix(content, \"#\") {\n        if attempt \u003c maxAttempts {\n            fmt.Printf(\" Invalid content, retrying...\\n      \")\n            continue\n        }\n        return lastErr\n    }\n\n    // Post-process and write\n    content = linkFixer.FixLinks(content, item.DirPath)\n    return g.Writer.WritePage(item, content)\n}\n```\n\n\u003e Source: internal/generator/content_phase.go#L111-L156\n\n**Validation conditions:**\n1. `claude.ExtractDocumentTag()` must be able to find `\u003cdocument\u003e...` in the response","en-US/core-modules/generator/index-phase/index.md":"# Index and Navigation Generation Phase\n\nThe Index and Navigation Generation Phase (Index Phase) is the fourth stage of the overall documentation generation pipeline. It is responsible for automatically generating the main index page, sidebar navigation file, and sub-category index pages based on the established directory structure (`Catalog`), providing the documentation with a navigable skeleton.\n\n## Overview\n\nAfter the first three phases (scan, catalog generation, content generation) are complete, all document content has been written to the output directory, but a unified entry point and navigation structure is still missing. The core responsibilities of the Index and Navigation Generation Phase are:\n\n- **Generate `index.md`**: The main entry page for the documentation, listing all sections in a tree-structured table of contents\n- **Generate `_sidebar.md`**: A sidebar navigation file for use with static documentation browsers such as Docsify\n- **Generate category index pages**: For all \"parent nodes with children,\" generate independent category index pages (`\u003csection\u003e/index.md`) listing links to their direct child items\n\nThis phase operates entirely on the established `catalog.Catalog` structure and does not require calling the Claude CLI — it is purely local content generation. Multilingual support is implemented via a `UIStrings` string mapping table, currently supporting `zh-TW` and `en-US` interface languages.\n\n## Architecture\n\n```mermaid\nflowchart TD\n    GenerateIndex[\"GenerateIndex\\n(index_phase.go)\"]\n    Catalog[\"catalog.Catalog\"]\n    Flatten[\"Catalog.Flatten()\"]\n    navGenIndex[\"output.GenerateIndex()\"]\n    navGenSidebar[\"output.GenerateSidebar()\"]\n    navGenCategory[\"output.GenerateCategoryIndex()\"]\n    Writer[\"output.Writer\"]\n    UIStrings[\"output.UIStrings\\n(Language String Map)\"]\n\n    WriteFile[\"Writer.WriteFile()\"]\n    WritePage[\"Writer.WritePage()\"]\n\n    outIndex[\"index.md\\n(Main Entry Page)\"]\n    outSidebar[\"_sidebar.md\\n(Sidebar Navigation)\"]\n    outCatPages[\"Category Index Pages\\n(each section/index.md)\"]\n\n    GenerateIndex --\u003e Catalog\n    Catalog --\u003e Flatten\n    GenerateIndex --\u003e navGenIndex\n    GenerateIndex --\u003e navGenSidebar\n    GenerateIndex --\u003e navGenCategory\n\n    navGenIndex --\u003e UIStrings\n    navGenSidebar --\u003e UIStrings\n    navGenCategory --\u003e UIStrings\n\n    navGenIndex --\u003e WriteFile --\u003e outIndex\n    navGenSidebar --\u003e WriteFile --\u003e outSidebar\n    navGenCategory --\u003e WritePage --\u003e outCatPages\n\n    Flatten --\u003e|\"HasChildren check\\nand child filtering\"| GenerateIndex\n```\n\n## Output File Descriptions\n\n### Main Index Page `index.md`\n\nGenerated by `output.GenerateIndex()`, it contains:\n\n1. A top-level heading: `{Project Name} {techDocs language string}`\n2. Project description (if configured)\n3. A horizontal divider\n4. A second-level heading \"Table of Contents\" (language-dependent)\n5. All catalog items displayed as an indented nested list, each with a relative path link\n\n```go\nfunc GenerateIndex(projectName, projectDesc string, cat *catalog.Catalog, lang string) string {\n\tui := getUIStrings(lang)\n\tvar sb strings.Builder\n\n\tsb.WriteString(fmt.Sprintf(\"# %s %s\\n\\n\", projectName, ui[\"techDocs\"]))\n\n\tif projectDesc != \"\" {\n\t\tsb.WriteString(projectDesc + \"\\n\\n\")\n\t}\n\n\tsb.WriteString(\"---\\n\\n\")\n\tsb.WriteString(fmt.Sprintf(\"## %s\\n\\n\", ui[\"catalog\"]))\n\n\tfor _, item := range cat.Items {\n\t\twriteIndexItem(\u0026sb, item, \"\", 0)\n\t}\n\n\tsb.WriteString(\"\\n---\\n\\n\")\n\tsb.WriteString(fmt.Sprintf(\"*%s*\\n\", ui[\"autoGenerated\"]))\n\n\treturn sb.String()\n}\n```\n\n\u003e Source: internal/output/navigation.go#L38-L59\n\nEach catalog item link is built recursively by `writeIndexItem`, using the `resolveDirPath` function to handle both Format A (relative path) and Format B (already includes parent path):\n\n```go\nfunc writeIndexItem(sb *strings.Builder, item catalog.CatalogItem, parentDir string, depth int) {\n\tindent := strings.Repeat(\"  \", depth)\n\tdirPath := resolveDirPath(item.Path, parentDir)\n\n\tlink := fmt.Sprintf(\"./%s/index.md\", dirPath)\n\tsb.WriteString(fmt.Sprintf(\"%s- [%s](%s)\\n\", indent, item.Title, link))\n\n\tfor _, child := range item.Children {\n\t\twriteIndexItem(sb, child, dirPath, depth+1)\n\t}\n}\n```\n\n\u003e Source: internal/output/navigation.go#L61-L71\n\n---\n\n### Sidebar Navigation `_sidebar.md`\n\nGenerated by `output.GenerateSidebar()`, the format is similar to the main index page, except:\n\n- The heading is the plain project name (without an appended language string)\n- A \"Home\" link (pointing to `./index.md`) is always inserted at the top\n\n```go\nfunc GenerateSidebar(projectName string, cat *catalog.Catalog, lang string) string {\n\tui := getUIStrings(lang)\n\tvar sb strings.Builder\n\n\tsb.WriteString(fmt.Sprintf(\"# %s\\n\\n\", projectName))\n\tsb.WriteString(fmt.Sprintf(\"- [%s](./index.md)\\n\", ui[\"home\"]))\n\n\tfor _, item := range cat.Items {\n\t\twriteSidebarItem(\u0026sb, item, \"\", 0)\n\t}\n\n\treturn sb.String()\n}\n```\n\n\u003e Source: internal/output/navigation.go#L74-L86\n\n---\n\n### Category Index Pages\n\nFor all catalog items where `HasChildren == true`, `GenerateIndex` additionally generates a corresponding `\u003cDirPath\u003e/index.md` whose content is a link list of its **direct child items**.\n\nThe child filtering logic is implemented in `index_phase.go`:\n\n```go\nitems := cat.Flatten()\nfor _, item := range items {\n    if !item.HasChildren {\n        continue\n    }\n\n    // find direct children\n    var children []catalog.FlatItem\n    for _, child := range items {\n        if child.ParentPath == item.Path \u0026\u0026 child.Path != item.Path {\n            children = append(children, child)\n        }\n    }\n\n    if len(children) \u003e 0 {\n        categoryContent := output.GenerateCategoryIndex(item, children, lang)\n        if err := g.Writer.WritePage(item, categoryContent); err != nil {\n            g.Logger.Warn(\"failed to write category index\", \"path\", item.Path, \"error\", err)\n        }\n    }\n}\n```\n\n\u003e Source: internal/generator/index_phase.go#L32-L52\n\n`output.GenerateCategoryIndex` uses `computeRelativePath` (based on `filepath.Rel`) to calculate the correct relative path for each child item:\n\n```go\nfunc GenerateCategoryIndex(item catalog.FlatItem, children []catalog.FlatItem, lang string) string {\n\tui := getUIStrings(lang)\n\tvar sb strings.Builder\n\n\tsb.WriteString(fmt.Sprintf(\"# %s\\n\\n\", item.Title))\n\tsb.WriteString(ui[\"sectionContains\"] + \"\\n\\n\")\n\n\tfor _, child := range children {\n\t\trelPath := computeRelativePath(item.DirPath, child.DirPath)\n\t\tsb.WriteString(fmt.Sprintf(\"- [%s](%s/index.md)\\n\", child.Title, relPath))\n\t}\n\n\treturn sb.String()\n}\n```\n\n\u003e Source: internal/output/navigation.go#L101-L114\n\n## Multilingual String Mapping\n\n`navigation.go` defines the `UIStrings` mapping table, keyed by language code:\n\n```go\nvar UIStrings = map[string]map[string]string{\n\t\"zh-TW\": {\n\t\t\"techDocs\":        \"技術文件\",\n\t\t\"catalog\":         \"目錄\",\n\t\t\"home\":            \"首頁\",\n\t\t\"sectionContains\": \"本章節包含以下內容：\",\n\t\t\"autoGenerated\":   \"本文件由 [selfmd](https://github.com/monkenwu/selfmd) 自動產生\",\n\t},\n\t\"en-US\": {\n\t\t\"techDocs\":        \"Technical Documentation\",\n\t\t\"catalog\":         \"Table of Contents\",\n\t\t\"home\":            \"Home\",\n\t\t\"sectionContains\": \"This section contains the following:\",\n\t\t\"autoGenerated\":   \"This documentation was automatically generated by [selfmd](https://github.com/monkenwu/selfmd)\",\n\t},\n}\n```\n\n\u003e Source: internal/output/navigation.go#L12-L27\n\nThe `getUIStrings` function automatically falls back to `en-US` when the requested language is not found:\n\n```go\nfunc getUIStrings(lang string) map[string]string {\n\tif s, ok := UIStrings[lang]; ok {\n\t\treturn s\n\t}\n\treturn UIStrings[\"en-US\"]\n}\n```\n\n\u003e Source: internal/output/navigation.go#L30-L35\n\nThe language code is read from `g.Config.Output.Language` at the entry point of `GenerateIndex`:\n\n```go\nfunc (g *Generator) GenerateIndex(_ context.Context, cat *catalog.Catalog) error {\n\tlang := g.Config.Output.Language\n\t// ...\n}\n```\n\n\u003e Source: internal/generator/index_phase.go#L11-L12\n\n## Core Flow\n\n```mermaid\nsequenceDiagram\n    participant Pipeline as \"pipeline.go\\nGenerate()\"\n    participant IndexPhase as \"index_phase.go\\nGenerateIndex()\"\n    participant Nav as \"output/navigation.go\"\n    participant Writer as \"output.Writer\"\n\n    Pipeline-\u003e\u003eIndexPhase: GenerateIndex(ctx, cat)\n    IndexPhase-\u003e\u003eNav: output.GenerateIndex(name, desc, cat, lang)\n    Nav--\u003e\u003eIndexPhase: indexContent (string)\n    IndexPhase-\u003e\u003eWriter: WriteFile(\"index.md\", indexContent)\n\n    IndexPhase-\u003e\u003eNav: output.GenerateSidebar(name, cat, lang)\n    Nav--\u003e\u003eIndexPhase: sidebarContent (string)\n    IndexPhase-\u003e\u003eWriter: WriteFile(\"_sidebar.md\", sidebarContent)\n\n    IndexPhase-\u003e\u003eIndexPhase: cat.Flatten() → get all FlatItems\n\n    loop For each item where HasChildren == true\n        IndexPhase-\u003e\u003eIndexPhase: Filter children where child.ParentPath == item.Path\n        IndexPhase-\u003e\u003eNav: output.GenerateCategoryIndex(item, children, lang)\n        Nav--\u003e\u003eIndexPhase: categoryContent (string)\n        IndexPhase-\u003e\u003eWriter: WritePage(item, categoryContent)\n    end\n\n    IndexPhase--\u003e\u003ePipeline: nil (success)\n\n    Pipeline-\u003e\u003eWriter: WriteViewer(projectName, docMeta)\n    Note over Writer: Generates index.html, app.js,\u003cbr/\u003estyle.css, _data.js (static viewer)\n```\n\n## Path Resolution Logic\n\n### `resolveDirPath`\n\n`resolveDirPath` in `navigation.go` handles two formats for catalog item paths:\n\n- **Format A**: `item.Path` is a relative path (e.g., `\"init\"`), which needs to be joined with the parent path → outputs `\"cli/init\"`\n- **Format B**: `item.Path` already contains the parent path prefix (e.g., `\"cli/init\"`), used directly\n\n```go\nfunc resolveDirPath(itemPath, parentDir string) string {\n\tif parentDir == \"\" {\n\t\treturn itemPath\n\t}\n\tif strings.HasPrefix(itemPath, parentDir+\"/\") {\n\t\treturn itemPath\n\t}\n\treturn parentDir + \"/\" + itemPath\n}\n```\n\n\u003e Source: internal/output/navigation.go#L118-L126\n\n### `computeRelativePath`\n\nLinks to child items in category index pages use `computeRelativePath` to compute relative paths, which internally relies on the standard library's `filepath.Rel`:\n\n```go\nfunc computeRelativePath(fromDir, toDir string) string {\n\trel, err := filepath.Rel(fromDir, toDir)\n\tif err != nil {\n\t\treturn \"./\" + toDir\n\t}\n\treturn filepath.ToSlash(rel)\n}\n```\n\n\u003e Source: internal/output/navigation.go#L129-L135\n\n## Position in the Pipeline\n\n`GenerateIndex` is called by the `Generate()` method in `pipeline.go` as **Phase 4**, immediately after content page generation (Phase 3):\n\n```go\n// Phase 4: Generate Index \u0026 Navigation\nfmt.Println(\"[4/4] Generating navigation and index...\")\nif err := g.GenerateIndex(ctx, cat); err != nil {\n    return fmt.Errorf(\"failed to generate index: %w\", err)\n}\n```\n\n\u003e Source: internal/generator/pipeline.go#L139-L143\n\nAfter `GenerateIndex` completes, the pipeline continues by calling `g.Writer.WriteViewer()` to generate the static HTML viewer (`index.html`, `app.js`, `style.css`, `_data.js`). This is the responsibility of `output.Writer` and is outside the scope of `index_phase.go`.\n\n## Related Links\n\n- [Documentation Generation Pipeline](../index.md)\n- [Catalog Generation Phase](../catalog-phase/index.md)\n- [Content Page Generation Phase](../content-phase/index.md)\n- [Translation Phase](../translate-phase/index.md)\n- [Document Catalog Management](../../catalog/index.md)\n- [Output Writing and Link Repair](../../output-writer/index.md)\n- [Static Documentation Viewer](../../static-viewer/index.md)\n- [Multilingual Support](../../../i18n/index.md)\n- [Overall Flow and Four-Phase Pipeline](../../../architecture/pipeline/index.md)\n\n## Reference Files\n\n| File Path | Description |\n|----------|------|\n| `internal/generator/index_phase.go` | `GenerateIndex` main function, category index page filtering logic |\n| `internal/generator/pipeline.go` | `Generator` struct definition, pipeline flow, Phase 4 call site |\n| `internal/output/navigation.go` | `GenerateIndex`, `GenerateSidebar`, `GenerateCategoryIndex`, and path resolution helper functions |\n| `internal/output/writer.go` | `Writer.WriteFile`, `Writer.WritePage`, `DocMeta`, `LangInfo` struct definitions |\n| `internal/output/viewer.go` | `WriteViewer`, `bundleData`, static viewer asset generation |\n| `internal/catalog/catalog.go` | `Catalog`, `CatalogItem`, `FlatItem` struct definitions, `Flatten()` method |","en-US/core-modules/generator/index.md":"# Document Generation Pipeline\n\nThis section contains the following:\n\n- [Catalog Generation Phase](catalog-phase/index.md)\n- [Content Page Generation Phase](content-phase/index.md)\n- [Index and Navigation Generation Phase](index-phase/index.md)\n- [Translation Phase](translate-phase/index.md)\n","en-US/core-modules/generator/translate-phase/index.md":"# Translation Phase\n\nThe translation phase is responsible for batch-translating documents generated in the primary language into the secondary languages defined in `selfmd.yaml` configuration, using the Claude CLI, and producing a complete navigation structure in the corresponding language subdirectories.\n\n## Overview\n\nThe translation phase is a supplementary process independent of the four-phase document generation pipeline, triggered by the `selfmd translate` command. Its core design principles are:\n\n- **Incremental translation**: Skips existing translated pages by default, only translating new or missing pages\n- **Parallel processing**: Uses `errgroup` and a semaphore to control concurrency, accelerating translation of large documentation sets\n- **Catalog rebuild**: Automatically rebuilds the translated language's document catalog after translation, keeping titles and catalog structure consistent\n- **Leaf-node-only translation**: Category index pages (`HasChildren = true`) are generated automatically by the system and do not require Claude translation\n\nTranslation phase output is placed in the `.doc-build/{language-code}/` subdirectory, stored alongside the primary language output.\n\n### Key Terms\n\n| Term | Description |\n|------|------|\n| Source language | The language configured in `output.language` — the language of the original documents |\n| Secondary languages | The list of target translation languages configured in `output.secondary_languages` |\n| Leaf item | A terminal page in the catalog with no child items — an actual document content page |\n| `langWriter` | An `output.Writer` pointing to a language subdirectory, created via `ForLanguage()` |\n\n## Architecture\n\n```mermaid\nflowchart TD\n    CLI[\"cmd/translate.go\\nrunTranslate()\"]\n    Gen[\"Generator\\nTranslate()\"]\n    CatReader[\"output.Writer\\nReadCatalogJSON()\"]\n    CatParser[\"catalog.Parse()\"]\n    Flatten[\"catalog.Flatten()\"]\n    LangWriter[\"output.Writer\\nForLanguage(lang)\"]\n    TranslatePages[\"Generator\\ntranslatePages()\"]\n    PromptEngine[\"prompt.Engine\\nRenderTranslate()\"]\n    ClaudeRunner[\"claude.Runner\\nRunWithRetry()\"]\n    ExtractDoc[\"claude.ExtractDocumentTag()\"]\n    ExtractTitle[\"extractTitle()\"]\n    BuildCat[\"buildTranslatedCatalog()\"]\n    NavGen[\"output.GenerateIndex()\\noutput.GenerateSidebar()\\noutput.GenerateCategoryIndex()\"]\n    ViewerGen[\"output.Writer\\nWriteViewer()\"]\n\n    CLI --\u003e|\"TranslateOptions\"| Gen\n    Gen --\u003e CatReader\n    CatReader --\u003e|\"JSON string\"| CatParser\n    CatParser --\u003e|\"*Catalog\"| Flatten\n    Flatten --\u003e|\"[]FlatItem\"| TranslatePages\n    Gen --\u003e LangWriter\n    LangWriter --\u003e TranslatePages\n    TranslatePages --\u003e|\"TranslatePromptData\"| PromptEngine\n    PromptEngine --\u003e|\"rendered prompt\"| ClaudeRunner\n    ClaudeRunner --\u003e|\"RunResult\"| ExtractDoc\n    ExtractDoc --\u003e|\"translated content\"| ExtractTitle\n    ExtractTitle --\u003e|\"translatedTitles map\"| BuildCat\n    BuildCat --\u003e|\"*Catalog (translated)\"| NavGen\n    NavGen --\u003e LangWriter\n    Gen --\u003e ViewerGen\n```\n\n## Core Data Structures\n\n### TranslateOptions\n\nConfiguration options for translation execution, passed in from the CLI command:\n\n```go\ntype TranslateOptions struct {\n    TargetLanguages []string\n    Force           bool\n    Concurrency     int\n}\n```\n\n\u003e Source: internal/generator/translate_phase.go#L21-L25\n\n### TranslatePromptData\n\nData passed to the translation prompt template:\n\n```go\ntype TranslatePromptData struct {\n    SourceLanguage     string // e.g., \"zh-TW\"\n    SourceLanguageName string // e.g., \"繁體中文\"\n    TargetLanguage     string // e.g., \"en-US\"\n    TargetLanguageName string // e.g., \"English\"\n    SourceContent      string // the full markdown content to translate\n}\n```\n\n\u003e Source: internal/prompt/engine.go#L98-L104\n\n## Core Flow\n\n### Translate() — Main Flow\n\n```mermaid\nsequenceDiagram\n    participant CLI as selfmd translate\n    participant G as Generator\n    participant W as Writer\n    participant Cat as catalog\n    participant Nav as output\n\n    CLI-\u003e\u003eG: Translate(ctx, opts)\n    G-\u003e\u003eW: ReadCatalogJSON()\n    W--\u003e\u003eG: JSON string\n    G-\u003e\u003eCat: Parse(json)\n    Cat--\u003e\u003eG: *Catalog\n    G-\u003e\u003eCat: Flatten()\n    Cat--\u003e\u003eG: []FlatItem\n\n    loop For each target language\n        G-\u003e\u003eW: ForLanguage(targetLang)\n        W--\u003e\u003eG: langWriter\n        G-\u003e\u003eG: translatePages(ctx, items, langWriter, ...)\n        Note over G: Translate all leaf-node pages in parallel\n        G-\u003e\u003eG: buildTranslatedCatalog(cat, translatedTitles)\n        G-\u003e\u003eNav: GenerateIndex(projectName, desc, translatedCat, lang)\n        G-\u003e\u003eNav: GenerateSidebar(projectName, translatedCat, lang)\n        G-\u003e\u003eNav: GenerateCategoryIndex(item, children, lang)\n    end\n\n    G-\u003e\u003eW: WriteViewer(projectName, docMeta)\n```\n\n### translatePages() — Parallel Translation\n\n`translatePages()` processes only leaf-node pages (`HasChildren == false`), using `errgroup` and a semaphore for concurrency control:\n\n```go\neg, ctx := errgroup.WithContext(ctx)\nsem := make(chan struct{}, opts.Concurrency)\n\nfor _, item := range leafItems {\n    item := item\n    eg.Go(func() error {\n        // Skip if already translated and not forcing\n        if !opts.Force \u0026\u0026 langWriter.PageExists(item) {\n            skipped.Add(1)\n            // ...\n            return nil\n        }\n\n        sem \u003c- struct{}{}\n        defer func() { \u003c-sem }()\n\n        // Read source content\n        sourceContent, err := g.Writer.ReadPage(item)\n        // ...\n\n        // Render translate prompt\n        data := prompt.TranslatePromptData{ /* ... */ }\n        rendered, err := g.Engine.RenderTranslate(data)\n\n        // Call Claude\n        result, err := g.Runner.RunWithRetry(ctx, claude.RunOptions{\n            Prompt:  rendered,\n            WorkDir: g.RootDir,\n        })\n\n        // Extract translated content\n        content, err := claude.ExtractDocumentTag(result.Content)\n        // ...\n\n        // Write translated page\n        langWriter.WritePage(item, content)\n        return nil\n    })\n}\neg.Wait()\n```\n\n\u003e Source: internal/generator/translate_phase.go#L150-L249\n\n### Translation Skip Logic\n\nWhen `--force` is not specified, a page is skipped if the corresponding translated file already exists in the target language directory. When skipping, the system still attempts to extract the title from the existing translation to ensure catalog completeness:\n\n```go\nif !opts.Force \u0026\u0026 langWriter.PageExists(item) {\n    skipped.Add(1)\n    // Try to extract title from existing translation\n    if content, err := langWriter.ReadPage(item); err == nil {\n        if title := extractTitle(content); title != \"\" {\n            titlesMu.Lock()\n            translatedTitles[item.Path] = title\n            titlesMu.Unlock()\n        }\n    }\n    fmt.Printf(\"      [skip] %s (already exists)\\n\", item.Title)\n    return nil\n}\n```\n\n\u003e Source: internal/generator/translate_phase.go#L157-L169\n\n## Translated Catalog Rebuild\n\nAfter translation completes, the system rebuilds the translated language's `Catalog` using the collected translated titles (`translatedTitles` map), then uses this catalog to generate the navigation structure:\n\n```go\n// buildTranslatedCatalog creates a copy of the catalog with translated titles.\nfunc buildTranslatedCatalog(original *catalog.Catalog, translatedTitles map[string]string) *catalog.Catalog {\n    translated := \u0026catalog.Catalog{\n        Items: translateCatalogItems(original.Items, translatedTitles, \"\"),\n    }\n    return translated\n}\n```\n\n\u003e Source: internal/generator/translate_phase.go#L276-L282\n\n`translateCatalogItems()` recursively traverses all catalog items. If a `dotPath` (e.g., `core-modules.scanner`) has a corresponding translated title in `translatedTitles`, the translated title is used:\n\n```go\n// Use translated title if available\nif translatedTitle, ok := titles[dotPath]; ok {\n    result[i].Title = translatedTitle\n}\n```\n\n\u003e Source: internal/generator/translate_phase.go#L298-L300\n\n## Translation Prompt Template\n\nTranslation uses a shared template (`templates/translate.tmpl`) rather than language-specific subfolders, ensuring the translation command is language-agnostic:\n\n```\nYou are a professional technical documentation translator. Your task is to translate\nthe following documentation page from {{.SourceLanguageName}} ({{.SourceLanguage}})\nto {{.TargetLanguageName}} ({{.TargetLanguage}}).\n\n## Translation Rules\n1. Preserve all Markdown formatting\n2. Do not translate code — code identifiers, file paths remain as-is\n3. Translate section headings\n4. Preserve relative links — only translate display text\n5. Preserve Mermaid diagrams — translate labels but keep syntax correct\n6. Preserve source annotations\n7. Natural translation — produce fluent {{.TargetLanguageName}}\n8. Preserve reference file tables — translate headers but keep paths\n```\n\n\u003e Source: internal/prompt/templates/translate.tmpl#L1-L35\n\n`Engine.RenderTranslate()` uses `renderShared()` rather than `render()`, so the template is executed from the shared `sharedTemplates` rather than language-specific `templates`:\n\n```go\nfunc (e *Engine) RenderTranslate(data TranslatePromptData) (string, error) {\n    return e.renderShared(\"translate.tmpl\", data)\n}\n```\n\n\u003e Source: internal/prompt/engine.go#L132-L134\n\n## Output Structure\n\nAfter translation, each secondary language's output is placed under `.doc-build/{lang}/`:\n\n```\n.doc-build/\n├── index.md            # Primary language homepage\n├── _sidebar.md         # Primary language sidebar\n├── _catalog.json       # Primary language catalog JSON\n├── en-US/              # Secondary language directory (example)\n│   ├── index.md        # Translated homepage\n│   ├── _sidebar.md     # Translated sidebar\n│   ├── _catalog.json   # Translated catalog JSON (with translated titles)\n│   └── {section}/\n│       └── {page}/\n│           └── index.md   # Translated page\n└── index.html          # Browser entry point (contains all language data)\n```\n\nThe `ForLanguage()` method creates a Writer pointing to the language subdirectory:\n\n```go\nfunc (w *Writer) ForLanguage(lang string) *Writer {\n    return \u0026Writer{\n        BaseDir: filepath.Join(w.BaseDir, lang),\n    }\n}\n```\n\n\u003e Source: internal/output/writer.go#L139-L143\n\n## Localization of Navigation Components\n\nThe `index.md`, `_sidebar.md`, and category index pages generated after translation use language-specific UI strings provided by `output.UIStrings`:\n\n```go\nvar UIStrings = map[string]map[string]string{\n    \"zh-TW\": {\n        \"techDocs\":        \"技術文件\",\n        \"sectionContains\": \"本章節包含以下內容：\",\n        // ...\n    },\n    \"en-US\": {\n        \"techDocs\":        \"Technical Documentation\",\n        \"sectionContains\": \"This section contains the following:\",\n        // ...\n    },\n}\n```\n\n\u003e Source: internal/output/navigation.go#L12-L27\n\n## Title Extraction Helper\n\n`extractTitle()` uses a regular expression to extract the first `#` heading from a Markdown document, used to collect translated page titles and rebuild the translated catalog:\n\n```go\nfunc extractTitle(content string) string {\n    re := regexp.MustCompile(`(?m)^#\\s+(.+)$`)\n    match := re.FindStringSubmatch(content)\n    if len(match) \u003e= 2 {\n        return strings.TrimSpace(match[1])\n    }\n    return \"\"\n}\n```\n\n\u003e Source: internal/generator/translate_phase.go#L267-L274\n\n## CLI Usage Examples\n\nThe translation phase is triggered via the `selfmd translate` command:\n\n```go\nvar translateCmd = \u0026cobra.Command{\n    Use:   \"translate\",\n    Short: \"Translate primary language documents into secondary languages\",\n    Long: `Using the generated primary language documents as the source, translate them\ninto the secondary languages defined in the configuration file.\nTranslation output is placed in .doc-build/{language-code}/ subdirectories.`,\n    RunE: runTranslate,\n}\n```\n\n\u003e Source: cmd/translate.go#L24-L30\n\nAvailable flags:\n\n| Flag | Description |\n|------|------|\n| `--lang \u003ccode,...\u003e` | Translate only the specified languages (default: all secondary languages) |\n| `--force` | Force re-translation of existing files |\n| `--concurrency \u003cn\u003e` | Concurrency level (overrides `max_concurrent` in the config file) |\n\n**Prerequisite**: `selfmd generate` must be run first to generate primary language documents. The translation phase depends on `.doc-build/_catalog.json` and the original page content.\n\n## Related Links\n\n- [selfmd translate](../../../cli/cmd-translate/index.md)\n- [Document Generation Pipeline](../index.md)\n- [Index and Navigation Generation Phase](../index-phase/index.md)\n- [Multilingual Support](../../../i18n/index.md)\n- [Translation Workflow](../../../i18n/translation-workflow/index.md)\n- [Supported Languages and Templates](../../../i18n/supported-languages/index.md)\n- [Prompt Template Engine](../../prompt-engine/index.md)\n- [Claude CLI Runner](../../claude-runner/index.md)\n- [Output Writer and Link Fixing](../../output-writer/index.md)\n\n## Reference Files\n\n| File Path | Description |\n|----------|------|\n| `internal/generator/translate_phase.go` | Translation phase core implementation: `Translate()`, `translatePages()`, `buildTranslatedCatalog()`, `extractTitle()` |\n| `internal/generator/pipeline.go` | `Generator` struct definition, `NewGenerator()`, `buildDocMeta()` |\n| `internal/prompt/engine.go` | `TranslatePromptData` struct, `RenderTranslate()` method |\n| `internal/prompt/templates/translate.tmpl` | Shared translation prompt template |\n| `internal/output/writer.go` | `Writer`, `ForLanguage()`, `PageExists()`, `ReadPage()`, `WritePage()` |\n| `internal/output/navigation.go` | `UIStrings`, `GenerateIndex()`, `GenerateSidebar()`, `GenerateCategoryIndex()` |\n| `internal/catalog/catalog.go` | `Catalog`, `FlatItem`, `Flatten()`, `CatalogItem` |\n| `internal/config/config.go` | `OutputConfig`, `GetLangNativeName()`, `KnownLanguages` |\n| `cmd/translate.go` | `translate` CLI command implementation |","en-US/core-modules/incremental-update/index.md":"# Incremental Update\n\nThe Incremental Update module enables selfmd to regenerate only the affected documentation pages after git changes, avoiding the time-consuming full `generate` process every time and significantly reducing both time and API costs.\n\n## Overview\n\nThe core idea behind incremental updates is: **only update pages that need updating**. When code changes occur, the system will:\n\n1. Retrieve the list of changed source files from the git diff\n2. Match which existing documentation pages reference those changed files (called \"matches\")\n3. For new files that don't yet have corresponding documentation, determine whether new pages need to be created\n4. Regenerate only the pages that actually need updating\n\nThe system tracks the last-updated commit by persisting a `_last_commit` file in the output directory, allowing each `selfmd update` run to precisely calculate what needs to be regenerated.\n\n**Key Terms:**\n\n| Term | Description |\n|------|-------------|\n| Matched pages (matched) | Existing documentation pages whose content contains paths of changed files |\n| Unmatched files (unmatched) | Changed files not referenced by any documentation page |\n| Leaf promotion | When an existing leaf node in the documentation tree needs to become a parent node, its original content is automatically moved to an `overview` child page |\n| Base commit (previousCommit) | The starting commit used as the basis for diff comparison against the current HEAD |\n\n## Architecture\n\n```mermaid\nflowchart TD\n    CLI[\"cmd/update.go\\nrunUpdate()\"]\n    GitPkg[\"git package\\nGetChangedFiles()\\nFilterChangedFiles()\\nParseChangedFiles()\"]\n    Scanner[\"scanner.Scan()\"]\n    Updater[\"Generator.Update()\"]\n    Match[\"matchChangedFilesToDocs()\\nMatch changed files vs existing pages\"]\n    DetermineMatched[\"determineMatchedUpdates()\\nAsk Claude: which pages need updating\"]\n    DetermineUnmatched[\"determineUnmatchedPages()\\nAsk Claude: whether new pages are needed\"]\n    AddCatalog[\"addItemToCatalog()\\nUpdate catalog tree\"]\n    Generate[\"generateSinglePage()\\nRegenerate page content\"]\n    GenerateIndex[\"GenerateIndex()\\nUpdate navigation and index\"]\n    Writer[\"output.Writer\\nRead/write pages, catalog, commit records\"]\n    CatalogPkg[\"catalog.Catalog\\nCatalog data structure\"]\n    ClaudeRunner[\"claude.Runner\\nCall Claude CLI\"]\n    PromptEngine[\"prompt.Engine\\nRenderUpdateMatched()\\nRenderUpdateUnmatched()\"]\n\n    CLI --\u003e GitPkg\n    CLI --\u003e Scanner\n    CLI --\u003e Updater\n    Updater --\u003e Match\n    Updater --\u003e DetermineMatched\n    Updater --\u003e DetermineUnmatched\n    Updater --\u003e AddCatalog\n    Updater --\u003e Generate\n    Updater --\u003e GenerateIndex\n    Updater --\u003e Writer\n    DetermineMatched --\u003e ClaudeRunner\n    DetermineMatched --\u003e PromptEngine\n    DetermineUnmatched --\u003e ClaudeRunner\n    DetermineUnmatched --\u003e PromptEngine\n    Generate --\u003e ClaudeRunner\n    Match --\u003e Writer\n    Match --\u003e CatalogPkg\n    AddCatalog --\u003e CatalogPkg\n    Writer --\u003e CatalogPkg\n```\n\n## Data Structures\n\n### Core Types\n\n```go\n// UpdateMatchedResult represents a page that Claude determined needs regeneration.\ntype UpdateMatchedResult struct {\n\tCatalogPath string `json:\"catalogPath\"`\n\tTitle       string `json:\"title\"`\n\tReason      string `json:\"reason\"`\n}\n\n// UpdateUnmatchedResult represents a new page that Claude determined should be created.\ntype UpdateUnmatchedResult struct {\n\tCatalogPath string `json:\"catalogPath\"`\n\tTitle       string `json:\"title\"`\n\tReason      string `json:\"reason\"`\n}\n```\n\n\u003e Source: internal/generator/updater.go#L17-L29\n\n```go\n// matchResult holds the mapping between changed files and the doc pages that reference them.\ntype matchResult struct {\n\t// changedFile is the source file path that changed\n\tchangedFile string\n\t// pages are the doc pages that reference this file\n\tpages []catalog.FlatItem\n}\n```\n\n\u003e Source: internal/generator/updater.go#L168-L174\n\n```go\n// promotedLeaf records when a leaf node was promoted to a parent by adding an \"overview\" child.\ntype promotedLeaf struct {\n\t// OriginalPath is the dot-notation path of the original leaf (e.g. \"core-modules.mcp-integration\")\n\tOriginalPath string\n\t// OverviewPath is the dot-notation path of the new overview child (e.g. \"core-modules.mcp-integration.overview\")\n\tOverviewPath string\n\t// OriginalTitle is the title of the original leaf\n\tOriginalTitle string\n}\n```\n\n\u003e Source: internal/generator/updater.go#L359-L367\n\n### Prompt Data Structures\n\nIncremental update uses two prompt data structures, corresponding to the two Claude calls for \"matched page determination\" and \"unmatched page determination\":\n\n```go\n// UpdateMatchedPromptData holds data for deciding which existing pages need regeneration.\ntype UpdateMatchedPromptData struct {\n\tRepositoryName string\n\tLanguage       string\n\tChangedFiles   string // list of changed source files\n\tAffectedPages  string // pages that reference these files (path + title + summary)\n}\n\n// UpdateUnmatchedPromptData holds data for deciding whether new pages are needed.\ntype UpdateUnmatchedPromptData struct {\n\tRepositoryName  string\n\tLanguage        string\n\tUnmatchedFiles  string // changed files not referenced in any existing doc\n\tExistingCatalog string // existing catalog JSON\n\tCatalogTable    string // formatted link table of all pages\n}\n```\n\n\u003e Source: internal/prompt/engine.go#L80-L95\n\n## Core Flow\n\n### The Four Steps of Update()\n\n```mermaid\nflowchart TD\n    A[\"Start: Update()\"] --\u003e B[\"Read _catalog.json\\nParse existing catalog\"]\n    B --\u003e C[\"ParseChangedFiles()\\nParse git diff output\"]\n    C --\u003e D{Any changed files?}\n    D --\u003e|No| E[\"Print 'no changes'\\nExit\"]\n    D --\u003e|Yes| F[\"[1/4] matchChangedFilesToDocs()\\nMatch changed files against doc pages\"]\n    F --\u003e G[\"[2/4] determineMatchedUpdates()\\n(when matches exist)\\nClaude determines which pages need updating\"]\n    G --\u003e H[\"[3/4] determineUnmatchedPages()\\n(when unmatched files exist)\\nClaude determines whether new pages are needed\"]\n    H --\u003e I{New pages needed?}\n    I --\u003e|Yes| J[\"addItemToCatalog()\\nUpdate catalog tree\"]\n    J --\u003e K[\"WriteCatalogJSON()\\nSave updated catalog\"]\n    K --\u003e L[\"[4/4] generateSinglePage()\\nRegenerate pages one by one\"]\n    I --\u003e|No| L\n    L --\u003e M{New pages added?}\n    M --\u003e|Yes| N[\"GenerateIndex()\\nRegenerate navigation and index\"]\n    M --\u003e|No| O[\"SaveLastCommit()\\nSave current commit\"]\n    N --\u003e O\n    O --\u003e P[\"Print total cost\\nExit\"]\n```\n\n### Matching Logic\n\n`matchChangedFilesToDocs()` uses a **string search** strategy: it reads all documentation page contents at once, then checks whether each changed file's path appears in the text of any page.\n\n```go\n// For each changed file, find which pages reference it\nfor _, f := range files {\n    var matchedPages []catalog.FlatItem\n    for _, item := range items {\n        content, ok := pageContents[item.Path]\n        if !ok {\n            continue\n        }\n        if strings.Contains(content, f.Path) {\n            matchedPages = append(matchedPages, item)\n        }\n    }\n    // ...\n}\n```\n\n\u003e Source: internal/generator/updater.go#L191-L213\n\n### Leaf Promotion\n\nWhen Claude decides to add a child page under an existing leaf node (e.g., adding `core-modules.scanner.advanced` under `core-modules.scanner`), the system automatically promotes the original leaf node to a parent node and moves its original content to an `overview` child page:\n\n```go\nif len(item.Children) == 0 {\n    // This is a leaf node that needs to become a parent.\n    // Add an \"overview\" child to preserve the original content.\n    (*children)[i].Children = append((*children)[i].Children, catalog.CatalogItem{\n        Title: item.Title,\n        Path:  \"overview\",\n        Order: 0,\n    })\n    *promoted = \u0026promotedLeaf{\n        OriginalPath:  currentDotPath,\n        OverviewPath:  currentDotPath + \".overview\",\n        OriginalTitle: item.Title,\n    }\n}\n```\n\n\u003e Source: internal/generator/updater.go#L402-L414\n\n## Commit Tracking Mechanism\n\nIncremental updates rely on a \"base commit\" (previousCommit) to calculate the git diff range. The system uses the following priority order:\n\n```mermaid\nflowchart TD\n    A[\"runUpdate() starts\"] --\u003e B{Did the user\\nspecify --since?}\n    B --\u003e|Yes| C[\"Use the commit specified\\nby --since as the base\"]\n    B --\u003e|No| D[\"ReadLastCommit()\\nRead _last_commit file\"]\n    D --\u003e E{Read successful?}\n    E --\u003e|Yes| F[\"Use the commit saved from\\nthe last generate/update\"]\n    E --\u003e|No| G[\"GetMergeBase()\\nCalculate divergence point from baseBranch\"]\n    G --\u003e H{Successful?}\n    H --\u003e|Yes| I[\"Use the merge-base commit\"]\n    H --\u003e|No| J[\"Return error:\\nPrompt user to run selfmd generate first\"]\n```\n\n\u003e Source: cmd/update.go#L67-L81\n\nAfter each successful `update` run, the system saves the current HEAD commit to the `_last_commit` file for use in the next incremental update:\n\n```go\n// Save current commit for next incremental update\nif err := g.Writer.SaveLastCommit(currentCommit); err != nil {\n    g.Logger.Warn(\"Failed to save commit record\", \"error\", err)\n}\n```\n\n\u003e Source: internal/generator/updater.go#L159-L162\n\n`_last_commit` is also written after `generate` completes, ensuring `update` can be used immediately after the first run:\n\n```go\n// Save current commit for incremental updates\nif git.IsGitRepo(g.RootDir) {\n    if commit, err := git.GetCurrentCommit(g.RootDir); err == nil {\n        if err := g.Writer.SaveLastCommit(commit); err != nil {\n            g.Logger.Warn(\"Failed to save commit record\", \"error\", err)\n        }\n    }\n}\n```\n\n\u003e Source: internal/generator/pipeline.go#L157-L164\n\n## Usage Examples\n\n### Basic Incremental Update\n\n```bash\n# Automatically detect all changes since the last generate/update\nselfmd update\n```\n\n### Specifying a Base Commit\n\n```bash\n# Compare against a specific commit\nselfmd update --since abc1234\n\n# Compare against a tag or branch\nselfmd update --since v1.0.0\nselfmd update --since main\n```\n\n\u003e Source: cmd/update.go#L19-L31\n\n### CLI Command Definition\n\n```go\nvar updateCmd = \u0026cobra.Command{\n    Use:   \"update\",\n    Short: \"Incrementally update documentation based on git changes\",\n    Long: `Analyze git changes and incrementally update affected documentation pages.\nRequires selfmd generate to have been run first to produce the initial documentation.`,\n    RunE: runUpdate,\n}\n\nfunc init() {\n    updateCmd.Flags().StringVar(\u0026sinceCommit, \"since\", \"\", \"Compare against the specified commit (defaults to the commit from the last generate/update)\")\n    rootCmd.AddCommand(updateCmd)\n}\n```\n\n\u003e Source: cmd/update.go#L21-L32\n\n### Example Output\n\nThe system displays progress across four steps during execution:\n\n```\nDiff range: abc12345..def67890\nChanged files:\nM   internal/scanner/scanner.go\nA   internal/scanner/filetree.go\n\n[1/4] Searching for affected documentation pages...\n      2 changed files matched to existing docs, 0 unmatched\n[2/4] Calling Claude to determine which pages need updating...\n      → Project Scanner: core logic in scanner.go has changed\n      Done (1 page needs updating)\n[3/4] All changed files already have corresponding docs, skipping\n[4/4] Regenerating 1 page...\n      [1/1] Project Scanner (core-modules.scanner)... Done (12.3s, $0.0024)\n\nUpdate complete! Total cost: $0.0024 USD\n```\n\n## Prerequisites\n\nRunning `selfmd update` requires the following conditions to be met:\n\n1. **Must be a git repository**: The system checks `git.IsGitRepo(rootDir)` at startup and returns an error immediately if not in a git repository\n2. **Must have run `selfmd generate` first**: The system needs to read `_catalog.json` to understand the existing documentation structure; if the catalog doesn't exist, it will prompt you to run `generate` first\n3. **Claude CLI must be available**: Same as `generate`, requires Claude CLI to be functioning properly\n\n```go\nif !git.IsGitRepo(rootDir) {\n    return fmt.Errorf(\"current directory is not a git repository, cannot perform incremental update\")\n}\n```\n\n\u003e Source: cmd/update.go#L49-L51\n\n## Related Links\n\n- [Git Diff Change Detection](../../git-integration/change-detection/index.md)\n- [Affected Page Determination Logic](../../git-integration/affected-pages/index.md)\n- [Documentation Catalog Management](../catalog/index.md)\n- [Documentation Generation Pipeline](../generator/index.md)\n- [Content Page Generation Phase](../generator/content-phase/index.md)\n- [Prompt Template Engine](../prompt-engine/index.md)\n- [selfmd update Command](../../cli/cmd-update/index.md)\n\n## Reference Files\n\n| File Path | Description |\n|-----------|-------------|\n| `internal/generator/updater.go` | Core incremental update logic: `Update()`, `matchChangedFilesToDocs()`, `determineMatchedUpdates()`, `determineUnmatchedPages()`, `addItemToCatalog()` |\n| `internal/generator/pipeline.go` | `Generator` struct definition, full `Generate()` pipeline (including commit saving) |\n| `internal/generator/content_phase.go` | `generateSinglePage()` implementation, reused by the updater to regenerate pages |\n| `internal/git/git.go` | Git operation wrappers: `GetChangedFiles()`, `FilterChangedFiles()`, `ParseChangedFiles()`, `GetCurrentCommit()` |\n| `internal/catalog/catalog.go` | `Catalog`, `CatalogItem`, `FlatItem` data structures and the `Flatten()` method |\n| `internal/output/writer.go` | `ReadPage()`, `WritePage()`, `SaveLastCommit()`, `ReadLastCommit()`, `WriteCatalogJSON()` |\n| `internal/prompt/engine.go` | `UpdateMatchedPromptData`, `UpdateUnmatchedPromptData` data structures and `RenderUpdateMatched()`, `RenderUpdateUnmatched()` |\n| `cmd/update.go` | `selfmd update` command definition and `runUpdate()` execution logic |","en-US/core-modules/index.md":"# Core Modules\n\nThis section contains the following:\n\n- [Project Scanner](scanner/index.md)\n- [Documentation Catalog Management](catalog/index.md)\n- [Prompt Template Engine](prompt-engine/index.md)\n- [Claude CLI Runner](claude-runner/index.md)\n- [Document Generation Pipeline](generator/index.md)\n- [Incremental Update](incremental-update/index.md)\n- [Output Writing \u0026 Link Fixing](output-writer/index.md)\n- [Static Document Viewer](static-viewer/index.md)\n","en-US/core-modules/output-writer/index.md":"# Output Writing \u0026 Link Fixing\n\nThe `internal/output` package is responsible for writing generated Markdown files to disk, fixing relative links within documents, generating navigation structures, and bundling static browser assets.\n\n## Overview\n\nAfter the Claude CLI completes content generation, the system needs to persist results to the `.doc-build/` output directory and ensure that internal links between pages are valid and navigable. The `output` package consists of four cooperating components:\n\n| Component | File | Responsibility |\n|-----------|------|----------------|\n| `Writer` | `writer.go` | Low-level file I/O, unified management of all write operations |\n| `LinkFixer` | `linkfixer.go` | Detects and fixes broken relative links |\n| Navigation functions | `navigation.go` | Generates `index.md`, `_sidebar.md`, and category index pages |\n| `WriteViewer` | `viewer.go` | Bundles static HTML/JS/CSS and the `_data.js` data package |\n\nWithin the pipeline, the `output` package is invoked in both phase 3 (content page generation) and phase 4 (navigation and static browser generation).\n\n## Architecture\n\n```mermaid\nflowchart TD\n    Generator[\"Generator (pipeline.go)\"]\n\n    subgraph output_pkg[\"internal/output package\"]\n        Writer[\"Writer\\n(writer.go)\"]\n        LinkFixer[\"LinkFixer\\n(linkfixer.go)\"]\n        NavFuncs[\"Navigation functions\\n(navigation.go)\"]\n        ViewerFunc[\"WriteViewer\\n(viewer.go)\"]\n    end\n\n    subgraph output_dir[\".doc-build/ output directory\"]\n        Pages[\"*.md document pages\"]\n        Catalog[\"_catalog.json\"]\n        LastCommit[\"_last_commit\"]\n        Index[\"index.md / _sidebar.md\"]\n        HTML[\"index.html / app.js / style.css\"]\n        DataJS[\"_data.js (data package)\"]\n        DocMeta[\"_doc_meta.json\"]\n    end\n\n    Generator --\u003e|\"WritePage / WriteFile\"| Writer\n    Generator --\u003e|\"NewLinkFixer → FixLinks\"| LinkFixer\n    Generator --\u003e|\"GenerateIndex / GenerateSidebar\"| NavFuncs\n    Generator --\u003e|\"WriteViewer\"| ViewerFunc\n\n    Writer --\u003e Pages\n    Writer --\u003e Catalog\n    Writer --\u003e LastCommit\n    NavFuncs --\u003e Index\n    ViewerFunc --\u003e HTML\n    ViewerFunc --\u003e DataJS\n    ViewerFunc --\u003e DocMeta\n\n    LinkFixer -.-\u003e|\"returns fixed content\"| Writer\n```\n\n## Writer — File Writer\n\n`Writer` is the unified entry point for all disk operations. It holds the absolute path `BaseDir` of the output directory (defaulting to `.doc-build/`).\n\n### Struct Definition\n\n```go\n// Writer handles writing documentation files to the output directory.\ntype Writer struct {\n\tBaseDir string // absolute path to .doc-build/\n}\n\n// NewWriter creates a new output writer.\nfunc NewWriter(baseDir string) *Writer {\n\treturn \u0026Writer{BaseDir: baseDir}\n}\n```\n\n\u003e Source: internal/output/writer.go#L26-L33\n\n### Core Methods\n\n#### Directory \u0026 Lifecycle\n\n```go\n// Clean removes the output directory and recreates it.\nfunc (w *Writer) Clean() error {\n\tif err := os.RemoveAll(w.BaseDir); err != nil {\n\t\treturn fmt.Errorf(\"清除輸出目錄失敗: %w\", err)\n\t}\n\treturn os.MkdirAll(w.BaseDir, 0755)\n}\n\n// EnsureDir ensures the output directory exists.\nfunc (w *Writer) EnsureDir() error {\n\treturn os.MkdirAll(w.BaseDir, 0755)\n}\n```\n\n\u003e Source: internal/output/writer.go#L36-L46\n\n#### Page Writing \u0026 Reading\n\n```go\n// WritePage writes a documentation page for a catalog item.\nfunc (w *Writer) WritePage(item catalog.FlatItem, content string) error {\n\tdir := filepath.Join(w.BaseDir, item.DirPath)\n\tif err := os.MkdirAll(dir, 0755); err != nil {\n\t\treturn fmt.Errorf(\"建立目錄 %s 失敗: %w\", dir, err)\n\t}\n\n\tpath := filepath.Join(dir, \"index.md\")\n\tif err := os.WriteFile(path, []byte(content), 0644); err != nil {\n\t\treturn fmt.Errorf(\"寫入 %s 失敗: %w\", path, err)\n\t}\n\treturn nil\n}\n```\n\n\u003e Source: internal/output/writer.go#L48-L60\n\n`WritePage` accepts a `catalog.FlatItem` (the flattened representation of a catalog entry) and automatically creates `index.md` under the corresponding `DirPath`.\n\n#### Page Existence Check\n\n```go\n// PageExists checks if a documentation page exists and has valid content.\nfunc (w *Writer) PageExists(item catalog.FlatItem) bool {\n\tpath := filepath.Join(w.BaseDir, item.DirPath, \"index.md\")\n\tdata, err := os.ReadFile(path)\n\tif err != nil {\n\t\treturn false\n\t}\n\tcontent := strings.TrimSpace(string(data))\n\tif content == \"\" {\n\t\treturn false\n\t}\n\tif strings.Contains(content, \"此頁面產生失敗\") {\n\t\treturn false\n\t}\n\treturn true\n}\n```\n\n\u003e Source: internal/output/writer.go#L95-L111\n\n`PageExists` does more than check if a file exists — it also excludes blank pages and failed placeholder pages (those containing the failure marker), ensuring that incremental updates correctly identify which pages need to be regenerated.\n\n#### Multi-Language Support\n\n```go\n// ForLanguage returns a new Writer that writes to a language-specific subdirectory.\nfunc (w *Writer) ForLanguage(lang string) *Writer {\n\treturn \u0026Writer{\n\t\tBaseDir: filepath.Join(w.BaseDir, lang),\n\t}\n}\n```\n\n\u003e Source: internal/output/writer.go#L138-L143\n\nTranslated content for each language is written to a `.doc-build/{lang}/` subdirectory. `ForLanguage` creates a `Writer` instance pointing to that subdirectory.\n\n#### Persistence Helper Files\n\n| Method | File | Purpose |\n|--------|------|---------|\n| `WriteCatalogJSON` | `_catalog.json` | Saves the catalog structure for reuse during incremental updates |\n| `ReadCatalogJSON` | `_catalog.json` | Reads back the catalog structure |\n| `SaveLastCommit` | `_last_commit` | Saves the Git commit hash |\n| `ReadLastCommit` | `_last_commit` | Reads the last commit for diff computation |\n\n## LinkFixer — Link Fixer\n\n`LinkFixer` validates and repairs all internal links in Markdown before content is written to disk, handling cases where Claude generates incorrectly formatted links (e.g., dot-notation, missing path segments).\n\n### Initialization\n\n```go\n// LinkFixer validates and fixes relative links in generated markdown content.\ntype LinkFixer struct {\n\tallItems  []catalog.FlatItem\n\tdirPaths  map[string]bool   // set of all valid dirPaths\n\tpathIndex map[string]string // various lookup keys → dirPath\n}\n\n// NewLinkFixer creates a link fixer from a catalog.\nfunc NewLinkFixer(cat *catalog.Catalog) *LinkFixer {\n\titems := cat.Flatten()\n\tdirPaths := make(map[string]bool)\n\tpathIndex := make(map[string]string)\n\n\tfor _, item := range items {\n\t\tdirPaths[item.DirPath] = true\n\n\t\t// index by multiple keys for fuzzy matching\n\t\tpathIndex[item.DirPath] = item.DirPath\n\t\tpathIndex[item.Path] = item.DirPath                          // dot-notation\n\t\tpathIndex[strings.ReplaceAll(item.Path, \".\", \"/\")] = item.DirPath // explicit slash conversion\n\n\t\t// index by last segment (e.g., \"scanner\" → \"core-modules/scanner\")\n\t\tparts := strings.Split(item.DirPath, \"/\")\n\t\tlastSeg := parts[len(parts)-1]\n\t\tif _, exists := pathIndex[lastSeg]; !exists {\n\t\t\tpathIndex[lastSeg] = item.DirPath\n\t\t}\n\t}\n\n\treturn \u0026LinkFixer{\n\t\tallItems:  items,\n\t\tdirPaths:  dirPaths,\n\t\tpathIndex: pathIndex,\n\t}\n}\n```\n\n\u003e Source: internal/output/linkfixer.go#L11-L48\n\n`pathIndex` builds a multi-key index for flexible fuzzy lookup:\n- `dirPath` (e.g., `core-modules/scanner`)\n- `dot-notation path` (e.g., `core-modules.scanner`)\n- last path segment (e.g., `scanner`)\n- lowercase variants\n\n### Link Fixing Flow\n\n```go\n// FixLinks scans markdown content for relative links and fixes broken ones.\nfunc (lf *LinkFixer) FixLinks(content string, currentDirPath string) string {\n\t// match markdown links: [text](target)\n\tlinkRe := regexp.MustCompile(`\\[([^\\]]+)\\]\\(([^)]+)\\)`)\n\n\treturn linkRe.ReplaceAllStringFunc(content, func(match string) string {\n\t\t// ...skip external links, anchors, images...\n\t\tfixed := lf.fixSingleLink(target, currentDirPath)\n\t\tif fixed != \"\" \u0026\u0026 fixed != target {\n\t\t\treturn \"[\" + text + \"](\" + fixed + \")\"\n\t\t}\n\t\treturn match\n\t})\n}\n```\n\n\u003e Source: internal/output/linkfixer.go#L50-L82\n\nThe repair strategy proceeds in order:\n\n```mermaid\nflowchart TD\n    A[\"Get link target\"] --\u003e B{\"External link\\n/ anchor / image?\"}\n    B --\u003e|Yes| Z[\"Keep as-is\"]\n    B --\u003e|No| C[\"resolveRelative:\\nattempt direct relative path resolution\"]\n    C --\u003e D{\"Points to a valid page?\"}\n    D --\u003e|Yes| Z\n    D --\u003e|No| E[\"extractPathSlug:\\nclean target (strip ../ .md /index.md)\"]\n    E --\u003e F[\"Look up in pathIndex (exact)\"]\n    F --\u003e G{\"Found?\"}\n    G --\u003e|Yes| H[\"computeRelativePath:\\ncalculate correct relative path\"]\n    G --\u003e|No| I[\"Lowercase lookup\"]\n    I --\u003e J{\"Found?\"}\n    J --\u003e|Yes| H\n    J --\u003e|No| K[\"Last segment / hyphen-combination lookup\"]\n    K --\u003e L{\"Found?\"}\n    L --\u003e|Yes| H\n    L --\u003e|No| M[\"Suffix substring match\"]\n    M --\u003e N{\"Found?\"}\n    N --\u003e|Yes| H\n    N --\u003e|No| Z\n    H --\u003e O[\"Output corrected link\"]\n```\n\n### Relative Path Computation\n\n```go\n// computeRelativePath computes the relative path from one catalog item to another.\nfunc (lf *LinkFixer) computeRelativePath(fromDirPath, toDirPath string) string {\n\trel, err := filepath.Rel(fromDirPath, toDirPath)\n\tif err != nil {\n\t\treturn \"\"\n\t}\n\trel = filepath.ToSlash(rel)\n\treturn rel + \"/index.md\"\n}\n```\n\n\u003e Source: internal/output/linkfixer.go#L174-L182\n\nAll fixed links are normalized to the `{relative-path}/index.md` format.\n\n## Navigation — Navigation Generation\n\n`navigation.go` provides three pure functions that generate the documentation's navigation structure with no external state dependencies.\n\n### Multi-Language UI Strings\n\n```go\nvar UIStrings = map[string]map[string]string{\n\t\"zh-TW\": {\n\t\t\"techDocs\":        \"技術文件\",\n\t\t\"catalog\":         \"目錄\",\n\t\t\"home\":            \"首頁\",\n\t\t\"sectionContains\": \"本章節包含以下內容：\",\n\t\t\"autoGenerated\":   \"本文件由 [selfmd](https://github.com/monkenwu/selfmd) 自動產生\",\n\t},\n\t\"en-US\": {\n\t\t\"techDocs\":        \"Technical Documentation\",\n\t\t// ...\n\t},\n}\n```\n\n\u003e Source: internal/output/navigation.go#L12-L27\n\n### Three Navigation Generation Functions\n\n| Function | Output Target | Description |\n|----------|--------------|-------------|\n| `GenerateIndex` | `index.md` | Home page listing the complete catalog with links |\n| `GenerateSidebar` | `_sidebar.md` | Sidebar navigation for use by the static browser |\n| `GenerateCategoryIndex` | `index.md` for each parent node | Category index page listing child sections |\n\n```go\n// GenerateIndex generates the main index.md landing page.\nfunc GenerateIndex(projectName, projectDesc string, cat *catalog.Catalog, lang string) string {\n\tui := getUIStrings(lang)\n\tvar sb strings.Builder\n\tsb.WriteString(fmt.Sprintf(\"# %s %s\\n\\n\", projectName, ui[\"techDocs\"]))\n\t// ...\n\tfor _, item := range cat.Items {\n\t\twriteIndexItem(\u0026sb, item, \"\", 0)\n\t}\n\t// ...\n}\n```\n\n\u003e Source: internal/output/navigation.go#L37-L59\n\n## WriteViewer — Static Browser Bundler\n\n`viewer.go` uses Go's `//go:embed` directive to embed static browser assets directly into the binary, writing them out at generation time without requiring any external network resources.\n\n### Embedded Assets\n\n```go\n//go:embed viewer/index.html\nvar viewerHTML string\n\n//go:embed viewer/app.js\nvar viewerJS string\n\n//go:embed viewer/style.css\nvar viewerCSS string\n```\n\n\u003e Source: internal/output/viewer.go#L12-L19\n\n### Data Bundling (`_data.js`)\n\n```go\n// bundleData walks the output directory, collects all .md files and _catalog.json,\n// and writes them as a single _data.js file for client-side rendering.\nfunc (w *Writer) bundleData(projectName string, docMeta *DocMeta) error {\n\t// ...\n\t// Build data object\n\tdata := map[string]interface{}{\n\t\t\"catalog\": catalogObj,\n\t\t\"pages\":   pages,\n\t}\n\t// ...\n\tcontent := \"window.DOC_DATA = \" + string(jsonBytes) + \";\\n\"\n\treturn w.WriteFile(\"_data.js\", content)\n}\n```\n\n\u003e Source: internal/output/viewer.go#L61-L193\n\n`_data.js` serializes all Markdown page content and the catalog structure as JSON, injected as the `window.DOC_DATA` global variable, allowing the browser-side `app.js` to render documentation without starting a server.\n\nIn multi-language mode, pages for secondary languages are also collected and placed under `data[\"languages\"][langCode]`:\n\n```go\nlanguages := make(map[string]interface{})\nfor _, lang := range docMeta.AvailableLanguages {\n    if lang.IsDefault {\n        continue\n    }\n    // Read lang-specific catalog and pages from .doc-build/{lang}/\n    langEntry[\"catalog\"] = catObj\n    langEntry[\"pages\"] = langPages\n    languages[lang.Code] = langEntry\n}\n```\n\n\u003e Source: internal/output/viewer.go#L135-L185\n\n### DocMeta — Language Metadata\n\n```go\n// DocMeta holds metadata about the documentation build, including language info.\ntype DocMeta struct {\n\tDefaultLanguage    string     `json:\"default_language\"`\n\tAvailableLanguages []LangInfo `json:\"available_languages\"`\n}\n\n// LangInfo describes a single available language.\ntype LangInfo struct {\n\tCode       string `json:\"code\"`\n\tNativeName string `json:\"native_name\"`\n\tIsDefault  bool   `json:\"is_default\"`\n}\n```\n\n\u003e Source: internal/output/writer.go#L12-L23\n\n## Core Flows\n\n### Content Page Write Sequence\n\n```mermaid\nsequenceDiagram\n    participant G as Generator\n    participant LF as LinkFixer\n    participant W as Writer\n    participant FS as File System\n\n    G-\u003e\u003eLF: NewLinkFixer(cat)\n    Note over LF: Build pathIndex multi-key index\n\n    loop Each catalog.FlatItem\n        G-\u003e\u003eG: generateSinglePage (calls Claude)\n        G-\u003e\u003eG: claude.ExtractDocumentTag (extract document tag)\n        G-\u003e\u003eLF: FixLinks(content, item.DirPath)\n        LF-\u003e\u003eLF: regexp scan all [text](target)\n        LF-\u003e\u003eLF: fixSingleLink (fuzzy lookup + compute relative path)\n        LF--\u003e\u003eG: fixed content\n        G-\u003e\u003eW: WritePage(item, content)\n        W-\u003e\u003eFS: MkdirAll + WriteFile (index.md)\n    end\n```\n\n### Role in the Full Pipeline\n\n```mermaid\nsequenceDiagram\n    participant P as pipeline.go\n    participant W as Writer\n    participant Nav as navigation.go\n    participant V as viewer.go\n\n    P-\u003e\u003eW: Clean() or EnsureDir()\n    P-\u003e\u003eW: WriteCatalogJSON(cat)\n    P-\u003e\u003eNav: GenerateIndex / GenerateSidebar / GenerateCategoryIndex\n    Nav--\u003e\u003eP: Markdown string\n    P-\u003e\u003eW: WriteFile(\"index.md\")\n    P-\u003e\u003eW: WriteFile(\"_sidebar.md\")\n    P-\u003e\u003eW: WritePage(item, categoryContent)\n    P-\u003e\u003eV: WriteViewer(projectName, docMeta)\n    V-\u003e\u003eW: WriteFile(\"index.html\" / \"app.js\" / \"style.css\")\n    V-\u003e\u003eV: bundleData (scan all .md files)\n    V-\u003e\u003eW: WriteFile(\"_data.js\")\n    V-\u003e\u003eW: WriteFile(\"_doc_meta.json\")\n    P-\u003e\u003eW: SaveLastCommit(commit)\n```\n\n## Usage Examples\n\n### Writer Initialization (from Generator)\n\n```go\nabsOutDir := cfg.Output.Dir\nif absOutDir == \"\" {\n    absOutDir = \".doc-build\"\n}\n\nwriter := output.NewWriter(absOutDir)\n```\n\n\u003e Source: internal/generator/pipeline.go#L43-L48\n\n### Using LinkFixer During Content Generation\n\n```go\n// Build the link fixer once for all pages\nlinkFixer := output.NewLinkFixer(cat)\n\n// ...(after generating each page in parallel)\n\n// Post-process: fix broken links\ncontent = linkFixer.FixLinks(content, item.DirPath)\n\nreturn g.Writer.WritePage(item, content)\n```\n\n\u003e Source: internal/generator/content_phase.go#L29-L153\n\n### Multi-Language Writer\n\n```go\n// ForLanguage returns a new Writer that writes to a language-specific subdirectory.\nfunc (w *Writer) ForLanguage(lang string) *Writer {\n    return \u0026Writer{\n        BaseDir: filepath.Join(w.BaseDir, lang),\n    }\n}\n```\n\n\u003e Source: internal/output/writer.go#L138-L143\n\nCalling `w.ForLanguage(\"en-US\")` during the translation phase returns a Writer pointing to `.doc-build/en-US/`. Translated pages written through it are also collected by `bundleData` into `_data.js`.\n\n## Related Links\n\n- [Documentation Generation Pipeline](../generator/index.md) — How the pipeline calls `Writer` and `LinkFixer`\n- [Content Page Generation Phase](../generator/content-phase/index.md) — When `LinkFixer.FixLinks` is used\n- [Index \u0026 Navigation Generation Phase](../generator/index-phase/index.md) — Callers of the Navigation functions\n- [Static Documentation Browser](../static-viewer/index.md) — Consumer of `_data.js`\n- [Document Catalog Management](../catalog/index.md) — Definitions of `catalog.FlatItem` and `catalog.Catalog`\n- [Incremental Updates](../incremental-update/index.md) — Usage contexts for `PageExists` and `ReadLastCommit`\n- [Translation Phase](../generator/translate-phase/index.md) — Usage context for `ForLanguage`\n\n## Reference Files\n\n| File Path | Description |\n|-----------|-------------|\n| `internal/output/writer.go` | `Writer` struct definition, page writing, persistence helper methods, `DocMeta` definition |\n| `internal/output/linkfixer.go` | `LinkFixer` struct, multi-key index construction, link scanning and repair logic |\n| `internal/output/navigation.go` | `GenerateIndex`, `GenerateSidebar`, `GenerateCategoryIndex`, and multi-language UI strings |\n| `internal/output/viewer.go` | `WriteViewer`, `bundleData`, embedded static asset output |\n| `internal/catalog/catalog.go` | `Catalog`, `CatalogItem`, `FlatItem` definitions and `Flatten` method |\n| `internal/generator/pipeline.go` | `Generator` struct, four-phase pipeline main flow, `buildDocMeta` |\n| `internal/generator/content_phase.go` | `GenerateContent`, `generateSinglePage`, `LinkFixer` usage |\n| `internal/generator/index_phase.go` | Implementation of `GenerateIndex` calling Navigation functions |","en-US/core-modules/prompt-engine/index.md":"# Prompt Template Engine\n\n`prompt.Engine` is selfmd's prompt template engine, responsible for combining structured data with predefined templates to generate the complete prompts passed to the Claude CLI.\n\n## Overview\n\nThe prompt template engine resides in the `internal/prompt/` package with three core responsibilities:\n\n1. **Template loading**: Uses Go's `embed.FS` mechanism to embed all `.tmpl` files under the `templates/` directory into the binary at compile time, ensuring no additional template files are needed at deployment.\n2. **Language routing**: Determines which language subfolder (`zh-TW` or `en-US`) to load based on `OutputConfig.GetEffectiveTemplateLang()`. The shared template (`translate.tmpl`) is managed independently, outside any language subfolder.\n3. **Data rendering**: Provides six high-level rendering methods, each corresponding to a specific stage of the document generation pipeline, accepting strongly-typed data structs and returning rendered strings.\n\nIn the overall architecture, `Engine` is one of `Generator`'s core dependencies, working alongside `claude.Runner`: `Engine` is responsible for \"converting data into prompt text,\" while `Runner` is responsible for \"sending prompt text to Claude and retrieving the response.\"\n\n### Key Terms\n\n- **Template Language**: Determines which language folder's `.tmpl` files to use. Currently supports `zh-TW` and `en-US`.\n- **Language Override**: When the user-configured output language has no corresponding template (e.g., `ja-JP`), the engine falls back to the English template (`en-US`) and adds an explicit instruction in the prompt, directing Claude to output in the target language.\n- **Shared Template**: `translate.tmpl` does not depend on a specific language and can translate any language combination, so it is loaded independently outside the language subfolders.\n\n## Architecture\n\n### Component Dependencies\n\n```mermaid\nflowchart TD\n    Config[\"config.OutputConfig\"]\n    Pipeline[\"generator.NewGenerator\"]\n    Engine[\"prompt.Engine\"]\n    LangTmpl[\"Language Template Set\\ntemplates/zh-TW/*.tmpl\\ntemplates/en-US/*.tmpl\"]\n    SharedTmpl[\"Shared Template\\ntemplates/translate.tmpl\"]\n    EmbedFS[\"embed.FS\\ntemplatFS\"]\n\n    CatalogPhase[\"generator.GenerateCatalog\"]\n    ContentPhase[\"generator.GenerateContent\"]\n    TranslatePhase[\"generator.Translate\"]\n    UpdaterPhase[\"generator.Updater\"]\n\n    Config --\u003e|\"GetEffectiveTemplateLang()\"| Pipeline\n    Pipeline --\u003e|\"prompt.NewEngine(templateLang)\"| Engine\n    EmbedFS --\u003e LangTmpl\n    EmbedFS --\u003e SharedTmpl\n    LangTmpl --\u003e Engine\n    SharedTmpl --\u003e Engine\n\n    Engine --\u003e|\"RenderCatalog()\"| CatalogPhase\n    Engine --\u003e|\"RenderContent()\"| ContentPhase\n    Engine --\u003e|\"RenderTranslate()\"| TranslatePhase\n    Engine --\u003e|\"RenderUpdateMatched()\\nRenderUpdateUnmatched()\"| UpdaterPhase\n```\n\n### Template File Organization\n\n```mermaid\nflowchart TD\n    subgraph FS[\"embed.FS: templateFS\"]\n        subgraph ZhTW[\"templates/zh-TW/\"]\n            z1[\"catalog.tmpl\"]\n            z2[\"content.tmpl\"]\n            z3[\"updater.tmpl\"]\n            z4[\"update_matched.tmpl\"]\n            z5[\"update_unmatched.tmpl\"]\n        end\n        subgraph EnUS[\"templates/en-US/\"]\n            e1[\"catalog.tmpl\"]\n            e2[\"content.tmpl\"]\n            e3[\"updater.tmpl\"]\n            e4[\"update_matched.tmpl\"]\n            e5[\"update_unmatched.tmpl\"]\n        end\n        subgraph Shared[\"templates/ (root)\"]\n            s1[\"translate.tmpl\"]\n        end\n    end\n\n    Engine_Lang[\"Engine.templates\\n(Language Template Set)\"]\n    Engine_Shared[\"Engine.sharedTemplates\\n(Shared Templates)\"]\n\n    ZhTW --\u003e Engine_Lang\n    EnUS --\u003e Engine_Lang\n    Shared --\u003e Engine_Shared\n```\n\n## Core Data Structures\n\n`Engine` defines six data structs corresponding to different rendering scenarios:\n\n### CatalogPromptData\n\nUsed in the **catalog generation phase**, providing the complete project scan results for Claude to analyze and design the documentation catalog.\n\n```go\ntype CatalogPromptData struct {\n\tRepositoryName       string\n\tProjectType          string\n\tLanguage             string\n\tLanguageName         string // native display name (e.g., \"繁體中文\")\n\tLanguageOverride     bool   // true when template lang != output lang\n\tLanguageOverrideName string // native name of the desired output language\n\tKeyFiles             string\n\tEntryPoints          string\n\tFileTree             string\n\tReadmeContent        string\n}\n```\n\n\u003e Source: internal/prompt/engine.go#L40-L51\n\n### ContentPromptData\n\nUsed in the **content page generation phase**, specifying the target page's position in the catalog, the list of linkable pages, and existing content in update scenarios.\n\n```go\ntype ContentPromptData struct {\n\tRepositoryName       string\n\tLanguage             string\n\tLanguageName         string\n\tLanguageOverride     bool\n\tLanguageOverrideName string\n\tCatalogPath          string\n\tCatalogTitle         string\n\tCatalogDirPath       string // filesystem dir path of THIS item, e.g., \"configuration/claude-config\"\n\tProjectDir           string\n\tFileTree             string\n\tCatalogTable         string // formatted table of all catalog items with their dir paths\n\tExistingContent      string // existing page content for update context (empty for new pages)\n}\n```\n\n\u003e Source: internal/prompt/engine.go#L54-L67\n\n### UpdateMatchedPromptData and UpdateUnmatchedPromptData\n\nUsed in the **incremental update phase**, handling two subtasks: \"determining which existing pages need to be regenerated\" and \"determining whether new pages need to be added.\"\n\n```go\ntype UpdateMatchedPromptData struct {\n\tRepositoryName string\n\tLanguage       string\n\tChangedFiles   string // list of changed source files\n\tAffectedPages  string // pages that reference these files (path + title + summary)\n}\n\ntype UpdateUnmatchedPromptData struct {\n\tRepositoryName  string\n\tLanguage        string\n\tUnmatchedFiles  string // changed files not referenced in any existing doc\n\tExistingCatalog string // existing catalog JSON\n\tCatalogTable    string // formatted link table of all pages\n}\n```\n\n\u003e Source: internal/prompt/engine.go#L81-L95\n\n### TranslatePromptData\n\nUsed in the **translation phase**, specifying the source language, target language, and the complete Markdown content to translate.\n\n```go\ntype TranslatePromptData struct {\n\tSourceLanguage     string // e.g., \"zh-TW\"\n\tSourceLanguageName string // e.g., \"繁體中文\"\n\tTargetLanguage     string // e.g., \"en-US\"\n\tTargetLanguageName string // e.g., \"English\"\n\tSourceContent      string // the full markdown content to translate\n}\n```\n\n\u003e Source: internal/prompt/engine.go#L98-L104\n\n## Template Language Selection Logic\n\nThe engine's language selection is controlled by two methods in `config.OutputConfig`:\n\n```go\n// SupportedTemplateLangs lists language codes that have built-in prompt template folders.\nvar SupportedTemplateLangs = []string{\"zh-TW\", \"en-US\"}\n\n// GetEffectiveTemplateLang returns which template folder to load.\n// If Language has a built-in template set, returns it; otherwise falls back to \"en-US\".\nfunc (o *OutputConfig) GetEffectiveTemplateLang() string {\n\tfor _, lang := range SupportedTemplateLangs {\n\t\tif o.Language == lang {\n\t\t\treturn o.Language\n\t\t}\n\t}\n\treturn \"en-US\"\n}\n\n// NeedsLanguageOverride returns true when the template language differs from Language,\n// meaning the prompt needs an explicit instruction to output in the configured language.\nfunc (o *OutputConfig) NeedsLanguageOverride() bool {\n\treturn o.GetEffectiveTemplateLang() != o.Language\n}\n```\n\n\u003e Source: internal/config/config.go#L53-L71\n\nWhen `LanguageOverride` is `true`, the template adds an explicit language instruction to the prompt, directing Claude to output in the specified language even if the template itself is written in English.\n\n## Core Flows\n\n### Engine Initialization and Rendering Flow\n\n```mermaid\nsequenceDiagram\n    participant Gen as generator.NewGenerator\n    participant Cfg as config.OutputConfig\n    participant Eng as prompt.NewEngine\n    participant FS as embed.FS\n\n    Gen-\u003e\u003eCfg: GetEffectiveTemplateLang()\n    Cfg--\u003e\u003eGen: templateLang (e.g., \"zh-TW\")\n    Gen-\u003e\u003eEng: NewEngine(templateLang)\n    Eng-\u003e\u003eFS: ParseFS(\"templates/zh-TW/*.tmpl\")\n    FS--\u003e\u003eEng: language-specific templates\n    Eng-\u003e\u003eFS: ParseFS(\"templates/*.tmpl\")\n    FS--\u003e\u003eEng: shared templates (translate.tmpl)\n    Eng--\u003e\u003eGen: *Engine\n\n    Note over Gen: Document generation phase begins\n\n    Gen-\u003e\u003eEng: RenderCatalog(data)\n    Eng-\u003e\u003eEng: render(\"catalog.tmpl\", data)\n    Eng--\u003e\u003eGen: rendered prompt string\n\n    Gen-\u003e\u003eEng: RenderContent(data)\n    Eng-\u003e\u003eEng: render(\"content.tmpl\", data)\n    Eng--\u003e\u003eGen: rendered prompt string\n\n    Gen-\u003e\u003eEng: RenderTranslate(data)\n    Eng-\u003e\u003eEng: renderShared(\"translate.tmpl\", data)\n    Eng--\u003e\u003eGen: rendered prompt string\n```\n\n### Language Override Decision Flow\n\n```mermaid\nflowchart TD\n    A[\"User sets output.language\\n(e.g., ja-JP)\"]\n    B{\"Is it a supported\\ntemplate language?\\nSupportedTemplateLangs\"}\n    C[\"Use corresponding language template\\n(zh-TW or en-US)\\nLanguageOverride = false\"]\n    D[\"Fall back to en-US template\\nLanguageOverride = true\\nLanguageOverrideName = ja-JP\"]\n    E[\"Template adds language override instruction\\ndirecting Claude to output in target language\"]\n\n    A --\u003e B\n    B --\u003e|\"Yes (zh-TW / en-US)\"| C\n    B --\u003e|\"No\"| D\n    D --\u003e E\n```\n\n## Usage Examples\n\n### Initializing the Engine\n\n```go\n// NewGenerator creates a new Generator.\nfunc NewGenerator(cfg *config.Config, rootDir string, logger *slog.Logger) (*Generator, error) {\n\ttemplateLang := cfg.Output.GetEffectiveTemplateLang()\n\tengine, err := prompt.NewEngine(templateLang)\n\tif err != nil {\n\t\treturn nil, err\n\t}\n\t// ...\n\treturn \u0026Generator{\n\t\t// ...\n\t\tEngine: engine,\n\t}, nil\n}\n```\n\n\u003e Source: internal/generator/pipeline.go#L35-L59\n\n### Rendering a Catalog Prompt\n\n```go\nfunc (g *Generator) GenerateCatalog(ctx context.Context, scan *scanner.ScanResult) (*catalog.Catalog, error) {\n\tlangName := config.GetLangNativeName(g.Config.Output.Language)\n\tdata := prompt.CatalogPromptData{\n\t\tRepositoryName:       g.Config.Project.Name,\n\t\tProjectType:          g.Config.Project.Type,\n\t\tLanguage:             g.Config.Output.Language,\n\t\tLanguageName:         langName,\n\t\tLanguageOverride:     g.Config.Output.NeedsLanguageOverride(),\n\t\tLanguageOverrideName: langName,\n\t\tKeyFiles:             scan.KeyFiles(),\n\t\tEntryPoints:          scan.EntryPointsFormatted(),\n\t\tFileTree:             scanner.RenderTree(scan.Tree, 4),\n\t\tReadmeContent:        scan.ReadmeContent,\n\t}\n\n\trendered, err := g.Engine.RenderCatalog(data)\n\tif err != nil {\n\t\treturn nil, err\n\t}\n\t// rendered is the complete prompt string, passed to claude.Runner\n}\n```\n\n\u003e Source: internal/generator/catalog_phase.go#L16-L62\n\n### Rendering a Translation Prompt\n\n```go\nrendered, err := g.Engine.RenderTranslate(data)\n```\n\n\u003e Source: internal/generator/translate_phase.go#L195\n\n## Related Links\n\n- [Document Generation Pipeline](../generator/index.md) — How `Engine` is used in the four-phase pipeline\n- [Catalog Generation Phase](../generator/catalog-phase/index.md) — Detailed flow using `RenderCatalog`\n- [Content Page Generation Phase](../generator/content-phase/index.md) — Detailed flow using `RenderContent`\n- [Translation Phase](../generator/translate-phase/index.md) — Detailed flow using `RenderTranslate`\n- [Incremental Update](../incremental-update/index.md) — Scenarios using `RenderUpdateMatched` and `RenderUpdateUnmatched`\n- [Claude CLI Runner](../claude-runner/index.md) — The downstream component that receives `Engine`'s rendered output\n- [Multilingual Support](../../i18n/index.md) — User-side configuration for the language override mechanism\n\n## Reference Files\n\n| File Path | Description |\n|-----------|-------------|\n| `internal/prompt/engine.go` | `Engine` struct, data type definitions, and rendering methods |\n| `internal/prompt/templates/zh-TW/catalog.tmpl` | Traditional Chinese catalog generation prompt template |\n| `internal/prompt/templates/zh-TW/content.tmpl` | Traditional Chinese content page generation prompt template |\n| `internal/prompt/templates/zh-TW/updater.tmpl` | Traditional Chinese incremental update (legacy) prompt template |\n| `internal/prompt/templates/zh-TW/update_matched.tmpl` | Traditional Chinese: prompt template for determining which existing pages need regeneration |\n| `internal/prompt/templates/zh-TW/update_unmatched.tmpl` | Traditional Chinese: prompt template for determining whether new pages need to be added |\n| `internal/prompt/templates/translate.tmpl` | Shared translation prompt template (language-agnostic) |\n| `internal/prompt/templates/en-US/catalog.tmpl` | English catalog generation prompt template |\n| `internal/config/config.go` | `OutputConfig.GetEffectiveTemplateLang()`, `NeedsLanguageOverride()`, and `SupportedTemplateLangs` definitions |\n| `internal/generator/pipeline.go` | `Generator` struct definition and `NewGenerator` initialization logic |\n| `internal/generator/catalog_phase.go` | `GenerateCatalog`: example usage of `RenderCatalog` |","en-US/core-modules/scanner/index.md":"# Project Scanner\n\nThe project scanner (`scanner` package) traverses the target project's directory structure, collects a file list, builds a tree structure, reads the README and entry point files, and packages the results into a `ScanResult` for use by the downstream documentation generation pipeline.\n\n## Overview\n\nIn selfmd's four-phase pipeline, the scanner is the first core module to execute (Phase 1). Its responsibilities are:\n\n- **Collecting matching files**: Filters source files that need documentation based on `include` and `exclude` glob rules defined in `selfmd.yaml` under `targets`\n- **Building a File Tree**: Converts a flat list of file paths into a hierarchical `FileNode` tree structure, which can then be rendered into a human-readable directory format\n- **Reading key context**: Automatically reads `README.md` and the entry point files specified in the configuration, providing background context for Claude when generating the catalog\n\nThe scan result (`ScanResult`) is the starting point for the entire pipeline: both the Catalog Phase and Content Phase depend on it for the file tree, KEY files list, and entry point contents.\n\n### Core Concepts\n\n| Term | Description |\n|------|------|\n| `ScanResult` | The complete result object after a scan, containing the tree structure, file list, README, and more |\n| `FileNode` | Represents a single node in the file tree; can be either a directory or a file |\n| `BuildTree` | A function that converts a flat list of paths into a `FileNode` tree |\n| `RenderTree` | Renders a `FileNode` tree into UNIX `tree`-command-style text for injection into prompts |\n| Entry Points | Important files specified in the configuration (e.g., `main.go`) whose contents are fully read for Claude's reference |\n\n## Architecture\n\n```mermaid\nflowchart TD\n    Config[\"config.Config\\n(targets.include / exclude\\ntargets.entry_points)\"]\n    RootDir[\"rootDir\\nTarget project root directory\"]\n\n    Scan[\"scanner.Scan()\"]\n\n    WalkDir[\"filepath.WalkDir()\"]\n    GlobMatch[\"doublestar.Match()\\ninclude / exclude filtering\"]\n    ReadReadme[\"readFileIfExists()\\nREADME.md\"]\n    ReadEntryPoints[\"readFileIfExists()\\nentry_points\"]\n    BuildTree[\"BuildTree()\\nFlat paths → FileNode tree\"]\n    SortTree[\"sortTree()\\nDirectories first, alphabetical sort\"]\n\n    ScanResult[\"ScanResult\\n- RootDir\\n- Tree (*FileNode)\\n- FileList\\n- TotalFiles / TotalDirs\\n- ReadmeContent\\n- EntryPointContents\"]\n\n    CatalogPhase[\"GenerateCatalog()\\nCatalog Phase\"]\n    ContentPhase[\"GenerateContent()\\nContent Phase\"]\n    RenderTree[\"RenderTree()\\nText tree rendering\"]\n\n    Config --\u003e Scan\n    RootDir --\u003e Scan\n    Scan --\u003e WalkDir\n    WalkDir --\u003e GlobMatch\n    GlobMatch --\u003e BuildTree\n    BuildTree --\u003e SortTree\n    Scan --\u003e ReadReadme\n    Scan --\u003e ReadEntryPoints\n    SortTree --\u003e ScanResult\n    ReadReadme --\u003e ScanResult\n    ReadEntryPoints --\u003e ScanResult\n\n    ScanResult --\u003e CatalogPhase\n    ScanResult --\u003e ContentPhase\n    ScanResult --\u003e RenderTree\n```\n\n## Data Structures\n\n### FileNode\n\n`FileNode` is the basic unit of the file tree, representing a directory or file:\n\n```go\ntype FileNode struct {\n    Name     string\n    Path     string // relative path from project root\n    IsDir    bool\n    Children []*FileNode\n}\n```\n\n\u003e Source: `internal/scanner/filetree.go#L11-L16`\n\n### ScanResult\n\n`ScanResult` encapsulates all output from a complete scan:\n\n```go\ntype ScanResult struct {\n    RootDir            string\n    Tree               *FileNode\n    FileList           []string\n    TotalFiles         int\n    TotalDirs          int\n    ReadmeContent      string\n    EntryPointContents map[string]string\n}\n```\n\n\u003e Source: `internal/scanner/filetree.go#L19-L27`\n\n## Core Flow\n\n### Scan — Main Scan Process\n\n```mermaid\nsequenceDiagram\n    participant Pipeline as generator.Generate()\n    participant S as scanner.Scan()\n    participant FS as File System\n    participant BT as BuildTree()\n\n    Pipeline-\u003e\u003eS: Scan(cfg, rootDir)\n    S-\u003e\u003eFS: filepath.WalkDir(rootDir, ...)\n    loop Each path\n        FS--\u003e\u003eS: path, DirEntry\n        S-\u003e\u003eS: Compute relative path (rel)\n        alt Matches exclude rule\n            S-\u003e\u003eS: Skip (SkipDir for directories)\n        else Matches include rule (or no include set)\n            S-\u003e\u003eS: Append to files []string\n        end\n    end\n    S-\u003e\u003eBT: BuildTree(projectName, files)\n    BT--\u003e\u003eS: *FileNode (sorted)\n    S-\u003e\u003eFS: Read README.md\n    S-\u003e\u003eFS: Read entry_points files\n    S--\u003e\u003ePipeline: *ScanResult\n```\n\n### File Filtering Logic\n\nScanning uses a two-layer \"exclude first, then include\" filtering strategy:\n\n1. **Exclude takes priority**: If a path matches any `exclude` glob pattern, directories call `filepath.SkipDir` to skip the entire subtree, and files are skipped individually\n2. **Include filtering**: If an `include` list is configured, only files matching at least one pattern are added to the results\n\n```go\n// check excludes\nfor _, pattern := range cfg.Targets.Exclude {\n    matched, _ := doublestar.Match(pattern, rel)\n    if matched {\n        if d.IsDir() {\n            return filepath.SkipDir\n        }\n        return nil\n    }\n}\n\n// check includes\nif len(cfg.Targets.Include) \u003e 0 {\n    included := false\n    for _, pattern := range cfg.Targets.Include {\n        matched, _ := doublestar.Match(pattern, rel)\n        if matched {\n            included = true\n            break\n        }\n    }\n    if !included {\n        return nil\n    }\n}\n```\n\n\u003e Source: `internal/scanner/scanner.go#L33-L61`\n\nGlob matching uses the `doublestar` package, which supports the `**` wildcard (e.g., `vendor/**`, `internal/**`).\n\n### BuildTree — Tree Structure Construction\n\n`BuildTree` takes a flat list of relative paths and incrementally builds a `FileNode` tree:\n\n```go\nfunc BuildTree(rootName string, paths []string) *FileNode {\n    root := \u0026FileNode{\n        Name:  rootName,\n        Path:  \"\",\n        IsDir: true,\n    }\n\n    for _, p := range paths {\n        parts := strings.Split(filepath.ToSlash(p), \"/\")\n        current := root\n        for i, part := range parts {\n            isLast := i == len(parts)-1\n            child := findChild(current, part)\n            if child == nil {\n                child = \u0026FileNode{\n                    Name:  part,\n                    Path:  strings.Join(parts[:i+1], \"/\"),\n                    IsDir: !isLast,\n                }\n                current.Children = append(current.Children, child)\n            }\n            if !isLast {\n                child.IsDir = true\n            }\n            current = child\n        }\n    }\n\n    sortTree(root)\n    return root\n}\n```\n\n\u003e Source: `internal/scanner/filetree.go#L30-L60`\n\nAfter construction, `sortTree` sorts each level of nodes: **directory nodes come first, and nodes of the same type are sorted alphabetically**.\n\n### RenderTree — Text Tree Rendering\n\n`RenderTree` converts a `FileNode` tree into text output similar to the UNIX `tree` command, for injection into Claude prompts:\n\n```go\nfunc RenderTree(node *FileNode, maxDepth int) string {\n    var sb strings.Builder\n    sb.WriteString(node.Name + \"/\\n\")\n    renderChildren(\u0026sb, node, \"\", maxDepth, 0)\n    return sb.String()\n}\n```\n\n\u003e Source: `internal/scanner/filetree.go#L87-L92`\n\nThe rendering includes two safeguards:\n- `maxDepth`: Limits the maximum expansion depth (Catalog Phase uses 4 levels, Content Phase uses 3)\n- Each level renders at most 30 child nodes; beyond that, `... (N more items)` is displayed\n\n## Helper Methods\n\n### KeyFiles()\n\nThe scan result provides a `KeyFiles()` method that filters well-known important files (such as `main.go`, `Dockerfile`, `go.mod`, etc.) from `FileList` and returns them as a comma-separated string for use as supplementary information in the Catalog Prompt:\n\n```go\nfunc (s *ScanResult) KeyFiles() string {\n    notable := []string{}\n    patterns := []string{\n        \"main.go\", \"main.py\", \"main.rs\", \"main.ts\", \"main.js\",\n        \"index.ts\", \"index.js\", \"app.go\", \"app.py\", \"app.ts\",\n        \"Makefile\", \"Dockerfile\", \"docker-compose.yml\", \"compose.yaml\",\n        \"package.json\", \"go.mod\", \"Cargo.toml\", \"pom.xml\",\n        \"README.md\", \"CHANGELOG.md\",\n    }\n    // ...\n    if len(notable) \u003e 20 {\n        notable = notable[:20]\n    }\n    return strings.Join(notable, \", \")\n}\n```\n\n\u003e Source: `internal/scanner/scanner.go#L117-L141`\n\n### EntryPointsFormatted()\n\nFormats the contents of entry point files specified in the configuration as Markdown code blocks. Each entry point is limited to 10,000 characters and truncated if exceeded:\n\n```go\nfunc (s *ScanResult) EntryPointsFormatted() string {\n    if len(s.EntryPointContents) == 0 {\n        return \"(no entry points specified)\"\n    }\n\n    var sb strings.Builder\n    for path, content := range s.EntryPointContents {\n        sb.WriteString(\"### \" + path + \"\\n```\\n\")\n        if len(content) \u003e 10000 {\n            content = content[:10000] + \"\\n... (truncated)\"\n        }\n        sb.WriteString(content)\n        sb.WriteString(\"\\n```\\n\\n\")\n    }\n    return sb.String()\n}\n```\n\n\u003e Source: `internal/scanner/scanner.go#L144-L160`\n\n### readFileIfExists()\n\nA private helper function that reads file contents and automatically truncates them if they exceed 50,000 characters:\n\n```go\nfunc readFileIfExists(rootDir, relPath string) string {\n    data, err := os.ReadFile(filepath.Join(rootDir, relPath))\n    if err != nil {\n        return \"\"\n    }\n    content := string(data)\n    if len(content) \u003e 50000 {\n        content = content[:50000] + \"\\n... (truncated)\"\n    }\n    return content\n}\n```\n\n\u003e Source: `internal/scanner/scanner.go#L103-L114`\n\n## Usage Examples\n\n### Calling the Scanner in the Pipeline\n\nThe following is the actual code in `generator.Generate()` that invokes the scanner:\n\n```go\n// Phase 1: Scan\nfmt.Println(ui.T(\"[1/4] 掃描專案結構...\", \"[1/4] Scanning project structure...\"))\nscan, err := scanner.Scan(g.Config, g.RootDir)\nif err != nil {\n    return fmt.Errorf(ui.T(\"掃描專案失敗: %w\", \"failed to scan project: %w\"), err)\n}\nfmt.Printf(ui.T(\"      找到 %d 個檔案，分布於 %d 個目錄\\n\", \"      Found %d files in %d directories\\n\"), scan.TotalFiles, scan.TotalDirs)\n```\n\n\u003e Source: `internal/generator/pipeline.go#L88-L94`\n\n### Using the Scan Result in the Catalog Phase\n\n```go\ndata := prompt.CatalogPromptData{\n    // ...\n    KeyFiles:      scan.KeyFiles(),\n    EntryPoints:   scan.EntryPointsFormatted(),\n    FileTree:      scanner.RenderTree(scan.Tree, 4),\n    ReadmeContent: scan.ReadmeContent,\n}\n```\n\n\u003e Source: `internal/generator/catalog_phase.go#L18-L29`\n\n### Using the Scan Result in the Content Phase\n\n```go\ndata := prompt.ContentPromptData{\n    // ...\n    FileTree: scanner.RenderTree(scan.Tree, 3),\n}\n```\n\n\u003e Source: `internal/generator/content_phase.go#L102-L103`\n\n## Related Links\n\n- [Documentation Generation Pipeline](../generator/index.md) — The scanner's position in the four-phase pipeline and when it is invoked\n- [Catalog Generation Phase](../generator/catalog-phase/index.md) — The first downstream phase that directly consumes `ScanResult`\n- [Content Page Generation Phase](../generator/content-phase/index.md) — Uses `RenderTree` to inject the file tree into prompts\n- [Project and Scan Target Configuration](../../configuration/project-targets/index.md) — How to configure `include`, `exclude`, and `entry_points`\n- [Core Modules](../index.md) — Return to the core modules overview\n\n## Reference Files\n\n| File Path | Description |\n|----------|------|\n| `internal/scanner/scanner.go` | `Scan()` main function, `KeyFiles()`, `EntryPointsFormatted()`, `readFileIfExists()` |\n| `internal/scanner/filetree.go` | `FileNode` and `ScanResult` data structure definitions; `BuildTree()`, `RenderTree()`, `sortTree()` |\n| `internal/generator/pipeline.go` | Pipeline main flow, showing when the scanner is called and how its results are used |\n| `internal/generator/catalog_phase.go` | How `ScanResult` methods are consumed in the Catalog Phase |\n| `internal/generator/content_phase.go` | How `RenderTree` is used in the Content Phase |\n| `internal/config/config.go` | `TargetsConfig` struct definition (`Include`, `Exclude`, `EntryPoints`) |","en-US/core-modules/static-viewer/index.md":"# Static Document Viewer\n\nThe static document viewer is the final output interface of selfmd, delivered as a zero-dependency single-page application (SPA). Simply open `index.html` in a browser to browse all documentation — no server or network service required.\n\n## Overview\n\nAfter each documentation generation run, selfmd automatically creates a set of static web files under the `.doc-build/` directory. Users can open `.doc-build/index.html` in any browser to view all generated documents via a sidebar, live Markdown rendering, and Mermaid diagram support.\n\nThe core design principles of the static viewer are:\n\n- **Serverless**: All Markdown content and catalog structure are pre-bundled into `_data.js` and injected as a JavaScript global variable — no backend API dependency\n- **Binary Embed**: The three static assets (HTML, JavaScript, CSS) are compiled into the selfmd binary at build time using Go's `//go:embed` directive, requiring no extra files at distribution\n- **Single Entry Point**: `index.html` is the sole entry point, with client-side routing implemented via URL hash (`#path/to/page.md`)\n- **Multilingual Support**: When translated versions of documents exist, a language switcher appears at the top of the sidebar; switching languages dynamically replaces page content and the catalog\n\nOutput files involved in the viewer:\n\n| File | Description |\n|------|-------------|\n| `index.html` | HTML shell with project name and language code injected |\n| `app.js` | Frontend SPA logic (routing, rendering, interaction) |\n| `style.css` | Layout and visual styles |\n| `_data.js` | Data bundle containing all Markdown content and the catalog |\n| `_doc_meta.json` | Language metadata (optional) |\n\n## Architecture\n\n```mermaid\nflowchart TD\n    subgraph Go_Build[\"Go Binary (embed)\"]\n        EmbedHTML[\"viewer/index.html\"]\n        EmbedJS[\"viewer/app.js\"]\n        EmbedCSS[\"viewer/style.css\"]\n    end\n\n    subgraph WriteViewer[\"Writer.WriteViewer()\"]\n        Inject[\"Inject PROJECT_NAME / LANG\"]\n        BundleData[\"bundleData()\\nCollect .md + _catalog.json\"]\n        DocMeta[\"Serialize _doc_meta.json\"]\n    end\n\n    subgraph Output[\".doc-build/ Output Directory\"]\n        OutHTML[\"index.html\"]\n        OutJS[\"app.js\"]\n        OutCSS[\"style.css\"]\n        OutData[\"_data.js\\nwindow.DOC_DATA = {...}\"]\n        OutMeta[\"_doc_meta.json\"]\n    end\n\n    subgraph Browser[\"Browser SPA (app.js)\"]\n        Init[\"init()\"]\n        Sidebar[\"buildSidebar()\"]\n        Router[\"handleRoute() — Hash Routing\"]\n        Render[\"renderContent() — Markdown Rendering\"]\n        LangSwitch[\"switchLanguage()\"]\n    end\n\n    EmbedHTML --\u003e Inject\n    EmbedJS --\u003e WriteViewer\n    EmbedCSS --\u003e WriteViewer\n    Inject --\u003e OutHTML\n    BundleData --\u003e OutData\n    DocMeta --\u003e OutMeta\n    WriteViewer --\u003e OutJS\n    WriteViewer --\u003e OutCSS\n\n    OutHTML --\u003e Browser\n    OutData --\u003e Init\n    Init --\u003e Sidebar\n    Init --\u003e Router\n    Router --\u003e Render\n    LangSwitch --\u003e Sidebar\n```\n\n\u003e Source: `internal/output/viewer.go`, `internal/output/viewer/app.js`\n\n## Static Asset Embedding\n\nThe three static asset files are embedded directly into the binary at compile time via Go's `embed` package, requiring no corresponding file paths to exist in the runtime environment.\n\n```go\n//go:embed viewer/index.html\nvar viewerHTML string\n\n//go:embed viewer/app.js\nvar viewerJS string\n\n//go:embed viewer/style.css\nvar viewerCSS string\n```\n\n\u003e Source: `internal/output/viewer.go#L12-L19`\n\nBefore writing `index.html`, `WriteViewer` performs string substitution on the template to inject the project name (`{{PROJECT_NAME}}`) and language code (`{{LANG}}`) into the HTML:\n\n```go\nfunc (w *Writer) WriteViewer(projectName string, docMeta *DocMeta) error {\n    html := strings.ReplaceAll(viewerHTML, \"{{PROJECT_NAME}}\", projectName)\n    lang := \"zh-TW\"\n    if docMeta != nil {\n        lang = docMeta.DefaultLanguage\n    }\n    html = strings.ReplaceAll(html, \"{{LANG}}\", lang)\n\n    if err := w.WriteFile(\"index.html\", html); err != nil {\n        return fmt.Errorf(\"寫入 index.html 失敗: %w\", err)\n    }\n    // ...\n}\n```\n\n\u003e Source: `internal/output/viewer.go#L23-L43`\n\n## Data Bundling (bundleData)\n\nThe `bundleData` function scans the `.doc-build/` directory, bundling all Markdown pages and the catalog structure into a single `_data.js` file.\n\n### Bundling Process\n\n1. Read `_catalog.json` as the catalog structure\n2. Use `filepath.Walk` to traverse the output directory and collect all `.md` files (excluding files prefixed with `_`)\n3. If multilingual configuration is present, skip primary-language pages inside language subdirectories (`en-US/`, `ja-JP/`, etc.)\n4. If translated languages exist, separately collect the catalog and pages from each language subdirectory\n5. Serialize all data to JSON and write to `_data.js`\n\n```go\nfunc (w *Writer) bundleData(projectName string, docMeta *DocMeta) error {\n    // Read catalog\n    catalogPath := filepath.Join(w.BaseDir, \"_catalog.json\")\n    catalogBytes, err := os.ReadFile(catalogPath)\n    // ...\n\n    // Collect all master-language .md files (skip language subdirectories)\n    pages := make(map[string]string)\n    // ...\n    err = filepath.Walk(w.BaseDir, func(path string, info os.FileInfo, err error) error {\n        // Skip files starting with _\n        if strings.HasPrefix(filepath.Base(relPath), \"_\") {\n            return nil\n        }\n        // Skip files inside language subdirectories\n        topDir := strings.SplitN(relPath, \"/\", 2)[0]\n        if langDirs[topDir] {\n            return nil\n        }\n        // ...\n    })\n    // ...\n    content := \"window.DOC_DATA = \" + string(jsonBytes) + \";\\n\"\n    return w.WriteFile(\"_data.js\", content)\n}\n```\n\n\u003e Source: `internal/output/viewer.go#L61-L193`\n\n### `_data.js` Data Structure\n\nThe resulting `window.DOC_DATA` global object has the following structure:\n\n```javascript\nwindow.DOC_DATA = {\n  \"catalog\": { /* contents of _catalog.json */ },\n  \"pages\": {\n    \"overview/index.md\": \"# Overview\\n...\",\n    \"core-modules/scanner/index.md\": \"# Scanner\\n...\"\n    // all primary-language .md files\n  },\n  \"meta\": {\n    \"default_language\": \"zh-TW\",\n    \"available_languages\": [\n      { \"code\": \"zh-TW\", \"native_name\": \"繁體中文\", \"is_default\": true },\n      { \"code\": \"en-US\", \"native_name\": \"English\", \"is_default\": false }\n    ]\n  },\n  \"languages\": {\n    \"en-US\": {\n      \"catalog\": { /* English catalog */ },\n      \"pages\": { \"overview/index.md\": \"# Overview\\n...\" }\n    }\n  }\n};\n```\n\n\u003e Source: `internal/output/viewer.go#L126-L192`\n\n## Frontend Application (app.js)\n\n`app.js` is a SPA written in vanilla JavaScript (ES5-compatible), wrapped in an immediately invoked function expression (IIFE), with no dependency on any frontend framework.\n\n### Module Function Overview\n\n| Function Group | Key Functions | Description |\n|---------------|---------------|-------------|\n| Initialization | `init()` | Load data, configure Marked, initialize routing |\n| Sidebar | `buildSidebar()` / `renderSidebarSection()` | Recursively build a collapsible sidebar from the catalog |\n| Routing | `handleRoute()` / `loadPage()` | URL hash-based client-side routing |\n| Content Rendering | `renderContent()` / `fixLinks()` | Markdown rendering and relative path conversion |\n| Mermaid | `renderMermaid()` | Detect mermaid code blocks and call `mermaid.run()` |\n| Language Switching | `buildLangSwitcher()` / `switchLanguage()` | Multilingual `\u003cselect\u003e` component and data switching |\n| Toolbar | `buildPageToolbar()` | Per-page \"Copy Path\" and \"Download Markdown\" buttons |\n| Fullscreen | `enterMindmapFullscreen()` / `exitMindmapFullscreen()` | Fullscreen zoom and pan for Mermaid diagrams |\n| Mobile | `setupMobileMenu()` | Hamburger menu and sidebar overlay |\n\n### Routing Mechanism\n\nRouting is implemented via URL hash: the value of `location.hash` is the relative path of the page (e.g., `#core-modules/scanner/index.md`). When navigating between pages, `loadPage(path)` is called to retrieve the Markdown string from `window.DOC_DATA.pages` and render it.\n\n```javascript\nfunction handleRoute() {\n    var path = location.hash.slice(1) || \"index.md\";\n    loadPage(path);\n}\n\nfunction loadPage(path) {\n    var md = pages[path];\n    if (!md) {\n        document.getElementById(\"article\").innerHTML =\n            \"\u003ch1\u003e頁面未找到\u003c/h1\u003e\u003cp\u003e找不到 \u003ccode\u003e\" + escapeHtml(path) + \"\u003c/code\u003e\u003c/p\u003e\";\n        return;\n    }\n    renderContent(md, path);\n    updateActiveLink(path);\n    updateTitle(path);\n    document.getElementById(\"content\").scrollTop = 0;\n    document.getElementById(\"sidebar\").classList.remove(\"open\");\n}\n```\n\n\u003e Source: `internal/output/viewer/app.js#L172-L196`\n\n### Relative Link Resolution\n\nRelative links in Markdown (e.g., `../other-section/index.md`) must be converted to hash links (`#other-section/index.md`) within the SPA. `fixLinks()` iterates over all `\u003ca\u003e` elements after rendering to perform this conversion:\n\n```javascript\nfunction fixLinks(container, currentPath) {\n    var baseDir = currentPath.replace(/[^/]*$/, \"\");\n    var links = container.querySelectorAll(\"a[href]\");\n    for (var i = 0; i \u003c links.length; i++) {\n        var href = links[i].getAttribute(\"href\");\n        if (href.indexOf(\"://\") !== -1 || href.charAt(0) === \"#\" || href.indexOf(\"mailto:\") === 0) continue;\n        var resolved = resolvePath(baseDir, href);\n        links[i].setAttribute(\"href\", \"#\" + resolved);\n    }\n}\n```\n\n\u003e Source: `internal/output/viewer/app.js#L280-L293`\n\n### Mermaid Diagram Fullscreen\n\nEach Mermaid diagram has a fullscreen button (`⛶`). Clicking it enters fullscreen mode, with support for scroll-wheel zoom (0.8× to 2.0×) and mouse-drag panning:\n\n```javascript\nfunction onMmWheel(e) {\n    e.preventDefault();\n    var delta = e.deltaY \u003e 0 ? 0.95 : 1.05;\n    var newScale = mmState.scale * delta;\n    if (newScale \u003c 0.8) newScale = 0.8;\n    if (newScale \u003e 2.0) newScale = 2.0;\n    mmState.scale = newScale;\n    applyMmTransform();\n}\n```\n\n\u003e Source: `internal/output/viewer/app.js#L526-L534`\n\n## Visual Styles (style.css)\n\n`style.css` defines the design system using CSS custom properties (CSS Variables), presenting a dark-themed sidebar alongside a light main content area:\n\n```css\n:root {\n    --sidebar-width: 280px;\n    --sidebar-bg: #1a1b26;\n    --sidebar-text: #a9b1d6;\n    --sidebar-active-bg: rgba(122, 162, 247, 0.12);\n    --sidebar-active-text: #7aa2f7;\n    --content-bg: #ffffff;\n    --text-color: #2e3440;\n    /* ... */\n}\n```\n\n\u003e Source: `internal/output/viewer/style.css#L1-L19`\n\nResponsive design uses a `@media (max-width: 860px)` breakpoint to hide the sidebar and show the hamburger menu on narrow screens:\n\n```css\n@media (max-width: 860px) {\n    #menu-toggle { display: block; }\n    #sidebar {\n        position: fixed;\n        transform: translateX(-100%);\n        transition: transform 0.25s ease;\n    }\n    #sidebar.open { transform: translateX(0); }\n}\n```\n\n\u003e Source: `internal/output/viewer/style.css#L521-L551`\n\n## Core Flow\n\n```mermaid\nsequenceDiagram\n    participant Pipeline as generator/pipeline.go\n    participant ViewerWriter as Writer.WriteViewer()\n    participant BundleData as bundleData()\n    participant FS as .doc-build/ Filesystem\n    participant Browser as User Browser\n\n    Pipeline-\u003e\u003eViewerWriter: WriteViewer(projectName, docMeta)\n    ViewerWriter-\u003e\u003eViewerWriter: Inject PROJECT_NAME / LANG into HTML\n    ViewerWriter-\u003e\u003eFS: Write index.html\n    ViewerWriter-\u003e\u003eFS: Write app.js\n    ViewerWriter-\u003e\u003eFS: Write style.css\n    ViewerWriter-\u003e\u003eFS: Write _doc_meta.json\n    ViewerWriter-\u003e\u003eBundleData: bundleData()\n    BundleData-\u003e\u003eFS: Read _catalog.json\n    BundleData-\u003e\u003eFS: Walk and collect all .md files\n    BundleData-\u003e\u003eFS: Collect translated language pages (if any)\n    BundleData-\u003e\u003eFS: Write _data.js (window.DOC_DATA)\n    BundleData--\u003e\u003eViewerWriter: Done\n    ViewerWriter--\u003e\u003ePipeline: nil (success)\n\n    Note over Browser: User opens index.html\n    Browser-\u003e\u003eFS: Load _data.js\n    Browser-\u003e\u003eBrowser: init()\n    Browser-\u003e\u003eBrowser: buildSidebar()\n    Browser-\u003e\u003eBrowser: handleRoute() (read URL hash)\n    Browser-\u003e\u003eBrowser: renderContent() (Markdown → HTML)\n    Browser-\u003e\u003eBrowser: renderMermaid() (Mermaid diagrams)\n```\n\n## External Library Dependencies\n\nThree third-party libraries are loaded via CDN in the browser, each included via a `\u003cscript\u003e` tag in `index.html`:\n\n```html\n\u003cscript src=\"https://cdn.jsdelivr.net/npm/marked/marked.min.js\"\u003e\u003c/script\u003e\n\u003cscript src=\"https://cdn.jsdelivr.net/npm/highlight.js@11/highlight.min.js\"\u003e\u003c/script\u003e\n\u003cscript src=\"https://cdn.jsdelivr.net/npm/mermaid/dist/mermaid.min.js\"\u003e\u003c/script\u003e\n```\n\n\u003e Source: `internal/output/viewer/index.html#L26-L28`\n\n| Library | Purpose |\n|---------|---------|\n| [marked](https://marked.js.org/) | Markdown-to-HTML rendering (GFM support) |\n| [highlight.js](https://highlightjs.org/) | Code syntax highlighting |\n| [mermaid](https://mermaid.js.org/) | Mermaid diagram rendering (flowcharts, sequence diagrams, etc.) |\n\n\u003e **Note**: Due to the CDN dependency, text content remains visible in offline environments, but code highlighting and Mermaid diagrams require a network connection to render correctly.\n\n## When WriteViewer Is Called\n\n`WriteViewer` is invoked at two points:\n\n1. **After `selfmd generate` completes**: Called immediately after the fourth pipeline stage (index and navigation) finishes\n2. **After `selfmd translate` completes**: Called again to re-bundle `_data.js` with multilingual data\n\n```go\n// In pipeline.go (after generate completes)\nif err := g.Writer.WriteViewer(g.Config.Project.Name, docMeta); err != nil {\n    g.Logger.Warn(\"產生瀏覽器失敗\", \"error\", err)\n} else {\n    fmt.Println(\"      完成，開啟 .doc-build/index.html 即可瀏覽\")\n}\n```\n\n\u003e Source: `internal/generator/pipeline.go#L149-L155`\n\n## Related Links\n\n- [Output Writer and Link Fixing](../output-writer/index.md) — The `Writer` struct and base write functions like `WriteFile`\n- [Document Generation Pipeline](../generator/index.md) — The four-stage pipeline that triggers `WriteViewer`\n- [Index and Navigation Generation Phase](../generator/index-phase/index.md) — Pipeline stage four, after which `WriteViewer` is called\n- [Translation Phase](../generator/translate-phase/index.md) — `WriteViewer` is called again after translation completes\n- [Multilingual Support](../../i18n/index.md) — Language switcher and multilingual data bundling\n- [Output Structure](../../overview/output-structure/index.md) — Description of all output files under `.doc-build/`\n\n## Reference Files\n\n| File Path | Description |\n|-----------|-------------|\n| `internal/output/viewer.go` | `WriteViewer()`, `bundleData()`, and Go embed declarations |\n| `internal/output/viewer/index.html` | HTML shell template with `{{PROJECT_NAME}}` and `{{LANG}}` placeholders |\n| `internal/output/viewer/app.js` | Complete frontend SPA logic (routing, rendering, language switching, Mermaid fullscreen) |\n| `internal/output/viewer/style.css` | CSS styles including CSS variables, responsive design, and print mode |\n| `internal/output/writer.go` | `Writer` struct definition and base write functions like `WriteFile` |\n| `internal/output/navigation.go` | Navigation page generation functions such as `GenerateIndex` and `GenerateSidebar` |\n| `internal/generator/pipeline.go` | Main pipeline flow that calls `WriteViewer` |\n| `internal/generator/translate_phase.go` | Calls `WriteViewer` again after translation completes |","en-US/getting-started/first-run/index.md":"# Generating Your First Document\n\nAfter completing the initial setup, run `selfmd generate` to launch the four-phase documentation generation pipeline, which automatically scans your project, calls Claude CLI to write documentation, and outputs a static website.\n\n## Overview\n\n`selfmd generate` is the core command of selfmd. It reads the configuration from `selfmd.yaml` and executes the following steps in order:\n\n1. **Scan** the project directory structure and source code\n2. **Call Claude CLI** to generate the documentation catalog\n3. **Call Claude CLI in parallel** to generate each documentation page\n4. **Generate** the index, sidebar, and static browser\n\nThe entire process is fully automated. When complete, the full documentation website can be found in the output directory (default: `.doc-build/`), ready to browse by opening `index.html`.\n\n---\n\n## Prerequisites\n\nBefore running `generate`, confirm the following:\n\n| Condition | Description |\n|-----------|-------------|\n| `selfmd.yaml` exists | Created by running `selfmd init`, or created manually |\n| Claude CLI is installed and callable | The program automatically calls `claude.CheckAvailable()` on startup to verify |\n| Current directory is the project root | selfmd uses the working directory as `rootDir` |\n\n---\n\n## Quick Start\n\n```bash\n# Basic usage\nselfmd generate\n\n# Force-clean the output directory before regenerating\nselfmd generate --clean\n\n# Preview which files will be scanned without actually calling Claude\nselfmd generate --dry-run\n\n# Increase concurrency to speed up generation\nselfmd generate --concurrency 5\n```\n\n---\n\n## Architecture\n\n```mermaid\nflowchart TD\n    CLI[\"selfmd generate\\ncmd/generate.go\"] --\u003e CheckClaude[\"claude.CheckAvailable()\"]\n    CLI --\u003e LoadCfg[\"config.Load()\"]\n    CLI --\u003e NewGen[\"generator.NewGenerator()\"]\n    NewGen --\u003e Runner[\"claude.Runner\"]\n    NewGen --\u003e Engine[\"prompt.Engine\"]\n    NewGen --\u003e Writer[\"output.Writer\"]\n\n    NewGen --\u003e Generate[\"Generator.Generate()\"]\n\n    Generate --\u003e Phase0[\"Phase 0\\nClean or ensure output directory\"]\n    Phase0 --\u003e Phase1[\"Phase 1\\nscanner.Scan()\"]\n    Phase1 --\u003e Phase2{\"Catalog\\nalready exists?\"}\n    Phase2 -- \"Yes (non --clean mode)\" --\u003e LoadCatalog[\"Load existing _catalog.json\"]\n    Phase2 -- \"No\" --\u003e GenCatalog[\"GenerateCatalog()\\nCall Claude CLI\"]\n    LoadCatalog --\u003e Phase3[\"Phase 3\\nGenerateContent()\\nCall Claude CLI in parallel\"]\n    GenCatalog --\u003e Phase3\n    Phase3 --\u003e Phase4[\"Phase 4\\nGenerateIndex()\\nGenerate index.md / _sidebar.md\"]\n    Phase4 --\u003e Viewer[\"Writer.WriteViewer()\\nGenerate static HTML browser\"]\n    Viewer --\u003e SaveCommit[\"git.SaveLastCommit()\\nRecord current commit\"]\n```\n\n---\n\n## The Four Phases in Detail\n\n### Phase 0: Initialize Output Directory\n\nThe program first determines whether the output directory needs to be cleaned:\n\n```go\nclean := opts.Clean || g.Config.Output.CleanBeforeGenerate\nif clean {\n    fmt.Println(ui.T(\"[0/4] 清除輸出目錄...\", \"[0/4] Cleaning output directory...\"))\n    if !opts.DryRun {\n        if err := g.Writer.Clean(); err != nil {\n            return err\n        }\n    }\n} else {\n    if err := g.Writer.EnsureDir(); err != nil {\n        return err\n    }\n}\n```\n\n\u003e Source: `internal/generator/pipeline.go#L73-L85`\n\nThe `--clean` flag or `clean_before_generate: true` in the config file will trigger the clean behavior; otherwise, the program only ensures the directory exists.\n\n---\n\n### Phase 1: Scan Project Structure\n\nCalls `scanner.Scan()` to traverse the project directory:\n\n```go\nfmt.Println(ui.T(\"[1/4] 掃描專案結構...\", \"[1/4] Scanning project structure...\"))\nscan, err := scanner.Scan(g.Config, g.RootDir)\n```\n\n\u003e Source: `internal/generator/pipeline.go#L88-L93`\n\nThe scanner filters files according to `targets.include` and `targets.exclude` in `selfmd.yaml`, and also reads:\n- `README.md` (used as background context for Claude)\n- The contents of entry files specified in `entry_points`\n\nWhen using `--dry-run`, the program prints the file tree at this stage and exits without calling Claude.\n\n---\n\n### Phase 2: Generate the Documentation Catalog\n\nThis is when Claude CLI is called for the first time. If `_catalog.json` already exists in the output directory (i.e., not in `--clean` mode), selfmd will load the existing catalog first to save costs:\n\n```go\nif !clean {\n    catJSON, readErr := g.Writer.ReadCatalogJSON()\n    if readErr == nil {\n        cat, err = catalog.Parse(catJSON)\n    }\n    if cat != nil {\n        items := cat.Flatten()\n        fmt.Printf(ui.T(\"[2/4] 載入已存目錄（%d 個章節，%d 個項目）\\n\", ...))\n    }\n}\nif cat == nil {\n    fmt.Println(ui.T(\"[2/4] 產生文件目錄...\", \"[2/4] Generating catalog...\"))\n    cat, err = g.GenerateCatalog(ctx, scan)\n    // ...\n    if err := g.Writer.WriteCatalogJSON(cat); err != nil { ... }\n}\n```\n\n\u003e Source: `internal/generator/pipeline.go#L103-L128`\n\nThe generated catalog JSON is saved to `.doc-build/_catalog.json` for use in subsequent incremental updates.\n\n---\n\n### Phase 3: Generate Content Pages in Parallel\n\nThis is the most time-consuming phase. selfmd uses `errgroup` and a semaphore to control concurrency:\n\n```go\nconcurrency := g.Config.Claude.MaxConcurrent\nif opts.Concurrency \u003e 0 {\n    concurrency = opts.Concurrency\n}\nfmt.Printf(ui.T(\"[3/4] 產生內容頁面（並行度：%d）...\\n\", ...), concurrency)\nif err := g.GenerateContent(ctx, scan, cat, concurrency, !clean); err != nil {\n    g.Logger.Warn(ui.T(\"部分頁面產生失敗\", \"some pages failed to generate\"), \"error\", err)\n}\n```\n\n\u003e Source: `internal/generator/pipeline.go#L131-L138`\n\nEach documentation page corresponds to one Claude CLI call. If a page already exists (non `--clean` mode), it is automatically skipped:\n\n```go\nif skipExisting \u0026\u0026 g.Writer.PageExists(item) {\n    skipped.Add(1)\n    fmt.Printf(ui.T(\"      [跳過] %s（已存在）\\n\", ...), item.Title)\n    return nil\n}\n```\n\n\u003e Source: `internal/generator/content_phase.go#L44-L48`\n\nIf a page fails to generate, selfmd **does not abort the entire process** — instead it writes a placeholder page and continues with the remaining pages.\n\n---\n\n### Phase 4: Generate Index and Navigation\n\nThe final phase produces three types of output:\n\n```go\n// Main index page\nindexContent := output.GenerateIndex(...)\ng.Writer.WriteFile(\"index.md\", indexContent)\n\n// Sidebar navigation\nsidebarContent := output.GenerateSidebar(...)\ng.Writer.WriteFile(\"_sidebar.md\", sidebarContent)\n\n// Category indexes for sections with child pages\nfor _, item := range items {\n    if !item.HasChildren { continue }\n    categoryContent := output.GenerateCategoryIndex(item, children, lang)\n    g.Writer.WritePage(item, categoryContent)\n}\n```\n\n\u003e Source: `internal/generator/index_phase.go#L14-L53`\n\n---\n\n## Command Flags\n\n| Flag | Default | Description |\n|------|---------|-------------|\n| `--clean` | `false` | Force-clean the output directory before regenerating |\n| `--no-clean` | `false` | Ignore `clean_before_generate` in the config file and preserve existing documents |\n| `--dry-run` | `false` | Scan and print the file tree only, without calling Claude |\n| `--concurrency N` | `0` (uses config value) | Override `claude.max_concurrent` with a specific concurrency level |\n\n```go\ngenerateCmd.Flags().BoolVar(\u0026cleanFlag, \"clean\", false, \"強制清除輸出目錄\")\ngenerateCmd.Flags().BoolVar(\u0026noCleanFlag, \"no-clean\", false, \"不清除輸出目錄\")\ngenerateCmd.Flags().BoolVar(\u0026dryRun, \"dry-run\", false, \"只顯示計畫，不實際執行\")\ngenerateCmd.Flags().IntVar(\u0026concurrencyNum, \"concurrency\", 0, \"並行度（覆蓋設定檔）\")\n```\n\n\u003e Source: `cmd/generate.go#L34-L39`\n\n---\n\n## Output Structure\n\nWhen complete, the `.doc-build/` directory has the following structure:\n\n```\n.doc-build/\n├── index.md              ← Main index (Phase 4)\n├── index.html            ← Static HTML browser entry point\n├── _sidebar.md           ← Sidebar navigation (Phase 4)\n├── _catalog.json         ← Documentation catalog cache (used for incremental updates)\n├── _last_commit          ← Git commit record (used for incremental updates)\n├── _data.js              ← Data bundle for the static browser\n├── \u003csection\u003e/\n│   └── \u003cpage\u003e/\n│       └── index.md      ← Individual documentation pages (Phase 3)\n└── ...\n```\n\n---\n\n## Completion Summary\n\nAfter a successful generation, the terminal displays a summary similar to the following:\n\n```\n========================================\nDocumentation generation complete!\n  Output directory: .doc-build\n  Pages generated: 42 succeeded\n  Total time: 3m25s\n  Total cost: $0.1234 USD\n========================================\n```\n\n\u003e Source: `internal/generator/pipeline.go#L168-L180`\n\nOpen `.doc-build/index.html` in your browser to view the complete documentation.\n\n---\n\n## FAQ\n\n**Q: Some pages show \"This page failed to generate\" after running**\n\nThis is a normal protective mechanism — failed pages are written with placeholder content. Re-run `selfmd generate` (without `--clean`) and the program will automatically skip completed pages, regenerating only the ones that failed.\n\n**Q: I want to completely regenerate all pages**\n\nRun `selfmd generate --clean` to clear the output directory and regenerate everything from scratch.\n\n**Q: How do I speed up generation?**\n\nIncreasing the `--concurrency` value (e.g., `--concurrency 8`) raises the concurrency level, but be mindful of Claude CLI's API rate limits.\n\n---\n\n## Related Links\n\n- [Installation and Build](../installation/index.md)\n- [Initial Setup](../init/index.md)\n- [selfmd generate Command Reference](../../cli/cmd-generate/index.md)\n- [selfmd.yaml Configuration Overview](../../configuration/config-overview/index.md)\n- [Overall Pipeline and Four Phases](../../architecture/pipeline/index.md)\n- [Output Structure](../../overview/output-structure/index.md)\n- [Incremental Updates](../../core-modules/incremental-update/index.md)\n\n---\n\n## Reference Files\n\n| File Path | Description |\n|-----------|-------------|\n| `cmd/generate.go` | `generate` command definition, flag declarations, `runGenerate` entry point |\n| `internal/generator/pipeline.go` | `Generator` struct, `Generate()` four-phase main pipeline |\n| `internal/generator/catalog_phase.go` | Phase 2: calls Claude to generate the documentation catalog |\n| `internal/generator/content_phase.go` | Phase 3: generates content pages in parallel |\n| `internal/generator/index_phase.go` | Phase 4: generates the index, sidebar, and category indexes |\n| `internal/config/config.go` | `Config` struct definition, defaults, and `Load()` logic |\n| `internal/scanner/scanner.go` | Project directory scanning logic |\n| `internal/output/writer.go` | `Writer` struct, page writing, and state persistence |\n| `cmd/init.go` | `init` command, for understanding prerequisites |","en-US/getting-started/index.md":"# Quick Start\n\nThis section contains the following:\n\n- [Installation \u0026 Build](installation/index.md)\n- [Initialization Setup](init/index.md)\n- [Generating Your First Document](first-run/index.md)\n","en-US/getting-started/init/index.md":"# Initialization Setup\n\nRunning the `selfmd init` command automatically scans the current directory, detects the project type, and generates a `selfmd.yaml` configuration file, establishing the foundation for subsequent documentation generation.\n\n## Overview\n\n`selfmd init` is the first step when using selfmd. It automatically determines the project type by analyzing characteristic files in the directory (such as `go.mod`, `package.json`, `requirements.txt`, etc.) and generates a `selfmd.yaml` configuration file pre-filled with sensible defaults.\n\nAfter initialization, users only need to fine-tune the configuration file as needed before running `selfmd generate` to start generating documentation.\n\n**Core responsibilities:**\n- Detect project type (`backend`, `frontend`, `fullstack`, `library`)\n- Infer common entry point file paths\n- Populate the complete `Config` struct with default values and serialize to YAML\n\n## Architecture\n\n```mermaid\nflowchart TD\n    User[\"User runs selfmd init\"]\n    CheckExist{\"selfmd.yaml\\nalready exists?\"}\n    ForceFlag{\"--force\\nflag?\"}\n    Error[\"Return error\\n(use --force to overwrite)\"]\n    DefaultCfg[\"config.DefaultConfig()\\nCreate default config\"]\n    Detect[\"detectProject()\\nScan characteristic files\"]\n    SetFields[\"Populate\\nProject.Type / Name / EntryPoints\"]\n    Save[\"cfg.Save(cfgFile)\\nWrite selfmd.yaml\"]\n    Print[\"Print initialization summary\"]\n\n    User --\u003e CheckExist\n    CheckExist -- No --\u003e DefaultCfg\n    CheckExist -- Yes --\u003e ForceFlag\n    ForceFlag -- Yes --\u003e DefaultCfg\n    ForceFlag -- No --\u003e Error\n    DefaultCfg --\u003e Detect\n    Detect --\u003e SetFields\n    SetFields --\u003e Save\n    Save --\u003e Print\n```\n\n## Project Type Detection\n\nThe `detectProject()` function sequentially checks whether the following characteristic files exist in the directory, mapping each to a project type and a list of suggested entry points:\n\n| Characteristic File | Project Type | Suggested Entry Points |\n|---------------------|--------------|------------------------|\n| `go.mod` | `backend` | `main.go`, `cmd/root.go` |\n| `Cargo.toml` | `backend` | `src/main.rs`, `src/lib.rs` |\n| `package.json` | `frontend` | `src/index.ts`, `src/index.js`, `src/main.ts`, `src/App.tsx` |\n| `pom.xml` | `backend` | `src/main/java` |\n| `build.gradle` | `backend` | `src/main/java` |\n| `requirements.txt` | `backend` | `main.py`, `app.py`, `src/main.py` |\n| `pyproject.toml` | `backend` | `src/main.py`, `main.py` |\n| `composer.json` | `backend` | `public/index.php`, `src/Kernel.php` |\n| `Gemfile` | `backend` | `config/application.rb`, `app/` |\n| (no match) | `library` | (empty) |\n\n**fullstack special case:** If `package.json` (frontend) is detected but `go.mod` or a `server/` directory also exists, the type is automatically upgraded to `fullstack`.\n\n```go\n// check if frontend project also has backend\nif c.pType == \"frontend\" {\n    if _, err := os.Stat(\"go.mod\"); err == nil {\n        return \"fullstack\", found\n    }\n    if _, err := os.Stat(\"server\"); err == nil {\n        return \"fullstack\", found\n    }\n}\n```\n\n\u003e Source: cmd/init.go#L87-L94\n\nAfter a characteristic file is detected, the function retains only entry point files that **actually exist on disk** — paths that do not exist are not written to the config.\n\n## Default Configuration Values\n\nThe initial configuration generated by `config.DefaultConfig()` includes the following defaults:\n\n```go\nfunc DefaultConfig() *Config {\n    return \u0026Config{\n        Project: ProjectConfig{\n            Name: filepath.Base(mustGetwd()),\n            Type: \"backend\",\n        },\n        Targets: TargetsConfig{\n            Include: []string{\"src/**\", \"pkg/**\", \"cmd/**\", \"internal/**\", \"lib/**\", \"app/**\"},\n            Exclude: []string{\n                \"vendor/**\", \"node_modules/**\", \".git/**\", \".doc-build/**\",\n                \"**/*.pb.go\", \"**/generated/**\", \"dist/**\", \"build/**\",\n            },\n            EntryPoints: []string{},\n        },\n        Output: OutputConfig{\n            Dir:                 \".doc-build\",\n            Language:            \"zh-TW\",\n            SecondaryLanguages:  []string{},\n            CleanBeforeGenerate: false,\n        },\n        Claude: ClaudeConfig{\n            Model:          \"sonnet\",\n            MaxConcurrent:  3,\n            TimeoutSeconds: 300,\n            MaxRetries:     2,\n            AllowedTools:   []string{\"Read\", \"Glob\", \"Grep\"},\n            ExtraArgs:      []string{},\n        },\n        Git: GitConfig{\n            Enabled:    true,\n            BaseBranch: \"main\",\n        },\n    }\n}\n```\n\n\u003e Source: internal/config/config.go#L96-L129\n\n## Configuration File Structure\n\n`selfmd.yaml` consists of five top-level blocks corresponding to the fields of the `Config` struct:\n\n```mermaid\nerDiagram\n    Config {\n        ProjectConfig project\n        TargetsConfig targets\n        OutputConfig  output\n        ClaudeConfig  claude\n        GitConfig     git\n    }\n    ProjectConfig {\n        string name\n        string type\n        string description\n    }\n    TargetsConfig {\n        string[] include\n        string[] exclude\n        string[] entry_points\n    }\n    OutputConfig {\n        string dir\n        string language\n        string[] secondary_languages\n        bool   clean_before_generate\n    }\n    ClaudeConfig {\n        string model\n        int    max_concurrent\n        int    timeout_seconds\n        int    max_retries\n        string[] allowed_tools\n        string[] extra_args\n    }\n    GitConfig {\n        bool   enabled\n        string base_branch\n    }\n    Config ||--|| ProjectConfig : \"project\"\n    Config ||--|| TargetsConfig : \"targets\"\n    Config ||--|| OutputConfig  : \"output\"\n    Config ||--|| ClaudeConfig  : \"claude\"\n    Config ||--|| GitConfig     : \"git\"\n```\n\n## Core Flow\n\n```mermaid\nsequenceDiagram\n    participant U as User\n    participant Init as runInit()\n    participant OS as os.Stat()\n    participant CFG as config.DefaultConfig()\n    participant Detect as detectProject()\n    participant Save as cfg.Save()\n\n    U-\u003e\u003eInit: selfmd init [--force]\n    Init-\u003e\u003eOS: Check if selfmd.yaml exists\n    alt Exists and no --force\n        Init--\u003e\u003eU: Error: use --force to overwrite\n    else Does not exist or --force provided\n        Init-\u003e\u003eCFG: Create default Config\n        CFG--\u003e\u003eInit: *Config (with all defaults)\n        Init-\u003e\u003eDetect: Scan characteristic files\n        Detect-\u003e\u003eOS: os.Stat() each characteristic file in sequence\n        Detect--\u003e\u003eInit: projectType, entryPoints\n        Init-\u003e\u003eInit: Overwrite Project.Type / Name / EntryPoints\n        Init-\u003e\u003eSave: yaml.Marshal + os.WriteFile\n        Save--\u003e\u003eInit: Write successful\n        Init--\u003e\u003eU: Print summary (project name, type, output dir, etc.)\n    end\n```\n\n## Command Usage\n\n### Basic Initialization\n\n```bash\nselfmd init\n```\n\nGenerates `selfmd.yaml` in the current directory. If the file already exists, the command aborts with an error message.\n\n### Force Overwrite\n\n```bash\nselfmd init --force\n```\n\nUse the `--force` flag to overwrite an existing configuration file.\n\n\u003e Source: cmd/init.go#L23-L26\n\n### Specify Configuration File Path\n\n```bash\nselfmd init --config path/to/custom.yaml\n```\n\nUse the global `--config` (or `-c`) flag to specify an output path. Defaults to `selfmd.yaml`.\n\n\u003e Source: cmd/root.go#L33\n\n## Post-Initialization Configuration Adjustments\n\nThe generated `selfmd.yaml` contains sensible defaults. Common settings that may need adjustment include:\n\n| Setting | Default | Description |\n|---------|---------|-------------|\n| `project.description` | (empty) | Add a project description to improve AI documentation quality |\n| `targets.include` | Common directory globs | Adjust the scan scope to match the actual project structure |\n| `output.language` | `zh-TW` | Primary documentation language |\n| `output.secondary_languages` | `[]` | Add multi-language output, e.g. `[\"en-US\"]` |\n| `claude.max_concurrent` | `3` | Tune concurrency to balance speed and resource usage |\n| `git.base_branch` | `main` | Adjust to match the project's actual main branch name |\n\nFor configuration details, see [selfmd.yaml Structure Overview](../../configuration/config-overview/index.md).\n\n## Configuration Validation Rules\n\nWhen loading the configuration, the `validate()` function enforces the following rules:\n\n```go\nfunc (c *Config) validate() error {\n    if c.Output.Dir == \"\" {\n        return fmt.Errorf(\"output.dir 不可為空\")\n    }\n    if c.Output.Language == \"\" {\n        return fmt.Errorf(\"output.language 不可為空\")\n    }\n    if c.Claude.MaxConcurrent \u003c 1 {\n        c.Claude.MaxConcurrent = 1\n    }\n    if c.Claude.TimeoutSeconds \u003c 30 {\n        c.Claude.TimeoutSeconds = 30\n    }\n    if c.Claude.MaxRetries \u003c 0 {\n        c.Claude.MaxRetries = 0\n    }\n    return nil\n}\n```\n\n\u003e Source: internal/config/config.go#L157-L174\n\n- `output.dir` and `output.language` are required fields\n- `claude.max_concurrent` has a minimum value of `1`\n- `claude.timeout_seconds` has a minimum value of `30`\n- `claude.max_retries` must not be negative\n\n## Related Links\n\n- [Installation \u0026 Build](../installation/index.md) — Installation steps before running `selfmd init`\n- [Generating Your First Document](../first-run/index.md) — Next steps after initialization\n- [selfmd init Command Reference](../../cli/cmd-init/index.md) — Full command parameter reference\n- [selfmd.yaml Structure Overview](../../configuration/config-overview/index.md) — Detailed description of each configuration field\n- [Project \u0026 Scan Target Configuration](../../configuration/project-targets/index.md) — Advanced configuration for the `targets` block\n- [Output \u0026 Multi-language Configuration](../../configuration/output-language/index.md) — Language settings for the `output` block\n\n## Reference Files\n\n| File Path | Description |\n|-----------|-------------|\n| `cmd/init.go` | `selfmd init` command implementation, including `runInit()` and `detectProject()` functions |\n| `cmd/root.go` | Root command definition, global flag declarations (`--config`, `--force`, etc.) |\n| `internal/config/config.go` | `Config` struct definition, `DefaultConfig()`, `Load()`, `Save()`, and `validate()` implementations |","en-US/getting-started/installation/index.md":"# Installation \u0026 Build\n\nThis page explains how to obtain the selfmd source code, compile the executable, and verify the prerequisites needed to run it.\n\n## Overview\n\nselfmd is a CLI tool written in Go that must be compiled locally before use. Since selfmd uses the local Claude Code CLI as its AI backend, **both the Go toolchain and Claude Code CLI** are required prerequisites for it to function correctly.\n\nKey terminology:\n- **Claude Code CLI**: Anthropic's official local AI agent; selfmd invokes its `claude` command via a subprocess\n- **Cross-compilation**: Compiling a binary on one platform that can run on another platform\n\n## Prerequisites\n\n| Requirement | Minimum Version | Description |\n|-------------|----------------|-------------|\n| Go toolchain | 1.25+ | Used to compile the selfmd source code |\n| Claude Code CLI | Latest | selfmd calls the `claude` command at runtime |\n\n### Claude Code CLI Verification\n\nEach time selfmd runs commands such as `generate`, `update`, or `translate`, it first calls `CheckAvailable()` to confirm that `claude` is installed and accessible on the `PATH`:\n\n```go\n// CheckAvailable verifies that the claude CLI is installed and accessible.\nfunc CheckAvailable() error {\n\t_, err := exec.LookPath(\"claude\")\n\tif err != nil {\n\t\treturn fmt.Errorf(\"找不到 claude CLI。請先安裝 Claude Code：https://docs.anthropic.com/en/docs/claude-code\")\n\t}\n\treturn nil\n}\n```\n\n\u003e Source: `internal/claude/runner.go#L146-L152`\n\n## Architecture\n\nThe diagram below illustrates selfmd's installation components and their dependencies:\n\n```mermaid\nflowchart TD\n    subgraph 前置需求[\"Prerequisites\"]\n        GoSDK[\"Go 1.25+\\nToolchain\"]\n        ClaudeCLI[\"Claude Code CLI\\n(claude command)\"]\n    end\n\n    subgraph 建置流程[\"Build Process\"]\n        Source[\"Source Code\\ngithub.com/monkenwu/selfmd\"]\n        GoBuild[\"go build\"]\n        Binary[\"selfmd\\nExecutable\"]\n    end\n\n    subgraph 相依套件[\"Go Dependencies (go.mod)\"]\n        Cobra[\"cobra v1.10.2\\nCLI Framework\"]\n        YAML[\"yaml.v3\\nConfig Parsing\"]\n        Sync[\"golang.org/x/sync\\nConcurrency Control\"]\n        Doublestar[\"doublestar/v4\\nGlob Matching\"]\n    end\n\n    GoSDK --\u003e GoBuild\n    Source --\u003e GoBuild\n    GoBuild --\u003e Binary\n    Cobra --\u003e Source\n    YAML --\u003e Source\n    Sync --\u003e Source\n    Doublestar --\u003e Source\n\n    Binary --\u003e|\"Runtime call\"| ClaudeCLI\n```\n\n## Go Dependencies\n\nselfmd's dependencies are defined in `go.mod` with four direct dependencies:\n\n```\nmodule github.com/monkenwu/selfmd\n\ngo 1.25.7\n\nrequire (\n\tgithub.com/bmatcuk/doublestar/v4 v4.10.0\n\tgithub.com/spf13/cobra v1.10.2\n\tgolang.org/x/sync v0.19.0\n\tgopkg.in/yaml.v3 v3.0.1\n)\n```\n\n\u003e Source: `go.mod#L1-L10`\n\n| Package | Version | Purpose |\n|---------|---------|---------|\n| `github.com/spf13/cobra` | v1.10.2 | CLI command framework managing all subcommands (init, generate, update, translate) |\n| `gopkg.in/yaml.v3` | v3.0.1 | Parsing and writing the `selfmd.yaml` configuration file |\n| `golang.org/x/sync` | v0.19.0 | Goroutine synchronization during concurrent document generation |\n| `github.com/bmatcuk/doublestar/v4` | v4.10.0 | Glob path matching with `**` wildcard support, used for scanning target configuration |\n\n## Build Steps\n\n### Get the Source Code\n\n```bash\ngit clone https://github.com/monkenwu/selfmd.git\ncd selfmd\n```\n\n### Build for Current Platform\n\n```bash\ngo build -o selfmd .\n```\n\n\u003e Source: `README.md#L18-L19`\n\n### Cross-Compilation\n\nselfmd supports cross-compilation to multiple platforms by setting the `GOOS` and `GOARCH` environment variables:\n\n```bash\n# Linux arm64\nGOOS=linux GOARCH=arm64 go build -o ./bin/selfmd-linux-arm64\n\n# Linux amd64\nGOOS=linux GOARCH=amd64 go build -o ./bin/selfmd-linux-amd64\n\n# macOS arm64 (Apple Silicon)\nGOOS=darwin GOARCH=arm64 go build -o ./bin/selfmd-macos-arm64\n\n# macOS amd64 (Intel)\nGOOS=darwin GOARCH=amd64 go build -o ./bin/selfmd-macos-amd64\n\n# Windows amd64\nGOOS=windows GOARCH=amd64 go build -o ./bin/selfmd-windows-amd64.exe\n\n# Windows arm64\nGOOS=windows GOARCH=arm64 go build -o ./bin/selfmd-windows-arm64.exe\n```\n\n\u003e Source: `README.md#L21-L31`\n\n## Core Flow\n\n```mermaid\nsequenceDiagram\n    participant User as User\n    participant GoBuild as go build\n    participant selfmd as selfmd Executable\n    participant CheckAvailable as CheckAvailable()\n    participant ClaudeCLI as claude CLI\n\n    User-\u003e\u003eGoBuild: go build -o selfmd .\n    GoBuild--\u003e\u003eselfmd: Compilation complete\n\n    User-\u003e\u003eselfmd: selfmd generate\n    selfmd-\u003e\u003eCheckAvailable: Verify claude is available\n    CheckAvailable-\u003e\u003eClaudeCLI: exec.LookPath(\"claude\")\n    alt claude is installed\n        ClaudeCLI--\u003e\u003eCheckAvailable: Path found\n        CheckAvailable--\u003e\u003eselfmd: nil (no error)\n        selfmd-\u003e\u003eselfmd: Continue with document generation\n    else claude is not installed\n        ClaudeCLI--\u003e\u003eCheckAvailable: Executable not found\n        CheckAvailable--\u003e\u003eselfmd: Return error message\n        selfmd--\u003e\u003eUser: Prompt to install Claude Code\n    end\n```\n\n## Usage Examples\n\n### Verify Installation\n\nAfter compiling, use the following command to confirm selfmd is working correctly:\n\n```bash\n./selfmd --help\n```\n\nThe output should display:\n\n```\nselfmd — 專案文件自動產生器\n\nselfmd 是一個 CLI 工具，透過本地 Claude Code CLI 作為 AI 後端，\n自動掃描專案目錄並產生結構化的 Wiki 風格繁體中文技術文件。\n...\n```\n\n\u003e Source: `cmd/root.go#L17-L25`\n\n### Global Flags\n\nselfmd provides three global flags that can be used with any subcommand:\n\n```go\nrootCmd.PersistentFlags().StringVarP(\u0026cfgFile, \"config\", \"c\", \"selfmd.yaml\", \"設定檔路徑\")\nrootCmd.PersistentFlags().BoolVarP(\u0026verbose, \"verbose\", \"v\", false, \"顯示詳細輸出\")\nrootCmd.PersistentFlags().BoolVarP(\u0026quiet, \"quiet\", \"q\", false, \"僅顯示錯誤訊息\")\n```\n\n\u003e Source: `cmd/root.go#L33-L35`\n\n| Flag | Shorthand | Default | Description |\n|------|-----------|---------|-------------|\n| `--config` | `-c` | `selfmd.yaml` | Specify the configuration file path |\n| `--verbose` | `-v` | `false` | Show detailed debug output |\n| `--quiet` | `-q` | `false` | Show only error messages, suppress normal output |\n\n## Entry Point\n\nselfmd's entry point is `main.go` in the root directory, which delegates directly to `cmd.Execute()`:\n\n```go\npackage main\n\nimport (\n\t\"os\"\n\n\t\"github.com/monkenwu/selfmd/cmd\"\n)\n\nfunc main() {\n\tif err := cmd.Execute(); err != nil {\n\t\tos.Exit(1)\n\t}\n}\n```\n\n\u003e Source: `main.go#L1-L13`\n\n## Related Links\n\n- [Quick Start](../index.md) — Quick start overview\n- [Initialization](../init/index.md) — Steps to run `selfmd init` and create a configuration file after building\n- [Generating Your First Document](../first-run/index.md) — Complete workflow for generating your first document after installation\n- [selfmd init Command Reference](../../cli/cmd-init/index.md) — Complete flags and behavior for the init command\n- [selfmd generate Command Reference](../../cli/cmd-generate/index.md) — Complete flags and behavior for the generate command\n- [selfmd.yaml Configuration Overview](../../configuration/config-overview/index.md) — Detailed description of each configuration file field\n- [Claude CLI Integration Settings](../../configuration/claude-config/index.md) — Configure Claude model, concurrency, timeout, and other parameters\n\n## Reference Files\n\n| File Path | Description |\n|-----------|-------------|\n| `main.go` | Entry point, delegates to `cmd.Execute()` |\n| `go.mod` | Go module definition and dependency versions |\n| `README.md` | Project documentation including installation and build instructions |\n| `cmd/root.go` | Root command definition, global flags, and the `Execute()` function |\n| `cmd/init.go` | `init` subcommand implementation, including project type detection logic |\n| `cmd/generate.go` | `generate` subcommand implementation, calls `CheckAvailable()` to verify Claude CLI |\n| `internal/claude/runner.go` | `CheckAvailable()` function that verifies `claude` command exists on PATH |\n| `internal/config/config.go` | `Config` struct definition, default values, and `Load()`/`Save()` functions |","en-US/git-integration/affected-pages/index.md":"# Affected Page Determination Logic\n\nDuring `selfmd update` execution, the system needs to determine which documentation pages should be updated and which new pages need to be created, using two separate paths. This page explains the implementation and flow of this determination logic.\n\n## Overview\n\nAfter git diff returns a set of changed files, the `Update()` function does not blindly regenerate all documentation. Instead, it employs a **two-phase determination strategy**:\n\n1. **Text matching (exact match)**: First searches existing documentation content to see if changed source file paths are directly referenced, classifying changed files into \"matched\" and \"unmatched\" categories.\n2. **Claude AI semantic judgment**: Calls Claude separately for both categories, having the AI read the actual changes and make final decisions — which matched pages truly need updating? Which unmatched files need new pages created?\n\nThe core principle of this design is \"conservative updates\": regeneration is only triggered when code changes genuinely affect the behavior, architecture, or API described in the documentation.\n\n---\n\n## Architecture\n\n### Overall Determination Flow\n\n```mermaid\nflowchart TD\n    A[\"git.ParseChangedFiles()\"] --\u003e B[\"matchChangedFilesToDocs()\"]\n    B --\u003e C{Does documentation content reference this file path?}\n    C --\u003e|\"Yes → matched\"| D[\"determineMatchedUpdates()\"]\n    C --\u003e|\"No → unmatched\"| E[\"determineUnmatchedPages()\"]\n\n    D --\u003e F[\"Claude\\nupdate_matched.tmpl\"]\n    E --\u003e G[\"Claude\\nupdate_unmatched.tmpl\"]\n\n    F --\u003e H[\"List of pages to regenerate\\n[]UpdateMatchedResult\"]\n    G --\u003e I[\"List of pages to create\\n[]UpdateUnmatchedResult\"]\n\n    H --\u003e J[\"generateSinglePage()\"]\n    I --\u003e K[\"addItemToCatalog()\"]\n    K --\u003e L{\"Did a leaf node become a parent node?\"}\n    L --\u003e|Yes| M[\"promotedLeaf\\nContent moved to overview subpage\"]\n    L --\u003e|No| J\n    M --\u003e J\n```\n\n### Data Type Relationships\n\n```mermaid\nerDiagram\n    matchResult {\n        string changedFile \"Changed source code path\"\n        FlatItem_array pages \"Documentation pages referencing this file\"\n    }\n    UpdateMatchedResult {\n        string catalogPath \"Documentation path (dot-separated)\"\n        string title \"Page title\"\n        string reason \"Reason for regeneration\"\n    }\n    UpdateUnmatchedResult {\n        string catalogPath \"New page path (dot-separated)\"\n        string title \"New page title\"\n        string reason \"Reason for creation\"\n    }\n    promotedLeaf {\n        string OriginalPath \"Original leaf node path\"\n        string OverviewPath \"New overview subpage path\"\n        string OriginalTitle \"Original leaf node title\"\n    }\n    matchResult ||--o{ UpdateMatchedResult : \"Produced after Claude filtering\"\n    UpdateUnmatchedResult ||--o| promotedLeaf : \"May trigger leaf node promotion\"\n```\n\n---\n\n## Phase 1: Text Matching (matchChangedFilesToDocs)\n\n`matchChangedFilesToDocs()` performs initial filtering by searching whether existing documentation page content contains the path string of each changed file.\n\n```go\n// For each changed file, find which pages reference it\nfor _, f := range files {\n    var matchedPages []catalog.FlatItem\n    for _, item := range items {\n        content, ok := pageContents[item.Path]\n        if !ok {\n            continue\n        }\n        if strings.Contains(content, f.Path) {\n            matchedPages = append(matchedPages, item)\n        }\n    }\n\n    if len(matchedPages) \u003e 0 {\n        matched = append(matched, matchResult{\n            changedFile: f.Path,\n            pages:       matchedPages,\n        })\n    } else {\n        unmatched = append(unmatched, f.Path)\n    }\n}\n```\n\n\u003e Source: internal/generator/updater.go#L191-L213\n\n**Key design decisions**:\n\n- Uses `strings.Contains(content, f.Path)` for string matching rather than glob or regex — simple and reliable\n- Pre-reads all page content into a `pageContents` map to avoid repeated I/O\n- A single changed file can match multiple documentation pages; the same page can also be matched by multiple changed files (deduplicated later)\n\n---\n\n## Phase 2A: Determining Whether Matched Pages Need Updating (determineMatchedUpdates)\n\nFor \"matched\" files, `determineMatchedUpdates()` constructs a prompt containing the list of changed files and summaries of affected pages, then passes it to Claude for judgment.\n\n### Prompt Data Assembly\n\n```go\ndata := prompt.UpdateMatchedPromptData{\n    RepositoryName: g.Config.Project.Name,\n    Language:       g.Config.Output.Language,\n    ChangedFiles:   changedFilesList.String(),\n    AffectedPages:  affectedPagesInfo.String(),\n}\n\nrendered, err := g.Engine.RenderUpdateMatched(data)\n```\n\n\u003e Source: internal/generator/updater.go#L257-L265\n\n`AffectedPages` contains the title, catalogPath, and a 500-character content preview (`content[:500] + \"...\"`) for each potentially affected page, helping Claude understand the current scope of the documentation.\n\n### Claude's Judgment Criteria\n\n`update_matched.tmpl` explicitly instructs Claude with the following rules:\n\n| Needs Regeneration | Does Not Need Regeneration |\n|-------------------|---------------------------|\n| Function signature or API interface changes | Pure code style adjustments |\n| Addition or removal of significant features | Internal refactoring that doesn't affect external behavior |\n| Architecture or flow changes | Bug fixes with no behavior change |\n| Configuration format or option changes | Comment or docstring changes |\n\n\u003e Source: internal/prompt/templates/zh-TW/update_matched.tmpl#L40-L46\n\n### Claude Response Format\n\nClaude returns the pages that need regeneration as a JSON array:\n\n```go\ntype UpdateMatchedResult struct {\n    CatalogPath string `json:\"catalogPath\"`\n    Title       string `json:\"title\"`\n    Reason      string `json:\"reason\"`\n}\n```\n\n\u003e Source: internal/generator/updater.go#L18-L22\n\nThe system then maps `CatalogPath` back to a `catalog.FlatItem`. If Claude returns a path that does not exist, a warning is logged and the entry is skipped:\n\n```go\nfor _, r := range results {\n    if item, ok := itemMap[r.CatalogPath]; ok {\n        fmt.Printf(\"      → %s：%s\\n\", item.Title, r.Reason)\n        pagesToRegen = append(pagesToRegen, item)\n    } else {\n        g.Logger.Warn(\"Claude returned a catalogPath that does not exist\", \"path\", r.CatalogPath)\n    }\n}\n```\n\n\u003e Source: internal/generator/updater.go#L296-L303\n\n---\n\n## Phase 2B: Determining Whether Unmatched Files Need New Pages (determineUnmatchedPages)\n\nFor \"unmatched\" changed files (not referenced in any existing documentation), `determineUnmatchedPages()` asks Claude: do these added or modified files represent functionality that warrants creating new documentation pages?\n\n### Prompt Data Assembly\n\n```go\ndata := prompt.UpdateUnmatchedPromptData{\n    RepositoryName:  g.Config.Project.Name,\n    Language:        g.Config.Output.Language,\n    UnmatchedFiles:  fileList.String(),\n    ExistingCatalog: existingCatalog,\n    CatalogTable:    cat.BuildLinkTable(),\n}\n```\n\n\u003e Source: internal/generator/updater.go#L320-L327\n\n`ExistingCatalog` is the full catalog JSON, and `CatalogTable` is a formatted page list (for display in the prompt), allowing Claude to understand the existing documentation structure when deciding where to place new pages.\n\n### Claude's Judgment Criteria\n\n| Needs a New Page | Does Not Need a New Page |\n|-----------------|-------------------------|\n| Implements an entirely new feature module or subsystem | Helper or utility files for existing modules |\n| Adds a significant group of API endpoints | Test files |\n| Introduces a new architectural component or design pattern | Minor bug fixes |\n| Adds significant configuration or deployment mechanisms | Changes that logically belong within an existing page's scope |\n\n\u003e Source: internal/prompt/templates/zh-TW/update_unmatched.tmpl#L41-L51\n\n---\n\n## Leaf Node Promotion\n\nWhen Claude decides to add a subpage under an existing leaf node (a documentation node with no children), the original leaf node must be converted into a parent node. The system handles this through `addItemToCatalog()`.\n\n### Promotion Logic\n\n```go\nif len(item.Children) == 0 {\n    // This is a leaf node that needs to become a parent.\n    // Add an \"overview\" child to preserve the original content.\n    (*children)[i].Children = append((*children)[i].Children, catalog.CatalogItem{\n        Title: item.Title,\n        Path:  \"overview\",\n        Order: 0,\n    })\n    *promoted = \u0026promotedLeaf{\n        OriginalPath:  currentDotPath,\n        OverviewPath:  currentDotPath + \".overview\",\n        OriginalTitle: item.Title,\n    }\n}\n```\n\n\u003e Source: internal/generator/updater.go#L402-L415\n\nAfter promotion, the existing content of the original leaf node is moved to the newly created `overview` subpage:\n\n```go\nif content, err := g.Writer.ReadPage(origItem); err == nil \u0026\u0026 content != \"\" {\n    if err := g.Writer.WritePage(overviewItem, content); err != nil {\n        g.Logger.Warn(\"Failed to move page to overview\", \"from\", promoted.OriginalPath, \"error\", err)\n    } else {\n        fmt.Printf(\"      → Page promoted: %s original content moved to %s\\n\", promoted.OriginalPath, promoted.OverviewPath)\n    }\n}\n```\n\n\u003e Source: internal/generator/updater.go#L109-L116\n\n---\n\n## Core Flow\n\n```mermaid\nsequenceDiagram\n    participant Cmd as \"cmd/update.go\"\n    participant Gen as \"Generator.Update()\"\n    participant Match as \"matchChangedFilesToDocs()\"\n    participant Writer as \"output.Writer\"\n    participant ClaudeM as \"Claude (update_matched)\"\n    participant ClaudeU as \"Claude (update_unmatched)\"\n\n    Cmd-\u003e\u003eGen: Update(ctx, scan, prevCommit, curCommit, changedFiles)\n    Gen-\u003e\u003eGen: git.ParseChangedFiles(changedFiles)\n    Gen-\u003e\u003eMatch: matchChangedFilesToDocs(files, cat)\n    Match-\u003e\u003eWriter: ReadPage(item) × N\n    Writer--\u003e\u003eMatch: page content\n    Match-\u003e\u003eMatch: strings.Contains(content, filePath)\n    Match--\u003e\u003eGen: matched[], unmatched[]\n\n    alt len(matched) \u003e 0\n        Gen-\u003e\u003eClaudeM: RenderUpdateMatched(data)\n        ClaudeM--\u003e\u003eGen: []UpdateMatchedResult (pages to regenerate)\n    end\n\n    alt len(unmatched) \u003e 0\n        Gen-\u003e\u003eClaudeU: RenderUpdateUnmatched(data)\n        ClaudeU--\u003e\u003eGen: []UpdateUnmatchedResult (pages to create)\n        Gen-\u003e\u003eGen: addItemToCatalog() × M\n    end\n\n    Gen-\u003e\u003eGen: generateSinglePage() × (matched + new)\n    Gen-\u003e\u003eWriter: SaveLastCommit(currentCommit)\n```\n\n---\n\n## Usage Examples\n\n### Running the Update Command\n\n```bash\n# Use the commit recorded from the last generate/update as the baseline\nselfmd update\n\n# Specify a starting commit\nselfmd update --since abc1234\n```\n\n### Commit Baseline Selection Logic\n\n```go\npreviousCommit := sinceCommit\nif previousCommit == \"\" {\n    // Try reading saved commit from last generate/update\n    saved, readErr := gen.Writer.ReadLastCommit()\n    if readErr == nil \u0026\u0026 saved != \"\" {\n        previousCommit = saved\n    } else {\n        // Fallback to merge-base\n        base, err := git.GetMergeBase(rootDir, cfg.Git.BaseBranch)\n        // ...\n        previousCommit = base\n    }\n}\n```\n\n\u003e Source: cmd/update.go#L68-L82\n\nPriority order: `--since` flag → commit saved from last generate/update → merge-base\n\n### Changed File Filtering\n\n```go\nchangedFiles = git.FilterChangedFiles(changedFiles, cfg.Targets.Include, cfg.Targets.Exclude)\n```\n\n\u003e Source: cmd/update.go#L94\n\n`FilterChangedFiles()` uses doublestar glob patterns to apply include/exclude filtering on the git diff output, ensuring only target files specified in the configuration trigger documentation updates.\n\n---\n\n## Related Links\n\n- [Git Diff Change Detection](../change-detection/index.md)\n- [Git Integration and Incremental Updates](../index.md)\n- [Incremental Updates](../../core-modules/incremental-update/index.md)\n- [Documentation Generation Pipeline](../../core-modules/generator/index.md)\n- [Git Integration Configuration](../../configuration/git-config/index.md)\n- [Prompt Template Engine](../../core-modules/prompt-engine/index.md)\n\n---\n\n## Reference Files\n\n| File Path | Description |\n|-----------|-------------|\n| `internal/generator/updater.go` | Core logic for affected page determination (`matchChangedFilesToDocs`, `determineMatchedUpdates`, `determineUnmatchedPages`, `addItemToCatalog`) |\n| `internal/git/git.go` | Git operation wrappers, including `ParseChangedFiles` and `FilterChangedFiles` |\n| `cmd/update.go` | `selfmd update` command implementation, responsible for commit baseline selection and calling `Generator.Update()` |\n| `internal/catalog/catalog.go` | Data structure definitions for `Catalog`, `FlatItem`, and `CatalogItem` |\n| `internal/prompt/engine.go` | `UpdateMatchedPromptData`, `UpdateUnmatchedPromptData` data structures and `RenderUpdateMatched`, `RenderUpdateUnmatched` functions |\n| `internal/prompt/templates/zh-TW/update_matched.tmpl` | Claude prompt template for determining \"whether matched pages need regeneration\" |\n| `internal/prompt/templates/zh-TW/update_unmatched.tmpl` | Claude prompt template for determining \"whether unmatched files need new pages\" |","en-US/git-integration/change-detection/index.md":"# Git Diff Change Detection\n\nThe `internal/git` package provides low-level functionality for interacting with the Git version control system. It is responsible for detecting file changes between two commits, and for parsing and filtering raw `git diff` output into structured data for use by the incremental update workflow.\n\n## Overview\n\nWhen `selfmd update` is executed, the system needs to know which source files have changed since the last documentation generation. The `internal/git` package handles this entirely:\n\n- **Detect Git environment**: Confirm whether the current directory is a valid Git repository\n- **Compare commit ranges**: Retrieve the list of changed files between two commits\n- **Parse raw output**: Convert the text output of `git diff --name-status` into a structured `ChangedFile` list\n- **Apply filter rules**: Filter out irrelevant files based on the `targets.include` and `targets.exclude` glob patterns from the config file\n- **Provide commit queries**: Retrieve version information such as the HEAD commit hash and merge base\n\nThis package is intentionally kept pure — it only wraps Git CLI calls and contains no documentation generation logic. All complex logic for determining which documentation pages are affected is handled by the upper-layer `generator` package (`updater.go`).\n\n---\n\n## Architecture\n\n```mermaid\nflowchart TD\n    UpdateCmd[\"cmd/update.go\\nrunUpdate()\"]\n    GitPkg[\"internal/git/git.go\"]\n    IsGitRepo[\"IsGitRepo()\"]\n    GetCurrentCommit[\"GetCurrentCommit()\"]\n    GetMergeBase[\"GetMergeBase()\"]\n    GetChangedFiles[\"GetChangedFiles()\"]\n    FilterChangedFiles[\"FilterChangedFiles()\"]\n    ParseChangedFiles[\"ParseChangedFiles()\"]\n    Config[\"GitConfig\\nTargetsConfig\"]\n    Updater[\"generator/updater.go\\nGenerator.Update()\"]\n    runGit[\"runGit() — internal helper\"]\n\n    UpdateCmd --\u003e|\"1. Validate Git environment\"| IsGitRepo\n    UpdateCmd --\u003e|\"2. Get HEAD\"| GetCurrentCommit\n    UpdateCmd --\u003e|\"3a. Get merge-base (when no saved commit)\"| GetMergeBase\n    UpdateCmd --\u003e|\"4. Get changed files\"| GetChangedFiles\n    UpdateCmd --\u003e|\"5. Apply filter rules\"| FilterChangedFiles\n    Config --\u003e|\"include / exclude patterns\"| FilterChangedFiles\n    UpdateCmd --\u003e|\"6. Pass filtered raw text\"| Updater\n    Updater --\u003e|\"7. Parse into structured list\"| ParseChangedFiles\n\n    IsGitRepo --\u003e runGit\n    GetCurrentCommit --\u003e runGit\n    GetMergeBase --\u003e runGit\n    GetChangedFiles --\u003e runGit\n    runGit --\u003e|\"exec.Command(git...)\"| GitCLI[\"git CLI\"]\n```\n\n---\n\n## Core Data Structures\n\n### `ChangedFile`\n\nRepresents a single file change record from `git diff --name-status` output.\n\n```go\n// ChangedFile represents a single file from git diff --name-status output.\ntype ChangedFile struct {\n\tStatus string // \"M\", \"A\", \"D\", \"R\"\n\tPath   string\n}\n```\n\n\u003e Source: internal/git/git.go#L47-L51\n\n| Field | Description |\n|-------|-------------|\n| `Status` | Change status. `M` = Modified, `A` = Added, `D` = Deleted, `R` = Renamed |\n| `Path` | File path relative to the working directory; for renames, this is the **destination path** |\n\n---\n\n## Public Function Reference\n\n### `IsGitRepo(dir string) bool`\n\nConfirms whether the specified directory is inside a Git repository. Runs `git rev-parse --is-inside-work-tree` and uses the command's success or failure as the result.\n\n```go\nfunc IsGitRepo(dir string) bool {\n\tcmd := exec.Command(\"git\", \"rev-parse\", \"--is-inside-work-tree\")\n\tcmd.Dir = dir\n\terr := cmd.Run()\n\treturn err == nil\n}\n```\n\n\u003e Source: internal/git/git.go#L13-L18\n\n---\n\n### `GetCurrentCommit(dir string) (string, error)`\n\nReturns the full commit hash (40 hexadecimal characters) of the current `HEAD`.\n\n```go\nfunc GetCurrentCommit(dir string) (string, error) {\n\treturn runGit(dir, \"rev-parse\", \"HEAD\")\n}\n```\n\n\u003e Source: internal/git/git.go#L21-L23\n\n---\n\n### `GetMergeBase(dir, baseBranch string) (string, error)`\n\nFinds the most recent common ancestor commit between the current branch and the specified base branch (`baseBranch`). Used as a fallback starting point for comparison when no previously saved commit is available.\n\n```go\nfunc GetMergeBase(dir, baseBranch string) (string, error) {\n\treturn runGit(dir, \"merge-base\", baseBranch, \"HEAD\")\n}\n```\n\n\u003e Source: internal/git/git.go#L26-L28\n\n---\n\n### `GetChangedFiles(dir, fromCommit, toCommit string) (string, error)`\n\nRetrieves the raw text output of all changed files between two commits (`git diff --relative --name-status fromCommit..toCommit`).\n\nThe `--relative` flag ensures paths are relative to the working directory rather than the Git repository root, which is especially important in subdirectory projects.\n\n```go\nfunc GetChangedFiles(dir, fromCommit, toCommit string) (string, error) {\n\treturn runGit(dir, \"diff\", \"--relative\", \"--name-status\", fromCommit+\"..\"+toCommit)\n}\n```\n\n\u003e Source: internal/git/git.go#L32-L34\n\n**Example output:**\n\n```\nM\tinternal/git/git.go\nA\tinternal/scanner/scanner.go\nD\tcmd/old.go\nR100\tcmd/old_name.go\tcmd/new_name.go\n```\n\n---\n\n### `GetChangedFilesSince(dir, sinceCommit string) (string, error)`\n\nRetrieves all changes from the specified commit to `HEAD`. A convenience wrapper around `GetChangedFiles` that fixes `HEAD` as the end point.\n\n```go\nfunc GetChangedFilesSince(dir, sinceCommit string) (string, error) {\n\treturn runGit(dir, \"diff\", \"--relative\", \"--name-status\", sinceCommit+\"..HEAD\")\n}\n```\n\n\u003e Source: internal/git/git.go#L38-L40\n\n---\n\n### `ParseChangedFiles(changedFiles string) []ChangedFile`\n\nParses the raw text output of `git diff --name-status` into a structured `[]ChangedFile` list.\n\n```go\nfunc ParseChangedFiles(changedFiles string) []ChangedFile {\n\tvar result []ChangedFile\n\tfor _, line := range strings.Split(changedFiles, \"\\n\") {\n\t\tline = strings.TrimSpace(line)\n\t\tif line == \"\" {\n\t\t\tcontinue\n\t\t}\n\t\tparts := strings.SplitN(line, \"\\t\", 3)\n\t\tif len(parts) \u003c 2 {\n\t\t\tcontinue\n\t\t}\n\t\tstatus := string(parts[0][0]) // \"M\", \"A\", \"D\", or \"R\" (R100 → R)\n\t\tpath := parts[len(parts)-1]   // for renames, use destination path\n\t\tresult = append(result, ChangedFile{Status: status, Path: path})\n\t}\n\treturn result\n}\n```\n\n\u003e Source: internal/git/git.go#L54-L70\n\n**Parsing rules:**\n\n- Each line is tab (`\\t`) delimited and split into at most 3 parts (to handle the rename format `R100\\told\\tnew`)\n- The status code uses only the first character (`R100` → `R`)\n- The path uses the last field (the destination path for renames)\n\n---\n\n### `FilterChangedFiles(changedFiles string, includes, excludes []string) string`\n\nFilters the raw text output of `git diff --name-status` according to the glob patterns defined in `targets.include` and `targets.exclude`, returning the matching raw text in the same format.\n\n```go\nfunc FilterChangedFiles(changedFiles string, includes, excludes []string) string {\n\tlines := strings.Split(changedFiles, \"\\n\")\n\tvar filtered []string\n\n\tfor _, line := range lines {\n\t\t// ...\n\t\t// Check excludes\n\t\texcluded := false\n\t\tfor _, pattern := range excludes {\n\t\t\tif matched, _ := doublestar.Match(pattern, filePath); matched {\n\t\t\t\texcluded = true\n\t\t\t\tbreak\n\t\t\t}\n\t\t}\n\t\t// Check includes (if configured)\n\t\tif len(includes) \u003e 0 {\n\t\t\tincluded := false\n\t\t\tfor _, pattern := range includes {\n\t\t\t\tif matched, _ := doublestar.Match(pattern, filePath); matched {\n\t\t\t\t\tincluded = true\n\t\t\t\t\tbreak\n\t\t\t\t}\n\t\t\t}\n\t\t\tif !included {\n\t\t\t\tcontinue\n\t\t\t}\n\t\t}\n\t\tfiltered = append(filtered, line)\n\t}\n\treturn strings.Join(filtered, \"\\n\")\n}\n```\n\n\u003e Source: internal/git/git.go#L73-L122\n\n**Filter priority:**\n\n1. `excludes` are applied first: a file matching any exclude pattern is excluded\n2. `includes` are applied next: if configured, a file not matching any include pattern is excluded\n3. If `includes` is empty, no restriction is applied (all non-excluded files are allowed)\n\nGlob pattern matching uses the [`doublestar`](https://github.com/bmatcuk/doublestar) package, which supports `**` double-star wildcards.\n\n---\n\n## Core Workflow\n\nThe following is the complete operational sequence of Git change detection when `selfmd update` runs:\n\n```mermaid\nsequenceDiagram\n    participant User as User\n    participant UpdateCmd as cmd/update.go\n    participant Git as internal/git/git.go\n    participant Writer as output/writer.go\n    participant Updater as generator/updater.go\n\n    User-\u003e\u003eUpdateCmd: selfmd update [--since \u003ccommit\u003e]\n    UpdateCmd-\u003e\u003eGit: IsGitRepo(rootDir)\n    Git--\u003e\u003eUpdateCmd: true / false\n\n    alt Not a Git repository\n        UpdateCmd--\u003e\u003eUser: Error: current directory is not a git repository\n    end\n\n    UpdateCmd-\u003e\u003eWriter: ReadLastCommit()\n    Writer--\u003e\u003eUpdateCmd: previousCommit (or error)\n\n    alt No saved commit\n        UpdateCmd-\u003e\u003eGit: GetMergeBase(rootDir, baseBranch)\n        Git--\u003e\u003eUpdateCmd: mergeBaseCommit\n    end\n\n    UpdateCmd-\u003e\u003eGit: GetCurrentCommit(rootDir)\n    Git--\u003e\u003eUpdateCmd: currentCommit (HEAD hash)\n\n    UpdateCmd-\u003e\u003eGit: GetChangedFiles(rootDir, previousCommit, currentCommit)\n    Git--\u003e\u003eUpdateCmd: rawDiff (git diff --name-status output)\n\n    UpdateCmd-\u003e\u003eGit: FilterChangedFiles(rawDiff, includes, excludes)\n    Git--\u003e\u003eUpdateCmd: filteredDiff\n\n    UpdateCmd-\u003e\u003eUpdater: Update(ctx, scan, previousCommit, currentCommit, filteredDiff)\n    Updater-\u003e\u003eGit: ParseChangedFiles(filteredDiff)\n    Git--\u003e\u003eUpdater: []ChangedFile\n\n    Updater-\u003e\u003eUpdater: matchChangedFilesToDocs()\n    Note over Updater: Determine affected pages (see Affected Page Detection Logic)\n\n    Updater-\u003e\u003eWriter: SaveLastCommit(currentCommit)\n```\n\n---\n\n## Comparison Starting Point Selection Logic\n\nThe incremental comparison starting point for `selfmd update` is determined by the following priority order:\n\n```mermaid\nflowchart TD\n    A[\"Run selfmd update\"] --\u003e B{\"--since flag present?\"}\n    B --\u003e|\"Yes\"| E[\"Use specified commit hash\"]\n    B --\u003e|\"No\"| C{\"ReadLastCommit() succeeded?\"}\n    C --\u003e|\"Yes\"| F[\"Use commit saved by last generate/update\"]\n    C --\u003e|\"No\"| D[\"GetMergeBase(baseBranch, HEAD)\"]\n    D --\u003e G[\"Use merge base commit\"]\n    E --\u003e H[\"GetChangedFiles(previousCommit, currentCommit)\"]\n    F --\u003e H\n    G --\u003e H\n```\n\n| Scenario | Source of comparison starting point |\n|----------|-------------------------------------|\n| First update, `generate` has been run before | Commit saved in `.doc-build/.last-commit` |\n| Using the `--since` flag | User-specified commit hash |\n| No saved record (fallback) | `git merge-base \u003cbaseBranch\u003e HEAD` |\n\n---\n\n## Configuration Parameters\n\nThe behavior of Git change detection is controlled by the following sections in `selfmd.yaml`:\n\n```yaml\ngit:\n  enabled: true\n  base_branch: main   # Base branch name for GetMergeBase()\n\ntargets:\n  include:\n    - \"src/**\"\n    - \"internal/**\"\n  exclude:\n    - \"vendor/**\"\n    - \"**/*.pb.go\"\n    - \".doc-build/**\"\n```\n\nCorresponding Go struct:\n\n```go\ntype GitConfig struct {\n\tEnabled    bool   `yaml:\"enabled\"`\n\tBaseBranch string `yaml:\"base_branch\"`\n}\n```\n\n\u003e Source: internal/config/config.go#L91-L94\n\n---\n\n## Usage Example\n\nThe following is a complete excerpt from `cmd/update.go` showing the full Git detection workflow call:\n\n```go\nif !git.IsGitRepo(rootDir) {\n    return fmt.Errorf(\"當前目錄不是 git 倉庫，無法執行增量更新\")\n}\n\n// Determine comparison commit\npreviousCommit := sinceCommit\nif previousCommit == \"\" {\n    saved, readErr := gen.Writer.ReadLastCommit()\n    if readErr == nil \u0026\u0026 saved != \"\" {\n        previousCommit = saved\n    } else {\n        base, err := git.GetMergeBase(rootDir, cfg.Git.BaseBranch)\n        if err != nil {\n            return fmt.Errorf(\"無法取得基準 commit: %w\\n提示：先執行 selfmd generate 或使用 --since 指定 commit\", err)\n        }\n        previousCommit = base\n    }\n}\n\ncurrentCommit, err := git.GetCurrentCommit(rootDir)\n// ...\n\nchangedFiles, err := git.GetChangedFiles(rootDir, previousCommit, currentCommit)\n// ...\n\nchangedFiles = git.FilterChangedFiles(changedFiles, cfg.Targets.Include, cfg.Targets.Exclude)\n```\n\n\u003e Source: cmd/update.go#L49-L99\n\n---\n\n## Related Links\n\n- [Git Integration and Incremental Updates](../index.md)\n- [Affected Page Detection Logic](../affected-pages/index.md)\n- [Incremental Updates](../../core-modules/incremental-update/index.md)\n- [selfmd update Command](../../cli/cmd-update/index.md)\n- [Git Integration Configuration](../../configuration/git-config/index.md)\n\n---\n\n## Reference Files\n\n| File Path | Description |\n|-----------|-------------|\n| `internal/git/git.go` | Complete implementation of the Git package: IsGitRepo, GetCurrentCommit, GetMergeBase, GetChangedFiles, GetChangedFilesSince, ParseChangedFiles, FilterChangedFiles, runGit |\n| `cmd/update.go` | Implementation of the `selfmd update` command, demonstrating the complete Git package call flow |\n| `internal/config/config.go` | `GitConfig` and `TargetsConfig` struct definitions; configuration parameters that control change detection behavior |\n| `internal/generator/updater.go` | Consumer of `Generator.Update()` and `ParseChangedFiles()`; responsible for converting the changed file list into affected documentation pages |","en-US/git-integration/index.md":"# Git Integration and Incremental Updates\n\nThis section contains the following:\n\n- [Git Diff Change Detection](change-detection/index.md)\n- [Affected Page Determination Logic](affected-pages/index.md)\n","en-US/i18n/index.md":"# Multi-language Support\n\nThis section contains the following:\n\n- [Supported Languages and Templates](supported-languages/index.md)\n- [Translation Workflow](translation-workflow/index.md)\n","en-US/i18n/supported-languages/index.md":"# Supported Languages and Templates\n\nselfmd supports multilingual documentation generation through a two-layer language architecture: **output language** (11 languages) determines the language of the documentation content, and **template language** (2 languages) determines the language used in Prompt instructions.\n\n## Overview\n\nselfmd's multilingual support operates at two levels:\n\n- **Output Language**: The language in which the final documentation is presented. Configured via `output.language` (primary language) and `output.secondary_languages` (list of secondary languages) in `selfmd.yaml`. The system currently defines 11 known languages.\n- **Template Language**: The language used in Prompt instructions received by the Claude CLI. Only `zh-TW` and `en-US` have built-in template folders; all other languages automatically fall back to the `en-US` template and inject explicit language output instructions into the Prompt via the **LanguageOverride** mechanism.\n\nThis design allows selfmd to support far more output languages than the number of available templates, without requiring a complete set of Prompt templates for every language.\n\n## Architecture\n\n```mermaid\nflowchart TD\n    Config[\"OutputConfig\\n(output.language)\"]\n    GetEffective[\"GetEffectiveTemplateLang()\"]\n    NeedsOverride[\"NeedsLanguageOverride()\"]\n    SupportedTemplateLangs[\"SupportedTemplateLangs\\n[zh-TW, en-US]\"]\n    TemplatezHTW[\"templates/zh-TW/*.tmpl\"]\n    TemplateENUS[\"templates/en-US/*.tmpl\"]\n    SharedTemplate[\"templates/translate.tmpl\\n(shared template)\"]\n    Engine[\"prompt.Engine\\n.templates\\n.sharedTemplates\"]\n    LangOverridePrompt[\"Inject language output instruction into Prompt\"]\n    ClaudeRunner[\"claude.Runner\"]\n    KnownLanguages[\"KnownLanguages\\n(11-language lookup table)\"]\n    GetLangNativeName[\"GetLangNativeName()\"]\n\n    Config --\u003e|set primary language| GetEffective\n    GetEffective --\u003e|query| SupportedTemplateLangs\n    SupportedTemplateLangs --\u003e|matches zh-TW| TemplatezHTW\n    SupportedTemplateLangs --\u003e|matches en-US| TemplateENUS\n    SupportedTemplateLangs --\u003e|no match, fall back| TemplateENUS\n    TemplatezHTW --\u003e Engine\n    TemplateENUS --\u003e Engine\n    SharedTemplate --\u003e Engine\n    Config --\u003e NeedsOverride\n    NeedsOverride --\u003e|true: language override needed| LangOverridePrompt\n    LangOverridePrompt --\u003e Engine\n    Engine --\u003e ClaudeRunner\n    KnownLanguages --\u003e GetLangNativeName\n    GetLangNativeName --\u003e|provide native name| Engine\n```\n\n## Known Language List\n\nThe system defines 11 language codes and their native names in the `KnownLanguages` lookup table:\n\n```go\nvar KnownLanguages = map[string]string{\n    \"zh-TW\": \"繁體中文\",\n    \"zh-CN\": \"简体中文\",\n    \"en-US\": \"English\",\n    \"ja-JP\": \"日本語\",\n    \"ko-KR\": \"한국어\",\n    \"fr-FR\": \"Français\",\n    \"de-DE\": \"Deutsch\",\n    \"es-ES\": \"Español\",\n    \"pt-BR\": \"Português\",\n    \"th-TH\": \"ไทย\",\n    \"vi-VN\": \"Tiếng Việt\",\n}\n```\n\n\u003e Source: internal/config/config.go#L39-L51\n\n| Language Code | Native Name | Built-in Template | Notes |\n|--------------|-------------|-------------------|-------|\n| `zh-TW` | 繁體中文 | ✅ | Default primary language |\n| `en-US` | English | ✅ | Template fallback language |\n| `zh-CN` | 简体中文 | ❌ | Uses en-US template + LanguageOverride |\n| `ja-JP` | 日本語 | ❌ | Uses en-US template + LanguageOverride |\n| `ko-KR` | 한국어 | ❌ | Uses en-US template + LanguageOverride |\n| `fr-FR` | Français | ❌ | Uses en-US template + LanguageOverride |\n| `de-DE` | Deutsch | ❌ | Uses en-US template + LanguageOverride |\n| `es-ES` | Español | ❌ | Uses en-US template + LanguageOverride |\n| `pt-BR` | Português | ❌ | Uses en-US template + LanguageOverride |\n| `th-TH` | ไทย | ❌ | Uses en-US template + LanguageOverride |\n| `vi-VN` | Tiếng Việt | ❌ | Uses en-US template + LanguageOverride |\n\n## Built-in Template Folders\n\nCurrently only `zh-TW` and `en-US` have complete template folders:\n\n```go\nvar SupportedTemplateLangs = []string{\"zh-TW\", \"en-US\"}\n```\n\n\u003e Source: internal/config/config.go#L54\n\nEach language folder contains the following template files:\n\n```\ninternal/prompt/templates/\n├── zh-TW/\n│   ├── catalog.tmpl          # Documentation catalog generation Prompt\n│   ├── content.tmpl          # Content page generation Prompt\n│   ├── updater.tmpl          # Incremental update Prompt (legacy)\n│   ├── update_matched.tmpl   # Affected page detection Prompt\n│   └── update_unmatched.tmpl # New page addition detection Prompt\n├── en-US/\n│   ├── catalog.tmpl\n│   ├── content.tmpl\n│   ├── updater.tmpl\n│   ├── update_matched.tmpl\n│   └── update_unmatched.tmpl\n└── translate.tmpl            # Translation Prompt (shared across all languages)\n```\n\n### Template Purpose Reference\n\n| Template File | Corresponding Method | Purpose |\n|--------------|---------------------|---------|\n| `catalog.tmpl` | `Engine.RenderCatalog()` | Instructs Claude to analyze the project and generate the documentation catalog structure |\n| `content.tmpl` | `Engine.RenderContent()` | Instructs Claude to write a Wiki page for a specific catalog entry |\n| `updater.tmpl` | `Engine.RenderUpdater()` | Incremental update (legacy, kept for reference) |\n| `update_matched.tmpl` | `Engine.RenderUpdateMatched()` | Determines which existing pages need to be regenerated due to code changes |\n| `update_unmatched.tmpl` | `Engine.RenderUpdateUnmatched()` | Determines whether changed files not covered by existing documentation need new pages |\n| `translate.tmpl` | `Engine.RenderTranslate()` | Translates documentation pages (shared across all languages, regardless of template language) |\n\n### Shared Template: translate.tmpl\n\nThe translation template is the only shared template (not tied to any language folder). It is written in English and dynamically injects source and target language information via `TranslatePromptData`:\n\n```go\ntype TranslatePromptData struct {\n    SourceLanguage     string // e.g., \"zh-TW\"\n    SourceLanguageName string // e.g., \"繁體中文\"\n    TargetLanguage     string // e.g., \"en-US\"\n    TargetLanguageName string // e.g., \"English\"\n    SourceContent      string // full Markdown content to translate\n}\n```\n\n\u003e Source: internal/prompt/engine.go#L97-L104\n\n## Template Language Selection Mechanism\n\n### GetEffectiveTemplateLang()\n\nWhen the system initializes `prompt.Engine`, this method is called to determine which language folder's templates to load. If the configured primary language has a corresponding template, that language is used; otherwise it falls back to `en-US`:\n\n```go\nfunc (o *OutputConfig) GetEffectiveTemplateLang() string {\n    for _, lang := range SupportedTemplateLangs {\n        if o.Language == lang {\n            return o.Language\n        }\n    }\n    return \"en-US\"\n}\n```\n\n\u003e Source: internal/config/config.go#L58-L65\n\n### NeedsLanguageOverride()\n\nWhen the template language (`en-US`) does not match the actual configured output language (e.g., `ja-JP`), this method returns `true` and the system injects explicit language output instructions into the Prompt:\n\n```go\nfunc (o *OutputConfig) NeedsLanguageOverride() bool {\n    return o.GetEffectiveTemplateLang() != o.Language\n}\n```\n\n\u003e Source: internal/config/config.go#L69-L71\n\n### Effect of LanguageOverride in the Prompt\n\nUsing `content.tmpl` (en-US version) as an example, when `LanguageOverride` is `true`, the template appends a forced language instruction to the project information section:\n\n```\n{{- if .LanguageOverride}}\n- **Document Language**: {{.LanguageOverrideName}} ({{.Language}})\n- **IMPORTANT**: All documentation content MUST be written in **{{.LanguageOverrideName}}** ({{.Language}}).\n{{- else}}\n- **Document Language**: {{.LanguageName}} ({{.Language}})\n{{- end}}\n```\n\n\u003e Source: internal/prompt/templates/en-US/content.tmpl#L20-L27\n\n## Navigation Page Localization\n\nIn addition to Prompt templates, when the system generates navigation pages (home page, sidebar, category index), it displays UI strings corresponding to the language. Currently `UIStrings` directly supports `zh-TW` and `en-US`; all other languages fall back to `en-US`:\n\n```go\nvar UIStrings = map[string]map[string]string{\n    \"zh-TW\": {\n        \"techDocs\":        \"技術文件\",\n        \"catalog\":         \"目錄\",\n        \"home\":            \"首頁\",\n        \"sectionContains\": \"本章節包含以下內容：\",\n        \"autoGenerated\":   \"本文件由 [selfmd](https://github.com/monkenwu/selfmd) 自動產生\",\n    },\n    \"en-US\": {\n        \"techDocs\":        \"Technical Documentation\",\n        \"catalog\":         \"Table of Contents\",\n        \"home\":            \"Home\",\n        \"sectionContains\": \"This section contains the following:\",\n        \"autoGenerated\":   \"This documentation was automatically generated by [selfmd](https://github.com/monkenwu/selfmd)\",\n    },\n}\n```\n\n\u003e Source: internal/output/navigation.go#L12-L27\n\n## Core Flow\n\n```mermaid\nsequenceDiagram\n    participant CFG as OutputConfig\n    participant GEN as NewGenerator\n    participant ENG as prompt.Engine\n    participant RUNNER as claude.Runner\n\n    GEN-\u003e\u003eCFG: GetEffectiveTemplateLang()\n    CFG--\u003e\u003eGEN: templateLang (\"zh-TW\" or \"en-US\")\n    GEN-\u003e\u003eENG: NewEngine(templateLang)\n    ENG-\u003e\u003eENG: Load templates/{templateLang}/*.tmpl\n    ENG-\u003e\u003eENG: Load templates/translate.tmpl (shared)\n\n    Note over GEN,ENG: During documentation generation\n\n    GEN-\u003e\u003eCFG: NeedsLanguageOverride()\n    CFG--\u003e\u003eGEN: true/false\n    alt Language override required\n        GEN-\u003e\u003eENG: RenderContent(data with LanguageOverride=true)\n    else No override needed\n        GEN-\u003e\u003eENG: RenderContent(data with LanguageOverride=false)\n    end\n    ENG--\u003e\u003eGEN: Rendered Prompt\n    GEN-\u003e\u003eRUNNER: RunWithRetry(prompt)\n    RUNNER--\u003e\u003eGEN: Documentation content in target language\n```\n\n## Usage Examples\n\n### Setting Primary Language to Japanese (No Built-in Template)\n\n```yaml\noutput:\n  language: ja-JP\n  secondary_languages:\n    - en-US\n    - zh-TW\n```\n\nSystem behavior:\n1. `GetEffectiveTemplateLang()` returns `\"en-US\"` (fallback)\n2. `NeedsLanguageOverride()` returns `true`\n3. Injected into Prompt: \"All documentation content must be written in 日本語 (ja-JP)\"\n4. `GetLangNativeName(\"ja-JP\")` returns `\"日本語\"` for use in the Prompt\n\n### Getting a Language's Native Name\n\n```go\nfunc GetLangNativeName(code string) string {\n    if name, ok := KnownLanguages[code]; ok {\n        return name\n    }\n    return code\n}\n```\n\n\u003e Source: internal/config/config.go#L75-L80\n\nIf an unknown language code (e.g., `\"ru-RU\"`) is passed in, the function returns the code itself (`\"ru-RU\"`) without error.\n\n### Translation Command Usage Example\n\n```go\ndata := prompt.TranslatePromptData{\n    SourceLanguage:     sourceLang,\n    SourceLanguageName: sourceLangName,\n    TargetLanguage:     targetLang,\n    TargetLanguageName: targetLangName,\n    SourceContent:      sourceContent,\n}\nrendered, err := g.Engine.RenderTranslate(data)\n```\n\n\u003e Source: internal/generator/translate_phase.go#L186-L194\n\n## Related Links\n\n- [Multilingual Support (Overview)](../index.md)\n- [Translation Workflow](../translation-workflow/index.md)\n- [Output and Multilingual Configuration](../../configuration/output-language/index.md)\n- [selfmd translate Command](../../cli/cmd-translate/index.md)\n- [Prompt Template Engine](../../core-modules/prompt-engine/index.md)\n- [Translation Phase](../../core-modules/generator/translate-phase/index.md)\n\n## Reference Files\n\n| File Path | Description |\n|-----------|-------------|\n| `internal/config/config.go` | Definitions for `KnownLanguages`, `SupportedTemplateLangs`, `GetEffectiveTemplateLang()`, `NeedsLanguageOverride()`, and `GetLangNativeName()` |\n| `internal/prompt/engine.go` | `Engine` struct, `NewEngine()`, all `Render*()` methods, and `TranslatePromptData` definition |\n| `internal/prompt/templates/zh-TW/catalog.tmpl` | Traditional Chinese catalog generation Prompt template |\n| `internal/prompt/templates/zh-TW/content.tmpl` | Traditional Chinese content page generation Prompt template |\n| `internal/prompt/templates/zh-TW/update_matched.tmpl` | Traditional Chinese affected page detection Prompt template |\n| `internal/prompt/templates/zh-TW/update_unmatched.tmpl` | Traditional Chinese new page addition detection Prompt template |\n| `internal/prompt/templates/zh-TW/updater.tmpl` | Traditional Chinese incremental update Prompt template (legacy) |\n| `internal/prompt/templates/en-US/catalog.tmpl` | English catalog generation Prompt template |\n| `internal/prompt/templates/en-US/content.tmpl` | English content page generation Prompt template (includes LanguageOverride logic) |\n| `internal/prompt/templates/translate.tmpl` | Shared translation Prompt template (all languages) |\n| `internal/output/navigation.go` | `UIStrings` navigation page localization strings and `getUIStrings()` fallback logic |\n| `internal/generator/pipeline.go` | `GetEffectiveTemplateLang()` call within `NewGenerator()` |\n| `internal/generator/translate_phase.go` | Translation pipeline, `TranslateOptions`, and `translatePages()` |\n| `cmd/translate.go` | `selfmd translate` command implementation and target language validation logic |","en-US/i18n/translation-workflow/index.md":"# Translation Workflow\n\nThe `selfmd translate` command takes the primary language output files as the source of truth, automatically translates them into one or more secondary languages via the Claude CLI, and writes the results into separate language subdirectories.\n\n## Overview\n\nThe translation workflow is the core mechanism for selfmd's multilingual support. After configuring `output.secondary_languages` in `selfmd.yaml`, running `selfmd translate` will translate all generated primary language documents into every configured secondary language.\n\n**Key Concepts:**\n\n- **Primary Language**: Configured via `output.language`, this is the original language of all content pages and the **source language** for translation.\n- **Secondary Languages**: The list of languages configured in `output.secondary_languages`. Each language corresponds to a separate output subdirectory.\n- **Shared Translation Template**: Translation uses `translate.tmpl`, a shared template independent of language — not a language-specific template folder.\n- **Incremental Skipping**: By default, existing translated pages are skipped. Use `--force` to force re-translation.\n\nThe translation workflow is decoupled from the primary document generation workflow — `selfmd generate` must complete before `selfmd translate` can be run.\n\n## Architecture\n\n```mermaid\nflowchart TD\n    CLI[\"cmd/translate.go\\n(translateCmd)\"]\n    Config[\"config.Config\\noutput.secondary_languages\"]\n    Generator[\"generator.Generator\\nTranslate()\"]\n    TranslatePages[\"translatePages()\\nParallel leaf page translation\"]\n    Engine[\"prompt.Engine\\nRenderTranslate()\"]\n    Runner[\"claude.Runner\\nRunWithRetry()\"]\n    Template[\"translate.tmpl\\nShared translation template\"]\n    SourceWriter[\"output.Writer\\nRead primary language pages\"]\n    LangWriter[\"output.Writer.ForLanguage()\\nWrite to language subdirectory\"]\n    CatalogBuild[\"buildTranslatedCatalog()\\nRebuild translated catalog\"]\n    NavGen[\"output.GenerateIndex()\\noutput.GenerateSidebar()\"]\n\n    CLI --\u003e|\"Validate languages, create Generator\"| Generator\n    Config --\u003e|\"targetLangs, concurrency\"| CLI\n    Generator --\u003e|\"Read _catalog.json\"| SourceWriter\n    Generator --\u003e TranslatePages\n    TranslatePages --\u003e|\"TranslatePromptData\"| Engine\n    Engine --\u003e|\"Render translate.tmpl\"| Template\n    Engine --\u003e|\"rendered prompt\"| Runner\n    Runner --\u003e|\"claude -p --output-format json\"| Runner\n    Runner --\u003e|\"RunResult.Content\"| TranslatePages\n    SourceWriter --\u003e|\"ReadPage(item)\"| TranslatePages\n    TranslatePages --\u003e|\"WritePage(item, content)\"| LangWriter\n    TranslatePages --\u003e|\"translatedTitles map\"| CatalogBuild\n    CatalogBuild --\u003e|\"Translated catalog\"| NavGen\n    NavGen --\u003e|\"index.md, _sidebar.md\"| LangWriter\n```\n\n## Configuration\n\n### Relevant Fields in selfmd.yaml\n\n```yaml\noutput:\n  language: \"zh-TW\"               # Primary language (translation source)\n  secondary_languages:             # Target languages for translation\n    - \"en-US\"\n    - \"ja-JP\"\n```\n\n\u003e Source: `internal/config/config.go#L31-L36`\n\n### Supported Language Codes\n\n`config.KnownLanguages` defines the mapping of known language codes to their native names:\n\n```go\nvar KnownLanguages = map[string]string{\n    \"zh-TW\": \"繁體中文\",\n    \"zh-CN\": \"简体中文\",\n    \"en-US\": \"English\",\n    \"ja-JP\": \"日本語\",\n    \"ko-KR\": \"한국어\",\n    \"fr-FR\": \"Français\",\n    \"de-DE\": \"Deutsch\",\n    \"es-ES\": \"Español\",\n    \"pt-BR\": \"Português\",\n    \"th-TH\": \"ไทย\",\n    \"vi-VN\": \"Tiếng Việt\",\n}\n```\n\n\u003e Source: `internal/config/config.go#L39-L51`\n\nLanguage codes not in the table above can still be used — `GetLangNativeName()` returns the language code itself when no matching native name is found.\n\n### Prompt Template Language Fallback\n\nThe translation prompt uses the **shared template** `translate.tmpl`, which is unaffected by the `output.language` template language fallback logic. This template is written in English and explicitly specifies both the source and target languages:\n\n```go\n// SupportedTemplateLangs lists language codes that have built-in prompt template folders.\nvar SupportedTemplateLangs = []string{\"zh-TW\", \"en-US\"}\n```\n\n\u003e Source: `internal/config/config.go#L54`\n\n## CLI Command\n\n```\nselfmd translate [flags]\n```\n\n| Flag | Description |\n|------|-------------|\n| `--lang` | Translate only the specified language (can be used multiple times; default: all secondary languages) |\n| `--force` | Force re-translation of existing files |\n| `--concurrency` | Concurrency level (overrides the `claude.max_concurrent` setting) |\n\n`cmd/translate.go` validates that specified languages exist in the `secondary_languages` list before starting translation:\n\n```go\nfor _, l := range translateLangs {\n    if !validLangs[l] {\n        return fmt.Errorf(\"語言 %s 不在 secondary_languages 列表中（可用：%s）\",\n            l, strings.Join(cfg.Output.SecondaryLanguages, \", \"))\n    }\n}\n```\n\n\u003e Source: `cmd/translate.go#L61-L65`\n\n## Core Workflow\n\n### Translation Pipeline Overview\n\n```mermaid\nsequenceDiagram\n    participant CLI as translateCmd\n    participant Gen as Generator.Translate()\n    participant Catalog as catalog.Parse()\n    participant Pages as translatePages()\n    participant Claude as claude.Runner\n    participant Writer as output.Writer\n\n    CLI-\u003e\u003eGen: Translate(ctx, TranslateOptions)\n    Gen-\u003e\u003eWriter: ReadCatalogJSON()\n    Writer--\u003e\u003eGen: _catalog.json\n    Gen-\u003e\u003eCatalog: Parse(catJSON)\n    Catalog--\u003e\u003eGen: *catalog.Catalog\n\n    loop For each target language\n        Gen-\u003e\u003eWriter: ForLanguage(targetLang)\n        Gen-\u003e\u003ePages: translatePages(items, langWriter, ...)\n        loop For each leaf page (parallel)\n            Pages-\u003e\u003eWriter: ReadPage(item)\n            Writer--\u003e\u003ePages: sourceContent\n            Pages-\u003e\u003eClaude: RunWithRetry(TranslatePrompt)\n            Claude--\u003e\u003ePages: RunResult (with translated Markdown)\n            Pages-\u003e\u003eWriter: WritePage(item, translatedContent)\n        end\n        Pages--\u003e\u003eGen: translatedTitles map\n        Gen-\u003e\u003eWriter: WriteCatalogJSON(translatedCat)\n        Gen-\u003e\u003eWriter: WriteFile(\"index.md\")\n        Gen-\u003e\u003eWriter: WriteFile(\"_sidebar.md\")\n    end\n\n    Gen-\u003e\u003eWriter: WriteViewer (update language switcher data)\n```\n\n### Page Translation Details\n\n`translatePages()` only translates **leaf nodes** (`HasChildren == false`). Category index pages are regenerated in the target language by `output.GenerateCategoryIndex()`.\n\n**Skip Logic:**\n\n```go\nif !opts.Force \u0026\u0026 langWriter.PageExists(item) {\n    skipped.Add(1)\n    // Extract title from existing translation (for catalog rebuild)\n    if content, err := langWriter.ReadPage(item); err == nil {\n        if title := extractTitle(content); title != \"\" {\n            titlesMu.Lock()\n            translatedTitles[item.Path] = title\n            titlesMu.Unlock()\n        }\n    }\n    fmt.Printf(\"      [skipped] %s (already exists)\\n\", item.Title)\n    return nil\n}\n```\n\n\u003e Source: `internal/generator/translate_phase.go#L157-L168`\n\n**Concurrency Control:**\n\nBounded concurrency is implemented using `errgroup` and a buffered channel (semaphore):\n\n```go\neg, ctx := errgroup.WithContext(ctx)\nsem := make(chan struct{}, opts.Concurrency)\n\nfor _, item := range leafItems {\n    item := item\n    eg.Go(func() error {\n        sem \u003c- struct{}{}\n        defer func() { \u003c-sem }()\n        // ... translation logic\n    })\n}\neg.Wait()\n```\n\n\u003e Source: `internal/generator/translate_phase.go#L150-L249`\n\n### Translated Catalog Rebuild\n\nAfter translation completes, the system rebuilds the catalog (`_catalog.json`) using the translated page titles. `extractTitle()` extracts the title from the first `#` heading in the translated Markdown:\n\n```go\nfunc extractTitle(content string) string {\n    re := regexp.MustCompile(`(?m)^#\\s+(.+)$`)\n    match := re.FindStringSubmatch(content)\n    if len(match) \u003e= 2 {\n        return strings.TrimSpace(match[1])\n    }\n    return \"\"\n}\n```\n\n\u003e Source: `internal/generator/translate_phase.go#L267-L274`\n\n## Translation Prompt Rules\n\n`internal/prompt/templates/translate.tmpl` is the shared template, written in English, that instructs Claude to follow these rules when translating documents:\n\n| Rule | Description |\n|------|-------------|\n| Preserve Markdown formatting | Headings, links, code blocks, tables, Mermaid diagrams |\n| Do not translate code | Identifiers, file paths, variable names, and code blocks remain as-is |\n| Translate section headings | Use natural expressions in the target language |\n| Preserve relative link paths | `[text](../path/index.md)` — only translate display text, keep paths unchanged |\n| Preserve Mermaid diagrams | Translate diagram labels, keep syntax unchanged |\n| Preserve source annotations | `\u003e Source: path/to/file#L10-L25` format stays unchanged |\n| Natural translation | Produce fluent target-language text, not word-by-word translation |\n| Preserve reference file tables | Translate column headers, keep file paths as-is |\n\n\u003e Source: `internal/prompt/templates/translate.tmpl#L1-L35`\n\n## Output Directory Structure\n\nPrimary language documents are placed in `.doc-build/`, and each secondary language's translations are placed in the corresponding subdirectory:\n\n```\n.doc-build/\n├── _catalog.json          # Primary language catalog\n├── index.md               # Primary language home page\n├── _sidebar.md            # Primary language sidebar\n├── {section}/{page}/\n│   └── index.md           # Primary language content page\n├── en-US/                 # English translation\n│   ├── _catalog.json\n│   ├── index.md\n│   ├── _sidebar.md\n│   └── {section}/{page}/\n│       └── index.md\n└── ja-JP/                 # Japanese translation\n    └── ...\n```\n\n`Writer.ForLanguage(targetLang)` creates a new Writer instance with the language subdirectory as its `BaseDir`:\n\n```go\nfunc (w *Writer) ForLanguage(lang string) *Writer {\n    return \u0026Writer{\n        BaseDir: filepath.Join(w.BaseDir, lang),\n    }\n}\n```\n\n\u003e Source: `internal/output/writer.go#L138-L143`\n\n## Browser Multilingual Integration\n\nAfter translation completes, `Translate()` calls `buildDocMeta()` to regenerate the static browser (`index.html`), injecting all language information into the browser's language switcher. The `DocMeta` struct describes the primary and secondary languages:\n\n```go\ntype DocMeta struct {\n    DefaultLanguage    string     `json:\"default_language\"`\n    AvailableLanguages []LangInfo `json:\"available_languages\"`\n}\n\ntype LangInfo struct {\n    Code       string `json:\"code\"`\n    NativeName string `json:\"native_name\"`\n    IsDefault  bool   `json:\"is_default\"`\n}\n```\n\n\u003e Source: `internal/output/writer.go#L13-L23`\n\n## UI String Localization\n\n`output.UIStrings` defines the UI strings used in category index pages, home pages, and other navigation pages. Currently `zh-TW` and `en-US` are built in; other languages fall back to `en-US`:\n\n```go\nvar UIStrings = map[string]map[string]string{\n    \"zh-TW\": {\n        \"techDocs\":        \"技術文件\",\n        \"sectionContains\": \"本章節包含以下內容：\",\n        // ...\n    },\n    \"en-US\": {\n        \"techDocs\":        \"Technical Documentation\",\n        \"sectionContains\": \"This section contains the following:\",\n        // ...\n    },\n}\n```\n\n\u003e Source: `internal/output/navigation.go#L12-L27`\n\n## Related Links\n\n- [Supported Languages and Templates](../supported-languages/index.md)\n- [Multilingual Support](../index.md)\n- [Translation Phase](../../core-modules/generator/translate-phase/index.md)\n- [Claude CLI Runner](../../core-modules/claude-runner/index.md)\n- [Prompt Template Engine](../../core-modules/prompt-engine/index.md)\n- [selfmd translate](../../cli/cmd-translate/index.md)\n- [Output and Language Configuration](../../configuration/output-language/index.md)\n- [Static Document Viewer](../../core-modules/static-viewer/index.md)\n\n## Reference Files\n\n| File Path | Description |\n|-----------|-------------|\n| `internal/generator/translate_phase.go` | Core translation pipeline logic: `Translate()`, `translatePages()`, `buildTranslatedCatalog()` |\n| `cmd/translate.go` | `selfmd translate` CLI command implementation, language validation and option parsing |\n| `internal/config/config.go` | `OutputConfig`, `KnownLanguages`, `SupportedTemplateLangs`, `GetLangNativeName()` |\n| `internal/prompt/templates/translate.tmpl` | Shared prompt template for translation |\n| `internal/prompt/engine.go` | `TranslatePromptData` struct, `RenderTranslate()` method |\n| `internal/output/writer.go` | `Writer.ForLanguage()`, `ReadPage()`, `WritePage()`, `DocMeta` |\n| `internal/output/navigation.go` | `UIStrings`, `GenerateIndex()`, `GenerateSidebar()`, `GenerateCategoryIndex()` |\n| `internal/catalog/catalog.go` | `Catalog`, `FlatItem`, `Flatten()` |\n| `internal/generator/pipeline.go` | `Generator` struct, `buildDocMeta()` |\n| `internal/claude/runner.go` | `Runner.RunWithRetry()` translation call execution |","en-US/index.md":"# selfmd Technical Documentation\n\n---\n\n## Table of Contents\n\n- [Overview](./overview/index.md)\n  - [Project Overview \u0026 Features](./overview/introduction/index.md)\n  - [Tech Stack \u0026 Dependencies](./overview/tech-stack/index.md)\n  - [Output Structure](./overview/output-structure/index.md)\n- [Quick Start](./getting-started/index.md)\n  - [Installation \u0026 Build](./getting-started/installation/index.md)\n  - [Initialization Setup](./getting-started/init/index.md)\n  - [Generating Your First Document](./getting-started/first-run/index.md)\n- [CLI Command Reference](./cli/index.md)\n  - [selfmd init](./cli/cmd-init/index.md)\n  - [selfmd generate](./cli/cmd-generate/index.md)\n  - [selfmd update](./cli/cmd-update/index.md)\n  - [selfmd translate](./cli/cmd-translate/index.md)\n- [Configuration Guide](./configuration/index.md)\n  - [selfmd.yaml Structure Overview](./configuration/config-overview/index.md)\n  - [Project and Scan Target Configuration](./configuration/project-targets/index.md)\n  - [Output \u0026 Multilingual Configuration](./configuration/output-language/index.md)\n  - [Claude CLI Integration Settings](./configuration/claude-config/index.md)\n  - [Git Integration Configuration](./configuration/git-config/index.md)\n- [System Architecture](./architecture/index.md)\n  - [Overall Flow and Four-Phase Pipeline](./architecture/pipeline/index.md)\n  - [Module Dependency Graph](./architecture/module-dependencies/index.md)\n- [Core Modules](./core-modules/index.md)\n  - [Project Scanner](./core-modules/scanner/index.md)\n  - [Documentation Catalog Management](./core-modules/catalog/index.md)\n  - [Prompt Template Engine](./core-modules/prompt-engine/index.md)\n  - [Claude CLI Runner](./core-modules/claude-runner/index.md)\n  - [Document Generation Pipeline](./core-modules/generator/index.md)\n    - [Catalog Generation Phase](./core-modules/generator/catalog-phase/index.md)\n    - [Content Page Generation Phase](./core-modules/generator/content-phase/index.md)\n    - [Index and Navigation Generation Phase](./core-modules/generator/index-phase/index.md)\n    - [Translation Phase](./core-modules/generator/translate-phase/index.md)\n  - [Incremental Update](./core-modules/incremental-update/index.md)\n  - [Output Writing \u0026 Link Fixing](./core-modules/output-writer/index.md)\n  - [Static Document Viewer](./core-modules/static-viewer/index.md)\n- [Multi-language Support](./i18n/index.md)\n  - [Supported Languages and Templates](./i18n/supported-languages/index.md)\n  - [Translation Workflow](./i18n/translation-workflow/index.md)\n- [Git Integration and Incremental Updates](./git-integration/index.md)\n  - [Git Diff Change Detection](./git-integration/change-detection/index.md)\n  - [Affected Page Determination Logic](./git-integration/affected-pages/index.md)\n\n---\n\n*This documentation was automatically generated by [selfmd](https://github.com/monkenwu/selfmd)*\n","en-US/overview/index.md":"# Overview\n\nThis section contains the following:\n\n- [Project Overview \u0026 Features](introduction/index.md)\n- [Tech Stack \u0026 Dependencies](tech-stack/index.md)\n- [Output Structure](output-structure/index.md)\n","en-US/overview/introduction/index.md":"# Project Overview \u0026 Features\n\n`selfmd` is a CLI tool written in Go that automatically scans source code directories of any project and generates structured, Wiki-style technical documentation — using a locally running Claude Code CLI as the AI backend.\n\n## Overview\n\nThe core problem `selfmd` solves is that technical documentation tends to become outdated quickly due to high maintenance costs. By combining Claude Code CLI's code comprehension capabilities with an automated pipeline, `selfmd` continuously generates high-quality Markdown technical documentation for software projects without requiring manual authoring.\n\n### Positioning\n\n| Attribute | Description |\n|-----------|-------------|\n| **AI Backend** | Local Claude Code CLI (`claude` command), no remote API calls |\n| **Document Format** | Markdown, with support for Mermaid diagrams and source code annotations |\n| **Default Language** | Traditional Chinese (zh-TW), configurable to any language |\n| **Output Location** | `.doc-build/` folder under the project root |\n| **Target Projects** | Software projects in any language (Go, Rust, Python, Node.js, etc.) |\n\n### Core Concepts\n\n- **Catalog**: A hierarchical document outline automatically planned by AI after analyzing the project structure, defining the path and title of each page\n- **Pipeline**: Four sequentially executed stages, from scanning to output in one continuous flow\n- **Runner**: Wraps `claude` subprocess calls into retryable, timeout-capable asynchronous work units\n- **Incremental Update**: Detects source code changes via git diff and only regenerates affected documentation pages\n\n---\n\n## Architecture\n\nThe diagram below shows `selfmd`'s main modules and data flow.\n\n```mermaid\nflowchart TD\n    User[\"User (selfmd CLI)\"]\n\n    subgraph cmd[\"cmd/ (command layer)\"]\n        CmdInit[\"init\"]\n        CmdGen[\"generate\"]\n        CmdUpdate[\"update\"]\n        CmdTrans[\"translate\"]\n    end\n\n    subgraph internal[\"internal/ (core modules)\"]\n        Config[\"config\\nLoad selfmd.yaml\"]\n        Scanner[\"scanner\\nScan project directory\"]\n        Catalog[\"catalog\\nDocument catalog management\"]\n        Prompt[\"prompt\\nTemplate engine\"]\n        ClaudeRunner[\"claude\\nRunner / Parser\"]\n        Generator[\"generator\\nFour-stage pipeline\"]\n        Git[\"git\\nGit Diff integration\"]\n        Output[\"output\\nWriter / LinkFixer / Viewer\"]\n    end\n\n    User --\u003e cmd\n    CmdGen --\u003e Generator\n    CmdUpdate --\u003e Generator\n    CmdTrans --\u003e Generator\n    CmdInit --\u003e Config\n\n    Generator --\u003e Config\n    Generator --\u003e Scanner\n    Generator --\u003e Catalog\n    Generator --\u003e Prompt\n    Generator --\u003e ClaudeRunner\n    Generator --\u003e Git\n    Generator --\u003e Output\n\n    ClaudeRunner --\u003e|\"subprocess: claude -p\"| AI[\"Claude Code CLI\"]\n    Output --\u003e|\"Markdown + HTML\"| DocBuild[\".doc-build/\"]\n```\n\n---\n\n## Features\n\n### 1. Four-Stage Automated Documentation Pipeline\n\nWhen `selfmd generate` is executed, the pipeline completes the following four stages in sequence:\n\n```go\n// Phase 1: Scan\nfmt.Println(\"[1/4] 掃描專案結構...\")\nscan, err := scanner.Scan(g.Config, g.RootDir)\n\n// Phase 2: Generate Catalog\nfmt.Println(\"[2/4] 產生文件目錄...\")\ncat, err = g.GenerateCatalog(ctx, scan)\n\n// Phase 3: Generate Content（並行）\nfmt.Printf(\"[3/4] 產生內容頁面（並行度：%d）...\\n\", concurrency)\nif err := g.GenerateContent(ctx, scan, cat, concurrency, !clean); err != nil { ... }\n\n// Phase 4: Generate Index \u0026 Navigation\nfmt.Println(\"[4/4] 產生導航與索引...\")\nif err := g.GenerateIndex(ctx, cat); err != nil { ... }\n```\n\n\u003e Source: `internal/generator/pipeline.go#L86-L143`\n\nAfter the four stages complete, the system automatically generates a static HTML documentation site (`index.html`) that can be browsed directly, and records the current commit in the Git repository for use by the next incremental update.\n\n---\n\n### 2. Claude Code CLI Integration\n\n`selfmd` does not call the Anthropic API directly — all AI tasks are executed via the locally installed `claude` CLI as a subprocess. Each invocation:\n\n- Passes the rendered prompt via `stdin`\n- Retrieves structured responses using `--output-format json`\n- Allows `Read`, `Glob`, and `Grep` tools by default so Claude can read source code\n- Automatically blocks `Write` and `Edit` tools to prevent AI from accidentally modifying source code\n\n```go\nargs := []string{\n    \"-p\",\n    \"--output-format\", \"json\",\n}\n// ...\nargs = append(args, \"--disallowedTools\", \"Write\", \"--disallowedTools\", \"Edit\")\ncmd := exec.CommandContext(ctx, \"claude\", args...)\ncmd.Stdin = strings.NewReader(opts.Prompt)\n```\n\n\u003e Source: `internal/claude/runner.go#L32-L76`\n\n---\n\n### 3. Automatic Project Type Detection\n\n`selfmd init` scans the current directory and automatically determines the project type based on configuration files (`go.mod`, `package.json`, `Cargo.toml`, etc.), then generates `selfmd.yaml`:\n\n| Detected File | Project Type |\n|--------------|--------------|\n| `go.mod` | `backend` |\n| `package.json` | `frontend` (or `fullstack` if `go.mod` is also present) |\n| `Cargo.toml` | `backend` |\n| `requirements.txt` / `pyproject.toml` | `backend` |\n| `pom.xml` / `build.gradle` | `backend` |\n| `Gemfile` | `backend` |\n| None matched | `library` |\n\n\u003e Source: `cmd/init.go#L60-L98`\n\n---\n\n### 4. Git Integration \u0026 Incremental Updates\n\nWhen source code changes, there is no need to regenerate all documentation. `selfmd update` will:\n\n1. Read the commit hash recorded during the last `generate` run (stored in `.doc-build/_last_commit`)\n2. Call `git diff --name-status` to get the list of changed files\n3. Apply include/exclude filter rules to select target files\n4. Regenerate only the affected documentation pages\n\n```go\nchangedFiles, err := git.GetChangedFiles(rootDir, previousCommit, currentCommit)\nchangedFiles = git.FilterChangedFiles(changedFiles, cfg.Targets.Include, cfg.Targets.Exclude)\n```\n\n\u003e Source: `cmd/update.go#L89-L94`\n\n---\n\n### 5. Multi-Language Documentation Support\n\n`selfmd` natively supports multi-language documentation. After configuring `secondary_languages` in `selfmd.yaml`, running `selfmd translate` translates the primary language documentation into other languages. Translation results are stored in `.doc-build/{language-code}/` subdirectories.\n\nBuilt-in prompt templates currently support `zh-TW` and `en-US`; documentation output supports 11 languages:\n\n```go\nvar KnownLanguages = map[string]string{\n    \"zh-TW\": \"繁體中文\",\n    \"zh-CN\": \"简体中文\",\n    \"en-US\": \"English\",\n    \"ja-JP\": \"日本語\",\n    \"ko-KR\": \"한국어\",\n    \"fr-FR\": \"Français\",\n    \"de-DE\": \"Deutsch\",\n    \"es-ES\": \"Español\",\n    \"pt-BR\": \"Português\",\n    \"th-TH\": \"ไทย\",\n    \"vi-VN\": \"Tiếng Việt\",\n}\n```\n\n\u003e Source: `internal/config/config.go#L39-L51`\n\n---\n\n### 6. Parallel Page Generation\n\nTo reduce documentation generation time for large projects, `selfmd` supports parallel Claude invocations. The default concurrency is 3, adjustable via the configuration file or the `--concurrency` flag:\n\n```go\nClaude: ClaudeConfig{\n    Model:         \"sonnet\",\n    MaxConcurrent: 3,\n    TimeoutSeconds: 300,\n    MaxRetries:    2,\n    AllowedTools:  []string{\"Read\", \"Glob\", \"Grep\"},\n},\n```\n\n\u003e Source: `internal/config/config.go#L116-L123`\n\n---\n\n### 7. Static HTML Documentation Viewer\n\nAfter documentation generation is complete, `selfmd` produces a static documentation site at `.doc-build/index.html` that can be opened directly in a browser with no server required. The viewer includes a language switcher for navigating multi-language documentation.\n\n---\n\n## Core Workflow\n\n```mermaid\nsequenceDiagram\n    participant User as User\n    participant CLI as selfmd CLI\n    participant Scanner as scanner\n    participant Claude as Claude Code CLI\n    participant FS as .doc-build/\n\n    User-\u003e\u003eCLI: selfmd generate\n    CLI-\u003e\u003eScanner: Scan project directory and entry files\n    Scanner--\u003e\u003eCLI: ScanResult (file tree, README)\n\n    CLI-\u003e\u003eClaude: Render catalog.tmpl → call claude -p\n    Claude--\u003e\u003eCLI: Catalog JSON (Catalog)\n\n    loop For each catalog page (parallel)\n        CLI-\u003e\u003eClaude: Render content.tmpl → call claude -p\n        Claude--\u003e\u003eCLI: Markdown page content\n        CLI-\u003e\u003eFS: Write {dirPath}/index.md\n    end\n\n    CLI-\u003e\u003eClaude: Render navigation and index\n    Claude--\u003e\u003eCLI: index.md content\n    CLI-\u003e\u003eFS: Generate static HTML viewer\n    CLI-\u003e\u003eFS: Save _last_commit\n    CLI--\u003e\u003eUser: Completion report (page count, duration, cost)\n```\n\n---\n\n## CLI Command Reference\n\n| Command | Description |\n|---------|-------------|\n| `selfmd init` | Detect project type and generate `selfmd.yaml` configuration file |\n| `selfmd generate` | Run the full four-stage documentation generation pipeline |\n| `selfmd generate --dry-run` | Display scan results only, without calling Claude |\n| `selfmd generate --clean` | Clear the output directory and regenerate from scratch |\n| `selfmd update` | Incrementally update affected documentation pages based on git diff |\n| `selfmd translate` | Translate primary language documentation into secondary languages |\n\nGlobal flags shared by all commands:\n\n| Flag | Description |\n|------|-------------|\n| `-c, --config` | Configuration file path (default: `selfmd.yaml`) |\n| `-v, --verbose` | Show detailed debug output |\n| `-q, --quiet` | Show error messages only |\n\n\u003e Source: `cmd/root.go#L30-L33`\n\n---\n\n## Related Links\n\n- [Tech Stack \u0026 Dependencies](../tech-stack/index.md) — Learn about the languages, frameworks, and external packages used by `selfmd`\n- [Output Structure](../output-structure/index.md) — Complete structure of the `.doc-build/` directory\n- [Installation \u0026 Build](../../getting-started/installation/index.md) — How to install and run `selfmd` locally\n- [Initialization](../../getting-started/init/index.md) — Detailed usage guide for `selfmd init`\n- [selfmd generate](../../cli/cmd-generate/index.md) — Full parameter reference for the generate command\n- [selfmd update](../../cli/cmd-update/index.md) — Full parameter reference for the update command\n- [selfmd translate](../../cli/cmd-translate/index.md) — Full parameter reference for the translate command\n- [Overall Flow \u0026 Four-Stage Pipeline](../../architecture/pipeline/index.md) — Deep dive into the pipeline architecture design\n- [Claude CLI Runner](../../core-modules/claude-runner/index.md) — Implementation details of the Runner module\n- [Multi-Language Support](../../i18n/index.md) — Configuration and translation workflow for multi-language documentation\n- [Git Integration \u0026 Incremental Updates](../../git-integration/index.md) — How incremental updates work\n\n---\n\n## Reference Files\n\n| File Path | Description |\n|-----------|-------------|\n| `cmd/root.go` | CLI root command definition, global flag configuration |\n| `cmd/generate.go` | `generate` command implementation, pipeline entry point |\n| `cmd/init.go` | `init` command implementation, project type detection logic |\n| `cmd/update.go` | `update` command implementation, incremental update flow |\n| `cmd/translate.go` | `translate` command implementation, multi-language translation flow |\n| `internal/config/config.go` | `Config` struct definition, default values, known languages list |\n| `internal/generator/pipeline.go` | `Generator` struct, four-stage pipeline implementation |\n| `internal/scanner/scanner.go` | Project directory scanner implementation |\n| `internal/claude/runner.go` | Claude CLI subprocess execution wrapper |\n| `internal/prompt/engine.go` | Prompt template engine, PromptData type definitions |\n| `internal/output/writer.go` | Output directory writer, Catalog JSON management |\n| `internal/git/git.go` | Git diff integration, changed file filtering |","en-US/overview/output-structure/index.md":"# Output Structure\n\nAfter `selfmd` finishes running, all generated files, static browser assets, and metadata are stored in the output directory (default: `.doc-build/`). This page describes the complete file structure of that directory and the purpose of each file.\n\n## Overview\n\nThe output directory is managed entirely by `output.Writer`. The four generation phases each handle a distinct responsibility, writing different types of files to the output directory in sequence:\n\n- **Catalog phase**: writes `_catalog.json` (catalog index JSON)\n- **Content phase**: writes `{dir}/index.md` content pages for each section\n- **Index \u0026 navigation phase**: writes `index.md`, `_sidebar.md`, and category index pages\n- **Static browser**: writes `index.html`, `app.js`, `style.css`, `_data.js`, `_doc_meta.json`\n- **Translation phase** (optional): writes translated versions under `{lang-code}/` subdirectories\n\nThe root path of the output directory is determined by the `output.dir` field in `selfmd.yaml`, with a default value of `.doc-build`.\n\n## Architecture\n\n```mermaid\nflowchart TD\n    A[\"selfmd generate\"] --\u003e B[\"output.Writer\"]\n    B --\u003e C[\"_catalog.json\"]\n    B --\u003e D[\"index.md (homepage)\"]\n    B --\u003e E[\"_sidebar.md (sidebar navigation)\"]\n    B --\u003e F[\"Content page directories\"]\n    B --\u003e G[\"Static browser assets\"]\n    B --\u003e H[\"Incremental update metadata\"]\n\n    F --\u003e F1[\"{section}/index.md\"]\n    F --\u003e F2[\"{section}/{subsection}/index.md\"]\n\n    G --\u003e G1[\"index.html\"]\n    G --\u003e G2[\"app.js\"]\n    G --\u003e G3[\"style.css\"]\n    G --\u003e G4[\"_data.js (bundled data)\"]\n    G --\u003e G5[\"_doc_meta.json\"]\n\n    H --\u003e H1[\"_last_commit\"]\n\n    I[\"selfmd translate\"] --\u003e J[\"Language subdirectories\"]\n    J --\u003e J1[\"{lang-code}/_catalog.json\"]\n    J --\u003e J2[\"{lang-code}/index.md\"]\n    J --\u003e J3[\"{lang-code}/_sidebar.md\"]\n    J --\u003e J4[\"{lang-code}/{section}/index.md\"]\n```\n\n## Full Directory Structure\n\nAfter running `selfmd generate` with translation enabled, a typical output directory looks like this:\n\n```\n.doc-build/\n├── index.html          # Static documentation browser entry page\n├── app.js              # Browser frontend JavaScript\n├── style.css           # Browser stylesheet\n├── _data.js            # Bundled data for all Markdown content (loaded by the browser)\n├── _doc_meta.json      # Multilingual metadata\n├── _catalog.json       # Document catalog structure (JSON, used for incremental updates)\n├── _last_commit        # Git commit hash from the last generation run\n├── index.md            # Documentation homepage (table of contents)\n├── _sidebar.md         # Docsify/browser sidebar navigation\n│\n├── {section}/\n│   └── index.md        # Section content page\n├── {section}/\n│   ├── index.md        # Category index page (auto-generated when subsections exist)\n│   └── {subsection}/\n│       └── index.md    # Subsection content page\n│\n└── {lang-code}/        # Secondary language directory (e.g. en-US/)\n    ├── _catalog.json   # Translated catalog structure\n    ├── index.md        # Translated homepage\n    ├── _sidebar.md     # Translated sidebar navigation\n    └── {section}/\n        └── index.md    # Translated content page\n```\n\n## File Descriptions by Type\n\n### System Files (Underscore-prefixed)\n\nFiles beginning with an underscore (`_`) are for internal system use. They are excluded from the static browser's page routing and do not appear in the documentation table of contents.\n\n| File | Description |\n|------|-------------|\n| `_catalog.json` | JSON serialization of the document catalog, reused by incremental updates (`selfmd update`) to avoid re-calling Claude |\n| `_last_commit` | Records the Git commit hash from the last generation run; used by `selfmd update` to determine which pages need regeneration |\n| `_data.js` | Bundles all `.md` files and the catalog structure into a single JavaScript data object for client-side rendering in the static browser |\n| `_doc_meta.json` | Records the primary language and all secondary languages with their codes and native names, used by the language-switching feature |\n| `_sidebar.md` | Navigation sidebar, automatically generated by `GenerateSidebar` from the catalog structure |\n\n### Static Browser Assets\n\n```go\n// viewer.go writes three embedded static assets to the output directory\nif err := w.WriteFile(\"index.html\", html); err != nil { ... }\nif err := w.WriteFile(\"app.js\", viewerJS); err != nil { ... }\nif err := w.WriteFile(\"style.css\", viewerCSS); err != nil { ... }\n```\n\n\u003e Source: `internal/output/viewer.go#L34-L44`\n\n`index.html` is the browser's entry page. The `{{PROJECT_NAME}}` and `{{LANG}}` placeholders are replaced with the actual project name and language code at write time.\n\n### Content Pages\n\nEach documentation item (`catalog.FlatItem`) is written as an `index.md` file under its corresponding directory path:\n\n```go\n// writer.go: WritePage uses FlatItem.DirPath to determine the directory location\nfunc (w *Writer) WritePage(item catalog.FlatItem, content string) error {\n    dir := filepath.Join(w.BaseDir, item.DirPath)\n    path := filepath.Join(dir, \"index.md\")\n    // ...\n}\n```\n\n\u003e Source: `internal/output/writer.go#L50-L61`\n\nPath mapping rule: the `DirPath` from the catalog structure (e.g. `core-modules/scanner`) maps directly to the filesystem path, producing `core-modules/scanner/index.md`.\n\n### Homepage and Category Indexes\n\n- **`index.md`** (homepage): generated by `GenerateIndex`, contains a full linked table of contents\n- **`{section}/index.md`** (category index): when a section has subsections, its `index.md` is automatically generated by `GenerateCategoryIndex`, listing links to its direct children\n\n```go\n// index_phase.go: category indexes are only generated for items with children\nfor _, item := range items {\n    if !item.HasChildren {\n        continue\n    }\n    // ...\n    categoryContent := output.GenerateCategoryIndex(item, children, lang)\n    if err := g.Writer.WritePage(item, categoryContent); err != nil { ... }\n}\n```\n\n\u003e Source: `internal/generator/index_phase.go#L34-L53`\n\n### `_data.js` Data Bundle\n\nThe static browser does not rely on server-side routing. Instead, it loads all content on the client side via `_data.js`. The bundling logic scans all `.md` files, excludes underscore-prefixed files and secondary language directories, and embeds the content as JSON:\n\n```go\n// viewer.go: data structure for _data.js\ndata := map[string]interface{}{\n    \"catalog\": catalogObj,\n    \"pages\":   pages,\n}\n// For multilingual builds, add meta and per-language data\nif docMeta != nil {\n    data[\"meta\"] = docMeta\n    // ... add languages object\n}\n\ncontent := \"window.DOC_DATA = \" + string(jsonBytes) + \";\\n\"\nreturn w.WriteFile(\"_data.js\", content)\n```\n\n\u003e Source: `internal/output/viewer.go#L128-L195`\n\n## Multilingual Directory Structure\n\nWhen multilingual translation is enabled (via `selfmd translate`), each secondary language gets its own subdirectory under the output directory, mirroring the structure of the primary language exactly:\n\n```\n.doc-build/\n├── (primary language content, directly at root)\n└── en-US/              # Secondary language (en-US as example)\n    ├── _catalog.json   # Translated catalog\n    ├── index.md        # Translated homepage\n    ├── _sidebar.md     # Translated sidebar\n    └── core-modules/\n        └── scanner/\n            └── index.md\n```\n\nThe `Writer.ForLanguage` method creates a writer scoped to the language subdirectory:\n\n```go\n// writer.go: creates a Writer for a language subdirectory\nfunc (w *Writer) ForLanguage(lang string) *Writer {\n    return \u0026Writer{\n        BaseDir: filepath.Join(w.BaseDir, lang),\n    }\n}\n```\n\n\u003e Source: `internal/output/writer.go#L139-L144`\n\n## Output Directory Configuration\n\nOutput directory settings are found in the `output` section of `selfmd.yaml`:\n\n```go\n// config.go: OutputConfig struct\ntype OutputConfig struct {\n    Dir                 string   `yaml:\"dir\"`\n    Language            string   `yaml:\"language\"`\n    SecondaryLanguages  []string `yaml:\"secondary_languages\"`\n    CleanBeforeGenerate bool     `yaml:\"clean_before_generate\"`\n}\n```\n\n\u003e Source: `internal/config/config.go#L31-L36`\n\nDefault values:\n\n| Setting | Default | Description |\n|---------|---------|-------------|\n| `output.dir` | `.doc-build` | Output directory path |\n| `output.language` | `zh-TW` | Primary language (content placed directly at root) |\n| `output.secondary_languages` | `[]` (empty) | List of secondary languages, each gets its own subdirectory |\n| `output.clean_before_generate` | `false` | Whether to clear the previous output before generating |\n\n## Incremental Update Files\n\n`_catalog.json` and `_last_commit` are the core of the incremental update mechanism:\n\n```go\n// writer.go: saves metadata needed for incremental updates\nfunc (w *Writer) WriteCatalogJSON(cat *catalog.Catalog) error {\n    data, err := cat.ToJSON()\n    return w.WriteFile(\"_catalog.json\", data)\n}\n\nfunc (w *Writer) SaveLastCommit(commit string) error {\n    return w.WriteFile(\"_last_commit\", commit)\n}\n```\n\n\u003e Source: `internal/output/writer.go#L77-L137`\n\nWhen `selfmd update` runs, it reads these two files, compares the current Git commit against the commit from the last generation run, and regenerates only the affected pages.\n\n## Related Links\n\n- [Overall Pipeline and Four-Phase Architecture](../../architecture/pipeline/index.md)\n- [Output Writing and Link Fixing](../../core-modules/output-writer/index.md)\n- [Static Documentation Browser](../../core-modules/static-viewer/index.md)\n- [Multilingual Support](../../i18n/index.md)\n- [Output and Language Configuration](../../configuration/output-language/index.md)\n- [Incremental Updates](../../core-modules/incremental-update/index.md)\n\n## Reference Files\n\n| File Path | Description |\n|-----------|-------------|\n| `internal/output/writer.go` | `Writer` struct and all file-writing methods |\n| `internal/output/viewer.go` | Static browser asset writing and `_data.js` bundling logic |\n| `internal/output/navigation.go` | Generation logic for `index.md`, `_sidebar.md`, and category index pages |\n| `internal/output/linkfixer.go` | Link fixer that ensures relative links between pages are correct |\n| `internal/generator/pipeline.go` | Overall coordination of the four-phase pipeline and generation order for each output type |\n| `internal/generator/index_phase.go` | Index and navigation phase implementation |\n| `internal/generator/translate_phase.go` | Translation phase and language subdirectory writing logic |\n| `internal/catalog/catalog.go` | `Catalog` and `FlatItem` structs, `DirPath` path mapping rules |\n| `internal/config/config.go` | `OutputConfig` struct definition and default values |","en-US/overview/tech-stack/index.md":"# Tech Stack \u0026 Dependencies\n\nselfmd is implemented in pure Go with a minimal set of dependencies — only four direct external packages are used, with the remainder of functionality relying on the Go standard library.\n\n## Overview\n\nOne of selfmd's design goals is to remain lightweight and easy to install. Beyond the Go runtime itself, the tool requires two external CLI tools at runtime:\n\n- **Claude Code CLI** (`claude`): The AI backend, responsible for analyzing source code and generating documentation content\n- **Git CLI** (`git`): Used during incremental updates to detect changes in source code\n\nThese external tools are not managed through Go's package system — they are invoked via `os/exec` by calling binaries already installed on the system.\n\n## Architecture\n\n```mermaid\ngraph TD\n    subgraph GoStdLib[\"Go Standard Library\"]\n        embed[\"embed\\n(embed templates)\"]\n        slog[\"log/slog\\n(structured logging)\"]\n        exec[\"os/exec\\n(subprocess execution)\"]\n        tmpl[\"text/template\\n(template rendering)\"]\n        json[\"encoding/json\\n(JSON serialization)\"]\n        ctx[\"context\\n(timeout control)\"]\n        sync_pkg[\"sync / sync/atomic\\n(concurrency primitives)\"]\n    end\n\n    subgraph ExternalDeps[\"External Dependencies\"]\n        cobra[\"cobra v1.10.2\\n(CLI framework)\"]\n        pflag[\"pflag v1.0.9\\n(flag parsing, indirect)\"]\n        doublestar[\"doublestar v4.10.0\\n(glob matching)\"]\n        errgroup[\"x/sync v0.19.0\\n(errgroup concurrency)\"]\n        yaml[\"yaml.v3 v3.0.1\\n(YAML parsing)\"]\n        mousetrap[\"mousetrap v1.1.0\\n(Windows compat, indirect)\"]\n    end\n\n    subgraph ExternalTools[\"External Runtime Tools (non-Go packages)\"]\n        claude_cli[\"Claude Code CLI\\n(claude command)\"]\n        git_cli[\"Git CLI\\n(git command)\"]\n    end\n\n    cobra --\u003e pflag\n    cobra --\u003e mousetrap\n\n    cmd_pkg[\"cmd/*\"] --\u003e cobra\n    scanner_pkg[\"internal/scanner\"] --\u003e doublestar\n    git_pkg[\"internal/git\"] --\u003e doublestar\n    config_pkg[\"internal/config\"] --\u003e yaml\n    prompt_pkg[\"internal/prompt\"] --\u003e embed\n    prompt_pkg --\u003e tmpl\n    claude_pkg[\"internal/claude\"] --\u003e exec\n    claude_pkg --\u003e json\n    claude_pkg --\u003e slog\n    claude_pkg --\u003e ctx\n    git_pkg --\u003e exec\n    generator_pkg[\"internal/generator\"] --\u003e errgroup\n    generator_pkg --\u003e sync_pkg\n    output_pkg[\"internal/output\"] --\u003e json\n\n    claude_pkg --\u003e claude_cli\n    git_pkg --\u003e git_cli\n```\n\n## Dependency Details\n\n### Direct Dependencies\n\n| Package | Version | Purpose | Used In |\n|---------|---------|---------|---------|\n| `github.com/spf13/cobra` | v1.10.2 | CLI command framework | `cmd/root.go`, all command files |\n| `github.com/bmatcuk/doublestar/v4` | v4.10.0 | Double-star (`**`) glob pattern matching | `internal/scanner/scanner.go`, `internal/git/git.go` |\n| `golang.org/x/sync` | v0.19.0 | `errgroup` concurrent task groups | `internal/generator/content_phase.go`, `translate_phase.go` |\n| `gopkg.in/yaml.v3` | v3.0.1 | YAML config file parsing and serialization | `internal/config/config.go` |\n\n### Indirect Dependencies\n\n| Package | Version | Description |\n|---------|---------|-------------|\n| `github.com/spf13/pflag` | v1.0.9 | Underlying flag parsing implementation for cobra |\n| `github.com/inconshreveable/mousetrap` | v1.1.0 | Windows platform compatibility support for cobra |\n\n\u003e Source: `go.mod#L1-L15`\n\n```go\nmodule github.com/monkenwu/selfmd\n\ngo 1.25.7\n\nrequire (\n\tgithub.com/bmatcuk/doublestar/v4 v4.10.0\n\tgithub.com/spf13/cobra v1.10.2\n\tgolang.org/x/sync v0.19.0\n\tgopkg.in/yaml.v3 v3.0.1\n)\n\nrequire (\n\tgithub.com/inconshreveable/mousetrap v1.1.0 // indirect\n\tgithub.com/spf13/pflag v1.0.9 // indirect\n)\n```\n\n\u003e Source: `go.mod#L1-L15`\n\n---\n\n### cobra — CLI Framework\n\n`cobra` handles the routing structure for all subcommands (`init`, `generate`, `update`, `translate`), flag definitions, and automatic help text generation.\n\n```go\nvar rootCmd = \u0026cobra.Command{\n\tUse:   \"selfmd\",\n\tShort: \"selfmd — 專案文件自動產生器\",\n\tLong: `selfmd 是一個 CLI 工具，透過本地 Claude Code CLI 作為 AI 後端，\n自動掃描專案目錄並產生結構化的 Wiki 風格繁體中文技術文件。`,\n}\n```\n\n\u003e Source: `cmd/root.go#L17-L25`\n\n---\n\n### doublestar — Glob Pattern Matching\n\nGo's standard library `filepath.Match` does not support `**` double-star patterns (recursive directory matching). `doublestar` fills this gap, allowing users to specify patterns like `internal/**` or `**/*.pb.go` in `selfmd.yaml`.\n\n```go\n// check excludes\nfor _, pattern := range cfg.Targets.Exclude {\n    matched, _ := doublestar.Match(pattern, rel)\n    if matched {\n        if d.IsDir() {\n            return filepath.SkipDir\n        }\n        return nil\n    }\n}\n```\n\n\u003e Source: `internal/scanner/scanner.go#L33-L41`\n\n---\n\n### golang.org/x/sync (errgroup) — Concurrent Task Management\n\n`errgroup.WithContext` combined with a channel as a semaphore controls the number of concurrent Claude CLI invocations, preventing them from exceeding the configured `max_concurrent` limit.\n\n```go\neg, ctx := errgroup.WithContext(ctx)\nsem := make(chan struct{}, concurrency)\n\nfor _, item := range items {\n    item := item\n    eg.Go(func() error {\n        sem \u003c- struct{}{}\n        defer func() { \u003c-sem }()\n        // ... generate page\n        return nil\n    })\n}\n```\n\n\u003e Source: `internal/generator/content_phase.go#L37-L50`\n\n---\n\n### yaml.v3 — Config File Parsing\n\nBoth reading and writing of the `selfmd.yaml` config file are handled through `yaml.v3`. The `Load` function first constructs a `Config` object with default values, then uses YAML Unmarshal to override with user-defined fields.\n\n```go\nfunc Load(path string) (*Config, error) {\n\tdata, err := os.ReadFile(path)\n\t// ...\n\tcfg := DefaultConfig()\n\tif err := yaml.Unmarshal(data, cfg); err != nil {\n\t\treturn nil, fmt.Errorf(\"設定檔格式錯誤: %w\", err)\n\t}\n\t// ...\n}\n```\n\n\u003e Source: `internal/config/config.go#L131-L147`\n\n---\n\n## Go Standard Library — Key Usage\n\n| Package | Purpose | Used In |\n|---------|---------|---------|\n| `embed` | Compile-time embedding of prompt templates (`.tmpl` files) | `internal/prompt/engine.go` |\n| `text/template` | Renders prompt templates by injecting data into text | `internal/prompt/engine.go` |\n| `os/exec` | Invokes `claude` and `git` subprocesses | `internal/claude/runner.go`, `internal/git/git.go` |\n| `log/slog` | Structured logging (built-in since Go 1.21) | `internal/claude/runner.go`, `internal/generator/pipeline.go` |\n| `encoding/json` | JSON serialization for the catalog | `internal/catalog/catalog.go`, `internal/claude/parser.go` |\n| `context` | Subprocess timeout control and cancellation | `internal/claude/runner.go` |\n| `sync` / `sync/atomic` | Concurrency counters (completed, failed, skipped) | `internal/generator/content_phase.go` |\n| `path/filepath` | Cross-platform path operations | Multiple locations |\n\n### embed — Compile-Time Template Embedding\n\nThe `//go:embed` directive bundles all `.tmpl` files under the `templates/` directory into the binary at compile time, so users do not need to deploy template files separately.\n\n```go\n//go:embed templates/*/*.tmpl templates/*.tmpl\nvar templateFS embed.FS\n```\n\n\u003e Source: `internal/prompt/engine.go#L10-L11`\n\n### log/slog — Structured Logging\n\n`slog` is the structured logging package introduced in Go 1.21, replacing the third-party logging libraries that were previously common. selfmd uses `slog.Logger` as its internal logging interface, passing it uniformly into each module.\n\n```go\nr.logger.Debug(\"claude completed\",\n    \"duration\", elapsed.Round(time.Millisecond),\n    \"cost_usd\", result.CostUSD,\n    \"is_error\", result.IsError,\n)\n```\n\n\u003e Source: `internal/claude/runner.go#L103-L108`\n\n---\n\n## External Runtime Tool Dependencies\n\n### Claude Code CLI\n\nselfmd's AI capabilities come from invoking the locally installed `claude` CLI, rather than directly integrating the Anthropic API SDK. This design lets users reuse their existing Claude Code license and configuration.\n\n```go\ncmd := exec.CommandContext(ctx, \"claude\", args...)\n// ...\ncmd.Stdin = strings.NewReader(opts.Prompt)\n```\n\n\u003e Source: `internal/claude/runner.go#L69-L75`\n\nBefore startup, availability of the `claude` binary is verified:\n\n```go\nfunc CheckAvailable() error {\n\t_, err := exec.LookPath(\"claude\")\n\tif err != nil {\n\t\treturn fmt.Errorf(\"找不到 claude CLI。請先安裝 Claude Code：https://docs.anthropic.com/en/docs/claude-code\")\n\t}\n\treturn nil\n}\n```\n\n\u003e Source: `internal/claude/runner.go#L146-L152`\n\n### Git CLI\n\nThe incremental update feature detects source code changes by running commands such as `git diff` and `git rev-parse`, without relying on any Go Git library:\n\n```go\nfunc runGit(dir string, args ...string) (string, error) {\n\tcmd := exec.Command(\"git\", args...)\n\tcmd.Dir = dir\n\t// ...\n}\n```\n\n\u003e Source: `internal/git/git.go#L124-L141`\n\n---\n\n## Core Flow\n\n```mermaid\nsequenceDiagram\n    participant User\n    participant cobra\n    participant config_yaml as yaml.v3\n    participant scanner_ds as doublestar\n    participant prompt_embed as embed / text/template\n    participant runner_exec as os/exec (claude)\n    participant gen_eg as errgroup (x/sync)\n    participant git_exec as os/exec (git)\n\n    User-\u003e\u003ecobra: selfmd generate\n    cobra-\u003e\u003econfig_yaml: Load selfmd.yaml\n    cobra-\u003e\u003escanner_ds: Scan directories (glob filtering)\n    cobra-\u003e\u003eprompt_embed: Render prompt templates\n    cobra-\u003e\u003egen_eg: Start concurrent task group\n    loop Each documentation page (semaphore-bounded)\n        gen_eg-\u003e\u003erunner_exec: Invoke claude CLI\n        runner_exec--\u003e\u003egen_eg: Return JSON result\n    end\n    cobra-\u003e\u003egit_exec: Save current commit (for incremental updates)\n```\n\n---\n\n## Related Links\n\n- [Overall Flow \u0026 Four-Phase Pipeline](../../architecture/pipeline/index.md)\n- [Claude CLI Runner](../../core-modules/claude-runner/index.md)\n- [Project Scanner](../../core-modules/scanner/index.md)\n- [Prompt Template Engine](../../core-modules/prompt-engine/index.md)\n- [Configuration Reference](../../configuration/index.md)\n- [Git Integration Configuration](../../configuration/git-config/index.md)\n\n---\n\n## Reference Files\n\n| File Path | Description |\n|-----------|-------------|\n| `go.mod` | Go module definition, including all direct and indirect dependencies |\n| `cmd/root.go` | cobra root command definition, demonstrating CLI framework usage |\n| `internal/config/config.go` | yaml.v3 implementation for config file parsing |\n| `internal/scanner/scanner.go` | doublestar usage for include/exclude pattern matching |\n| `internal/git/git.go` | os/exec implementation for invoking the git CLI |\n| `internal/claude/runner.go` | os/exec for invoking the claude CLI, with log/slog usage examples |\n| `internal/claude/types.go` | JSON type definitions for Claude CLI responses |\n| `internal/prompt/engine.go` | embed + text/template for embedding and rendering templates |\n| `internal/generator/content_phase.go` | errgroup + channel semaphore for concurrency control |\n| `internal/generator/pipeline.go` | Overall pipeline, showing how modules integrate |\n| `internal/catalog/catalog.go` | encoding/json for catalog serialization |\n| `internal/output/writer.go` | Output writing, demonstrating standard os package usage |\n| `internal/output/navigation.go` | Navigation page generation implementation |\n| `internal/scanner/filetree.go` | File tree data structure definitions (ScanResult, FileNode) |","getting-started/first-run/index.md":"# 產生第一份文件\n\n完成初始化設定後，執行 `selfmd generate` 即可啟動四階段文件產生管線，自動掃描專案、呼叫 Claude CLI 撰寫文件並輸出靜態網站。\n\n## 概述\n\n`selfmd generate` 是 selfmd 的核心指令。它讀取 `selfmd.yaml` 的設定，依序執行以下流程：\n\n1. **掃描**專案目錄結構與原始碼\n2. **呼叫 Claude CLI** 產生文件目錄（Catalog）\n3. **並行呼叫 Claude CLI** 產生每一頁文件內容\n4. **產生**索引、側邊欄與靜態瀏覽器\n\n整個過程完全自動化，結束後在輸出目錄（預設 `.doc-build/`）中即可找到完整的文件網站，直接開啟 `index.html` 瀏覽。\n\n---\n\n## 前置條件\n\n在執行 `generate` 之前，請確認：\n\n| 條件 | 說明 |\n|------|------|\n| `selfmd.yaml` 已存在 | 執行 `selfmd init` 建立，或手動建立 |\n| Claude CLI 已安裝並可呼叫 | 程式啟動時會自動呼叫 `claude.CheckAvailable()` 驗證 |\n| 當前目錄為專案根目錄 | selfmd 以執行目錄為 `rootDir` |\n\n---\n\n## 快速執行\n\n```bash\n# 最基本的使用方式\nselfmd generate\n\n# 強制清除輸出目錄後重新產生\nselfmd generate --clean\n\n# 先預覽將掃描哪些檔案，不實際呼叫 Claude\nselfmd generate --dry-run\n\n# 提高並行度以加快產生速度\nselfmd generate --concurrency 5\n```\n\n---\n\n## 架構\n\n```mermaid\nflowchart TD\n    CLI[\"selfmd generate\\ncmd/generate.go\"] --\u003e CheckClaude[\"claude.CheckAvailable()\"]\n    CLI --\u003e LoadCfg[\"config.Load()\"]\n    CLI --\u003e NewGen[\"generator.NewGenerator()\"]\n    NewGen --\u003e Runner[\"claude.Runner\"]\n    NewGen --\u003e Engine[\"prompt.Engine\"]\n    NewGen --\u003e Writer[\"output.Writer\"]\n\n    NewGen --\u003e Generate[\"Generator.Generate()\"]\n\n    Generate --\u003e Phase0[\"Phase 0\\n清除或確保輸出目錄\"]\n    Phase0 --\u003e Phase1[\"Phase 1\\nscanner.Scan()\"]\n    Phase1 --\u003e Phase2{\"目錄是否\\n已存在？\"}\n    Phase2 -- \"是（非 --clean 模式）\" --\u003e LoadCatalog[\"載入既有 _catalog.json\"]\n    Phase2 -- \"否\" --\u003e GenCatalog[\"GenerateCatalog()\\n呼叫 Claude CLI\"]\n    LoadCatalog --\u003e Phase3[\"Phase 3\\nGenerateContent()\\n並行呼叫 Claude CLI\"]\n    GenCatalog --\u003e Phase3\n    Phase3 --\u003e Phase4[\"Phase 4\\nGenerateIndex()\\n產生 index.md / _sidebar.md\"]\n    Phase4 --\u003e Viewer[\"Writer.WriteViewer()\\n產生靜態 HTML 瀏覽器\"]\n    Viewer --\u003e SaveCommit[\"git.SaveLastCommit()\\n記錄本次 commit\"]\n```\n\n---\n\n## 四個執行階段詳解\n\n### Phase 0：初始化輸出目錄\n\n程式先判斷是否需要清除輸出目錄：\n\n```go\nclean := opts.Clean || g.Config.Output.CleanBeforeGenerate\nif clean {\n    fmt.Println(ui.T(\"[0/4] 清除輸出目錄...\", \"[0/4] Cleaning output directory...\"))\n    if !opts.DryRun {\n        if err := g.Writer.Clean(); err != nil {\n            return err\n        }\n    }\n} else {\n    if err := g.Writer.EnsureDir(); err != nil {\n        return err\n    }\n}\n```\n\n\u003e 來源：`internal/generator/pipeline.go#L73-L85`\n\n`--clean` 旗標或設定檔中的 `clean_before_generate: true` 都會觸發清除行為；否則只確保目錄存在。\n\n---\n\n### Phase 1：掃描專案結構\n\n呼叫 `scanner.Scan()` 遍歷專案目錄：\n\n```go\nfmt.Println(ui.T(\"[1/4] 掃描專案結構...\", \"[1/4] Scanning project structure...\"))\nscan, err := scanner.Scan(g.Config, g.RootDir)\n```\n\n\u003e 來源：`internal/generator/pipeline.go#L88-L93`\n\n掃描器依照 `selfmd.yaml` 中的 `targets.include` 與 `targets.exclude` 篩選檔案，同時讀取：\n- `README.md`（作為 Claude 的背景知識）\n- `entry_points` 中指定的入口檔案內容\n\n若使用 `--dry-run`，程式在此階段印出檔案樹後即結束，不會呼叫 Claude。\n\n---\n\n### Phase 2：產生文件目錄（Catalog）\n\n這是第一次呼叫 Claude CLI 的時機。若輸出目錄中已有 `_catalog.json`（即非 `--clean` 模式），selfmd 會優先載入既有目錄以節省費用：\n\n```go\nif !clean {\n    catJSON, readErr := g.Writer.ReadCatalogJSON()\n    if readErr == nil {\n        cat, err = catalog.Parse(catJSON)\n    }\n    if cat != nil {\n        items := cat.Flatten()\n        fmt.Printf(ui.T(\"[2/4] 載入已存目錄（%d 個章節，%d 個項目）\\n\", ...))\n    }\n}\nif cat == nil {\n    fmt.Println(ui.T(\"[2/4] 產生文件目錄...\", \"[2/4] Generating catalog...\"))\n    cat, err = g.GenerateCatalog(ctx, scan)\n    // ...\n    if err := g.Writer.WriteCatalogJSON(cat); err != nil { ... }\n}\n```\n\n\u003e 來源：`internal/generator/pipeline.go#L103-L128`\n\n產生的目錄 JSON 儲存至 `.doc-build/_catalog.json`，供後續增量更新使用。\n\n---\n\n### Phase 3：並行產生內容頁面\n\n這是最耗時的階段。selfmd 使用 `errgroup` 與 semaphore（信號量）控制並行度：\n\n```go\nconcurrency := g.Config.Claude.MaxConcurrent\nif opts.Concurrency \u003e 0 {\n    concurrency = opts.Concurrency\n}\nfmt.Printf(ui.T(\"[3/4] 產生內容頁面（並行度：%d）...\\n\", ...), concurrency)\nif err := g.GenerateContent(ctx, scan, cat, concurrency, !clean); err != nil {\n    g.Logger.Warn(ui.T(\"部分頁面產生失敗\", \"some pages failed to generate\"), \"error\", err)\n}\n```\n\n\u003e 來源：`internal/generator/pipeline.go#L131-L138`\n\n每個文件頁面對應一次 Claude CLI 呼叫。若頁面已存在（非 `--clean` 模式），會自動跳過：\n\n```go\nif skipExisting \u0026\u0026 g.Writer.PageExists(item) {\n    skipped.Add(1)\n    fmt.Printf(ui.T(\"      [跳過] %s（已存在）\\n\", ...), item.Title)\n    return nil\n}\n```\n\n\u003e 來源：`internal/generator/content_phase.go#L44-L48`\n\n若某頁面產生失敗，selfmd **不會中止整個流程**，而是寫入佔位頁面並繼續其他頁面。\n\n---\n\n### Phase 4：產生索引與導航\n\n最後階段產生三類輸出：\n\n```go\n// 主索引頁\nindexContent := output.GenerateIndex(...)\ng.Writer.WriteFile(\"index.md\", indexContent)\n\n// 側邊欄導航\nsidebarContent := output.GenerateSidebar(...)\ng.Writer.WriteFile(\"_sidebar.md\", sidebarContent)\n\n// 有子頁面的分類索引\nfor _, item := range items {\n    if !item.HasChildren { continue }\n    categoryContent := output.GenerateCategoryIndex(item, children, lang)\n    g.Writer.WritePage(item, categoryContent)\n}\n```\n\n\u003e 來源：`internal/generator/index_phase.go#L14-L53`\n\n---\n\n## 指令旗標\n\n| 旗標 | 預設值 | 說明 |\n|------|--------|------|\n| `--clean` | `false` | 強制清除輸出目錄後重新產生 |\n| `--no-clean` | `false` | 忽略設定檔中的 `clean_before_generate`，保留現有文件 |\n| `--dry-run` | `false` | 只掃描並印出檔案樹，不呼叫 Claude |\n| `--concurrency N` | `0`（使用設定檔值） | 覆蓋 `claude.max_concurrent`，指定並行數量 |\n\n```go\ngenerateCmd.Flags().BoolVar(\u0026cleanFlag, \"clean\", false, \"強制清除輸出目錄\")\ngenerateCmd.Flags().BoolVar(\u0026noCleanFlag, \"no-clean\", false, \"不清除輸出目錄\")\ngenerateCmd.Flags().BoolVar(\u0026dryRun, \"dry-run\", false, \"只顯示計畫，不實際執行\")\ngenerateCmd.Flags().IntVar(\u0026concurrencyNum, \"concurrency\", 0, \"並行度（覆蓋設定檔）\")\n```\n\n\u003e 來源：`cmd/generate.go#L34-L39`\n\n---\n\n## 輸出結構\n\n完成後，`.doc-build/` 目錄結構如下：\n\n```\n.doc-build/\n├── index.md              ← 主索引（Phase 4）\n├── index.html            ← 靜態 HTML 瀏覽器入口\n├── _sidebar.md           ← 側邊欄導航（Phase 4）\n├── _catalog.json         ← 文件目錄快取（供增量更新使用）\n├── _last_commit          ← Git commit 記錄（供增量更新使用）\n├── _data.js              ← 靜態瀏覽器的資料 bundle\n├── \u003csection\u003e/\n│   └── \u003cpage\u003e/\n│       └── index.md      ← 各文件頁面（Phase 3）\n└── ...\n```\n\n---\n\n## 完成摘要\n\n產生成功後，終端機顯示類似以下的摘要：\n\n```\n========================================\n文件產生完成！\n  輸出目錄：.doc-build\n  頁面數量：42 成功\n  總耗時：3m25s\n  總費用：$0.1234 USD\n========================================\n```\n\n\u003e 來源：`internal/generator/pipeline.go#L168-L180`\n\n開啟 `.doc-build/index.html` 即可在瀏覽器中瀏覽完整文件。\n\n---\n\n## 常見問題\n\n**Q：執行後部分頁面顯示「此頁面產生失敗」**\n\n這是正常的保護機制，失敗的頁面會寫入佔位內容。重新執行 `selfmd generate`（不加 `--clean`），程式會自動跳過已完成的頁面，只重新產生失敗的頁面。\n\n**Q：想要完全重新產生所有頁面**\n\n執行 `selfmd generate --clean`，清除輸出目錄後從頭重新產生。\n\n**Q：如何加快產生速度**\n\n增加 `--concurrency` 的數值（例如 `--concurrency 8`）可以提高並行度，但需留意 Claude CLI 的 API 速率限制。\n\n---\n\n## 相關連結\n\n- [安裝與建置](../installation/index.md)\n- [初始化設定](../init/index.md)\n- [selfmd generate 指令完整參考](../../cli/cmd-generate/index.md)\n- [selfmd.yaml 結構總覽](../../configuration/config-overview/index.md)\n- [整體流程與四階段管線](../../architecture/pipeline/index.md)\n- [輸出結構說明](../../overview/output-structure/index.md)\n- [增量更新](../../core-modules/incremental-update/index.md)\n\n---\n\n## 參考檔案\n\n| 檔案路徑 | 說明 |\n|----------|------|\n| `cmd/generate.go` | `generate` 指令定義、旗標宣告、`runGenerate` 進入點 |\n| `internal/generator/pipeline.go` | `Generator` 結構、`Generate()` 四階段主流程 |\n| `internal/generator/catalog_phase.go` | Phase 2：呼叫 Claude 產生文件目錄 |\n| `internal/generator/content_phase.go` | Phase 3：並行產生內容頁面 |\n| `internal/generator/index_phase.go` | Phase 4：產生索引、側邊欄與分類索引 |\n| `internal/config/config.go` | `Config` 結構定義、預設值與 `Load()` 邏輯 |\n| `internal/scanner/scanner.go` | 專案目錄掃描邏輯 |\n| `internal/output/writer.go` | `Writer` 結構、頁面寫入與狀態儲存 |\n| `cmd/init.go` | `init` 指令，了解前置條件 |","getting-started/index.md":"# 快速開始\n\nThis section contains the following:\n\n- [安裝與建置](installation/index.md)\n- [初始化設定](init/index.md)\n- [產生第一份文件](first-run/index.md)\n","getting-started/init/index.md":"# 初始化設定\n\n執行 `selfmd init` 指令，自動掃描當前目錄、偵測專案類型，並產生 `selfmd.yaml` 設定檔，為後續文件產生流程建立基礎設定。\n\n## 概述\n\n`selfmd init` 是使用 selfmd 的第一個步驟。它透過分析目錄中的特徵檔案（如 `go.mod`、`package.json`、`requirements.txt` 等）來自動判斷專案類型，並產生一份預填好合理預設值的 `selfmd.yaml` 設定檔。\n\n初始化完成後，使用者只需根據需求微調設定檔，即可執行 `selfmd generate` 開始產生文件。\n\n**核心職責：**\n- 偵測專案類型（`backend`、`frontend`、`fullstack`、`library`）\n- 推斷常見的入口點檔案路徑（entry points）\n- 以預設值填充完整的 `Config` 結構並序列化為 YAML\n\n## 架構\n\n```mermaid\nflowchart TD\n    User[\"使用者執行 selfmd init\"]\n    CheckExist{\"selfmd.yaml\\n已存在？\"}\n    ForceFlag{\"--force\\n旗標？\"}\n    Error[\"回傳錯誤\\n（請用 --force 覆蓋）\"]\n    DefaultCfg[\"config.DefaultConfig()\\n建立預設設定\"]\n    Detect[\"detectProject()\\n掃描特徵檔案\"]\n    SetFields[\"填入\\nProject.Type / Name / EntryPoints\"]\n    Save[\"cfg.Save(cfgFile)\\n寫入 selfmd.yaml\"]\n    Print[\"印出初始化摘要資訊\"]\n\n    User --\u003e CheckExist\n    CheckExist -- 否 --\u003e DefaultCfg\n    CheckExist -- 是 --\u003e ForceFlag\n    ForceFlag -- 是 --\u003e DefaultCfg\n    ForceFlag -- 否 --\u003e Error\n    DefaultCfg --\u003e Detect\n    Detect --\u003e SetFields\n    SetFields --\u003e Save\n    Save --\u003e Print\n```\n\n## 專案類型偵測\n\n`detectProject()` 函式依序檢查目錄中是否存在以下特徵檔案，並對應到專案類型與建議的入口點清單：\n\n| 特徵檔案 | 專案類型 | 建議入口點 |\n|----------|----------|------------|\n| `go.mod` | `backend` | `main.go`, `cmd/root.go` |\n| `Cargo.toml` | `backend` | `src/main.rs`, `src/lib.rs` |\n| `package.json` | `frontend` | `src/index.ts`, `src/index.js`, `src/main.ts`, `src/App.tsx` |\n| `pom.xml` | `backend` | `src/main/java` |\n| `build.gradle` | `backend` | `src/main/java` |\n| `requirements.txt` | `backend` | `main.py`, `app.py`, `src/main.py` |\n| `pyproject.toml` | `backend` | `src/main.py`, `main.py` |\n| `composer.json` | `backend` | `public/index.php`, `src/Kernel.php` |\n| `Gemfile` | `backend` | `config/application.rb`, `app/` |\n| （無符合） | `library` | （空） |\n\n**fullstack 特例：** 若偵測到 `package.json`（frontend），但同時存在 `go.mod` 或 `server/` 目錄，則自動升級為 `fullstack` 類型。\n\n```go\n// check if frontend project also has backend\nif c.pType == \"frontend\" {\n    if _, err := os.Stat(\"go.mod\"); err == nil {\n        return \"fullstack\", found\n    }\n    if _, err := os.Stat(\"server\"); err == nil {\n        return \"fullstack\", found\n    }\n}\n```\n\n\u003e 來源：cmd/init.go#L87-L94\n\n偵測到特徵檔案後，函式只保留**實際存在於磁碟上**的入口點檔案，不會寫入不存在的路徑。\n\n## 預設設定值\n\n`config.DefaultConfig()` 產生的初始設定包含以下預設值：\n\n```go\nfunc DefaultConfig() *Config {\n    return \u0026Config{\n        Project: ProjectConfig{\n            Name: filepath.Base(mustGetwd()),\n            Type: \"backend\",\n        },\n        Targets: TargetsConfig{\n            Include: []string{\"src/**\", \"pkg/**\", \"cmd/**\", \"internal/**\", \"lib/**\", \"app/**\"},\n            Exclude: []string{\n                \"vendor/**\", \"node_modules/**\", \".git/**\", \".doc-build/**\",\n                \"**/*.pb.go\", \"**/generated/**\", \"dist/**\", \"build/**\",\n            },\n            EntryPoints: []string{},\n        },\n        Output: OutputConfig{\n            Dir:                 \".doc-build\",\n            Language:            \"zh-TW\",\n            SecondaryLanguages:  []string{},\n            CleanBeforeGenerate: false,\n        },\n        Claude: ClaudeConfig{\n            Model:          \"sonnet\",\n            MaxConcurrent:  3,\n            TimeoutSeconds: 300,\n            MaxRetries:     2,\n            AllowedTools:   []string{\"Read\", \"Glob\", \"Grep\"},\n            ExtraArgs:      []string{},\n        },\n        Git: GitConfig{\n            Enabled:    true,\n            BaseBranch: \"main\",\n        },\n    }\n}\n```\n\n\u003e 來源：internal/config/config.go#L96-L129\n\n## 設定檔結構\n\n`selfmd.yaml` 由五個頂層區塊組成，對應 `Config` 結構體的欄位：\n\n```mermaid\nerDiagram\n    Config {\n        ProjectConfig project\n        TargetsConfig targets\n        OutputConfig  output\n        ClaudeConfig  claude\n        GitConfig     git\n    }\n    ProjectConfig {\n        string name\n        string type\n        string description\n    }\n    TargetsConfig {\n        string[] include\n        string[] exclude\n        string[] entry_points\n    }\n    OutputConfig {\n        string dir\n        string language\n        string[] secondary_languages\n        bool   clean_before_generate\n    }\n    ClaudeConfig {\n        string model\n        int    max_concurrent\n        int    timeout_seconds\n        int    max_retries\n        string[] allowed_tools\n        string[] extra_args\n    }\n    GitConfig {\n        bool   enabled\n        string base_branch\n    }\n    Config ||--|| ProjectConfig : \"project\"\n    Config ||--|| TargetsConfig : \"targets\"\n    Config ||--|| OutputConfig  : \"output\"\n    Config ||--|| ClaudeConfig  : \"claude\"\n    Config ||--|| GitConfig     : \"git\"\n```\n\n## 核心流程\n\n```mermaid\nsequenceDiagram\n    participant U as 使用者\n    participant Init as runInit()\n    participant OS as os.Stat()\n    participant CFG as config.DefaultConfig()\n    participant Detect as detectProject()\n    participant Save as cfg.Save()\n\n    U-\u003e\u003eInit: selfmd init [--force]\n    Init-\u003e\u003eOS: 檢查 selfmd.yaml 是否存在\n    alt 已存在且無 --force\n        Init--\u003e\u003eU: 錯誤：請使用 --force 覆蓋\n    else 不存在或有 --force\n        Init-\u003e\u003eCFG: 建立預設 Config\n        CFG--\u003e\u003eInit: *Config（含所有預設值）\n        Init-\u003e\u003eDetect: 掃描特徵檔案\n        Detect-\u003e\u003eOS: 依序 os.Stat() 各特徵檔案\n        Detect--\u003e\u003eInit: projectType, entryPoints\n        Init-\u003e\u003eInit: 覆寫 Project.Type / Name / EntryPoints\n        Init-\u003e\u003eSave: yaml.Marshal + os.WriteFile\n        Save--\u003e\u003eInit: 寫入成功\n        Init--\u003e\u003eU: 印出摘要（專案名稱、類型、輸出目錄等）\n    end\n```\n\n## 指令用法\n\n### 基本初始化\n\n```bash\nselfmd init\n```\n\n在當前目錄產生 `selfmd.yaml`。若檔案已存在，指令會中止並提示錯誤。\n\n### 強制覆蓋\n\n```bash\nselfmd init --force\n```\n\n使用 `--force` 旗標可覆蓋已存在的設定檔。\n\n\u003e 來源：cmd/init.go#L23-L26\n\n### 指定設定檔路徑\n\n```bash\nselfmd init --config path/to/custom.yaml\n```\n\n透過全域 `--config`（或 `-c`）旗標可指定輸出路徑，預設為 `selfmd.yaml`。\n\n\u003e 來源：cmd/root.go#L33\n\n## 初始化後的設定調整\n\n產生的 `selfmd.yaml` 包含合理的預設值，常見需要調整的設定包括：\n\n| 設定項目 | 預設值 | 說明 |\n|----------|--------|------|\n| `project.description` | （空） | 加入專案描述以改善 AI 文件品質 |\n| `targets.include` | 常見目錄 glob | 根據實際專案結構調整掃描範圍 |\n| `output.language` | `zh-TW` | 主要文件語言 |\n| `output.secondary_languages` | `[]` | 加入多語言輸出，如 `[\"en-US\"]` |\n| `claude.max_concurrent` | `3` | 調整並發數以平衡速度與資源消耗 |\n| `git.base_branch` | `main` | 依專案實際主分支名稱調整 |\n\n設定說明請參考「[selfmd.yaml 結構總覽](../../configuration/config-overview/index.md)」。\n\n## 設定驗證規則\n\n載入設定時，`validate()` 函式會強制執行以下規則：\n\n```go\nfunc (c *Config) validate() error {\n    if c.Output.Dir == \"\" {\n        return fmt.Errorf(\"output.dir 不可為空\")\n    }\n    if c.Output.Language == \"\" {\n        return fmt.Errorf(\"output.language 不可為空\")\n    }\n    if c.Claude.MaxConcurrent \u003c 1 {\n        c.Claude.MaxConcurrent = 1\n    }\n    if c.Claude.TimeoutSeconds \u003c 30 {\n        c.Claude.TimeoutSeconds = 30\n    }\n    if c.Claude.MaxRetries \u003c 0 {\n        c.Claude.MaxRetries = 0\n    }\n    return nil\n}\n```\n\n\u003e 來源：internal/config/config.go#L157-L174\n\n- `output.dir` 與 `output.language` 為必填欄位\n- `claude.max_concurrent` 最小值為 `1`\n- `claude.timeout_seconds` 最小值為 `30`\n- `claude.max_retries` 不可為負數\n\n## 相關連結\n\n- [安裝與建置](../installation/index.md) — 執行 `selfmd init` 前的安裝步驟\n- [產生第一份文件](../first-run/index.md) — 初始化完成後的下一步\n- [selfmd init 指令參考](../../cli/cmd-init/index.md) — 完整的指令參數說明\n- [selfmd.yaml 結構總覽](../../configuration/config-overview/index.md) — 各設定欄位的詳細說明\n- [專案與掃描目標設定](../../configuration/project-targets/index.md) — `targets` 區塊的進階設定\n- [輸出與多語言設定](../../configuration/output-language/index.md) — `output` 區塊的語言設定\n\n## 參考檔案\n\n| 檔案路徑 | 說明 |\n|----------|------|\n| `cmd/init.go` | `selfmd init` 指令實作，含 `runInit()` 與 `detectProject()` 函式 |\n| `cmd/root.go` | 根指令定義，全域旗標（`--config`、`--force` 等）宣告 |\n| `internal/config/config.go` | `Config` 結構體定義、`DefaultConfig()`、`Load()`、`Save()`、`validate()` 實作 |","getting-started/installation/index.md":"# 安裝與建置\n\n本頁說明如何取得 selfmd 的原始碼、編譯執行檔，以及確認執行環境的前置需求。\n\n## 概述\n\nselfmd 是以 Go 語言撰寫的 CLI 工具，需要在本機自行編譯後使用。由於 selfmd 以本地 Claude Code CLI 作為 AI 後端，因此**同時需要 Go 工具鏈與 Claude Code CLI** 兩項前置需求才能正常運作。\n\n核心術語說明：\n- **Claude Code CLI**：Anthropic 官方提供的本地 AI 代理程式，selfmd 透過子行程（subprocess）方式呼叫其 `claude` 指令\n- **交叉編譯（Cross-compilation）**：在一個平台上編譯出其他平台可執行的二進位檔案\n\n## 前置需求\n\n| 需求 | 最低版本 | 說明 |\n|------|---------|------|\n| Go 工具鏈 | 1.25+ | 用於編譯 selfmd 原始碼 |\n| Claude Code CLI | 最新版 | selfmd 於執行期透過 `claude` 指令呼叫 |\n\n### Claude Code CLI 的驗證機制\n\nselfmd 在每次執行 `generate`、`update`、`translate` 等指令時，會先呼叫 `CheckAvailable()` 確認 `claude` 已安裝並可在 `PATH` 中找到：\n\n```go\n// CheckAvailable verifies that the claude CLI is installed and accessible.\nfunc CheckAvailable() error {\n\t_, err := exec.LookPath(\"claude\")\n\tif err != nil {\n\t\treturn fmt.Errorf(\"找不到 claude CLI。請先安裝 Claude Code：https://docs.anthropic.com/en/docs/claude-code\")\n\t}\n\treturn nil\n}\n```\n\n\u003e 來源：`internal/claude/runner.go#L146-L152`\n\n## 架構\n\n以下圖表說明 selfmd 的安裝組成及各元件間的依賴關係：\n\n```mermaid\nflowchart TD\n    subgraph 前置需求[\"前置需求\"]\n        GoSDK[\"Go 1.25+\\n工具鏈\"]\n        ClaudeCLI[\"Claude Code CLI\\n（claude 指令）\"]\n    end\n\n    subgraph 建置流程[\"建置流程\"]\n        Source[\"原始碼\\ngithub.com/monkenwu/selfmd\"]\n        GoBuild[\"go build\"]\n        Binary[\"selfmd\\n執行檔\"]\n    end\n\n    subgraph 相依套件[\"Go 相依套件（go.mod）\"]\n        Cobra[\"cobra v1.10.2\\nCLI 框架\"]\n        YAML[\"yaml.v3\\n設定檔解析\"]\n        Sync[\"golang.org/x/sync\\n並行控制\"]\n        Doublestar[\"doublestar/v4\\nGlob 比對\"]\n    end\n\n    GoSDK --\u003e GoBuild\n    Source --\u003e GoBuild\n    GoBuild --\u003e Binary\n    Cobra --\u003e Source\n    YAML --\u003e Source\n    Sync --\u003e Source\n    Doublestar --\u003e Source\n\n    Binary --\u003e|\"執行期呼叫\"| ClaudeCLI\n```\n\n## Go 相依套件說明\n\nselfmd 的相依套件定義於 `go.mod`，共四個直接相依：\n\n```\nmodule github.com/monkenwu/selfmd\n\ngo 1.25.7\n\nrequire (\n\tgithub.com/bmatcuk/doublestar/v4 v4.10.0\n\tgithub.com/spf13/cobra v1.10.2\n\tgolang.org/x/sync v0.19.0\n\tgopkg.in/yaml.v3 v3.0.1\n)\n```\n\n\u003e 來源：`go.mod#L1-L10`\n\n| 套件 | 版本 | 用途 |\n|------|------|------|\n| `github.com/spf13/cobra` | v1.10.2 | CLI 指令框架，管理所有子指令（init、generate、update、translate） |\n| `gopkg.in/yaml.v3` | v3.0.1 | 解析與寫入 `selfmd.yaml` 設定檔 |\n| `golang.org/x/sync` | v0.19.0 | 並行文件產生時的協程同步控制 |\n| `github.com/bmatcuk/doublestar/v4` | v4.10.0 | 支援 `**` 萬用字元的 Glob 路徑比對，用於掃描目標設定 |\n\n## 編譯步驟\n\n### 取得原始碼\n\n```bash\ngit clone https://github.com/monkenwu/selfmd.git\ncd selfmd\n```\n\n### 編譯當前平台\n\n```bash\ngo build -o selfmd .\n```\n\n\u003e 來源：`README.md#L18-L19`\n\n### 交叉編譯（Cross-compilation）\n\nselfmd 支援交叉編譯至多個平台，只需設定 `GOOS` 與 `GOARCH` 環境變數：\n\n```bash\n# Linux arm64\nGOOS=linux GOARCH=arm64 go build -o ./bin/selfmd-linux-arm64\n\n# Linux amd64\nGOOS=linux GOARCH=amd64 go build -o ./bin/selfmd-linux-amd64\n\n# macOS arm64（Apple Silicon）\nGOOS=darwin GOARCH=arm64 go build -o ./bin/selfmd-macos-arm64\n\n# macOS amd64（Intel）\nGOOS=darwin GOARCH=amd64 go build -o ./bin/selfmd-macos-amd64\n\n# Windows amd64\nGOOS=windows GOARCH=amd64 go build -o ./bin/selfmd-windows-amd64.exe\n\n# Windows arm64\nGOOS=windows GOARCH=arm64 go build -o ./bin/selfmd-windows-arm64.exe\n```\n\n\u003e 來源：`README.md#L21-L31`\n\n## 核心流程\n\n```mermaid\nsequenceDiagram\n    participant 使用者\n    participant GoBuild as go build\n    participant selfmd as selfmd 執行檔\n    participant CheckAvailable as CheckAvailable()\n    participant ClaudeCLI as claude CLI\n\n    使用者-\u003e\u003eGoBuild: go build -o selfmd .\n    GoBuild--\u003e\u003eselfmd: 編譯完成\n\n    使用者-\u003e\u003eselfmd: selfmd generate\n    selfmd-\u003e\u003eCheckAvailable: 確認 claude 可用\n    CheckAvailable-\u003e\u003eClaudeCLI: exec.LookPath(\"claude\")\n    alt claude 已安裝\n        ClaudeCLI--\u003e\u003eCheckAvailable: 路徑存在\n        CheckAvailable--\u003e\u003eselfmd: nil（無錯誤）\n        selfmd-\u003e\u003eselfmd: 繼續執行文件產生流程\n    else claude 未安裝\n        ClaudeCLI--\u003e\u003eCheckAvailable: 找不到執行檔\n        CheckAvailable--\u003e\u003eselfmd: 回傳錯誤訊息\n        selfmd--\u003e\u003e使用者: 提示安裝 Claude Code\n    end\n```\n\n## 使用範例\n\n### 驗證安裝\n\n編譯完成後，可使用以下指令確認 selfmd 正常運作：\n\n```bash\n./selfmd --help\n```\n\n輸出應顯示：\n\n```\nselfmd — 專案文件自動產生器\n\nselfmd 是一個 CLI 工具，透過本地 Claude Code CLI 作為 AI 後端，\n自動掃描專案目錄並產生結構化的 Wiki 風格繁體中文技術文件。\n...\n```\n\n\u003e 來源：`cmd/root.go#L17-L25`\n\n### 全域旗標\n\nselfmd 提供三個全域旗標，可與任何子指令搭配使用：\n\n```go\nrootCmd.PersistentFlags().StringVarP(\u0026cfgFile, \"config\", \"c\", \"selfmd.yaml\", \"設定檔路徑\")\nrootCmd.PersistentFlags().BoolVarP(\u0026verbose, \"verbose\", \"v\", false, \"顯示詳細輸出\")\nrootCmd.PersistentFlags().BoolVarP(\u0026quiet, \"quiet\", \"q\", false, \"僅顯示錯誤訊息\")\n```\n\n\u003e 來源：`cmd/root.go#L33-L35`\n\n| 旗標 | 簡寫 | 預設值 | 說明 |\n|------|------|--------|------|\n| `--config` | `-c` | `selfmd.yaml` | 指定設定檔路徑 |\n| `--verbose` | `-v` | `false` | 顯示詳細的 debug 輸出 |\n| `--quiet` | `-q` | `false` | 僅顯示錯誤訊息，抑制一般輸出 |\n\n## 程式進入點\n\nselfmd 的程式進入點位於根目錄的 `main.go`，直接委派給 `cmd.Execute()`：\n\n```go\npackage main\n\nimport (\n\t\"os\"\n\n\t\"github.com/monkenwu/selfmd/cmd\"\n)\n\nfunc main() {\n\tif err := cmd.Execute(); err != nil {\n\t\tos.Exit(1)\n\t}\n}\n```\n\n\u003e 來源：`main.go#L1-L13`\n\n## 相關連結\n\n- [快速開始](../index.md) — 快速開始總覽\n- [初始化設定](../init/index.md) — 編譯完成後，執行 `selfmd init` 建立設定檔的步驟說明\n- [產生第一份文件](../first-run/index.md) — 完成安裝後產生第一份文件的完整流程\n- [selfmd init 指令參考](../../cli/cmd-init/index.md) — init 指令的完整旗標與行為說明\n- [selfmd generate 指令參考](../../cli/cmd-generate/index.md) — generate 指令的完整旗標與行為說明\n- [selfmd.yaml 結構總覽](../../configuration/config-overview/index.md) — 設定檔各欄位的詳細說明\n- [Claude CLI 整合設定](../../configuration/claude-config/index.md) — 設定 Claude 模型、並行度、逾時等參數\n\n## 參考檔案\n\n| 檔案路徑 | 說明 |\n|----------|------|\n| `main.go` | 程式進入點，委派給 `cmd.Execute()` |\n| `go.mod` | Go 模組定義與相依套件版本 |\n| `README.md` | 專案說明文件，包含安裝與建置指令 |\n| `cmd/root.go` | 根指令定義、全域旗標與 `Execute()` 函式 |\n| `cmd/init.go` | `init` 子指令實作，包含專案類型偵測邏輯 |\n| `cmd/generate.go` | `generate` 子指令實作，呼叫 `CheckAvailable()` 驗證 Claude CLI |\n| `internal/claude/runner.go` | `CheckAvailable()` 函式，驗證 `claude` 指令是否存在於 PATH |\n| `internal/config/config.go` | `Config` 結構定義、預設值與 `Load()`/`Save()` 函式 |","git-integration/affected-pages/index.md":"# 受影響頁面判斷邏輯\n\n在 `selfmd update` 執行過程中，系統需要分兩條路徑判斷哪些文件頁面應被更新，以及哪些新頁面需要建立。本頁面說明這套判斷邏輯的實作原理與流程。\n\n## 概述\n\n當 git diff 回傳一批變更檔案後，`Update()` 函式並不會盲目地重新產生所有文件，而是採用**兩階段判斷策略**：\n\n1. **文字比對（精確匹配）**：先搜尋現有文件內容中是否直接提及變更的原始碼檔案路徑，將變更檔案分為「已匹配」與「未匹配」兩類。\n2. **Claude AI 語意判斷**：對兩類檔案分別呼叫 Claude，由 AI 閱讀實際變更並做出最終決策——哪些已匹配頁面真正需要更新？哪些未匹配檔案需要建立新頁面？\n\n這套設計的核心原則是「保守更新」：只有在程式碼變更確實影響文件所描述的行為、架構或 API 時，才觸發重新產生。\n\n---\n\n## 架構\n\n### 整體判斷流程\n\n```mermaid\nflowchart TD\n    A[\"git.ParseChangedFiles()\"] --\u003e B[\"matchChangedFilesToDocs()\"]\n    B --\u003e C{文件內容是否提及此檔案路徑?}\n    C --\u003e|\"是 → matched\"| D[\"determineMatchedUpdates()\"]\n    C --\u003e|\"否 → unmatched\"| E[\"determineUnmatchedPages()\"]\n\n    D --\u003e F[\"Claude\\nupdate_matched.tmpl\"]\n    E --\u003e G[\"Claude\\nupdate_unmatched.tmpl\"]\n\n    F --\u003e H[\"需要重新產生的頁面清單\\n[]UpdateMatchedResult\"]\n    G --\u003e I[\"需要新建的頁面清單\\n[]UpdateUnmatchedResult\"]\n\n    H --\u003e J[\"generateSinglePage()\"]\n    I --\u003e K[\"addItemToCatalog()\"]\n    K --\u003e L{\"原葉節點變為父節點?\"}\n    L --\u003e|是| M[\"promotedLeaf\\n內容移至 overview 子頁面\"]\n    L --\u003e|否| J\n    M --\u003e J\n```\n\n### 資料型別關係\n\n```mermaid\nerDiagram\n    matchResult {\n        string changedFile \"變更的原始碼路徑\"\n        FlatItem_array pages \"引用此檔案的文件頁面\"\n    }\n    UpdateMatchedResult {\n        string catalogPath \"文件路徑（點分隔）\"\n        string title \"頁面標題\"\n        string reason \"需要重新產生的原因\"\n    }\n    UpdateUnmatchedResult {\n        string catalogPath \"新頁面路徑（點分隔）\"\n        string title \"新頁面標題\"\n        string reason \"需要新增的原因\"\n    }\n    promotedLeaf {\n        string OriginalPath \"原葉節點路徑\"\n        string OverviewPath \"新 overview 子頁面路徑\"\n        string OriginalTitle \"原葉節點標題\"\n    }\n    matchResult ||--o{ UpdateMatchedResult : \"Claude 過濾後產生\"\n    UpdateUnmatchedResult ||--o| promotedLeaf : \"可能觸發葉節點升級\"\n```\n\n---\n\n## 第一階段：文字比對（matchChangedFilesToDocs）\n\n`matchChangedFilesToDocs()` 透過搜尋現有文件頁面內容是否包含變更檔案的路徑字串，進行初步過濾。\n\n```go\n// For each changed file, find which pages reference it\nfor _, f := range files {\n    var matchedPages []catalog.FlatItem\n    for _, item := range items {\n        content, ok := pageContents[item.Path]\n        if !ok {\n            continue\n        }\n        if strings.Contains(content, f.Path) {\n            matchedPages = append(matchedPages, item)\n        }\n    }\n\n    if len(matchedPages) \u003e 0 {\n        matched = append(matched, matchResult{\n            changedFile: f.Path,\n            pages:       matchedPages,\n        })\n    } else {\n        unmatched = append(unmatched, f.Path)\n    }\n}\n```\n\n\u003e 來源：internal/generator/updater.go#L191-L213\n\n**關鍵設計決策**：\n\n- 使用 `strings.Contains(content, f.Path)` 做字串匹配，而非 glob 或正規表達式，簡單可靠\n- 預先讀取所有頁面內容到 `pageContents` map，避免重複 I/O\n- 一個變更檔案可對應多個文件頁面；相同頁面也可被多個變更檔案匹配（後續去重）\n\n---\n\n## 第二階段 A：判斷已匹配頁面是否需要更新（determineMatchedUpdates）\n\n針對「已匹配」的檔案，`determineMatchedUpdates()` 建構包含變更檔案清單與受影響頁面摘要的 prompt，傳給 Claude 判斷。\n\n### Prompt 資料組裝\n\n```go\ndata := prompt.UpdateMatchedPromptData{\n    RepositoryName: g.Config.Project.Name,\n    Language:       g.Config.Output.Language,\n    ChangedFiles:   changedFilesList.String(),\n    AffectedPages:  affectedPagesInfo.String(),\n}\n\nrendered, err := g.Engine.RenderUpdateMatched(data)\n```\n\n\u003e 來源：internal/generator/updater.go#L257-L265\n\n`AffectedPages` 包含每個可能受影響頁面的標題、catalogPath，以及頁面內容的前 500 字摘要（`content[:500] + \"...\"`），供 Claude 理解當前文件的描述範圍。\n\n### Claude 的判斷標準\n\n`update_matched.tmpl` 明確告知 Claude 以下判斷規則：\n\n| 需要重新產生 | 不需要重新產生 |\n|------------|-------------|\n| 函式簽名或 API 介面變更 | 純粹的程式碼風格調整 |\n| 新增或刪除重要功能 | 不影響對外行為的內部重構 |\n| 架構或流程變更 | 錯誤修正但行為未改變 |\n| 設定格式或選項變更 | 註解或文件字串變更 |\n\n\u003e 來源：internal/prompt/templates/zh-TW/update_matched.tmpl#L40-L46\n\n### Claude 回傳格式\n\nClaude 以 JSON 陣列回傳需要重新產生的頁面：\n\n```go\ntype UpdateMatchedResult struct {\n    CatalogPath string `json:\"catalogPath\"`\n    Title       string `json:\"title\"`\n    Reason      string `json:\"reason\"`\n}\n```\n\n\u003e 來源：internal/generator/updater.go#L18-L22\n\n系統接著將 `CatalogPath` 對應回 `catalog.FlatItem`，若 Claude 回傳了不存在的路徑，會記錄警告並跳過：\n\n```go\nfor _, r := range results {\n    if item, ok := itemMap[r.CatalogPath]; ok {\n        fmt.Printf(\"      → %s：%s\\n\", item.Title, r.Reason)\n        pagesToRegen = append(pagesToRegen, item)\n    } else {\n        g.Logger.Warn(\"Claude 回傳的 catalogPath 不存在\", \"path\", r.CatalogPath)\n    }\n}\n```\n\n\u003e 來源：internal/generator/updater.go#L296-L303\n\n---\n\n## 第二階段 B：判斷未匹配檔案是否需要新頁面（determineUnmatchedPages）\n\n針對「未匹配」（現有文件中沒有提及）的變更檔案，`determineUnmatchedPages()` 問 Claude：這些新增或修改的檔案是否代表需要建立新文件頁面的功能？\n\n### Prompt 資料組裝\n\n```go\ndata := prompt.UpdateUnmatchedPromptData{\n    RepositoryName:  g.Config.Project.Name,\n    Language:        g.Config.Output.Language,\n    UnmatchedFiles:  fileList.String(),\n    ExistingCatalog: existingCatalog,\n    CatalogTable:    cat.BuildLinkTable(),\n}\n```\n\n\u003e 來源：internal/generator/updater.go#L320-L327\n\n`ExistingCatalog` 是完整的目錄 JSON，`CatalogTable` 則是格式化後的頁面列表（用於 prompt 展示），讓 Claude 了解現有文件結構以決定新頁面的位置。\n\n### Claude 的判斷標準\n\n| 需要新頁面 | 不需要新頁面 |\n|-----------|------------|\n| 實作了全新的功能模組或子系統 | 現有模組的輔助檔案（helper、utility）|\n| 新增了重要的 API 端點群組 | 測試檔案 |\n| 引入了新的架構元件或設計模式 | 小型的 bug 修正 |\n| 新增了重要的設定或部署機制 | 邏輯上屬於現有頁面範疇的變更 |\n\n\u003e 來源：internal/prompt/templates/zh-TW/update_unmatched.tmpl#L41-L51\n\n---\n\n## 葉節點升級（Leaf Node Promotion）\n\n當 Claude 決定在現有葉節點（leaf node，即沒有子頁面的文件節點）下新增子頁面時，原葉節點必須轉變為父節點。系統透過 `addItemToCatalog()` 處理這個情況。\n\n### 升級邏輯\n\n```go\nif len(item.Children) == 0 {\n    // This is a leaf node that needs to become a parent.\n    // Add an \"overview\" child to preserve the original content.\n    (*children)[i].Children = append((*children)[i].Children, catalog.CatalogItem{\n        Title: item.Title,\n        Path:  \"overview\",\n        Order: 0,\n    })\n    *promoted = \u0026promotedLeaf{\n        OriginalPath:  currentDotPath,\n        OverviewPath:  currentDotPath + \".overview\",\n        OriginalTitle: item.Title,\n    }\n}\n```\n\n\u003e 來源：internal/generator/updater.go#L402-L415\n\n升級後，原葉節點的現有內容會被搬移至新建的 `overview` 子頁面：\n\n```go\nif content, err := g.Writer.ReadPage(origItem); err == nil \u0026\u0026 content != \"\" {\n    if err := g.Writer.WritePage(overviewItem, content); err != nil {\n        g.Logger.Warn(\"搬移頁面至 overview 失敗\", \"from\", promoted.OriginalPath, \"error\", err)\n    } else {\n        fmt.Printf(\"      → 頁面升級：%s 原內容移至 %s\\n\", promoted.OriginalPath, promoted.OverviewPath)\n    }\n}\n```\n\n\u003e 來源：internal/generator/updater.go#L109-L116\n\n---\n\n## 核心流程\n\n```mermaid\nsequenceDiagram\n    participant Cmd as \"cmd/update.go\"\n    participant Gen as \"Generator.Update()\"\n    participant Match as \"matchChangedFilesToDocs()\"\n    participant Writer as \"output.Writer\"\n    participant ClaudeM as \"Claude (update_matched)\"\n    participant ClaudeU as \"Claude (update_unmatched)\"\n\n    Cmd-\u003e\u003eGen: Update(ctx, scan, prevCommit, curCommit, changedFiles)\n    Gen-\u003e\u003eGen: git.ParseChangedFiles(changedFiles)\n    Gen-\u003e\u003eMatch: matchChangedFilesToDocs(files, cat)\n    Match-\u003e\u003eWriter: ReadPage(item) × N\n    Writer--\u003e\u003eMatch: page content\n    Match-\u003e\u003eMatch: strings.Contains(content, filePath)\n    Match--\u003e\u003eGen: matched[], unmatched[]\n\n    alt len(matched) \u003e 0\n        Gen-\u003e\u003eClaudeM: RenderUpdateMatched(data)\n        ClaudeM--\u003e\u003eGen: []UpdateMatchedResult（需要重新產生的頁面）\n    end\n\n    alt len(unmatched) \u003e 0\n        Gen-\u003e\u003eClaudeU: RenderUpdateUnmatched(data)\n        ClaudeU--\u003e\u003eGen: []UpdateUnmatchedResult（需要新增的頁面）\n        Gen-\u003e\u003eGen: addItemToCatalog() × M\n    end\n\n    Gen-\u003e\u003eGen: generateSinglePage() × (matched + new)\n    Gen-\u003e\u003eWriter: SaveLastCommit(currentCommit)\n```\n\n---\n\n## 使用範例\n\n### 執行 update 指令\n\n```bash\n# 使用上次 generate/update 記錄的 commit 作為基準\nselfmd update\n\n# 指定起始 commit\nselfmd update --since abc1234\n```\n\n### commit 基準選取邏輯\n\n```go\npreviousCommit := sinceCommit\nif previousCommit == \"\" {\n    // Try reading saved commit from last generate/update\n    saved, readErr := gen.Writer.ReadLastCommit()\n    if readErr == nil \u0026\u0026 saved != \"\" {\n        previousCommit = saved\n    } else {\n        // Fallback to merge-base\n        base, err := git.GetMergeBase(rootDir, cfg.Git.BaseBranch)\n        // ...\n        previousCommit = base\n    }\n}\n```\n\n\u003e 來源：cmd/update.go#L68-L82\n\n優先順序：`--since` 參數 → 上次 generate/update 儲存的 commit → merge-base\n\n### 變更檔案篩選\n\n```go\nchangedFiles = git.FilterChangedFiles(changedFiles, cfg.Targets.Include, cfg.Targets.Exclude)\n```\n\n\u003e 來源：cmd/update.go#L94\n\n`FilterChangedFiles()` 使用 doublestar glob 模式對 git diff 輸出進行 include/exclude 篩選，確保只有設定中指定的目標檔案才會觸發文件更新。\n\n---\n\n## 相關連結\n\n- [Git Diff 變更偵測](../change-detection/index.md)\n- [Git 整合與增量更新](../index.md)\n- [增量更新](../../core-modules/incremental-update/index.md)\n- [文件產生管線](../../core-modules/generator/index.md)\n- [Git 整合設定](../../configuration/git-config/index.md)\n- [Prompt 模板引擎](../../core-modules/prompt-engine/index.md)\n\n---\n\n## 參考檔案\n\n| 檔案路徑 | 說明 |\n|----------|------|\n| `internal/generator/updater.go` | 受影響頁面判斷核心邏輯（`matchChangedFilesToDocs`、`determineMatchedUpdates`、`determineUnmatchedPages`、`addItemToCatalog`）|\n| `internal/git/git.go` | Git 操作封裝，包含 `ParseChangedFiles`、`FilterChangedFiles` |\n| `cmd/update.go` | `selfmd update` 指令實作，負責 commit 基準選取與呼叫 `Generator.Update()` |\n| `internal/catalog/catalog.go` | `Catalog`、`FlatItem`、`CatalogItem` 資料結構定義 |\n| `internal/prompt/engine.go` | `UpdateMatchedPromptData`、`UpdateUnmatchedPromptData` 資料結構及 `RenderUpdateMatched`、`RenderUpdateUnmatched` |\n| `internal/prompt/templates/zh-TW/update_matched.tmpl` | Claude 判斷「已匹配頁面是否需要重新產生」的 prompt 模板 |\n| `internal/prompt/templates/zh-TW/update_unmatched.tmpl` | Claude 判斷「未匹配檔案是否需要新頁面」的 prompt 模板 |","git-integration/change-detection/index.md":"# Git Diff 變更偵測\n\n`internal/git` 套件提供與 Git 版本控制系統互動的底層功能，負責偵測兩個提交（commit）之間的檔案變更，並將原始 `git diff` 輸出解析、過濾為結構化資料，供增量更新流程使用。\n\n## 概述\n\n當執行 `selfmd update` 時，系統需要知道「哪些原始碼檔案自上次文件產生以來發生了變更」。這項工作由 `internal/git` 套件全權負責：\n\n- **偵測 Git 環境**：確認當前目錄是否為有效的 Git 倉庫\n- **比對提交範圍**：取得兩個 commit 之間的差異檔案清單\n- **解析原始輸出**：將 `git diff --name-status` 的文字輸出轉換為結構化的 `ChangedFile` 清單\n- **套用過濾規則**：依照設定檔的 `targets.include` 與 `targets.exclude` glob 模式篩選無關檔案\n- **提供 commit 查詢**：取得 HEAD commit hash、merge base 等版本資訊\n\n此套件刻意保持純粹，僅封裝 Git CLI 呼叫，不涉及任何文件產生邏輯。所有複雜的「哪些文件頁面受影響」判斷邏輯，則由上層的 `generator` 套件（`updater.go`）處理。\n\n---\n\n## 架構\n\n```mermaid\nflowchart TD\n    UpdateCmd[\"cmd/update.go\\nrunUpdate()\"]\n    GitPkg[\"internal/git/git.go\"]\n    IsGitRepo[\"IsGitRepo()\"]\n    GetCurrentCommit[\"GetCurrentCommit()\"]\n    GetMergeBase[\"GetMergeBase()\"]\n    GetChangedFiles[\"GetChangedFiles()\"]\n    FilterChangedFiles[\"FilterChangedFiles()\"]\n    ParseChangedFiles[\"ParseChangedFiles()\"]\n    Config[\"GitConfig\\nTargetsConfig\"]\n    Updater[\"generator/updater.go\\nGenerator.Update()\"]\n    runGit[\"runGit() — 內部輔助函式\"]\n\n    UpdateCmd --\u003e|\"1. 驗證 Git 環境\"| IsGitRepo\n    UpdateCmd --\u003e|\"2. 取得 HEAD\"| GetCurrentCommit\n    UpdateCmd --\u003e|\"3a. 取得 merge-base（無儲存 commit 時）\"| GetMergeBase\n    UpdateCmd --\u003e|\"4. 取得變更檔案\"| GetChangedFiles\n    UpdateCmd --\u003e|\"5. 套用過濾規則\"| FilterChangedFiles\n    Config --\u003e|\"include / exclude 模式\"| FilterChangedFiles\n    UpdateCmd --\u003e|\"6. 傳入已過濾的原始文字\"| Updater\n    Updater --\u003e|\"7. 解析為結構化清單\"| ParseChangedFiles\n\n    IsGitRepo --\u003e runGit\n    GetCurrentCommit --\u003e runGit\n    GetMergeBase --\u003e runGit\n    GetChangedFiles --\u003e runGit\n    runGit --\u003e|\"exec.Command(git...)\"| GitCLI[\"git CLI\"]\n```\n\n---\n\n## 核心資料結構\n\n### `ChangedFile`\n\n代表一筆來自 `git diff --name-status` 的檔案變更記錄。\n\n```go\n// ChangedFile represents a single file from git diff --name-status output.\ntype ChangedFile struct {\n\tStatus string // \"M\", \"A\", \"D\", \"R\"\n\tPath   string\n}\n```\n\n\u003e 來源：internal/git/git.go#L47-L51\n\n| 欄位 | 說明 |\n|------|------|\n| `Status` | 變更狀態。`M`＝修改、`A`＝新增、`D`＝刪除、`R`＝重新命名 |\n| `Path` | 相對於工作目錄的檔案路徑；若為重新命名，則為**目標路徑** |\n\n---\n\n## 公開函式說明\n\n### `IsGitRepo(dir string) bool`\n\n確認指定目錄是否位於 Git 倉庫內。執行 `git rev-parse --is-inside-work-tree` 並以指令是否成功作為判斷依據。\n\n```go\nfunc IsGitRepo(dir string) bool {\n\tcmd := exec.Command(\"git\", \"rev-parse\", \"--is-inside-work-tree\")\n\tcmd.Dir = dir\n\terr := cmd.Run()\n\treturn err == nil\n}\n```\n\n\u003e 來源：internal/git/git.go#L13-L18\n\n---\n\n### `GetCurrentCommit(dir string) (string, error)`\n\n回傳當前 `HEAD` 的完整 commit hash（40 位十六進位字元）。\n\n```go\nfunc GetCurrentCommit(dir string) (string, error) {\n\treturn runGit(dir, \"rev-parse\", \"HEAD\")\n}\n```\n\n\u003e 來源：internal/git/git.go#L21-L23\n\n---\n\n### `GetMergeBase(dir, baseBranch string) (string, error)`\n\n找出當前分支與指定基底分支（`baseBranch`）的最近共同祖先 commit。當沒有已儲存的上次 commit 時，此函式作為比對起點的回退方案。\n\n```go\nfunc GetMergeBase(dir, baseBranch string) (string, error) {\n\treturn runGit(dir, \"merge-base\", baseBranch, \"HEAD\")\n}\n```\n\n\u003e 來源：internal/git/git.go#L26-L28\n\n---\n\n### `GetChangedFiles(dir, fromCommit, toCommit string) (string, error)`\n\n取得兩個 commit 之間所有變更檔案的原始文字輸出（`git diff --relative --name-status fromCommit..toCommit`）。\n\n使用 `--relative` 旗標確保路徑相對於工作目錄而非 Git 倉庫根目錄，這在子目錄專案中尤為重要。\n\n```go\nfunc GetChangedFiles(dir, fromCommit, toCommit string) (string, error) {\n\treturn runGit(dir, \"diff\", \"--relative\", \"--name-status\", fromCommit+\"..\"+toCommit)\n}\n```\n\n\u003e 來源：internal/git/git.go#L32-L34\n\n**輸出範例：**\n\n```\nM\tinternal/git/git.go\nA\tinternal/scanner/scanner.go\nD\tcmd/old.go\nR100\tcmd/old_name.go\tcmd/new_name.go\n```\n\n---\n\n### `GetChangedFilesSince(dir, sinceCommit string) (string, error)`\n\n取得指定 commit 至 `HEAD` 之間的所有變更。是 `GetChangedFiles` 的便利包裝，固定將 `HEAD` 作為結束點。\n\n```go\nfunc GetChangedFilesSince(dir, sinceCommit string) (string, error) {\n\treturn runGit(dir, \"diff\", \"--relative\", \"--name-status\", sinceCommit+\"..HEAD\")\n}\n```\n\n\u003e 來源：internal/git/git.go#L38-L40\n\n---\n\n### `ParseChangedFiles(changedFiles string) []ChangedFile`\n\n將 `git diff --name-status` 的原始文字輸出解析為 `[]ChangedFile` 結構化清單。\n\n```go\nfunc ParseChangedFiles(changedFiles string) []ChangedFile {\n\tvar result []ChangedFile\n\tfor _, line := range strings.Split(changedFiles, \"\\n\") {\n\t\tline = strings.TrimSpace(line)\n\t\tif line == \"\" {\n\t\t\tcontinue\n\t\t}\n\t\tparts := strings.SplitN(line, \"\\t\", 3)\n\t\tif len(parts) \u003c 2 {\n\t\t\tcontinue\n\t\t}\n\t\tstatus := string(parts[0][0]) // \"M\", \"A\", \"D\", or \"R\" (R100 → R)\n\t\tpath := parts[len(parts)-1]   // for renames, use destination path\n\t\tresult = append(result, ChangedFile{Status: status, Path: path})\n\t}\n\treturn result\n}\n```\n\n\u003e 來源：internal/git/git.go#L54-L70\n\n**解析規則：**\n\n- 每行以 Tab（`\\t`）分隔，最多切成 3 部分（處理重新命名格式 `R100\\told\\tnew`）\n- 狀態碼取第一個字元（`R100` → `R`）\n- 路徑取最後一個欄位（重新命名時為目標路徑）\n\n---\n\n### `FilterChangedFiles(changedFiles string, includes, excludes []string) string`\n\n依照 `targets.include` 與 `targets.exclude` 設定的 glob 模式，過濾 `git diff --name-status` 的原始文字輸出，回傳符合條件的原始文字（保持相同格式）。\n\n```go\nfunc FilterChangedFiles(changedFiles string, includes, excludes []string) string {\n\tlines := strings.Split(changedFiles, \"\\n\")\n\tvar filtered []string\n\n\tfor _, line := range lines {\n\t\t// ...\n\t\t// Check excludes\n\t\texcluded := false\n\t\tfor _, pattern := range excludes {\n\t\t\tif matched, _ := doublestar.Match(pattern, filePath); matched {\n\t\t\t\texcluded = true\n\t\t\t\tbreak\n\t\t\t}\n\t\t}\n\t\t// Check includes (if configured)\n\t\tif len(includes) \u003e 0 {\n\t\t\tincluded := false\n\t\t\tfor _, pattern := range includes {\n\t\t\t\tif matched, _ := doublestar.Match(pattern, filePath); matched {\n\t\t\t\t\tincluded = true\n\t\t\t\t\tbreak\n\t\t\t\t}\n\t\t\t}\n\t\t\tif !included {\n\t\t\t\tcontinue\n\t\t\t}\n\t\t}\n\t\tfiltered = append(filtered, line)\n\t}\n\treturn strings.Join(filtered, \"\\n\")\n}\n```\n\n\u003e 來源：internal/git/git.go#L73-L122\n\n**過濾優先順序：**\n\n1. 先套用 `excludes`：命中任何 exclude 模式即排除\n2. 再套用 `includes`：若有設定，未命中任何 include 模式則排除\n3. 若 `includes` 為空，則不限制（允許所有非 excluded 的檔案）\n\nGlob 模式比對使用 [`doublestar`](https://github.com/bmatcuk/doublestar) 套件，支援 `**` 雙星號萬用字元。\n\n---\n\n## 核心流程\n\n以下為 `selfmd update` 執行時，Git 變更偵測的完整運作序列：\n\n```mermaid\nsequenceDiagram\n    participant User as 使用者\n    participant UpdateCmd as cmd/update.go\n    participant Git as internal/git/git.go\n    participant Writer as output/writer.go\n    participant Updater as generator/updater.go\n\n    User-\u003e\u003eUpdateCmd: selfmd update [--since \u003ccommit\u003e]\n    UpdateCmd-\u003e\u003eGit: IsGitRepo(rootDir)\n    Git--\u003e\u003eUpdateCmd: true / false\n\n    alt 非 Git 倉庫\n        UpdateCmd--\u003e\u003eUser: 錯誤：當前目錄不是 git 倉庫\n    end\n\n    UpdateCmd-\u003e\u003eWriter: ReadLastCommit()\n    Writer--\u003e\u003eUpdateCmd: previousCommit（或錯誤）\n\n    alt 無已儲存的 commit\n        UpdateCmd-\u003e\u003eGit: GetMergeBase(rootDir, baseBranch)\n        Git--\u003e\u003eUpdateCmd: mergeBaseCommit\n    end\n\n    UpdateCmd-\u003e\u003eGit: GetCurrentCommit(rootDir)\n    Git--\u003e\u003eUpdateCmd: currentCommit（HEAD hash）\n\n    UpdateCmd-\u003e\u003eGit: GetChangedFiles(rootDir, previousCommit, currentCommit)\n    Git--\u003e\u003eUpdateCmd: rawDiff（git diff --name-status 輸出）\n\n    UpdateCmd-\u003e\u003eGit: FilterChangedFiles(rawDiff, includes, excludes)\n    Git--\u003e\u003eUpdateCmd: filteredDiff\n\n    UpdateCmd-\u003e\u003eUpdater: Update(ctx, scan, previousCommit, currentCommit, filteredDiff)\n    Updater-\u003e\u003eGit: ParseChangedFiles(filteredDiff)\n    Git--\u003e\u003eUpdater: []ChangedFile\n\n    Updater-\u003e\u003eUpdater: matchChangedFilesToDocs()\n    Note over Updater: 判斷受影響頁面（詳見受影響頁面判斷邏輯）\n\n    Updater-\u003e\u003eWriter: SaveLastCommit(currentCommit)\n```\n\n---\n\n## 比對起點的選取邏輯\n\n`selfmd update` 的增量比對起點按以下優先順序決定：\n\n```mermaid\nflowchart TD\n    A[\"執行 selfmd update\"] --\u003e B{\"有 --since 旗標？\"}\n    B --\u003e|\"是\"| E[\"使用指定的 commit hash\"]\n    B --\u003e|\"否\"| C{\"ReadLastCommit() 成功？\"}\n    C --\u003e|\"是\"| F[\"使用上次 generate/update 儲存的 commit\"]\n    C --\u003e|\"否\"| D[\"GetMergeBase(baseBranch, HEAD)\"]\n    D --\u003e G[\"使用 merge base commit\"]\n    E --\u003e H[\"GetChangedFiles(previousCommit, currentCommit)\"]\n    F --\u003e H\n    G --\u003e H\n```\n\n| 情境 | 比對起點來源 |\n|------|-------------|\n| 首次更新，已執行過 `generate` | `.doc-build/.last-commit` 中儲存的 commit |\n| 使用 `--since` 旗標 | 使用者指定的 commit hash |\n| 無儲存記錄（回退方案） | `git merge-base \u003cbaseBranch\u003e HEAD` |\n\n---\n\n## 設定參數\n\nGit 變更偵測的行為由 `selfmd.yaml` 中的以下區段控制：\n\n```yaml\ngit:\n  enabled: true\n  base_branch: main   # GetMergeBase() 的基底分支名稱\n\ntargets:\n  include:\n    - \"src/**\"\n    - \"internal/**\"\n  exclude:\n    - \"vendor/**\"\n    - \"**/*.pb.go\"\n    - \".doc-build/**\"\n```\n\n對應的 Go 結構：\n\n```go\ntype GitConfig struct {\n\tEnabled    bool   `yaml:\"enabled\"`\n\tBaseBranch string `yaml:\"base_branch\"`\n}\n```\n\n\u003e 來源：internal/config/config.go#L91-L94\n\n---\n\n## 使用範例\n\n以下為 `cmd/update.go` 中呼叫整個 Git 偵測流程的完整片段：\n\n```go\nif !git.IsGitRepo(rootDir) {\n    return fmt.Errorf(\"當前目錄不是 git 倉庫，無法執行增量更新\")\n}\n\n// Determine comparison commit\npreviousCommit := sinceCommit\nif previousCommit == \"\" {\n    saved, readErr := gen.Writer.ReadLastCommit()\n    if readErr == nil \u0026\u0026 saved != \"\" {\n        previousCommit = saved\n    } else {\n        base, err := git.GetMergeBase(rootDir, cfg.Git.BaseBranch)\n        if err != nil {\n            return fmt.Errorf(\"無法取得基準 commit: %w\\n提示：先執行 selfmd generate 或使用 --since 指定 commit\", err)\n        }\n        previousCommit = base\n    }\n}\n\ncurrentCommit, err := git.GetCurrentCommit(rootDir)\n// ...\n\nchangedFiles, err := git.GetChangedFiles(rootDir, previousCommit, currentCommit)\n// ...\n\nchangedFiles = git.FilterChangedFiles(changedFiles, cfg.Targets.Include, cfg.Targets.Exclude)\n```\n\n\u003e 來源：cmd/update.go#L49-L99\n\n---\n\n## 相關連結\n\n- [Git 整合與增量更新](../index.md)\n- [受影響頁面判斷邏輯](../affected-pages/index.md)\n- [增量更新](../../core-modules/incremental-update/index.md)\n- [selfmd update 指令](../../cli/cmd-update/index.md)\n- [Git 整合設定](../../configuration/git-config/index.md)\n\n---\n\n## 參考檔案\n\n| 檔案路徑 | 說明 |\n|----------|------|\n| `internal/git/git.go` | Git 套件全部實作：IsGitRepo、GetCurrentCommit、GetMergeBase、GetChangedFiles、GetChangedFilesSince、ParseChangedFiles、FilterChangedFiles、runGit |\n| `cmd/update.go` | `selfmd update` 指令實作，展示 Git 套件的完整呼叫流程 |\n| `internal/config/config.go` | `GitConfig`、`TargetsConfig` 結構定義，控制變更偵測行為的設定參數 |\n| `internal/generator/updater.go` | `Generator.Update()` 與 `ParseChangedFiles()` 的使用端，負責將變更檔案清單轉換為受影響文件頁面 |","git-integration/index.md":"# Git 整合與增量更新\n\nThis section contains the following:\n\n- [Git Diff 變更偵測](change-detection/index.md)\n- [受影響頁面判斷邏輯](affected-pages/index.md)\n","i18n/index.md":"# 多語言支援\n\nThis section contains the following:\n\n- [支援的語言與模板](supported-languages/index.md)\n- [翻譯工作流程](translation-workflow/index.md)\n","i18n/supported-languages/index.md":"# 支援的語言與模板\n\nselfmd 透過雙層語言架構支援多語言文件產生：**輸出語言**（11 種）決定文件內容的語言，**模板語言**（2 種）決定 Prompt 指令所使用的語言。\n\n## 概述\n\nselfmd 的多語言支援分為兩個層次：\n\n- **輸出語言（Output Language）**：文件最終呈現的語言。透過 `selfmd.yaml` 中的 `output.language`（主要語言）與 `output.secondary_languages`（次要語言列表）設定。目前系統定義了 11 種已知語言。\n- **模板語言（Template Language）**：Claude CLI 所接收到的 Prompt 指令所用的語言。目前只有 `zh-TW` 與 `en-US` 兩種語言擁有內建模板資料夾；其他語言會自動回退到 `en-US` 模板，並透過 **LanguageOverride** 機制在 Prompt 中加入明確的語言輸出指示。\n\n這種設計讓 selfmd 能支援遠超過模板數量的輸出語言，同時不需要為每種語言維護完整的 Prompt 模板集合。\n\n## 架構\n\n```mermaid\nflowchart TD\n    Config[\"OutputConfig\\n(output.language)\"]\n    GetEffective[\"GetEffectiveTemplateLang()\"]\n    NeedsOverride[\"NeedsLanguageOverride()\"]\n    SupportedTemplateLangs[\"SupportedTemplateLangs\\n[zh-TW, en-US]\"]\n    TemplatezHTW[\"templates/zh-TW/*.tmpl\"]\n    TemplateENUS[\"templates/en-US/*.tmpl\"]\n    SharedTemplate[\"templates/translate.tmpl\\n(共用模板)\"]\n    Engine[\"prompt.Engine\\n.templates\\n.sharedTemplates\"]\n    LangOverridePrompt[\"Prompt 加入語言輸出指示\"]\n    ClaudeRunner[\"claude.Runner\"]\n    KnownLanguages[\"KnownLanguages\\n(11 種語言對照表)\"]\n    GetLangNativeName[\"GetLangNativeName()\"]\n\n    Config --\u003e|設定主要語言| GetEffective\n    GetEffective --\u003e|查詢| SupportedTemplateLangs\n    SupportedTemplateLangs --\u003e|符合 zh-TW| TemplatezHTW\n    SupportedTemplateLangs --\u003e|符合 en-US| TemplateENUS\n    SupportedTemplateLangs --\u003e|不符合，回退| TemplateENUS\n    TemplatezHTW --\u003e Engine\n    TemplateENUS --\u003e Engine\n    SharedTemplate --\u003e Engine\n    Config --\u003e NeedsOverride\n    NeedsOverride --\u003e|true：需要語言覆蓋| LangOverridePrompt\n    LangOverridePrompt --\u003e Engine\n    Engine --\u003e ClaudeRunner\n    KnownLanguages --\u003e GetLangNativeName\n    GetLangNativeName --\u003e|提供母語名稱| Engine\n```\n\n## 已知語言清單\n\n系統在 `KnownLanguages` 對照表中定義了 11 種語言代碼及其母語名稱：\n\n```go\nvar KnownLanguages = map[string]string{\n    \"zh-TW\": \"繁體中文\",\n    \"zh-CN\": \"简体中文\",\n    \"en-US\": \"English\",\n    \"ja-JP\": \"日本語\",\n    \"ko-KR\": \"한국어\",\n    \"fr-FR\": \"Français\",\n    \"de-DE\": \"Deutsch\",\n    \"es-ES\": \"Español\",\n    \"pt-BR\": \"Português\",\n    \"th-TH\": \"ไทย\",\n    \"vi-VN\": \"Tiếng Việt\",\n}\n```\n\n\u003e 來源：internal/config/config.go#L39-L51\n\n| 語言代碼 | 母語名稱 | 有內建模板 | 備註 |\n|---------|---------|-----------|------|\n| `zh-TW` | 繁體中文 | ✅ | 預設主要語言 |\n| `en-US` | English | ✅ | 模板回退語言 |\n| `zh-CN` | 简体中文 | ❌ | 使用 en-US 模板 + LanguageOverride |\n| `ja-JP` | 日本語 | ❌ | 使用 en-US 模板 + LanguageOverride |\n| `ko-KR` | 한국어 | ❌ | 使用 en-US 模板 + LanguageOverride |\n| `fr-FR` | Français | ❌ | 使用 en-US 模板 + LanguageOverride |\n| `de-DE` | Deutsch | ❌ | 使用 en-US 模板 + LanguageOverride |\n| `es-ES` | Español | ❌ | 使用 en-US 模板 + LanguageOverride |\n| `pt-BR` | Português | ❌ | 使用 en-US 模板 + LanguageOverride |\n| `th-TH` | ไทย | ❌ | 使用 en-US 模板 + LanguageOverride |\n| `vi-VN` | Tiếng Việt | ❌ | 使用 en-US 模板 + LanguageOverride |\n\n## 內建模板資料夾\n\n目前只有 `zh-TW` 與 `en-US` 兩種語言擁有完整的模板資料夾：\n\n```go\nvar SupportedTemplateLangs = []string{\"zh-TW\", \"en-US\"}\n```\n\n\u003e 來源：internal/config/config.go#L54\n\n每個語言資料夾包含以下模板檔案：\n\n```\ninternal/prompt/templates/\n├── zh-TW/\n│   ├── catalog.tmpl          # 文件目錄產生 Prompt\n│   ├── content.tmpl          # 內容頁面產生 Prompt\n│   ├── updater.tmpl          # 增量更新 Prompt（舊版）\n│   ├── update_matched.tmpl   # 判斷受影響頁面 Prompt\n│   └── update_unmatched.tmpl # 判斷是否新增頁面 Prompt\n├── en-US/\n│   ├── catalog.tmpl\n│   ├── content.tmpl\n│   ├── updater.tmpl\n│   ├── update_matched.tmpl\n│   └── update_unmatched.tmpl\n└── translate.tmpl            # 翻譯 Prompt（所有語言共用）\n```\n\n### 模板用途說明\n\n| 模板檔案 | 對應方法 | 用途 |\n|---------|---------|------|\n| `catalog.tmpl` | `Engine.RenderCatalog()` | 指示 Claude 分析專案並產生文件目錄結構 |\n| `content.tmpl` | `Engine.RenderContent()` | 指示 Claude 為特定目錄條目撰寫 Wiki 頁面 |\n| `updater.tmpl` | `Engine.RenderUpdater()` | 增量更新（舊版，保留作為參考） |\n| `update_matched.tmpl` | `Engine.RenderUpdateMatched()` | 判斷哪些現有頁面需因程式碼變更而重新產生 |\n| `update_unmatched.tmpl` | `Engine.RenderUpdateUnmatched()` | 判斷未被現有文件提及的變更檔案是否需要新增頁面 |\n| `translate.tmpl` | `Engine.RenderTranslate()` | 翻譯文件頁面（所有語言共用，不分模板語言） |\n\n### 共用模板：translate.tmpl\n\n翻譯模板是唯一的共用模板（不依賴語言資料夾），以英文撰寫，並透過 `TranslatePromptData` 動態注入來源語言與目標語言資訊：\n\n```go\ntype TranslatePromptData struct {\n    SourceLanguage     string // e.g., \"zh-TW\"\n    SourceLanguageName string // e.g., \"繁體中文\"\n    TargetLanguage     string // e.g., \"en-US\"\n    TargetLanguageName string // e.g., \"English\"\n    SourceContent      string // 要翻譯的完整 Markdown 內容\n}\n```\n\n\u003e 來源：internal/prompt/engine.go#L97-L104\n\n## 模板語言選取機制\n\n### GetEffectiveTemplateLang()\n\n當系統初始化 `prompt.Engine` 時，會呼叫此方法決定要載入哪個語言資料夾的模板。若設定的主要語言有對應模板，則使用該語言；否則回退至 `en-US`：\n\n```go\nfunc (o *OutputConfig) GetEffectiveTemplateLang() string {\n    for _, lang := range SupportedTemplateLangs {\n        if o.Language == lang {\n            return o.Language\n        }\n    }\n    return \"en-US\"\n}\n```\n\n\u003e 來源：internal/config/config.go#L58-L65\n\n### NeedsLanguageOverride()\n\n當模板語言（`en-US`）與實際設定的輸出語言（例如 `ja-JP`）不一致時，此方法回傳 `true`，系統會在 Prompt 中注入明確的語言輸出指示：\n\n```go\nfunc (o *OutputConfig) NeedsLanguageOverride() bool {\n    return o.GetEffectiveTemplateLang() != o.Language\n}\n```\n\n\u003e 來源：internal/config/config.go#L69-L71\n\n### LanguageOverride 在 Prompt 中的效果\n\n以 `content.tmpl`（en-US 版本）為例，當 `LanguageOverride` 為 `true` 時，模板會在專案資訊區段加入強制語言指示：\n\n```\n{{- if .LanguageOverride}}\n- **Document Language**: {{.LanguageOverrideName}} ({{.Language}})\n- **IMPORTANT**: All documentation content MUST be written in **{{.LanguageOverrideName}}** ({{.Language}}).\n{{- else}}\n- **Document Language**: {{.LanguageName}} ({{.Language}})\n{{- end}}\n```\n\n\u003e 來源：internal/prompt/templates/en-US/content.tmpl#L20-L27\n\n## 導航頁面本地化\n\n除了 Prompt 模板之外，系統產生導航頁面（首頁、側欄、分類索引）時，也依據語言顯示對應的 UI 字串。目前 `UIStrings` 直接支援 `zh-TW` 與 `en-US`，其他語言則回退至 `en-US`：\n\n```go\nvar UIStrings = map[string]map[string]string{\n    \"zh-TW\": {\n        \"techDocs\":        \"技術文件\",\n        \"catalog\":         \"目錄\",\n        \"home\":            \"首頁\",\n        \"sectionContains\": \"本章節包含以下內容：\",\n        \"autoGenerated\":   \"本文件由 [selfmd](https://github.com/monkenwu/selfmd) 自動產生\",\n    },\n    \"en-US\": {\n        \"techDocs\":        \"Technical Documentation\",\n        \"catalog\":         \"Table of Contents\",\n        \"home\":            \"Home\",\n        \"sectionContains\": \"This section contains the following:\",\n        \"autoGenerated\":   \"This documentation was automatically generated by [selfmd](https://github.com/monkenwu/selfmd)\",\n    },\n}\n```\n\n\u003e 來源：internal/output/navigation.go#L12-L27\n\n## 核心流程\n\n```mermaid\nsequenceDiagram\n    participant CFG as OutputConfig\n    participant GEN as NewGenerator\n    participant ENG as prompt.Engine\n    participant RUNNER as claude.Runner\n\n    GEN-\u003e\u003eCFG: GetEffectiveTemplateLang()\n    CFG--\u003e\u003eGEN: templateLang (\"zh-TW\" 或 \"en-US\")\n    GEN-\u003e\u003eENG: NewEngine(templateLang)\n    ENG-\u003e\u003eENG: 載入 templates/{templateLang}/*.tmpl\n    ENG-\u003e\u003eENG: 載入 templates/translate.tmpl（共用）\n\n    Note over GEN,ENG: 文件產生時\n\n    GEN-\u003e\u003eCFG: NeedsLanguageOverride()\n    CFG--\u003e\u003eGEN: true/false\n    alt 需要語言覆蓋\n        GEN-\u003e\u003eENG: RenderContent(data with LanguageOverride=true)\n    else 不需要覆蓋\n        GEN-\u003e\u003eENG: RenderContent(data with LanguageOverride=false)\n    end\n    ENG--\u003e\u003eGEN: 渲染後的 Prompt\n    GEN-\u003e\u003eRUNNER: RunWithRetry(prompt)\n    RUNNER--\u003e\u003eGEN: 目標語言的文件內容\n```\n\n## 使用範例\n\n### 設定主要語言為日文（無內建模板）\n\n```yaml\noutput:\n  language: ja-JP\n  secondary_languages:\n    - en-US\n    - zh-TW\n```\n\n系統行為：\n1. `GetEffectiveTemplateLang()` 回傳 `\"en-US\"`（回退）\n2. `NeedsLanguageOverride()` 回傳 `true`\n3. Prompt 中注入：「所有文件內容必須以日本語（ja-JP）撰寫」\n4. `GetLangNativeName(\"ja-JP\")` 回傳 `\"日本語\"` 供 Prompt 使用\n\n### 取得語言母語名稱\n\n```go\nfunc GetLangNativeName(code string) string {\n    if name, ok := KnownLanguages[code]; ok {\n        return name\n    }\n    return code\n}\n```\n\n\u003e 來源：internal/config/config.go#L75-L80\n\n若傳入未知語言代碼（如 `\"ru-RU\"`），函式直接回傳代碼本身（`\"ru-RU\"`），不會出錯。\n\n### 翻譯指令使用範例\n\n```go\ndata := prompt.TranslatePromptData{\n    SourceLanguage:     sourceLang,\n    SourceLanguageName: sourceLangName,\n    TargetLanguage:     targetLang,\n    TargetLanguageName: targetLangName,\n    SourceContent:      sourceContent,\n}\nrendered, err := g.Engine.RenderTranslate(data)\n```\n\n\u003e 來源：internal/generator/translate_phase.go#L186-L194\n\n## 相關連結\n\n- [多語言支援（概覽）](../index.md)\n- [翻譯工作流程](../translation-workflow/index.md)\n- [輸出與多語言設定](../../configuration/output-language/index.md)\n- [selfmd translate 指令](../../cli/cmd-translate/index.md)\n- [Prompt 模板引擎](../../core-modules/prompt-engine/index.md)\n- [翻譯階段](../../core-modules/generator/translate-phase/index.md)\n\n## 參考檔案\n\n| 檔案路徑 | 說明 |\n|----------|------|\n| `internal/config/config.go` | `KnownLanguages`、`SupportedTemplateLangs`、`GetEffectiveTemplateLang()`、`NeedsLanguageOverride()`、`GetLangNativeName()` 定義 |\n| `internal/prompt/engine.go` | `Engine` 結構、`NewEngine()`、所有 `Render*()` 方法、`TranslatePromptData` 定義 |\n| `internal/prompt/templates/zh-TW/catalog.tmpl` | 繁體中文目錄產生 Prompt 模板 |\n| `internal/prompt/templates/zh-TW/content.tmpl` | 繁體中文內容頁面產生 Prompt 模板 |\n| `internal/prompt/templates/zh-TW/update_matched.tmpl` | 繁體中文受影響頁面判斷 Prompt 模板 |\n| `internal/prompt/templates/zh-TW/update_unmatched.tmpl` | 繁體中文新增頁面判斷 Prompt 模板 |\n| `internal/prompt/templates/zh-TW/updater.tmpl` | 繁體中文增量更新 Prompt 模板（舊版） |\n| `internal/prompt/templates/en-US/catalog.tmpl` | 英文目錄產生 Prompt 模板 |\n| `internal/prompt/templates/en-US/content.tmpl` | 英文內容頁面產生 Prompt 模板（含 LanguageOverride 邏輯） |\n| `internal/prompt/templates/translate.tmpl` | 翻譯 Prompt 共用模板（所有語言） |\n| `internal/output/navigation.go` | `UIStrings` 導航頁面本地化字串、`getUIStrings()` 回退邏輯 |\n| `internal/generator/pipeline.go` | `NewGenerator()` 中的 `GetEffectiveTemplateLang()` 呼叫 |\n| `internal/generator/translate_phase.go` | 翻譯管線、`TranslateOptions`、`translatePages()` |\n| `cmd/translate.go` | `selfmd translate` 指令實作與目標語言驗證邏輯 |","i18n/translation-workflow/index.md":"# 翻譯工作流程\n\n`selfmd translate` 指令以主要語言的產出文件為基準，透過 Claude CLI 自動翻譯為一或多個次要語言，並將結果寫入獨立的語言子目錄。\n\n## 概述\n\n翻譯工作流程是 selfmd 多語言支援的核心機制。使用者在 `selfmd.yaml` 中設定 `output.secondary_languages` 後，執行 `selfmd translate` 即可將已產生的主要語言文件翻譯為所有次要語言。\n\n**關鍵概念：**\n\n- **主要語言（Primary Language）**：`output.language` 設定，是所有內容頁面的原始語言，也是翻譯的**來源語言**。\n- **次要語言（Secondary Languages）**：`output.secondary_languages` 設定的語言列表，每個語言對應一個獨立的輸出子目錄。\n- **共用翻譯模板**：翻譯使用 `translate.tmpl`，為不分語言的共用模板，而非語言特定模板資料夾下的模板。\n- **增量跳過**：預設情況下已存在的翻譯頁面會被跳過，使用 `--force` 強制重新翻譯。\n\n翻譯流程與主要文件產生流程解耦——必須先完成 `selfmd generate`，才能執行 `selfmd translate`。\n\n## 架構\n\n```mermaid\nflowchart TD\n    CLI[\"cmd/translate.go\\n（translateCmd）\"]\n    Config[\"config.Config\\noutput.secondary_languages\"]\n    Generator[\"generator.Generator\\nTranslate()\"]\n    TranslatePages[\"translatePages()\\n並行翻譯葉節點頁面\"]\n    Engine[\"prompt.Engine\\nRenderTranslate()\"]\n    Runner[\"claude.Runner\\nRunWithRetry()\"]\n    Template[\"translate.tmpl\\n共用翻譯模板\"]\n    SourceWriter[\"output.Writer\\n讀取主語言頁面\"]\n    LangWriter[\"output.Writer.ForLanguage()\\n寫入語言子目錄\"]\n    CatalogBuild[\"buildTranslatedCatalog()\\n重建翻譯目錄\"]\n    NavGen[\"output.GenerateIndex()\\noutput.GenerateSidebar()\"]\n\n    CLI --\u003e|\"驗證語言、建立 Generator\"| Generator\n    Config --\u003e|\"targetLangs, concurrency\"| CLI\n    Generator --\u003e|\"讀取 _catalog.json\"| SourceWriter\n    Generator --\u003e TranslatePages\n    TranslatePages --\u003e|\"TranslatePromptData\"| Engine\n    Engine --\u003e|\"渲染 translate.tmpl\"| Template\n    Engine --\u003e|\"rendered prompt\"| Runner\n    Runner --\u003e|\"claude -p --output-format json\"| Runner\n    Runner --\u003e|\"RunResult.Content\"| TranslatePages\n    SourceWriter --\u003e|\"ReadPage(item)\"| TranslatePages\n    TranslatePages --\u003e|\"WritePage(item, content)\"| LangWriter\n    TranslatePages --\u003e|\"translatedTitles map\"| CatalogBuild\n    CatalogBuild --\u003e|\"翻譯後目錄\"| NavGen\n    NavGen --\u003e|\"index.md, _sidebar.md\"| LangWriter\n```\n\n## 設定\n\n### selfmd.yaml 相關欄位\n\n```yaml\noutput:\n  language: \"zh-TW\"               # 主要語言（翻譯來源）\n  secondary_languages:             # 翻譯目標語言列表\n    - \"en-US\"\n    - \"ja-JP\"\n```\n\n\u003e 來源：`internal/config/config.go#L31-L36`\n\n### 支援的語言代碼\n\n`config.KnownLanguages` 定義了系統已知的語言代碼與原生名稱對照：\n\n```go\nvar KnownLanguages = map[string]string{\n    \"zh-TW\": \"繁體中文\",\n    \"zh-CN\": \"简体中文\",\n    \"en-US\": \"English\",\n    \"ja-JP\": \"日本語\",\n    \"ko-KR\": \"한국어\",\n    \"fr-FR\": \"Français\",\n    \"de-DE\": \"Deutsch\",\n    \"es-ES\": \"Español\",\n    \"pt-BR\": \"Português\",\n    \"th-TH\": \"ไทย\",\n    \"vi-VN\": \"Tiếng Việt\",\n}\n```\n\n\u003e 來源：`internal/config/config.go#L39-L51`\n\n不在上表中的語言代碼也可使用，`GetLangNativeName()` 函式在找不到對應名稱時會直接返回語言代碼本身。\n\n### Prompt 模板語言回退\n\n翻譯 Prompt 使用的是**共用模板** `translate.tmpl`，不受 `output.language` 的模板語言回退邏輯影響。此模板以英文撰寫，明確指定來源語言與目標語言：\n\n```go\n// SupportedTemplateLangs lists language codes that have built-in prompt template folders.\nvar SupportedTemplateLangs = []string{\"zh-TW\", \"en-US\"}\n```\n\n\u003e 來源：`internal/config/config.go#L54`\n\n## CLI 指令\n\n```\nselfmd translate [flags]\n```\n\n| 旗標 | 說明 |\n|------|------|\n| `--lang` | 只翻譯指定語言（可多次使用，預設：所有次要語言） |\n| `--force` | 強制重新翻譯已存在的檔案 |\n| `--concurrency` | 並行度（覆蓋 `claude.max_concurrent` 設定） |\n\n`cmd/translate.go` 在啟動翻譯前會驗證指定語言是否存在於 `secondary_languages` 清單中：\n\n```go\nfor _, l := range translateLangs {\n    if !validLangs[l] {\n        return fmt.Errorf(\"語言 %s 不在 secondary_languages 列表中（可用：%s）\",\n            l, strings.Join(cfg.Output.SecondaryLanguages, \", \"))\n    }\n}\n```\n\n\u003e 來源：`cmd/translate.go#L61-L65`\n\n## 核心流程\n\n### 翻譯管線總覽\n\n```mermaid\nsequenceDiagram\n    participant CLI as translateCmd\n    participant Gen as Generator.Translate()\n    participant Catalog as catalog.Parse()\n    participant Pages as translatePages()\n    participant Claude as claude.Runner\n    participant Writer as output.Writer\n\n    CLI-\u003e\u003eGen: Translate(ctx, TranslateOptions)\n    Gen-\u003e\u003eWriter: ReadCatalogJSON()\n    Writer--\u003e\u003eGen: _catalog.json\n    Gen-\u003e\u003eCatalog: Parse(catJSON)\n    Catalog--\u003e\u003eGen: *catalog.Catalog\n\n    loop 每個目標語言\n        Gen-\u003e\u003eWriter: ForLanguage(targetLang)\n        Gen-\u003e\u003ePages: translatePages(items, langWriter, ...)\n        loop 每個葉節點頁面（並行）\n            Pages-\u003e\u003eWriter: ReadPage(item)\n            Writer--\u003e\u003ePages: sourceContent\n            Pages-\u003e\u003eClaude: RunWithRetry(TranslatePrompt)\n            Claude--\u003e\u003ePages: RunResult（含翻譯後 Markdown）\n            Pages-\u003e\u003eWriter: WritePage(item, translatedContent)\n        end\n        Pages--\u003e\u003eGen: translatedTitles map\n        Gen-\u003e\u003eWriter: WriteCatalogJSON(translatedCat)\n        Gen-\u003e\u003eWriter: WriteFile(\"index.md\")\n        Gen-\u003e\u003eWriter: WriteFile(\"_sidebar.md\")\n    end\n\n    Gen-\u003e\u003eWriter: WriteViewer（更新語言切換器資料）\n```\n\n### 頁面翻譯細節\n\n`translatePages()` 只翻譯**葉節點**（`HasChildren == false`）頁面，分類索引頁面由 `output.GenerateCategoryIndex()` 重新以目標語言生成。\n\n**跳過邏輯：**\n\n```go\nif !opts.Force \u0026\u0026 langWriter.PageExists(item) {\n    skipped.Add(1)\n    // 從已存在的翻譯中提取標題（供目錄重建用）\n    if content, err := langWriter.ReadPage(item); err == nil {\n        if title := extractTitle(content); title != \"\" {\n            titlesMu.Lock()\n            translatedTitles[item.Path] = title\n            titlesMu.Unlock()\n        }\n    }\n    fmt.Printf(\"      [跳過] %s（已存在）\\n\", item.Title)\n    return nil\n}\n```\n\n\u003e 來源：`internal/generator/translate_phase.go#L157-L168`\n\n**並行控制：**\n\n使用 `errgroup` + 緩衝通道（semaphore）實現有界並行：\n\n```go\neg, ctx := errgroup.WithContext(ctx)\nsem := make(chan struct{}, opts.Concurrency)\n\nfor _, item := range leafItems {\n    item := item\n    eg.Go(func() error {\n        sem \u003c- struct{}{}\n        defer func() { \u003c-sem }()\n        // ... 翻譯邏輯\n    })\n}\neg.Wait()\n```\n\n\u003e 來源：`internal/generator/translate_phase.go#L150-L249`\n\n### 翻譯目錄重建\n\n翻譯完成後，系統會以翻譯後的頁面標題重建目錄（`_catalog.json`）。`extractTitle()` 從翻譯後 Markdown 的第一個 `#` 標題中提取標題：\n\n```go\nfunc extractTitle(content string) string {\n    re := regexp.MustCompile(`(?m)^#\\s+(.+)$`)\n    match := re.FindStringSubmatch(content)\n    if len(match) \u003e= 2 {\n        return strings.TrimSpace(match[1])\n    }\n    return \"\"\n}\n```\n\n\u003e 來源：`internal/generator/translate_phase.go#L267-L274`\n\n## 翻譯 Prompt 規則\n\n`internal/prompt/templates/translate.tmpl` 是共用模板，以英文撰寫，指示 Claude 翻譯文件時必須遵守以下規則：\n\n| 規則 | 說明 |\n|------|------|\n| 保留 Markdown 格式 | 標題、連結、程式碼區塊、表格、Mermaid 圖表 |\n| 不翻譯程式碼 | 識別符、檔案路徑、變數名稱、程式碼區塊保持原文 |\n| 翻譯章節標題 | 使用目標語言的自然表達 |\n| 保留相對連結路徑 | `[text](../path/index.md)` 只翻譯顯示文字，路徑不變 |\n| 保留 Mermaid 圖表 | 翻譯圖表標籤，語法不變 |\n| 保留來源標註 | `\u003e Source: path/to/file#L10-L25` 格式不變 |\n| 自然翻譯 | 產出流暢的目標語言文字，非逐字翻譯 |\n| 保留參考檔案表 | 翻譯表頭，檔案路徑不變 |\n\n\u003e 來源：`internal/prompt/templates/translate.tmpl#L1-L35`\n\n## 輸出目錄結構\n\n主要語言文件置於 `.doc-build/`，每個次要語言的翻譯置於對應的子目錄：\n\n```\n.doc-build/\n├── _catalog.json          # 主要語言目錄\n├── index.md               # 主要語言首頁\n├── _sidebar.md            # 主要語言側欄\n├── {section}/{page}/\n│   └── index.md           # 主要語言內容頁面\n├── en-US/                 # 英文翻譯\n│   ├── _catalog.json\n│   ├── index.md\n│   ├── _sidebar.md\n│   └── {section}/{page}/\n│       └── index.md\n└── ja-JP/                 # 日文翻譯\n    └── ...\n```\n\n`Writer.ForLanguage(targetLang)` 建立一個以語言子目錄為 `BaseDir` 的新 Writer 實例：\n\n```go\nfunc (w *Writer) ForLanguage(lang string) *Writer {\n    return \u0026Writer{\n        BaseDir: filepath.Join(w.BaseDir, lang),\n    }\n}\n```\n\n\u003e 來源：`internal/output/writer.go#L138-L143`\n\n## 瀏覽器多語言整合\n\n翻譯完成後，`Translate()` 會呼叫 `buildDocMeta()` 重新產生靜態瀏覽器（`index.html`），將所有語言資訊注入瀏覽器的語言切換器。`DocMeta` 結構描述主要與次要語言：\n\n```go\ntype DocMeta struct {\n    DefaultLanguage    string     `json:\"default_language\"`\n    AvailableLanguages []LangInfo `json:\"available_languages\"`\n}\n\ntype LangInfo struct {\n    Code       string `json:\"code\"`\n    NativeName string `json:\"native_name\"`\n    IsDefault  bool   `json:\"is_default\"`\n}\n```\n\n\u003e 來源：`internal/output/writer.go#L13-L23`\n\n## UI 字串本地化\n\n`output.UIStrings` 定義了分類索引頁、首頁等導航頁面中使用的 UI 字串。目前內建 `zh-TW` 與 `en-US` 兩組，其他語言回退至 `en-US`：\n\n```go\nvar UIStrings = map[string]map[string]string{\n    \"zh-TW\": {\n        \"techDocs\":        \"技術文件\",\n        \"sectionContains\": \"本章節包含以下內容：\",\n        // ...\n    },\n    \"en-US\": {\n        \"techDocs\":        \"Technical Documentation\",\n        \"sectionContains\": \"This section contains the following:\",\n        // ...\n    },\n}\n```\n\n\u003e 來源：`internal/output/navigation.go#L12-L27`\n\n## 相關連結\n\n- [支援的語言與模板](../supported-languages/index.md)\n- [多語言支援](../index.md)\n- [翻譯階段](../../core-modules/generator/translate-phase/index.md)\n- [Claude CLI 執行器](../../core-modules/claude-runner/index.md)\n- [Prompt 模板引擎](../../core-modules/prompt-engine/index.md)\n- [selfmd translate](../../cli/cmd-translate/index.md)\n- [輸出與多語言設定](../../configuration/output-language/index.md)\n- [靜態文件瀏覽器](../../core-modules/static-viewer/index.md)\n\n## 參考檔案\n\n| 檔案路徑 | 說明 |\n|----------|------|\n| `internal/generator/translate_phase.go` | 翻譯管線核心邏輯：`Translate()`、`translatePages()`、`buildTranslatedCatalog()` |\n| `cmd/translate.go` | `selfmd translate` CLI 指令實作，語言驗證與選項解析 |\n| `internal/config/config.go` | `OutputConfig`、`KnownLanguages`、`SupportedTemplateLangs`、`GetLangNativeName()` |\n| `internal/prompt/templates/translate.tmpl` | 翻譯用共用 Prompt 模板 |\n| `internal/prompt/engine.go` | `TranslatePromptData` 結構、`RenderTranslate()` 方法 |\n| `internal/output/writer.go` | `Writer.ForLanguage()`、`ReadPage()`、`WritePage()`、`DocMeta` |\n| `internal/output/navigation.go` | `UIStrings`、`GenerateIndex()`、`GenerateSidebar()`、`GenerateCategoryIndex()` |\n| `internal/catalog/catalog.go` | `Catalog`、`FlatItem`、`Flatten()` |\n| `internal/generator/pipeline.go` | `Generator` 結構、`buildDocMeta()` |\n| `internal/claude/runner.go` | `Runner.RunWithRetry()` 翻譯呼叫執行 |","index.md":"# selfmd Technical Documentation\n\n---\n\n## Table of Contents\n\n- [概述](./overview/index.md)\n  - [專案介紹與功能特色](./overview/introduction/index.md)\n  - [技術棧與相依套件](./overview/tech-stack/index.md)\n  - [輸出結構說明](./overview/output-structure/index.md)\n- [快速開始](./getting-started/index.md)\n  - [安裝與建置](./getting-started/installation/index.md)\n  - [初始化設定](./getting-started/init/index.md)\n  - [產生第一份文件](./getting-started/first-run/index.md)\n- [CLI 指令參考](./cli/index.md)\n  - [selfmd init](./cli/cmd-init/index.md)\n  - [selfmd generate](./cli/cmd-generate/index.md)\n  - [selfmd update](./cli/cmd-update/index.md)\n  - [selfmd translate](./cli/cmd-translate/index.md)\n- [設定說明](./configuration/index.md)\n  - [selfmd.yaml 結構總覽](./configuration/config-overview/index.md)\n  - [專案與掃描目標設定](./configuration/project-targets/index.md)\n  - [輸出與多語言設定](./configuration/output-language/index.md)\n  - [Claude CLI 整合設定](./configuration/claude-config/index.md)\n  - [Git 整合設定](./configuration/git-config/index.md)\n- [系統架構](./architecture/index.md)\n  - [整體流程與四階段管線](./architecture/pipeline/index.md)\n  - [模組依賴關係](./architecture/module-dependencies/index.md)\n- [核心模組](./core-modules/index.md)\n  - [專案掃描器](./core-modules/scanner/index.md)\n  - [文件目錄管理](./core-modules/catalog/index.md)\n  - [Prompt 模板引擎](./core-modules/prompt-engine/index.md)\n  - [Claude CLI 執行器](./core-modules/claude-runner/index.md)\n  - [文件產生管線](./core-modules/generator/index.md)\n    - [目錄產生階段](./core-modules/generator/catalog-phase/index.md)\n    - [內容頁面產生階段](./core-modules/generator/content-phase/index.md)\n    - [索引與導航產生階段](./core-modules/generator/index-phase/index.md)\n    - [翻譯階段](./core-modules/generator/translate-phase/index.md)\n  - [增量更新](./core-modules/incremental-update/index.md)\n  - [輸出寫入與連結修復](./core-modules/output-writer/index.md)\n  - [靜態文件瀏覽器](./core-modules/static-viewer/index.md)\n- [多語言支援](./i18n/index.md)\n  - [支援的語言與模板](./i18n/supported-languages/index.md)\n  - [翻譯工作流程](./i18n/translation-workflow/index.md)\n- [Git 整合與增量更新](./git-integration/index.md)\n  - [Git Diff 變更偵測](./git-integration/change-detection/index.md)\n  - [受影響頁面判斷邏輯](./git-integration/affected-pages/index.md)\n\n---\n\n*This documentation was automatically generated by [selfmd](https://github.com/monkenwu/selfmd)*\n","overview/index.md":"# 概述\n\nThis section contains the following:\n\n- [專案介紹與功能特色](introduction/index.md)\n- [技術棧與相依套件](tech-stack/index.md)\n- [輸出結構說明](output-structure/index.md)\n","overview/introduction/index.md":"# 專案介紹與功能特色\n\n`selfmd` 是一款 Go 語言撰寫的 CLI 工具，透過在本地端執行 Claude Code CLI 作為 AI 後端，自動掃描任意專案的原始碼目錄，並產生結構化的 Wiki 風格技術文件。\n\n## 概述\n\n`selfmd` 解決的核心問題是：技術文件往往因維護成本高而快速老化。透過將 Claude Code CLI 的程式碼理解能力與自動化管線結合，`selfmd` 能夠在不需要人工撰寫的情況下，持續為軟體專案產生高品質的 Markdown 技術文件。\n\n### 主要定位\n\n| 特性 | 說明 |\n|------|------|\n| **AI 後端** | 本地 Claude Code CLI（`claude` 指令），不透過遠端 API |\n| **文件格式** | Markdown，支援 Mermaid 圖表與程式碼來源標註 |\n| **預設語言** | 繁體中文（zh-TW），可透過設定切換任意語言 |\n| **輸出位置** | 專案根目錄下的 `.doc-build/` 資料夾 |\n| **適用對象** | 任意語言的軟體專案（Go、Rust、Python、Node.js 等） |\n\n### 核心概念\n\n- **Catalog（文件目錄）**：由 AI 分析專案結構後自動規劃的階層式文件大綱，定義每個頁面的路徑與標題\n- **Pipeline（管線）**：四個有序執行的階段，從掃描到輸出一氣呵成\n- **Runner（執行器）**：將 `claude` 子行程的呼叫封裝為可重試、可超時的非同步工作單元\n- **Incremental Update（增量更新）**：透過 git diff 偵測原始碼變更，只重新產生受影響的文件頁面\n\n---\n\n## 架構\n\n下圖展示 `selfmd` 的主要模組與資料流向。\n\n```mermaid\nflowchart TD\n    User[\"使用者（selfmd CLI）\"]\n\n    subgraph cmd[\"cmd/（指令層）\"]\n        CmdInit[\"init\"]\n        CmdGen[\"generate\"]\n        CmdUpdate[\"update\"]\n        CmdTrans[\"translate\"]\n    end\n\n    subgraph internal[\"internal/（核心模組）\"]\n        Config[\"config\\n載入 selfmd.yaml\"]\n        Scanner[\"scanner\\n掃描專案目錄\"]\n        Catalog[\"catalog\\n文件目錄管理\"]\n        Prompt[\"prompt\\n模板引擎\"]\n        ClaudeRunner[\"claude\\nRunner / Parser\"]\n        Generator[\"generator\\n四階段管線\"]\n        Git[\"git\\nGit Diff 整合\"]\n        Output[\"output\\nWriter / LinkFixer / Viewer\"]\n    end\n\n    User --\u003e cmd\n    CmdGen --\u003e Generator\n    CmdUpdate --\u003e Generator\n    CmdTrans --\u003e Generator\n    CmdInit --\u003e Config\n\n    Generator --\u003e Config\n    Generator --\u003e Scanner\n    Generator --\u003e Catalog\n    Generator --\u003e Prompt\n    Generator --\u003e ClaudeRunner\n    Generator --\u003e Git\n    Generator --\u003e Output\n\n    ClaudeRunner --\u003e|\"subprocess: claude -p\"| AI[\"Claude Code CLI\"]\n    Output --\u003e|\"Markdown + HTML\"| DocBuild[\".doc-build/\"]\n```\n\n---\n\n## 功能特色\n\n### 1. 四階段自動化文件產生管線\n\n執行 `selfmd generate` 時，管線依序完成以下四個階段：\n\n```go\n// Phase 1: Scan\nfmt.Println(\"[1/4] 掃描專案結構...\")\nscan, err := scanner.Scan(g.Config, g.RootDir)\n\n// Phase 2: Generate Catalog\nfmt.Println(\"[2/4] 產生文件目錄...\")\ncat, err = g.GenerateCatalog(ctx, scan)\n\n// Phase 3: Generate Content（並行）\nfmt.Printf(\"[3/4] 產生內容頁面（並行度：%d）...\\n\", concurrency)\nif err := g.GenerateContent(ctx, scan, cat, concurrency, !clean); err != nil { ... }\n\n// Phase 4: Generate Index \u0026 Navigation\nfmt.Println(\"[4/4] 產生導航與索引...\")\nif err := g.GenerateIndex(ctx, cat); err != nil { ... }\n```\n\n\u003e 來源：`internal/generator/pipeline.go#L86-L143`\n\n四個階段完成後，系統會自動產生可直接瀏覽的靜態 HTML 文件站台（`index.html`），並在 Git 倉庫中記錄本次 commit，供下次增量更新使用。\n\n---\n\n### 2. Claude Code CLI 整合\n\n`selfmd` 不直接呼叫 Anthropic API，而是透過本地安裝的 `claude` CLI 子行程執行所有 AI 任務。每次呼叫會：\n\n- 透過 `stdin` 傳入渲染後的 Prompt\n- 以 `--output-format json` 取得結構化回應\n- 預設允許 `Read`、`Glob`、`Grep` 工具讓 Claude 讀取原始碼\n- 自動封鎖 `Write`、`Edit` 工具，防止 AI 意外修改原始碼\n\n```go\nargs := []string{\n    \"-p\",\n    \"--output-format\", \"json\",\n}\n// ...\nargs = append(args, \"--disallowedTools\", \"Write\", \"--disallowedTools\", \"Edit\")\ncmd := exec.CommandContext(ctx, \"claude\", args...)\ncmd.Stdin = strings.NewReader(opts.Prompt)\n```\n\n\u003e 來源：`internal/claude/runner.go#L32-L76`\n\n---\n\n### 3. 自動偵測專案類型\n\n`selfmd init` 會掃描當前目錄，依據設定檔（`go.mod`、`package.json`、`Cargo.toml` 等）自動判斷專案類型並產生 `selfmd.yaml`：\n\n| 偵測檔案 | 專案類型 |\n|---------|---------|\n| `go.mod` | `backend` |\n| `package.json` | `frontend`（若同時有 `go.mod` 則為 `fullstack`） |\n| `Cargo.toml` | `backend` |\n| `requirements.txt` / `pyproject.toml` | `backend` |\n| `pom.xml` / `build.gradle` | `backend` |\n| `Gemfile` | `backend` |\n| 無符合 | `library` |\n\n\u003e 來源：`cmd/init.go#L60-L98`\n\n---\n\n### 4. Git 整合與增量更新\n\n當原始碼發生變更時，無需重新產生全部文件。`selfmd update` 會：\n\n1. 讀取上次 `generate` 時記錄的 commit hash（儲存於 `.doc-build/_last_commit`）\n2. 呼叫 `git diff --name-status` 取得變更檔案清單\n3. 套用 include/exclude 過濾規則，篩選出目標檔案\n4. 僅重新產生受影響的文件頁面\n\n```go\nchangedFiles, err := git.GetChangedFiles(rootDir, previousCommit, currentCommit)\nchangedFiles = git.FilterChangedFiles(changedFiles, cfg.Targets.Include, cfg.Targets.Exclude)\n```\n\n\u003e 來源：`cmd/update.go#L89-L94`\n\n---\n\n### 5. 多語言文件支援\n\n`selfmd` 原生支援多語言文件。透過 `selfmd.yaml` 設定 `secondary_languages` 後，執行 `selfmd translate` 即可將主要語言的文件翻譯為其他語言。翻譯結果存放於 `.doc-build/{語言代碼}/` 子目錄。\n\n目前內建 Prompt 模板語言支援 `zh-TW` 與 `en-US`；文件輸出則支援 11 種語言：\n\n```go\nvar KnownLanguages = map[string]string{\n    \"zh-TW\": \"繁體中文\",\n    \"zh-CN\": \"简体中文\",\n    \"en-US\": \"English\",\n    \"ja-JP\": \"日本語\",\n    \"ko-KR\": \"한국어\",\n    \"fr-FR\": \"Français\",\n    \"de-DE\": \"Deutsch\",\n    \"es-ES\": \"Español\",\n    \"pt-BR\": \"Português\",\n    \"th-TH\": \"ไทย\",\n    \"vi-VN\": \"Tiếng Việt\",\n}\n```\n\n\u003e 來源：`internal/config/config.go#L39-L51`\n\n---\n\n### 6. 並行頁面產生\n\n為縮短大型專案的文件產生時間，`selfmd` 支援並行呼叫 Claude，預設並行度為 3，可透過設定檔或 `--concurrency` 旗標調整：\n\n```go\nClaude: ClaudeConfig{\n    Model:         \"sonnet\",\n    MaxConcurrent: 3,\n    TimeoutSeconds: 300,\n    MaxRetries:    2,\n    AllowedTools:  []string{\"Read\", \"Glob\", \"Grep\"},\n},\n```\n\n\u003e 來源：`internal/config/config.go#L116-L123`\n\n---\n\n### 7. 靜態 HTML 文件瀏覽器\n\n文件產生完成後，`selfmd` 會在 `.doc-build/index.html` 產生一個可直接在瀏覽器開啟的靜態文件站台，無需架設任何伺服器。瀏覽器包含語言切換功能，支援多語言文件導航。\n\n---\n\n## 核心工作流程\n\n```mermaid\nsequenceDiagram\n    participant User as 使用者\n    participant CLI as selfmd CLI\n    participant Scanner as scanner\n    participant Claude as Claude Code CLI\n    participant FS as .doc-build/\n\n    User-\u003e\u003eCLI: selfmd generate\n    CLI-\u003e\u003eScanner: 掃描專案目錄與入口檔案\n    Scanner--\u003e\u003eCLI: ScanResult（檔案樹、README）\n\n    CLI-\u003e\u003eClaude: 渲染 catalog.tmpl → 呼叫 claude -p\n    Claude--\u003e\u003eCLI: 文件目錄 JSON（Catalog）\n\n    loop 每個目錄頁面（並行）\n        CLI-\u003e\u003eClaude: 渲染 content.tmpl → 呼叫 claude -p\n        Claude--\u003e\u003eCLI: Markdown 頁面內容\n        CLI-\u003e\u003eFS: 寫入 {dirPath}/index.md\n    end\n\n    CLI-\u003e\u003eClaude: 渲染導航與索引\n    Claude--\u003e\u003eCLI: index.md 內容\n    CLI-\u003e\u003eFS: 產生靜態 HTML 瀏覽器\n    CLI-\u003e\u003eFS: 儲存 _last_commit\n    CLI--\u003e\u003eUser: 完成報告（頁面數、耗時、費用）\n```\n\n---\n\n## CLI 指令總覽\n\n| 指令 | 說明 |\n|------|------|\n| `selfmd init` | 偵測專案類型，產生 `selfmd.yaml` 設定檔 |\n| `selfmd generate` | 執行完整四階段文件產生管線 |\n| `selfmd generate --dry-run` | 僅顯示掃描結果，不實際呼叫 Claude |\n| `selfmd generate --clean` | 清除輸出目錄後重新產生 |\n| `selfmd update` | 基於 git diff 增量更新受影響的文件頁面 |\n| `selfmd translate` | 將主要語言文件翻譯為次要語言 |\n\n所有指令共用的全域旗標：\n\n| 旗標 | 說明 |\n|------|------|\n| `-c, --config` | 設定檔路徑（預設：`selfmd.yaml`） |\n| `-v, --verbose` | 顯示詳細 Debug 輸出 |\n| `-q, --quiet` | 僅顯示錯誤訊息 |\n\n\u003e 來源：`cmd/root.go#L30-L33`\n\n---\n\n## 相關連結\n\n- [技術棧與相依套件](../tech-stack/index.md) — 了解 `selfmd` 使用的程式語言、框架與外部套件\n- [輸出結構說明](../output-structure/index.md) — `.doc-build/` 目錄的完整結構\n- [安裝與建置](../../getting-started/installation/index.md) — 如何在本機安裝並執行 `selfmd`\n- [初始化設定](../../getting-started/init/index.md) — `selfmd init` 的詳細使用說明\n- [selfmd generate](../../cli/cmd-generate/index.md) — generate 指令完整參數說明\n- [selfmd update](../../cli/cmd-update/index.md) — update 指令完整參數說明\n- [selfmd translate](../../cli/cmd-translate/index.md) — translate 指令完整參數說明\n- [整體流程與四階段管線](../../architecture/pipeline/index.md) — 深入了解管線架構設計\n- [Claude CLI 執行器](../../core-modules/claude-runner/index.md) — Runner 模組的實作細節\n- [多語言支援](../../i18n/index.md) — 多語言文件的設定與翻譯工作流程\n- [Git 整合與增量更新](../../git-integration/index.md) — 增量更新的運作原理\n\n---\n\n## 參考檔案\n\n| 檔案路徑 | 說明 |\n|----------|------|\n| `cmd/root.go` | CLI 根指令定義、全域旗標設定 |\n| `cmd/generate.go` | `generate` 指令實作，管線入口 |\n| `cmd/init.go` | `init` 指令實作，專案類型偵測邏輯 |\n| `cmd/update.go` | `update` 指令實作，增量更新流程 |\n| `cmd/translate.go` | `translate` 指令實作，多語言翻譯流程 |\n| `internal/config/config.go` | `Config` 結構定義、預設值、已知語言清單 |\n| `internal/generator/pipeline.go` | `Generator` 結構、四階段管線實作 |\n| `internal/scanner/scanner.go` | 專案目錄掃描器實作 |\n| `internal/claude/runner.go` | Claude CLI 子行程執行封裝 |\n| `internal/prompt/engine.go` | Prompt 模板引擎、各類型 PromptData 定義 |\n| `internal/output/writer.go` | 輸出目錄寫入、Catalog JSON 管理 |\n| `internal/git/git.go` | Git diff 整合、變更檔案過濾 |","overview/output-structure/index.md":"# 輸出結構說明\n\nselfmd 執行完成後，所有產生的文件、靜態瀏覽器資源及中繼資料均集中存放於輸出目錄（預設為 `.doc-build/`）。本頁說明該目錄的完整檔案結構與各檔案的用途。\n\n## 概述\n\n輸出目錄由 `output.Writer` 統一管理寫入。selfmd 的四個產生階段各司其職，依序將不同類型的檔案寫入輸出目錄：\n\n- **目錄階段**：寫入 `_catalog.json`（目錄索引 JSON）\n- **內容階段**：寫入各章節的 `{dir}/index.md` 內容頁面\n- **索引與導航階段**：寫入 `index.md`、`_sidebar.md` 及分類索引頁面\n- **靜態瀏覽器**：寫入 `index.html`、`app.js`、`style.css`、`_data.js`、`_doc_meta.json`\n- **翻譯階段**（可選）：在 `{lang-code}/` 子目錄下寫入各語言的對應版本\n\n輸出目錄的根目錄路徑由 `selfmd.yaml` 中的 `output.dir` 欄位決定，預設值為 `.doc-build`。\n\n## 架構\n\n```mermaid\nflowchart TD\n    A[\"selfmd generate\"] --\u003e B[\"output.Writer\"]\n    B --\u003e C[\"_catalog.json\"]\n    B --\u003e D[\"index.md（主頁）\"]\n    B --\u003e E[\"_sidebar.md（側欄導航）\"]\n    B --\u003e F[\"內容頁面目錄\"]\n    B --\u003e G[\"靜態瀏覽器資源\"]\n    B --\u003e H[\"增量更新中繼資料\"]\n\n    F --\u003e F1[\"{section}/index.md\"]\n    F --\u003e F2[\"{section}/{subsection}/index.md\"]\n\n    G --\u003e G1[\"index.html\"]\n    G --\u003e G2[\"app.js\"]\n    G --\u003e G3[\"style.css\"]\n    G --\u003e G4[\"_data.js（打包資料）\"]\n    G --\u003e G5[\"_doc_meta.json\"]\n\n    H --\u003e H1[\"_last_commit\"]\n\n    I[\"selfmd translate\"] --\u003e J[\"語言子目錄\"]\n    J --\u003e J1[\"{lang-code}/_catalog.json\"]\n    J --\u003e J2[\"{lang-code}/index.md\"]\n    J --\u003e J3[\"{lang-code}/_sidebar.md\"]\n    J --\u003e J4[\"{lang-code}/{section}/index.md\"]\n```\n\n## 完整目錄結構\n\n執行 `selfmd generate` 並加上翻譯後，典型的輸出目錄結構如下：\n\n```\n.doc-build/\n├── index.html          # 靜態文件瀏覽器入口頁面\n├── app.js              # 瀏覽器前端 JavaScript\n├── style.css           # 瀏覽器樣式表\n├── _data.js            # 所有 Markdown 內容的打包資料（供瀏覽器載入）\n├── _doc_meta.json      # 多語言中繼資訊\n├── _catalog.json       # 文件目錄結構（JSON，供增量更新使用）\n├── _last_commit        # 最後一次產生時的 Git commit hash\n├── index.md            # 文件主頁（目錄列表）\n├── _sidebar.md         # Docsify/瀏覽器側欄導航\n│\n├── {section}/\n│   └── index.md        # 章節內容頁面\n├── {section}/\n│   ├── index.md        # 分類索引頁面（有子章節時自動產生）\n│   └── {subsection}/\n│       └── index.md    # 子章節內容頁面\n│\n└── {lang-code}/        # 次要語言目錄（如 en-US/）\n    ├── _catalog.json   # 翻譯版目錄結構\n    ├── index.md        # 翻譯版主頁\n    ├── _sidebar.md     # 翻譯版側欄導航\n    └── {section}/\n        └── index.md    # 翻譯版內容頁面\n```\n\n## 各類型檔案說明\n\n### 系統檔案（底線前綴）\n\n以底線（`_`）開頭的檔案為系統內部使用，不納入靜態瀏覽器的頁面路由，也不會顯示於文件目錄中。\n\n| 檔案 | 說明 |\n|------|------|\n| `_catalog.json` | 文件目錄的 JSON 序列化，供增量更新（`selfmd update`）重用，避免重新呼叫 Claude |\n| `_last_commit` | 紀錄最後一次產生時的 Git commit hash，供 `selfmd update` 判斷需更新的頁面 |\n| `_data.js` | 將所有 `.md` 檔案與目錄結構打包為單一 JavaScript 資料物件，供靜態瀏覽器在客戶端渲染 |\n| `_doc_meta.json` | 記錄主語言與所有次要語言的代碼及原生名稱，供語言切換功能使用 |\n| `_sidebar.md` | 導航側欄，由 `GenerateSidebar` 自動從目錄結構產生 |\n\n### 靜態瀏覽器資源\n\n```go\n// viewer.go 將三個嵌入式靜態資源寫入輸出目錄\nif err := w.WriteFile(\"index.html\", html); err != nil { ... }\nif err := w.WriteFile(\"app.js\", viewerJS); err != nil { ... }\nif err := w.WriteFile(\"style.css\", viewerCSS); err != nil { ... }\n```\n\n\u003e 來源：`internal/output/viewer.go#L34-L44`\n\n`index.html` 是瀏覽器的入口頁面，其中 `{{PROJECT_NAME}}` 與 `{{LANG}}` 佔位符會在寫入時被替換為實際的專案名稱與語言代碼。\n\n### 內容頁面\n\n每個文件項目（`catalog.FlatItem`）的頁面均以 `index.md` 為檔名，存放於對應的目錄路徑下：\n\n```go\n// writer.go：WritePage 使用 FlatItem.DirPath 決定目錄位置\nfunc (w *Writer) WritePage(item catalog.FlatItem, content string) error {\n    dir := filepath.Join(w.BaseDir, item.DirPath)\n    path := filepath.Join(dir, \"index.md\")\n    // ...\n}\n```\n\n\u003e 來源：`internal/output/writer.go#L50-L61`\n\n路徑對應規則：目錄結構中的 `DirPath`（如 `core-modules/scanner`）直接映射為檔案系統路徑，最終產生 `core-modules/scanner/index.md`。\n\n### 主頁與分類索引\n\n- **`index.md`**（主頁）：由 `GenerateIndex` 產生，包含完整的文件目錄連結列表\n- **`{section}/index.md`**（分類索引）：當一個章節有子章節時，其 `index.md` 由 `GenerateCategoryIndex` 自動產生，列出直接子章節的連結\n\n```go\n// index_phase.go：分類索引只為有子章節的項目產生\nfor _, item := range items {\n    if !item.HasChildren {\n        continue\n    }\n    // ...\n    categoryContent := output.GenerateCategoryIndex(item, children, lang)\n    if err := g.Writer.WritePage(item, categoryContent); err != nil { ... }\n}\n```\n\n\u003e 來源：`internal/generator/index_phase.go#L34-L53`\n\n### `_data.js` 資料打包\n\n靜態瀏覽器不依賴伺服器端路由，而是透過 `_data.js` 在客戶端載入所有內容。打包邏輯會掃描所有 `.md` 檔案，排除底線前綴檔案與次要語言目錄，將內容以 JSON 格式嵌入：\n\n```go\n// viewer.go：_data.js 的資料結構\ndata := map[string]interface{}{\n    \"catalog\": catalogObj,\n    \"pages\":   pages,\n}\n// 多語言時加入 meta 與各語言資料\nif docMeta != nil {\n    data[\"meta\"] = docMeta\n    // ... 加入 languages 物件\n}\n\ncontent := \"window.DOC_DATA = \" + string(jsonBytes) + \";\\n\"\nreturn w.WriteFile(\"_data.js\", content)\n```\n\n\u003e 來源：`internal/output/viewer.go#L128-L195`\n\n## 多語言目錄結構\n\n啟用多語言翻譯後（透過 `selfmd translate`），每個次要語言會在輸出目錄下建立獨立的子目錄，結構與主語言完全相同：\n\n```\n.doc-build/\n├── （主語言內容，直接在根目錄下）\n└── en-US/              # 次要語言（以 en-US 為例）\n    ├── _catalog.json   # 翻譯版目錄\n    ├── index.md        # 翻譯版主頁\n    ├── _sidebar.md     # 翻譯版側欄\n    └── core-modules/\n        └── scanner/\n            └── index.md\n```\n\n`Writer.ForLanguage` 方法負責建立語言子目錄的寫入器：\n\n```go\n// writer.go：產生語言子目錄的 Writer\nfunc (w *Writer) ForLanguage(lang string) *Writer {\n    return \u0026Writer{\n        BaseDir: filepath.Join(w.BaseDir, lang),\n    }\n}\n```\n\n\u003e 來源：`internal/output/writer.go#L139-L144`\n\n## 輸出目錄設定\n\n輸出目錄相關設定位於 `selfmd.yaml` 的 `output` 區段：\n\n```go\n// config.go：OutputConfig 結構\ntype OutputConfig struct {\n    Dir                 string   `yaml:\"dir\"`\n    Language            string   `yaml:\"language\"`\n    SecondaryLanguages  []string `yaml:\"secondary_languages\"`\n    CleanBeforeGenerate bool     `yaml:\"clean_before_generate\"`\n}\n```\n\n\u003e 來源：`internal/config/config.go#L31-L36`\n\n預設值：\n\n| 設定項 | 預設值 | 說明 |\n|--------|--------|------|\n| `output.dir` | `.doc-build` | 輸出目錄路徑 |\n| `output.language` | `zh-TW` | 主語言（內容直接在根目錄） |\n| `output.secondary_languages` | `[]`（空） | 次要語言列表，各自建立子目錄 |\n| `output.clean_before_generate` | `false` | 是否在產生前清除舊輸出 |\n\n## 增量更新檔案\n\n`_catalog.json` 與 `_last_commit` 是增量更新機制的核心：\n\n```go\n// writer.go：保存增量更新所需的中繼資料\nfunc (w *Writer) WriteCatalogJSON(cat *catalog.Catalog) error {\n    data, err := cat.ToJSON()\n    return w.WriteFile(\"_catalog.json\", data)\n}\n\nfunc (w *Writer) SaveLastCommit(commit string) error {\n    return w.WriteFile(\"_last_commit\", commit)\n}\n```\n\n\u003e 來源：`internal/output/writer.go#L77-L137`\n\n執行 `selfmd update` 時，系統會讀取這兩個檔案，比對目前的 Git commit 與上次產生時的 commit，僅重新產生受影響的頁面。\n\n## 相關連結\n\n- [整體流程與四階段管線](../../architecture/pipeline/index.md)\n- [輸出寫入與連結修復](../../core-modules/output-writer/index.md)\n- [靜態文件瀏覽器](../../core-modules/static-viewer/index.md)\n- [多語言支援](../../i18n/index.md)\n- [輸出與多語言設定](../../configuration/output-language/index.md)\n- [增量更新](../../core-modules/incremental-update/index.md)\n\n## 參考檔案\n\n| 檔案路徑 | 說明 |\n|----------|------|\n| `internal/output/writer.go` | `Writer` 結構與所有檔案寫入方法 |\n| `internal/output/viewer.go` | 靜態瀏覽器資源寫入與 `_data.js` 打包邏輯 |\n| `internal/output/navigation.go` | `index.md`、`_sidebar.md` 及分類索引頁面產生邏輯 |\n| `internal/output/linkfixer.go` | 連結修復器，確保頁面間相對連結正確 |\n| `internal/generator/pipeline.go` | 四階段管線整體協調，各類型輸出的產生順序 |\n| `internal/generator/index_phase.go` | 索引與導航階段實作 |\n| `internal/generator/translate_phase.go` | 翻譯階段與語言子目錄寫入邏輯 |\n| `internal/catalog/catalog.go` | `Catalog` 與 `FlatItem` 結構，`DirPath` 路徑映射規則 |\n| `internal/config/config.go` | `OutputConfig` 結構定義與預設值 |","overview/tech-stack/index.md":"# 技術棧與相依套件\n\nselfmd 以純 Go 實作，相依套件精簡，僅引入四個直接外部依賴，其餘功能均仰賴 Go 標準函式庫完成。\n\n## 概述\n\nselfmd 的設計目標之一是保持輕量、易於安裝。整個工具鏈除了 Go 執行環境本身之外，在執行期還需要兩個外部 CLI 工具：\n\n- **Claude Code CLI**（`claude`）：作為 AI 後端，負責分析原始碼並產生文件內容\n- **Git CLI**（`git`）：用於增量更新時偵測原始碼的變更\n\n這兩個外部工具不透過 Go 套件管理，而是透過 `os/exec` 呼叫系統中已安裝的執行檔。\n\n## 架構\n\n```mermaid\ngraph TD\n    subgraph GoStdLib[\"Go 標準函式庫\"]\n        embed[\"embed\\n（嵌入模板）\"]\n        slog[\"log/slog\\n（結構化日誌）\"]\n        exec[\"os/exec\\n（子行程執行）\"]\n        tmpl[\"text/template\\n（模板渲染）\"]\n        json[\"encoding/json\\n（JSON 序列化）\"]\n        ctx[\"context\\n（逾時控制）\"]\n        sync_pkg[\"sync / sync/atomic\\n（並行原語）\"]\n    end\n\n    subgraph ExternalDeps[\"外部相依套件\"]\n        cobra[\"cobra v1.10.2\\n（CLI 框架）\"]\n        pflag[\"pflag v1.0.9\\n（旗標解析，間接）\"]\n        doublestar[\"doublestar v4.10.0\\n（Glob 比對）\"]\n        errgroup[\"x/sync v0.19.0\\n（errgroup 並行）\"]\n        yaml[\"yaml.v3 v3.0.1\\n（YAML 解析）\"]\n        mousetrap[\"mousetrap v1.1.0\\n（Windows 相容，間接）\"]\n    end\n\n    subgraph ExternalTools[\"外部執行工具（非 Go 套件）\"]\n        claude_cli[\"Claude Code CLI\\n（claude 指令）\"]\n        git_cli[\"Git CLI\\n（git 指令）\"]\n    end\n\n    cobra --\u003e pflag\n    cobra --\u003e mousetrap\n\n    cmd_pkg[\"cmd/*\"] --\u003e cobra\n    scanner_pkg[\"internal/scanner\"] --\u003e doublestar\n    git_pkg[\"internal/git\"] --\u003e doublestar\n    config_pkg[\"internal/config\"] --\u003e yaml\n    prompt_pkg[\"internal/prompt\"] --\u003e embed\n    prompt_pkg --\u003e tmpl\n    claude_pkg[\"internal/claude\"] --\u003e exec\n    claude_pkg --\u003e json\n    claude_pkg --\u003e slog\n    claude_pkg --\u003e ctx\n    git_pkg --\u003e exec\n    generator_pkg[\"internal/generator\"] --\u003e errgroup\n    generator_pkg --\u003e sync_pkg\n    output_pkg[\"internal/output\"] --\u003e json\n\n    claude_pkg --\u003e claude_cli\n    git_pkg --\u003e git_cli\n```\n\n## 相依套件詳細說明\n\n### 直接相依套件\n\n| 套件 | 版本 | 用途 | 使用位置 |\n|------|------|------|----------|\n| `github.com/spf13/cobra` | v1.10.2 | CLI 指令框架 | `cmd/root.go`、所有指令檔案 |\n| `github.com/bmatcuk/doublestar/v4` | v4.10.0 | 雙星號（`**`）Glob 模式比對 | `internal/scanner/scanner.go`、`internal/git/git.go` |\n| `golang.org/x/sync` | v0.19.0 | `errgroup` 並行任務群組 | `internal/generator/content_phase.go`、`translate_phase.go` |\n| `gopkg.in/yaml.v3` | v3.0.1 | YAML 設定檔解析與序列化 | `internal/config/config.go` |\n\n### 間接相依套件\n\n| 套件 | 版本 | 說明 |\n|------|------|------|\n| `github.com/spf13/pflag` | v1.0.9 | cobra 的旗標解析底層實作 |\n| `github.com/inconshreveable/mousetrap` | v1.1.0 | cobra 在 Windows 平台的相容性支援 |\n\n\u003e 來源：`go.mod#L1-L15`\n\n```go\nmodule github.com/monkenwu/selfmd\n\ngo 1.25.7\n\nrequire (\n\tgithub.com/bmatcuk/doublestar/v4 v4.10.0\n\tgithub.com/spf13/cobra v1.10.2\n\tgolang.org/x/sync v0.19.0\n\tgopkg.in/yaml.v3 v3.0.1\n)\n\nrequire (\n\tgithub.com/inconshreveable/mousetrap v1.1.0 // indirect\n\tgithub.com/spf13/pflag v1.0.9 // indirect\n)\n```\n\n\u003e 來源：`go.mod#L1-L15`\n\n---\n\n### cobra — CLI 框架\n\n`cobra` 負責建立所有子指令（`init`、`generate`、`update`、`translate`）的路由結構、旗標定義，以及使用說明的自動生成。\n\n```go\nvar rootCmd = \u0026cobra.Command{\n\tUse:   \"selfmd\",\n\tShort: \"selfmd — 專案文件自動產生器\",\n\tLong: `selfmd 是一個 CLI 工具，透過本地 Claude Code CLI 作為 AI 後端，\n自動掃描專案目錄並產生結構化的 Wiki 風格繁體中文技術文件。`,\n}\n```\n\n\u003e 來源：`cmd/root.go#L17-L25`\n\n---\n\n### doublestar — Glob 模式比對\n\nGo 標準函式庫的 `filepath.Match` 不支援 `**` 雙星號（遞迴目錄比對）。`doublestar` 填補了這個空缺，讓使用者可以在 `selfmd.yaml` 中使用如 `internal/**` 或 `**/*.pb.go` 這類模式。\n\n```go\n// check excludes\nfor _, pattern := range cfg.Targets.Exclude {\n    matched, _ := doublestar.Match(pattern, rel)\n    if matched {\n        if d.IsDir() {\n            return filepath.SkipDir\n        }\n        return nil\n    }\n}\n```\n\n\u003e 來源：`internal/scanner/scanner.go#L33-L41`\n\n---\n\n### golang.org/x/sync（errgroup）— 並行任務管控\n\n`errgroup.WithContext` 搭配 channel 作為 semaphore，管控同時執行的 Claude CLI 呼叫數量，防止超過設定的 `max_concurrent` 上限。\n\n```go\neg, ctx := errgroup.WithContext(ctx)\nsem := make(chan struct{}, concurrency)\n\nfor _, item := range items {\n    item := item\n    eg.Go(func() error {\n        sem \u003c- struct{}{}\n        defer func() { \u003c-sem }()\n        // ... generate page\n        return nil\n    })\n}\n```\n\n\u003e 來源：`internal/generator/content_phase.go#L37-L50`\n\n---\n\n### yaml.v3 — 設定檔解析\n\n設定檔 `selfmd.yaml` 的讀取與寫入均透過 `yaml.v3` 完成。`Load` 函式先建立含預設值的 `Config` 物件，再用 YAML Unmarshal 覆蓋使用者定義的欄位。\n\n```go\nfunc Load(path string) (*Config, error) {\n\tdata, err := os.ReadFile(path)\n\t// ...\n\tcfg := DefaultConfig()\n\tif err := yaml.Unmarshal(data, cfg); err != nil {\n\t\treturn nil, fmt.Errorf(\"設定檔格式錯誤: %w\", err)\n\t}\n\t// ...\n}\n```\n\n\u003e 來源：`internal/config/config.go#L131-L147`\n\n---\n\n## Go 標準函式庫重點用法\n\n| 套件 | 用途 | 使用模組 |\n|------|------|----------|\n| `embed` | 編譯期嵌入 Prompt 模板（`.tmpl` 檔） | `internal/prompt/engine.go` |\n| `text/template` | 渲染 Prompt 模板，將資料注入文字 | `internal/prompt/engine.go` |\n| `os/exec` | 呼叫 `claude` 和 `git` 子行程 | `internal/claude/runner.go`、`internal/git/git.go` |\n| `log/slog` | 結構化日誌（Go 1.21+ 內建） | `internal/claude/runner.go`、`internal/generator/pipeline.go` |\n| `encoding/json` | 目錄（Catalog）的 JSON 序列化 | `internal/catalog/catalog.go`、`internal/claude/parser.go` |\n| `context` | 子行程逾時控制與取消 | `internal/claude/runner.go` |\n| `sync` / `sync/atomic` | 並行計數器（完成數、失敗數、跳過數） | `internal/generator/content_phase.go` |\n| `path/filepath` | 跨平台路徑操作 | 多處 |\n\n### embed — 編譯期嵌入模板\n\n`//go:embed` 指示詞將 `templates/` 目錄下所有 `.tmpl` 檔案在編譯時打包進二進位執行檔，使用者無需額外部署模板檔案。\n\n```go\n//go:embed templates/*/*.tmpl templates/*.tmpl\nvar templateFS embed.FS\n```\n\n\u003e 來源：`internal/prompt/engine.go#L10-L11`\n\n### log/slog — 結構化日誌\n\n`slog` 是 Go 1.21 引入的標準結構化日誌套件，取代了過去常見的第三方日誌函式庫。selfmd 以 `slog.Logger` 作為內部日誌介面，統一傳入各模組。\n\n```go\nr.logger.Debug(\"claude completed\",\n    \"duration\", elapsed.Round(time.Millisecond),\n    \"cost_usd\", result.CostUSD,\n    \"is_error\", result.IsError,\n)\n```\n\n\u003e 來源：`internal/claude/runner.go#L103-L108`\n\n---\n\n## 外部執行工具相依性\n\n### Claude Code CLI\n\nselfmd 的 AI 能力來自於呼叫本地安裝的 `claude` CLI，而非直接整合 Anthropic API SDK。這樣的設計讓使用者可以沿用已有的 Claude Code 授權與設定。\n\n```go\ncmd := exec.CommandContext(ctx, \"claude\", args...)\n// ...\ncmd.Stdin = strings.NewReader(opts.Prompt)\n```\n\n\u003e 來源：`internal/claude/runner.go#L69-L75`\n\n啟動前會先驗證 `claude` 是否可執行：\n\n```go\nfunc CheckAvailable() error {\n\t_, err := exec.LookPath(\"claude\")\n\tif err != nil {\n\t\treturn fmt.Errorf(\"找不到 claude CLI。請先安裝 Claude Code：https://docs.anthropic.com/en/docs/claude-code\")\n\t}\n\treturn nil\n}\n```\n\n\u003e 來源：`internal/claude/runner.go#L146-L152`\n\n### Git CLI\n\n增量更新功能透過執行 `git diff`、`git rev-parse` 等指令偵測原始碼變更，不依賴任何 Go 的 Git 函式庫：\n\n```go\nfunc runGit(dir string, args ...string) (string, error) {\n\tcmd := exec.Command(\"git\", args...)\n\tcmd.Dir = dir\n\t// ...\n}\n```\n\n\u003e 來源：`internal/git/git.go#L124-L141`\n\n---\n\n## 核心流程\n\n```mermaid\nsequenceDiagram\n    participant User\n    participant cobra\n    participant config_yaml as yaml.v3\n    participant scanner_ds as doublestar\n    participant prompt_embed as embed / text/template\n    participant runner_exec as os/exec（claude）\n    participant gen_eg as errgroup（x/sync）\n    participant git_exec as os/exec（git）\n\n    User-\u003e\u003ecobra: selfmd generate\n    cobra-\u003e\u003econfig_yaml: 載入 selfmd.yaml\n    cobra-\u003e\u003escanner_ds: 掃描目錄（Glob 過濾）\n    cobra-\u003e\u003eprompt_embed: 渲染 Prompt 模板\n    cobra-\u003e\u003egen_eg: 啟動並行任務群組\n    loop 每個文件頁面（受 semaphore 限制）\n        gen_eg-\u003e\u003erunner_exec: 呼叫 claude CLI\n        runner_exec--\u003e\u003egen_eg: 回傳 JSON 結果\n    end\n    cobra-\u003e\u003egit_exec: 儲存目前 commit（供增量更新）\n```\n\n---\n\n## 相關連結\n\n- [整體流程與四階段管線](../../architecture/pipeline/index.md)\n- [Claude CLI 執行器](../../core-modules/claude-runner/index.md)\n- [專案掃描器](../../core-modules/scanner/index.md)\n- [Prompt 模板引擎](../../core-modules/prompt-engine/index.md)\n- [設定說明](../../configuration/index.md)\n- [Git 整合設定](../../configuration/git-config/index.md)\n\n---\n\n## 參考檔案\n\n| 檔案路徑 | 說明 |\n|----------|------|\n| `go.mod` | Go 模組定義，含所有直接與間接相依套件 |\n| `cmd/root.go` | cobra 根指令定義，展示 CLI 框架使用方式 |\n| `internal/config/config.go` | yaml.v3 用於設定檔解析的實作 |\n| `internal/scanner/scanner.go` | doublestar 用於 include/exclude 模式比對 |\n| `internal/git/git.go` | os/exec 呼叫 git CLI 的實作 |\n| `internal/claude/runner.go` | os/exec 呼叫 claude CLI、log/slog 使用範例 |\n| `internal/claude/types.go` | Claude CLI 回應的 JSON 型別定義 |\n| `internal/prompt/engine.go` | embed + text/template 嵌入並渲染模板 |\n| `internal/generator/content_phase.go` | errgroup + channel semaphore 並行控制 |\n| `internal/generator/pipeline.go` | 整體管線，展示各模組如何整合 |\n| `internal/catalog/catalog.go` | encoding/json 用於目錄的序列化 |\n| `internal/output/writer.go` | 輸出寫入，展示標準 os 套件使用 |\n| `internal/output/navigation.go` | 導航頁面生成實作 |\n| `internal/scanner/filetree.go` | 檔案樹資料結構定義（ScanResult、FileNode） |"}};
